<#
================================================================================
 New-GPTImage.ps1 — AI image generator for Azure Foundry
 PowerShell script to generate and edit images through image-gen models
 (gpt-image-2, gpt-image-1.5, MAI-Image, FLUX, ...) hosted on Azure Foundry.

 The current script version is in the $script:ScriptVersion variable (below);
 the TUI version is in $script:TuiVersion. The complete change history, from the
 first release to the current one, is kept in the changelog file distributed
 alongside the script (this header no longer contains the inline changelog).

 REQUIREMENT: PowerShell 7.0+ (for reliable Unicode/UTF-8 support and multilingual
 i18n, including Chinese, Japanese, Hindi, Russian, Arabic). On PowerShell 5.1
 (Windows PowerShell) UTF-8 I/O is unreliable: the #requires directive above
 blocks execution with a clear message.

 FEATURE OVERVIEW:
 - Text-to-image generation and image-to-image editing (edit), multi-model
 - Model configuration in New-GPTImage.conf (endpoint, DPAPI-encrypted key,
   pricing, API schema and authMode per model); -AddModel / -EditModel /
   -RemoveModel wizards to manage models without editing the .conf by hand
 - Full command-line interface and full-screen interactive interface (-TUI)
 - Batch processing (including parallel), model benchmarking (-Bench), automatic
   model selection (-Auto Cost|Quality|Time)
 - USD/EUR cost tracking, analytics, HTML gallery, per-image metadata
 - Full internationalization (11 languages) via New-GPTImage.lang
================================================================================
#>

param(
    # --- Prompt text input ---
    # String describing what to generate. Minimum length 5 characters.
    # Alternative: -PromptFile to read the prompt from a file.
    [string]$Prompt,

    # Path to a .txt/.md file containing the prompt. If specified, overrides -Prompt.
    [string]$PromptFile,

    # --- Model to use ---
    # Logical model name (e.g. "gpt-image-2"). Must exist in New-GPTImage.conf
    # under the "models.<name>" key. If omitted, uses "defaultModel" from config.
    [string]$Model,

    # --- Generation parameters ---
    # How many images to generate in the same request. Default 1, typical max 10.
    # ValidateRange 1-100 rejects nonsensical values up front (0, negative, excessive)
    # with a clear PowerShell binder error, before any logic runs.
    [ValidateRange(1, 100)]
    [int]$NImages = 1,

    # Output size, in "WIDTHxHEIGHT" format (e.g. "1024x1024", "1536x1024").
    # Valid values for gpt-image-2: 1024x1024 (1:1), 1536x1024 (3:2), 1024x1536 (2:3).
    # If omitted, uses "defaultSize" from config.
    # AUTOMATIC DOWNSCALING: if the requested size exceeds the chosen model's limits
    # (e.g. 2048x2048 on a model with a maximum area of 1024x1024), the script reduces
    # it automatically to the nearest valid value while preserving the aspect ratio,
    # with a [WARN] notice, instead of failing. It only fails if the reduction is not
    # possible (e.g. an aspect ratio that cannot be realized within the model's limits).
    [string]$Size,

    # Generation quality. Valid values: "low", "medium", "high".
    # Increasing time: low ~50s, medium ~80s, high ~230s on gpt-image-2.
    # If omitted, uses "defaultQuality" from config.
    [string]$Quality,

    # Output file format (LOCAL side; the server always returns PNG).
    # Valid values: "png", "jpg", "webp". The jpg/webp conversion happens via
    # System.Drawing (requires Windows). On other OSes, automatic fallback to PNG.
    # The "base64" value is deprecated and mapped to -OutputMode base64 + Format png.
    [string]$Format,

    # Content moderation policy. Valid values: "auto", "low".
    # "auto" (Foundry default): strict filters, may degrade realistic faces.
    # "low" (recommended for portraits): permissive filters.
    # If omitted, uses "defaultModeration" from config (recommended default: "low").
    [string]$Moderation,

    # How closely the output adheres to the input images. Values: "low", "high".
    # Supported ONLY by models that have "supportsInputFidelity: true" in config.
    # gpt-image-2 already works at high fidelity by default and does NOT accept this
    # parameter (we silently ignore it with a WARN). Used by gpt-image-1.5 and others.
    [string]$InputFidelity,

    # Background type in the output. Values: "auto", "opaque", "transparent".
    # "transparent" requires output_format PNG (preserves the alpha channel).
    # Supported only by models with "supportsBackground: true" in config.
    [string]$Background,

    # Path to a PNG mask with an alpha channel for inpainting. The TRANSPARENT areas of
    # the mask indicate the regions to modify; the opaque ones stay unchanged.
    # Also requires -InputImages and a model with "supportsInpainting: true" in config.
    [string]$Mask,

    # --- Batch processing ---
    # Path to a .json file with an array of requests. Each item may have:
    # { "prompt": "...", "size": "...", "quality": "...", "n": 1, "format": "...",
    # "inputImages": [...], "mask": "...", "id": 1 }
    # If "id" is not present it is assigned automatically (1, 2, 3...).
    [string]$Batch,

    # Number of batch requests run in parallel. Range 1-5 (default 0 = use
    # "batchThreads" from config, or 1 if undefined). Threads > 1 uses
    # ForEach-Object -Parallel from PowerShell 7+.
    [int]$Threads = 0,

    # --- Model benchmarking ---
    # List of models (comma-separated) on which to run the SAME prompt (or the same
    # prompts, when combined with -Batch) to compare time, cost and quality.
    # Examples: -Bench gpt-image-2,MAI-Image-2.5,FLUX.2-pro  or  -Bench "gpt-image-2","FLUX.2-pro"
    # When set, it activates benchmark mode: the -Model parameter is ignored (the models
    # are those of -Bench). A model that fails does not block the others. The results
    # (time/cost/tokens/image path) are shown at the end of the run, grouped by prompt.
    [string[]]$Bench = @(),

    # Path to the CSV file in which to export the benchmark results (one row per
    # prompt x model combination). Active only with -Bench. If omitted, the results
    # are shown on screen only.
    [string]$BenchExport = "",

    # --- Metadata ---
    # If True, a .json file is created next to each image with all the parameters
    # needed to regenerate it. Priority: CLI parameter > config > default False.
    # Accepts True/False (handier to type than $true/$false). Empty string = "not
    # specified": in that case the value from config is used. The ValidateSet is lenient
    # toward common variants (uppercase/lowercase, 1/0, yes/no, on/off).
    [ValidateSet("True","False","true","false","1","0","yes","no","on","off","")]
    [string]$Metadata = "",

    # --- Output ---
    # Output mode. "file" = save image file. "base64" = save a .txt with base64.
    [ValidateSet("file","base64")]
    [string]$OutputMode = "file",

    # Folder in which to save the outputs. If omitted, uses "defaultOutputFolder" from config.
    # Both absolute and relative paths are supported.
    [string]$OutputFolder,

    # Array of paths to reference images for edit mode. Accepted extensions:
    # .png, .jpg, .jpeg. Max 20 MB per file. They are validated, converted to RGB and
    # resized (max long side) automatically before sending.
    [string[]]$InputImages,

    # --- Verbosity ---
    # Controls the on-screen output. All ERRORs ALWAYS go to stderr regardless.
    # The log file ALWAYS contains everything, regardless of verbosity.
    # verbose: shows everything (INFO, WARN, TIME, COST, ERROR)
    # normal: shows INFO, WARN, ERROR; hides TIME and COST
    # silent: shows only ERROR (on stderr)
    # ultrasilent: no on-screen output (ERROR still on stderr)
    [ValidateSet("verbose","normal","silent","ultrasilent")]
    [string]$Verbosity = "verbose",

    # --- Switches ---
    # "Dry run" mode: validates all parameters and shows the final prompt, but
    # does NOT make any API call. Useful for prompt debugging.
    [switch]$DryRun,

    # Generates the New-GPTImage.conf file with default values and exits.
    # If the file already exists, it is not overwritten (exits with a message).
    [switch]$Setup,

    # Script help. Shows the complete list of parameters with descriptions.
    # To also see 3 examples per parameter, use: -Help Example
    # TECHNICAL NOTE: "Example" is captured as a residual positional argument
    # (ValueFromRemainingArguments) to let the user type "-Help" on its own
    # WITHOUT PowerShell complaining about a "missing argument".
    [switch]$Help,

    # Analytics: prints 10 textual charts on costs/usage (layout 5 rows x 2 columns).
    # The first 8 cover costs and tokens of image generations; charts [9] and [10]
    # cover the text-model costs (optimize/negative/storyboard/describe).
    # With no extra value it uses the default currency from config (defaultCurrency).
    # With a value EUR | USD | Token (-Analytics USD), it uses that currency.
    # TECHNICAL NOTE: the optional value is captured as a residual argument
    # (see $RemainingArgs at the bottom of the param block).
    [switch]$Analytics,

    # If specified together with -Analytics, saves the charts to this text file
    # instead of showing them on screen. Path absolute or relative to $PSScriptRoot.
    [string]$AnalyticsFile,

    # Write policy for the -AnalyticsFile when it ALREADY EXISTS:
    # - neither of the two: the script EXITS with a WARN without touching the file
    # - -Overwrite: overwrites the existing file (action logged with a WARN)
    # - -Append: appends the new report at the end of the existing file
    # If the file does NOT exist, it is created normally in both cases.
    # -Overwrite and -Append are mutually exclusive.
    [switch]$Overwrite,
    [switch]$Append,

    # If specified together with -Analytics, exports ALL cost records (from the first
    # to the last) to a CSV file suited to BI/dashboards, then exits. Path absolute or
    # relative to $PSScriptRoot. See Export-AnalyticsCsv for the record layout.
    [string]$ExportAll,

    # Auto mode: the script automatically chooses the best model according to the
    # indicated strategy. Valid values:
    # - "Cost": chooses the CHEAPEST model (cost_score = inputUsd+imageUsd)
    # - "Quality": chooses the model with the BEST QUALITY (qualityRating field 1-10)
    # - "Time": chooses the FASTEST model (speedRating field 1-10)
    # Considers only models with active=true and endpoint+apiKey configured.
    # Filters by requested features (mask -> supportsInpainting, etc.).
    # The Quality/Time ratings are subjective evaluations to enter manually
    # in the .conf (1=worst, 10=best). Overrides -Model if specified.
    [ValidateSet("Cost","Quality","Time","")]
    [string]$Auto = "",

    # Forces a refresh of the data supporting -Auto, bypassing the weekly cache.
    # Applies together with -Auto:
    # -Auto Quality -Force -> re-downloads the arena.ai leaderboard (even if cached < 7 days)
    # -Auto Time -Force -> recomputes the time medians from the log (even if cached < 7 days)
    # -Auto Cost -Force -> internally runs -ModelPrice Force to refresh the prices
    # Without -Auto, this flag is ignored (for now; in the future it might be
    # extended to other commands).
    [switch]$Force,

    # Prints the list of configured models with their status (active/inactive,
    # endpoint configured/empty, apiKey ok/empty). Highlights active and working
    # models in green. Exits afterward.
    [switch]$ModelList,

    # Prints the current script version and exits.
    [switch]$Version,

    # Forces the update of model prices via the Azure Retail API.
    # The "Force" value bypasses the daily check (pricingLastUpdated) and attempts
    # the API call anyway. Useful for debugging or when you suspect the prices
    # changed recently and the daily check has not run again yet.
    [ValidateSet("Force","")]
    [string]$ModelPrice = "",

    # Runs a free-form query against the Azure Retail Prices API to explore the catalog.
    # Useful to identify the real serviceName, productName and meterName of the models,
    # when the exact match fails. Searches contains(productName, '<keyword>').
    # Example: -PricingDiscovery "MAI", -PricingDiscovery "GPT-Image"
    # Exits after running the query and showing the results on screen + a JSON file.
    #
    # The default is a sentinel value "__NOTSET__" (different from "") so we can
    # distinguish three cases: (a) parameter not passed -> sentinel, normal
    # behavior; (b) -PricingDiscovery "" or spaces -> we show the usage; (c) a valid
    # keyword -> runs the discovery. AllowEmptyString allows -PricingDiscovery ""
    # without binder errors. NB: the completely bare flag (-PricingDiscovery with no
    # following token) is a limitation of the PowerShell binder for typed [string]
    # parameters and still produces "Missing an argument"; to avoid it just
    # pass at least "" (e.g. -PricingDiscovery "") or a keyword.
    [AllowEmptyString()]
    [string]$PricingDiscovery = "__NOTSET__",

    # Language of user-facing messages.
    # Supported values: it | en | fr | es | pt | de | ru | zh | ja | hi | ar.
    # Latin: it (Italian), en (English), fr (French), es (Spanish),
    # pt (Portuguese), de (German)
    # Cyrillic: ru (Russian)
    # CJK: zh (Mandarin Chinese), ja (Japanese)
    # Devanagari: hi (Hindi)
    # Arabic (RTL): ar (MSA Arabic) - the data is preserved correctly in files and at
    # runtime, but the console does NOT render RTL or contextual shaping
    # (see Test-Prerequisites, which emits a WARN). Correct rendering
    # only in a future GUI/TUI with bidirectional support.
    # Non-Latin languages require a UTF-8 console (set automatically in
    # Test-Prerequisites) and, for CJK/Devanagari, a suitable terminal font.
    # If the console is not UTF-8 capable, there is automatic fallback to English.
    # If omitted, uses "language" from config, or "it" as a fallback.
    [ValidateSet("it","en","fr","es","pt","de","ru","zh","ja","hi","ar","")]
    [string]$Lang = "",

    # Maximum spend limit for the current request (or for the whole batch).
    # If the conservative cost estimate (+20% margin) exceeds this
    # value, the script BLOCKS execution and shows the estimate.
    # The value is expressed in the default currency (defaultCurrency).
    # IMPORTANT: the type is [string[]] (array), not [string] or [double]. Reason:
    # PowerShell interprets the COMMA as the array-construction operator BEFORE
    # looking at the parameter type, so "1,0" arrives as @("1","0"). A scalar
    # type ([double] or [string]) would make the binding fail ("cannot convert
    # System.Object[]..."). With [string[]] the array is absorbed, and in parsing
    # we recompose the elements with the comma (@("1","0") -> "1,0") before
    # converting. This way "1,0", "1.0" and "1" all work.
    [string[]]$BudgetRaw = @(),

    # Generates a gallery.html file in the images folder (defaultOutputFolder),
    # which lets you view the images with thumbnails, lightbox, metadata.
    # Exits after generating the gallery.
    [switch]$Gallery,

    # Runs a check of the active models (a DryRun call to each) and reports
    # which endpoints are reachable. Exits afterward. Useful to validate the conf.
    [switch]$CheckModels,

    # Runs an availability test on the endpoints of ALL ACTIVE models:
    # for each one it verifies that the endpoint responds (network reachability +
    # HTTP response from the API) and reports [INFO] available / [WARN] unreachable,
    # indicating the deploy region. Useful to understand whether there is a problem with a
    # specific region or Foundry. Exits afterward. Does not generate images.
    [switch]$CheckEndpoint,

    # Downloads locally the official Azure pricing pages of ALL configured models,
    # reading pricingMapping.pricingPageUrl from the .conf. Deduplicates the pages (several
    # models can share the same URL) and saves them in a subfolder next to the .conf.
    # Uses the same HTTP headers as the internal scraper, so the saved HTML is identical to
    # what the pricing pipeline analyzes. Useful for debugging the scraping or for
    # inspecting the published prices by hand. Exits afterward. Does not generate images.
    [switch]$DumpPricingPages,

    # Model management without editing the .conf by hand. Each starts an interactive wizard
    # and exits afterward. -AddModel adds a new model: guided questions, API key encrypted
    # in DPAPI, and defaults pre-filled based on the chosen schema (operationalParams via
    # Get-SchemaOperationalDefaults and pricing/meterRoles structure via Get-SchemaPricingDefaults,
    # so the entry is complete and computes costs correctly right away).
    # -RemoveModel removes an existing model (with confirmation, warns if it was the defaultModel).
    # -EditModel edits an existing model: the connection fields (endpoint, deployment,
    # shortName, authMode, supportsEdit/editEndpoint, region, API key) and, through optional
    # sections accessed on request, also the feature flags, the meter prices and the
    # numeric operational parameters.
    [switch]$AddModel,
    [switch]$RemoveModel,
    [switch]$EditModel,

    # --- Automatic self-test ---
    # -SelfTest enables the built-in test suite that verifies the script's
    # behavior (re-launches ITSELF as a subprocess for end-to-end tests).
    # Must be combined with EXACTLY one of these three modes:
    #   -Simulate : runs only the tests that do NOT consume tokens/images (DryRun,
    #               validations, local commands). No cost. May do a
    #               network probe, which is free.
    #   -Real     : runs only the tests that generate real images (token consumption).
    #   -AllTest  : runs all the tests (Simulate + Real).
    # Exits after running the tests, with exit code 0 (no KO) or 1 (at least one KO).
    [switch]$SelfTest,
    [switch]$Simulate,
    [switch]$Real,
    [switch]$AllTest,

    # -TUI : starts the full-screen interactive interface (full-screen TUI).
    #        Uses the main configuration file (the "tui" section); if the section
    #        is missing, it is normalized in memory with the default values.
    [switch]$TUI,

    # -DecryptLog : prints the decrypted log to stdout (for grep and debugging) and exits.
    [switch]$DecryptLog,

    # -Storyboard : generates a narrative sequence of coherent images from the prompt.
    [switch]$Storyboard,

    # -SequenceImages : number of storyboard scenes (2-20, default 5).
    [ValidateRange(2, 20)]
    [int]$SequenceImages = 5,

    # -OptimizePrompt : rewrites the prompt via the text model from the conf.
    [switch]$OptimizePrompt,

    # -NegativePrompt : generates a negative prompt and injects it into the positive prompt.
    [switch]$NegativePrompt,

    # -DescribeImage <path> : analyzes an image with the MULTIMODAL text model
    # configured in textModel and generates a descriptive prompt from it (image-to-prompt).
    [string]$DescribeImage = "",

    # ----- IaC (Infrastructure as Code) -----
    # -IaC : generates (and optionally runs) the Azure CLI provisioning script to
    # create the infrastructure the script needs (Resource Group, Foundry resource
    # CognitiveServices kind=AIServices, Foundry Project; in later increments also
    # App Insights and model deployment). Format: pure 'az' commands (single dependency).
    [switch]$IaC,

    # IaC mode: 'generate' (writes the script without touching Azure),
    # 'dry-run' (shows what would be created without creating it), 'execute' (creates the
    # resources after explicit confirmation).
    [ValidateSet('generate', 'dry-run', 'execute')]
    [string]$IaCMode = 'generate',

    # Support parameters for non-interactive use of the IaC (if omitted, Increment 4
    # introduces the interactive wizard that asks for them one by one with sensible defaults).
    [string]$IaCResourceGroup = "",
    [string]$IaCRegion = "",
    [string]$IaCFoundryName = "",
    [string]$IaCProjectName = "",

    # ----- IaC: OPTIONAL model deployment (Increment 3) -----
    # -IaCDeployModel enables the deployment of an image model on the Foundry resource.
    # It is optional and separate from the infrastructure: availability depends on region,
    # subscription quotas and other factors, so it is not guaranteed.
    [switch]$IaCDeployModel,
    [string]$IaCModelName = "gpt-image-1",
    [string]$IaCModelVersion = "",
    # Model format: 'OpenAI' for OpenAI models (gpt-image), 'Microsoft' for the
    # MAI models (MAI-Image-*). Determines --model-format in the az command.
    [ValidateSet('OpenAI', 'Microsoft')]
    [string]$IaCModelFormat = "OpenAI",
    [string]$IaCModelSku = "GlobalStandard",
    [int]$IaCModelCapacity = 1,

    # -IaCTeardown : tears down the resources created by the IaC (deletes the Resource Group
    # with all its content) after explicit confirmation. DESTRUCTIVE operation.
    [switch]$IaCTeardown,

    # -IaCPurgeSoftDeleted : if the Foundry resource exists in a "soft-deleted" state
    # (CognitiveServices resources are not deleted immediately), it removes it PERMANENTLY
    # before recreating it. Without this flag, the IaC stops and explains what to do.
    [switch]$IaCPurgeSoftDeleted,

    # -IaCWizard : starts the guided interactive collection of the IaC parameters (asks for RG,
    # region, names, options with sensible defaults), then proceeds to execution. Handy
    # for those who do not want to remember all the command-line parameters.
    [switch]$IaCWizard,

    # -NoTelemetry : disables telemetry sending ONLY for this run,
    # whatever the value in the .conf. Internal use: the SelfTest passes it to the
    # generation subprocesses so the test images do not pollute the real
    # metrics. It can also be used manually for a single run.
    [switch]$NoTelemetry,

    # Captures residual arguments that do not correspond to known parameters.
    # Used to allow "-Help Example" and "-Analytics USD/EUR/Token" as
    # parameters-with-optional-value: PowerShell by default does not allow optional
    # arguments on typed parameters; with ValueFromRemainingArguments instead
    # we can handle it manually after the param block.
    [Parameter(ValueFromRemainingArguments=$true)]
    [string[]]$RemainingArgs = @()
)

# Budget parsing. $BudgetRaw arrives as an ARRAY of strings because PowerShell
# splits "1,0" on the comma into @("1","0") during binding (see the comment on the
# parameter). I recompose the elements by joining them with the comma: @("1","0") -> "1,0",
# then normalize the decimal separator to a dot and convert in a culture-invariant way.
# This way "1,0", "1.0" and "1" all give the same value. Empty -> $null (no check).
[Nullable[double]]$Budget = $null
if ($BudgetRaw -and @($BudgetRaw).Count -gt 0) {
    # Join with the comma to rebuild the original value typed by the user,
    # then bring the decimal separator to a dot for invariant parsing.
    $budgetJoined = (@($BudgetRaw) -join ',').Trim()
    if (-not [string]::IsNullOrWhiteSpace($budgetJoined)) {
        $budgetParsed = 0.0
        $budgetNorm = $budgetJoined.Replace(',', '.')
        if ([double]::TryParse($budgetNorm, [System.Globalization.NumberStyles]::Float, [System.Globalization.CultureInfo]::InvariantCulture, [ref]$budgetParsed)) {
            $Budget = $budgetParsed
        } else {
            # Non-numeric value: warn and proceed WITHOUT a budget. I do not block execution
            # for a malformed accessory parameter. The message uses Write-Host because
            # the logging system is not yet initialized at this point in the script.
            Write-Host ("[WARN] -Budget: value '" + $budgetJoined + "' not valid (expected a number, e.g. 1,0 or 1.0). Proceeding without a budget limit.") -ForegroundColor Yellow
        }
    }
}

# =================================================================
# SCRIPT VERSION
# =================================================================
# Script version, centralized in a SINGLE variable (defined here, before
# the -Version handler so it is seen by the early exit too). Update ONLY here.
# MAJOR.MINOR format (two digits after the dot). Bump policy:
#  - bugfix only:        +1 to the minor (or several minors if there are many bugs, e.g. 2.80 -> 2.85)
#  - new features or impactful changes: jump to the next ten (e.g. 2.81 -> 2.90)
# Shown in: log header ("Version: x.y"), help (-Help) and the -Version parameter.
$script:ScriptVersion = "5.92"

# TUI version (-TUI switch), centralized in a single variable and kept
# SEPARATE from the script version, but with the SAME bump policy: MAJOR.MINOR
# format (two digits after the dot), +1 to the minor for bugfix only, jump to the
# next ten for new features. Shown in the terminal window/tab title.
$script:TuiVersion = "0.92"

# HTML gallery version (-Gallery switch), tracked separately from
# ScriptVersion and TuiVersion: the gallery is by now a rich component in its own right.
$script:GalleryVersion = "1.71"

# Global flag: TRUE when the full-screen TUI is active. When active,
# Write-Log writes ONLY to file (never to screen) so as not to corrupt the
# full-screen rendering. Set/restored in Enter-TuiMode. $null/$false = normal
# CLI behavior (log to screen according to Verbosity).
$script:TuiActive = $false
# Global telemetry opt-out flag for this run (set by -NoTelemetry).
$script:NoTelemetryFlag = [bool]$NoTelemetry

# ANSI sequences for "synchronized output" (DEC private mode 2026): between Begin and
# End the terminal accumulates all writes and redraws the frame in one go,
# eliminating flicker. Terminals that do not support it ignore the sequence
# (unknown private mode), so it is safe as a no-op. Used by Show-Tui.
$script:TuiSyncBegin = "$([char]27)$([char]91)?2026h"
$script:TuiSyncEnd   = "$([char]27)$([char]91)?2026l"

# =================================================================
# PATH CONSTANTS
# =================================================================
# All support files are in the same folder as the script,
# next to New-GPTImage.ps1. This makes the script "portable": just copy
# the folder to move it, and all the relative files move with it.
$script:ConfigFile = Join-Path $PSScriptRoot "New-GPTImage.conf"   # Configuration (JSON), read at startup
$script:LogFile    = Join-Path $PSScriptRoot "New-GPTImage.log"    # Application log (text), append-only
$script:StatsFile  = Join-Path $PSScriptRoot "New-GPTImage.stat"   # Timing telemetry (JSONL), 1 line per generation
$script:CostFile   = Join-Path $PSScriptRoot "New-GPTImage.cost"   # Daily cost aggregate (JSONL), 1 line per day
$script:LangFile   = Join-Path $PSScriptRoot "New-GPTImage.lang"   # i18n translations (JSON), optional

# Handling of the -Version parameter (must be among the first, even before reading the config)
# NB: we do NOT use T here because this block runs BEFORE the T function is
# defined and the language pack is loaded. The version number is identical
# in all languages anyway, so there is nothing to translate.
if ($Version) {
    # -Version returns only the version number (no script name).
    # With -TUI -Version you get the TUI version instead, which is tracked
    # separately. The number is identical in all languages: nothing to translate.
    if ($TUI) {
        Write-Host $script:TuiVersion
    }
    elseif ($Gallery) {
        Write-Host $script:GalleryVersion
    }
    else {
        Write-Host $script:ScriptVersion
    }
    exit 0
}

# =================================================================
# EARLY LOGGER
# =================================================================

# ============================================================
# FUNCTION DEFINITIONS (all grouped, defined before use)
# ============================================================
function Write-Log {
    param(
        [string]$Message,
        [ValidateSet("INFO","WARN","ERROR","TIME","COST","PROMPT")]
        [string]$Level = "INFO"
    )

    # Anti log-injection sanitization: messages with newlines (e.g. prompts or hostile
    # file names) must not be able to forge fake log lines or break the
    # parsers that re-read the log (e.g. the COST line reader).
    if ($Message -and $Message -match "[\r\n]") { $Message = $Message -replace "\r?\n", " " }

    $timestamp = (Get-Date).ToString("yyyy-MM-dd HH:mm:ss", [System.Globalization.CultureInfo]::InvariantCulture)
    $line = "[$timestamp] [$Level] $Message"

    # On-screen coloring:
    # INFO -> default color (no coloring)
    # WARN -> DarkYellow (dark yellow, not light)
    # ERROR -> Red
    # TIME -> file only, not on screen (it is internal telemetry)
    # COST -> default (handled separately by Write-CostLog)
    $color = switch ($Level) {
        "WARN"  { "DarkYellow" }
        "ERROR" { "Red" }
        default { $null }
    }

    # On-screen output with the following rules:
    # - TIME never on screen (only in the log file)
    # - ERROR: always red on screen via Write-Host (except ultrasilent).
    # In ultrasilent mode, I write to stderr so a calling script can
    # intercept the error with `script.ps1 2>error.txt`.
    # IMPORTANT: I do NOT write to stderr in interactive mode because PowerShell
    # in chat mode would show stderr as DUPLICATED white text (in addition to the red
    # of Write-Host). This created the "red line + identical white line" effect.
    # - WARN: dark yellow, in verbose and normal
    # - INFO/COST: default, in verbose and normal
    # In TUI mode the console is managed by the full-screen rendering: Write-Log
    # writes ONLY to file, never on screen (see $script:TuiActive in Enter-TuiMode).
    if ($script:TuiActive) { }
    elseif ($Level -eq "ERROR") {
        if ($Verbosity -eq "ultrasilent") {
            # stderr only (Write-Host does not write in ultrasilent)
            [Console]::Error.WriteLine($line)
        } else {
            # Only colored Write-Host, no stderr to avoid visual duplication
            Write-Host $line -ForegroundColor Red
        }
    }
    elseif ($Level -eq "TIME") {
        # TIME is telemetry: file only, never on screen
    }
    elseif ($Level -eq "PROMPT") {
        # PROMPT: like TIME, file only never on screen. The prompt content has already
        # possibly been obfuscated (Base64) upstream according to the privacy section
        # of the .conf. On screen the prompts keep appearing where already foreseen.
    }
    elseif ($Verbosity -eq "verbose") {
        if ($color) { Write-Host $line -ForegroundColor $color } else { Write-Host $line }
    }
    elseif ($Verbosity -eq "normal") {
        # In normal: no COST on screen (already handled by the separate Write-CostLog), the rest yes
        if ($Level -ne "COST") {
            if ($color) { Write-Host $line -ForegroundColor $color } else { Write-Host $line }
        }
    }
    # silent: nothing on stdout/stderr except ERROR
    # ultrasilent: nothing on stdout, ERROR still on stderr

    if ($script:LogFile) {
        Add-Content -Path $script:LogFile -Value (Protect-LogFileLine $line) -Encoding UTF8 -ErrorAction SilentlyContinue
    }
}

# Logs a prompt to the log file at the [PROMPT] level (file-only, never on screen).
# Handles privacy: depending on the 'privacy' section of the .conf, the prompt
# content may be obfuscated in Base64 before writing it. Always adds a separate
# line with the length in characters and the ESTIMATED tokens of the prompt (useful
# for debugging and future calculations). On screen the prompts keep appearing elsewhere
# (this function does NOT print anything to screen).
# Parameters:
#   -LabelKey:   .lang key for the label (e.g. 'prompt.original')
#   -PromptText: the prompt text
#   -Kind:       "image" (user prompt) | "support" (optimize/negative/storyboard/describe).
#                Determines WHICH privacy switch to consult.
#   -Config:     the config (to read the privacy section)
function Write-PromptLog {
    param(
        [Parameter(Mandatory=$true)][string]$LabelKey,
        [string]$PromptText = "",
        [ValidateSet("image","support")][string]$Kind = "image",
        $Config = $null
    )
    if ($null -eq $PromptText) { $PromptText = "" }

    # Decide whether to obfuscate based on the privacy section of the .conf.
    $obfuscate = $false
    if ($Config -and $Config.privacy) {
        if ($Kind -eq "image"   -and $Config.privacy.imagePrompts   -eq $true) { $obfuscate = $true }
        if ($Kind -eq "support" -and $Config.privacy.supportPrompts -eq $true) { $obfuscate = $true }
    }

    # Length in characters and ESTIMATED tokens (heuristic ~4 char/token, the same
    # used by Get-EstimatedTokens for inputs). Computed on the PLAINTEXT,
    # so they stay useful even when the prompt is obfuscated.
    $charLen = $PromptText.Length
    $estTokens = [int][math]::Ceiling($charLen / 4.0)
    if ($estTokens -lt 1 -and $charLen -gt 0) { $estTokens = 1 }
    if ($charLen -eq 0) { $estTokens = 0 }

    # Content to write: plaintext or Base64 (UTF8).
    $content = $PromptText
    $encNote = ""
    if ($obfuscate) {
        $bytes = [System.Text.Encoding]::UTF8.GetBytes($PromptText)
        $content = [System.Convert]::ToBase64String($bytes)
        $encNote = " " + (T 'prompt.encoded_note')
    }

    # Line 1: label + content (possibly obfuscated).
    $label = T $LabelKey
    Write-Log ($label + ": " + $content + $encNote) -Level PROMPT
    # Line 2: metrics, which REPEAT the label (no anonymous indentation, so
    # the line is aligned with the others and readable on its own). Always plaintext: they are
    # numbers, they do not reveal the content.
    Write-Log (T 'prompt.metrics' $label $charLen $estTokens) -Level PROMPT
}


function Format-DisplayDate {
    <#
    Formats a date/time for DISPLAY to the user, respecting the operating
    system's regional settings (CultureInfo.CurrentCulture).
    This way a user with Italian Windows sees "29/05/2026 11:56:28", one with
    US Windows "5/29/2026 11:56:28 AM", one with German Windows "29.05.2026 11:56:28".

    IMPORTANT: this function must NOT be used for dates that end up in the log
    file, in .conf/.stat/.cost files or in any JSON: those MUST stay
    in ISO format "yyyy-MM-dd[ HH:mm:ss]" because they are structured
    machine-readable data, parsed elsewhere with ParseExact. Display only.

    Parameters:
      -Date:     [datetime] to format (default: now)
      -DateOnly: if present, shows only the date (culture's "d" pattern),
                 otherwise date+time ("G" pattern, general long time).
    #>
    param(
        [datetime]$Date = (Get-Date),
        [switch]$DateOnly
    )
    $culture = [System.Globalization.CultureInfo]::CurrentCulture
    if ($DateOnly) {
        return $Date.ToString("d", $culture)   # culture's short date pattern
    } else {
        return $Date.ToString("G", $culture)   # general date/time (long time)
    }
}

function Format-StorageNumber {
    <#
    Formats a number for WRITING into the script's internal files (.log, .cost,
    .stat) in INVARIANT format: decimal separator "." and no thousands
    separator. This ensures the files are:
      - portable across PCs with different cultures (a .log written in Italy stays
        readable/parsable on a US PC and vice versa);
      - reliably parsable by the analytics regex, which expects the
        decimal dot and digits without separators.

    It is the numeric equivalent of the ISO format used for dates in the files. Do NOT use
    for what the user sees: for that there is Format-DisplayNumber.

    Parameters:
      -Value:    the number to format
      -Decimals: decimal digits (default 6, as in the .log costs)
    #>
    param(
        [double]$Value,
        [int]$Decimals = 6
    )
    return $Value.ToString("F$Decimals", [System.Globalization.CultureInfo]::InvariantCulture)
}

function Format-DisplayNumber {
    <#
    Formats a number for DISPLAY to the user or for EXPORT
    (INFO/WARN/ERROR messages, analytics charts, pricing, CSV), respecting the
    system's regional settings (CultureInfo.CurrentCulture). This way an Italian
    user sees "0,42" and "1.234,50", a US one "0.42" and "1,234.50".

    It is the numeric equivalent of Format-DisplayDate. Do NOT use for data written in the
    internal files: for those there is Format-StorageNumber (invariant format).

    Parameters:
      -Value:        the number to format
      -Decimals:     decimal digits (default 2)
      -ThousandsSep: if present, uses the culture's thousands separator
                     ("N" format, e.g. "1.234,50" in IT). Without it, "F" format with no
                     thousands separator (e.g. "1234,50").
    #>
    param(
        [double]$Value,
        [int]$Decimals = 2,
        [switch]$ThousandsSep
    )
    $culture = [System.Globalization.CultureInfo]::CurrentCulture
    $fmt = if ($ThousandsSep) { "N$Decimals" } else { "F$Decimals" }
    return $Value.ToString($fmt, $culture)
}

function Test-Prerequisites {
    <#
    Verifies the system and environment prerequisites BEFORE the script gets into
    the thick of it. Centralizes checks that were previously scattered or implicit.

    Checks:
      1. PowerShell version (requires >= 7.0). NB: the #requires directive at the top
         of the file already blocks PS < 7; this is a second defensive check that
         logs a clear message in case the script is dot-sourced or invoked
         in ways that bypass #requires.
      2. Console encoding setup to UTF-8 (uncorrupted multilingual output).
      3. Presence/validation of the support files (.conf, .lang).
      4. UTF-8 encoding normalization of the text files: if a BOM is detected
         (written by old Windows PowerShell 5.1 sessions) it removes it,
         rewriting the file in UTF-8 without BOM.
      5. Renderability of the requested language: if the console cannot handle
         the necessary Unicode script -> WARN + English fallback.

    Returns [PSCustomObject]:
      Ok            = $true if the critical checks pass
      EffectiveLang = the language actually usable (may be the "en" fallback)
      Messages      = list of messages (logged by the caller in a deferred way)

    NB: some messages here do not use T() because the function is called VERY
        early, before the language pack is loaded. The messages are in Italian
        (the script's base language) + English where critical.
    #>
    param(
        [string]$RequestedLang = "",
        [string]$ConfigPath = "",
        [string]$LangPath = "",
        [switch]$SkipConsoleSetup
    )

    # Messages: list of objects { Key; Args } translated by the caller with T AFTER
    # the language pack is loaded (Test-Prerequisites runs before the langpack).
    # The Level field indicates the severity with which to log them.
    $result = [PSCustomObject]@{
        Ok            = $true
        EffectiveLang = $RequestedLang
        Messages      = @()
        # FatalMessage: direct bilingual message for errors that cause an exit BEFORE
        # the langpack (e.g. PowerShell too old). Null if no fatal error.
        FatalMessage  = $null
    }

    # ---- 1. PowerShell version (defensive, #requires is the first line of defense) ----
    $psMajor = $PSVersionTable.PSVersion.Major
    if ($psMajor -lt 7) {
        # This error can occur BEFORE the langpack: direct bilingual message.
        $result.Ok = $false
        $result.FatalMessage = "PowerShell $($PSVersionTable.PSVersion) detected. " +
                               "This script requires PowerShell 7.0+ " +
                               "(Unicode/UTF-8). Download: https://aka.ms/powershell"
        return $result
    }

    # ---- 2. Console UTF-8 encoding setup ----
    # Wrapped in try/catch: in some hosts (ISE, redirect, CI) [Console]::OutputEncoding
    # is not settable and throws. In that case we proceed anyway (output redirected
    # to a UTF-8 file works just the same).
    if (-not $SkipConsoleSetup) {
        try {
            $utf8NoBom = New-Object System.Text.UTF8Encoding($false)
            [Console]::OutputEncoding = $utf8NoBom
            try { [Console]::InputEncoding = $utf8NoBom } catch { }
            $global:OutputEncoding = $utf8NoBom
        } catch {
            $result.Messages += [PSCustomObject]@{ Key = 'prereq.console_encoding_failed'; Args = @($_.Exception.Message); Level = 'WARN' }
        }
    }

    # ---- 3+4. Support files + BOM normalization ----
    foreach ($filePair in @(
        @{ Path = $ConfigPath; Name = ".conf"; Required = $false },
        @{ Path = $LangPath;   Name = ".lang"; Required = $false }
    )) {
        $p = $filePair.Path
        if (-not $p) { continue }
        if (Test-Path $p) {
            try {
                $bytes = [System.IO.File]::ReadAllBytes($p)
                if ($bytes.Length -ge 3 -and $bytes[0] -eq 0xEF -and $bytes[1] -eq 0xBB -and $bytes[2] -eq 0xBF) {
                    # UTF-8 BOM detected: rewrite without BOM
                    $textContent = [System.Text.Encoding]::UTF8.GetString($bytes, 3, $bytes.Length - 3)
                    $utf8NoBom = New-Object System.Text.UTF8Encoding($false)
                    [System.IO.File]::WriteAllText($p, $textContent, $utf8NoBom)
                    $result.Messages += [PSCustomObject]@{ Key = 'prereq.bom_removed'; Args = @($filePair.Name); Level = 'WARN' }
                }
            } catch {
                $result.Messages += [PSCustomObject]@{ Key = 'prereq.normalize_failed'; Args = @($filePair.Name, $_.Exception.Message); Level = 'WARN' }
            }
        } elseif ($filePair.Required) {
            $result.Messages += [PSCustomObject]@{ Key = 'prereq.required_file_missing'; Args = @($filePair.Name, $p); Level = 'ERROR' }
            $result.Ok = $false
        }
    }

    # ---- 5. Language renderability ----
    $lang = if ($RequestedLang -and $RequestedLang.Trim() -ne "") { $RequestedLang.ToLower() } else { "" }
    if ($lang -and $script:LanguageScripts.ContainsKey($lang)) {
        $scriptType = $script:LanguageScripts[$lang]
        if ($scriptType -ne "latin") {
            # The console output must be UTF-8 for any non-Latin language
            $isUtf8 = $false
            try {
                $enc = [Console]::OutputEncoding
                $isUtf8 = ($enc.CodePage -eq 65001) -or ($enc.WebName -eq 'utf-8')
            } catch {
                $isUtf8 = $false
            }
            if (-not $isUtf8) {
                $result.Messages += [PSCustomObject]@{ Key = 'prereq.lang_needs_utf8'; Args = @($lang); Level = 'WARN' }
                $result.EffectiveLang = "en"
            } else {
                if ($script:RtlLanguages -contains $lang) {
                    $result.Messages += [PSCustomObject]@{ Key = 'prereq.lang_rtl'; Args = @($lang); Level = 'WARN' }
                } elseif ($scriptType -in @("cjk", "devanagari")) {
                    $result.Messages += [PSCustomObject]@{ Key = 'prereq.lang_font_dependent'; Args = @($lang, $scriptType); Level = 'WARN' }
                }
            }
        }
    }

    return $result
}

# Prints to screen the prerequisite messages (info/warning) accumulated during the initial checks.
function Write-PrereqMessages {
    param($Messages)
    if (-not $Messages) { return }
    foreach ($m in $Messages) {
        if ($m -is [string]) {
            Write-Log $m -Level WARN
            continue
        }
        $level = if ($m.Level) { $m.Level } else { 'WARN' }
        $msgArgs = if ($m.Args) { @($m.Args) } else { @() }
        $text  = T $m.Key @msgArgs
        Write-Log $text -Level $level
    }
}

# Masks an API key for log/output: shows only the first and last 4 characters (or *** if too short).
function Format-MaskedKey {
    param([string]$Key)
    if (-not $Key -or $Key.Length -lt 8) { return "***" }
    $prefix = $Key.Substring(0, 4)
    $suffix = $Key.Substring($Key.Length - 4, 4)
    return "$prefix...$suffix"
}

function Test-ApiKeyEncoded {
    <#
    Checks whether a string is already encoded (has one of the known prefixes).
    Returns $true if it has the prefix "enc:", "b64:" or "aes:", $false otherwise.
    An empty or $null string is considered "not encoded" (it is NOT a secret).
    #>
    param([string]$Value)
    if (-not $Value -or $Value.Trim() -eq "") { return $false }
    return ($Value.StartsWith("enc:") -or $Value.StartsWith("b64:") -or $Value.StartsWith("aes:"))
}

function Protect-ApiKey {
    <#
    Encodes a plaintext string into the appropriate format for the platform.
    Windows -> DPAPI (ConvertFrom-SecureString), prefix "enc:"
    Unix    -> AES-256-GCM with a per-user master key, prefix "aes:"
               (Keychain on macOS, 0600 keyfile on Linux); Base64 fallback "b64:"
               only if the master key is not obtainable.
    #>
    param([Parameter(Mandatory=$true)][string]$PlainText)

    if ($script:IsWin) {
        try {
            # SecureString -> ConvertFrom-SecureString uses DPAPI internally.
            # The output is hex-encoded and tied to the current Windows user.
            $secure = ConvertTo-SecureString $PlainText -AsPlainText -Force
            $encoded = ConvertFrom-SecureString $secure
            return "enc:$encoded"
        } catch {
            Write-Log (T 'apikey.dpapi_error' ($_.Exception.Message)) -Level WARN
            Write-Log (T 'apikey.not_encrypted_warning') -Level WARN
            $bytes = [System.Text.Encoding]::UTF8.GetBytes($PlainText)
            return "b64:" + [System.Convert]::ToBase64String($bytes)
        }
    } else {
        # Linux/macOS: real AES-256-GCM encryption. The per-user master key lives
        # in the Keychain on macOS or in a 0600 keyfile on Linux (see Get-ApiKeyMasterKey).
        $masterKey = Get-ApiKeyMasterKey
        if ($masterKey) {
            try {
                $nonce = [byte[]]::new(12)
                [System.Security.Cryptography.RandomNumberGenerator]::Fill($nonce)
                $plainBytes = [System.Text.Encoding]::UTF8.GetBytes($PlainText)
                $cipher = [byte[]]::new($plainBytes.Length)
                $tag    = [byte[]]::new(16)
                $gcm = $null
                # .NET 8+ requires the explicit tag size; earlier versions do not.
                try { $gcm = [System.Security.Cryptography.AesGcm]::new($masterKey, 16) }
                catch { $gcm = [System.Security.Cryptography.AesGcm]::new($masterKey) }
                try { $gcm.Encrypt($nonce, $plainBytes, $cipher, $tag) }
                finally { $gcm.Dispose() }
                # Payload layout: nonce (12) + tag (16) + ciphertext.
                $payload = [byte[]]::new(28 + $cipher.Length)
                [Array]::Copy($nonce,  0, $payload, 0, 12)
                [Array]::Copy($tag,    0, $payload, 12, 16)
                [Array]::Copy($cipher, 0, $payload, 28, $cipher.Length)
                return "aes:" + [System.Convert]::ToBase64String($payload)
            } catch {
                Write-Log (T 'apikey.aes_encrypt_failed' ($_.Exception.Message)) -Level WARN
            }
        }
        # Last-resort fallback: obfuscated Base64, with the historical WARN.
        Write-Log (T 'apikey.not_encrypted_warning') -Level WARN
        $bytes = [System.Text.Encoding]::UTF8.GetBytes($PlainText)
        return "b64:" + [System.Convert]::ToBase64String($bytes)
    }
}

# Returns (creating it on first use) the per-user AES-256 master key used to
# encrypt the API keys on non-Windows systems. On macOS the key lives in the system
# Keychain via the preinstalled 'security' command; on Linux (or if the Keychain is
# not available) in a keyfile with 0600 permissions under ~/.config/new-gptimage.
# The key is cached in $script:AesMasterKey for the duration of the run.
function Get-ApiKeyMasterKey {
    if ($script:AesMasterKey) { return $script:AesMasterKey }

    if ($script:IsWin) {
        # On Windows the master key is needed ONLY for log encryption (the API
        # keys use DPAPI directly with the enc: prefix). I store it in a
        # per-user DPAPI-protected file under %APPDATA%.
        try {
            $dirWin = Join-Path $env:APPDATA "New-GPTImage"
            if (-not (Test-Path $dirWin)) { New-Item -ItemType Directory -Path $dirWin -Force | Out-Null }
            $keyFileWin = Join-Path $dirWin "master.key"
            if (Test-Path $keyFileWin) {
                $sec = (Get-Content $keyFileWin -Raw -ErrorAction Stop).Trim() | ConvertTo-SecureString
                $bstr = [System.Runtime.InteropServices.Marshal]::SecureStringToBSTR($sec)
                try { $b64 = [System.Runtime.InteropServices.Marshal]::PtrToStringBSTR($bstr) }
                finally { [System.Runtime.InteropServices.Marshal]::ZeroFreeBSTR($bstr) }
                $key = [System.Convert]::FromBase64String($b64)
                if ($key.Length -eq 32) { $script:AesMasterKey = $key; return $key }
            }
            $newKey = [byte[]]::new(32)
            [System.Security.Cryptography.RandomNumberGenerator]::Fill($newKey)
            $secNew = ConvertTo-SecureString ([System.Convert]::ToBase64String($newKey)) -AsPlainText -Force
            Set-Content -Path $keyFileWin -Value (ConvertFrom-SecureString $secNew) -Encoding ascii
            $script:AesMasterKey = $newKey
            return $newKey
        } catch {
            Write-Log (T 'apikey.aes_encrypt_failed' ($_.Exception.Message)) -Level WARN
            return $null
        }
    }

    $svc  = "New-GPTImage"
    $acct = [string]$env:USER
    try {
        if ($script:IsMac) {
            $found = & security find-generic-password -s $svc -a $acct -w 2>$null
            if ($LASTEXITCODE -eq 0 -and $found) {
                $key = [System.Convert]::FromBase64String(([string]$found).Trim())
                if ($key.Length -eq 32) { $script:AesMasterKey = $key; return $key }
            }
            $newKey = [byte[]]::new(32)
            [System.Security.Cryptography.RandomNumberGenerator]::Fill($newKey)
            & security add-generic-password -s $svc -a $acct -w ([System.Convert]::ToBase64String($newKey)) -U 2>$null | Out-Null
            if ($LASTEXITCODE -eq 0) { $script:AesMasterKey = $newKey; return $newKey }
            # Keychain not usable: fall back to the keyfile as on Linux.
        }
        $dir = Join-Path $HOME ".config/new-gptimage"
        if (-not (Test-Path $dir)) { New-Item -ItemType Directory -Path $dir -Force | Out-Null }
        $keyFile = Join-Path $dir "master.key"
        if (Test-Path $keyFile) {
            $key = [System.Convert]::FromBase64String(((Get-Content $keyFile -Raw -ErrorAction Stop)).Trim())
            if ($key.Length -eq 32) { $script:AesMasterKey = $key; return $key }
        }
        $newKey = [byte[]]::new(32)
        [System.Security.Cryptography.RandomNumberGenerator]::Fill($newKey)
        Set-Content -Path $keyFile -Value ([System.Convert]::ToBase64String($newKey)) -Encoding ascii -NoNewline
        # User-only permissions: .NET API if available, otherwise system chmod.
        try { [System.IO.File]::SetUnixFileMode($keyFile, ([System.IO.UnixFileMode]::UserRead -bor [System.IO.UnixFileMode]::UserWrite)) }
        catch { try { & chmod 600 $keyFile 2>$null } catch { } }
        $script:AesMasterKey = $newKey
        return $newKey
    } catch {
        Write-Log (T 'apikey.aes_encrypt_failed' ($_.Exception.Message)) -Level WARN
        return $null
    }
}

# Encrypts a line destined for the log file when log encryption is active.
# Encrypted line format: "ENC1:" + Base64(nonce 12 + tag 16 + ciphertext AES-GCM).
# If encryption is not active (or the key is unavailable) the line passes in plaintext.
function Protect-LogFileLine {
    param([string]$Text)
    if (-not $script:LogEncryptionActive) { return $Text }
    $key = Get-ApiKeyMasterKey
    if (-not $key) { return $Text }
    try {
        $nonce = [byte[]]::new(12)
        [System.Security.Cryptography.RandomNumberGenerator]::Fill($nonce)
        $plainBytes = [System.Text.Encoding]::UTF8.GetBytes($Text)
        $cipher = [byte[]]::new($plainBytes.Length)
        $tag    = [byte[]]::new(16)
        $gcm = $null
        try { $gcm = [System.Security.Cryptography.AesGcm]::new($key, 16) }
        catch { $gcm = [System.Security.Cryptography.AesGcm]::new($key) }
        try { $gcm.Encrypt($nonce, $plainBytes, $cipher, $tag) } finally { $gcm.Dispose() }
        $payload = [byte[]]::new(28 + $cipher.Length)
        [Array]::Copy($nonce,  0, $payload, 0, 12)
        [Array]::Copy($tag,    0, $payload, 12, 16)
        [Array]::Copy($cipher, 0, $payload, 28, $cipher.Length)
        return "ENC1:" + [System.Convert]::ToBase64String($payload)
    } catch { return $Text }
}

# Decrypts a log line if it is encrypted (ENC1: prefix), otherwise returns it
# unchanged. On a decryption error it returns the original line, so the readers
# stay tolerant to mixed files or changed master keys.
function Unprotect-LogLine {
    param([string]$Line)
    if (-not $Line -or -not $Line.StartsWith("ENC1:")) { return $Line }
    try {
        $key = Get-ApiKeyMasterKey
        if (-not $key) { return $Line }
        $payload = [System.Convert]::FromBase64String($Line.Substring(5))
        if ($payload.Length -lt 28) { return $Line }
        $nonce  = [byte[]]($payload[0..11])
        $tag    = [byte[]]($payload[12..27])
        $cipher = if ($payload.Length -gt 28) { [byte[]]($payload[28..($payload.Length - 1)]) } else { [byte[]]@() }
        $plainBytes = [byte[]]::new($cipher.Length)
        $gcm = $null
        try { $gcm = [System.Security.Cryptography.AesGcm]::new($key, 16) }
        catch { $gcm = [System.Security.Cryptography.AesGcm]::new($key) }
        try { $gcm.Decrypt($nonce, $cipher, $tag, $plainBytes) } finally { $gcm.Dispose() }
        return [System.Text.Encoding]::UTF8.GetString($plainBytes)
    } catch { return $Line }
}

# Reads the log file, decrypting the ENC1: lines (the others pass through unchanged).
function Get-DecryptedLogLines {
    param([string]$Path)
    $out = [System.Collections.Generic.List[string]]::new()
    foreach ($l in @(Get-Content $Path -Encoding UTF8 -ErrorAction Stop)) {
        [void]$out.Add((Unprotect-LogLine $l))
    }
    return @($out)
}

# Enables log encryption (the logEncryption conf option). If the existing file
# contains plaintext lines it converts them all: INFO at the start, INFO at the end,
# ERROR if the conversion fails. Writing happens to a temporary file with
# atomic replacement so as not to lose the log if an error occurs midway.
function Enable-LogEncryption {
    try {
        if (-not (Test-Path $script:LogFile)) {
            $script:LogEncryptionActive = $true
            return
        }
        $rawLines = @(Get-Content $script:LogFile -Encoding UTF8 -ErrorAction Stop)
        $hasPlain = $false
        foreach ($l in $rawLines) {
            if ($l -and -not $l.StartsWith("ENC1:")) { $hasPlain = $true; break }
        }
        if (-not $hasPlain) {
            $script:LogEncryptionActive = $true
            return
        }
        Write-Log (T 'logenc.start')
        $rawLines = @(Get-Content $script:LogFile -Encoding UTF8 -ErrorAction Stop)
        $script:LogEncryptionActive = $true
        $tmp = $script:LogFile + ".encrypting"
        $sb = [System.Text.StringBuilder]::new()
        foreach ($l in $rawLines) {
            if ($l.StartsWith("ENC1:")) { [void]$sb.AppendLine($l) }
            else { [void]$sb.AppendLine((Protect-LogFileLine $l)) }
        }
        [System.IO.File]::WriteAllText($tmp, $sb.ToString(), [System.Text.UTF8Encoding]::new($false))
        Move-Item -Path $tmp -Destination $script:LogFile -Force
        Write-Log (T 'logenc.done' $rawLines.Count)
    } catch {
        Write-Log (T 'logenc.failed' ($_.Exception.Message)) -Level ERROR
    }
}

# Verifies the availability of the text model BEFORE using it (optimize/negative/
# storyboard/describe). Checks: (1) configuration present (endpoint+model+apiKey),
# (2) network reachability of the host (TCP:443, lightweight, no tokens consumed).
# Returns [PSCustomObject] { Available; Reason } where Reason is an i18n key.
# It is not blocking per se: the caller decides whether WARN (proceeds) or ERROR (stops)
# based on how much the requested function depends on the text model.
function Test-TextModelAvailable {
    param($Config, [int]$TimeoutSec = 5)
    $res = [PSCustomObject]@{ Available = $false; Reason = 'textmodel.check_unreachable' }
    $tm = $Config.textModel
    if (-not $tm -or -not $tm.endpoint -or -not $tm.model) {
        $res.Reason = 'textmodel.check_not_configured'
        return $res
    }
    $key = $null
    if ($tm.apiKey) { $key = Unprotect-ApiKey ([string]$tm.apiKey) }
    if (-not $key) {
        $res.Reason = 'textmodel.check_no_key'
        return $res
    }
    $hostName = Get-HostFromUrl ([string]$tm.endpoint)
    if (-not $hostName) {
        $res.Reason = 'textmodel.check_invalid_url'
        return $res
    }
    # TCP reachability of the host (like the internet check): lightweight, consumes no
    # tokens and does not depend on auth. If the host does not respond, the model is not usable.
    if (-not (Test-InternetConnectivity -TargetHost $hostName -TargetPort 443 -TimeoutSec $TimeoutSec)) {
        $res.Reason = 'textmodel.check_unreachable'
        return $res
    }
    $res.Available = $true
    $res.Reason = 'textmodel.check_ok'
    return $res
}

# Calls the text model configured in the "textModel" section of the .conf
# (OpenAI-compatible chat/completions endpoint, e.g. GPT on Foundry) and returns the
# textual content of the response, or $null on error. The section is agnostic:
# endpoint, model, authMode (bearer | api-key), maxCompletionTokens, reasoningEffort.
function Invoke-TextModel {
    param(
        [array]$Messages,
        $Config,
        [int]$TimeoutSec = 0,        # 0 = use the default below / the conf value
        [int]$MaxTokensOverride = 0  # 0 = use the conf's maxCompletionTokens; >0 forces
                                     # a larger budget (useful for "long" tasks such as
                                     # the storyboard, where the reasoning + the JSON output
                                     # can exceed the default budget)
    )
    $tm = $Config.textModel
    if (-not $tm -or -not $tm.endpoint -or -not $tm.model) {
        Write-Log (T 'textmodel.not_configured') -Level ERROR
        return $null
    }
    # Timeout: reasoning models (e.g. gpt-5.x with reasoning_effort) can
    # "think" for a long time before answering. Priority: explicit caller
    # parameter -> textModel.timeoutSec from the conf -> 600s default. The default was
    # raised to 600s because recent "pro" reasoning models (e.g. gpt-5.4-pro)
    # with complex prompts can exceed 5 minutes, especially on the negative prompt.
    if ($TimeoutSec -le 0) {
        $TimeoutSec = if ($tm.timeoutSec -and [int]$tm.timeoutSec -gt 0) { [int]$tm.timeoutSec } else { 600 }
    }
    $key = $null
    if ($tm.apiKey) { $key = Unprotect-ApiKey ([string]$tm.apiKey) }
    if (-not $key) {
        Write-Log (T 'textmodel.no_key') -Level ERROR
        return $null
    }
    # Azure Foundry exposes two text APIs with DIFFERENT payload and response:
    #   - /chat/completions : requires "messages",  responds in choices[0].message.content
    #   - /responses        : requires "input",     responds in output[].content[].text
    #                         (and puts the maxCompletionTokens reasoning budget as
    #                          "max_output_tokens", not "max_completion_tokens")
    # The type is auto-detected from the URL, or forced via the conf field apiType
    # ("chat" | "responses"). This way the textModel section stays agnostic.
    $endpoint = [string]$tm.endpoint
    $apiType = if ($tm.apiType) { [string]$tm.apiType } else { '' }
    if (-not $apiType) {
        if     ($endpoint -match '/responses\b')         { $apiType = 'responses' }
        elseif ($endpoint -match '/chat/completions\b')  { $apiType = 'chat' }
        else                                              { $apiType = 'chat' }
    }
    $maxTok = if ($MaxTokensOverride -gt 0) { $MaxTokensOverride }
              elseif ($tm.maxCompletionTokens) { [int]$tm.maxCompletionTokens } else { 4096 }

    if ($apiType -eq 'responses') {
        # The /responses API accepts a string or a list of typed messages;
        # I use the list to preserve the system role. The content goes in "input".
        $inputItems = @()
        foreach ($m in @($Messages)) {
            $contentList = @()
            if ($m.content -is [string]) {
                $contentList = @( @{ type = "input_text"; text = [string]$m.content } )
            } else {
                # Multimodal content: I remap the chat-style types to the responses ones.
                foreach ($part in @($m.content)) {
                    if ($part.type -eq "image_url") {
                        $contentList += @{ type = "input_image"; image_url = [string]$part.image_url.url }
                    } else {
                        $contentList += @{ type = "input_text"; text = [string]$part.text }
                    }
                }
            }
            $inputItems += @{ role = [string]$m.role; content = $contentList }
        }
        $body = [ordered]@{
            model = [string]$tm.model
            input = $inputItems
        }
        $body.max_output_tokens = $maxTok
        if ($tm.reasoningEffort) { $body.reasoning = @{ effort = [string]$tm.reasoningEffort } }
    }
    else {
        $body = [ordered]@{
            messages = $Messages
            model    = [string]$tm.model
        }
        $body.max_completion_tokens = $maxTok
        if ($tm.reasoningEffort) { $body.reasoning_effort = [string]$tm.reasoningEffort }
    }

    $headers = @{ 'Content-Type' = 'application/json' }
    $authMode = if ($tm.authMode) { [string]$tm.authMode } else { 'bearer' }
    if ($authMode -eq 'api-key') { $headers['api-key'] = $key }
    else { $headers['Authorization'] = "Bearer $key" }

    try {
        $resp = Invoke-RestMethod -Method Post -Uri $endpoint -Headers $headers `
                                  -Body ($body | ConvertTo-Json -Depth 12) -TimeoutSec $TimeoutSec -ErrorAction Stop
        # Extraction of used tokens from the 'usage' field (real, not estimated). The two API
        # types use different names: chat -> prompt_tokens/completion_tokens; responses ->
        # input_tokens/output_tokens. I normalize them into InputTokens/OutputTokens.
        $inTok = 0; $outTok = 0
        try {
            if ($resp.PSObject.Properties.Name -contains 'usage' -and $resp.usage) {
                $u = $resp.usage
                if ($u.PSObject.Properties.Name -contains 'input_tokens')  { $inTok  = [int]$u.input_tokens }
                elseif ($u.PSObject.Properties.Name -contains 'prompt_tokens') { $inTok = [int]$u.prompt_tokens }
                if ($u.PSObject.Properties.Name -contains 'output_tokens')     { $outTok = [int]$u.output_tokens }
                elseif ($u.PSObject.Properties.Name -contains 'completion_tokens') { $outTok = [int]$u.completion_tokens }
            }
        } catch { }
        # Text extraction depending on the API.
        $content = $null
        if ($apiType -eq 'responses') {
            # Preference: the aggregated output_text field (if present); otherwise
            # I concatenate the text blocks inside output[].content[].
            if ($resp.PSObject.Properties.Name -contains 'output_text' -and $resp.output_text) {
                $content = ($resp.output_text -join "`n")
            } else {
                $parts = @()
                foreach ($o in @($resp.output)) {
                    foreach ($c in @($o.content)) {
                        if ($null -ne $c.text) { $parts += [string]$c.text }
                    }
                }
                if ($parts.Count -gt 0) { $content = ($parts -join "`n") }
            }
        }
        else {
            $content = $resp.choices[0].message.content
        }
        if ($content) {
            return [pscustomobject]@{
                Text = ([string]$content).Trim()
                InputTokens = $inTok
                OutputTokens = $outTok
            }
        }
        # Empty content: a typical cause with reasoning models is the exhaustion of the
        # token budget in the reasoning (finish_reason = "length"), with no room for
        # the output. I detect it and give a useful diagnostic message instead of the generic one.
        $finishReason = $null
        try { $finishReason = $resp.choices[0].finish_reason } catch { }
        if ($finishReason -eq 'length') {
            Write-Log (T 'textmodel.empty_truncated') -Level ERROR
        } else {
            Write-Log (T 'textmodel.call_failed' "risposta priva di contenuto testuale") -Level ERROR
        }
        return $null
    } catch {
        # The body of the HTTP response contains Foundry's explanation (e.g. which
        # field is missing or invalid): without extracting it the user only sees "400 Bad
        # Request". I read it from the exception stream, truncated.
        $detail = $_.Exception.Message
        # Client timeout: usually means long reasoning. I suggest the action.
        if ($detail -match 'HttpClient\.Timeout|was canceled due to the configured') {
            $detail = (T 'textmodel.timeout' $TimeoutSec)
        }
        try {
            $respObj = $_.Exception.Response
            if ($respObj) {
                $stream = $respObj.GetResponseStream()
                if ($stream) {
                    $reader = [System.IO.StreamReader]::new($stream)
                    try { $rawErr = $reader.ReadToEnd() } finally { $reader.Dispose() }
                    if ($rawErr) {
                        if ($rawErr.Length -gt 500) { $rawErr = $rawErr.Substring(0, 500) + "..." }
                        $detail = "$detail | $rawErr"
                    }
                }
            }
            elseif ($_.ErrorDetails -and $_.ErrorDetails.Message) {
                $em = [string]$_.ErrorDetails.Message
                if ($em.Length -gt 500) { $em = $em.Substring(0, 500) + "..." }
                $detail = "$detail | $em"
            }
        } catch { }
        Write-Log (T 'textmodel.call_failed' $detail) -Level ERROR
        return $null
    }
}

# Rewrites the user prompt into a prompt optimized for image generation
# (subject, composition, light, style, technical details). Returns $null on error.
function Invoke-TextModelPromptRewrite {
    param([string]$Prompt, $Config)
    $sys = "You are an expert prompt engineer for AI image generation. Rewrite the user's prompt into a single optimized image-generation prompt: keep the original intent and language, make subject, composition, lighting, style and technical details explicit and vivid. Reply with the rewritten prompt ONLY, no preamble, no quotes, no markdown."
    $messages = @(
        @{ role = "system"; content = $sys }
        @{ role = "user";   content = $Prompt }
    )
    $out = Invoke-TextModel -Messages $messages -Config $Config
    if ($out -and $out.Text) {
        return [pscustomobject]@{
            Text = ($out.Text -replace '^```[a-z]*', '' -replace '```$', '').Trim()
            InputTokens = $out.InputTokens
            OutputTokens = $out.OutputTokens
        }
    }
    return $null
}

# Generates a negative prompt (a concise list of defects/artifacts to avoid) coherent
# with the given prompt. It is then injected into the positive prompt as "Avoid: ...",
# so the feature stays compatible with all models (even those without a
# native negative_prompt field). Returns $null on error.
function Invoke-TextModelNegative {
    param([string]$Prompt, $Config)
    $sys = "You generate negative prompts for AI image generation. Given the user's image prompt, reply with a concise comma-separated list (max 25 items) of defects, artifacts and unwanted elements to avoid for that specific image. Reply with the list ONLY, no preamble, no markdown."
    $messages = @(
        @{ role = "system"; content = $sys }
        @{ role = "user";   content = $Prompt }
    )
    $out = Invoke-TextModel -Messages $messages -Config $Config
    if ($out -and $out.Text) {
        return [pscustomobject]@{
            Text = ($out.Text -replace '^```[a-z]*', '' -replace '```$', '').Trim()
            InputTokens = $out.InputTokens
            OutputTokens = $out.OutputTokens
        }
    }
    return $null
}

# Analyzes an image with the MULTIMODAL text model (it must support visual
# input) and generates a detailed descriptive prompt (image-to-prompt). The image
# is sent as a base64 data URL in the OpenAI-style multimodal content format.
# Extracts the text of an entry inside a ZIP archive (docx/odt) opening the file
# in SHARED mode: ZipFile.OpenRead requires exclusive access and fails if
# the document is open in Word or being synced by OneDrive ("file in use by another
# process"). Here I read the bytes with FileShare ReadWrite and open the ZIP from memory.
function Get-ZipEntryText {
    param([string]$Path, [string]$EntryName)
    Add-Type -AssemblyName System.IO.Compression | Out-Null
    Add-Type -AssemblyName System.IO.Compression.FileSystem | Out-Null
    $bytes = $null
    $fs = [System.IO.FileStream]::new($Path, [System.IO.FileMode]::Open, [System.IO.FileAccess]::Read, [System.IO.FileShare]::ReadWrite)
    try {
        $ms = [System.IO.MemoryStream]::new()
        try {
            $fs.CopyTo($ms)
            $bytes = $ms.ToArray()
        } finally { $ms.Dispose() }
    } finally { $fs.Dispose() }

    $memZip = [System.IO.MemoryStream]::new($bytes)
    try {
        $zip = [System.IO.Compression.ZipArchive]::new($memZip, [System.IO.Compression.ZipArchiveMode]::Read)
        try {
            $entry = $zip.Entries | Where-Object { $_.FullName -eq $EntryName } | Select-Object -First 1
            if (-not $entry) { return $null }
            $reader = [System.IO.StreamReader]::new($entry.Open())
            try { return $reader.ReadToEnd() } finally { $reader.Dispose() }
        } finally { $zip.Dispose() }
    } finally { $memZip.Dispose() }
}

# Reads the prompt from a file supporting several formats WITHOUT external libraries:
#   .txt .md          -> plain text
#   .docx .odt        -> ZIP archives with XML inside: I extract the text via
#                        System.IO.Compression (included in .NET), no dependencies
#   .doc              -> old binary OLE format: NOT parsable without heavy
#                        libraries; clear message with a conversion suggestion
# Returns the text, or $null on error (already logged).
function Read-PromptFile {
    param([string]$Path)
    if (-not (Test-Path -LiteralPath $Path -PathType Leaf)) {
        Write-Log (T 'prompt.file_read_failed' $Path "file not found") -Level ERROR
        return $null
    }
    $ext = [System.IO.Path]::GetExtension($Path).ToLower()
    try {
        switch ($ext) {
            { $_ -in '.txt', '.md', '' } {
                return (Get-Content -LiteralPath $Path -Raw -Encoding UTF8 -ErrorAction Stop)
            }
            '.docx' {
                # .docx: ZIP -> word/document.xml. The text is in the <w:t> tags; the
                # </w:p> paragraphs become newlines. Strip all the other tags.
                $xml = Get-ZipEntryText -Path $Path -EntryName 'word/document.xml'
                if (-not $xml) { Write-Log (T 'prompt.docx_no_content' $Path) -Level ERROR; return $null }
                $xml = $xml -replace '</w:p>', "`n"
                $xml = $xml -replace '<[^>]+>', ''
                return [System.Net.WebUtility]::HtmlDecode($xml).Trim()
            }
            '.odt' {
                # .odt (OpenDocument): ZIP -> content.xml. Text in the <text:p> tags,
                # paragraphs delimited by </text:p>. Same strategy as docx.
                $xml = Get-ZipEntryText -Path $Path -EntryName 'content.xml'
                if (-not $xml) { Write-Log (T 'prompt.docx_no_content' $Path) -Level ERROR; return $null }
                $xml = $xml -replace '</text:p>', "`n"
                $xml = $xml -replace '<[^>]+>', ''
                return [System.Net.WebUtility]::HtmlDecode($xml).Trim()
            }
            '.doc' {
                # Old binary OLE format: not reliably extractable without
                # external libraries. I indicate the way out.
                Write-Log (T 'prompt.doc_unsupported' $Path) -Level ERROR
                return $null
            }
            default {
                # Unrecognized extension: I try it as plain text anyway.
                return (Get-Content -LiteralPath $Path -Raw -Encoding UTF8 -ErrorAction Stop)
            }
        }
    } catch {
        Write-Log (T 'prompt.file_read_failed' $Path ($_.Exception.Message)) -Level ERROR
        return $null
    }
}

function Invoke-TextModelDescribe {
    param([string]$ImagePath, $Config, [string]$Language = "en")
    if (-not (Test-Path $ImagePath)) {
        Write-Log (T 'describe.not_found' $ImagePath) -Level ERROR
        return $null
    }
    try {
        $bytes = [System.IO.File]::ReadAllBytes($ImagePath)
    } catch {
        Write-Log (T 'describe.read_failed' ($_.Exception.Message)) -Level ERROR
        return $null
    }
    $ext = [System.IO.Path]::GetExtension($ImagePath).ToLower().TrimStart('.')
    $mime = switch ($ext) { 'png' { 'image/png' } 'jpg' { 'image/jpeg' } 'jpeg' { 'image/jpeg' } 'webp' { 'image/webp' } default { 'image/png' } }
    $b64 = [System.Convert]::ToBase64String($bytes)
    $dataUrl = "data:$mime;base64,$b64"
    # Map the language code -> language name to instruct the model about the output.
    $langName = switch ($Language) {
        'it' { 'Italian' } 'en' { 'English' } 'fr' { 'French' } 'es' { 'Spanish' }
        'pt' { 'Portuguese' } 'de' { 'German' } 'ru' { 'Russian' } 'zh' { 'Chinese' }
        'ja' { 'Japanese' } 'hi' { 'Hindi' } 'ar' { 'Arabic' } default { 'English' }
    }
    $sys = "You are an expert at reverse-engineering AI image generation prompts. Look at the image and write a single, detailed prompt that could regenerate a very similar image: describe subject, composition, lighting, style, color palette, mood and technical photographic details. Write the prompt in $langName. Reply with the prompt ONLY, no preamble, no quotes, no markdown."
    # Multimodal content: text + image (image_url format, compatible both with
    # chat/completions and responses via the adaptation in Invoke-TextModel).
    $messages = @(
        @{ role = "system"; content = $sys }
        @{ role = "user"; content = @(
            @{ type = "text"; text = "Generate a detailed generation prompt for this image." }
            @{ type = "image_url"; image_url = @{ url = $dataUrl } }
        ) }
    )
    $out = Invoke-TextModel -Messages $messages -Config $Config -TimeoutSec 180
    if ($out -and $out.Text) {
        return [pscustomobject]@{
            Text = ($out.Text -replace '^```[a-z]*', '' -replace '```$', '').Trim()
            InputTokens = [int]$out.InputTokens
            OutputTokens = [int]$out.OutputTokens
        }
    }
    return $null
}

# Decomposes a narrative text into a shared "style bible" and N scene
# descriptions, via the text model. Returns an object { style_bible; scenes }
# or $null on error (invalid JSON, insufficient scenes, model not configured).
function Invoke-StoryboardDecompose {
    param([string]$Narrative, [int]$Count, $Config)
    $sys = "You are an expert storyboard director and cinematographer for AI image generation. Decompose the user's narrative into exactly $Count sequential scenes that together tell the story with clear visual progression (beginning, development, resolution): each scene must advance the story and differ meaningfully from the others in action, framing or moment.`n`nFirst produce a STYLE BIBLE: one reusable, detailed paragraph that locks the visual identity of the whole sequence. It MUST fix: the colour palette, the art technique/medium, the era/setting, the overall mood and lighting style, and — critically — a precise, unchanging physical description of EVERY recurring character (age, build, hair, face, distinctive features and exact clothing), so the same character looks identical in every image. Name each recurring character so scenes can refer to them unambiguously.`n`nThen write the scenes. Each scene description must: be fully self-contained and purely visual (describe only what is in frame, not narration or sound); reference recurring characters by the same name and keep their fixed appearance from the style bible; specify the shot type and camera angle (e.g. wide establishing shot, medium shot, close-up, low angle) and the composition; maintain continuity of place, time of day and props with the adjacent scenes unless the story requires a change. Vary the shot types across the sequence for visual rhythm. Write in the same language as the narrative.`n`nRespond ONLY with valid JSON, no markdown fences, in this exact shape: {`"style_bible`": `"...`", `"scenes`": [`"scene 1 description`", `"...`"]}."
    $messages = @(
        @{ role = "system"; content = $sys }
        @{ role = "user";   content = $Narrative }
    )
    # The storyboard produces a lot of text (style bible + N scenes in JSON) and often runs
    # on reasoning models: it needs a large token budget, otherwise the reasoning
    # consumes everything and the response comes back empty. I scale the budget with the number of scenes.
    $sbBudget = [math]::Max(8192, 2048 + $Count * 700)
    $out = Invoke-TextModel -Messages $messages -Config $Config -MaxTokensOverride $sbBudget
    if (-not $out -or -not $out.Text) { return $null }
    $jsonText = ($out.Text -replace '^```[a-z]*', '' -replace '```$', '').Trim()
    try {
        $obj = $jsonText | ConvertFrom-Json -ErrorAction Stop
    } catch {
        Write-Log (T 'story.decompose_failed' ($_.Exception.Message)) -Level ERROR
        return $null
    }
    $scenes = @($obj.scenes)
    if (-not $obj.style_bible -or $scenes.Count -lt $Count) {
        Write-Log (T 'story.decompose_failed' ("style_bible or scenes missing: " + $scenes.Count + "/" + $Count)) -Level ERROR
        return $null
    }
    return [pscustomobject]@{
        StyleBible   = [string]$obj.style_bible
        Scenes       = @($scenes | Select-Object -First $Count | ForEach-Object { [string]$_ })
        InputTokens  = [int]$out.InputTokens
        OutputTokens = [int]$out.OutputTokens
    }
}

# =================================================================
# IaC (Infrastructure as Code) — Increment 1
# Generates the Azure CLI provisioning script to create the infrastructure
# needed to run New-GPTImage: Resource Group, Foundry resource
# (Microsoft.CognitiveServices/accounts kind=AIServices) and a Foundry Project.
# Format: pure 'az' commands (single dependency: only the Azure CLI).
# =================================================================

# Pre-flight (RF-2): verifies that the environment is ready for the IaC. Checks the
# presence of the 'az' CLI, an active login and a selected subscription. It does NOT run
# anything invasive: only reads (az version, az account show). Returns an object
# with Ready (bool) and the detected details; problems are logged with the command
# to fix them, never run automatically.
function Test-IaCPrerequisites {
    $result = [pscustomobject]@{
        Ready          = $false
        AzPresent      = $false
        AzVersion      = ""
        LoggedIn       = $false
        Account        = ""
        SubscriptionId = ""
        SubscriptionName = ""
        TenantId       = ""
    }

    # 1. Presence of the az CLI in the PATH
    $azCmd = Get-Command az -ErrorAction SilentlyContinue
    if (-not $azCmd) {
        Write-Log (T 'iac.az_not_found') -Level ERROR
        Write-Log (T 'iac.az_install_hint') -Level INFO
        return $result
    }
    $result.AzPresent = $true

    # 2. az version (informational). 'az version' emits JSON.
    try {
        $verJson = az version --output json 2>$null | ConvertFrom-Json -ErrorAction Stop
        if ($verJson -and $verJson.'azure-cli') {
            $result.AzVersion = [string]$verJson.'azure-cli'
            Write-Log (T 'iac.az_version' $result.AzVersion) -Level INFO
        }
    } catch {
        # Non-blocking: if I cannot read the version, I proceed anyway.
        Write-Log (T 'iac.az_version_unknown') -Level WARN
    }

    # 3. Active login and selected subscription (az account show -> JSON)
    try {
        $acct = az account show --output json 2>$null | ConvertFrom-Json -ErrorAction Stop
        if ($acct -and $acct.id) {
            $result.LoggedIn       = $true
            $result.Account        = [string]$acct.user.name
            $result.SubscriptionId = [string]$acct.id
            $result.SubscriptionName = [string]$acct.name
            $result.TenantId       = [string]$acct.tenantId
            Write-Log (T 'iac.account_active' $result.Account $acct.name) -Level INFO
            Write-Log (T 'iac.subscription' $result.SubscriptionId) -Level INFO
        }
    } catch {
        Write-Log (T 'iac.not_logged_in') -Level ERROR
        Write-Log (T 'iac.login_hint') -Level INFO
        return $result
    }

    $result.Ready = ($result.AzPresent -and $result.LoggedIn)
    return $result
}

# Sanitizes a name for use as an Azure resource name: lowercase, only letters/digits/
# hyphens, no leading/trailing hyphens, limited length. This way the generated names
# respect Azure's constraints even if the user passes something non-conforming.
function Get-IaCSafeName {
    param([string]$Name, [int]$MaxLen = 24)
    $n = $Name.ToLower()
    $n = $n -replace '[^a-z0-9-]', ''
    $n = $n.Trim('-')
    if ($n.Length -gt $MaxLen) { $n = $n.Substring(0, $MaxLen) }
    $n = $n.Trim('-')
    return $n
}

# Generator (RF-4, generate mode): produces the text of a provisioning
# script made of pure 'az' commands. It does NOT run anything: it returns the string.
# For Increment 1 it covers Resource Group + Foundry resource + Project. App Insights,
# model deployment, dry-run/execute and the wizard arrive in the later increments.
function New-IaCProvisioningScript {
    param(
        [string]$ResourceGroup,
        [string]$Region,
        [string]$FoundryName,
        [string]$ProjectName,
        [string]$SubscriptionId,
        [bool]$IncludeTelemetry = $true,
        [string]$LogAnalyticsName = "",
        [string]$AppInsightsName = "",
        [bool]$DeployModel = $false,
        [string]$ModelName = "",
        [string]$ModelVersion = "",
        [string]$ModelFormat = "OpenAI",
        [string]$ModelSku = "GlobalStandard",
        [int]$ModelCapacity = 1,
        [string]$DeploymentName = ""
    )

    # customSubDomainName is required to enable the Foundry Projects on the
    # CognitiveServices resource (together with --allow-project-management). I use the
    # resource name as the subdomain: it must be globally unique.
    $subdomain = $FoundryName

    $sb = [System.Text.StringBuilder]::new()
    [void]$sb.AppendLine("#!/usr/bin/env bash")
    [void]$sb.AppendLine("# ============================================================")
    [void]$sb.AppendLine("# New-GPTImage - Infrastructure provisioning script (IaC)")
    [void]$sb.AppendLine("# Generato il $((Get-Date).ToString('yyyy-MM-dd HH:mm:ss'))")
    [void]$sb.AppendLine("# Model: single-resource Foundry (CognitiveServices kind=AIServices)")
    [void]$sb.AppendLine("# Dependency: Azure CLI (az). Run after 'az login'.")
    [void]$sb.AppendLine("# ============================================================")
    [void]$sb.AppendLine("set -e")
    [void]$sb.AppendLine("")
    [void]$sb.AppendLine("# --- Parameters ---")
    [void]$sb.AppendLine("SUBSCRIPTION_ID=`"$SubscriptionId`"")
    [void]$sb.AppendLine("RESOURCE_GROUP=`"$ResourceGroup`"")
    [void]$sb.AppendLine("REGION=`"$Region`"")
    [void]$sb.AppendLine("FOUNDRY_NAME=`"$FoundryName`"")
    [void]$sb.AppendLine("PROJECT_NAME=`"$ProjectName`"")
    [void]$sb.AppendLine("SUBDOMAIN=`"$subdomain`"")
    if ($IncludeTelemetry) {
        [void]$sb.AppendLine("LOG_ANALYTICS_NAME=`"$LogAnalyticsName`"")
        [void]$sb.AppendLine("APP_INSIGHTS_NAME=`"$AppInsightsName`"")
    }
    if ($DeployModel) {
        [void]$sb.AppendLine("DEPLOYMENT_NAME=`"$DeploymentName`"")
        [void]$sb.AppendLine("MODEL_NAME=`"$ModelName`"")
        [void]$sb.AppendLine("MODEL_FORMAT=`"$ModelFormat`"")
        [void]$sb.AppendLine("MODEL_SKU=`"$ModelSku`"")
        [void]$sb.AppendLine("MODEL_CAPACITY=`"$ModelCapacity`"")
        [void]$sb.AppendLine("MODEL_VERSION=`"$ModelVersion`"")
    }
    [void]$sb.AppendLine("")
    [void]$sb.AppendLine("# Select the target subscription")
    [void]$sb.AppendLine("az account set --subscription `"`$SUBSCRIPTION_ID`"")
    [void]$sb.AppendLine("")
    [void]$sb.AppendLine("# --- 1. Resource Group ---")
    [void]$sb.AppendLine("az group create \")
    [void]$sb.AppendLine("  --name `"`$RESOURCE_GROUP`" \")
    [void]$sb.AppendLine("  --location `"`$REGION`"")
    [void]$sb.AppendLine("")
    [void]$sb.AppendLine("# --- 2. Foundry resource (CognitiveServices kind=AIServices) ---")
    [void]$sb.AppendLine("# --allow-project-management (without value) enables Foundry Projects.")
    [void]$sb.AppendLine("az cognitiveservices account create \")
    [void]$sb.AppendLine("  --name `"`$FOUNDRY_NAME`" \")
    [void]$sb.AppendLine("  --resource-group `"`$RESOURCE_GROUP`" \")
    [void]$sb.AppendLine("  --location `"`$REGION`" \")
    [void]$sb.AppendLine("  --kind AIServices \")
    [void]$sb.AppendLine("  --sku S0 \")
    [void]$sb.AppendLine("  --allow-project-management \")
    [void]$sb.AppendLine("  --yes")
    [void]$sb.AppendLine("")
    [void]$sb.AppendLine("# --- 2b. Custom subdomain (required for Projects; separate command) ---")
    [void]$sb.AppendLine("# Il sottodominio deve essere univoco a livello globale.")
    [void]$sb.AppendLine("az cognitiveservices account update \")
    [void]$sb.AppendLine("  --name `"`$FOUNDRY_NAME`" \")
    [void]$sb.AppendLine("  --resource-group `"`$RESOURCE_GROUP`" \")
    [void]$sb.AppendLine("  --custom-domain `"`$SUBDOMAIN`"")
    [void]$sb.AppendLine("")
    [void]$sb.AppendLine("# --- 3. Foundry Project (child of the resource) ---")
    [void]$sb.AppendLine("# Note: --name is the parent RESOURCE, --project-name is the project.")
    [void]$sb.AppendLine("az cognitiveservices account project create \")
    [void]$sb.AppendLine("  --name `"`$FOUNDRY_NAME`" \")
    [void]$sb.AppendLine("  --resource-group `"`$RESOURCE_GROUP`" \")
    [void]$sb.AppendLine("  --project-name `"`$PROJECT_NAME`" \")
    [void]$sb.AppendLine("  --location `"`$REGION`"")
    [void]$sb.AppendLine("")
    if ($IncludeTelemetry) {
        [void]$sb.AppendLine("# --- 4. Log Analytics Workspace (backing for Application Insights) ---")
        [void]$sb.AppendLine("az monitor log-analytics workspace create \")
        [void]$sb.AppendLine("  --resource-group `"`$RESOURCE_GROUP`" \")
        [void]$sb.AppendLine("  --workspace-name `"`$LOG_ANALYTICS_NAME`" \")
        [void]$sb.AppendLine("  --location `"`$REGION`"")
        [void]$sb.AppendLine("")
        [void]$sb.AppendLine("# Retrieve the workspace resource ID to link it to App Insights.")
        [void]$sb.AppendLine("LAW_ID=`$(az monitor log-analytics workspace show \")
        [void]$sb.AppendLine("  --resource-group `"`$RESOURCE_GROUP`" \")
        [void]$sb.AppendLine("  --workspace-name `"`$LOG_ANALYTICS_NAME`" \")
        [void]$sb.AppendLine("  --query id --output tsv)")
        [void]$sb.AppendLine("")
        [void]$sb.AppendLine("# --- 5. Application Insights (workspace-based) for telemetry ---")
        [void]$sb.AppendLine("# L'estensione application-insights non e' inclusa di default in az.")
        [void]$sb.AppendLine("az extension add --name application-insights --only-show-errors 2>/dev/null || true")
        [void]$sb.AppendLine("az monitor app-insights component create \")
        [void]$sb.AppendLine("  --app `"`$APP_INSIGHTS_NAME`" \")
        [void]$sb.AppendLine("  --resource-group `"`$RESOURCE_GROUP`" \")
        [void]$sb.AppendLine("  --location `"`$REGION`" \")
        [void]$sb.AppendLine("  --workspace `"`$LAW_ID`" \")
        [void]$sb.AppendLine("  --application-type web")
        [void]$sb.AppendLine("")
        [void]$sb.AppendLine("# App Insights connection string: needed by the script for telemetry")
        [void]$sb.AppendLine("# (conf telemetry.azureMonitor). Stampala per copiarla nel .conf.")
        [void]$sb.AppendLine("echo `"Application Insights connection string:`"")
        [void]$sb.AppendLine("az monitor app-insights component show \")
        [void]$sb.AppendLine("  --app `"`$APP_INSIGHTS_NAME`" \")
        [void]$sb.AppendLine("  --resource-group `"`$RESOURCE_GROUP`" \")
        [void]$sb.AppendLine("  --query connectionString --output tsv")
        [void]$sb.AppendLine("")
        [void]$sb.AppendLine("# NOTE: the Workbook with the telemetry charts (15 charts) is created")
        [void]$sb.AppendLine("# by the script's -IaCMode execute mode, not by this provision.sh,")
        [void]$sb.AppendLine("# because its content is a JSON too large to be handled here.")
        [void]$sb.AppendLine("# To get it, run: New-GPTImage.ps1 -IaC -IaCMode execute ...")
        [void]$sb.AppendLine("")
    }
    if ($DeployModel) {
        [void]$sb.AppendLine("# --- 6. Image model deployment (OPTIONAL) ---")
        [void]$sb.AppendLine("# Availability depends on region and quotas: this step can fail")
        [void]$sb.AppendLine("# without invalidating the infrastructure already created above.")
        [void]$sb.AppendLine("az cognitiveservices account deployment create \")
        [void]$sb.AppendLine("  --name `"`$FOUNDRY_NAME`" \")
        [void]$sb.AppendLine("  --resource-group `"`$RESOURCE_GROUP`" \")
        [void]$sb.AppendLine("  --deployment-name `"`$DEPLOYMENT_NAME`" \")
        [void]$sb.AppendLine("  --model-name `"`$MODEL_NAME`" \")
        [void]$sb.AppendLine("  --model-format `"`$MODEL_FORMAT`" \")
        [void]$sb.AppendLine("  --model-version `"`$MODEL_VERSION`" \")
        [void]$sb.AppendLine("  --sku-name `"`$MODEL_SKU`" \")
        [void]$sb.AppendLine("  --sku-capacity `"`$MODEL_CAPACITY`" || echo `"WARNING: model deployment failed (region/quota?). Infrastructure created anyway.`"")
        [void]$sb.AppendLine("")
    }
    [void]$sb.AppendLine("# --- Done ---")
    [void]$sb.AppendLine("echo `"Infrastructure created. Foundry endpoint:`"")
    [void]$sb.AppendLine("az cognitiveservices account show \")
    [void]$sb.AppendLine("  --name `"`$FOUNDRY_NAME`" \")
    [void]$sb.AppendLine("  --resource-group `"`$RESOURCE_GROUP`" \")
    [void]$sb.AppendLine("  --query `"properties.endpoint`" --output tsv")

    # CRITICAL: provision.sh is a bash script, it must use LF line endings.
    # StringBuilder.AppendLine uses Environment.NewLine (CRLF on Windows): I convert
    # every CRLF (and every isolated CR) to LF, otherwise bash reads a \r on each line
    # and all the commands fail.
    $text = $sb.ToString()
    $text = $text -replace "`r`n", "`n"
    $text = $text -replace "`r", "`n"
    return $text
}

# Orchestrator of the -IaC command (Increment 1: generate mode only). Resolves the
# parameters (from the command line or defaults), runs the pre-flight, generates the script and
# saves it in a dedicated folder. The dry-run/execute modes and the interactive
# wizard arrive in the later increments.
# Runs the provisioning steps directly via the az CLI from PowerShell (execute
# mode). Each step is an az command invoked with argument splatting; the
# errors interrupt the sequence (like 'set -e' in the bash script). Returns $true
# only if all the steps succeed. It does NOT handle rollback: on
# error the already-created resources remain (idempotency/teardown arrives in Inc. 3).
# Derives a default version for the known image models, used when the user
# does not pass -IaCModelVersion (az requires --model-version as mandatory). For models
# not in the list it returns an empty string: in that case the user MUST provide the version.
function Get-IaCDefaultModelVersion {
    param([string]$ModelName)
    switch -Wildcard ($ModelName.ToLower()) {
        'gpt-image-1*'   { return '2025-04-15' }
        'dall-e-3'       { return '3.0' }
        default          { return '' }
    }
}

# Idempotently checks whether a CognitiveServices resource already exists. Returns $true
# if it exists, so the creation steps can be skipped on a rerun (RF-7).
# Generates a DETERMINISTIC GUID from a string (MD5 hash -> GUID format). It serves to
# give the workbook a stable name across runs: rerunning the IaC acts on the
# same workbook instead of creating a new one each time. It is not a cryptographic GUID
# (MD5 is fine for this purpose: it only needs to be repeatable and well distributed).
function New-IaCDeterministicGuid {
    param([string]$InputString)
    $md5 = [System.Security.Cryptography.MD5]::Create()
    try {
        $bytes = $md5.ComputeHash([System.Text.Encoding]::UTF8.GetBytes($InputString))
        return ([guid]::new($bytes)).ToString()
    } finally {
        $md5.Dispose()
    }
}

# Builds the serialized JSON of an Azure Monitor Workbook with the New-GPTImage
# telemetry charts. The charts are "empty at time zero" and populate as
# the script sends data to Application Insights. The KQL queries run
# when the workbook is opened (not at deploy time), so an empty App Insights simply shows
# empty charts, with no errors. The result is a JSON string ready
# for the --serialized-data parameter of 'az monitor app-insights workbook create'.
#
# NB: the charts reprise the concepts of -Analytics (cost per day/month, per
# model, images per model) and expand them with the extended metrics (input/output/text/
# image tokens, broken-down costs, per-image metrics, performance).
function Get-IaCWorkbookJson {
    # Helper: creates a query "item" (chart) of the workbook. $Viz determines the
    # chart type: 'barchart', 'linechart', 'timechart', 'piechart', 'table'.
    # $DurationMs sets the chart's default time window (for "per year" charts
    # a wide window is needed, otherwise the older data is not visible).
    function New-WbQueryItem {
        param([string]$Title, [string]$Query, [string]$Viz, [int]$Size = 0, [long]$DurationMs = 2592000000, $ChartSettings = $null)
        $content = [ordered]@{
            version          = "KqlItem/1.0"
            query            = $Query
            size             = $Size
            title            = $Title
            timeContext      = [ordered]@{ durationMs = $DurationMs }
            queryType        = 0
            resourceType     = "microsoft.insights/components"
            visualization    = $Viz
        }
        # Optional chartSettings: for charts with dates on the X axis we use the label
        # as a string (no spurious "12:00" hour ticks), but we fix the order
        # on the X axis via the sortable key column, so they stay chronological.
        if ($ChartSettings) { $content.chartSettings = $ChartSettings }
        return [ordered]@{
            type = 3
            content = $content
            name = "query-" + ([guid]::NewGuid().ToString('N').Substring(0,8))
        }
    }
    # Helper: creates a text "item" (section header).
    function New-WbTextItem {
        param([string]$Markdown)
        return [ordered]@{
            type = 1
            content = [ordered]@{ json = $Markdown }
            name = "text-" + ([guid]::NewGuid().ToString('N').Substring(0,8))
        }
    }

    # Helper: builds a KQL query for time-based bar/line charts, with
    # the X axis as a readable STRING (dd/MM/yy or MM/yyyy) to prevent Azure from
    # treating it as a time axis and inserting spurious "12:00" hour ticks. To
    # prevent the barcharts from reordering the bars by Y value, the result set also includes
    # a sortable key column 'k' (yyyy-MM-dd / yyyy-MM): the chronological
    # ordering is then fixed via chartSettings (see $dateChartSettings).
    # Parameters:
    #   -Series: array @{ name=<column>; agg=<sum|avg>; field=<customMeasurements.X> }
    #   -Step:   "1d" for days, "30d" for months
    #   -XName:  X-axis column name (Day/Month)
    function Get-WbTimeSeriesQuery {
        param(
            [string]$BaseQuery,
            [array]$Series,
            [string]$Step,
            [string]$XName
        )
        if ($Step -eq "30d") {
            $kExpr = 'format_datetime(timestamp, "yyyy-MM")'
            $labelExpr = 'format_datetime(timestamp, "MM/yyyy")'
        } else {
            $kExpr = 'format_datetime(timestamp, "yyyy-MM-dd")'
            $labelExpr = 'format_datetime(timestamp, "dd/MM/yy")'
        }
        # summarize by k (sortable) + label; series aggregations
        $aggParts = @()
        foreach ($s in $Series) {
            $aggParts += ("{0} = {1}(todouble({2}))" -f $s.name, $s.agg, $s.field)
        }
        $aggStr = $aggParts -join ", "
        # project: label (X axis), k (for the sort via chartSettings), series
        $projParts = @($XName, "k")
        foreach ($s in $Series) { $projParts += $s.name }
        $projStr = $projParts -join ", "

        return ("{0} | extend k = {1}, {2} = {3} | summarize {4} by k, {2} | order by k asc | project {5}" -f `
            $BaseQuery, $kExpr, $XName, $labelExpr, $aggStr, $projStr)
    }


    # Time windows (in ms) for the charts at different granularity.
    $D30  = 2592000000      # 30 days
    $D365 = 31536000000     # 365 days
    $D3Y  = 94608000000     # ~3 years (for the "per year" view)

    # Common base of the queries: filters the script's telemetry events.
    $base = 'customEvents | where name == "ImageGeneration"'

    # Time-based X axis: the daily/monthly charts use Get-WbTimeSeriesQuery
    # (make-series), which generates a continuous fixed-step series avoiding the hour
    # ticks. The yearly ones, few points, stay on a simple summarize.
    $yearKey  = 'extend Year = startofyear(timestamp)'

    # chartSettings for the day/month charts: the X axis is the string label (Day/
    # Month), but the bar ordering is fixed on the key column 'k'
    # (chronological) in ascending order, so Azure does NOT reorder them by Y value.
    # 'xAxis' indicates the X-axis column; 'group'/'sortBy' drive the ordering.
    $chartDay = [ordered]@{
        xAxis  = "Day"
        sortBy = @( [ordered]@{ field = "k"; order = 1 } )
    }
    $chartMonth = [ordered]@{
        xAxis  = "Month"
        sortBy = @( [ordered]@{ field = "k"; order = 1 } )
    }

    $items = @()
    $items += New-WbTextItem "# New-GPTImage - Image generation telemetry`n`nThe charts populate as the script generates images with telemetry active (telemetry.azureMonitor=true). If they are empty, no data has arrived yet."

    # ===================== COSTS =====================
    $items += New-WbTextItem "## Costs"
    # Cost per day (label dd/mm/yy)
    $items += New-WbQueryItem "Total cost per day (EUR)" `
        (Get-WbTimeSeriesQuery $base @(@{name="CostEUR"; agg="sum"; field="customMeasurements.costEur"}) "1d" "Day") 'barchart' 0 $D30 $chartDay
    # Cost per month (label mm/yyyy)
    $items += New-WbQueryItem "Total cost per month (EUR)" `
        (Get-WbTimeSeriesQuery $base @(@{name="CostEUR"; agg="sum"; field="customMeasurements.costEur"}) "30d" "Month") 'barchart' 0 $D365 $chartMonth
    # Cost per year (label yyyy)
    $items += New-WbQueryItem "Total cost per year (EUR)" `
        ($base + ' | ' + $yearKey + ' | summarize CostEUR = sum(todouble(customMeasurements.costEur)) by Year | order by Year asc') 'barchart' 0 $D3Y
    # Average cost per image over time
    $items += New-WbQueryItem "Average cost per image (EUR) per day" `
        (Get-WbTimeSeriesQuery $base @(@{name="AvgCostPerImage"; agg="avg"; field="customMeasurements.costPerImageEur"}) "1d" "Day") 'linechart' 0 $D30 $chartDay
    # Input vs output cost over time
    $items += New-WbQueryItem "Input vs output cost (EUR) per day" `
        (Get-WbTimeSeriesQuery $base @(@{name="Input"; agg="sum"; field="customMeasurements.inputCostEur"}, @{name="Output"; agg="sum"; field="customMeasurements.outputCostEur"}) "1d" "Day") 'barchart' 0 $D30 $chartDay
    # Cost per model
    $items += New-WbQueryItem "Total cost per model (EUR)" `
        ($base + ' | summarize CostEUR = sum(todouble(customMeasurements.costEur)) by Model = tostring(customDimensions.model) | order by CostEUR desc') 'barchart' 0 $D365
    # Cost per model and quality
    $items += New-WbQueryItem "Cost per model and quality (EUR)" `
        ($base + ' | summarize CostEUR = sum(todouble(customMeasurements.costEur)) by Model = tostring(customDimensions.model), Quality = tostring(customDimensions.quality) | order by CostEUR desc') 'table' 0 $D365

    # ===================== TOKENS =====================
    $items += New-WbTextItem "## Tokens"
    $items += New-WbQueryItem "Total tokens per day" `
        (Get-WbTimeSeriesQuery $base @(@{name="Token"; agg="sum"; field="customMeasurements.totalTokens"}) "1d" "Day") 'barchart' 0 $D30 $chartDay
    $items += New-WbQueryItem "Input vs output tokens per day" `
        (Get-WbTimeSeriesQuery $base @(@{name="Input"; agg="sum"; field="customMeasurements.inputTokens"}, @{name="Output"; agg="sum"; field="customMeasurements.outputTokens"}) "1d" "Day") 'barchart' 0 $D30 $chartDay
    $items += New-WbQueryItem "Text vs image tokens per day" `
        (Get-WbTimeSeriesQuery $base @(@{name="Text"; agg="sum"; field="customMeasurements.textTokens"}, @{name="Image"; agg="sum"; field="customMeasurements.imageTokens"}) "1d" "Day") 'barchart' 0 $D30 $chartDay
    $items += New-WbQueryItem "Average tokens per image per day" `
        (Get-WbTimeSeriesQuery $base @(@{name="AvgTokensPerImage"; agg="avg"; field="customMeasurements.tokensPerImage"}) "1d" "Day") 'linechart' 0 $D30 $chartDay

    # ===================== TEXT MODEL COST =====================
    # Separate "TextModelCost" events (optimize/negative/storyboard/describe): tracked
    # apart from the image costs. Dedicated base query on that event.
    $baseText = 'customEvents | where name == "TextModelCost"'
    $items += New-WbTextItem "## Text model cost`n`nCost of the text model used for prompt optimization and negative prompt (tracked separately from the image costs). Requires the prices set in textModel.inputUsdPerMillion/outputUsdPerMillion in the .conf."
    $items += New-WbQueryItem "Text model cost per day (EUR)" `
        (Get-WbTimeSeriesQuery $baseText @(@{name="TextCostEUR"; agg="sum"; field="customMeasurements.textCostEur"}) "1d" "Day") 'barchart' 0 $D30 $chartDay
    $items += New-WbQueryItem "Text tokens (input vs output) per day" `
        (Get-WbTimeSeriesQuery $baseText @(@{name="Input"; agg="sum"; field="customMeasurements.textInputTokens"}, @{name="Output"; agg="sum"; field="customMeasurements.textOutputTokens"}) "1d" "Day") 'barchart' 0 $D30 $chartDay
    $items += New-WbQueryItem "Total text cost (EUR)" `
        ($baseText + ' | summarize TextCostEUR = sum(todouble(customMeasurements.textCostEur))') 'tiles' 0 $D365
    # Text model cost per FUNCTION (operation: optimize/negative/storyboard/describe).
    $items += New-WbQueryItem "Text model cost per function (EUR)" `
        ($baseText + ' | summarize CostEUR = sum(todouble(customMeasurements.textCostEur)) by Function = tostring(customDimensions.operation) | order by CostEUR desc') 'piechart' 0 $D365

    # ===================== IMAGES =====================
    $items += New-WbTextItem "## Images"
    # Images per day / month / year
    $items += New-WbQueryItem "Images generated per day" `
        (Get-WbTimeSeriesQuery $base @(@{name="Images"; agg="sum"; field="customMeasurements.images"}) "1d" "Day") 'barchart' 0 $D30 $chartDay
    $items += New-WbQueryItem "Images generated per month" `
        (Get-WbTimeSeriesQuery $base @(@{name="Images"; agg="sum"; field="customMeasurements.images"}) "30d" "Month") 'barchart' 0 $D365 $chartMonth
    $items += New-WbQueryItem "Images generated per year" `
        ($base + ' | ' + $yearKey + ' | summarize Images = sum(todouble(customMeasurements.images)) by Year | order by Year asc') 'barchart' 0 $D3Y
    # Images per model (pie)
    $items += New-WbQueryItem "Images generated per model" `
        ($base + ' | summarize Images = sum(todouble(customMeasurements.images)) by Model = tostring(customDimensions.model) | order by Images desc') 'piechart' 0 $D365

    # ===================== USAGE PARAMETERS =====================
    $items += New-WbTextItem "## Usage parameters"
    # Most used sizes (general)
    $items += New-WbQueryItem "Most used sizes" `
        ($base + ' | summarize Generations = count() by Dimension = tostring(customDimensions.size) | order by Generations desc') 'piechart' 0 $D365
    # Size per model
    $items += New-WbQueryItem "Sizes per model" `
        ($base + ' | summarize Generations = count() by Model = tostring(customDimensions.model), Dimension = tostring(customDimensions.size) | order by Generations desc') 'table' 0 $D365
    # Most used qualities
    $items += New-WbQueryItem "Most used qualities" `
        ($base + ' | summarize Generations = count() by Quality = tostring(customDimensions.quality) | order by Generations desc') 'piechart' 0 $D365
    # Distribution by size and quality
    $items += New-WbQueryItem "Distribution by size and quality" `
        ($base + ' | summarize Generations = count() by Dimension = tostring(customDimensions.size), Quality = tostring(customDimensions.quality) | order by Generations desc') 'table' 0 $D365
    # Generations by source (cli/tui/batch)
    $items += New-WbQueryItem "Generations per source (CLI/TUI/batch)" `
        ($base + ' | summarize Generations = count() by Source = tostring(customDimensions.source) | order by Generations desc') 'piechart' 0 $D365

    # ===================== FUNCTIONS / STORYBOARD =====================
    $items += New-WbTextItem "## Functions and storyboard"
    # Most used features: I count the generations per source as a proxy
    # of the modes. NOTE: optimize/negative/storyboard are not yet dedicated
    # properties in the telemetry; until they are, this chart shows the
    # breakdown by source, and the storyboard is identifiable from the following
    # sub-charts based on the generations with several images in sequence.
    $items += New-WbQueryItem "Generations per source" `
        ($base + ' | summarize Generations = count() by Source = tostring(customDimensions.source) | order by Generations desc') 'barchart' 0 $D365
    # Storyboard: storyboard generations typically have several images. I show the
    # distribution of the number of images per generation (a proxy of the length
    # of the sequences): how many generations have 1, 2, 3... images.
    $items += New-WbQueryItem "Distribution of images per generation (sequences)" `
        ($base + ' | summarize Generations = count() by ImagesPerGeneration = toint(todouble(customMeasurements.images)) | order by ImagesPerGeneration asc') 'barchart' 0 $D365
    # Models most used for multi-image generations (storyboard proxy: images > 1)
    $items += New-WbQueryItem "Models most used for sequences (images > 1)" `
        ($base + ' | where todouble(customMeasurements.images) > 1 | summarize Sequences = count() by Model = tostring(customDimensions.model) | order by Sequences desc') 'barchart' 0 $D365
    # Average images per sequence, per model (multi-image only)
    $items += New-WbQueryItem "Average images per sequence, per model" `
        ($base + ' | where todouble(customMeasurements.images) > 1 | summarize AvgImages = avg(todouble(customMeasurements.images)) by Model = tostring(customDimensions.model) | order by AvgImages desc') 'barchart' 0 $D365

    # ===================== PERFORMANCE =====================
    $items += New-WbTextItem "## Performance"
    $items += New-WbQueryItem "Average generation duration (sec) per day" `
        (Get-WbTimeSeriesQuery $base @(@{name="AvgDurationSec"; agg="avg"; field="customMeasurements.durationSec"}) "1d" "Day") 'linechart' 0 $D30 $chartDay
    $items += New-WbQueryItem "Seconds per image per day" `
        (Get-WbTimeSeriesQuery $base @(@{name="SecPerImage"; agg="avg"; field="customMeasurements.secPerImage"}) "1d" "Day") 'linechart' 0 $D30 $chartDay
    # Average duration per model
    $items += New-WbQueryItem "Average duration (sec) per model" `
        ($base + ' | summarize AvgDurationSec = avg(todouble(customMeasurements.durationSec)) by Model = tostring(customDimensions.model) | order by AvgDurationSec desc') 'barchart' 0 $D365

    $wb = [ordered]@{
        version           = "Notebook/1.0"
        items             = $items
        isLocked          = $false
        fallbackResourceIds = @("Azure Monitor")
    }
    return ($wb | ConvertTo-Json -Depth 20 -Compress)
}



# Counts the charts (query-type items) in the workbook JSON, for messages always
# aligned to the real number without hardcoding the figure.
function Get-IaCWorkbookChartCount {
    try {
        $wb = (Get-IaCWorkbookJson) | ConvertFrom-Json
        return @($wb.items | Where-Object { $_.type -eq 3 }).Count
    } catch {
        return 0
    }
}

function Test-IaCResourceExists {
    param([string]$ResourceGroup, [string]$FoundryName)
    $null = & az cognitiveservices account show --name $FoundryName --resource-group $ResourceGroup --query id --output tsv 2>$null
    return ($LASTEXITCODE -eq 0)
}

# Checks whether the Foundry Project already exists (idempotency of the Project step).
function Test-IaCProjectExists {
    param([string]$ResourceGroup, [string]$FoundryName, [string]$ProjectName)
    $null = & az cognitiveservices account project show --name $FoundryName --resource-group $ResourceGroup --project-name $ProjectName --query id --output tsv 2>$null
    return ($LASTEXITCODE -eq 0)
}

# Checks whether the Log Analytics Workspace already exists.
function Test-IaCLogAnalyticsExists {
    param([string]$ResourceGroup, [string]$WorkspaceName)
    $null = & az monitor log-analytics workspace show --resource-group $ResourceGroup --workspace-name $WorkspaceName --query id --output tsv 2>$null
    return ($LASTEXITCODE -eq 0)
}

# Checks whether the Application Insights resource already exists.
function Test-IaCAppInsightsExists {
    param([string]$ResourceGroup, [string]$AppInsightsName)
    $null = & az monitor app-insights component show --app $AppInsightsName --resource-group $ResourceGroup --query id --output tsv 2>$null
    return ($LASTEXITCODE -eq 0)
}

# Checks whether the Foundry resource exists in a SOFT-DELETED state. The
# CognitiveServices resources are not deleted immediately: after a delete/teardown they stay
# recoverable for a few days, and in that state it is not possible to recreate one
# with the same name without first restoring or purging it. Returns $true if the
# resource is soft-deleted in the indicated region.
function Test-IaCResourceSoftDeleted {
    param([string]$ResourceGroup, [string]$FoundryName, [string]$Region)
    $null = & az cognitiveservices account show-deleted --name $FoundryName --resource-group $ResourceGroup --location $Region --query id --output tsv 2>$null
    return ($LASTEXITCODE -eq 0)
}

# Checks whether a model deployment already exists on the resource (idempotency).
function Test-IaCDeploymentExists {
    param([string]$ResourceGroup, [string]$FoundryName, [string]$DeploymentName)
    $null = & az cognitiveservices account deployment show --name $FoundryName --resource-group $ResourceGroup --deployment-name $DeploymentName --query id --output tsv 2>$null
    return ($LASTEXITCODE -eq 0)
}

# Teardown (RF-7): tears down the infrastructure by deleting the Resource Group with all
# its content. DESTRUCTIVE and irreversible operation: requires explicit confirmation
# by typing the resource group name (double safety).
function Invoke-IaCTeardown {
    param([string]$ResourceGroup)

    Write-Log (T 'iac.teardown_start') -Level INFO

    $pre = Test-IaCPrerequisites
    if (-not $pre.Ready) {
        Write-Log (T 'iac.preflight_failed') -Level ERROR
        return $false
    }

    if (-not $ResourceGroup) {
        Write-Log (T 'iac.teardown_no_rg') -Level ERROR
        return $false
    }

    # I verify that the resource group exists before proposing its deletion.
    $null = & az group show --name $ResourceGroup --query id --output tsv 2>$null
    if ($LASTEXITCODE -ne 0) {
        Write-Log (T 'iac.teardown_rg_not_found' $ResourceGroup) -Level ERROR
        return $false
    }

    # List what will be deleted, so the user knows exactly what they lose.
    Write-Log (T 'iac.teardown_warning' $ResourceGroup) -Level WARN
    $resList = & az resource list --resource-group $ResourceGroup --query "[].{name:name, type:type}" --output tsv 2>$null
    if ($resList) {
        Write-Log (T 'iac.teardown_resources') -Level INFO
        foreach ($line in @($resList)) {
            if ($line.Trim()) { Write-Log ("  - " + $line) -Level INFO }
        }
    }

    # Double safety: to proceed the user must type EXACTLY the RG name.
    $typed = Read-Host (T 'iac.teardown_confirm_prompt' $ResourceGroup)
    if ($typed.Trim() -cne $ResourceGroup) {
        Write-Log (T 'iac.teardown_aborted') -Level INFO
        return $false
    }

    Write-Log (T 'iac.teardown_deleting' $ResourceGroup) -Level INFO
    $out = & az group delete --name $ResourceGroup --yes 2>&1
    if ($LASTEXITCODE -ne 0) {
        Write-Log (T 'iac.teardown_failed' ([string]$out)) -Level ERROR
        return $false
    }
    Write-Log (T 'iac.teardown_done' $ResourceGroup) -Level INFO
    return $true
}

function Invoke-IaCExecute {
    param(
        [string]$SubscriptionId,
        [string]$ResourceGroup,
        [string]$Region,
        [string]$FoundryName,
        [string]$ProjectName,
        [bool]$IncludeTelemetry,
        [string]$LogAnalyticsName,
        [string]$AppInsightsName,
        [bool]$DeployModel = $false,
        [string]$ModelName = "",
        [string]$ModelVersion = "",
        [string]$ModelFormat = "OpenAI",
        [string]$ModelSku = "GlobalStandard",
        [int]$ModelCapacity = 1,
        [string]$DeploymentName = "",
        [bool]$PurgeSoftDeleted = $false
    )
    $subdomain = $FoundryName

    # Internal helper: runs 'az' with the given arguments, logs the step, and on
    # a non-zero exit code logs the error and signals the failure to the caller.
    function Invoke-AzStep {
        param([string]$Label, [string[]]$AzArgs)
        Write-Log (T 'iac.exec_step' $Label) -Level INFO
        $out = & az @AzArgs 2>&1
        if ($LASTEXITCODE -ne 0) {
            Write-Log (T 'iac.exec_step_failed' $Label ([string]$out)) -Level ERROR
            return $false
        }
        return $true
    }

    # Select the subscription
    if (-not (Invoke-AzStep -Label "az account set" -AzArgs @('account','set','--subscription',$SubscriptionId))) { return $false }

    # 1. Resource Group
    if (-not (Invoke-AzStep -Label "Resource Group" -AzArgs @('group','create','--name',$ResourceGroup,'--location',$Region))) { return $false }

    # 2. Foundry resource (idempotent: if it already exists, skip the creation)
    if (Test-IaCResourceExists -ResourceGroup $ResourceGroup -FoundryName $FoundryName) {
        Write-Log (T 'iac.exec_skip_exists' "Foundry resource") -Level WARN
    } else {
        # Special case: the resource might exist in a SOFT-DELETED state (after a
        # previous teardown). In that state 'account create' fails. I detect it and,
        # if the user passed -IaCPurgeSoftDeleted, I purge it permanently before
        # recreating; otherwise I stop with a clear message and the command to use.
        if (Test-IaCResourceSoftDeleted -ResourceGroup $ResourceGroup -FoundryName $FoundryName -Region $Region) {
            if ($PurgeSoftDeleted) {
                Write-Log (T 'iac.exec_purging' $FoundryName) -Level WARN
                if (-not (Invoke-AzStep -Label "Purge soft-deleted" -AzArgs @('cognitiveservices','account','purge','--name',$FoundryName,'--resource-group',$ResourceGroup,'--location',$Region))) { return $false }
            } else {
                Write-Log (T 'iac.exec_soft_deleted' $FoundryName) -Level ERROR
                Write-Log (T 'iac.exec_soft_deleted_hint' $FoundryName $ResourceGroup $Region) -Level INFO
                return $false
            }
        }
        if (-not (Invoke-AzStep -Label "Foundry resource" -AzArgs @('cognitiveservices','account','create','--name',$FoundryName,'--resource-group',$ResourceGroup,'--location',$Region,'--kind','AIServices','--sku','S0','--allow-project-management','--yes'))) { return $false }
    }

    # 2b. Custom subdomain
    if (-not (Invoke-AzStep -Label "Custom subdomain" -AzArgs @('cognitiveservices','account','update','--name',$FoundryName,'--resource-group',$ResourceGroup,'--custom-domain',$subdomain))) { return $false }

    # 3. Foundry Project (idempotent)
    if (Test-IaCProjectExists -ResourceGroup $ResourceGroup -FoundryName $FoundryName -ProjectName $ProjectName) {
        Write-Log (T 'iac.exec_skip_exists' "Foundry Project") -Level WARN
    } else {
        if (-not (Invoke-AzStep -Label "Foundry Project" -AzArgs @('cognitiveservices','account','project','create','--name',$FoundryName,'--resource-group',$ResourceGroup,'--project-name',$ProjectName,'--location',$Region))) { return $false }
    }

    if ($IncludeTelemetry) {
        # 4. Log Analytics Workspace (idempotent)
        if (Test-IaCLogAnalyticsExists -ResourceGroup $ResourceGroup -WorkspaceName $LogAnalyticsName) {
            Write-Log (T 'iac.exec_skip_exists' "Log Analytics Workspace") -Level WARN
        } else {
            if (-not (Invoke-AzStep -Label "Log Analytics Workspace" -AzArgs @('monitor','log-analytics','workspace','create','--resource-group',$ResourceGroup,'--workspace-name',$LogAnalyticsName,'--location',$Region))) { return $false }
        }

        # Retrieve the workspace resource ID
        $lawId = (& az monitor log-analytics workspace show --resource-group $ResourceGroup --workspace-name $LogAnalyticsName --query id --output tsv 2>&1)
        if ($LASTEXITCODE -ne 0 -or -not $lawId) {
            Write-Log (T 'iac.exec_step_failed' "Log Analytics ID" ([string]$lawId)) -Level ERROR
            return $false
        }

        # 5. Application Insights (workspace-based). I add the extension if needed.
        & az extension add --name application-insights --only-show-errors 2>$null
        if (Test-IaCAppInsightsExists -ResourceGroup $ResourceGroup -AppInsightsName $AppInsightsName) {
            Write-Log (T 'iac.exec_skip_exists' "Application Insights") -Level WARN
        } else {
            if (-not (Invoke-AzStep -Label "Application Insights" -AzArgs @('monitor','app-insights','component','create','--app',$AppInsightsName,'--resource-group',$ResourceGroup,'--location',$Region,'--workspace',[string]$lawId,'--application-type','web'))) { return $false }
        }

        # Connection string: I retrieve and show it (for the conf telemetry.azureMonitor)
        $connStr = (& az monitor app-insights component show --app $AppInsightsName --resource-group $ResourceGroup --query connectionString --output tsv 2>&1)
        if ($LASTEXITCODE -eq 0 -and $connStr) {
            Write-Log (T 'iac.appinsights_connstr' ([string]$connStr)) -Level INFO
        }

        # Workbook with the telemetry charts. Always created together with App
        # Insights: the charts are empty until data arrives and populate by
        # themselves. Not fatal: an error here does not invalidate the infrastructure.
        $aiId = (& az monitor app-insights component show --app $AppInsightsName --resource-group $ResourceGroup --query id --output tsv 2>&1)
        if ($LASTEXITCODE -eq 0 -and $aiId) {
            # Deterministic GUID from the resource ID: this way reruns update the same
            # workbook instead of creating a new one on every run (idempotency).
            $wbName = (New-IaCDeterministicGuid ([string]$aiId + "/newgptimage-workbook"))
            $wbJson = Get-IaCWorkbookJson
            # I write the JSON to a temporary file (it is large): --serialized-data @file.
            $wbFile = Join-Path ([System.IO.Path]::GetTempPath()) ("ngi-wb-" + $wbName + ".json")
            $utf8NoBom = [System.Text.UTF8Encoding]::new($false)
            [System.IO.File]::WriteAllText($wbFile, $wbJson, $utf8NoBom)
            & az extension add --name application-insights --only-show-errors 2>$null
            $chartCount = Get-IaCWorkbookChartCount
            # I check FIRST whether the workbook already exists (rerun on existing
            # infrastructure), so I can give a clear message: create (new) or update
            # (existing). The data in Application Insights is never touched: the
            # workbook is only the "view" (queries/charts) on top of the data.
            $null = & az monitor app-insights workbook show --name $wbName --resource-group $ResourceGroup --query id --output tsv 2>$null
            $wbExists = ($LASTEXITCODE -eq 0)
            if ($wbExists) {
                # It already exists: I update it to the latest version of the charts (WARN to
                # signal that it is not a creation but an update).
                Write-Log (T 'iac.exec_workbook_updating' $chartCount) -Level WARN
                $wbUpd = & az monitor app-insights workbook update --name $wbName --resource-group $ResourceGroup `
                    --display-name "New-GPTImage Telemetry" --category workbook `
                    --source-id ([string]$aiId).ToLower() --serialized-data ("@" + $wbFile) 2>&1
                if ($LASTEXITCODE -eq 0) {
                    Write-Log (T 'iac.exec_workbook_updated') -Level INFO
                } else {
                    # Self-heal for the 'hidden-title' tag conflict: a workbook created by a
                    # PREVIOUS version of the script carries an Azure 'hidden-title' tag equal to
                    # the OLD display-name; updating it with a different --display-name is rejected
                    # by Azure ("Invalid hidden-title tag ... expecting hidden-title to be the same
                    # as properties.displayName"). The tag can only be realigned by recreating the
                    # workbook, so on THIS specific error I delete and recreate it (same GUID name,
                    # same charts). Detection is narrow on purpose: any other update failure keeps
                    # the existing workbook untouched and just logs a WARN, as before.
                    if ([string]$wbUpd -match 'hidden-title') {
                        Write-Log (T 'iac.exec_workbook_retitle') -Level WARN
                        $null = & az monitor app-insights workbook delete --name $wbName --resource-group $ResourceGroup --yes 2>&1
                        $wbRe = & az monitor app-insights workbook create --name $wbName --resource-group $ResourceGroup `
                            --location $Region --display-name "New-GPTImage Telemetry" --category workbook --kind shared `
                            --source-id ([string]$aiId).ToLower() --serialized-data ("@" + $wbFile) 2>&1
                        if ($LASTEXITCODE -eq 0) {
                            Write-Log (T 'iac.exec_workbook_updated') -Level INFO
                        } else {
                            Write-Log (T 'iac.exec_workbook_failed' ([string]$wbUpd + " | " + [string]$wbRe)) -Level WARN
                        }
                    } else {
                        Write-Log (T 'iac.exec_workbook_failed' ([string]$wbUpd)) -Level WARN
                    }
                }
            } else {
                # It does not exist: I create it from scratch.
                Write-Log (T 'iac.exec_workbook' $chartCount) -Level INFO
                $wbOut = & az monitor app-insights workbook create --name $wbName --resource-group $ResourceGroup `
                    --location $Region --display-name "New-GPTImage Telemetry" --category workbook --kind shared `
                    --source-id ([string]$aiId).ToLower() --serialized-data ("@" + $wbFile) 2>&1
                if ($LASTEXITCODE -eq 0) {
                    Write-Log (T 'iac.exec_workbook_done') -Level INFO
                } else {
                    # Create failed but the workbook did not appear to exist: I try update
                    # as a fallback (race/edge case), otherwise a non-fatal WARN.
                    $wbUpd = & az monitor app-insights workbook update --name $wbName --resource-group $ResourceGroup `
                        --display-name "New-GPTImage Telemetry" --category workbook `
                        --source-id ([string]$aiId).ToLower() --serialized-data ("@" + $wbFile) 2>&1
                    if ($LASTEXITCODE -eq 0) {
                        Write-Log (T 'iac.exec_workbook_updated') -Level INFO
                    } else {
                        Write-Log (T 'iac.exec_workbook_failed' ([string]$wbOut + " | " + [string]$wbUpd)) -Level WARN
                    }
                }
            }
            Remove-Item $wbFile -ErrorAction SilentlyContinue
        }
    }

    # OPTIONAL image model deployment (idempotent). Separate from the rest
    # because it is subject to availability by region and quotas: a failure here does NOT
    # invalidate the already-created infrastructure, so it logs a WARN and continues.
    if ($DeployModel) {
        if (Test-IaCDeploymentExists -ResourceGroup $ResourceGroup -FoundryName $FoundryName -DeploymentName $DeploymentName) {
            Write-Log (T 'iac.exec_skip_exists' ("Deployment " + $DeploymentName)) -Level WARN
        } else {
            # az requires --model-version: without it, the deployment fails. If the version
            # is not known, I skip the deployment with a clear message (the infrastructure
            # stays valid and the user can retry with -IaCModelVersion).
            if (-not $ModelVersion) {
                Write-Log (T 'iac.exec_deploy_no_version' $ModelName) -Level WARN
                Write-Log (T 'iac.exec_deploy_hint') -Level INFO
                return $true
            }
            $depArgs = @('cognitiveservices','account','deployment','create',
                '--name',$FoundryName,'--resource-group',$ResourceGroup,
                '--deployment-name',$DeploymentName,
                '--model-name',$ModelName,'--model-format',$ModelFormat,
                '--model-version',$ModelVersion,
                '--sku-name',$ModelSku,'--sku-capacity',[string]$ModelCapacity)
            Write-Log (T 'iac.exec_deploy_model' $ModelName $DeploymentName) -Level INFO
            $depOut = & az @depArgs 2>&1
            if ($LASTEXITCODE -ne 0) {
                # Non-fatal: the infrastructure is there, only the model was not created.
                Write-Log (T 'iac.exec_deploy_failed' ([string]$depOut)) -Level WARN
                Write-Log (T 'iac.exec_deploy_hint') -Level INFO
            } else {
                Write-Log (T 'iac.exec_deploy_done' $DeploymentName) -Level INFO
            }
        }
    }

    # Final endpoint: I read the "AI Foundry API" endpoint (services.ai.azure.com), which
    # is the one actually used for the generations, not the generic
    # properties.endpoint (which returns the cognitiveservices.azure.com domain).
    $endpoint = (& az cognitiveservices account show --name $FoundryName --resource-group $ResourceGroup --query "properties.endpoints.\"AI Foundry API\"" --output tsv 2>&1)
    if ($LASTEXITCODE -ne 0 -or -not $endpoint) {
        # Fallback to the generic field if the specific endpoint is not available.
        $endpoint = (& az cognitiveservices account show --name $FoundryName --resource-group $ResourceGroup --query "properties.endpoint" --output tsv 2>&1)
    }
    if ($LASTEXITCODE -eq 0 -and $endpoint) {
        Write-Log (T 'iac.exec_endpoint' ([string]$endpoint)) -Level INFO
    }
    return $true
}

# Orchestrator of the -IaC command. Three modes (RF-1):
#   generate : writes provision.sh without touching Azure (Increment 1)
#   dry-run  : shows what would be created without creating it (preview)
#   execute  : creates the resources via az, after explicit confirmation with a summary
# Recognizes an affirmative ("yes") answer to an interactive yes/no prompt, in ALL the
# languages supported by the script. The prompt itself is shown via T() in the active
# language, so the answer must be accepted in that same language. This helper centralizes
# the recognition for every confirmation point (Read-YesNo in the wizard, the -IaC execute
# confirmation, etc.).
#
# Accepted, case-insensitive and whitespace-trimmed:
#   - whole affirmative words per language, both in the NATIVE script and in Latin
#     transliteration (e.g. Russian "да" and "da", Japanese "はい" and "hai");
#   - only the UNAMBIGUOUS single-letter initials s / y / o / j (Italian/Spanish/Portuguese,
#     English, French, German), which never collide with the initial of a "no" in those
#     languages. Ambiguous initials are deliberately NOT accepted (e.g. Arabic "نعم" starts
#     with an "n" that means "no" in Italian/English), so anything not clearly affirmative
#     is treated as "no" — the prudent default for destructive actions.
#
# MAINTENANCE NOTE: the script currently supports 11 languages
# (it/en/fr/es/pt/de/ru/zh/ja/hi/ar). When a NEW language is added (new -Lang value and new
# column in New-GPTImage.lang), this function MUST be updated by adding that language's
# affirmative forms (native + transliteration) to $affirmatives below; otherwise users in
# the new language will not be able to confirm a prompt in their own language.
function Test-AffirmativeAnswer {
    param([string]$Answer)
    if ([string]::IsNullOrWhiteSpace($Answer)) { return $false }
    $a = $Answer.Trim().ToLower()
    # Whole affirmative words, per language (native script + Latin transliteration).
    $affirmatives = @(
        # it / es / pt
        'si', 'sì', 'sí', 'sim',
        # en
        'yes', 'yeah', 'yep',
        # fr
        'oui',
        # de
        'ja',
        # ru: да (+ transliteration)
        'да', 'da',
        # zh: 是 / 是的 / 对 (+ transliteration)
        '是', '是的', '对', 'shi', 'dui',
        # ja: はい / ええ / うん (+ transliteration)
        'はい', 'ええ', 'うん', 'hai',
        # hi: हाँ / हां (+ transliteration)
        'हाँ', 'हां', 'haan', 'han',
        # ar: نعم (+ transliteration)
        'نعم', 'naam', "na'am"
    )
    if ($a -in $affirmatives) { return $true }
    # Unambiguous single-letter initials only (never the initial of a "no" in those languages):
    #   s = sì/sí/sim, y = yes, o = oui, j = ja.
    if ($a -in @('s', 'y', 'o', 'j')) { return $true }
    return $false
}

# Interactive wizard (RF-3): collects the IaC parameters one by one with sensible defaults,
# shows a summary and then delegates to Invoke-IaC in execute mode. Each question
# accepts Enter to keep the default (shown in parentheses). Designed for those who do not
# want to remember the long list of command-line parameters.
function Invoke-IaCWizard {
    param([string]$OutputFolder)

    Write-Log (T 'iac.wizard_header') -Level INFO

    # Helper: asks for a value showing the default; empty Enter -> default.
    function Read-WithDefault {
        param([string]$PromptKey, [string]$Default)
        $label = (T $PromptKey) + " [" + $Default + "]"
        $val = Read-Host $label
        if ([string]::IsNullOrWhiteSpace($val)) { return $Default }
        return $val.Trim()
    }
    # Helper: yes/no question with a default.
    function Read-YesNo {
        param([string]$PromptKey, [bool]$DefaultYes)
        $def = if ($DefaultYes) { "y" } else { "n" }
        $label = (T $PromptKey) + " (y/n) [" + $def + "]"
        $val = Read-Host $label
        if ([string]::IsNullOrWhiteSpace($val)) { return $DefaultYes }
        return (Test-AffirmativeAnswer $val)
    }

    # Parameter collection with defaults consistent with those of Invoke-IaC.
    $rg      = Read-WithDefault 'iac.wizard_rg'       'rg-newgptimage'
    $region  = Read-WithDefault 'iac.wizard_region'   'swedencentral'
    $foundry = Read-WithDefault 'iac.wizard_foundry'  'foundrynewgptimage'
    $project = Read-WithDefault 'iac.wizard_project'  'proj-newgptimage'

    # Model deployment (optional)
    $deployModel = Read-YesNo 'iac.wizard_deploy_model' $false
    $modelName = "gpt-image-1"
    $modelVer  = ""
    if ($deployModel) {
        $modelName = Read-WithDefault 'iac.wizard_model_name' 'gpt-image-1'
        # Version: I propose the known default for the chosen model.
        $defVer = Get-IaCDefaultModelVersion $modelName
        $modelVer = Read-WithDefault 'iac.wizard_model_version' $defVer
    }

    # Automatic purge of any soft-deleted resources with the same name
    $purge = Read-YesNo 'iac.wizard_purge' $false

    # I delegate to the already-tested execute flow. The summary + final confirmation and
    # the soft-delete handling remain those of Invoke-IaC/Invoke-IaCExecute.
    return (Invoke-IaC -Mode 'execute' -ResourceGroup $rg -Region $region `
        -FoundryName $foundry -ProjectName $project -OutputFolder $OutputFolder `
        -DeployModel $deployModel -ModelName $modelName -ModelVersion $modelVer `
        -ModelFormat 'OpenAI' -ModelSku 'GlobalStandard' -ModelCapacity 1 `
        -PurgeSoftDeleted $purge)
}

function Invoke-IaC {
    param(
        [string]$Mode,
        [string]$ResourceGroup,
        [string]$Region,
        [string]$FoundryName,
        [string]$ProjectName,
        [string]$OutputFolder,
        [bool]$DeployModel = $false,
        [string]$ModelName = "gpt-image-1",
        [string]$ModelVersion = "",
        [string]$ModelFormat = "OpenAI",
        [string]$ModelSku = "GlobalStandard",
        [int]$ModelCapacity = 1,
        [bool]$PurgeSoftDeleted = $false
    )

    Write-Log (T 'iac.start') -Level INFO

    # Pre-flight (RF-2): without az + login we do not go further.
    $pre = Test-IaCPrerequisites
    if (-not $pre.Ready) {
        Write-Log (T 'iac.preflight_failed') -Level ERROR
        return $false
    }

    # Parameter resolution with sensible defaults. The interactive wizard (which asks them
    # one by one) arrives in Increment 4: here it uses the passed values or the defaults.
    $rg     = if ($ResourceGroup) { $ResourceGroup } else { "rg-newgptimage" }
    $region = if ($Region)        { $Region }        else { "swedencentral" }
    $foundry = if ($FoundryName)  { Get-IaCSafeName $FoundryName } else { "foundrynewgptimage" }
    $project = if ($ProjectName)  { Get-IaCSafeName $ProjectName } else { "proj-newgptimage" }
    # Telemetry names derived from the resource name (within the Azure limits).
    $lawName = Get-IaCSafeName ($foundry + "-law") 63
    $aiName  = Get-IaCSafeName ($foundry + "-ai") 255
    # Model deployment name (if requested): I use the model name.
    $deployName = Get-IaCSafeName $ModelName 64
    # az requires --model-version as mandatory: if the user did not pass it, I try to
    # derive a default for the known models. If it stays empty and the deployment is active,
    # I warn that an explicit version is needed.
    $modelVer = if ($ModelVersion) { $ModelVersion } else { Get-IaCDefaultModelVersion $ModelName }
    if ($DeployModel -and -not $modelVer) {
        Write-Log (T 'iac.model_version_required' $ModelName) -Level WARN
    }

    Write-Log (T 'iac.params_resolved' $rg $region $foundry $project) -Level INFO

    # ---------- EXECUTE MODE ----------
    if ($Mode -eq 'execute') {
        # Summary + explicit confirmation BEFORE creating anything (RF-1).
        Write-Log (T 'iac.exec_summary_header') -Level INFO
        Write-Log (T 'iac.exec_summary_sub' $pre.SubscriptionName $pre.SubscriptionId) -Level INFO
        Write-Log (T 'iac.exec_summary_rg' $rg $region) -Level INFO
        Write-Log (T 'iac.exec_summary_foundry' $foundry) -Level INFO
        Write-Log (T 'iac.exec_summary_project' $project) -Level INFO
        Write-Log (T 'iac.exec_summary_telemetry' $lawName $aiName) -Level INFO
        Write-Log (T 'iac.exec_summary_workbook' (Get-IaCWorkbookChartCount)) -Level INFO
        if ($DeployModel) {
            Write-Log (T 'iac.exec_summary_model' $ModelName $deployName $ModelSku $ModelCapacity) -Level INFO
        } else {
            Write-Log (T 'iac.exec_summary_no_model') -Level INFO
        }
        Write-Log (T 'iac.exec_cost_warning') -Level WARN

        $answer = Read-Host (T 'iac.exec_confirm_prompt')
        if (-not (Test-AffirmativeAnswer $answer)) {
            Write-Log (T 'iac.exec_aborted') -Level INFO
            return $false
        }

        $okExec = Invoke-IaCExecute -SubscriptionId $pre.SubscriptionId -ResourceGroup $rg `
            -Region $region -FoundryName $foundry -ProjectName $project `
            -IncludeTelemetry $true -LogAnalyticsName $lawName -AppInsightsName $aiName `
            -DeployModel $DeployModel -ModelName $ModelName -ModelVersion $modelVer `
            -ModelFormat $ModelFormat -ModelSku $ModelSku -ModelCapacity $ModelCapacity `
            -DeploymentName $deployName -PurgeSoftDeleted $PurgeSoftDeleted
        if ($okExec) {
            Write-Log (T 'iac.exec_done' $rg) -Level INFO
            return $true
        } else {
            Write-Log (T 'iac.exec_failed') -Level ERROR
            return $false
        }
    }

    # ---------- MODALITA' DRY-RUN ----------
    if ($Mode -eq 'dry-run') {
        # Anteprima non distruttiva: mostro i passi che verrebbero eseguiti. Per il
        # Resource Group: I use 'az group create' with --what-if when available; for
        # the CognitiveServices resources --what-if at the command level is not
        # guaranteed, so I list the commands transparently without running them.
        Write-Log (T 'iac.dryrun_header') -Level INFO
        $previewSteps = @(
            "az group create --name $rg --location $region",
            "az cognitiveservices account create --name $foundry --resource-group $rg --location $region --kind AIServices --sku S0 --allow-project-management --yes",
            "az cognitiveservices account update --name $foundry --resource-group $rg --custom-domain $foundry",
            "az cognitiveservices account project create --name $foundry --resource-group $rg --project-name $project --location $region",
            "az monitor log-analytics workspace create --resource-group $rg --workspace-name $lawName --location $region",
            "az monitor app-insights component create --app $aiName --resource-group $rg --location $region --workspace <LAW_ID> --application-type web"
        )
        if ($DeployModel) {
            $verPart = if ($modelVer) { " --model-version $modelVer" } else { " --model-version <RICHIESTA>" }
            $previewSteps += "az cognitiveservices account deployment create --name $foundry --resource-group $rg --deployment-name $deployName --model-name $ModelName --model-format $ModelFormat$verPart --sku-name $ModelSku --sku-capacity $ModelCapacity"
        }
        foreach ($step in $previewSteps) {
            Write-Log (T 'iac.dryrun_step' $step) -Level INFO
        }
        Write-Log (T 'iac.dryrun_footer') -Level INFO
        return $true
    }

    # ---------- GENERATE MODE (default) ----------
    $scriptText = New-IaCProvisioningScript -ResourceGroup $rg -Region $region `
        -FoundryName $foundry -ProjectName $project -SubscriptionId $pre.SubscriptionId `
        -IncludeTelemetry $true -LogAnalyticsName $lawName -AppInsightsName $aiName `
        -DeployModel $DeployModel -ModelName $ModelName -ModelVersion $modelVer `
        -ModelFormat $ModelFormat -ModelSku $ModelSku -ModelCapacity $ModelCapacity -DeploymentName $deployName

    $iacStamp = (Get-Date).ToString("yyyyMMdd_HHmmss", [System.Globalization.CultureInfo]::InvariantCulture)
    $iacDir = Join-Path $OutputFolder ("iac_" + $iacStamp)
    try {
        New-Item -ItemType Directory -Path $iacDir -Force | Out-Null
        $scriptPath = Join-Path $iacDir "provision.sh"
        $utf8NoBom = [System.Text.UTF8Encoding]::new($false)
        [System.IO.File]::WriteAllText($scriptPath, $scriptText, $utf8NoBom)
        Write-Log (T 'iac.script_generated' $scriptPath) -Level INFO
        Write-Log (T 'iac.next_steps') -Level INFO
        return $true
    } catch {
        Write-Log (T 'iac.save_failed' ($_.Exception.Message)) -Level ERROR
        return $false
    }
}


function Unprotect-ApiKey {
    <#
    Decodes an encoded string. Automatically recognizes the prefix.
    If the string has no prefix, it is considered already plaintext and is
    returned as-is (compatibility with existing confs).
    Returns $null if decoding fails (e.g. .conf moved to another PC with DPAPI).
    #>
    param([Parameter(Mandatory=$true)][string]$EncodedValue)

    if (-not $EncodedValue -or $EncodedValue.Trim() -eq "") { return $null }

    # No prefix -> plaintext (backward compatibility)
    if (-not (Test-ApiKeyEncoded $EncodedValue)) {
        return $EncodedValue
    }

    if ($EncodedValue.StartsWith("enc:")) {
        # DPAPI
        if (-not $script:IsWin) {
            Write-Log (T 'apikey.dpapi_not_windows') -Level ERROR
            return $null
        }
        try {
            $payload = $EncodedValue.Substring(4)
            $secure = ConvertTo-SecureString $payload
            # Estraggo il PlainText dalla SecureString
            $bstr = [System.Runtime.InteropServices.Marshal]::SecureStringToBSTR($secure)
            try {
                $plain = [System.Runtime.InteropServices.Marshal]::PtrToStringBSTR($bstr)
            } finally {
                [System.Runtime.InteropServices.Marshal]::ZeroFreeBSTR($bstr)
            }
            return $plain
        } catch {
            Write-Log (T 'apikey.dpapi_decode_failed' ($_.Exception.Message)) -Level ERROR
            return $null
        }
    }

    if ($EncodedValue.StartsWith("aes:")) {
        try {
            $masterKey = Get-ApiKeyMasterKey
            if (-not $masterKey) { throw "master key not available" }
            $payload = [System.Convert]::FromBase64String($EncodedValue.Substring(4))
            if ($payload.Length -lt 28) { throw "payload aes troppo corto" }
            $nonce  = [byte[]]($payload[0..11])
            $tag    = [byte[]]($payload[12..27])
            $cipher = if ($payload.Length -gt 28) { [byte[]]($payload[28..($payload.Length - 1)]) } else { [byte[]]@() }
            $plainBytes = [byte[]]::new($cipher.Length)
            $gcm = $null
            try { $gcm = [System.Security.Cryptography.AesGcm]::new($masterKey, 16) }
            catch { $gcm = [System.Security.Cryptography.AesGcm]::new($masterKey) }
            try { $gcm.Decrypt($nonce, $cipher, $tag, $plainBytes) }
            finally { $gcm.Dispose() }
            return [System.Text.Encoding]::UTF8.GetString($plainBytes)
        } catch {
            Write-Log (T 'apikey.aes_decode_failed' ($_.Exception.Message)) -Level ERROR
            return $null
        }
    }

    if ($EncodedValue.StartsWith("b64:")) {
        try {
            $payload = $EncodedValue.Substring(4)
            $bytes = [System.Convert]::FromBase64String($payload)
            return [System.Text.Encoding]::UTF8.GetString($bytes)
        } catch {
            Write-Log (T 'apikey.base64_decode_failed' ($_.Exception.Message)) -Level ERROR
            return $null
        }
    }

    return $null
}

function Read-ApiKeyFromUser {
    <#
    Chiede all'utente di inserire una API key in modalita' "hidden" (no echo).
    Loops until the user enters a non-empty string or cancels with Ctrl+C.
    For interactive use ONLY: if the script runs non-interactive (CI/CD, batch),
    this function cannot be used.
    #>
    param([string]$ModelName)

    Write-Host ""
    Write-Host (T 'apikey.not_encoded' $ModelName) -ForegroundColor Yellow
    Write-Host (T 'apikey.input_prompt') -ForegroundColor Cyan
    $secureInput = Read-Host -AsSecureString
    if (-not $secureInput -or $secureInput.Length -eq 0) {
        return $null
    }
    # Estrai plain text
    $bstr = [System.Runtime.InteropServices.Marshal]::SecureStringToBSTR($secureInput)
    try {
        $plain = [System.Runtime.InteropServices.Marshal]::PtrToStringBSTR($bstr)
    } finally {
        [System.Runtime.InteropServices.Marshal]::ZeroFreeBSTR($bstr)
    }
    return $plain
}

function Initialize-ApiKeys {
    <#
    At script launch, it scans all the ACTIVE models in the config and verifies
    that each apiKey is encoded. If it finds one in plaintext, it asks the user to
    re-enter it (to avoid the plaintext key staying on disk), then encodes
    it and saves the config.

    Behavior for NON-active models: total skip (their keys are
    spesso vuote, non c'e' motivo di chiederle).

    NOTE: this function MODIFIES the config in memory AND on disk. The call
    is idempotent: run again with an already-encoded conf, it does nothing.
    #>
    param(
        [Parameter(Mandatory=$true)] $Config,
        [Parameter(Mandatory=$true)] [string]$ConfigPath
    )

    $modelNames = @($Config.models | Get-Member -MemberType NoteProperty | Select-Object -ExpandProperty Name)
    $changedAnyKey = $false

    foreach ($mdlName in $modelNames) {
        $mdl = $Config.models.$mdlName

        # Skip non-active models
        $isActive = if ($null -ne $mdl.active) { [bool]$mdl.active } else { $true }
        if (-not $isActive) { continue }

        # Skip if apiKey empty (model not yet configured)
        if (-not $mdl.apiKey -or $mdl.apiKey.Trim() -eq "") { continue }

        # Skip if already encoded
        if (Test-ApiKeyEncoded $mdl.apiKey) { continue }

        # plaintext apiKey: I ask the user for confirmation and re-input
        Write-Log (T 'apikey.plain_found' $mdlName) -Level WARN

        # Strategy: for safety, we do NOT directly use the plaintext value read
        # from the .conf (it might have been compromised), but we ask the user to
        # re-enter it. UX trade-off: but safer.
        $newPlain = Read-ApiKeyFromUser -ModelName $mdlName
        if (-not $newPlain) {
            Write-Log (T 'apikey.none_provided' $mdlName) -Level WARN
            continue
        }

        # Encode and update in memory
        $encoded = Protect-ApiKey -PlainText $newPlain
        $mdl.apiKey = $encoded
        $changedAnyKey = $true

        $method = if ($script:IsWin) { "DPAPI" } else { "Base64" }
        Write-Log (T 'apikey.encoded_ok' $mdlName $method)
    }

    # If I changed at least one key, I save the .conf
    if ($changedAnyKey) {
        try {
            $Config | ConvertTo-Json -Depth 10 | Set-Content -Path $ConfigPath -Encoding UTF8 -ErrorAction Stop
            Write-Log (T 'apikey.config_saved' $ConfigPath)
        } catch {
            Write-Log (T 'apikey.config_save_error' ($_.Exception.Message)) -Level ERROR
        }
    }
}

function Import-LanguagePack {
    <#
    Loads the New-GPTImage.lang (JSON) file if it exists. If it does not exist, it leaves
    $script:LangPack at $null and all calls to T() will use the hardcoded
    Italian default.

    Expected structure of the .lang file:
    {
        "defaultLanguage": "it",
        "fallbackLanguage": "en",
        "translations": {
            "msg.internet_present": {
                "it": "Connessione internet presente",
                "en": "Internet connection available",
                "fr": "...", "es": "...", "pt": "..."
            },
            ...
        }
    }
    #>
    param([string]$LangFilePath, [string]$RequestedLang)

    # I set the current language: priority CLI parameter > config > "it"
    $script:CurrentLang = if ($RequestedLang -and $RequestedLang.Trim() -ne "") {
        $RequestedLang
    } else {
        "it"
    }

    if (-not (Test-Path $LangFilePath)) {
        $script:LangPack = $null
        return
    }

    try {
        $content = Get-Content $LangFilePath -Raw -Encoding UTF8 -ErrorAction Stop
        $script:LangPack = $content | ConvertFrom-Json -ErrorAction Stop
    } catch {
        Write-Log (T 'lang.parse_error' $LangFilePath ($_.Exception.Message)) -Level WARN
        $script:LangPack = $null
    }
}

function T {
    <#
    Translates a key into the current language. Supports substitution arguments
    posizionali in stile {0}, {1}, ...
    Es: T 'cost.synthetic_megapixels' 2 25 -> "(output: 2 MP, riferimenti: 25 MP)"

    Parameters:
      -Key:      key in the form "namespace.identifier" (e.g. "header.model_in_use")
                 mandatory, position 0
      -Args:     optional arguments to replace the placeholders {0}, {1}, ...
                 passed as residual arguments after the key

    Behavior:
      1. Looks up Key in the current language of the langpack
      2. If not found, tries the fallback language (default "en")
      3. If still not found, returns "[Key]" as a debug aid
      4. Replaces {0}, {1}, ... with the args

    TECHNICAL NOTE: the original signature had a -Default parameter for a hardcoded
    fallback. We removed it because it collided with the call pattern
    (T 'key' $arg0 $arg1 ...) - $arg0 was interpreted as -Default. The "[Key]"
    fallback is sufficient as a debug aid to identify missing keys in the langpack.
    #>
    param(
        [Parameter(Mandatory=$true, Position=0)] [string]$Key,
        [Parameter(ValueFromRemainingArguments=$true)] [object[]]$Arguments = @()
    )

    $text = $null

    if ($script:LangPack -and $script:LangPack.translations) {
        $entry = $script:LangPack.translations.$Key
        if ($entry) {
            # Current language
            if ($entry.PSObject.Properties.Name -contains $script:CurrentLang) {
                $text = $entry.$($script:CurrentLang)
            }
            # Fall back to the fallback language defined in the langpack (default "en")
            if (-not $text) {
                $fb = if ($script:LangPack.fallbackLanguage) { $script:LangPack.fallbackLanguage } else { "en" }
                if ($entry.PSObject.Properties.Name -contains $fb) {
                    $text = $entry.$fb
                }
            }
        }
    }

    # Fallback: I return the key as a debug aid if not found in any language.
    # This way the user sees immediately that a translation is missing and can report it.
    if (-not $text) {
        $text = "[$Key]"
    }

    # Substitute arguments {0}, {1}, ... with the passed values
    if ($Arguments -and $Arguments.Count -gt 0) {
        for ($i = 0; $i -lt $Arguments.Count; $i++) {
            $text = $text.Replace("{$i}", [string]$Arguments[$i])
        }
    }

    return $text
}

function Get-LocalCurrency {
    <#
    Determines the local currency based on the PowerShell system region.
    Uses [System.Globalization.RegionInfo]::CurrentRegion which reflects the
    Windows/macOS/Linux user's regional settings. Zero external calls.

    Hardcoded list of EU+EEA countries (ISO 3166-1 alpha-2 codes). If the country is in
    the list -> EUR. Otherwise -> USD. Unrecognized codes default to USD.
    #>
    $euCountries = @(
        # 27 EU countries
        'AT','BE','BG','CY','CZ','DE','DK','EE','ES','FI','FR','GR','HR','HU','IE',
        'IT','LT','LU','LV','MT','NL','PL','PT','RO','SE','SI','SK',
        # EEA: Iceland, Liechtenstein, Norway
        'IS','LI','NO',
        # CH and UK: for UX, I consider the Swiss franc and GBP closer to EUR
        # in the "if you are in Europe you prefer to see EUR" perspective
        'CH','GB'
    )

    try {
        $region = [System.Globalization.RegionInfo]::CurrentRegion
        $code = $region.TwoLetterISORegionName
        if ($euCountries -contains $code) {
            return [pscustomobject]@{ Currency = "EUR"; RegionCode = $code }
        }
        return [pscustomobject]@{ Currency = "USD"; RegionCode = $code }
    } catch {
        # If for any reason RegionInfo fails, fall back to USD
        return [pscustomobject]@{ Currency = "USD"; RegionCode = "??" }
    }
}

function Update-DefaultCurrency {
    <#
    Updates defaultCurrency and defaultCurrencyLastCheck in the config, once a day.
    Returns the currency to use.
    #>
    param(
        [Parameter(Mandatory=$true)] $Config,
        [Parameter(Mandatory=$true)] [string]$ConfigPath
    )

    $today = (Get-Date).ToString("yyyy-MM-dd", [System.Globalization.CultureInfo]::InvariantCulture)
    $lastCheck = if ($Config.PSObject.Properties.Name -contains 'defaultCurrencyLastCheck') {
                     $Config.defaultCurrencyLastCheck
                 } else { $null }
    $currentCurrency = if ($Config.PSObject.Properties.Name -contains 'defaultCurrency' -and
                           $Config.defaultCurrency) {
                          $Config.defaultCurrency
                      } else { $null }

    # Already updated today: skip
    if ($lastCheck -eq $today -and $currentCurrency) {
        return $currentCurrency
    }

    # Detection and update
    $detected = Get-LocalCurrency
    $newCurrency = $detected.Currency

    if ($Config.PSObject.Properties.Name -contains 'defaultCurrency') {
        $Config.defaultCurrency = $newCurrency
    } else {
        $Config | Add-Member -NotePropertyName 'defaultCurrency' -NotePropertyValue $newCurrency -Force
    }
    if ($Config.PSObject.Properties.Name -contains 'defaultCurrencyLastCheck') {
        $Config.defaultCurrencyLastCheck = $today
    } else {
        $Config | Add-Member -NotePropertyName 'defaultCurrencyLastCheck' -NotePropertyValue $today -Force
    }

    try {
        $Config | ConvertTo-Json -Depth 10 | Set-Content -Path $ConfigPath -Encoding UTF8 -ErrorAction Stop
        Write-Log (T 'currency.detected' $newCurrency ($detected.RegionCode))
    } catch {
        Write-Log (T 'currency.write_conf_failed' $newCurrency ($_.Exception.Message)) -Level WARN
    }

    return $newCurrency
}

function Test-InternetConnectivity {
    <#
    Verifies that there is internet connectivity BEFORE calling the Foundry API.
    Uses TcpClient toward a known host:port (default: Foundry endpoint on 443).
    No Test-NetConnection (Windows-only) and no Test-Connection (ICMP, often
    blocked by firewalls). TCP/443 is the most reliable cross-platform way to
    know whether "the internet really works for HTTPS".

    Parameters:
      -TargetHost: hostname to reach. Typically the host of the Foundry endpoint.
      -TargetPort: TCP port. Default 443 (HTTPS).
      -TimeoutSec: connection timeout in seconds. Default 5.

    Returns:
      $true  if the TCP connection succeeds within the timeout
      $false if the connection fails, times out or the hostname does not resolve
    #>
    param(
        [string]$TargetHost,
        [int]$TargetPort = 443,
        [int]$TimeoutSec = 5,
        # ADDITIONAL attempts after the first failure (0 = single attempt, as
        # in the past). The fatal preflight of the main flow uses Retries > 0:
        # a single network hiccup (e.g. saturated bandwidth after heavy upload/download)
        # must not make the whole generation fail before even calling the API.
        [int]$Retries = 0,
        [int]$RetryPauseSec = 2
    )

    if (-not $TargetHost -or $TargetHost.Trim() -eq "") {
        return $false
    }

    $attempts = 1 + [Math]::Max(0, $Retries)
    for ($try = 1; $try -le $attempts; $try++) {
        $client = $null
        try {
            $client = [System.Net.Sockets.TcpClient]::new()
            # ConnectAsync returns a Task we can await with an explicit timeout.
            $task = $client.ConnectAsync($TargetHost, $TargetPort)
            # Wait returns true if the task completed within the timeout, false otherwise.
            $completed = $task.Wait($TimeoutSec * 1000)
            if ($completed -and $client.Connected) {
                return $true
            }
        }
        catch {
            # DNS failed, host unreachable, firewall closing, etc.
        }
        finally {
            if ($client) { try { $client.Dispose() } catch { } }
        }
        if ($try -lt $attempts) { Start-Sleep -Seconds $RetryPauseSec }
    }
    return $false
}

function Get-HostFromUrl {
    <#
    Estrae l'hostname da un URL. Es. "https://foo.bar.com/path" -> "foo.bar.com".
    Used for the connectivity check toward the Foundry endpoint.
    #>
    param([string]$Url)
    try {
        return ([System.Uri]$Url).Host
    } catch {
        return $null
    }
}

function Save-ConfigToFile {
    <#
    Saves the config object to the .conf file in JSON, preserving UTF8 without BOM encoding.
    Centralizes the writing so all model-management operations (-AddModel,
    -RemoveModel, -EditModel) usano lo stesso percorso e gli stessi accorgimenti.
    Creates a .conf.bak backup before overwriting, for safety.
    #>
    param(
        [Parameter(Mandatory=$true)] $Config,
        [Parameter(Mandatory=$true)] [string]$Path
    )
    try {
        # Backup non distruttivo del conf esistente (se presente).
        if (Test-Path $Path) {
            Copy-Item -Path $Path -Destination ($Path + ".bak") -Force -ErrorAction SilentlyContinue
        }
        $json = $Config | ConvertTo-Json -Depth 20
        # Set-Content UTF8 without BOM (consistent with the rest of the script).
        $utf8NoBom = [System.Text.UTF8Encoding]::new($false)
        [System.IO.File]::WriteAllText($Path, $json, $utf8NoBom)
        return $true
    }
    catch {
        Write-Log (T 'modelmgmt.save_error' ($_.Exception.Message)) -Level ERROR
        return $false
    }
}

function Get-SchemaOperationalDefaults {
    <#
    Returns an operationalParams object with sensible defaults for the given schema.
    Used by the -AddModel wizard to pre-fill the limits without the user having to
    know them. The values reflect the providers' official documentation:
      openai-images: 10 img, dimensioni libere (div 16, aspect 1:3-3:1, lato<=3840), png/jpg
      mai-images:    1 img, lato>=768 area<=1048576, edit con 1 reference
      bfl-flux:      4 img, edit con max 8 reference, output fino a 4MP
    #>
    param([string]$Schema)

    switch ($Schema) {
        "mai-images" {
            return [ordered]@{
                maxImages = 1; maxImagesEnforce = $false
                allowedSizes = @(); allowedSizesEnforce = $false
                minSide = 768; maxSide = 0; maxArea = 1048576; sizeRulesEnforce = $true
                sizeDivisibleBy = 0; aspectRatioMin = 0.0; aspectRatioMax = 0.0
                maxReferenceImages = 1; maxReferenceImagesEnforce = $true
                allowedQuality = @(); allowedQualityEnforce = $false
                allowedFormat = @(); allowedFormatEnforce = $false
            }
        }
        "bfl-flux" {
            return [ordered]@{
                maxImages = 4; maxImagesEnforce = $false
                allowedSizes = @(); allowedSizesEnforce = $false
                minSide = 256; maxSide = 4096; maxArea = 0; sizeRulesEnforce = $false
                sizeDivisibleBy = 0; aspectRatioMin = 0.0; aspectRatioMax = 0.0
                maxReferenceImages = 8; maxReferenceImagesEnforce = $true
                allowedQuality = @(); allowedQualityEnforce = $false
                allowedFormat = @(); allowedFormatEnforce = $false
            }
        }
        default {
            # openai-images (default)
            return [ordered]@{
                maxImages = 10; maxImagesEnforce = $true
                allowedSizes = @(); allowedSizesEnforce = $false
                minSide = 0; maxSide = 3840; maxArea = 0; sizeRulesEnforce = $true
                sizeDivisibleBy = 16; aspectRatioMin = 0.333; aspectRatioMax = 3.0
                maxReferenceImages = 16; maxReferenceImagesEnforce = $false
                allowedQuality = @("low","medium","high","auto"); allowedQualityEnforce = $true
                allowedFormat = @("png","jpg"); allowedFormatEnforce = $true
            }
        }
    }
}

function Get-SchemaPricingDefaults {
    <#
    Returns an object with the pricing defaults for the given schema: the
    "meters" block (with the right keys for the schema, prices at 0) and the pieces of
    "pricingMapping" that depend on the schema (providerTab + meterRoles with the generic
    hints for the automatic price update). Used by -AddModel so as not to
    write a wrong pricing structure: each schema has a DIFFERENT number/names of meters,
    and a wrong block would make the cost calculation return 0 (the
    nonexistent meters count as 0) and would prevent the automatic update via -ModelPrice.

    The three families (aligned with the real models in the .conf):
      openai-images: 6 meters (inputText, cachedInputText, inputImage, cachedInputImage,
                     outputText, outputImage), providerTab "aoai"
      mai-images:    2 meters (input, output), providerTab "microsoft"
      bfl-flux:      3 meters (firstMpUsd, additionalMpUsd, referenceMpUsd),
                     providerTab "blackforestlabs"

    The hints in meterRoles are GENERIC (e.g. "Input Text", "Output Image"): they are enough
    for scraping the pricing page. For more precise hints (e.g. "Image 2 txt inp Gl")
    the user can refine the .conf by hand, but the generic ones work right away.

    Returns [PSCustomObject] with: Meters (ordered), ProviderTab (string),
    MeterRoles (ordered), ServiceName (string), PricingPageUrl (string).
    #>
    param([string]$Schema)

    switch ($Schema) {
        "mai-images" {
            return [PSCustomObject]@{
                Meters         = [ordered]@{ input = 0.0; output = 0.0 }
                ProviderTab    = "microsoft"
                ServiceName    = "Azure AI Foundry"
                PricingPageUrl = "https://azure.microsoft.com/en-us/pricing/details/ai-foundry-models/microsoft/"
                MeterRoles     = [ordered]@{
                    input  = @("Input", "Text Input", "Inpt")
                    output = @("Output", "Image Output", "Outpt Img")
                }
            }
        }
        "bfl-flux" {
            return [PSCustomObject]@{
                Meters         = [ordered]@{ firstMpUsd = 0.0; additionalMpUsd = 0.0; referenceMpUsd = 0.0 }
                ProviderTab    = "blackforestlabs"
                ServiceName    = "Azure AI Foundry"
                PricingPageUrl = "https://azure.microsoft.com/en-us/pricing/details/ai-foundry-models/black-forest-labs/"
                MeterRoles     = [ordered]@{
                    firstMpUsd      = @("Initial MP", "First Megapixel", "First MP")
                    additionalMpUsd = @("Additional Megapixel", "Subsequent Megapixel", "Additional MP")
                    referenceMpUsd  = @("Reference Megapixel", "Reference image", "Ref MP")
                }
            }
        }
        default {
            # openai-images (default)
            return [PSCustomObject]@{
                Meters         = [ordered]@{
                    inputText = 0.0; cachedInputText = 0.0; inputImage = 0.0
                    cachedInputImage = 0.0; outputText = 0.0; outputImage = 0.0
                }
                ProviderTab    = "aoai"
                ServiceName    = "Azure OpenAI"
                PricingPageUrl = "https://azure.microsoft.com/en-us/pricing/details/azure-openai/"
                MeterRoles     = [ordered]@{
                    inputText        = @("Input Text", "Inpt")
                    cachedInputText  = @("Cached Input Text", "cchd Inpt")
                    inputImage       = @("Input Image", "Input Img")
                    cachedInputImage = @("Cached Input Image", "Cached Input Img")
                    outputText       = @("Output Text", "Outpt Text")
                    outputImage      = @("Output Image", "Outpt Img")
                }
            }
        }
    }
}

function Read-WizardValue {
    <#
    Helper for the wizard: reads a value with a prompt, optional default and validation.
    - Shows the prompt (and the default in parentheses if present).
    - Se l'utente preme invio a vuoto e c'e' un default, usa il default.
    - If -Options is specified, accepts only one of those values (case-insensitive).
    - If -AllowEmpty is false, it repeats until it receives a non-empty value.
    #>
    param(
        [string]$Prompt,
        [string]$Default = "",
        [string[]]$Options = @(),
        [switch]$AllowEmpty
    )
    while ($true) {
        $promptText = $Prompt
        if ($Options.Count -gt 0) { $promptText += " [" + ($Options -join "/") + "]" }
        if ($Default -ne "")      { $promptText += " (" + (T 'modelmgmt.default_hint' $Default) + ")" }
        Write-Host ""
        Write-Host $promptText -ForegroundColor Cyan
        $val = Read-Host
        if ([string]::IsNullOrWhiteSpace($val)) {
            if ($Default -ne "") { return $Default }
            if ($AllowEmpty)     { return "" }
            Write-Host (T 'modelmgmt.value_required') -ForegroundColor Yellow
            continue
        }
        $val = $val.Trim()
        if ($Options.Count -gt 0) {
            $match = $Options | Where-Object { $_.ToLower() -eq $val.ToLower() }
            if (-not $match) {
                Write-Host (T 'modelmgmt.invalid_option' ($Options -join ", ")) -ForegroundColor Yellow
                continue
            }
            return $match
        }
        return $val
    }
}

function Read-WizardYesNo {
    <# Wizard helper: reads a yes/no answer, returns $true/$false. #>
    param([string]$Prompt, [bool]$Default = $false)
    $defStr = if ($Default) { (T 'modelmgmt.yes') } else { (T 'modelmgmt.no') }
    $ans = Read-WizardValue -Prompt $Prompt -Default $defStr -Options @((T 'modelmgmt.yes'), (T 'modelmgmt.no'))
    return ($ans.ToLower() -eq (T 'modelmgmt.yes').ToLower())
}

function Test-ModelEndpoint {
    <#
    Checks the AVAILABILITY of a single model, distinguishing between "unreachable
    host" and "endpoint that responds". Used by -CheckEndpoint.

    Two-level strategy:
      1. Network reachability: TCP connection to the host:443 (as for the internet
         check). If it fails, the host is not reachable (network, DNS,
         firewall problem, or region/Foundry not available).
      2. API response: a lightweight HTTP request to the endpoint with the model's
         auth. It does not generate images: we send a deliberately minimal/empty body and
         interpret the STATUS CODE:
           - 200/400         -> the endpoint and deployment respond (400 = our
                                minimal request is incomplete, but the model is there).
           - 401/403         -> the endpoint responds but authentication is rejected
                                (the model is reachable; probably a wrong apiKey).
           - 404             -> endpoint/deployment not found (wrong config or model
                                not present in that region).
           - 429             -> rate limit: the endpoint is there and responds.
           - 5xx             -> server/Foundry-side error.
           - no response     -> timeout/unreachable.

    Returns [PSCustomObject]:
      Available   = $true if the model turns out to be available/reachable
      Reason      = i18n key explaining the outcome (for the final message)
      HttpStatus  = HTTP code obtained (0 if no response)
      HostName    = host extracted from the endpoint
    Parameters:
      -Endpoint, -ApiKey, -Deployment, -ApiSchema: model data (apiKey already plaintext)
      -TimeoutSec: HTTP call timeout (default 10)
    #>
    param(
        [string]$Endpoint,
        [string]$ApiKey,
        [string]$Deployment,
        [string]$ApiSchema = "openai-images",
        [string]$AuthMode = "",
        [int]$TimeoutSec = 10
    )

    $res = [PSCustomObject]@{
        Available  = $false
        Reason     = 'checkendpoint.unreachable'
        HttpStatus = 0
        HostName   = $null
    }

    $hostName = Get-HostFromUrl $Endpoint
    $res.HostName = $hostName
    if (-not $hostName) {
        $res.Reason = 'checkendpoint.invalid_url'
        return $res
    }

    # Livello 1: raggiungibilita' TCP
    if (-not (Test-InternetConnectivity -TargetHost $hostName -TargetPort 443 -TimeoutSec 5)) {
        $res.Reason = 'checkendpoint.unreachable'
        return $res
    }

    # Level 2: lightweight HTTP call. We do not want to generate images, so we send
    # a minimal (empty) body. We interpret the status code to decide.
    # NB: here we use HttpClient instead of Invoke-RestMethod (used elsewhere in the
    # script) on purpose: Invoke-RestMethod THROWS an exception on 4xx/5xx codes,
    # making it awkward to read the status (400/401/404 are informative outcomes for us,
    # not fatal errors). With HttpClient we read the StatusCode directly.
    $client = $null
    try {
        $handler = [System.Net.Http.HttpClientHandler]::new()
        $client = [System.Net.Http.HttpClient]::new($handler)
        $client.Timeout = [TimeSpan]::FromSeconds($TimeoutSec)

        # Auth header: default per schema, but overridable by AuthMode (from the conf).
        # Consistent with the real generation (Invoke-ImageGeneration).
        $useBearer = ($ApiSchema -eq "bfl-flux")
        if ($AuthMode -eq "bearer") { $useBearer = $true }
        elseif ($AuthMode -eq "api-key") { $useBearer = $false }
        if ($useBearer) {
            $client.DefaultRequestHeaders.Authorization =
                [System.Net.Http.Headers.AuthenticationHeaderValue]::new("Bearer", $ApiKey)
        } else {
            $client.DefaultRequestHeaders.Add("api-key", $ApiKey)
        }

        # Minimal body: we include the "model" field with the deployment, because some
        # endpoints (e.g. /openai/v1/images/generations) ROUTE the request based on the
        # model and, WITHOUT the model field, respond 404 even if the deployment exists
        # (this was the bug for which gpt-image-* showed 404 despite being available).
        # We deliberately OMIT prompt/size/etc.: this way the API responds 400 "missing
        # parameters" (model present and reachable) without generating any image.
        $probeModel = if ($Deployment -and $Deployment.Trim() -ne "") { $Deployment } else { "_probe_" }
        $probeBody  = (@{ model = $probeModel } | ConvertTo-Json -Compress)
        $content = [System.Net.Http.StringContent]::new($probeBody, [System.Text.Encoding]::UTF8, "application/json")
        $response = $client.PostAsync($Endpoint, $content).GetAwaiter().GetResult()
        $code = [int]$response.StatusCode
        $res.HttpStatus = $code

        if ($code -in @(200, 400, 422, 429)) {
            # The endpoint and the model respond: 200 ok, 400/422 minimal request
            # incomplete (missing parameters), 429 rate limit. In all cases the
            # model is reachable and recognized.
            $res.Available = $true
            $res.Reason = 'checkendpoint.available'
        } elseif ($code -in @(401, 403)) {
            # Endpoint reachable, but auth rejected. The model is there; we still
            # report it as "reachable" but with a warning about authentication.
            $res.Available = $true
            $res.Reason = 'checkendpoint.auth_failed'
        } elseif ($code -eq 404) {
            $res.Available = $false
            $res.Reason = 'checkendpoint.not_found'
        } else {
            $res.Available = $false
            $res.Reason = 'checkendpoint.http_error'
        }
    }
    catch {
        # Timeout o errore di rete a livello HTTP (l'host rispondeva al TCP ma non
        # all'HTTP entro il timeout).
        $res.Available = $false
        $res.Reason = 'checkendpoint.http_timeout'
    }
    finally {
        if ($client) { try { $client.Dispose() } catch { } }
    }

    return $res
}

function Invoke-AddModelWizard {
    <#
    Interactive wizard to add a new model to the .conf without editing it by hand.
    Guides the user with questions and pre-fills the values based on the chosen SCHEMA
    (openai-images / mai-images / bfl-flux): the operationalParams via
    Get-SchemaOperationalDefaults and the pricing structure (meters) + pricingMapping
    (providerTab, meterRoles) via Get-SchemaPricingDefaults. This ensures the entry
    is COMPLETE and with the correct meters for the schema, so the cost calculation and
    the automatic price update (-ModelPrice) work right away. It encrypts the
    API key in DPAPI and saves the .conf. Robust: validates the inputs, prevents duplicate names,
    and shows a summary (including the list of created meters) before confirming.
    #>
    param([Parameter(Mandatory=$true)] $Config, [Parameter(Mandatory=$true)] [string]$ConfigPath)

    Write-Host ""
    Write-Host (T 'modelmgmt.add_title') -ForegroundColor Green
    Write-Host ("=" * 50)

    # 1. Logical model name (unique)
    $existingNames = @($Config.models.PSObject.Properties.Name)
    $name = ""
    while ($true) {
        $name = Read-WizardValue -Prompt (T 'modelmgmt.ask_name')
        if ($existingNames -contains $name) {
            Write-Host (T 'modelmgmt.name_exists' $name) -ForegroundColor Yellow
            continue
        }
        break
    }

    # 2. API schema (determines the dialect)
    $schema = Read-WizardValue -Prompt (T 'modelmgmt.ask_schema') `
                               -Options @("openai-images","mai-images","bfl-flux") `
                               -Default "openai-images"

    # 3. Deployment (default = name)
    $deployment = Read-WizardValue -Prompt (T 'modelmgmt.ask_deployment') -Default $name

    # 4. Generation endpoint
    $endpoint = Read-WizardValue -Prompt (T 'modelmgmt.ask_endpoint')

    # 5. Auth mode (default per schema: flux=bearer, others=api-key)
    $defaultAuth = if ($schema -eq "bfl-flux") { "bearer" } else { "api-key" }
    $authMode = Read-WizardValue -Prompt (T 'modelmgmt.ask_authmode') `
                                 -Options @("api-key","bearer") -Default $defaultAuth

    # 6. Edit support
    $supportsEdit = Read-WizardYesNo -Prompt (T 'modelmgmt.ask_edit') -Default $false
    $editEndpoint = ""
    if ($supportsEdit) {
        $editEndpoint = Read-WizardValue -Prompt (T 'modelmgmt.ask_editendpoint') -AllowEmpty
    }

    # 7. shortName per i grafici (default = nome)
    $shortName = Read-WizardValue -Prompt (T 'modelmgmt.ask_shortname') -Default $name -AllowEmpty

    # 8. Region (per analytics/pricing)
    $region = Read-WizardValue -Prompt (T 'modelmgmt.ask_region') -Default "eastus" -AllowEmpty

    # 9. API key (encrypted in DPAPI). We can also leave it empty and have it asked
    # at first use (Initialize-ApiKeys), but the wizard offers to enter it right away.
    $encodedKey = ""
    if (Read-WizardYesNo -Prompt (T 'modelmgmt.ask_setkey') -Default $true) {
        $plainKey = Read-ApiKeyFromUser -ModelName $name
        if ($plainKey) {
            $encodedKey = Protect-ApiKey -PlainText $plainKey
        }
    }

    # I build the model entry with the schema's operational AND pricing defaults.
    $opDefaults    = Get-SchemaOperationalDefaults -Schema $schema
    $priceDefaults = Get-SchemaPricingDefaults -Schema $schema
    $newModel = [ordered]@{
        active                = $true
        endpoint              = $endpoint
        editEndpoint          = $editEndpoint
        failoverEndpoint      = ""
        failoverEditEndpoint  = ""
        apiKey                = $encodedKey
        deployment            = $deployment
        shortName             = $shortName
        supportsInpainting    = $false
        supportsInputFidelity = $false
        supportsBackground    = $false
        qualityRating         = 0.0
        speedRating           = 0.0
        pricing               = [ordered]@{
            imagePerUnitUsd = 0.0; lastUpdated = ""; lastUpdatedSource = ""
            meters = $priceDefaults.Meters
        }
        pricingMapping        = [ordered]@{
            officialName = $name; providerTab = $priceDefaults.ProviderTab
            serviceName = $priceDefaults.ServiceName
            armRegionName = $region; productHints = @($name)
            meterRoles = $priceDefaults.MeterRoles
            pricingPageUrl = $priceDefaults.PricingPageUrl
        }
        qualityArenaAlias       = ""
        qualityRatingLastUpdate = ""
        speedRatingLastUpdate   = ""
        apiSchema               = $schema
        authMode                = $authMode
        supportsEdit            = $supportsEdit
        operationalParams       = $opDefaults
    }

    # Summary before writing
    Write-Host ""
    Write-Host (T 'modelmgmt.summary_title') -ForegroundColor Green
    Write-Host ("  " + (T 'modelmgmt.sum_name')       + ": $name")
    Write-Host ("  " + (T 'modelmgmt.sum_schema')     + ": $schema")
    Write-Host ("  " + (T 'modelmgmt.sum_deployment') + ": $deployment")
    Write-Host ("  " + (T 'modelmgmt.sum_endpoint')   + ": $endpoint")
    Write-Host ("  " + (T 'modelmgmt.sum_authmode')   + ": $authMode")
    Write-Host ("  " + (T 'modelmgmt.sum_edit')       + ": " + $(if ($supportsEdit) { (T 'modelmgmt.yes') } else { (T 'modelmgmt.no') }))
    Write-Host ("  " + (T 'modelmgmt.sum_shortname')  + ": $shortName")
    Write-Host ("  " + (T 'modelmgmt.sum_pricing')    + ": " + (@($priceDefaults.Meters.Keys) -join ', '))
    Write-Host ("  " + (T 'modelmgmt.sum_key')        + ": " + $(if ($encodedKey) { (T 'modelmgmt.key_set') } else { (T 'modelmgmt.key_empty') }))
    Write-Host ""

    if (-not (Read-WizardYesNo -Prompt (T 'modelmgmt.confirm_save') -Default $true)) {
        Write-Host (T 'modelmgmt.aborted') -ForegroundColor Yellow
        return
    }

    # Add to the config and save
    $Config.models | Add-Member -MemberType NoteProperty -Name $name -Value ([PSCustomObject]$newModel)
    if (Save-ConfigToFile -Config $Config -Path $ConfigPath) {
        Write-Host ""
        Write-Log (T 'modelmgmt.added_ok' $name)
        if (-not $encodedKey) {
            Write-Host (T 'modelmgmt.key_reminder' $name) -ForegroundColor Yellow
        }
    }
}

function Invoke-RemoveModelWizard {
    <#
    Removes a model from the .conf in a guided and safe way: lists the models, asks
    which one to remove, asks for explicit confirmation (irreversible operation, even if
    there is the .bak backup), and saves.
    #>
    param([Parameter(Mandatory=$true)] $Config, [Parameter(Mandatory=$true)] [string]$ConfigPath)

    Write-Host ""
    Write-Host (T 'modelmgmt.remove_title') -ForegroundColor Green
    Write-Host ("=" * 50)

    $names = @($Config.models.PSObject.Properties.Name)
    if ($names.Count -eq 0) {
        Write-Host (T 'modelmgmt.no_models') -ForegroundColor Yellow
        return
    }
    # Numbered list
    Write-Host (T 'modelmgmt.available_models') -ForegroundColor Cyan
    for ($i = 0; $i -lt $names.Count; $i++) {
        $mc = $Config.models.($names[$i])
        $act = if ($null -ne $mc.active -and -not $mc.active) { " (" + (T 'modelmgmt.inactive') + ")" } else { "" }
        Write-Host ("  [" + ($i+1) + "] " + $names[$i] + $act)
    }

    $sel = Read-WizardValue -Prompt (T 'modelmgmt.ask_which_remove')
    # I accept both the number and the name
    $target = $null
    $num = 0
    if ([int]::TryParse($sel, [ref]$num) -and $num -ge 1 -and $num -le $names.Count) {
        $target = $names[$num-1]
    } elseif ($names -contains $sel) {
        $target = $sel
    }
    if (-not $target) {
        Write-Host (T 'modelmgmt.invalid_selection') -ForegroundColor Yellow
        return
    }

    if (-not (Read-WizardYesNo -Prompt (T 'modelmgmt.confirm_remove' $target) -Default $false)) {
        Write-Host (T 'modelmgmt.aborted') -ForegroundColor Yellow
        return
    }

    $Config.models.PSObject.Properties.Remove($target)
    # Se era il defaultModel, avviso
    if ($Config.defaultModel -eq $target) {
        Write-Host (T 'modelmgmt.was_default' $target) -ForegroundColor Yellow
    }
    if (Save-ConfigToFile -Config $Config -Path $ConfigPath) {
        Write-Log (T 'modelmgmt.removed_ok' $target)
    }
}

function Invoke-EditModelWizard {
    <#
    Edits an existing model. Lists the models, asks which one to edit, then for each
    field shows the current value as the default (Enter = unchanged).

    Connection fields, always proposed: endpoint, deployment, shortName, authMode,
    supportsEdit + editEndpoint, region (pricingMapping.armRegionName), and re-setting
    of the API key (encrypted in DPAPI).

    OPTIONAL sections, accessed only if the user confirms the relevant question
    (so as not to lengthen the wizard for those who only want to change an endpoint):
      - feature flags: supportsInpainting, supportsInputFidelity, supportsBackground
      - meter prices: edits the values of the model's EXISTING meters (the structure
        depends on the schema and is not changed); marks lastUpdatedSource = "manual"
      - operational parameters: the main numeric values of operationalParams (maxImages,
        minSide, maxSide, maxArea, sizeDivisibleBy, maxReferenceImages)
    Saves the .conf at the end, after confirmation.
    #>
    param([Parameter(Mandatory=$true)] $Config, [Parameter(Mandatory=$true)] [string]$ConfigPath)

    Write-Host ""
    Write-Host (T 'modelmgmt.edit_title') -ForegroundColor Green
    Write-Host ("=" * 50)

    $names = @($Config.models.PSObject.Properties.Name)
    if ($names.Count -eq 0) {
        Write-Host (T 'modelmgmt.no_models') -ForegroundColor Yellow
        return
    }
    Write-Host (T 'modelmgmt.available_models') -ForegroundColor Cyan
    for ($i = 0; $i -lt $names.Count; $i++) {
        Write-Host ("  [" + ($i+1) + "] " + $names[$i])
    }
    $sel = Read-WizardValue -Prompt (T 'modelmgmt.ask_which_edit')
    $target = $null; $num = 0
    if ([int]::TryParse($sel, [ref]$num) -and $num -ge 1 -and $num -le $names.Count) {
        $target = $names[$num-1]
    } elseif ($names -contains $sel) {
        $target = $sel
    }
    if (-not $target) {
        Write-Host (T 'modelmgmt.invalid_selection') -ForegroundColor Yellow
        return
    }

    $m = $Config.models.$target
    Write-Host ""
    Write-Host (T 'modelmgmt.editing' $target) -ForegroundColor Cyan
    Write-Host (T 'modelmgmt.edit_hint') -ForegroundColor DarkGray

    # Editable fields, each with the current value as the default.
    $m.endpoint     = Read-WizardValue -Prompt (T 'modelmgmt.ask_endpoint')   -Default ([string]$m.endpoint) -AllowEmpty
    $m.deployment   = Read-WizardValue -Prompt (T 'modelmgmt.ask_deployment') -Default ([string]$m.deployment) -AllowEmpty
    $curShort = if ($m.PSObject.Properties.Name -contains 'shortName') { [string]$m.shortName } else { $target }
    $newShort = Read-WizardValue -Prompt (T 'modelmgmt.ask_shortname') -Default $curShort -AllowEmpty
    if ($m.PSObject.Properties.Name -contains 'shortName') { $m.shortName = $newShort }
    else { $m | Add-Member -MemberType NoteProperty -Name shortName -Value $newShort }

    $curAuth = if ($m.PSObject.Properties.Name -contains 'authMode' -and $m.authMode) { [string]$m.authMode } else { "api-key" }
    $newAuth = Read-WizardValue -Prompt (T 'modelmgmt.ask_authmode') -Options @("api-key","bearer") -Default $curAuth
    if ($m.PSObject.Properties.Name -contains 'authMode') { $m.authMode = $newAuth }
    else { $m | Add-Member -MemberType NoteProperty -Name authMode -Value $newAuth }

    $curEdit = ($null -ne $m.supportsEdit -and $m.supportsEdit)
    $newEdit = Read-WizardYesNo -Prompt (T 'modelmgmt.ask_edit') -Default $curEdit
    $m.supportsEdit = $newEdit
    if ($newEdit) {
        $curEditEp = if ($m.PSObject.Properties.Name -contains 'editEndpoint') { [string]$m.editEndpoint } else { "" }
        $m.editEndpoint = Read-WizardValue -Prompt (T 'modelmgmt.ask_editendpoint') -Default $curEditEp -AllowEmpty
    }

    # Region
    $curRegion = if ($m.pricingMapping -and $m.pricingMapping.armRegionName) { [string]$m.pricingMapping.armRegionName } else { "" }
    $newRegion = Read-WizardValue -Prompt (T 'modelmgmt.ask_region') -Default $curRegion -AllowEmpty
    if ($m.pricingMapping) { $m.pricingMapping.armRegionName = $newRegion }

    # Re-set the key?
    if (Read-WizardYesNo -Prompt (T 'modelmgmt.ask_changekey') -Default $false) {
        $plainKey = Read-ApiKeyFromUser -ModelName $target
        if ($plainKey) { $m.apiKey = Protect-ApiKey -PlainText $plainKey }
    }

    # ---- Optional section: feature flags ----
    # I ask only if the user wants to enter this section, so as not to lengthen the
    # wizard for those who only want to change an endpoint.
    if (Read-WizardYesNo -Prompt (T 'modelmgmt.ask_edit_features') -Default $false) {
        $curInp = ($null -ne $m.supportsInpainting -and $m.supportsInpainting)
        $curIf  = ($null -ne $m.supportsInputFidelity -and $m.supportsInputFidelity)
        $curBg  = ($null -ne $m.supportsBackground -and $m.supportsBackground)
        $m.supportsInpainting    = Read-WizardYesNo -Prompt (T 'modelmgmt.ask_inpainting')     -Default $curInp
        $m.supportsInputFidelity = Read-WizardYesNo -Prompt (T 'modelmgmt.ask_inputfidelity')  -Default $curIf
        $m.supportsBackground    = Read-WizardYesNo -Prompt (T 'modelmgmt.ask_background')      -Default $curBg
    }

    # ---- Optional section: prices (meters) ----
    # I edit the prices of the model's EXISTING meters (the structure depends on the
    # schema; I do not change it, I only edit the values). For the automatic update there is
    # -ModelPrice anyway; this is for manual setting.
    if ($m.pricing -and $m.pricing.meters -and (Read-WizardYesNo -Prompt (T 'modelmgmt.ask_edit_pricing') -Default $false)) {
        foreach ($meterProp in @($m.pricing.meters.PSObject.Properties)) {
            $curVal = [string]$meterProp.Value
            $raw = Read-WizardValue -Prompt (T 'modelmgmt.ask_meter_price' $meterProp.Name) -Default $curVal -AllowEmpty
            $parsed = 0.0
            if (-not [string]::IsNullOrWhiteSpace($raw) -and
                [double]::TryParse($raw.Replace(',', '.'), [System.Globalization.NumberStyles]::Float, [System.Globalization.CultureInfo]::InvariantCulture, [ref]$parsed)) {
                $m.pricing.meters.($meterProp.Name) = $parsed
            }
        }
        # I mark the price as manually set.
        if ($m.pricing.PSObject.Properties.Name -contains 'lastUpdatedSource') { $m.pricing.lastUpdatedSource = "manual" }
        if ($m.pricing.PSObject.Properties.Name -contains 'lastUpdated') { $m.pricing.lastUpdated = (Get-Date).ToString("yyyy-MM-dd", [System.Globalization.CultureInfo]::InvariantCulture) }
    }

    # ---- Optional section: operational parameters ----
    # I edit the main numeric values of operationalParams (size limits and
    # number of images). The *Enforce fields and the lists stay unchanged (it is rarely needed
    # to change them by hand, and they can be edited in the .conf if necessary).
    if ($m.operationalParams -and (Read-WizardYesNo -Prompt (T 'modelmgmt.ask_edit_opparams') -Default $false)) {
        $op = $m.operationalParams
        foreach ($field in @('maxImages','minSide','maxSide','maxArea','sizeDivisibleBy','maxReferenceImages')) {
            if ($op.PSObject.Properties.Name -contains $field) {
                $curVal = [string]$op.$field
                $raw = Read-WizardValue -Prompt (T 'modelmgmt.ask_opparam' $field) -Default $curVal -AllowEmpty
                $parsed = 0
                if (-not [string]::IsNullOrWhiteSpace($raw) -and [int]::TryParse($raw, [ref]$parsed)) {
                    $op.$field = $parsed
                }
            }
        }
    }

    if (-not (Read-WizardYesNo -Prompt (T 'modelmgmt.confirm_save') -Default $true)) {
        Write-Host (T 'modelmgmt.aborted') -ForegroundColor Yellow
        return
    }
    if (Save-ConfigToFile -Config $Config -Path $ConfigPath) {
        Write-Log (T 'modelmgmt.edited_ok' $target)
    }
}

function Update-UsdToEurRate {
    <#
    Updates the USD->EUR exchange rate via the free frankfurter.app API
    (European Central Bank data, no API key, no GDPR concerns).
    The update happens ONCE A DAY: if the conf already contains
    a "usdToEurLastUpdate" field equal to today's date, the update is skipped.

    Behavior:
    - If the update is needed: calls the API with a 3s timeout, reads the rate,
      updates the fields in the conf in memory AND on disk, logs the result.
    - If the API fails (timeout, network error, malformed JSON): does not block the
      script, logs a WARN and continues with the existing value in the conf.
    - If the update is already today's: synthetic INFO log.

    Parameters:
      -Config: loaded config object (reference, modified in-place)
      -ConfigPath: path to the conf file, for the updated write to disk

    Returns: the rate value to use (whether it was updated or not).
    #>
    param(
        [Parameter(Mandatory=$true)] $Config,
        [Parameter(Mandatory=$true)] [string]$ConfigPath
    )

    $today = (Get-Date).ToString("yyyy-MM-dd", [System.Globalization.CultureInfo]::InvariantCulture)
    $lastUpdate = if ($Config.PSObject.Properties.Name -contains 'usdToEurLastUpdate') {
                      $Config.usdToEurLastUpdate
                  } else { $null }
    $currentRate = if ($Config.PSObject.Properties.Name -contains 'usdToEurRate' -and
                       $null -ne $Config.usdToEurRate -and
                       [double]$Config.usdToEurRate -gt 0) {
                      [double]$Config.usdToEurRate
                  } else { 0.92 }

    # Update already done today: skip
    if ($lastUpdate -eq $today) {
        Write-Log (T 'rate.already_today' $today (Format-DisplayNumber -Value $currentRate -Decimals 5))
        return $currentRate
    }

    # I try to call the API. Short timeout (3s) so as not to slow the script down.
    # frankfurter.app: ECB data, free, no API key, already optimized for CLI use.
    $apiUrl = "https://api.frankfurter.app/latest?base=USD&symbols=EUR"
    try {
        $response = Invoke-RestMethod -Uri $apiUrl -Method GET -TimeoutSec 3 -ErrorAction Stop
        if ($response -and $response.rates -and $response.rates.EUR) {
            $newRate = [double]$response.rates.EUR
            if ($newRate -gt 0) {
                # I update the config in memory
                if ($Config.PSObject.Properties.Name -contains 'usdToEurRate') {
                    $Config.usdToEurRate = $newRate
                } else {
                    $Config | Add-Member -NotePropertyName 'usdToEurRate' -NotePropertyValue $newRate -Force
                }
                if ($Config.PSObject.Properties.Name -contains 'usdToEurLastUpdate') {
                    $Config.usdToEurLastUpdate = $today
                } else {
                    $Config | Add-Member -NotePropertyName 'usdToEurLastUpdate' -NotePropertyValue $today -Force
                }

                # I save the updated config to disk (preserving the indented JSON format)
                try {
                    $Config | ConvertTo-Json -Depth 10 | Set-Content -Path $ConfigPath -Encoding UTF8 -ErrorAction Stop
                    Write-Log (T 'rate.updated' (Format-DisplayNumber -Value $newRate -Decimals 5) $today)
                }
                catch {
                    Write-Log (T 'rate.memory_only' (Format-DisplayNumber -Value $newRate -Decimals 5) ($_.Exception.Message)) -Level WARN
                }

                return $newRate
            }
        }
        # Valid response but without EUR (unlikely)
        Write-Log (T 'rate.unexpected_response' (Format-DisplayNumber -Value $currentRate -Decimals 5)) -Level WARN
        return $currentRate
    }
    catch {
        # Timeout, network error, API down. We continue with the previous value.
        Write-Log (T 'rate.update_failed' ($_.Exception.Message) (Format-DisplayNumber -Value $currentRate -Decimals 5)) -Level WARN
        return $currentRate
    }
}

function Convert-ConfigToNewPricingStructure {
    <#
    Automatic migration of the .conf pricing structure.

    Adds pricingMapping for each model + pricingUpdate root, and converts the
    pricing schema from 3 flat fields to a .meters hashtable
    with 6/2 keys to support Microsoft's granular pricing (Input Text, Cached Input
    Text, Input Image, Cached Input Image, Output Text, Output Image for AOAI; Input/Output
    for MAI). See Get-CostBreakdown for the rationale.

    Changes handled (in order):
      1. If 'pricingUpdate' is missing at the root level, adds it with sane defaults
      2. For each model:
         a. If 'pricingMapping' is missing, adds it with reasonable placeholders
         b. Migrates 'pricing.priceLastUpdated' -> 'pricing.lastUpdated' (legacy field)
         c. Adds 'pricing.lastUpdatedSource' if missing
         d. Adds 'pricing.imagePerUnitUsd' if missing
         e. ROUND E: converts the old flat fields
            ({input,output,image}TokensPerMillionUsd) into 'pricing.meters' as
            keys {inputText, outputText, outputImage} (AOAI provider) or
            {input, output} (Microsoft/MAI provider). The flat fields are
            removed AFTER the conversion (safe: they are copied first).
         f. ROUND E: updates pricingMapping.meterRoles to the new names if still
            using the old keys (inputTokens/outputTokens/imageTokens).
      3. Kept for compat: 'azureMeterFilter' (deprecated, only a log warning).

    Idempotent: rerunning it on an already-migrated conf changes nothing.
    Returns $true if it changed something, $false otherwise.
    #>
    param(
        [Parameter(Mandatory=$true)] $Config,
        [Parameter(Mandatory=$true)] [string]$ConfigPath
    )

    $changed = $false

    # ---- Aggiunta pricingUpdate root se manca ----
    if (-not ($Config.PSObject.Properties.Name -contains 'pricingUpdate')) {
        $newPricingUpdate = [PSCustomObject]@{
            enabled            = $true
            timeoutSec         = 15
            writeDiscoveryFile = $true
            frequencyDays      = 7
        }
        $Config | Add-Member -NotePropertyName 'pricingUpdate' -NotePropertyValue $newPricingUpdate -Force
        $changed = $true
    }

    # ---- Per-model migration ----
    $modelNames = @($Config.models | Get-Member -MemberType NoteProperty | Select-Object -ExpandProperty Name)
    foreach ($mdlName in $modelNames) {
        $mdl = $Config.models.$mdlName

        # ---- adding apiSchema and supportsEdit if missing ----
        # apiSchema: for pre-existing models we assume "openai-images" (the already
        # configured gpt-image). The new schemas (mai-images, bfl-flux) must be set by hand.
        # supportsEdit: default true for back-compat (gpt-image supports edit).
        if (-not ($mdl.PSObject.Properties.Name -contains 'apiSchema')) {
            $mdl | Add-Member -NotePropertyName 'apiSchema' -NotePropertyValue 'openai-images' -Force
            $changed = $true
        }
        if (-not ($mdl.PSObject.Properties.Name -contains 'supportsEdit')) {
            $mdl | Add-Member -NotePropertyName 'supportsEdit' -NotePropertyValue $true -Force
            $changed = $true
        }

        # ---- Pricing fields migration ----
        if ($mdl.pricing) {
            # priceLastUpdated -> lastUpdated
            if (($mdl.pricing.PSObject.Properties.Name -contains 'priceLastUpdated') -and
                -not ($mdl.pricing.PSObject.Properties.Name -contains 'lastUpdated')) {
                $oldVal = $mdl.pricing.priceLastUpdated
                $mdl.pricing | Add-Member -NotePropertyName 'lastUpdated' -NotePropertyValue $oldVal -Force
                $mdl.pricing.PSObject.Properties.Remove('priceLastUpdated')
                $changed = $true
            }
            if (-not ($mdl.pricing.PSObject.Properties.Name -contains 'lastUpdatedSource')) {
                $mdl.pricing | Add-Member -NotePropertyName 'lastUpdatedSource' -NotePropertyValue 'manual' -Force
                $changed = $true
            }
            if (-not ($mdl.pricing.PSObject.Properties.Name -contains 'imagePerUnitUsd')) {
                $mdl.pricing | Add-Member -NotePropertyName 'imagePerUnitUsd' -NotePropertyValue 0.0 -Force
                $changed = $true
            }

            # migration of the 3 flat fields -> meters
            # Detect: if there is NOT already a .meters, but there is at least one of the old flat fields
            $hasFlatFields = ($mdl.pricing.PSObject.Properties.Name -contains 'inputTokensPerMillionUsd') -or
                             ($mdl.pricing.PSObject.Properties.Name -contains 'outputTokensPerMillionUsd') -or
                             ($mdl.pricing.PSObject.Properties.Name -contains 'imageTokensPerMillionUsd')
            $hasMeters = ($mdl.pricing.PSObject.Properties.Name -contains 'meters') -and ($null -ne $mdl.pricing.meters)
            if ($hasFlatFields -and -not $hasMeters) {
                # I determine the provider (aoai vs microsoft) from the pricingMapping to
                # understand how to interpret the 3 old fields:
                # - AOAI: input=Input Text ($5), output=Output Text, image=Output Image ($30)
                # - MAI: input=Input, output=Output (any), image unused
                $providerTab = if ($mdl.pricingMapping -and $mdl.pricingMapping.providerTab) {
                    [string]$mdl.pricingMapping.providerTab
                } else { 'aoai' }   # conservative default

                $inV = if ($null -ne $mdl.pricing.inputTokensPerMillionUsd)  { [double]$mdl.pricing.inputTokensPerMillionUsd }  else { 0.0 }
                $ouV = if ($null -ne $mdl.pricing.outputTokensPerMillionUsd) { [double]$mdl.pricing.outputTokensPerMillionUsd } else { 0.0 }
                $imV = if ($null -ne $mdl.pricing.imageTokensPerMillionUsd)  { [double]$mdl.pricing.imageTokensPerMillionUsd }  else { 0.0 }

                if ($providerTab -ieq 'microsoft') {
                    # MAI columnar: input/output
                    $newMeters = [PSCustomObject]@{
                        input  = [math]::Round($inV, 4)
                        output = [math]::Round($ouV, 4)
                    }
                } else {
                    # AOAI labeled: the old 3 fields map to inputText/outputText/outputImage.
                    # We leave inputImage / cachedInputText / cachedInputImage at 0.0: they will be
                    # populated on the first -ModelPrice run (the scraping now extracts all 6 meters).
                    $newMeters = [PSCustomObject]@{
                        inputText        = [math]::Round($inV, 4)
                        cachedInputText  = 0.0
                        inputImage       = 0.0
                        cachedInputImage = 0.0
                        outputText       = [math]::Round($ouV, 4)
                        outputImage      = [math]::Round($imV, 4)
                    }
                }
                $mdl.pricing | Add-Member -NotePropertyName 'meters' -NotePropertyValue $newMeters -Force

                # I remove the old flat fields (already migrated): this way the new .conf
                # has no duplicates and the reading only reads .meters.
                foreach ($oldF in @('inputTokensPerMillionUsd', 'outputTokensPerMillionUsd', 'imageTokensPerMillionUsd')) {
                    if ($mdl.pricing.PSObject.Properties.Name -contains $oldF) {
                        $mdl.pricing.PSObject.Properties.Remove($oldF)
                    }
                }
                # I force lastUpdatedSource to 'migrated' for tracking
                $mdl.pricing.lastUpdatedSource = 'migrated'
                $changed = $true
            }

            # Case "missing both" (model just added by hand): initialize an empty meters
            if (-not $hasFlatFields -and -not $hasMeters) {
                $providerTab = if ($mdl.pricingMapping -and $mdl.pricingMapping.providerTab) {
                    [string]$mdl.pricingMapping.providerTab
                } else { 'aoai' }
                $newMeters = if ($providerTab -ieq 'microsoft') {
                    [PSCustomObject]@{ input = 0.0; output = 0.0 }
                } else {
                    [PSCustomObject]@{
                        inputText = 0.0; cachedInputText = 0.0;
                        inputImage = 0.0; cachedInputImage = 0.0;
                        outputText = 0.0; outputImage = 0.0
                    }
                }
                $mdl.pricing | Add-Member -NotePropertyName 'meters' -NotePropertyValue $newMeters -Force
                $changed = $true
            }
        }

        # ---- Migration of pricingMapping.meterRoles from the old names to the new ones ----
        if ($mdl.pricingMapping -and $mdl.pricingMapping.meterRoles) {
            $mr = $mdl.pricingMapping.meterRoles
            $hasOldRoleNames = ($mr.PSObject.Properties.Name -contains 'inputTokens')  -or
                               ($mr.PSObject.Properties.Name -contains 'outputTokens') -or
                               ($mr.PSObject.Properties.Name -contains 'imageTokens')
            if ($hasOldRoleNames) {
                $providerTab = if ($mdl.pricingMapping.providerTab) {
                    [string]$mdl.pricingMapping.providerTab
                } else { 'aoai' }

                # I build a new meterRoles with the new keys
                $newMr = if ($providerTab -ieq 'microsoft') {
                    [PSCustomObject]@{
                        input  = @("Input")
                        output = @("Output")
                    }
                } else {
                    [PSCustomObject]@{
                        inputText        = @("Input Text", "Inpt")
                        cachedInputText  = @("Cached Input Text", "cchd Inpt")
                        inputImage       = @("Input Image", "Input Img")
                        cachedInputImage = @("Cached Input Image", "Cached Input Img")
                        outputText       = @("Output Text", "Outpt Text", "Output")
                        outputImage      = @("Output Image", "Outpt Img")
                    }
                }
                $mdl.pricingMapping.meterRoles = $newMr
                $changed = $true
            }
        }

        # Aggiunta pricingMapping se manca
        if (-not ($mdl.PSObject.Properties.Name -contains 'pricingMapping')) {
            $defaultMapping = Get-DefaultPricingMappingForModel -ModelName $mdlName
            $mdl | Add-Member -NotePropertyName 'pricingMapping' -NotePropertyValue $defaultMapping -Force
            $changed = $true
        }

        # ---- fields for -Auto Quality/Time ----
        # I add the new fields 'qualityArenaAlias', 'qualityRatingLastUpdate',
        # 'speedRatingLastUpdate' if missing. I do NOT touch the existing values of
        # 'qualityRating' and 'speedRating' (they respect the user's manual evaluation).
        if (-not ($mdl.PSObject.Properties.Name -contains 'qualityArenaAlias')) {
            # I try to guess the arena alias from the model name (best-effort).
            # If there is no match, I leave an empty string: the scraping function will do
            # a fuzzy matching at runtime and, on failure, chooses the
            # closest model or logs a warning.
            $defaultAlias = ""
            $nameLower = $mdlName.ToLower()
            if ($nameLower -eq 'gpt-image-2')   { $defaultAlias = "gpt-image-2 (medium)" }
            elseif ($nameLower -eq 'gpt-image-1.5') { $defaultAlias = "gpt-image-1.5-high-fidelity" }
            elseif ($nameLower -eq 'mai-image-2')   { $defaultAlias = "mai-image-2" }
            $mdl | Add-Member -NotePropertyName 'qualityArenaAlias' -NotePropertyValue $defaultAlias -Force
            $changed = $true
        }
        if (-not ($mdl.PSObject.Properties.Name -contains 'qualityRatingLastUpdate')) {
            $mdl | Add-Member -NotePropertyName 'qualityRatingLastUpdate' -NotePropertyValue "" -Force
            $changed = $true
        }
        if (-not ($mdl.PSObject.Properties.Name -contains 'speedRatingLastUpdate')) {
            $mdl | Add-Member -NotePropertyName 'speedRatingLastUpdate' -NotePropertyValue "" -Force
            $changed = $true
        }
    }

    # ---- root autoUpdate block (for -Auto Quality/Time) ----
    if (-not ($Config.PSObject.Properties.Name -contains 'autoUpdate')) {
        $newAutoUpdate = [PSCustomObject]@{
            arenaUrl           = "https://arena.ai/leaderboard/text-to-image"
            arenaTimeoutSec    = 15
            qualityRefreshDays = 7
            timeRefreshDays    = 7
            timeMinRecords     = 3
            timeMaxRecords     = 50
        }
        $Config | Add-Member -NotePropertyName 'autoUpdate' -NotePropertyValue $newAutoUpdate -Force
        $changed = $true
    }

    # ---- Save if modified ----
    if ($changed) {
        try {
            $Config | ConvertTo-Json -Depth 10 | Set-Content -Path $ConfigPath -Encoding UTF8 -ErrorAction Stop
        } catch {
            # Best-effort: the migration does not block the script
        }
    }

    return $changed
}

function Get-DefaultPricingMappingForModel {
    <#
    Generates a default pricingMapping for a model based on its logical name.
    Uses heuristics to guess the probable naming on Azure:
      - "gpt-image-X"  -> API productName "Azure OpenAI Media", region eastus2, tab aoai (6 meters)
      - "MAI-image-X"  -> API productName "MAI Models", region eastus, tab microsoft (2 meters)
      - others         -> generic productHints based on the name, aoai schema by default
    meterRoles uses the new schema with API-specific hints as the
    first element (e.g. "Image 2 txt inp Gl") and HTML fallbacks as later elements
    (e.g. "Input Text"). This lets Phase 1 (exact API) match the
    Microsoft meters on the first try, avoiding scraping for the known models.
    The user can refine the mapping in the .conf after the migration (or leave
    che la pipeline di pricing esegua una discovery e suggerisca i nomi reali).
    #>
    param([Parameter(Mandatory=$true)] [string]$ModelName)

    $isMai = $ModelName -match '^MAI'
    $isGptImage = $ModelName -match '^gpt-image'

    if ($isMai) {
        # Example: "MAI-Image-2e" -> "MAI-Image-2-Efficient Global", meter pattern "Image 2e ..."
        # "MAI-Image-2" -> "MAI-Image-2 Global", meter pattern "Image 2 ..." (with a space)
        $base = if ($ModelName -match 'e$') {
            $ModelName -replace 'e$', '-Efficient'
        } else {
            $ModelName
        }
        # Pattern for the API meters: I extract the "core" of the name (e.g. "Image 2e" or "Image 2")
        # from the model name. "MAI-Image-2e" -> "Image 2e"; "MAI-Image-2" -> "Image 2".
        $meterCore = $ModelName -replace '^MAI-Image-', 'Image '
        return [PSCustomObject]@{
            officialName    = "$base Global"
            providerTab     = "microsoft"
            serviceName     = "Azure OpenAI"
            armRegionName   = "eastus"
            productHints    = @(
                "MAI Models",                   # productName API reale
                "$base Global",
                $base,
                $ModelName,
                "MAI-Image",
                "MAI"
            )
            meterRoles      = [PSCustomObject]@{
                input  = @("$meterCore Text Input glbl", "Input", "Inpt")
                output = @("$meterCore Output glbl", "Output", "Outpt")
            }
            pricingPageUrl  = "https://azure.microsoft.com/en-us/pricing/details/ai-foundry-models/microsoft/"
        }
    } elseif ($isGptImage) {
        # Esempio: "gpt-image-2" -> "GPT-Image-2 Global", pattern meter "Image 2 ..."
        $cap = $ModelName -replace '^gpt-image-', 'GPT-Image-'
        # Pattern meter API: "gpt-image-2" -> "Image 2", "gpt-image-1.5" -> "Image 1.5"
        $meterCore = $ModelName -replace '^gpt-image-', 'Image '
        return [PSCustomObject]@{
            officialName    = "$cap Global"
            providerTab     = "aoai"
            serviceName     = "Azure OpenAI"
            armRegionName   = "eastus2"
            productHints    = @(
                "Azure OpenAI Media",            # productName API reale
                "$cap Global",
                $cap,
                $ModelName,
                "Azure OpenAI"
            )
            meterRoles      = [PSCustomObject]@{
                inputText        = @("$meterCore txt inp Gl", "Input Text", "Inpt")
                cachedInputText  = @("$meterCore txt cd inp Gl", "Cached Input Text", "cchd Inpt")
                inputImage       = @("$meterCore img inp Gl", "Input Image", "Input Img")
                cachedInputImage = @("$meterCore img cd inp Gl", "Cached Input Image", "Cached Input Img")
                outputText       = @("$meterCore txt opt Gl", "Output Text", "Outpt Text")
                outputImage      = @("$meterCore img opt Gl", "Output Image", "Outpt Img", "Image Output")
            }
            pricingPageUrl  = "https://azure.microsoft.com/en-us/pricing/details/azure-openai/"
        }
    } else {
        # Generic model: hints derived from the name, labeled schema by default
        return [PSCustomObject]@{
            officialName    = $ModelName
            providerTab     = "aoai"
            serviceName     = "Azure OpenAI"
            armRegionName   = "eastus"
            productHints    = @($ModelName, "Azure OpenAI")
            meterRoles      = [PSCustomObject]@{
                inputText        = @("Input Text", "Inpt", "Input Tokens")
                cachedInputText  = @("Cached Input Text", "cchd Inpt", "Cached Inpt")
                inputImage       = @("Input Image", "Input Img")
                cachedInputImage = @("Cached Input Image", "Cached Input Img")
                outputText       = @("Output Text", "Outpt Text")
                outputImage      = @("Output Image", "Outpt Img", "Image Output")
            }
            pricingPageUrl  = ""
        }
    }
}

function Get-PricingUnitMultiplier {
    <#
    Normalizes the price returned by the API to USD per 1 MILLION units.

    The Azure Retail API returns the 'unitOfMeasure' field (e.g. "1K", "1M",
    "100", "1") which indicates for how many meter units the 'unitPrice' applies.
    Examples:
      - unitPrice=0.005, unitOfMeasure="1K Tokens" -> 0.005 USD per 1000 tokens
        => 5.00 USD per 1M tokens (multiplier 1000)
      - unitPrice=10.0, unitOfMeasure="1M Tokens" -> 10.0 USD per 1M tokens
        => 10.00 USD per 1M tokens (multiplier 1)
      - unitPrice=0.04, unitOfMeasure="1 Image" -> 0.04 USD per image
        => 40000 USD per 1M images (multiplier 1000000), but in practice
        we use this datum directly as "per image" (imagePerUnitUsd field)
      - unitPrice=4.0, unitOfMeasure="100 Images" -> 4.0 USD per 100 images
        => 0.04 USD per image (multiplier 0.01 when we want per image)

    Returns an object with:
      - PerMillionUsd: price normalized to USD/1M units (for tokens or sub-units)
      - PerUnitUsd:    price normalized to USD/1 unit (for a whole image)
      - UnitType:      "tokens" | "images" | "unknown"

    This way the caller can choose the appropriate field (inputTokensPerMillionUsd
    vs imagePerUnitUsd) based on the meter type.
    #>
    param(
        [Parameter(Mandatory=$true)] [double]$UnitPrice,
        [Parameter(Mandatory=$true)] [string]$UnitOfMeasure
    )

    # Parsing dell'unitOfMeasure. Esempi reali:
    # "1K Tokens", "1M Tokens", "1K", "1M", "1 Image", "100 Images", "1 Hour"
    $uom = $UnitOfMeasure.Trim()

    # Estraggo il numero (1, 100, 1000, 1000000, ...)
    $quantity = 1.0
    $unitText = ""
    if ($uom -match '^(\d+(?:\.\d+)?)\s*([KMG])?\s*(.*)$') {
        $quantity = [double]$Matches[1]
        $suffix = $Matches[2]
        $unitText = $Matches[3].Trim().ToLower()
        if ($suffix -eq 'K') { $quantity *= 1000 }
        elseif ($suffix -eq 'M') { $quantity *= 1000000 }
        elseif ($suffix -eq 'G') { $quantity *= 1000000000 }
    } else {
        # Formato non riconosciuto: assumo "1 <unit>"
        $unitText = $uom.ToLower()
    }

    # I determine the unit type
    # added "megapixel"/"mp" for the FLUX models (per-MP pricing).
    $unitType = if ($unitText -match 'token') { "tokens" }
                elseif ($unitText -match 'megapixel|mpx|\bmp\b') { "megapixels" }
                elseif ($unitText -match 'image') { "images" }
                else { "unknown" }

    # Calcoli:
    # - PerMillionUsd = (UnitPrice / quantity) * 1.000.000
    # - PerUnitUsd = UnitPrice / quantity
    $perUnit     = if ($quantity -gt 0) { $UnitPrice / $quantity } else { 0.0 }
    $perMillion  = $perUnit * 1000000.0

    return [PSCustomObject]@{
        PerMillionUsd = $perMillion
        PerUnitUsd    = $perUnit
        UnitType      = $unitType
        Quantity      = $quantity
        UnitText      = $unitText
    }
}

function Invoke-PricingApiQuery {
    <#
    Invoca la Azure Retail Prices API con un filtro OData, gestendo:
      - escape corretto del parametro $filter (delicatissimo in PowerShell)
      - paginazione automatica via NextPageLink (fino a 5 pagine = 500 record max)
      - timeout configurabile
      - currency code

    Returns the complete array of Items (concatenated from all pages), or
    $null on error (timeout, HTTP error, malformed JSON).

    Technical notes on escaping:
      The API accepts the parameter as `$filter`. In PowerShell, `$filter` inside
      double-quoted strings is interpreted as a variable. We therefore use
      `[uri]::EscapeDataString` on the filter value and build the URL
      by concatenating literal strings with backticks. The backtick before the `$`
      avoids PowerShell interpolation but keeps the literal `$` in the URL.
    #>
    param(
        [Parameter(Mandatory=$true)] [string]$Filter,
        [int]$TimeoutSec = 15,
        [string]$CurrencyCode = "USD",
        [int]$MaxPages = 5
    )

    $allItems = [System.Collections.Generic.List[object]]::new()
    $encodedFilter = [uri]::EscapeDataString($Filter)
    # Backtick davanti a $filter: lo lascia letterale nell'URL invece di interpolarlo
    $url = "https://prices.azure.com/api/retail/prices?`$filter=$encodedFilter&currencyCode=$CurrencyCode"

    $pageCount = 0
    while ($url -and $pageCount -lt $MaxPages) {
        try {
            # Headers per evitare problemi di compressione/encoding con alcuni proxy
            $headers = @{ 'Accept' = 'application/json' }
            $response = Invoke-RestMethod -Uri $url -Method GET -Headers $headers `
                                          -TimeoutSec $TimeoutSec -ErrorAction Stop
        } catch {
            # Distingui timeout da altri errori
            if ($_.Exception.Message -match 'timeout|timed out|task was canceled') {
                throw "TIMEOUT after ${TimeoutSec}s"
            }
            throw $_
        }

        if ($response -and $response.Items) {
            $allItems.AddRange(@($response.Items))
        }

        # Paginazione
        if ($response -and $response.NextPageLink) {
            $url = $response.NextPageLink
            $pageCount++
        } else {
            $url = $null
        }
    }

    return @($allItems)
}

function Find-MeterInItems {
    <#
    Searches for a specific meter among the Items returned by the API, trying the
    'meterHints' in order. Returns the first Item that matches, or $null.

    Logic:
      - For each hint (in order), look for an Item where meterName contains that hint
        (case-insensitive)
      - If found, returns the Item
      - If no hint matches, returns $null
    #>
    param(
        [Parameter(Mandatory=$true)] [array]$Items,
        [Parameter(Mandatory=$true)] [string[]]$MeterHints
    )

    foreach ($hint in $MeterHints) {
        $matched = $Items | Where-Object {
            $_.meterName -and ($_.meterName.ToLower().Contains($hint.ToLower()))
        } | Select-Object -First 1
        if ($matched) {
            return $matched
        }
    }
    return $null
}

function Get-ArmRegionAlias {
    <#
    Converts a region name in ARM format (e.g. "eastus2") into the alternative names
    used by the Azure pricing page (e.g. "us-east-2", "eastus2", "us-east2").

    The Retail API uses the canonical ARM format ("eastus2"), but the pricing page uses
    the "human readable" format with hyphens ("us-east-2"). Both are needed to
    match correctly.

    Returns an array of possible names to try in order. The first element is
    always the original ARM name (for fallback).
    #>
    param([string]$ArmRegion)

    if (-not $ArmRegion -or $ArmRegion.Trim() -eq "") { return @() }

    $arm = $ArmRegion.ToLower().Trim()
    $aliases = New-Object System.Collections.ArrayList
    [void]$aliases.Add($arm)

    # Mapping ARM -> pricing-page region. List compiled from the data observed in
    # debug-pricing-page-azureopenai.html. It is NOT exhaustive; for regions that do not
    # match the pattern, the "regex-based" section below handles it.
    $explicitMap = @{
        'eastus'        = @('us-east')
        'eastus2'       = @('us-east-2')
        'westus'        = @('us-west')
        'westus2'       = @('us-west-2')
        'westus3'       = @('us-west-3')
        'centralus'     = @('us-central')
        'northcentralus'= @('us-north-central')
        'southcentralus'= @('us-south-central')
        'westcentralus' = @('us-west-central')
        'westeurope'    = @('europe-west')
        'northeurope'   = @('europe-north')
        'francecentral' = @('france-central')
        'germanywestcentral'='germany-west-central'
        'italynorth'    = @('italy-north')
        'norwayeast'    = @('norway-east')
        'polandcentral' = @('poland-central')
        'spaincentral'  = @('spain-central')
        'swedencentral' = @('sweden-central')
        'switzerlandnorth'='switzerland-north'
        'uksouth'       = @('united-kingdom-south')
        'ukwest'        = @('united-kingdom-west')
        'uaenorth'      = @('uae-north')
        'australiaeast' = @('australia-east')
        'brazilsouth'   = @('brazil-south')
        'canadacentral' = @('canada-central')
        'canadaeast'    = @('canada-east')
        'japaneast'     = @('japan-east')
        'japanwest'     = @('japan-west')
        'koreacentral'  = @('korea-central')
        'southafricanorth'=@('south-africa-north')
        'southeastasia' = @('asia-pacific-southeast')
        'southindia'    = @('south-india')
    }

    if ($explicitMap.ContainsKey($arm)) {
        foreach ($a in $explicitMap[$arm]) {
            if (-not $aliases.Contains($a)) { [void]$aliases.Add($a) }
        }
    }

    # Regex-based: separates letters/numbers with hyphens (eastus2 -> east-us-2, us-east-2)
    # Generic strategy: insert a hyphen before each group of digits, then between
    # known regions (east/west/north/south/central). Approximate but covers many cases.
    if ($arm -match '^([a-z]+)([0-9]+)?$') {
        $letters = $Matches[1]
        $num = $Matches[2]
        # Separa direzioni: "eastus" -> "us-east", "westeurope" -> "europe-west"
        $directions = @('east', 'west', 'north', 'south', 'central')
        foreach ($dir in $directions) {
            if ($letters.StartsWith($dir)) {
                $area = $letters.Substring($dir.Length)
                if ($area) {
                    $variant = "$area-$dir"
                    if ($num) { $variant += "-$num" }
                    if (-not $aliases.Contains($variant)) { [void]$aliases.Add($variant) }
                }
            }
        }
    }

    return @($aliases)
}

function Get-PricesFromPricingPage {
    <#
    Downloads the official Microsoft Azure pricing page and extracts the prices
    for a specific model and region, using DOM parsing (not regex on the prices).

    Strategy:
      1. Download the page HTML with Invoke-WebRequest (no JS rendering).
      2. Find the <tr> row that contains OfficialName in the <td>.
      3. Identify the table structure via <thead><th>:
         a) "Labeled" (e.g. AOAI): cells contain "Label: <span data-amount>" pairs
            -> mapping by label (Input Text, Output Image, etc.)
         b) "Columnar" (e.g. MAI Microsoft): positional columns (Models | Input | Output)
            -> mapping by column position
      4. For each <span class='price-data' data-amount='{"regional":{...}}'>:
         decode the JSON, extract the price for ArmRegion (trying aliases).
      5. Map the labels/columns to the .conf meterRoles (inputTokens, outputTokens,
         imageTokens). The labels "Input Text" + "Input Image" accumulate under
         "inputTokens" via a default mapping consistent with the 4-field schema.

    Returns a hashtable @{ inputTokens = $normObject, outputTokens = ..., imageTokens = ... }
    where $normObject has PerMillionUsd, PerUnitUsd, UnitType. Empty if nothing found.

    NOTE: the prices on the page are in USD/1M tokens (e.g. $5.0 = $5/1M tokens).
    So PerMillionUsd = raw value of the data-amount, no conversion.
    #>
    param(
        [Parameter(Mandatory=$true)] [string]$PageUrl,
        [Parameter(Mandatory=$true)] [string]$OfficialName,
        [string]$ArmRegion = "",
        [hashtable]$MeterRoles = $null,
        [int]$TimeoutSec = 30
    )

    # --- 1. Download HTML ---
    $headers = @{
        'Accept' = 'text/html,application/xhtml+xml'
        'Accept-Language' = 'en-US,en;q=0.9'
        'User-Agent' = 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 PowerShell New-GPTImage.ps1'
    }
    $resp = Invoke-WebRequest -Uri $PageUrl -Headers $headers -TimeoutSec $TimeoutSec `
                              -ErrorAction Stop -UseBasicParsing
    $html = $resp.Content

    # --- 1b. "per-row" PARSER (meter-per-row tables, e.g. FLUX/Black Forest Labs) ---
    # Some pages (FLUX) use a "Models | Price/Image" table where EACH meter is
    # a SEPARATE ROW (e.g. "Flux 2 Pro Initial MP", "Flux 2 Pro MP", "Flux 2 Ref MP"),
    # NOT columns of the same row. The standard model (one row = one model, meters
    # in the columns) does not work here, and the OfficialName match also fails because
    # the model's "showcase" name does not appear as a single row.
    # This parser is INDEPENDENT of OfficialName: for each meter key in the .conf
    # (e.g. firstMpUsd) it looks for the <tr> whose first <td> contains one of the hints defined
    # in meterRoles (e.g. "Flux 2 Pro Initial MP") and extracts its data-amount.
    # I try it BEFORE the OfficialName match: if it finds prices, I am done; otherwise
    # I continue with the standard flow (labeled/columnar) that requires OfficialName.
    # It activates only if there are meterRoles and at least one hint matches a row name.
    if ($MeterRoles -and $MeterRoles.Keys.Count -gt 0) {
        $regionAliasesPR = Get-ArmRegionAlias -ArmRegion $ArmRegion
        $allRegionsPR = New-Object System.Collections.Generic.HashSet[string]
        # I extract ALL the <tr><td>name</td><td>...data-amount...</td></tr> rows of the page.
        $rowRe = [regex]::new('<tr>\s*<td>([^<]+)</td>\s*<td>(.*?)</td>\s*</tr>',
            [System.Text.RegularExpressions.RegexOptions]::Singleline)
        $pageRows = @()
        foreach ($rm in $rowRe.Matches($html)) {
            $rowName = $rm.Groups[1].Value.Trim()
            $rowCell = $rm.Groups[2].Value
            $daM = [regex]::Match($rowCell, "data-amount='([^']+)'",
                [System.Text.RegularExpressions.RegexOptions]::Singleline)
            if ($daM.Success) {
                $pageRows += [PSCustomObject]@{ Name = $rowName; DataAmount = $daM.Groups[1].Value }
            }
        }
        if ($pageRows.Count -gt 0) {
            $perRowPrices = @{}
            foreach ($meterKey in $MeterRoles.Keys) {
                $hints = @($MeterRoles[$meterKey])
                foreach ($pr in $pageRows) {
                    $nameLower = $pr.Name.ToLowerInvariant()
                    $hit = $false
                    foreach ($hint in $hints) {
                        if ($hint -and $nameLower.Contains([string]$hint.ToString().ToLowerInvariant())) {
                            $hit = $true; break
                        }
                    }
                    if ($hit) {
                        $da = $pr.DataAmount.Replace('&quot;', '"').Replace('&apos;', "'")
                        $price = Get-PriceFromDataAmount -DataAmountJson $da `
                                    -RegionAliases $regionAliasesPR -AllRegionsCollector $allRegionsPR
                        if ($null -ne $price) {
                            # NB: for per-megapixel tables the value is ALREADY the per-MP
                            # price (USD/Megapixel), not per 1M tokens: it is used raw.
                            $perRowPrices[$meterKey] = [double]$price
                            break
                        }
                    }
                }
            }
            if ($perRowPrices.Count -gt 0) {
                $regionUsedPR = ($regionAliasesPR | Where-Object { $_ -in $allRegionsPR } | Select-Object -First 1)
                if (-not $regionUsedPR) { $regionUsedPR = $ArmRegion }
                Write-Log (T 'pricing.scraping_html_parsed' $OfficialName 'per-row' $perRowPrices.Count $regionUsedPR)
                return $perRowPrices
            }
        }
    }

    # --- 2. Find <tr>...<td>OfficialName</td>...</tr> ---
    # I look for "OfficialName</td>" and then extract everything up to the next </tr>.
    # Robustness: I try MULTIPLE variants of the name before giving up, because the exact
    # text of the cell on the Azure page may differ from the .conf officialName
    # in details (uppercase, dots vs spaces, "Global"/"MP" suffixes). I try in order:
    #   1. the name as-is (case-insensitive)
    #   2. generated variants: without dots, dots<->spaces, without common suffixes
    # The match is always case-insensitive. This way an "almost right" officialName works
    # anyway, and the user does not have to get the string exactly right.
    $nameCandidates = [System.Collections.Generic.List[string]]::new()
    [void]$nameCandidates.Add($OfficialName)
    # Variant without dots (e.g. "FLUX.2 pro" -> "FLUX2 pro")
    [void]$nameCandidates.Add(($OfficialName -replace '\.', ''))
    # Variant dots -> spaces (e.g. "FLUX.2-pro" -> "FLUX 2-pro")
    [void]$nameCandidates.Add(($OfficialName -replace '\.', ' '))
    # Variant hyphens -> spaces (e.g. "FLUX.2-pro" -> "FLUX.2 pro")
    [void]$nameCandidates.Add(($OfficialName -replace '-', ' '))
    # Variant without common showcase suffixes (Global / MP / Initial MP)
    $stripped = $OfficialName -replace '\s+(Global|MP|Initial MP)\s*$', ''
    [void]$nameCandidates.Add($stripped)

    $rowMatch = $null
    $matchedName = $null
    foreach ($cand in $nameCandidates) {
        if ([string]::IsNullOrWhiteSpace($cand)) { continue }
        $candEsc = [regex]::Escape($cand.Trim())
        $rowPattern = "$candEsc</td>(.+?)</tr>"
        $m = [regex]::Match($html, $rowPattern,
            ([System.Text.RegularExpressions.RegexOptions]::Singleline -bor [System.Text.RegularExpressions.RegexOptions]::IgnoreCase))
        if ($m.Success) { $rowMatch = $m; $matchedName = $cand; break }
    }

    if (-not $rowMatch -or -not $rowMatch.Success) {
        Write-Log (T 'pricing.scraping_model_not_in_html' $OfficialName $PageUrl) -Level WARN
        return @{}
    }
    # For the subsequent steps I use the name that actually matched.
    $OfficialName = $matchedName
    $rowBody = $rowMatch.Groups[1].Value

    # --- 3. Identify the table structure from the nearest header before OfficialName ---
    $officialIdx = $html.IndexOf($OfficialName)
    # I look for the last <thead>...</thead> before OfficialName
    $theadIdx = $html.LastIndexOf('<thead', $officialIdx, [StringComparison]::OrdinalIgnoreCase)
    $theadEnd = -1
    if ($theadIdx -ge 0) {
        $theadEnd = $html.IndexOf('</thead>', $theadIdx, [StringComparison]::OrdinalIgnoreCase)
    }
    $tableColumns = @()
    if ($theadIdx -ge 0 -and $theadEnd -gt $theadIdx) {
        $theadHtml = $html.Substring($theadIdx, $theadEnd - $theadIdx + 8)
        $thMatches = [regex]::Matches($theadHtml, '<th[^>]*>(.+?)</th>', [System.Text.RegularExpressions.RegexOptions]::Singleline)
        foreach ($thm in $thMatches) {
            # Strip HTML tags interni
            $colText = $thm.Groups[1].Value
            $colText = [regex]::Replace($colText, '<[^>]+>', '')
            $colText = $colText.Trim()
            $tableColumns += $colText
        }
    }

    # I determine the structure:
    # - "labeled" if the rowBody contains patterns like "Label: <span..." (with a colon)
    # - "columnar" if only repeated <td>...<span>...</td>
    $hasLabels = [regex]::IsMatch($rowBody, '[A-Z][A-Za-z ]{2,}:\s*<span[^>]*price-data')
    $tableStructure = if ($hasLabels) { "labeled" } else { "columnar" }

    # --- 4. Extract prices ---
    # I try the region aliases first
    $regionAliases = Get-ArmRegionAlias -ArmRegion $ArmRegion

    $foundLabels = @{}  # label -> price USD/1M
    $allRegionsInPage = New-Object System.Collections.Generic.HashSet[string]

    if ($tableStructure -eq "labeled") {
        # Pattern: "Label: <span ... data-amount='JSON'..."
        $labelPattern = [regex]::new("([A-Z][A-Za-z ]+):\s*<span[^>]*data-amount='([^']+)'", [System.Text.RegularExpressions.RegexOptions]::Singleline)
        foreach ($lm in $labelPattern.Matches($rowBody)) {
            $label = $lm.Groups[1].Value.Trim()
            $dataAmount = $lm.Groups[2].Value
            # HTML entities decode
            $dataAmount = $dataAmount.Replace('&quot;', '"').Replace('&apos;', "'")

            $priceForRegion = Get-PriceFromDataAmount -DataAmountJson $dataAmount `
                                                      -RegionAliases $regionAliases `
                                                      -AllRegionsCollector $allRegionsInPage
            if ($null -ne $priceForRegion) {
                $foundLabels[$label] = $priceForRegion
            }
        }
    } else {
        # Columnar: <td> contiene <span data-amount> al posizionale
        # Each <td> is a column. I skip the first column (it is the model).
        $tdPattern = [regex]::new('<td[^>]*>(.+?)</td>', [System.Text.RegularExpressions.RegexOptions]::Singleline)
        # rowBody does not include the first <td>OfficialName</td> (already consumed by the row match).
        $tdMatches = $tdPattern.Matches($rowBody)
        $colIdx = 1  # parto da 1 perche' tableColumns[0] = "Models" (gia' consumata)
        foreach ($tdm in $tdMatches) {
            if ($colIdx -ge $tableColumns.Count) { break }
            $tdContent = $tdm.Groups[1].Value
            $spanMatch = [regex]::Match($tdContent, "data-amount='([^']+)'", [System.Text.RegularExpressions.RegexOptions]::Singleline)
            if ($spanMatch.Success) {
                $dataAmount = $spanMatch.Groups[1].Value
                $dataAmount = $dataAmount.Replace('&quot;', '"').Replace('&apos;', "'")
                $priceForRegion = Get-PriceFromDataAmount -DataAmountJson $dataAmount `
                                                          -RegionAliases $regionAliases `
                                                          -AllRegionsCollector $allRegionsInPage
                if ($null -ne $priceForRegion) {
                    $colLabel = $tableColumns[$colIdx]
                    # I normalize the column label: "Input (Per 1M tokens)" -> "Input"
                    $colLabelNorm = ($colLabel -replace '\(Per\s+1M\s+tokens?\)', '' -replace '\s+\(.+?\)', '').Trim()
                    $foundLabels[$colLabelNorm] = $priceForRegion
                }
            }
            $colIdx++
        }
    }

    # --- 5. If no price for the region, report with the available regions ---
    if ($foundLabels.Count -eq 0 -and $allRegionsInPage.Count -gt 0) {
        $sampleRegions = ($allRegionsInPage | Select-Object -First 10) -join ", "
        Write-Log (T 'pricing.scraping_no_region_match' $ArmRegion $sampleRegions) -Level WARN
        return @{}
    }

    # --- 6. Mapping label -> meter del nuovo schema ($Pricing.meters) ---
    # Three families of meters, depending on the model schema:
    #   - 6 meters for labeled models (AOAI GPT-Image)
    #   - 2 meters for columnar models (MAI Microsoft)
    #   - 3 meters for per-megapixel models (Black Forest Labs / FLUX)
    # The scraping extracts ALL the entries present on the page, not just 3 selected ones.
    #
    # Labeled models (AOAI GPT-Image):
    # "Input Text" -> inputText
    # "Cached Input Text" -> cachedInputText
    # "Input Image" -> inputImage
    # "Cached Input Image" -> cachedInputImage
    # "Output Text" -> outputText
    # "Output Image" -> outputImage
    # Columnar models (MAI Microsoft):
    # "Input" -> input
    # "Output" -> output
    # Per-megapixel models (FLUX / Black Forest Labs):
    # "Initial/First Megapixel" -> firstMpUsd
    # "Additional/Subsequent Megapixel" -> additionalMpUsd
    # "Reference Megapixel" -> referenceMpUsd
    #
    # Prices missing from the page (e.g. Output Text = N/A for gpt-image-2)
    # simply remain absent from the result. The cost calculation treats
    # an absent meter as zero price (safe).
    #
    # NB: the match is case-insensitive equality on the normalized label, never contains,
    # to avoid "Output Image" matching before "Output Text" if we only searched for "Output".
    $extractedPrices = @{}

    # Inline helper: price already in USD/1M tokens, returns it raw
    # (the new schema stores the simple value, not a PSCustomObject).
    $findExact = {
        param($Labels, [string]$Pattern)
        foreach ($k in $Labels.Keys) {
            if ($k -ieq $Pattern) { return $Labels[$k] }
        }
        return $null
    }

    if ($tableStructure -eq "labeled") {
        # Complete mapping page label -> meter key
        $labelToMeter = @{
            'Input Text'          = 'inputText'
            'Cached Input Text'   = 'cachedInputText'
            'Input Image'         = 'inputImage'
            'Cached Input Image'  = 'cachedInputImage'
            'Output Text'         = 'outputText'
            'Output Image'        = 'outputImage'
        }
        foreach ($lab in $labelToMeter.Keys) {
            $val = & $findExact $foundLabels $lab
            if ($null -ne $val) {
                $extractedPrices[$labelToMeter[$lab]] = [double]$val
            }
        }
    } else {
        # Columnar (MAI): solo Input/Output
        $labelToMeter = @{
            'Input'  = 'input'
            'Output' = 'output'
        }
        foreach ($lab in $labelToMeter.Keys) {
            $val = & $findExact $foundLabels $lab
            if ($null -ne $val) {
                $extractedPrices[$labelToMeter[$lab]] = [double]$val
            }
        }
    }

    # Matching aggiuntivo via meterRoles del .conf (schema-agnostico).
    # Serve per gli schemi NON token-based (es. FLUX per-megapixel) le cui label
    # ("First Megapixel", "Reference image", ...) are not in the hardcoded mapping
    # above. For each meter key defined in $MeterRoles, it looks among the labels
    # extracted from the page for one that contains (case-insensitive) one of the hints.
    # It does not overwrite values already extracted from the hardcoded mappings.
    if ($MeterRoles) {
        foreach ($meterKey in $MeterRoles.Keys) {
            if ($extractedPrices.ContainsKey($meterKey)) { continue }
            $hints = @($MeterRoles[$meterKey])
            $matched = $null
            foreach ($labelKey in $foundLabels.Keys) {
                foreach ($hint in $hints) {
                    if ($labelKey -and $hint -and $labelKey.ToLower().Contains($hint.ToString().ToLower())) {
                        $matched = $foundLabels[$labelKey]
                        break
                    }
                }
                if ($null -ne $matched) { break }
            }
            if ($null -ne $matched) {
                $extractedPrices[$meterKey] = [double]$matched
            }
        }
    }

    if ($extractedPrices.Count -gt 0) {
        $regionUsed = ($regionAliases | Where-Object { $_ -in $allRegionsInPage } | Select-Object -First 1)
        if (-not $regionUsed) { $regionUsed = $ArmRegion }
        Write-Log (T 'pricing.scraping_html_parsed' $OfficialName $tableStructure $extractedPrices.Count $regionUsed)
    }

    return $extractedPrices
}

function Get-PriceFromDataAmount {
    <#
    Decodes the data-amount='{...}' JSON of an Azure pricing page and
    returns the price for the requested region (trying its aliases).

    Possible JSON formats:
      - {"regional":{"us-east":5.0,"us-east-2":5.0,...}}  (for regional models)
      - {"currencies":{"USD":200.0}}                       (for single amounts)

    For the regional format, it tries each of the aliases in order. Returns $null
    if no alias matches.

    Fills AllRegionsCollector (HashSet) with all the regions found in the JSON
    (useful for error messages if no alias matches).
    #>
    param(
        [Parameter(Mandatory=$true)] [string]$DataAmountJson,
        [string[]]$RegionAliases = @(),
        $AllRegionsCollector = $null
    )

    try {
        $obj = $DataAmountJson | ConvertFrom-Json -ErrorAction Stop
    } catch {
        return $null
    }

    if ($obj.PSObject.Properties.Name -contains 'regional') {
        $regional = $obj.regional
        # Collects all the available regions
        if ($AllRegionsCollector) {
            foreach ($p in $regional.PSObject.Properties) {
                [void]$AllRegionsCollector.Add($p.Name)
            }
        }
        # I try the aliases in order
        foreach ($alias in $RegionAliases) {
            if ($regional.PSObject.Properties.Name -contains $alias) {
                return [double]$regional.$alias
            }
        }
        return $null
    } elseif ($obj.PSObject.Properties.Name -contains 'currencies') {
        # Formato {"currencies":{"USD":...}}: torno USD
        if ($obj.currencies.PSObject.Properties.Name -contains 'USD') {
            return [double]$obj.currencies.USD
        }
    }
    return $null
}

function Update-ModelPricingForOne {
    <#
    Runs the 4-phase pipeline for A SINGLE model.
    Returns a PSCustomObject with:
      - Success: $true if at least one price was updated
      - Source: "api-exact" | "api-relaxed" | "scraping" | "discovery" | "fallback"
      - PricesUpdated: object with the new values (or $null)
      - Message: descriptive message for the log
      - DiscoveryItems: array of candidates saved in the discovery (if applicable)
    #>
    param(
        [Parameter(Mandatory=$true)] [string]$ModelName,
        [Parameter(Mandatory=$true)] $ModelConfig,
        [Parameter(Mandatory=$true)] $PricingUpdateConfig
    )

    $mapping = $ModelConfig.pricingMapping
    $timeoutSec = if ($PricingUpdateConfig.timeoutSec) { [int]$PricingUpdateConfig.timeoutSec } else { 15 }
    $currencyCode = "USD"  # sempre USD: conversione locale fatta da Update-DefaultCurrency
    $armRegion = if ($mapping.armRegionName) { $mapping.armRegionName } else { "" }
    $serviceName = if ($mapping.serviceName) { $mapping.serviceName } else { "Azure OpenAI" }

    $productHints = @()
    if ($mapping.productHints) { $productHints = @($mapping.productHints) }
    elseif ($mapping.productNameContains) { $productHints = @($mapping.productNameContains) }

    if ($productHints.Count -eq 0) {
        return [PSCustomObject]@{
            Success = $false; Source = "skip"; PricesUpdated = $null
            Message = "no productHints in mapping"; DiscoveryItems = @()
        }
    }

    # Costruisci la lista di meter roles e relativi hints
    $meterRoles = @{}
    if ($mapping.meterRoles) {
        foreach ($prop in $mapping.meterRoles.PSObject.Properties) {
            $meterRoles[$prop.Name] = @($prop.Value)
        }
    }
    # Fallback: if there is no meterRoles, use reasonable defaults for the new
    # schema. The key names correspond to the keys of
    # pricing.meters: inputText, cachedInputText, inputImage, cachedInputImage,
    # outputText, outputImage (AOAI) / input, output (MAI).
    #
    # The hints are "fuzzy contains" on the Azure meterName: they need to cover the
    # real naming variants (Microsoft abbreviates a lot: "Inpt", "Img", "Opt",
    # "cd inp", "Glbl", etc.). Each hint applies in OR.
    if ($meterRoles.Count -eq 0) {
        $meterRoles = @{
            inputText         = @("Input Text", "Inpt", "Input Tokens", "Input")
            cachedInputText   = @("Cached Input Text", "Cached Input", "cchd Inpt", "Cached Inpt")
            inputImage        = @("Input Image", "Input Img")
            cachedInputImage  = @("Cached Input Image", "Cached Input Img")
            outputText        = @("Output Text", "Outpt Text", "Output Tokens", "Output")
            outputImage       = @("Output Image", "Outpt Img", "Image Output")
            input             = @("Input")
            output            = @("Output")
        }
    }

    # Internal helper: extract the prices from the Items for each meterRole
    function _extractPrices {
        param([array]$Items, [hashtable]$Roles)
        $result = @{}
        $anyFound = $false
        foreach ($role in $Roles.Keys) {
            $hints = $Roles[$role]
            $matched = Find-MeterInItems -Items $Items -MeterHints $hints
            if ($matched -and $null -ne $matched.unitPrice) {
                $norm = Get-PricingUnitMultiplier -UnitPrice ([double]$matched.unitPrice) -UnitOfMeasure $matched.unitOfMeasure
                $result[$role] = $norm
                $anyFound = $true
            }
        }
        return [PSCustomObject]@{ Found = $anyFound; Prices = $result }
    }

    # ============================================================
    # PHASE 1: exact API lookup (productHints[0] + strict armRegion)
    # ============================================================
    $primaryHint = $productHints[0]
    $primaryHintEscaped = $primaryHint.Replace("'", "''")  # escape OData apostrofo
    $filterParts = @("serviceName eq '$serviceName'", "contains(productName, '$primaryHintEscaped')")
    if ($armRegion) { $filterParts += "armRegionName eq '$armRegion'" }
    $filter = $filterParts -join ' and '

    try {
        Write-Log (T 'pricing.phase1_start' $ModelName $armRegion)
        $items = Invoke-PricingApiQuery -Filter $filter -TimeoutSec $timeoutSec -CurrencyCode $currencyCode
        if ($items.Count -gt 0) {
            $extracted = _extractPrices -Items $items -Roles $meterRoles
            if ($extracted.Found) {
                return [PSCustomObject]@{
                    Success = $true; Source = "api-exact"
                    PricesUpdated = $extracted.Prices; Message = "phase 1 ok"
                    DiscoveryItems = @()
                }
            }
        }
    } catch {
        if ($_.Exception.Message -match '^TIMEOUT') {
            Write-Log (T 'pricing.timeout' $ModelName $timeoutSec) -Level WARN
        } else {
            Write-Log (T 'pricing.api_error_phase' $ModelName "1" ($_.Exception.Message)) -Level WARN
        }
    }

    # ============================================================
    # PHASE 2: relaxed API lookup (I iterate over productHints, without region if needed)
    # ============================================================
    Write-Log (T 'pricing.phase2_start' $ModelName)
    for ($i = 0; $i -lt $productHints.Count; $i++) {
        $hint = $productHints[$i]
        $hintEscaped = $hint.Replace("'", "''")
        $hintLower = $hintEscaped.ToLower()
        # I try: with region first, then without. contains on productName made
        # case-insensitive via tolower (the Retail API is otherwise case-sensitive).
        $variants = @()
        if ($armRegion) {
            $variants += "serviceName eq '$serviceName' and contains(tolower(productName), '$hintLower') and armRegionName eq '$armRegion'"
        }
        $variants += "serviceName eq '$serviceName' and contains(tolower(productName), '$hintLower')"
        # Even more relaxed variant: without serviceName (captures other providers in the catalog)
        $variants += "contains(tolower(productName), '$hintLower')"

        foreach ($vFilter in $variants) {
            try {
                $items = Invoke-PricingApiQuery -Filter $vFilter -TimeoutSec $timeoutSec -CurrencyCode $currencyCode
                if ($items.Count -gt 0) {
                    # If I have the region, filter further on the client side
                    if ($armRegion) {
                        $itemsRegion = @($items | Where-Object { $_.armRegionName -eq $armRegion })
                        if ($itemsRegion.Count -gt 0) { $items = $itemsRegion }
                    }
                    $extracted = _extractPrices -Items $items -Roles $meterRoles
                    if ($extracted.Found) {
                        return [PSCustomObject]@{
                            Success = $true; Source = "api-relaxed"
                            PricesUpdated = $extracted.Prices
                            Message = "phase 2 ok with hint '$hint'"
                            DiscoveryItems = @()
                        }
                    }
                }
            } catch {
                if ($_.Exception.Message -notmatch '^TIMEOUT') {
                    Write-Log (T 'pricing.api_error_phase' $ModelName "2" ($_.Exception.Message)) -Level WARN
                }
            }
        }
    }

    # ============================================================
    # PHASE 3: scraping the official page (if pricingPageUrl is defined)
    # ============================================================
    # we use a DOM-based parser, not regex on the prices in the text.
    # The Microsoft page exposes the prices as:
    # <tr><td>GPT-Image-1.5 Global</td>
    # <td> Input Text: <span class='price-data' data-amount='{"regional":{"us-east-2":5.0,...}}'>...</span>
    # <br/>
    # Cached Input Text: <span class='price-data' data-amount='{"regional":{...}}'>...</span>
    # ...
    # </td></tr>
    # For AOAI models (GPT-Image): labeled cells ("Input Text:", "Output Image:")
    # For Microsoft models (MAI): positional columns (Models | Input | Output)
    # So the parser identifies the table structure from the <th> header.
    $pageUrl = if ($mapping.pricingPageUrl) { $mapping.pricingPageUrl } else { $null }
    $officialName = if ($mapping.officialName) { $mapping.officialName } else { $productHints[0] }

    if ($pageUrl -and $pageUrl.Trim() -ne "") {
        Write-Log (T 'pricing.phase3_start' $ModelName)
        try {
            $extractedPrices = Get-PricesFromPricingPage `
                -PageUrl $pageUrl `
                -OfficialName $officialName `
                -ArmRegion $armRegion `
                -MeterRoles $meterRoles `
                -TimeoutSec ($timeoutSec * 2)

            if ($extractedPrices -and $extractedPrices.Count -gt 0) {
                return [PSCustomObject]@{
                    Success = $true; Source = "scraping"
                    PricesUpdated = $extractedPrices
                    Message = "phase 3 ok"
                    DiscoveryItems = @()
                }
            }
        } catch {
            Write-Log (T 'pricing.phase3_failed' $ModelName ($_.Exception.Message)) -Level WARN
        }
    }

    # ============================================================
    # PHASE 4: discovery + fallback
    # ============================================================
    # the "discovery" query becomes an OR on productName / skuName / meterName
    # so we find candidates even when Microsoft does not put the model name
    # in productName (frequent for image models).
    Write-Log (T 'pricing.discovery_start' $ModelName)
    $discoveryItems = [System.Collections.Generic.List[object]]::new()
    $lastHint = $productHints[-1].Replace("'", "''").ToLower()
    $discoveryFilter = "contains(tolower(productName), '$lastHint') or contains(tolower(skuName), '$lastHint') or contains(tolower(meterName), '$lastHint')"
    try {
        $items = Invoke-PricingApiQuery -Filter $discoveryFilter -TimeoutSec $timeoutSec -CurrencyCode $currencyCode
        # Deduplicate by meterId (the OR can return the same meter multiple times)
        $items = $items | Sort-Object meterId -Unique
        foreach ($it in $items) {
            [void]$discoveryItems.Add([PSCustomObject]@{
                serviceName    = $it.serviceName
                productName    = $it.productName
                skuName        = $it.skuName
                meterName      = $it.meterName
                unitPrice      = $it.unitPrice
                unitOfMeasure  = $it.unitOfMeasure
                armRegionName  = $it.armRegionName
                effectiveStartDate = $it.effectiveStartDate
            })
        }
    } catch {
        # Discovery failed: oh well, local fallback
    }

    return [PSCustomObject]@{
        Success = $false; Source = "discovery-or-fallback"
        PricesUpdated = $null
        Message = "all phases failed, fallback to local prices"
        DiscoveryItems = @($discoveryItems)
    }
}

function Update-ModelPricing {
    <#
    Main model price update function (4-phase pipeline).

    Strategy:
      Phase 1: Exact API lookup with serviceName + productHints[0] + armRegionName
      Phase 2: Relaxed API lookup with all productHints, region fallback
      Phase 3: Scraping the official page (if pricingPageUrl is defined)
      Phase 4: Discovery (saves candidates to file) + fallback to local prices

    Runs once every N days (configurable via pricingUpdate.frequencyDays),
    or forced with -Force.

    The retrieved prices are in USD. If config.defaultCurrency != "USD" and there is an
    available exchange rate, they are converted before saving.

    NOTE: this function modifies $Config (PSCustomObject) and then serializes it
    to $ConfigPath. The changes are persistent.
    #>
    param(
        [Parameter(Mandatory=$true)] $Config,
        [Parameter(Mandatory=$true)] [string]$ConfigPath,
        [switch]$Force
    )

    # ====== Controllo abilitazione globale ======
    $pricingUpdateConf = $null
    if ($Config.PSObject.Properties.Name -contains 'pricingUpdate') {
        $pricingUpdateConf = $Config.pricingUpdate
    } else {
        # Auto-crea con default sani se manca
        $pricingUpdateConf = [PSCustomObject]@{
            enabled = $true
            currencyCode = "USD"
            timeoutSec = 15
            writeDiscoveryFile = $true
            frequencyDays = 7
        }
        $Config | Add-Member -NotePropertyName 'pricingUpdate' -NotePropertyValue $pricingUpdateConf -Force
    }

    if ($pricingUpdateConf.enabled -eq $false) {
        if ($Force) { Write-Log (T 'pricing.disabled') }
        return
    }

    # ====== Frequency check (skip if updated recently, unless -Force) ======
    $today = (Get-Date).ToString("yyyy-MM-dd", [System.Globalization.CultureInfo]::InvariantCulture)
    $lastUpdate = if ($Config.PSObject.Properties.Name -contains 'pricingLastUpdated') {
                      $Config.pricingLastUpdated
                  } else { $null }
    $frequencyDays = if ($pricingUpdateConf.frequencyDays) { [int]$pricingUpdateConf.frequencyDays } else { 7 }

    if (-not $Force -and $lastUpdate) {
        try {
            $lastDate = [datetime]::ParseExact($lastUpdate, "yyyy-MM-dd", [System.Globalization.CultureInfo]::InvariantCulture)
            $daysSince = ((Get-Date) - $lastDate).TotalDays
            if ($daysSince -lt $frequencyDays) {
                return  # skip silenzioso
            }
        } catch {
            # Data malformata: procedo come se non ci fosse
        }
    }

    if ($Force) {
        Write-Log (T 'pricing.force_bypass')
    }

    # ====== I iterate over the models ======
    $modelNames = @($Config.models | Get-Member -MemberType NoteProperty | Select-Object -ExpandProperty Name)
    $modelsUpdated = 0
    $modelsTotal = 0
    $discoveryByModel = @{}

    foreach ($mdlName in $modelNames) {
        $mdl = $Config.models.$mdlName

        # Skip if not active
        $isActive = if ($null -ne $mdl.active) { [bool]$mdl.active } else { $true }
        if (-not $isActive) { continue }
        $modelsTotal++

        # Deprecation warning for the old field
        if ($mdl.PSObject.Properties.Name -contains 'azureMeterFilter' -and
            (-not $mdl.azureMeterFilter -or $mdl.azureMeterFilter.Trim() -ne "")) {
            if ($Force) {
                # Show the warning only in Force mode so as not to clutter the routine logs
                Write-Log (T 'pricing.legacy_field_warn' $mdlName) -Level WARN
            }
        }

        # Skip if pricingMapping is missing
        if (-not $mdl.pricingMapping) {
            if ($Force) {
                Write-Log (T 'pricing.no_mapping' $mdlName) -Level WARN
            }
            continue
        }

        # Run the 4-phase pipeline for this model
        $result = Update-ModelPricingForOne -ModelName $mdlName -ModelConfig $mdl -PricingUpdateConfig $pricingUpdateConf

        if ($result.Success -and $result.PricesUpdated) {
            # updates pricing.meters (new 6/2-key schema).
            # $result.PricesUpdated e' un hashtable @{ inputText=5.0; outputImage=30.0; ... }
            # o @{ input=5.0; output=33.0 } per i columnar.
            $pricesObj = $mdl.pricing
            if (-not $pricesObj) {
                $pricesObj = [PSCustomObject]@{
                    meters            = [PSCustomObject]@{}
                    imagePerUnitUsd   = 0.0
                    lastUpdated       = ""
                    lastUpdatedSource = ""
                }
                $mdl | Add-Member -NotePropertyName 'pricing' -NotePropertyValue $pricesObj -Force
            }

            # Ensures pricing.meters exists (models with an old .conf
            # potrebbero non averlo)
            if (-not ($pricesObj.PSObject.Properties.Name -contains 'meters') -or
                -not $pricesObj.meters) {
                $pricesObj | Add-Member -NotePropertyName 'meters' -NotePropertyValue ([PSCustomObject]@{}) -Force
            }
            $metersObj = $pricesObj.meters

            foreach ($meterKey in $result.PricesUpdated.Keys) {
                # Il caso "imagePerUnit" e' speciale: rimane su $pricesObj.imagePerUnitUsd
                if ($meterKey -eq 'imagePerUnit') {
                    $val = $result.PricesUpdated[$meterKey]
                    # If it comes from scraping the value is a direct double (per-1M),
                    # converted to per-unit. If from the API, it is a PSCustomObject with PerUnitUsd.
                    $perUnit = if ($val -is [psobject] -and $val.PSObject.Properties.Name -contains 'PerUnitUsd') {
                        [double]$val.PerUnitUsd
                    } else {
                        [double]$val / 1000000.0
                    }
                    if (-not ($pricesObj.PSObject.Properties.Name -contains 'imagePerUnitUsd')) {
                        $pricesObj | Add-Member -NotePropertyName 'imagePerUnitUsd' -NotePropertyValue ([math]::Round($perUnit, 6)) -Force
                    } else {
                        $pricesObj.imagePerUnitUsd = [math]::Round($perUnit, 6)
                    }
                    continue
                }

                # All the other meters: they go into pricing.meters.<key>
                # the per-megapixel FLUX meters (firstMpUsd, additionalMpUsd,
                # referenceMpUsd) are in USD per MP, NOT per 1M tokens. For these we use
                # the per-unit value (PerUnitUsd) instead of PerMillionUsd.
                $isPerMpMeter = ($meterKey -in @('firstMpUsd','additionalMpUsd','referenceMpUsd'))
                $rawVal = $result.PricesUpdated[$meterKey]
                if ($isPerMpMeter) {
                    $perUnitVal = if ($rawVal -is [psobject] -and $rawVal.PSObject.Properties.Name -contains 'PerUnitUsd') {
                        [double]$rawVal.PerUnitUsd
                    } else {
                        [double]$rawVal
                    }
                    $newValue = [math]::Round($perUnitVal, 6)
                    if (-not ($metersObj.PSObject.Properties.Name -contains $meterKey)) {
                        $metersObj | Add-Member -NotePropertyName $meterKey -NotePropertyValue $newValue -Force
                    } else {
                        $metersObj.$meterKey = $newValue
                    }
                    continue
                }
                # Lo scraping passa double semplici (USD per 1M). L'API passa PSCustomObject con .PerMillionUsd.
                $perMillion = if ($rawVal -is [psobject] -and $rawVal.PSObject.Properties.Name -contains 'PerMillionUsd') {
                    [double]$rawVal.PerMillionUsd
                } else {
                    [double]$rawVal
                }
                $newValue = [math]::Round($perMillion, 4)

                if (-not ($metersObj.PSObject.Properties.Name -contains $meterKey)) {
                    $metersObj | Add-Member -NotePropertyName $meterKey -NotePropertyValue $newValue -Force
                } else {
                    $metersObj.$meterKey = $newValue
                }
            }

            # Metadata di tracking
            if (-not ($pricesObj.PSObject.Properties.Name -contains 'lastUpdated')) {
                $pricesObj | Add-Member -NotePropertyName 'lastUpdated' -NotePropertyValue $today -Force
            } else {
                $pricesObj.lastUpdated = $today
            }
            if (-not ($pricesObj.PSObject.Properties.Name -contains 'lastUpdatedSource')) {
                $pricesObj | Add-Member -NotePropertyName 'lastUpdatedSource' -NotePropertyValue $result.Source -Force
            } else {
                $pricesObj.lastUpdatedSource = $result.Source
            }

            $modelsUpdated++

            $msgKey = switch ($result.Source) {
                "api-exact"   { 'pricing.phase1_success' }
                "api-relaxed" { 'pricing.phase2_success' }
                "scraping"    { 'pricing.phase3_success' }
                default       { 'pricing.phase1_success' }
            }
            if ($result.Source -eq "api-relaxed") {
                # I extract the hint from the Message
                $hintUsed = if ($result.Message -match "hint '([^']+)'") { $Matches[1] } else { "?" }
                Write-Log (T $msgKey $mdlName $hintUsed)
            } else {
                Write-Log (T $msgKey $mdlName)
            }

        } else {
            # Discovery + fallback
            if ($result.DiscoveryItems -and $result.DiscoveryItems.Count -gt 0 -and
                $pricingUpdateConf.writeDiscoveryFile) {
                $discoveryByModel[$mdlName] = $result.DiscoveryItems
            } else {
                # Schema-aware message: for per-megapixel models (FLUX) the price
                # is not (yet) exposed in the Retail API and is not extractable from the
                # JS-rendered pricing page; the per-MP prices in the .conf are the source
                # corretta. Lo comunichiamo come INFO (comportamento atteso), non WARN.
                $mdlSchema = if ($mdl.apiSchema) { $mdl.apiSchema } else { "openai-images" }
                if ($mdlSchema -eq "bfl-flux") {
                    Write-Log (T 'pricing.fallback_local_permp' $mdlName) -Level INFO
                } else {
                    Write-Log (T 'pricing.fallback_local' $mdlName) -Level WARN
                }
            }
        }
    }

    # ====== Writing the discovery file (if there are candidates) ======
    if ($discoveryByModel.Count -gt 0 -and $pricingUpdateConf.writeDiscoveryFile) {
        $discoveryPath = Join-Path $PSScriptRoot "New-GPTImage.pricing-discovery.json"
        try {
            $discoveryObj = [PSCustomObject]@{
                generated_at = (Get-Date).ToString("yyyy-MM-dd HH:mm:ss", [System.Globalization.CultureInfo]::InvariantCulture)
                description = "Candidati API trovati per modelli che non hanno match esatto. Usa questi dati per raffinare il pricingMapping.meterRoles nel .conf."
                models = $discoveryByModel
            }
            $discoveryObj | ConvertTo-Json -Depth 10 | Set-Content -Path $discoveryPath -Encoding UTF8
            foreach ($mn in $discoveryByModel.Keys) {
                $count = $discoveryByModel[$mn].Count
                Write-Log (T 'pricing.discovery_saved' $count $discoveryPath) -Level WARN
            }
        } catch {
            Write-Log (T 'pricing.api_error_phase' "discovery-file-write" "4" ($_.Exception.Message)) -Level WARN
        }
    }

    # ====== Aggiorna timestamp globale ======
    if ($Config.PSObject.Properties.Name -contains 'pricingLastUpdated') {
        $Config.pricingLastUpdated = $today
    } else {
        $Config | Add-Member -NotePropertyName 'pricingLastUpdated' -NotePropertyValue $today -Force
    }

    # ====== Save config ======
    try {
        $Config | ConvertTo-Json -Depth 10 | Set-Content -Path $ConfigPath -Encoding UTF8 -ErrorAction Stop
        if ($Force) {
            $discoveryCount = $discoveryByModel.Count
            $discoveryNames = if ($discoveryCount -gt 0) { ($discoveryByModel.Keys -join ", ") } else { "-" }
            Write-Log (T 'pricing.update_summary' $modelsUpdated $modelsTotal $discoveryNames)
        }
    } catch {
        Write-Log (T 'pricing.save_error' ($_.Exception.Message)) -Level WARN
    }
}

function Get-SystemInfo {
    <#
    Collects system information for the initial logging:
      OS, version, CPU, total RAM, system disk size.
    Works on Windows / Linux / macOS with native approaches for each.
    If a piece of information is not available, returns 'N/D' in its place.
    #>
    $info = [ordered]@{
        OS         = "N/D"
        Version    = "N/D"
        CPU        = "N/D"
        RAM_GB     = "N/D"
        Disk_GB    = "N/D"
    }

    try {
        if ($script:IsWin) {
            # --- Windows ---
            try {
                $os = Get-CimInstance Win32_OperatingSystem -ErrorAction Stop
                $info.OS      = $os.Caption.Trim()
                $info.Version = $os.Version
                $info.RAM_GB  = [math]::Round([double]$os.TotalVisibleMemorySize / 1MB, 1)
            } catch { }

            try {
                $cpu = Get-CimInstance Win32_Processor -ErrorAction Stop | Select-Object -First 1
                $info.CPU = $cpu.Name.Trim()
            } catch { }

            try {
                $sysDrive = $env:SystemDrive   # es. 'C:'
                $disk = Get-CimInstance Win32_LogicalDisk -Filter "DeviceID='$sysDrive'" -ErrorAction Stop
                $info.Disk_GB = [math]::Round([double]$disk.Size / 1GB, 1)
            } catch { }
        }
        elseif ($script:IsMac) {
            # --- macOS ---
            try {
                $osName    = (sw_vers -productName)    2>$null
                $osVer     = (sw_vers -productVersion) 2>$null
                $info.OS      = if ($osName) { $osName.Trim() } else { "macOS" }
                $info.Version = if ($osVer)  { $osVer.Trim() }  else { "N/D" }
            } catch { }

            try {
                $cpuBrand = (sysctl -n machdep.cpu.brand_string) 2>$null
                $info.CPU = if ($cpuBrand) { $cpuBrand.Trim() } else { "N/D" }
            } catch { }

            try {
                $memBytes = [long]((sysctl -n hw.memsize) 2>$null)
                if ($memBytes -gt 0) {
                    $info.RAM_GB = [math]::Round($memBytes / 1GB, 1)
                }
            } catch { }

            try {
                # 'df -k /' returns the size in KB (1024-byte blocks)
                $dfOutput = (df -k /) 2>$null
                if ($dfOutput) {
                    $lines = $dfOutput -split "`n" | Where-Object { $_ -match '\S' }
                    if ($lines.Count -ge 2) {
                        $fields = $lines[1] -split '\s+' | Where-Object { $_ -ne '' }
                        if ($fields.Count -ge 2) {
                            $sizeKB = [long]$fields[1]
                            $info.Disk_GB = [math]::Round($sizeKB / (1024 * 1024), 1)
                        }
                    }
                }
            } catch { }
        }
        elseif ($script:IsLin) {
            # --- Linux ---
            try {
                if (Test-Path /etc/os-release) {
                    $osRelease = Get-Content /etc/os-release -Raw
                    if ($osRelease -match 'PRETTY_NAME="([^"]+)"') {
                        $info.OS = $Matches[1]
                    }
                    if ($osRelease -match 'VERSION_ID="?([^"\r\n]+)"?') {
                        $info.Version = $Matches[1]
                    }
                }
                if ($info.OS -eq "N/D") {
                    $info.OS = (uname -s) 2>$null
                }
            } catch { }

            try {
                if (Test-Path /proc/cpuinfo) {
                    $cpuInfo = Get-Content /proc/cpuinfo
                    $modelLine = $cpuInfo | Where-Object { $_ -match '^model name' } | Select-Object -First 1
                    if ($modelLine -and $modelLine -match ':\s*(.+)$') {
                        $info.CPU = $Matches[1].Trim()
                    }
                }
            } catch { }

            try {
                if (Test-Path /proc/meminfo) {
                    $memLine = Get-Content /proc/meminfo | Where-Object { $_ -match '^MemTotal:' } | Select-Object -First 1
                    if ($memLine -match 'MemTotal:\s+(\d+)\s*kB') {
                        $memKB = [long]$Matches[1]
                        $info.RAM_GB = [math]::Round($memKB / (1024 * 1024), 1)
                    }
                }
            } catch { }

            try {
                $dfOutput = (df -k /) 2>$null
                if ($dfOutput) {
                    $lines = $dfOutput -split "`n" | Where-Object { $_ -match '\S' }
                    if ($lines.Count -ge 2) {
                        $fields = $lines[1] -split '\s+' | Where-Object { $_ -ne '' }
                        if ($fields.Count -ge 2) {
                            $sizeKB = [long]$fields[1]
                            $info.Disk_GB = [math]::Round($sizeKB / (1024 * 1024), 1)
                        }
                    }
                }
            } catch { }
        }
    } catch { }

    return $info
}

function Test-RuntimePrerequisites {
    <#
    Prerequisite checks run AFTER loading the language pack (so they
    can use T() directly) and AFTER the definition of the platform
    variables ($script:IsWin/IsMac/IsLin) and the paths. It complements Test-Prerequisites
    (which runs "early" and covers only PowerShell version + console encoding + language).

    Two distinct areas, as required:

    SYSTEM AREA (generic, independent of the script):
      - Total RAM: WARN below a minimum threshold (the script uses System.Drawing for
        images; with very little RAM large images can fail).
      - Free disk space in the working directory: WARN below a threshold (space is
        needed to write images, logs and temporary files).

    SCRIPT AREA (files and permissions specific to this tool):
      - Script directory writable (needed for .log, .cost, .stat, output).
      - .log file writable/appendable (it is the heart of logging and analytics).
      - Presence of the support files (.conf already validated elsewhere; here a
        lightweight check on the already-loaded .lang).

    Returns [PSCustomObject] with:
      Ok       = $false if a CRITICAL check fails (e.g. dir not writable)
      Messages = list of { Key; Args; Level } already ready for Write-PrereqMessages
    Parameters:
      -ScriptDir:        script directory (PSScriptRoot)
      -LogPath:          path of the .log file
      -MinFreeDiskMB:    minimum free space threshold (MB) for the WARN (default 200)
      -MinRamGB:         minimum total RAM threshold (GB) for the WARN (default 1)
    #>
    param(
        [string]$ScriptDir,
        [string]$LogPath,
        [int]$MinFreeDiskMB = 200,
        [double]$MinRamGB = 1.0
    )

    $result = [PSCustomObject]@{
        Ok       = $true
        Messages = @()
    }

    # ---------- SYSTEM AREA ----------

    # RAM totale (best-effort, cross-platform). Solo WARN: non blocchiamo, ma avvisiamo.
    try {
        $ramGb = $null
        if ($script:IsWin) {
            $os = Get-CimInstance Win32_OperatingSystem -ErrorAction Stop
            $ramGb = [math]::Round([double]$os.TotalVisibleMemorySize / 1MB, 1)
        } elseif ($script:IsMac) {
            $memBytes = [long]((sysctl -n hw.memsize) 2>$null)
            if ($memBytes -gt 0) { $ramGb = [math]::Round($memBytes / 1GB, 1) }
        } elseif ($script:IsLin) {
            if (Test-Path /proc/meminfo) {
                $memLine = (Get-Content /proc/meminfo | Where-Object { $_ -match '^MemTotal:' } | Select-Object -First 1)
                if ($memLine -match '(\d+)\s*kB') { $ramGb = [math]::Round([double]$Matches[1] / 1MB, 1) }
            }
        }
        if ($null -ne $ramGb -and $ramGb -gt 0 -and $ramGb -lt $MinRamGB) {
            $result.Messages += [PSCustomObject]@{ Key = 'prereq.low_ram'; Args = @((Format-DisplayNumber $ramGb 1), (Format-DisplayNumber $MinRamGB 1)); Level = 'WARN' }
        }
    } catch { }

    # Free disk space in the working directory (best-effort, cross-platform).
    try {
        $freeMb = $null
        $checkDir = if ($ScriptDir -and (Test-Path $ScriptDir)) { $ScriptDir } else { (Get-Location).Path }
        if ($script:IsWin) {
            $driveLetter = ([System.IO.Path]::GetPathRoot($checkDir)).TrimEnd('\').TrimEnd(':')
            if ($driveLetter) {
                $d = Get-CimInstance Win32_LogicalDisk -Filter "DeviceID='$driveLetter`:'" -ErrorAction Stop
                if ($d -and $d.FreeSpace) { $freeMb = [math]::Round([double]$d.FreeSpace / 1MB, 0) }
            }
        } else {
            $dfOut = (df -k $checkDir) 2>$null
            if ($dfOut) {
                $lines = $dfOut -split "`n" | Where-Object { $_ -match '\S' }
                if ($lines.Count -ge 2) {
                    $f = $lines[1] -split '\s+' | Where-Object { $_ -ne '' }
                    # the "Available" field is typically the 4th (1-based), in KB
                    if ($f.Count -ge 4) { $freeMb = [math]::Round([double]$f[3] / 1024, 0) }
                }
            }
        }
        if ($null -ne $freeMb -and $freeMb -ge 0 -and $freeMb -lt $MinFreeDiskMB) {
            $result.Messages += [PSCustomObject]@{ Key = 'prereq.low_disk'; Args = @([string]$freeMb, [string]$MinFreeDiskMB); Level = 'WARN' }
        }
    } catch { }

    # ---------- AREA SCRIPT ----------

    # Script directory writable: we try to create/delete a probe file.
    # It is a CRITICAL check: without write access, log/output/state files fail.
    if ($ScriptDir -and (Test-Path $ScriptDir)) {
        $probe = Join-Path $ScriptDir (".write_probe_" + [Guid]::NewGuid().ToString('N') + ".tmp")
        try {
            [System.IO.File]::WriteAllText($probe, "probe")
            Remove-Item $probe -Force -ErrorAction SilentlyContinue
        } catch {
            $result.Ok = $false
            $result.Messages += [PSCustomObject]@{ Key = 'prereq.dir_not_writable'; Args = @($ScriptDir); Level = 'ERROR' }
        }
    }

    # .log file writable/appendable: if it exists, we verify we can append to it;
    # if it does not exist, we verify we can create it. WARN only: file logging is
    # important (analytics) but the script can still operate by logging to screen.
    if ($LogPath) {
        try {
            if (Test-Path $LogPath) {
                # I verify I can open the file in APPEND without writing anything
                # (non-destructive probe: I open and close immediately, no spurious lines).
                $fs = [System.IO.File]::Open($LogPath, [System.IO.FileMode]::Append, [System.IO.FileAccess]::Write, [System.IO.FileShare]::ReadWrite)
                $fs.Close()
                $fs.Dispose()
            } else {
                # I verify the containing directory is writable by creating the file
                $logDir = Split-Path -Parent $LogPath
                if ($logDir -and -not (Test-Path $logDir)) {
                    $result.Messages += [PSCustomObject]@{ Key = 'prereq.log_dir_missing'; Args = @($logDir); Level = 'WARN' }
                }
            }
        } catch {
            $result.Messages += [PSCustomObject]@{ Key = 'prereq.log_not_writable'; Args = @($LogPath, $_.Exception.Message); Level = 'WARN' }
        }
    }

    return $result
}

# Returns the COMPLETE default TUI configuration (all themes). Single source
