# Returns the JSON content of the default configuration file (used by -Setup to generate the .conf).
function Get-DefaultConfigJson {
    $default = [ordered]@{
        defaultModel = "gpt-image-2"
        models = [ordered]@{
            "gpt-image-2" = [ordered]@{
                # Connection status and configuration
                active                = $true
                endpoint              = ""
                editEndpoint          = ""
                # Failover endpoints (optional). If the primary endpoint
                # fails with 5xx errors, timeout or ECONNREFUSED, the script tries the
                # failover ONCE before applying the normal retry policy.
                # Leave empty to disable failover.
                failoverEndpoint      = ""
                failoverEditEndpoint  = ""
                apiKey                = ""
                deployment            = ""
                # Feature flags supported by the model
                supportsInpainting    = $true
                supportsInputFidelity = $false
                supportsBackground    = $true
                # Operational parameters of the model: limits validated BEFORE the API
                # call (see Test-ModelOperationalParams). The *Enforce fields distinguish
                # the CERTAIN limits (true -> blocking error) from the UNCERTAIN ones (false -> WARN).
                # maxImages: max number of images per request. allowedSizes: closed list of
                # sizes. minSide/maxSide/maxArea: numeric dimensional rules.
                # maxReferenceImages: max reference images in edit. allowedQuality/
                # allowedFormat: lists of valid values. Empty list = no constraint.
                operationalParams = [ordered]@{
                    maxImages                 = 10
                    maxImagesEnforce          = $true
                    allowedSizes              = @()
                    allowedSizesEnforce       = $false
                    minSide                   = 0
                    maxSide                   = 3840
                    maxArea                   = 0
                    sizeRulesEnforce          = $true
                    sizeDivisibleBy           = 16
                    aspectRatioMin            = 0.333
                    aspectRatioMax            = 3.0
                    maxReferenceImages        = 16
                    maxReferenceImagesEnforce = $false
                    allowedQuality            = @("low","medium","high","auto")
                    allowedQualityEnforce     = $true
                    allowedFormat             = @("png","jpg")
                    allowedFormatEnforce      = $true
                }
                # Rating for the -Auto parameter (historical 1-10 scale for back-compat,
                # but with these values they are populated automatically).
                # qualityRating: quality score of the model. With -Auto Quality the script
                # updates it by reading arena.ai/leaderboard/text-to-image; for back-compat
                # integer values 0-10 remain if edited by hand, but normally it is an
                # Arena score (~900-1400). 0 = not evaluated / not in the leaderboard.
                # speedRating: with -Auto Time the script computes it as the inverse MEDIAN of the
                # 'actual' times from the log for the quality+size of the current run.
                # Internally stored as a median in seconds (no longer as a 1-10 scale).
                # 0 = not enough data (< 3 runs).
                # qualityArenaAlias: exact name of the model on the arena if different (e.g.
                # "gpt-image-2 (medium)" for gpt-image-2). Empty = automatic match.
                # qualityRatingLastUpdate / speedRatingLastUpdate: date of the last refresh,
                # used for the weekly cache.
                qualityRating          = 8
                qualityArenaAlias      = "gpt-image-2 (medium)"
                qualityRatingLastUpdate= ""
                speedRating            = 5
                speedRatingLastUpdate  = ""
                # Model prices in USD. Automatically updatable via the Azure Retail
                # Prices API (see pricingMapping below) or manually.
                #
                # new 'meters' schema with 6 keys for labeled models
                # (AOAI GPT-Image) and 2 keys for columnar models (MAI). Each key
                # corresponds to an entry on the Azure pricing page:
                # AOAI: inputText, cachedInputText, inputImage, cachedInputImage,
                # outputText, outputImage (in USD per 1M tokens)
                # MAI: input, output (in USD per 1M tokens, covers everything including the images)
                #
                # imagePerUnitUsd: USD per 1 image (for per-image models, rare)
                # lastUpdated: date of the last update (YYYY-MM-DD)
                # lastUpdatedSource: "api-exact" | "api-relaxed" | "scraping" | "manual" | "migrated"
                pricing               = [ordered]@{
                    meters = [ordered]@{
                        inputText        = 5.00
                        cachedInputText  = 1.25
                        inputImage       = 8.00
                        cachedInputImage = 2.00
                        outputText       = 0.00     # N/A per gpt-image-2 (Output Text non fatturato)
                        outputImage      = 30.00
                    }
                    imagePerUnitUsd   = 0.00
                    lastUpdated       = "2026-05-23"
                    lastUpdatedSource = "manual"
                }
                # Mapping for the automatic price update via the Azure Retail
                # Prices API. See the full documentation in the README.
                #
                # 4-phase pipeline:
                # 1. Exact API: serviceName + productHints[0] + armRegionName
                # 2. Relaxed API: iterates over productHints (with and without region)
                # 3. Scraping: official pricing page (if pricingPageUrl)
