        tui                      = Get-DefaultTuiConfig
    }
    return ($default | ConvertTo-Json -Depth 12)
}

# Applies retention to the log file: removes the lines older than the configured threshold in days.
# Sends a telemetry event/metrics to Azure Application Insights via REST
# (official v2/track endpoint). Extracts InstrumentationKey and IngestionEndpoint from the
# conf connection string (telemetry.connectionString). It is NEVER blocking: every
# error (network, parsing, timeout) is silently ignored or logged as WARN,
# because telemetry must never compromise a generation. Sends an
# EventData schema with custom properties (duration, cost, tokens, outcome, model).
function Send-Telemetry {
    param(
        $Config,
        [string]$EventName = "ImageGeneration",
        [hashtable]$Properties = @{},
        [hashtable]$Metrics = @{}
    )
    try {
        $tm = $Config.telemetry
        # Telemetry disabled or section absent: I exit silently (it is the
        # normal state for those who do not use telemetry, not an error).
        if (-not $tm -or $tm.azureMonitor -ne $true) { return }

        # From here on telemetry IS active: the user MUST know what happens.
        # Se qualcosa non va (connection string mancante o malformata) lo segnalo con
        # an ERROR, but I NEVER block the generation (the function just returns).
        $connStr = [string]$tm.connectionString
        if (-not $connStr) {
            Write-Log (T 'telemetry.no_connstr') -Level ERROR
            return
        }

        # Parsing the connection string: "InstrumentationKey=...;IngestionEndpoint=...;..."
        $ikey = ""
        $ingest = ""
        foreach ($part in $connStr.Split(';')) {
            $kv = $part.Split('=', 2)
            if ($kv.Count -eq 2) {
                $key = $kv[0].Trim()
                $val = $kv[1].Trim()
                if ($key -eq 'InstrumentationKey') { $ikey = $val }
                elseif ($key -eq 'IngestionEndpoint') { $ingest = $val }
            }
        }
        # Malformed connection string: the InstrumentationKey or
        # IngestionEndpoint key is missing (e.g. copy-paste error). I report with a clear ERROR,
        # indicating which part is missing, but I continue without blocking the generation.
        if (-not $ikey -or -not $ingest) {
            $missing = @()
            if (-not $ikey)   { $missing += "InstrumentationKey" }
            if (-not $ingest) { $missing += "IngestionEndpoint" }
            Write-Log (T 'telemetry.bad_connstr' ($missing -join ", ")) -Level ERROR
            return
        }
        $url = $ingest.TrimEnd('/') + "/v2/track"

        # I announce the sending (the user knows telemetry is active and working).
        Write-Log (T 'telemetry.sending' $EventName) -Level INFO

        # The Application Insights properties must be strings; the metrics are
        # numeriche e vanno in measurements.
        $propsObj = @{}
        foreach ($k in $Properties.Keys) { $propsObj[$k] = [string]$Properties[$k] }
        $measObj = @{}
        foreach ($k in $Metrics.Keys) { $measObj[$k] = [double]$Metrics[$k] }

        $payload = @{
            name = "Microsoft.ApplicationInsights.Event"
            time = (Get-Date).ToUniversalTime().ToString("yyyy-MM-ddTHH:mm:ss.fffZ", [System.Globalization.CultureInfo]::InvariantCulture)
            iKey = $ikey
            tags = @{ "ai.cloud.role" = "New-GPTImage" }
            data = @{
                baseType = "EventData"
                baseData = @{
                    ver          = 2
                    name         = $EventName
                    properties   = $propsObj
                    measurements = $measObj
                }
            }
        }
        $json = $payload | ConvertTo-Json -Depth 10 -Compress

        # Non-blocking POST with a short timeout: telemetry must not slow the
        # script down. A failure here is silent (at most a WARN in the log).
        $null = Invoke-RestMethod -Uri $url -Method Post -Body $json `
            -ContentType "application/json" -TimeoutSec 10 -ErrorAction Stop
        Write-Log (T 'telemetry.sent' $EventName) -Level INFO
    } catch {
        # Never blocking: telemetry failed = WARN, the generation continues.
        Write-Log (T 'telemetry.failed' ($_.Exception.Message)) -Level WARN
    }
}


# Builds and sends the telemetry of A successful generation. Single function
# shared by all flows (CLI/single flow, batch, TUI) to avoid
# duplicating the metric-building logic in multiple places: a single place to
# maintain, no risk of divergence. It receives the generation's Cost object,
# the duration, the descriptive parameters and the SOURCE (cli|tui|batch). It is never
# blocking (delegates to Send-Telemetry, which handles errors and transparency).
#   -Cost      : the $result.Cost object (can be $null: still sends duration and images)
#   -DurationSec : total duration of the generation in seconds
#   -Model/-Size/-Quality : descriptive parameters (properties)
#   -NImages   : number of images generated (for the per-image metrics)
#   -Source    : source of the generation, "cli" | "tui" | "batch" | "benchmark"
function Send-GenerationTelemetry {
    param(
        $Config,
        $Cost,
        [double]$DurationSec = 0,
        [string]$Model = "",
        [string]$Size = "",
        [string]$Quality = "",
        [int]$NImages = 1,
        [ValidateSet("cli","tui","batch","benchmark")][string]$Source = "cli"
    )
    # Explicit opt-out for this run (e.g. SelfTest): do not send anything.
    if ($script:NoTelemetryFlag) { return }
    # Properties (customDimensions): categorie per filtrare/raggruppare in Azure.
    $props = @{
        model   = [string]$Model
        outcome = "success"
        size    = [string]$Size
        quality = [string]$Quality
        source  = $Source
    }
    # Measurements (customMeasurements): numeric values to aggregate.
    $metrics = @{ durationSec = [math]::Round($DurationSec, 2); images = [double]$NImages }
    if ($Cost) {
        # Tokens: totals + input/output and text/image breakdown.
        $metrics['totalTokens']  = [double]$Cost.total_tokens
        $metrics['inputTokens']  = [double]$Cost.input_tokens
        $metrics['outputTokens'] = [double]$Cost.output_tokens
        $metrics['textTokens']   = [double]$Cost.text_tokens
        $metrics['imageTokens']  = [double]$Cost.image_tokens
        # Costs: totals + input/output breakdown, in EUR and USD.
        $metrics['costEur']        = [double]$Cost.total_cost_eur
        $metrics['costUsd']        = [double]$Cost.total_cost_usd
        $metrics['inputCostEur']   = [double]$Cost.input_cost_eur
        $metrics['outputCostEur']  = [double]$Cost.output_cost_eur
        $metrics['inputCostUsd']   = [double]$Cost.input_cost_usd
        $metrics['outputCostUsd']  = [double]$Cost.output_cost_usd
        # Derived "per image" metrics. Anti division-by-zero guard.
        if ($NImages -gt 0) {
            $metrics['costPerImageEur'] = [math]::Round([double]$Cost.total_cost_eur / $NImages, 6)
            $metrics['tokensPerImage']  = [math]::Round([double]$Cost.total_tokens / $NImages, 2)
            $metrics['secPerImage']     = [math]::Round([math]::Round($DurationSec, 2) / $NImages, 2)
        }
    }
    Send-Telemetry -Config $Config -EventName "ImageGeneration" -Properties $props -Metrics $metrics
}

# Calculates and logs the TEXT MODEL COST (optimize/negative/storyboard/describe),
# tracked separately from the image cost. Uses the REAL tokens (API usage field) and the
# manual prices from the .conf (textModel.inputUsdPerMillion / outputUsdPerMillion). Logs a
# dedicated [COST] line and returns an object with the breakdown (for telemetry), or
# $null if the prices are not configured. It is never blocking.
function Write-TextCostLog {
    param(
        [int]$InputTokens,
        [int]$OutputTokens,
        $Config,
        [ValidateSet("optimize","negative","storyboard","describe")][string]$Operation = "optimize",
        [string]$Verbosity = "normal",
        [string]$DefaultCurrency = "EUR"
    )
    $tm = $Config.textModel
    if (-not $tm) { return $null }
    # Manual prices (USD per million tokens). If absent/zero, I cannot calculate:
    # I warn once and return without cost (the tokens are still in the prompt log anyway).
    $inUsdM  = if ($tm.PSObject.Properties.Name -contains 'inputUsdPerMillion'  -and [double]$tm.inputUsdPerMillion  -gt 0) { [double]$tm.inputUsdPerMillion }  else { 0 }
    $outUsdM = if ($tm.PSObject.Properties.Name -contains 'outputUsdPerMillion' -and [double]$tm.outputUsdPerMillion -gt 0) { [double]$tm.outputUsdPerMillion } else { 0 }
    if ($inUsdM -le 0 -and $outUsdM -le 0) {
        Write-Log (T 'textcost.no_pricing' ([string]$tm.model)) -Level WARN
        return $null
    }

    $inputUsd  = ($InputTokens  / 1000000.0) * $inUsdM
    $outputUsd = ($OutputTokens / 1000000.0) * $outUsdM
    $totalUsd  = $inputUsd + $outputUsd

    $rate = if ($Config.PSObject.Properties.Name -contains 'usdToEurRate' -and [double]$Config.usdToEurRate -gt 0) { [double]$Config.usdToEurRate } else { 1.0 }
    $inputEur  = $inputUsd  * $rate
    $outputEur = $outputUsd * $rate
    $totalEur  = $totalUsd  * $rate

    $totalTokens = $InputTokens + $OutputTokens
    $timestamp = (Get-Date).ToString("yyyy-MM-dd HH:mm:ss", [System.Globalization.CultureInfo]::InvariantCulture)
    # Readable label of the operation (Optimize/Negative/Storyboard/Describe), used
    # both in the file line prefix and in the on-screen summary.
    $opLabel = T ('textcost.op_' + $Operation)

    # VERBOSE line written directly to the file (not via Write-Log, to avoid the
    # duplicate on screen): prefix with the operation label + payload with
    # operation= so the user can isolate at a glance and via grep the cost of
    # each function (optimize/negative/storyboard/describe).
    $detailedLine = ("model={0} kind=textmodel operation={1} input_tokens={2} output_tokens={3} total_tokens={4} " +
                     "input_usd={5} output_usd={6} total_usd={7} total_eur={8} eur_rate={9}") -f `
                    ([string]$tm.model), $Operation, $InputTokens, $OutputTokens, $totalTokens, `
                    (Format-StorageNumber $inputUsd), (Format-StorageNumber $outputUsd), `
                    (Format-StorageNumber $totalUsd), (Format-StorageNumber $totalEur), (Format-StorageNumber $rate 4)
    $fullLogLine = "[$timestamp] [COST] ${opLabel}: $detailedLine"
    if ($script:LogFile) {
        Add-Content -Path $script:LogFile -Value (Protect-LogFileLine $fullLogLine) -Encoding UTF8 -ErrorAction SilentlyContinue
    }

    # On screen: SYNTHETIC version in the style of the image cost, in the local currency + tokens,
    # con l'etichetta dell'operazione. Es: "[COST] optimize: 0,3749 EUR (input: 357
    # tok, output: 14272 tok, totale: 14629 tok)".
    if ($Verbosity -eq "verbose" -or $Verbosity -eq "normal") {
        $localCost = if ($DefaultCurrency -eq "USD") {
            (Format-DisplayNumber -Value $totalUsd -Decimals 4) + " USD"
        } else {
            (Format-DisplayNumber -Value $totalEur -Decimals 4) + " EUR"
        }
        $detail = T 'cost.synthetic_tokens' $InputTokens $OutputTokens $totalTokens
        Write-Host ("[$timestamp] [COST] " + $opLabel + ": " + $localCost + " " + $detail)
    }

    return [pscustomobject]@{
        Operation = $Operation
        InputTokens = $InputTokens; OutputTokens = $OutputTokens
        TotalTokens = $totalTokens
        InputUsd = $inputUsd; OutputUsd = $outputUsd; TotalUsd = $totalUsd
        InputEur = $inputEur; OutputEur = $outputEur; TotalEur = $totalEur
        EurRate = $rate
    }
}

# Sends the text cost telemetry as a SEPARATE event ("TextModelCost"),
# so it does not mix with the "ImageGeneration" events in the charts. The operation
# (optimize/negative/storyboard/describe) is a property, to allow grouping by function.
# Non-blocking.
function Send-TextCostTelemetry {
    param($Config, $TextCost, [string]$TextModel = "")
    if ($script:NoTelemetryFlag) { return }
    if (-not $TextCost) { return }
    $props = @{
        textModel = [string]$TextModel
        operation = [string]$TextCost.Operation
        outcome   = "success"
    }
    $metrics = @{
        textInputTokens  = [double]$TextCost.InputTokens
        textOutputTokens = [double]$TextCost.OutputTokens
        textTotalTokens  = [double]$TextCost.TotalTokens
        textCostUsd      = [double]$TextCost.TotalUsd
        textCostEur      = [double]$TextCost.TotalEur
    }
    Send-Telemetry -Config $Config -EventName "TextModelCost" -Properties $props -Metrics $metrics
}

function Invoke-LogCleanup {
    param(
        [int]$MaxSizeMB,
        [int]$RetentionDays
    )

    if (-not (Test-Path $script:LogFile)) { return }

    try {
        $fileInfo = Get-Item $script:LogFile -ErrorAction Stop
    } catch { return }

    $sizeMB = $fileInfo.Length / 1MB
    if ($sizeMB -lt $MaxSizeMB) { return }

    $threshold = (Get-Date).AddDays(-$RetentionDays)

    try {
        $lines = Get-Content $script:LogFile -Encoding UTF8 -ErrorAction Stop
    } catch { return }

    $kept = New-Object System.Collections.Generic.List[string]
    $removed = 0

    foreach ($line in $lines) {
        # For the date filter I decrypt the line if necessary; in the file I ALWAYS
        # keep the original line (encrypted or not).
        $probe = Unprotect-LogLine $line
        if ($probe -match '^\[(\d{4}-\d{2}-\d{2})\s') {
            try {
                $lineDate = [DateTime]::ParseExact($Matches[1], "yyyy-MM-dd", [System.Globalization.CultureInfo]::InvariantCulture)
                if ($lineDate -ge $threshold) {
                    $kept.Add($line)
                } else {
                    $removed++
                }
            }
            catch {
                $kept.Add($line)
            }
        } else {
            $kept.Add($line)
        }
    }

    if ($removed -gt 0) {
        try {
            $kept | Set-Content -Path $script:LogFile -Encoding UTF8 -ErrorAction Stop
        } catch {
            return
        }
    }
    $script:PendingLogCleanupMessage = if ($removed -gt 0) {
        "Pulizia log: rimosse $removed righe piu' vecchie di $RetentionDays giorni (file era $([math]::Round($sizeMB,2)) MB)"
    } else { $null }
}

function Get-ArenaLeaderboard {
    <#
    Scrapes the text-to-image leaderboard of arena.ai (or the configured URL) and returns
    a hashtable @{ "arena model name" = score_int }.

    . Independent of the pricing parser because the structure of the
    page is completely different (generic leaderboard table, not labeled/columnar
    Azure).

    Parsing strategy (tolerant to small HTML variations):
      1. Downloads the HTML via Invoke-WebRequest (configurable timeout, browser UA).
      2. Extracts the table rows that contain patterns like:
            <a ... title="MODEL_NAME" ...>...</a>...<td...>SCORE</td>
         or equivalent forms (links without title, td with a specific class, etc.)
      3. Filter: the score must be a 3-4 digit integer in the range 800-2000 (the
         Elo values of the leaderboards typically lie in there).

    Returns:
      $null on network/timeout/parsing-failed error
      empty hashtable if it finds nothing (parsing ok but no match)
      hashtable popolata in caso di successo
    #>
    param(
        [Parameter(Mandatory=$true)] [string]$ArenaUrl,
        [int]$TimeoutSec = 15
    )

    # ---- 1. Download HTML ----
    $html = $null
    try {
        $headers = @{
            'User-Agent' = 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0 Safari/537.36'
            'Accept'     = 'text/html,application/xhtml+xml'
        }
        $response = Invoke-WebRequest -Uri $ArenaUrl -Method GET -Headers $headers `
                                      -TimeoutSec $TimeoutSec -UseBasicParsing `
                                      -ErrorAction Stop
        $html = $response.Content
    } catch {
        Write-Log (T 'auto.arena_fetch_failed' $ArenaUrl ($_.Exception.Message)) -Level WARN
        return $null
    }

    if (-not $html -or $html.Length -lt 1000) {
        Write-Log (T 'auto.arena_empty_response' $ArenaUrl) -Level WARN
        return $null
    }

    # ---- 2. Parsing ----
    # Pattern 1 (preferred): HTML link with title attribute = model name, followed
    # within the same <tr> or within a short distance (~800 chars) by a
    # 3-4 digit number. The "title" is the authoritative source of the name (the visible
    # text of the link might have prefixes like the lab's "Flux ").
    #
    # Pattern 2 (markdown fallback): in case the page is returned in markdown
    # format (unlikely but it happened during prototyping), pattern
    # [name](url) ... | SCORE
    #
    # Pattern 3 (safety net): if both fail, looks for the pattern "name with
    # parentheses, hyphens or dots" followed WITHIN 300 chars by a 4-digit number.
    # Less precise but robust to page reorganizations.
    $leaderboard = @{}

    # ---- Pattern 1: HTML structured ----
    # Tolerant to whitespace and CSS classes. The lazy ".{1,800}?" limit prevents
    # traversing the entire page, but it can traverse several <tr> if they are short.
    # The plausibility filter on the score (800-2000) prevents false positives.
    $pattern1 = '(?is)<a[^>]*\btitle="([^"]+)"[^>]*>.*?</a>(?:.{1,800}?)(?:<td[^>]*>|>)\s*(\d{3,4})\b'
    $matches1 = [regex]::Matches($html, $pattern1)
    foreach ($m in $matches1) {
        $name = $m.Groups[1].Value.Trim()
        $scoreText = $m.Groups[2].Value.Trim()
        $score = 0
        if ([int]::TryParse($scoreText, [ref]$score)) {
            if ($score -ge 800 -and $score -le 2000) {
                if (-not $leaderboard.ContainsKey($name)) {
                    $leaderboard[$name] = $score
                }
            }
        }
    }

    # ---- Pattern 2 (fallback): markdown-style [name](url) ... | SCORE ----
    if ($leaderboard.Count -eq 0) {
        $pattern2 = '\[([^\]]+)\]\([^)]+\)[^|]{0,200}\|\s*(\d{3,4})\b'
        $matches2 = [regex]::Matches($html, $pattern2)
        foreach ($m in $matches2) {
            $name = $m.Groups[1].Value.Trim()
            $scoreText = $m.Groups[2].Value.Trim()
            $score = 0
            if ([int]::TryParse($scoreText, [ref]$score)) {
                if ($score -ge 800 -and $score -le 2000) {
                    if (-not $leaderboard.ContainsKey($name)) {
                        $leaderboard[$name] = $score
                    }
                }
            }
        }
    }

    # ---- Pattern 3 (safety net): bare text after stripping the HTML tags ----
    # If patterns 1/2 failed, I strip the tags and look for textual patterns
    # "model-name-with-hyphens" + spaces + any text (up to 200 chars)
    # + space + standalone 3-4 digit number. Robust to unusual HTML structures.
    if ($leaderboard.Count -eq 0) {
        $plainText = [regex]::Replace($html, '(?is)<[^>]+>', ' ')
        $plainText = [regex]::Replace($plainText, '\s+', ' ')
        # Name: must have at least one internal hyphen (?:-[a-z0-9.]+)+
        # Forces the "word-word[-word...]" structure typical of model names.
        # Score: standalone 3-4 digit number preceded by whitespace.
        # (?!\d)(?!-) exclude adjacent digits/hyphen, so "2026-04-22" is not
        # matched as the score "2026" and "38,379" votes is not confused.
        $pattern3 = '\b([a-z][a-z0-9.]*(?:-[a-z0-9.]+)+)\s+[^\n]{1,200}?\s(\d{3,4})\b(?!\d)(?!-)'
        $matches3 = [regex]::Matches($plainText, $pattern3)
        foreach ($m in $matches3) {
            $name = $m.Groups[1].Value.Trim()
            $scoreText = $m.Groups[2].Value.Trim()
            $score = 0
            if ([int]::TryParse($scoreText, [ref]$score)) {
                if ($score -ge 800 -and $score -le 2000) {
                    if (-not $leaderboard.ContainsKey($name)) {
                        $leaderboard[$name] = $score
                    }
                }
            }
        }
    }

    if ($leaderboard.Count -eq 0) {
        Write-Log (T 'auto.arena_parse_failed' $ArenaUrl) -Level WARN
        return $null
    }

    Write-Log (T 'auto.arena_parsed' $ArenaUrl $leaderboard.Count)
    return $leaderboard
}

function Find-BestArenaMatch {
    <#
    Resolves the matching between the name of a local model (.conf) and an entry of the
    arena.ai leaderboard. Strategy:
      1. If ModelConfig has a non-empty qualityArenaAlias -> use that (exact case-insensitive lookup).
      2. Otherwise, fuzzy matching:
         a. Exact lookup on the model name (case-insensitive)
         b. If not found: looks for a leaderboard entry of which the model is a substring
            (case-insensitive). Example: "gpt-image-2" matches "gpt-image-2 (medium)".
         c. If not found: looks for a leaderboard entry that is a substring of the model
            (case-insensitive, the other way around). Rare case.
         d. If still nothing: looks for the model with the longest common prefix (best-effort,
            e.g. "MAI-Image-2e" -> "mai-image-2" as the closest).

    Returns: [PSCustomObject] with
      MatchedName  = name found in the leaderboard (or $null if no match)
      Score        = score (int)
      MatchMethod  = "alias" | "exact" | "model-in-arena" | "arena-in-model" | "prefix" | "none"
    #>
    param(
        [Parameter(Mandatory=$true)] [string]$ModelName,
        [Parameter(Mandatory=$true)] $ModelConfig,
        [Parameter(Mandatory=$true)] [hashtable]$Leaderboard
    )

    $nullResult = [PSCustomObject]@{ MatchedName = $null; Score = 0; MatchMethod = "none" }
    if ($Leaderboard.Count -eq 0) { return $nullResult }

    $modelLower = $ModelName.ToLower()

    # Helper: lookup case-insensitive
    $findKey = {
        param([string]$needle)
        foreach ($k in $Leaderboard.Keys) {
            if ($k -ieq $needle) { return $k }
        }
        return $null
    }

    # 1. Explicit alias
    $alias = if ($ModelConfig.PSObject.Properties.Name -contains 'qualityArenaAlias') {
        [string]$ModelConfig.qualityArenaAlias
    } else { "" }
    if ($alias -and $alias.Trim() -ne "") {
        $found = & $findKey $alias
        if ($found) {
            return [PSCustomObject]@{ MatchedName = $found; Score = $Leaderboard[$found]; MatchMethod = "alias" }
        }
    }

    # 2a. Exact match
    $found = & $findKey $ModelName
    if ($found) {
        return [PSCustomObject]@{ MatchedName = $found; Score = $Leaderboard[$found]; MatchMethod = "exact" }
    }

    # 2b. Model in arena (model name sottostringa di un'entry arena)
    foreach ($k in $Leaderboard.Keys) {
        if ($k.ToLower().Contains($modelLower)) {
            return [PSCustomObject]@{ MatchedName = $k; Score = $Leaderboard[$k]; MatchMethod = "model-in-arena" }
        }
    }

    # 2c. Arena in model (arena entry is a substring of the model name)
    foreach ($k in $Leaderboard.Keys) {
        if ($modelLower.Contains($k.ToLower())) {
            return [PSCustomObject]@{ MatchedName = $k; Score = $Leaderboard[$k]; MatchMethod = "arena-in-model" }
        }
    }

    # 2d. Best-effort: longest common prefix. For "MAI-Image-2e" I look for the
    # arena entry with the most initial characters in common (case-insensitive).
    # Threshold: at least 6 initial characters in common to avoid absurd matches.
    $bestKey = $null
    $bestPrefix = 0
    foreach ($k in $Leaderboard.Keys) {
        $kLower = $k.ToLower()
        $minLen = [math]::Min($modelLower.Length, $kLower.Length)
        $i = 0
        while ($i -lt $minLen -and $modelLower[$i] -eq $kLower[$i]) { $i++ }
        if ($i -ge 6 -and $i -gt $bestPrefix) {
            $bestPrefix = $i
            $bestKey = $k
        }
    }
    if ($bestKey) {
        return [PSCustomObject]@{ MatchedName = $bestKey; Score = $Leaderboard[$bestKey]; MatchMethod = "prefix" }
    }

    return $nullResult
}

function Update-QualityRatingsFromArena {
    <#
    Updates the .conf pricing-style: for each active model, downloads/uses the cache
    of the arena.ai leaderboard and populates qualityRating + qualityRatingLastUpdate.

    Cache: if qualityRatingLastUpdate for ALL the models is within qualityRefreshDays
    and $Force=$false, it does nothing (silent skip). Otherwise it downloads and updates.

    the values written in qualityRating are Arena scores (~900-1400), NOT
    1-10 values. Select-AutoModel treats them as "higher=better" and that is enough.

    Returns: $true if it updated something, $false otherwise.
    #>
    param(
        [Parameter(Mandatory=$true)] $Config,
        [Parameter(Mandatory=$true)] [string]$ConfigPath,
        [switch]$Force
    )

    $autoConf = $Config.autoUpdate
    if (-not $autoConf) {
        Write-Log (T 'auto.no_config_autoUpdate') -Level WARN
        return $false
    }

    $refreshDays = if ($autoConf.qualityRefreshDays) { [int]$autoConf.qualityRefreshDays } else { 7 }
    $arenaUrl    = if ($autoConf.arenaUrl)           { [string]$autoConf.arenaUrl }       else { "" }
    $timeoutSec  = if ($autoConf.arenaTimeoutSec)    { [int]$autoConf.arenaTimeoutSec }   else { 15 }

    if (-not $arenaUrl) {
        Write-Log (T 'auto.no_arena_url') -Level WARN
        return $false
    }

    # ---- Cache check: if ALL the active models are recent, skip ----
    $today = (Get-Date).ToString("yyyy-MM-dd", [System.Globalization.CultureInfo]::InvariantCulture)
    $needsRefresh = $Force.IsPresent
    if (-not $needsRefresh) {
        $activeModels = @($Config.models | Get-Member -MemberType NoteProperty |
                          ForEach-Object { $Config.models.$($_.Name) } |
                          Where-Object { $_.active -ne $false })
        foreach ($m in $activeModels) {
            $lastUpd = if ($m.PSObject.Properties.Name -contains 'qualityRatingLastUpdate') {
                [string]$m.qualityRatingLastUpdate
            } else { "" }
            if (-not $lastUpd) { $needsRefresh = $true; break }
            try {
                $lastDate = [datetime]::ParseExact($lastUpd, "yyyy-MM-dd", [System.Globalization.CultureInfo]::InvariantCulture)
                $daysSince = ((Get-Date) - $lastDate).TotalDays
                if ($daysSince -ge $refreshDays) { $needsRefresh = $true; break }
            } catch {
                $needsRefresh = $true; break
            }
        }
    }

    if (-not $needsRefresh) {
        return $false  # cache valida per tutti, skip silenzioso
    }

    if ($Force.IsPresent) {
        Write-Log (T 'auto.quality_force_bypass')
    }

    # ---- Download and parse the leaderboard ----
    Write-Log (T 'auto.quality_fetch_arena' $arenaUrl)
    $leaderboard = Get-ArenaLeaderboard -ArenaUrl $arenaUrl -TimeoutSec $timeoutSec

    if (-not $leaderboard -or $leaderboard.Count -eq 0) {
        # Fallback: we leave the cached values unchanged, reporting the problem.
        Write-Log (T 'auto.quality_fallback_cache') -Level WARN
        return $false
    }

    # ---- Update the models ----
    $modelsUpdated = 0
    $modelNames = @($Config.models | Get-Member -MemberType NoteProperty | Select-Object -ExpandProperty Name)
    foreach ($mdlName in $modelNames) {
        $mdl = $Config.models.$mdlName
        $match = Find-BestArenaMatch -ModelName $mdlName -ModelConfig $mdl -Leaderboard $leaderboard
        if ($match.MatchMethod -eq "none") {
            Write-Log (T 'auto.quality_no_match' $mdlName) -Level WARN
            # I leave qualityRating unchanged (if it was already there, it will be the old value;
            # se era 0, resta 0 e Select-AutoModel lo escludera' dalla Quality)
            continue
        }
        $mdl.qualityRating = [double]$match.Score
        if (-not ($mdl.PSObject.Properties.Name -contains 'qualityRatingLastUpdate')) {
            $mdl | Add-Member -NotePropertyName 'qualityRatingLastUpdate' -NotePropertyValue $today -Force
        } else {
            $mdl.qualityRatingLastUpdate = $today
        }
        Write-Log (T 'auto.quality_updated' $mdlName ([int]$match.Score) ($match.MatchedName) ($match.MatchMethod))
        $modelsUpdated++
    }

    # Save
    try {
        $Config | ConvertTo-Json -Depth 10 | Set-Content -Path $ConfigPath -Encoding UTF8 -ErrorAction Stop
    } catch {
        Write-Log (T 'auto.save_error' ($_.Exception.Message)) -Level WARN
    }
    Write-Log (T 'auto.quality_update_summary' $modelsUpdated)
    return ($modelsUpdated -gt 0)
}

function Update-SpeedRatingsFromLog {
    <#
    Updates speedRating by reading the [TIME] lines from the current log. For each
    model, it computes the median of the 'actual' times filtered by:
      - quality   = quality of the current run (e.g. "high")
      - size      = size of the current run (e.g. "1024x1024")
      - successfully completed (attempts>=1, has 'actual')

    Cache: if speedRatingLastUpdate for ALL the active models is within
    timeRefreshDays and $Force=$false, silent skip.

    Minimum data threshold: if a model has fewer than timeMinRecords matching
    runs, the model is excluded (speedRating set to 0).

    the values written in speedRating are medians in seconds. Select-AutoModel
    treats them as "lower=better".

    Returns: $true if it updated something, $false otherwise.
    #>
    param(
        [Parameter(Mandatory=$true)] $Config,
        [Parameter(Mandatory=$true)] [string]$ConfigPath,
        [Parameter(Mandatory=$true)] [string]$Quality,
        [Parameter(Mandatory=$true)] [string]$Size,
        [Parameter(Mandatory=$true)] [string]$LogFilePath,
        [switch]$Force
    )

    $autoConf = $Config.autoUpdate
    if (-not $autoConf) {
        Write-Log (T 'auto.no_config_autoUpdate') -Level WARN
        return $false
    }
    $refreshDays = if ($autoConf.timeRefreshDays) { [int]$autoConf.timeRefreshDays } else { 7 }
    $minRecords  = if ($autoConf.timeMinRecords)  { [int]$autoConf.timeMinRecords }  else { 3 }
    $maxRecords  = if ($autoConf.timeMaxRecords)  { [int]$autoConf.timeMaxRecords }  else { 50 }

    # ---- Cache check ----
    $today = (Get-Date).ToString("yyyy-MM-dd", [System.Globalization.CultureInfo]::InvariantCulture)
    $needsRefresh = $Force.IsPresent
    if (-not $needsRefresh) {
        $activeModels = @($Config.models | Get-Member -MemberType NoteProperty |
                          ForEach-Object { $Config.models.$($_.Name) } |
                          Where-Object { $_.active -ne $false })
        foreach ($m in $activeModels) {
            $lastUpd = if ($m.PSObject.Properties.Name -contains 'speedRatingLastUpdate') {
                [string]$m.speedRatingLastUpdate
            } else { "" }
            if (-not $lastUpd) { $needsRefresh = $true; break }
            try {
                $lastDate = [datetime]::ParseExact($lastUpd, "yyyy-MM-dd", [System.Globalization.CultureInfo]::InvariantCulture)
                if (((Get-Date) - $lastDate).TotalDays -ge $refreshDays) { $needsRefresh = $true; break }
            } catch { $needsRefresh = $true; break }
        }
    }
    if (-not $needsRefresh) { return $false }

    if ($Force.IsPresent) {
        Write-Log (T 'auto.time_force_bypass')
    }

    # ---- Leggo il log ----
    if (-not (Test-Path $LogFilePath)) {
        Write-Log (T 'auto.time_no_log' $LogFilePath) -Level WARN
        return $false
    }

    Write-Log (T 'auto.time_compute_medians' $Quality $Size)

    # Parsing [TIME] lines. Example format:
    # [2026-05-23 11:10:05] [TIME] date=2026-05-23 start=... end=... estimated=124 actual=97 model=gpt-image-1.5 deployment=... mode=edit prompt_len=154 size=1536x1024 format=png quality=high n_images=1 input_images_count=3 attempts=1
    # We extract: model, quality, size, actual
    $timesByModel = @{}  # model name -> list of times (sec) in reverse chronological order (latest first)

    # I read the log with robust handling: empty file -> empty array, 1-line file -> single array
    $logLines = @()
    try {
        $raw = Get-Content -Path $LogFilePath -Encoding UTF8 -ErrorAction Stop
        if ($null -eq $raw) {
            $logLines = @()
        } elseif ($raw -is [array]) {
            $logLines = $raw
        } else {
            # Single line: Get-Content returns a string, not an array
            $logLines = @($raw)
        }
        if ($logLines.Count -gt 0) {
            # Reverse to read the most recent records first (so we respect timeMaxRecords)
            [array]::Reverse($logLines)
        }
    } catch {
        Write-Log (T 'auto.time_log_read_error' ($_.Exception.Message)) -Level WARN
        return $false
    }

    if ($logLines.Count -eq 0) {
        # Empty log: no previous run to analyze. All the models will have
        # 0 records and therefore 0 medians -> we fall into the "insufficient data" case.
        Write-Log (T 'auto.time_no_records_yet') -Level WARN
    }

    # Model-name canonicalization: the historical records in the log may have the name
    # with a different case (e.g. "GPT-Image-2" vs "gpt-image-2") or suffixes ("gpt-image-2-cto").
    # Without merging, these create "phantom entries" in the Auto Time ranking and,
    # worse, their records do NOT match the .conf names (which use the canonical
    # case) and would be lost. I map each name back to the canonical .conf name.
    $confModelNamesST = @()
    if ($Config -and $Config.models) {
        $confModelNamesST = @($Config.models.PSObject.Properties.Name)
    }
    $canonMapST = @{}

    foreach ($line in $logLines) {
        if ($line -notmatch '\[TIME\]') { continue }
        # I extract the fields I need
        $modelMatch   = [regex]::Match($line, 'model=(\S+)')
        $qualityMatch = [regex]::Match($line, 'quality=(\S+)')
        $sizeMatch    = [regex]::Match($line, 'size=(\S+)')
        $actualMatch  = [regex]::Match($line, 'actual=(\d+(?:\.\d+)?)')
        if (-not ($modelMatch.Success -and $qualityMatch.Success -and $sizeMatch.Success -and $actualMatch.Success)) {
            continue
        }
        $logModel   = $modelMatch.Groups[1].Value
        $logQuality = $qualityMatch.Groups[1].Value
        $logSize    = $sizeMatch.Groups[1].Value
        $logActual  = [double]$actualMatch.Groups[1].Value
        # I map the model name back to the .conf canonical (merges case/suffix variants).
        $logModel = Get-CanonicalModelName -RawName $logModel -ConfModelNames $confModelNamesST -CanonMap $canonMapST
        # Filtra per quality+size. Confronto case-insensitive: $Quality/$Size sono gia'
        # normalizzati lowercase a monte, ma i record storici del log potrebbero avere
        # quality/size con case diverso (es. "High", "1024X1024").
        if ($logQuality -ine $Quality) { continue }
        if ($logSize    -ine $Size)    { continue }
        if (-not $timesByModel.ContainsKey($logModel)) {
            $timesByModel[$logModel] = New-Object System.Collections.ArrayList
        }
        if ($timesByModel[$logModel].Count -lt $maxRecords) {
            [void]$timesByModel[$logModel].Add($logActual)
        }
    }

    # ---- Compute the median per model and update the .conf ----
    # Two phases: first I compute the medians and update the .conf; then I log the results
    # SORTED from fastest to slowest (increasing median), so reading
    # the log makes the speed ranking immediately evident. Models with insufficient
    # data are logged separately (WARN), after the valid ones.
    $modelsUpdated = 0
    $modelNames = @($Config.models | Get-Member -MemberType NoteProperty | Select-Object -ExpandProperty Name)
    $medianResults = @()   # { Name; Median; Count } per i modelli con dati validi
    $insufficient  = @()   # { Name; Count } per i modelli con dati insufficienti
    foreach ($mdlName in $modelNames) {
        $mdl = $Config.models.$mdlName
        $times = if ($timesByModel.ContainsKey($mdlName)) { @($timesByModel[$mdlName]) } else { @() }
        if ($times.Count -lt $minRecords) {
            # Not enough data: speedRating = 0 (excluded by Select)
            $mdl.speedRating = 0.0
            $insufficient += [PSCustomObject]@{ Name = $mdlName; Count = $times.Count }
        } else {
            # Mediana
            $sorted = $times | Sort-Object
            $n = $sorted.Count
            $median = if ($n % 2 -eq 1) { $sorted[[int]($n/2)] }
                      else              { ($sorted[[int]($n/2 - 1)] + $sorted[[int]($n/2)]) / 2.0 }
            $mdl.speedRating = [math]::Round($median, 2)
            $medianResults += [PSCustomObject]@{ Name = $mdlName; Median = $median; Count = $times.Count }
            $modelsUpdated++
        }
        if (-not ($mdl.PSObject.Properties.Name -contains 'speedRatingLastUpdate')) {
            $mdl | Add-Member -NotePropertyName 'speedRatingLastUpdate' -NotePropertyValue $today -Force
        } else {
            $mdl.speedRatingLastUpdate = $today
        }
    }

    # Sorted log: first the valid models from fastest to slowest, then any
    # models with insufficient data.
    foreach ($r in ($medianResults | Sort-Object Median)) {
        Write-Log (T 'auto.time_median_computed' $r.Name ([math]::Round($r.Median, 1)) $r.Count)
    }
    foreach ($r in $insufficient) {
        Write-Log (T 'auto.time_insufficient_data' $r.Name $r.Count $minRecords) -Level WARN
    }

    try {
        $Config | ConvertTo-Json -Depth 10 | Set-Content -Path $ConfigPath -Encoding UTF8 -ErrorAction Stop
    } catch {
        Write-Log (T 'auto.save_error' ($_.Exception.Message)) -Level WARN
    }
    Write-Log (T 'auto.time_update_summary' $modelsUpdated)
    return ($modelsUpdated -gt 0)
}

function Select-AutoModel {
    <#
    Automatic model selection for -Auto. The strategy is mandatory.

    Supported strategies (-Strategy parameter):
      - "Cost":    chooses the CHEAPEST model. Cost_score = sum of the main
                   meters (for AOAI: inputText+outputImage; for MAI: input+output).
                   Lower = better.
      - "Quality": chooses the model with the BEST QUALITY. Uses the
                   "qualityRating" field (1-10, 10=best) present in the .conf for each
                   model. SUBJECTIVE evaluation to be set manually based
                   on the experience with the model on one's own typical use cases.
      - "Time":    chooses the FASTEST model. Uses the "speedRating" field
                   (1-10, 10=fastest) present in the .conf for each model.
                   SUBJECTIVE evaluation to be set manually.

    Filters always applied before the selection:
      1. active=true (field to set manually in the config)
      2. endpoint and apiKey configured (not empty)
      3. If the user passed -Mask:          requires supportsInpainting=true
      4. If the user passed -InputFidelity: requires supportsInputFidelity=true
      5. If the user passed -Background:    requires supportsBackground=true

    Returns: the name of the chosen model, or $null if none is eligible.
    Logs ALL the exclusions with reason, for full transparency in the choices.
    #>
    param(
        $Config,
        [Parameter(Mandatory=$true)][ValidateSet("Cost","Quality","Time")]
        [string]$Strategy,
        [bool]$NeedsInpainting,
        [bool]$NeedsInputFidelity,
        [bool]$NeedsBackground,
        [string]$RatingsFolder = "",
        # Parameters of the real generation: for the Cost strategy they are needed to estimate the
        # ACTUAL COST of A generation with these parameters (quality + size),
        # making different pricing metrics comparable (tokens vs megapixels).
        [string]$EffectiveQuality = "",
        [string]$EffectiveSize = "",
        [string]$PromptText = "",
        [double]$EurRate = 1.0
    )

    $allModelNames = @($Config.models | Get-Member -MemberType NoteProperty | Select-Object -ExpandProperty Name)
    $candidates = @()

    # Gallery votes (gallery_ratings.json), if present in the images folder.
    # For the Quality strategy, a model with at least $voteThreshold votes integrates the
    # giudizio reale dell'utente nello scoring (media pesata con lo score Arena).
    $galleryRatings = $null
    $voteThreshold = 5
    if ($Strategy -eq 'Quality' -and $RatingsFolder -and (Test-Path $RatingsFolder)) {
        $ratingsPath = Join-Path $RatingsFolder 'gallery_ratings.json'
        if (Test-Path $ratingsPath) {
            try {
                $rj = (Get-Content $ratingsPath -Raw -Encoding UTF8 -ErrorAction Stop) | ConvertFrom-Json -ErrorAction Stop
                if ($rj.models) {
                    $galleryRatings = $rj.models
                    Write-Log (T 'auto.ratings_loaded' $ratingsPath) -Level INFO
                }
            } catch {
                Write-Log (T 'auto.ratings_bad' ($_.Exception.Message)) -Level WARN
            }
        } else {
            # File assente: lo segnalo (richiesta esplicita di feedback). Non e' un
            # error: the selection continues with the Arena score only.
            Write-Log (T 'auto.ratings_not_found' $RatingsFolder) -Level INFO
        }
    }

    foreach ($name in $allModelNames) {
        $mc = $Config.models.$name

        # Skip if not active (default: active if the 'active' field is not defined,
        # per retrocompatibilita' con conf vecchi)
        $isActive = if ($null -ne $mc.active) { [bool]$mc.active } else { $true }
        if (-not $isActive) {
            Write-Log (T 'auto.excluded_inactive' $name) -Level INFO
            continue
        }

        # Skip if not configured (empty endpoint/apiKey)
        if (-not $mc.endpoint -or $mc.endpoint.Trim() -eq "") {
            Write-Log (T 'auto.excluded_empty_endpoint' $name) -Level INFO
            continue
        }
        if (-not $mc.apiKey -or $mc.apiKey.Trim() -eq "") {
            Write-Log (T 'auto.excluded_empty_apikey' $name) -Level INFO
            continue
        }

        # Skip if it does not support the required features
        $supInp = if ($null -ne $mc.supportsInpainting)    { [bool]$mc.supportsInpainting }    else { $false }
        $supIF  = if ($null -ne $mc.supportsInputFidelity) { [bool]$mc.supportsInputFidelity } else { $false }
        $supBg  = if ($null -ne $mc.supportsBackground)    { [bool]$mc.supportsBackground }    else { $false }

        if ($NeedsInpainting    -and -not $supInp) { Write-Log (T 'auto.excluded_no_inpainting' $name) -Level INFO; continue }
        if ($NeedsInputFidelity -and -not $supIF)  { Write-Log (T 'auto.excluded_no_input_fidelity' $name) -Level INFO; continue }
        if ($NeedsBackground    -and -not $supBg)  { Write-Log (T 'auto.excluded_no_background' $name) -Level INFO; continue }

        # Computing the three scores (one for each possible strategy)
        # CostScore (Cost strategy): ESTIMATED COST IN USD of A generation with the
        # real parameters passed by the user (quality + size). It is metric-agnostic:
        # it uses Get-CostBreakdown (the same function that computes the real [COST] at the end
        # of a generation), so models with DIFFERENT pricing metrics become
        # comparable on the same basis:
        #   - tokens (gpt-image, labeled): tokens estimated from quality+size via Get-EstimatedTokens
        #   - tokens (MAI, columnar):      same, mapped to input/output
        #   - megapixels (FLUX):           per-MP cost from the image dimensions
        # Previously costScore summed fixed meters (inputText+outputImage / input+output),
        # zeroing the per-megapixel models (FLUX -> 0 -> always "won") and comparing
        # non-homogeneous scales. Now the number is a real cost in USD, lower=better.
        $pricing = $mc.pricing
        $costScore = [double]::PositiveInfinity   # default: se non stimabile, non e' il piu' economico
        if ($pricing) {
            # Image dimensions from the real parameters (size "1024x1024").
            $genW = 0; $genH = 0
            if ($EffectiveSize -and $EffectiveSize -match '^(\d+)\s*[xX]\s*(\d+)$') {
                $genW = [int]$Matches[1]; $genH = [int]$Matches[2]
            }
            # Tokens estimated from quality+size (for token-based models; ignored by per-MP).
            $estTok = Get-EstimatedTokens -PromptText $PromptText -Width $genW -Height $genH `
                                          -NImages 1 -Quality $EffectiveQuality
            # Synthetic usage: I split text/image input prudently (all on text)
            # and the output on the image. Get-CostBreakdown maps these to the right meters
            # for the model schema (labeled or columnar). For per-MP models the
            # usage e' ignorata e conta solo GenWidth/GenHeight.
            $synthUsage = [PSCustomObject]@{
                input_tokens  = [int]$estTok.InputTokens
                output_tokens = [int]$estTok.OutputTokens
                total_tokens  = [int]($estTok.InputTokens + $estTok.OutputTokens)
            }
            try {
                $cb = Get-CostBreakdown -Usage $synthUsage -Pricing $pricing -EurRate $EurRate `
                                        -GenWidth $genW -GenHeight $genH -NImages 1 `
                                        -PromptText $PromptText -Quality $EffectiveQuality
                if ($cb -and $null -ne $cb.total_cost_usd) {
                    $estCost = [double]$cb.total_cost_usd
                    # A real cost of 0 is suspicious (prices not configured): I exclude it from
                    # "cheapest" by leaving it infinite, so it does not win due to missing data.
                    if ($estCost -gt 0) { $costScore = $estCost }
                }
            } catch {
                # Estimate failed for this model: it stays infinite (not eligible as
                # cheapest), but it does not block the selection of the others.
                $costScore = [double]::PositiveInfinity
            }
        }
        # QualityRating / SpeedRating :
        # - qualityRating: Arena score (~900-1400), 0 = not in leaderboard / not evaluated
        # - speedRating: median times in SECONDS for the current quality+size,
        # 0 = not enough data (< timeMinRecords)
        # The values are populated by Update-QualityRatingsFromArena / Update-SpeedRatingsFromLog
        # For back-compat: 1-10 values left by hand in the .conf are still interpreted as
        # quality rating (higher=better) e speedRating (lower=better) — non si distingue
        # quanti decimali, la logica funziona uniformemente.
        $qualityRating = if ($null -ne $mc.qualityRating) { [double]$mc.qualityRating } else { 0.0 }
        $speedRating   = if ($null -ne $mc.speedRating)   { [double]$mc.speedRating }   else { 0.0 }

        # Gallery votes for this model (if present and sufficient).
        $voteAvg = 0.0
        $voteCount = 0
        if ($galleryRatings) {
            # The match is case-insensitive on the model name.
            $mr = $galleryRatings.PSObject.Properties | Where-Object { $_.Name -ieq $name } | Select-Object -First 1
            if ($mr -and $mr.Value) {
                $voteCount = [int]$mr.Value.votes
                $voteAvg   = [double]$mr.Value.average
            }
        }

        $candidates += [pscustomobject]@{
            Name          = $name
            CostScore     = $costScore
            QualityRating = $qualityRating
            SpeedRating   = $speedRating
            VoteAvg       = $voteAvg
            VoteCount     = $voteCount
        }
    }

    if ($candidates.Count -eq 0) {
        Write-Log (T 'auto.no_eligible') -Level ERROR
        return $null
    }

    # Selezione in base alla strategia.
    # For Quality and Time further filters are needed: models with score=0 are excluded
    # because they mean "not evaluated" (Quality) or "insufficient data" (Time).
    # If AFTER the filter nothing remains, fallback to defaultModel with WARN.
    $best = $null
    switch ($Strategy) {
        "Cost"    {
            # Eligible: only models with a finite estimable cost (> 0). Models
            # with infinite costScore (prices not configured / estimate failed) are
            # excluded, so they do not "win" due to missing data as happened before.
            $eligible = @($candidates | Where-Object { $_.CostScore -ne [double]::PositiveInfinity })
            # Cost summary: one INFO line for each eligible model, sorted from
            # cheapest, BEFORE the final choice. It makes the decision transparent
            # and verifiable (you see the estimated cost of each, not just the winner).
            if ($eligible.Count -gt 0) {
                $sizeLbl = if ($EffectiveSize) { $EffectiveSize } else { "n/d" }
                $qLbl = if ($EffectiveQuality) { $EffectiveQuality } else { "n/d" }
                Write-Log (T 'auto.cost_breakdown_header' $qLbl $sizeLbl) -Level INFO
                foreach ($cand in ($eligible | Sort-Object CostScore)) {
                    $costFmt = "{0:N4}" -f $cand.CostScore
                    Write-Log (T 'auto.cost_breakdown_line' $cand.Name $costFmt) -Level INFO
                }
            }
            if ($eligible.Count -eq 0) {
                Write-Log (T 'auto.cost_no_eligible') -Level WARN
                $defModel = [string]$Config.defaultModel
                $fallback = $candidates | Where-Object { $_.Name -eq $defModel } | Select-Object -First 1
                if (-not $fallback) { $fallback = $candidates | Select-Object -First 1 }
                $best = $fallback
            } else {
                $best = $eligible | Sort-Object CostScore | Select-Object -First 1
            }
        }
        "Quality" {
            $eligible = @($candidates | Where-Object { $_.QualityRating -gt 0 })
            if ($eligible.Count -eq 0) {
                Write-Log (T 'auto.quality_no_eligible') -Level WARN
                $defModel = [string]$Config.defaultModel
                $fallback = $candidates | Where-Object { $_.Name -eq $defModel } | Select-Object -First 1
                if (-not $fallback) { $fallback = $candidates | Select-Object -First 1 }
                $best = $fallback
            } else {
                # Base score: Arena (higher=better). If gallery votes are available
                # with at least $voteThreshold votes for a model, I combine them with the
                # Arena score in a WEIGHTED AVERAGE. The two scales are different (Arena ~900-1400,
                # votes 1-5), so I normalize both to 0-1 relative to the eligible
                # candidates, then weight. The weight of the votes grows with the number of votes (more
                # votes = more confidence), with a cap at 60% so as never to zero out Arena.
                $arenaValues = @($eligible | ForEach-Object { $_.QualityRating })
                $arenaMin = ($arenaValues | Measure-Object -Minimum).Minimum
                $arenaMax = ($arenaValues | Measure-Object -Maximum).Maximum
                $arenaSpan = $arenaMax - $arenaMin
                $anyVotes = $false
                foreach ($c in $eligible) {
                    # Arena normalized 0-1 (if all equal, 1.0)
                    $arenaNorm = if ($arenaSpan -gt 0) { ($c.QualityRating - $arenaMin) / $arenaSpan } else { 1.0 }
                    if ($c.VoteCount -ge $voteThreshold) {
                        $anyVotes = $true
                        $voteNorm = $c.VoteAvg / 5.0   # voti su scala 1-5 -> 0-1
                        # Vote weight: 0.30 at the threshold, rises toward 0.60 with more votes.
                        $wVote = [math]::Min(0.60, 0.30 + ($c.VoteCount - $voteThreshold) * 0.03)
                        $combined = $wVote * $voteNorm + (1 - $wVote) * $arenaNorm
                    } else {
                        # Below threshold: I use Arena only (as before).
                        $combined = $arenaNorm
                    }
                    $c | Add-Member -NotePropertyName CombinedScore -NotePropertyValue $combined -Force
                }
                if ($anyVotes) {
                    Write-Log (T 'auto.quality_with_votes' $voteThreshold) -Level INFO
                    $best = $eligible | Sort-Object CombinedScore -Descending | Select-Object -First 1
                } else {
                    # No model has enough votes: classic behavior (Arena only).
                    # If however the votes file had been loaded (galleryRatings present),
                    # it means there are votes but below the threshold: I report it with an INFO,
                    # indicating the maximum number of votes found (feedback requested).
                    if ($galleryRatings) {
                        $maxVoteCand = $candidates | Sort-Object VoteCount -Descending | Select-Object -First 1
                        $maxVotes = if ($maxVoteCand) { [int]$maxVoteCand.VoteCount } else { 0 }
                        $maxVoteName = if ($maxVoteCand) { [string]$maxVoteCand.Name } else { "n/a" }
                        Write-Log (T 'auto.ratings_below_threshold' $voteThreshold $maxVotes $maxVoteName) -Level INFO
                    }
                    $best = $eligible | Sort-Object QualityRating -Descending | Select-Object -First 1
                }
            }
        }
        "Time" {
            $eligible = @($candidates | Where-Object { $_.SpeedRating -gt 0 })
            if ($eligible.Count -eq 0) {
                Write-Log (T 'auto.time_no_eligible') -Level WARN
                $defModel = [string]$Config.defaultModel
                $fallback = $candidates | Where-Object { $_.Name -eq $defModel } | Select-Object -First 1
                if (-not $fallback) { $fallback = $candidates | Select-Object -First 1 }
                $best = $fallback
            } else {
                # Lower = better (lower median in seconds = faster)
                $best = $eligible | Sort-Object SpeedRating | Select-Object -First 1
            }
        }
    }

    # Log the rationale: which strategy, which score, any required features
    $scoreInfo = switch ($Strategy) {
        "Cost"    {
            $costRounded = if ($best.CostScore -eq [double]::PositiveInfinity) { "n/d" } else { ("{0:N4}" -f $best.CostScore) }
            $sizeInfo = if ($EffectiveSize) { $EffectiveSize } else { "n/d" }
            $qInfo = if ($EffectiveQuality) { $EffectiveQuality } else { "n/d" }
            "costo stimato=$costRounded USD per 1 img ($qInfo, $sizeInfo)"
        }
        "Quality" { "qualityRating=$([math]::Round($best.QualityRating, 0)) (arena score)" }
        "Time"    { "speedRating=$([math]::Round($best.SpeedRating, 1))s (median, lower=faster)" }
    }
    $featuresMsg = @()
    if ($NeedsInpainting)    { $featuresMsg += "inpainting" }
    if ($NeedsInputFidelity) { $featuresMsg += "input_fidelity" }
    if ($NeedsBackground)    { $featuresMsg += "background" }
    $featuresStr = if ($featuresMsg.Count -gt 0) { " (supporta: $($featuresMsg -join ', '))" } else { "" }
    Write-Log (T 'auto.selected' $Strategy ($best.Name) $scoreInfo $featuresStr)
    return $best.Name
}

function Test-ImageFileSignature {
    <#
    Verifies that a file is REALLY an image of the expected format, by reading the first
    bytes ("magic number"). It protects against the case where a file with a .jpg/.png extension is
    actually something else (a renamed .txt, a corrupted/truncated file, an error HTML
    saved by mistake): the API would reject the file with a cryptic error, here instead
    we intercept it immediately with a clear message.
    NB: defined HERE (before the validation block that uses it) because PowerShell
    runs the script top-down: a function must already be known at the time of the call.

    Firme riconosciute:
      PNG  : 89 50 4E 47 0D 0A 1A 0A
      JPEG : FF D8 FF
      WEBP : "RIFF"...."WEBP"  (RIFF container con fourcc WEBP all'offset 8)
      GIF  : "GIF87a" / "GIF89a"
      BMP  : "BM"
    Returns an object with .IsValid (bool) and .DetectedType (string or $null).
    #>
    param([Parameter(Mandatory=$true)][string]$Path)

    $result = [PSCustomObject]@{ IsValid = $false; DetectedType = $null }
    try {
        $fs = [System.IO.File]::OpenRead($Path)
        try {
            $buf = New-Object byte[] 12
            $read = $fs.Read($buf, 0, 12)
        } finally {
            $fs.Dispose()
        }
        if ($read -lt 3) { return $result }   # file troppo corto per qualsiasi immagine

        # PNG
        if ($read -ge 8 -and $buf[0] -eq 0x89 -and $buf[1] -eq 0x50 -and $buf[2] -eq 0x4E -and
            $buf[3] -eq 0x47 -and $buf[4] -eq 0x0D -and $buf[5] -eq 0x0A -and $buf[6] -eq 0x1A -and $buf[7] -eq 0x0A) {
            $result.IsValid = $true; $result.DetectedType = "png"; return $result
        }
        # JPEG
        if ($buf[0] -eq 0xFF -and $buf[1] -eq 0xD8 -and $buf[2] -eq 0xFF) {
            $result.IsValid = $true; $result.DetectedType = "jpeg"; return $result
        }
        # WEBP: "RIFF" (0..3) + "WEBP" (8..11)
        if ($read -ge 12 -and $buf[0] -eq 0x52 -and $buf[1] -eq 0x49 -and $buf[2] -eq 0x46 -and $buf[3] -eq 0x46 -and
            $buf[8] -eq 0x57 -and $buf[9] -eq 0x45 -and $buf[10] -eq 0x42 -and $buf[11] -eq 0x50) {
            $result.IsValid = $true; $result.DetectedType = "webp"; return $result
        }
        # GIF: "GIF8"
        if ($read -ge 4 -and $buf[0] -eq 0x47 -and $buf[1] -eq 0x49 -and $buf[2] -eq 0x46 -and $buf[3] -eq 0x38) {
            $result.IsValid = $true; $result.DetectedType = "gif"; return $result
        }
        # BMP: "BM"
        if ($buf[0] -eq 0x42 -and $buf[1] -eq 0x4D) {
            $result.IsValid = $true; $result.DetectedType = "bmp"; return $result
        }
        return $result
    }
    catch {
        # Se non riesco a leggere il file, non blocco qui: il controllo di esistenza e
        # the subsequent phases will handle the error. I return "not valid" without an exception.
        return $result
    }
}

function Get-DownscaledSize {
    <#
    Given a model's operationalParams object and a size "WxH", computes the
    closest VALID size (<= requested) that the model accepts, preserving the aspect
    ratio as much as possible. Used for the auto-recovery: if the API rejects a size
    that is too large, instead of failing we retry with this reduced size.

    Two families of constraints (from the .conf):
      - allowedSizes (closed list, e.g. gpt-image-1.5): I choose from the list the size with
        the closest aspect ratio and area <= requested (on a tie, the larger area).
      - geometric constraints (maxArea/maxSide/sizeDivisibleBy, e.g. MAI/gpt-image-2):
        I proportionally reduce W and H until they fit within maxArea and maxSide,
        rounding to sizeDivisibleBy if required.

    Returns the new size "WxH" (string), or $null if it is not possible to reduce
    (size already valid, or no applicable constraint, or "auto").
    #>
    param($OpParams, [string]$Size)

    if (-not $OpParams -or [string]::IsNullOrWhiteSpace($Size) -or $Size -ieq "auto") { return $null }
    if ($Size -notmatch '^\s*(\d+)\s*[xX]\s*(\d+)\s*$') { return $null }
    $w = [int]$Matches[1]; $h = [int]$Matches[2]
    if ($w -le 0 -or $h -le 0) { return $null }
    $ar = $w / [double]$h

    function _prop($obj, [string]$name, $default) {
        if ($obj -and ($obj.PSObject.Properties.Name -contains $name) -and $null -ne $obj.$name) { return $obj.$name }
        return $default
    }

    # --- Family A: closed list of sizes ---
    $allowed = @(_prop $OpParams 'allowedSizes' @())
    $allowedWh = @($allowed | Where-Object { $_ -match '^\d+x\d+$' })
    if ($allowedWh.Count -gt 0) {
        # Candidates with area <= requested; I choose the one with the closest aspect ratio,
        # and on a tie the larger area (maximum compatible quality).
        $reqArea = $w * $h
        $best = $null; $bestArDiff = [double]::MaxValue; $bestArea = -1
        foreach ($s in $allowedWh) {
            $p = $s -split 'x'; $cw = [int]$p[0]; $ch = [int]$p[1]
            $cArea = $cw * $ch
            if ($cArea -gt $reqArea) { continue }
            $cAr = $cw / [double]$ch
            $arDiff = [math]::Abs($cAr - $ar)
            if ($arDiff -lt $bestArDiff - 0.0001 -or ($arDiff -le $bestArDiff + 0.0001 -and $cArea -gt $bestArea)) {
                $best = "$($cw)x$($ch)"; $bestArDiff = $arDiff; $bestArea = $cArea
            }
        }
        # If no candidate is <= requested (request smaller than all), I take
        # the smallest in the list with the closest AR.
        if (-not $best) {
            $bestArDiff = [double]::MaxValue; $bestArea = [int]::MaxValue
            foreach ($s in $allowedWh) {
                $p = $s -split 'x'; $cw = [int]$p[0]; $ch = [int]$p[1]
                $cAr = $cw / [double]$ch; $arDiff = [math]::Abs($cAr - $ar); $cArea = $cw * $ch
                if ($arDiff -lt $bestArDiff - 0.0001 -or ($arDiff -le $bestArDiff + 0.0001 -and $cArea -lt $bestArea)) {
                    $best = "$($cw)x$($ch)"; $bestArDiff = $arDiff; $bestArea = $cArea
                }
            }
        }
        if ($best -and $best -ine $Size) { return $best }
        return $null
    }

    # --- Family B: geometric constraints ---
    $maxArea = [int](_prop $OpParams 'maxArea' 0)
    $maxSide = [int](_prop $OpParams 'maxSide' 0)
    $minSide = [int](_prop $OpParams 'minSide' 0)
    $divBy   = [int](_prop $OpParams 'sizeDivisibleBy' 0)
    $nw = $w; $nh = $h
    $changed = $false

    # 1. I reduce for maxSide (long side within the limit, preserving AR).
    if ($maxSide -gt 0 -and ([math]::Max($nw, $nh) -gt $maxSide)) {
        $scale = $maxSide / [double]([math]::Max($nw, $nh))
        $nw = [int][math]::Floor($nw * $scale); $nh = [int][math]::Floor($nh * $scale); $changed = $true
    }
    # 2. I reduce for maxArea (area within the limit, preserving AR).
    if ($maxArea -gt 0 -and (($nw * $nh) -gt $maxArea)) {
        $scale = [math]::Sqrt($maxArea / [double]($nw * $nh))
        $nw = [int][math]::Floor($nw * $scale); $nh = [int][math]::Floor($nh * $scale); $changed = $true
    }
    if (-not $changed) { return $null }
    # 3. I round to sizeDivisibleBy (down, so as not to exceed the limits again).
    if ($divBy -gt 0) {
        $nw = [int]([math]::Floor($nw / [double]$divBy) * $divBy)
        $nh = [int]([math]::Floor($nh / [double]$divBy) * $divBy)
    }
    if ($nw -lt 1 -or $nh -lt 1) { return $null }
    # 4. minSide compliance: if after the reduction a side dropped below the minimum, the
    # size is not realizable for this AR (maxArea+minSide constraints incompatible with
    # the requested aspect ratio). I return $null: the auto-recovery will stop with an error
    # chiaro invece di insistere con una size comunque invalida.
    if ($minSide -gt 0 -and ([math]::Min($nw, $nh) -lt $minSide)) { return $null }
    $newSize = "$($nw)x$($nh)"
    if ($newSize -ieq $Size) { return $null }
    return $newSize
}

function Invoke-PreemptiveSizeDownscale {
    <#
    PREEMPTIVE downscaling of the size, to be called BEFORE the declarative validation
    and the API call. If the requested size does not respect the model's operationalParams
    constraints (closed list or geometric constraints), it tries to reduce it to the closest
    valid value with Get-DownscaledSize. Logic unified with the post-API auto-recovery:
    this way a size that is too large does NOT make the script fail, but is reduced and we proceed.

    Philosophy (agreed): downscaling is the PRIMARY behavior. The blocking
    validation steps in only if reducing is impossible (e.g. aspect ratio not realizable
    for that model), returning $null below and leaving it to the validation to
    give the error message.

    Returns the NEW size (string "WxH") if it reduced, or $null if reducing was not
    needed (size already valid) or was not possible. The caller, if it receives a value,
    replaces $Size and logs the WARN; if it receives $null, it continues with the original size
    (the validation will decide whether it is valid or not).

    NB: uses Test-ModelOperationalParams to understand whether the current size is ALREADY valid
    (in which case it touches nothing), avoiding useless downscaling on legitimate sizes.
    #>
    param($OpParams, [string]$ModelName, [string]$Size)

    if (-not $OpParams -or [string]::IsNullOrWhiteSpace($Size) -or $Size -ieq "auto") { return $null }

    # Is the current size already valid? If the validation reports no size errors,
    # there is nothing to reduce.
    $check = Test-ModelOperationalParams -OpParams $OpParams -ModelName $ModelName -Size $Size
    $hasSizeError = $false
    foreach ($msg in $check.Messages) {
        if ($msg.Level -eq 'ERROR' -and ($msg.Key -like 'opparams.size*')) { $hasSizeError = $true; break }
    }
    if (-not $hasSizeError) { return $null }

    # Invalid size: I try to reduce it.
    return (Get-DownscaledSize -OpParams $OpParams -Size $Size)
}

function Test-ModelOperationalParams {
    <#
    Validates the operational parameters requested by the user (NImages, Size, Quality,
    Format, number of reference images) against the limits declared in the
    "operationalParams" block of the model in the .conf, BEFORE calling the API. This way
    we intercept the errors with a clear and localized message, instead of leaving
    the API to fail with a cryptic error (or worse, to consume credits).

    Philosophy (agreed):
      - CERTAIN limits  (*Enforce field = true)  -> blocking ERROR (the script exits).
      - UNCERTAIN limits (*Enforce field = false) -> WARN: we warn but continue,
        because the model's real limit might differ and we do not want to block
        wrongly. The API remains the final authority.

    The limits live in the .conf (model's operationalParams), so they are updatable
    without touching the code. If a model does NOT have operationalParams, the function
    imposes nothing (backward compatibility: the historical hardcoded constraints remain active).

    operationalParams schema (all fields optional):
      maxImages, maxImagesEnforce
      allowedSizes (array "WxH"/"auto"), allowedSizesEnforce
      minSide, maxSide, maxArea, sizeRulesEnforce
      maxReferenceImages, maxReferenceImagesEnforce
      allowedQuality (array), allowedQualityEnforce
      allowedFormat (array), allowedFormatEnforce

    Parameters:
      -OpParams:    the model's operationalParams object (can be $null)
      -ModelName:   logical model name (for the messages)
      -NImages, -Size, -Quality, -Format: parameters requested by the user
      -ReferenceCount: number of reference images passed (edit), default 0

    Ritorna [PSCustomObject]:
      HasError = $true se almeno un limite CERTO e' violato
      Messages = lista di { Key; Args; Level } pronti per il log (ERROR o WARN)
    #>
    param(
        $OpParams,
        [string]$ModelName,
        [int]$NImages = 1,
        [string]$Size = "",
        [string]$Quality = "",
        [string]$Format = "",
        [int]$ReferenceCount = 0
    )

    $result = [PSCustomObject]@{
        HasError = $false
        Messages = @()
    }

    # No operationalParams block: I impose nothing (the historical hardcoded constraints
    # remain active elsewhere). Backward compatibility with .conf lacking the block.
    if (-not $OpParams) { return $result }

    # Helper to read a property safely (it may not exist in the .conf).
    function _prop($obj, [string]$name, $default) {
        if ($obj -and ($obj.PSObject.Properties.Name -contains $name) -and $null -ne $obj.$name) {
            return $obj.$name
        }
        return $default
    }

    # ---- 1) Number of images per request ----
    $maxImages = [int](_prop $OpParams 'maxImages' 0)
    if ($maxImages -gt 0 -and $NImages -gt $maxImages) {
        $enforce = [bool](_prop $OpParams 'maxImagesEnforce' $true)
        if ($enforce) {
            $result.HasError = $true
            $result.Messages += [PSCustomObject]@{ Key = 'opparams.max_images_error'; Args = @($ModelName, [string]$NImages, [string]$maxImages); Level = 'ERROR' }
        } else {
            $result.Messages += [PSCustomObject]@{ Key = 'opparams.max_images_warn'; Args = @($ModelName, [string]$NImages, [string]$maxImages); Level = 'WARN' }
        }
    }

    # ---- 2) Size: closed list of allowed dimensions ----
    $allowedSizes = @(_prop $OpParams 'allowedSizes' @())
    if ($allowedSizes.Count -gt 0 -and $Size -and $Size.Trim() -ne "") {
        # confronto case-insensitive e tollerante a spazi
        $sizeNorm = $Size.Trim().ToLower()
        $allowedNorm = $allowedSizes | ForEach-Object { ([string]$_).Trim().ToLower() }
        if ($allowedNorm -notcontains $sizeNorm) {
            $enforce = [bool](_prop $OpParams 'allowedSizesEnforce' $true)
            $sizesStr = ($allowedSizes -join ", ")
            if ($enforce) {
                $result.HasError = $true
                $result.Messages += [PSCustomObject]@{ Key = 'opparams.size_not_allowed_error'; Args = @($ModelName, $Size, $sizesStr); Level = 'ERROR' }
            } else {
                $result.Messages += [PSCustomObject]@{ Key = 'opparams.size_not_allowed_warn'; Args = @($ModelName, $Size, $sizesStr); Level = 'WARN' }
            }
        }
    }

    # ---- 3) Size: numeric rules (min/max side, max area) ----
    $sizeRulesEnforce = [bool](_prop $OpParams 'sizeRulesEnforce' $false)
    $minSide = [int](_prop $OpParams 'minSide' 0)
    $maxSide = [int](_prop $OpParams 'maxSide' 0)
    $maxArea = [int](_prop $OpParams 'maxArea' 0)
    $divBy   = [int](_prop $OpParams 'sizeDivisibleBy' 0)
    $arMin   = [double](_prop $OpParams 'aspectRatioMin' 0.0)
    $arMax   = [double](_prop $OpParams 'aspectRatioMax' 0.0)
    if ($Size -match '^\s*(\d+)\s*[xX]\s*(\d+)\s*$') {
        $w = [int]$Matches[1]; $h = [int]$Matches[2]
        $violations = @()
        if ($minSide -gt 0 -and ($w -lt $minSide -or $h -lt $minSide)) {
            $violations += (T 'opparams.rule_min_side' $minSide)
        }
        if ($maxSide -gt 0 -and ($w -gt $maxSide -or $h -gt $maxSide)) {
            $violations += (T 'opparams.rule_max_side' $maxSide)
        }
        if ($maxArea -gt 0 -and (($w * $h) -gt $maxArea)) {
            $violations += (T 'opparams.rule_max_area' $maxArea)
        }
        # Divisibility: some models (gpt-image-2) require sides that are multiples of N (16).
        if ($divBy -gt 0 -and (($w % $divBy) -ne 0 -or ($h % $divBy) -ne 0)) {
            $violations += (T 'opparams.rule_divisible' $divBy)
        }
        # Aspect ratio range (e.g. gpt-image-2 accepts between 1:3 and 3:1).
        if ($arMin -gt 0 -and $arMax -gt 0 -and $h -gt 0) {
            $ar = $w / [double]$h
            if ($ar -lt $arMin -or $ar -gt $arMax) {
                $violations += (T 'opparams.rule_aspect' (Format-DisplayNumber $arMin 2) (Format-DisplayNumber $arMax 2))
            }
        }
        if ($violations.Count -gt 0) {
            $vStr = ($violations -join "; ")
            if ($sizeRulesEnforce) {
                $result.HasError = $true
                $result.Messages += [PSCustomObject]@{ Key = 'opparams.size_rules_error'; Args = @($ModelName, $Size, $vStr); Level = 'ERROR' }
            } else {
                $result.Messages += [PSCustomObject]@{ Key = 'opparams.size_rules_warn'; Args = @($ModelName, $Size, $vStr); Level = 'WARN' }
            }
        }
    }

    # ---- 4) Reference images (edit) ----
    $maxRef = [int](_prop $OpParams 'maxReferenceImages' -1)
    if ($maxRef -ge 0 -and $ReferenceCount -gt $maxRef) {
        $enforce = [bool](_prop $OpParams 'maxReferenceImagesEnforce' $true)
        if ($enforce) {
            $result.HasError = $true
            $result.Messages += [PSCustomObject]@{ Key = 'opparams.max_ref_error'; Args = @($ModelName, [string]$ReferenceCount, [string]$maxRef); Level = 'ERROR' }
        } else {
            $result.Messages += [PSCustomObject]@{ Key = 'opparams.max_ref_warn'; Args = @($ModelName, [string]$ReferenceCount, [string]$maxRef); Level = 'WARN' }
        }
    }

    # ---- 5) Quality: closed list ----
    $allowedQuality = @(_prop $OpParams 'allowedQuality' @())
    if ($allowedQuality.Count -gt 0 -and $Quality -and $Quality.Trim() -ne "") {
        $qNorm = $Quality.Trim().ToLower()
        $allowedQNorm = $allowedQuality | ForEach-Object { ([string]$_).Trim().ToLower() }
        if ($allowedQNorm -notcontains $qNorm) {
            $enforce = [bool](_prop $OpParams 'allowedQualityEnforce' $true)
            $qStr = ($allowedQuality -join ", ")
            if ($enforce) {
                $result.HasError = $true
                $result.Messages += [PSCustomObject]@{ Key = 'opparams.quality_not_allowed_error'; Args = @($ModelName, $Quality, $qStr); Level = 'ERROR' }
            } else {
                $result.Messages += [PSCustomObject]@{ Key = 'opparams.quality_not_allowed_warn'; Args = @($ModelName, $Quality, $qStr); Level = 'WARN' }
            }
        }
    }

    # ---- 6) Format: closed list ----
    $allowedFormat = @(_prop $OpParams 'allowedFormat' @())
    if ($allowedFormat.Count -gt 0 -and $Format -and $Format.Trim() -ne "") {
        $fNorm = $Format.Trim().ToLower()
        $allowedFNorm = $allowedFormat | ForEach-Object { ([string]$_).Trim().ToLower() }
        if ($allowedFNorm -notcontains $fNorm) {
            $enforce = [bool](_prop $OpParams 'allowedFormatEnforce' $true)
            $fStr = ($allowedFormat -join ", ")
            if ($enforce) {
                $result.HasError = $true
                $result.Messages += [PSCustomObject]@{ Key = 'opparams.format_not_allowed_error'; Args = @($ModelName, $Format, $fStr); Level = 'ERROR' }
            } else {
                $result.Messages += [PSCustomObject]@{ Key = 'opparams.format_not_allowed_warn'; Args = @($ModelName, $Format, $fStr); Level = 'WARN' }
            }
        }
    }

    return $result
}

# Builds the output file name from the template (timestamp/index/promptHash) and sanitizes it of invalid characters.
function Get-OutputFileName {
    param(
        [string]$Template,
        [string]$Timestamp,
        [int]$Index,
        [string]$Hash,
        [string]$Extension
    )
    $name = $Template.Replace("{timestamp}", $Timestamp).
                      Replace("{index}",     $Index).
                      Replace("{promptHash}",$Hash) + ".$Extension"
    # Sanitizzazione difensiva: rimuovo i caratteri non validi nei nomi file su Windows
    # (< > : " / \ | ? * e i caratteri di controllo). Se il template nel .conf o un
    # substituted value contained one of these, the save would fail with a
    # cryptic error; here we replace them with "_" to ensure an always-valid name.
    $invalid = [System.IO.Path]::GetInvalidFileNameChars()
    $sb = [System.Text.StringBuilder]::new()
    foreach ($ch in $name.ToCharArray()) {
        if ($invalid -contains $ch) { [void]$sb.Append('_') }
        else { [void]$sb.Append($ch) }
    }
    return $sb.ToString()
}

function ConvertFrom-ApiError {
    param([string]$ErrorMessage)

    # The matches are ordered from the most specific to the most generic to avoid
    # mismatches (e.g. "429" matching "12:25:29" or "0.429"). We use an explicit
    # "HTTP NNN" when possible to minimize false positives.

    # Robust extraction of the API message: if the error text contains a
    # JSON body, I parse it and read .error.message (or .message). It is more reliable
    # than the regex, which stops at the first quote and truncates messages with
    # internal quotes; the regex remains as a fallback in the individual branches below.
    $apiMsg = $null
    if ($ErrorMessage -match '(?s)\{.*\}') {
        try {
            $parsedErr = $Matches[0] | ConvertFrom-Json -ErrorAction Stop
            if (($parsedErr.PSObject.Properties.Name -contains 'error') -and $parsedErr.error -and $parsedErr.error.message) {
                $apiMsg = [string]$parsedErr.error.message
            }
            elseif (($parsedErr.PSObject.Properties.Name -contains 'message') -and $parsedErr.message) {
                $apiMsg = [string]$parsedErr.message
            }
        }
        catch { $apiMsg = $null }
    }

    if ($ErrorMessage -match "^TIMEOUT") {
        return T 'apierr.timeout'
    }
    elseif ($ErrorMessage -match "Null response|connection interrupted") {
        return T 'apierr.connection_interrupted'
    }
    elseif ($ErrorMessage -match "Connection error") {
        return $ErrorMessage   # gia' descrittivo, lo passo intero
    }
    elseif ($ErrorMessage -match 'HTTP 429|TooManyRequests|rate.?limit') {
        return T 'apierr.rate_limit'
    }
    elseif ($ErrorMessage -match 'safety system|safety_violations|content[_ ]filter|content[_ ]policy|ResponsibleAIPolicy|jailbreak|rejected by the safety') {
        # Rifiuto per policy di sicurezza/contenuti (Azure content safety). NON e' un
        # parameter error: it is the request content that is being blocked.
        # I try to extract the specific API message; otherwise I use the generic one.
        if ($apiMsg) { return T 'apierr.safety_rejected_with_msg' $apiMsg }
        if ($ErrorMessage -match '"message"\s*:\s*"([^"]+)"') {
            return T 'apierr.safety_rejected_with_msg' $Matches[1]
        }
        return T 'apierr.safety_rejected_generic'
    }
    elseif ($ErrorMessage -match 'image_generation_user_error') {
        # I extract the specific message from the API JSON response if possible
        if ($apiMsg) { return T 'apierr.user_error_with_msg' $apiMsg }
        if ($ErrorMessage -match '"message"\s*:\s*"([^"]+)"') {
            return T 'apierr.user_error_with_msg' $Matches[1]
        }
        return T 'apierr.user_error_generic'
    }
    elseif ($ErrorMessage -match 'HTTP 400|BadRequest') {
        # I try to extract the API message to give useful information
        if ($apiMsg) { return T 'apierr.http400_with_msg' $apiMsg }
        if ($ErrorMessage -match '"message"\s*:\s*"([^"]+)"') {
            return T 'apierr.http400_with_msg' $Matches[1]
        }
        return T 'apierr.http400_generic'
    }
    elseif ($ErrorMessage -match 'HTTP 401|Unauthorized') {
        return T 'apierr.http401'
    }
    elseif ($ErrorMessage -match 'HTTP 403|Forbidden') {
        return T 'apierr.http403'
    }
    elseif ($ErrorMessage -match 'HTTP 404|NotFound') {
        return T 'apierr.http404'
    }
    elseif ($ErrorMessage -match 'HTTP 422|Unprocessable') {
        return T 'apierr.http422'
    }
    elseif ($ErrorMessage -match 'HTTP 500|InternalServerError') {
        return T 'apierr.http500'
    }
    elseif ($ErrorMessage -match 'HTTP 503|ServiceUnavailable') {
        return T 'apierr.http503'
    }
    else {
        return T 'apierr.unknown' $ErrorMessage
    }
}

# Validates an input image, converts it to RGB and resizes it within the model's limits before sending.
# Detects (once per run) the image tool available on the
# current platform: 'drawing' on Windows (System.Drawing), 'sips' on macOS
# (preinstalled in the system), 'magick' or 'convert' on Linux if ImageMagick is
# present, 'none' otherwise. Returns an object { Kind; Bin }.
function Get-ImageCliTool {
    if ($script:ImageCliTool) { return $script:ImageCliTool }
    $info = [pscustomobject]@{ Kind = 'none'; Bin = $null }
    if ($script:IsWin) {
        $info.Kind = 'drawing'
    }
    elseif ($script:IsMac -and (Get-Command sips -ErrorAction SilentlyContinue)) {
        $info.Kind = 'sips'; $info.Bin = 'sips'
    }
    elseif (Get-Command magick -ErrorAction SilentlyContinue) {
        $info.Kind = 'magick'; $info.Bin = 'magick'
    }
    elseif (Get-Command convert -ErrorAction SilentlyContinue) {
        $info.Kind = 'convert'; $info.Bin = 'convert'
    }
    $script:ImageCliTool = $info
    return $info
}

# Reads the width and height of an image via the available CLI tool
# (sips or ImageMagick). Returns an object { Width; Height } or $null on failure.
function Get-ImageDimensionsCli {
    param([string]$ImagePath, $Tool)
    try {
        if ($Tool.Kind -eq 'sips') {
            $out = & sips -g pixelWidth -g pixelHeight $ImagePath 2>$null
            $w = $null; $h = $null
            foreach ($line in @($out)) {
                if ($line -match 'pixelWidth:\s*(\d+)')  { $w = [int]$Matches[1] }
                if ($line -match 'pixelHeight:\s*(\d+)') { $h = [int]$Matches[1] }
            }
            if ($w -and $h) { return [pscustomobject]@{ Width = $w; Height = $h } }
        }
        else {
            $bin = if ($Tool.Kind -eq 'magick') { 'magick' } else { 'identify' }
            $args2 = if ($Tool.Kind -eq 'magick') { @('identify','-format','%w %h',$ImagePath) } else { @('-format','%w %h',$ImagePath) }
            $out = & $bin @args2 2>$null
            if ($LASTEXITCODE -eq 0 -and ([string]$out) -match '(\d+)\s+(\d+)') {
                return [pscustomobject]@{ Width = [int]$Matches[1]; Height = [int]$Matches[2] }
            }
        }
    } catch { }
    return $null
}

function ConvertTo-ValidImage {
    param(
        [string]$ImagePath,
        [int]$MaxDimension = 4096,
        [int]$MaxArea = 0      # se > 0, l'immagine viene scalata anche per rispettare quest'area max
    )

    # Cross-platform: System.Drawing.Common funziona solo su Windows nelle versioni
    # recenti di .NET. Su macOS uso sips (preinstallato), su Linux ImageMagick se
    # present; only in the absence of ANY tool do I throw the controlled error.
    if (-not $script:IsWin) {
        $cliTool = Get-ImageCliTool
        if ($cliTool.Kind -eq 'none') {
            Write-Log (T 'image.no_image_tool') -Level ERROR
            exit 1
        }

        if (-not (Test-Path $ImagePath)) {
            Write-Log (T 'image.file_not_found' $ImagePath) -Level ERROR
            exit 1
        }
        $cliInfo   = Get-Item $ImagePath
        $cliSizeMB = [math]::Round($cliInfo.Length / 1MB, 2)
        if ($cliSizeMB -ge 20) {
            Write-Log (T 'image.too_large' ($cliInfo.Name) $cliSizeMB) -Level ERROR
            exit 1
        }
        if (-not (Test-ImageFileSignature -ImagePath $ImagePath)) {
            Write-Log (T 'image.invalid_signature' ($cliInfo.Name)) -Level ERROR
            exit 1
        }

        $dims = Get-ImageDimensionsCli -ImagePath $ImagePath -Tool $cliTool
        if (-not $dims) {
            Write-Log (T 'image.conversion_failed' ($cliInfo.Name) "dimension read failed") -Level ERROR
            exit 1
        }

        # Same scaling math as the System.Drawing path: I respect both the
        # maximum side and, if requested, the model's maximum area.
        $scale = 1.0
        $maxSide = [Math]::Max($dims.Width, $dims.Height)
        if ($maxSide -gt $MaxDimension) { $scale = $MaxDimension / $maxSide }
        if ($MaxArea -gt 0) {
            $areaScaled = $dims.Width * $dims.Height * $scale * $scale
            if ($areaScaled -gt $MaxArea) {
                $scale = [Math]::Min($scale, [Math]::Sqrt($MaxArea / ($dims.Width * $dims.Height)))
            }
        }
        $tw = [Math]::Max(1, [int][Math]::Floor($dims.Width  * $scale))
        $th = [Math]::Max(1, [int][Math]::Floor($dims.Height * $scale))

        $cliTempPath = Join-Path ([System.IO.Path]::GetTempPath()) ("gptimg_validated_" + [Guid]::NewGuid().ToString('N') + ".png")
        if ($cliTool.Kind -eq 'sips') {
            if ($scale -lt 1.0) { & sips -s format png -z $th $tw $ImagePath --out $cliTempPath 2>$null | Out-Null }
            else                { & sips -s format png $ImagePath --out $cliTempPath 2>$null | Out-Null }
        }
        else {
            $bin = $cliTool.Bin
            if ($scale -lt 1.0) { & $bin $ImagePath -resize ("{0}x{1}!" -f $tw, $th) $cliTempPath 2>$null | Out-Null }
            else                { & $bin $ImagePath $cliTempPath 2>$null | Out-Null }
        }
        if ($LASTEXITCODE -ne 0 -or -not (Test-Path $cliTempPath)) {
            Write-Log (T 'image.conversion_failed' ($cliInfo.Name) ("tool " + $cliTool.Kind + " failed")) -Level ERROR
            exit 1
        }
        $script:TempFilesToCleanup += $cliTempPath
        $cliOutMB = [math]::Round((Get-Item $cliTempPath).Length / 1MB, 2)
        if ($cliOutMB -ge 20) { Write-Log (T 'image.png_large' $cliOutMB) -Level WARN }
        return $cliTempPath
    }

    Add-Type -AssemblyName System.Drawing

    if (-not (Test-Path $ImagePath)) {
        Write-Log (T 'image.file_not_found' $ImagePath) -Level ERROR
        exit 1
    }

    $fileInfo   = Get-Item $ImagePath
    $fileSizeMB = [math]::Round($fileInfo.Length / 1MB, 2)

    # Foundry rejects input images larger than 20 MB on the /images/edits endpoint
    # (documented limit, verified 2026-05). We fail early to give a clear
    # message to the user, instead of letting the API call return an opaque error.
    if ($fileSizeMB -ge 20) {
        Write-Log (T 'image.too_large' ($fileInfo.Name) $fileSizeMB) -Level ERROR
        exit 1
    }

    $image      = $null
    $memStream  = $null
    $newBitmap  = $null
    $graphics   = $null

    try {
        $imageBytes = [System.IO.File]::ReadAllBytes($ImagePath)
        $memStream  = [System.IO.MemoryStream]::new($imageBytes)

        # System.Drawing/libjpeg writes diagnostic messages (e.g. "Corrupt JPEG data:
        # 1 extraneous bytes before marker 0xd2") DIRECTLY to file descriptor 2
        # at the OS level, bypassing .NET's [Console]::Error layer and also SetStdHandle
        # via P/Invoke (libgdiplus caches the internal handle).
        #
        # Robust solution (Windows): I do a JPEG pre-check via an isolated PowerShell
        # sub-process, redirecting stderr to a file. If libjpeg complains
        # about something, I relog it as a formal [WARN]. Then I load the image in the main
        # process (where the message can still appear, but the pre-check already tells us
        # there is a problem).
        #
        # Alternative trick that works better: the sub-process runs Image.FromFile +
        # save as a clean PNG to a temporary file. Then we load THE
        # CLEAN FILE, which no longer causes libjpeg warnings.

        $needsPreflight = ($script:IsWin -and $ImagePath -match '\.jpe?g$')
        $cleanedTempPath = $null

        if ($needsPreflight) {
            $cleanedTempPath = Join-Path ([System.IO.Path]::GetTempPath()) "gptimg_clean_$([Guid]::NewGuid().ToString('N')).png"
            $stderrTempPath  = Join-Path ([System.IO.Path]::GetTempPath()) "gptimg_jpgerr_$([Guid]::NewGuid().ToString('N')).log"

            # PowerShell sub-process: loads the JPEG, saves it as PNG in the temp.
            # All the native stderr (including libjpeg) is captured in the file.
            $subScript = @"
Add-Type -AssemblyName System.Drawing
`$img = [System.Drawing.Image]::FromFile('$($ImagePath.Replace("'", "''"))')
`$img.Save('$cleanedTempPath', [System.Drawing.Imaging.ImageFormat]::Png)
`$img.Dispose()
"@
            $tmpScriptFile = Join-Path ([System.IO.Path]::GetTempPath()) "gptimg_script_$([Guid]::NewGuid().ToString('N')).ps1"
            Set-Content -Path $tmpScriptFile -Value $subScript -Encoding UTF8

            try {
                # Lancio pwsh in modalita' batch, redirigendo stderr al file.
                $psi = New-Object System.Diagnostics.ProcessStartInfo
                $psi.FileName = (Get-Process -Id $PID).Path   # usa lo stesso pwsh.exe
                $psi.Arguments = "-NoProfile -NonInteractive -File `"$tmpScriptFile`""
                $psi.UseShellExecute = $false
                $psi.RedirectStandardError = $true
                $psi.RedirectStandardOutput = $true
                $psi.CreateNoWindow = $true

                $proc = [System.Diagnostics.Process]::Start($psi)
                $stderrText = $proc.StandardError.ReadToEnd()
                # I must read stdout ALSO to drain the buffer and avoid a
                # possible process deadlock, but we do not need the content: I
                # discard it explicitly with [void] (here only stderr matters).
                [void]$proc.StandardOutput.ReadToEnd()
                $proc.WaitForExit(60000) | Out-Null

                # I save stderr for analysis
                if ($stderrText) {
                    Set-Content -Path $stderrTempPath -Value $stderrText -Encoding UTF8
                }
            }
            catch {
                # If the sub-process fails, fallback to direct loading (see below)
                $cleanedTempPath = $null
            }
            finally {
                try { Remove-Item $tmpScriptFile -Force -ErrorAction SilentlyContinue } catch {}
            }

            # Se il sub-process ha catturato messaggi (es. "Corrupt JPEG data"), li rilogo
            if ((Test-Path $stderrTempPath) -and ((Get-Item $stderrTempPath).Length -gt 0)) {
                try {
                    $captured = (Get-Content $stderrTempPath -Raw -Encoding UTF8 -ErrorAction SilentlyContinue)
                    if ($captured -and $captured.Trim()) {
                        foreach ($warnLine in ($captured -split "`n")) {
                            $cleanLine = $warnLine.Trim()
                            if ($cleanLine) {
                                Write-Log (T 'image.anomaly_detected' ($fileInfo.Name) $cleanLine) -Level WARN
                            }
                        }
                    }
                } catch {}
                try { Remove-Item $stderrTempPath -Force -ErrorAction SilentlyContinue } catch {}
            }
        }

        # Image loading: if I have a clean PNG, I use it (no libjpeg warnings).
        # Otherwise, I load the original file directly.
        if ($cleanedTempPath -and (Test-Path $cleanedTempPath)) {
            $script:TempFilesToCleanup += $cleanedTempPath
            $memStream.Dispose()
            $memStream = $null
            $imageBytes = [System.IO.File]::ReadAllBytes($cleanedTempPath)
            $memStream = [System.IO.MemoryStream]::new($imageBytes)
        }
        $image = [System.Drawing.Image]::FromStream($memStream)
    }
    catch {
        if ($memStream) { $memStream.Dispose() }
        Write-Log (T 'image.read_failed' ($fileInfo.Name) ($_.Exception.Message)) -Level ERROR
        exit 1
    }

    $origWidth   = $image.Width
    $origHeight  = $image.Height
    $origAspect  = if ($origHeight -gt 0) { [math]::Round($origWidth / [double]$origHeight, 3) } else { 0 }
    Write-Log (T 'image.info' ($fileInfo.Name) $fileSizeMB $origWidth $origHeight $origAspect)

    $newWidth  = $origWidth
    $newHeight = $origHeight
    $longestSide = [math]::Max($origWidth, $origHeight)

    if ($longestSide -gt $MaxDimension) {
        $scaleFactor = $MaxDimension / $longestSide
        $newWidth    = [math]::Round($origWidth * $scaleFactor)
        $newHeight   = [math]::Round($origHeight * $scaleFactor)
        if ($newWidth -lt 1)  { $newWidth = 1 }
        if ($newHeight -lt 1) { $newHeight = 1 }
        $newAspect = if ($newHeight -gt 0) { [math]::Round($newWidth / [double]$newHeight, 3) } else { 0 }
        Write-Log (T 'image.resized' $origWidth $origHeight $newWidth $newHeight $MaxDimension $newAspect)
    }

    # AREA constraint (for models like MAI that limit the total input area).
    # If after side-scaling the area still exceeds MaxArea, we scale further
    # preserving the aspect ratio. Solves the TIMEOUTs (408) caused by references that are too
    # large (e.g. 4000x3000 sent to a model that accepts at most ~1 MP).
    if ($MaxArea -gt 0 -and ($newWidth * $newHeight) -gt $MaxArea) {
        $areaScale = [math]::Sqrt($MaxArea / [double]($newWidth * $newHeight))
        $beforeW = $newWidth; $beforeH = $newHeight
        $newWidth  = [math]::Floor($newWidth  * $areaScale)
        $newHeight = [math]::Floor($newHeight * $areaScale)
        if ($newWidth -lt 1)  { $newWidth = 1 }
        if ($newHeight -lt 1) { $newHeight = 1 }
        $newAspect = if ($newHeight -gt 0) { [math]::Round($newWidth / [double]$newHeight, 3) } else { 0 }
        Write-Log (T 'image.resized_area' $beforeW $beforeH $newWidth $newHeight $MaxArea $newAspect)
    }

    try {
        $newBitmap = New-Object System.Drawing.Bitmap($newWidth, $newHeight, [System.Drawing.Imaging.PixelFormat]::Format24bppRgb)
        $graphics  = [System.Drawing.Graphics]::FromImage($newBitmap)
        $graphics.Clear([System.Drawing.Color]::White)
        $graphics.CompositingQuality = [System.Drawing.Drawing2D.CompositingQuality]::HighQuality
        $graphics.InterpolationMode  = [System.Drawing.Drawing2D.InterpolationMode]::HighQualityBicubic
        $graphics.SmoothingMode      = [System.Drawing.Drawing2D.SmoothingMode]::HighQuality
        $graphics.DrawImage($image, 0, 0, $newWidth, $newHeight)

        $tempDir      = [System.IO.Path]::GetTempPath()
        $tempFileName = "gptimg_validated_$([Guid]::NewGuid().ToString('N')).png"
        $tempPath     = Join-Path $tempDir $tempFileName

        $newBitmap.Save($tempPath, [System.Drawing.Imaging.ImageFormat]::Png)

        $script:TempFilesToCleanup += $tempPath

        $tempFileInfo = Get-Item $tempPath
        $tempSizeMB   = [math]::Round($tempFileInfo.Length / 1MB, 2)

        if ($tempSizeMB -ge 20) {
            Write-Log (T 'image.png_large' $tempSizeMB) -Level WARN
        }

        return $tempPath
    }
    catch {
        Write-Log (T 'image.conversion_failed' ($fileInfo.Name) ($_.Exception.Message)) -Level ERROR
        exit 1
    }
    finally {
        # Safe dispose of all the resources, both on success and on error.
        # The $null checks prevent NullReferenceException if the error occurred
        # before the creation of some resources.
        if ($graphics)  { try { $graphics.Dispose()  } catch { } }
        if ($newBitmap) { try { $newBitmap.Dispose() } catch { } }
        if ($image)     { try { $image.Dispose()     } catch { } }
        if ($memStream) { try { $memStream.Dispose() } catch { } }
    }
}

# Removes the temporary files created during image processing/conversion.
function Invoke-TempCleanup {
    if ($script:TempFilesToCleanup.Count -gt 0) {
        Write-Log (T 'image.temp_cleanup' ($script:TempFilesToCleanup.Count))
        foreach ($tmp in $script:TempFilesToCleanup) {
            if (Test-Path $tmp) {
                Remove-Item $tmp -Force -ErrorAction SilentlyContinue
            }
        }
        $script:TempFilesToCleanup = @()
    }
}

# Reads the time telemetry records from the .stat file (JSONL), limiting to the last N lines.
function Import-TimeStats {
    param([int]$MaxRecords = 1000)

    if (-not (Test-Path $script:StatsFile)) { return @() }

    $records = [System.Collections.Generic.List[object]]::new()
    try {
        $lines = Get-Content $script:StatsFile -Encoding UTF8 -ErrorAction Stop
    }
    catch {
        Write-Log (T 'stat.read_failed' $script:StatsFile ($_.Exception.Message)) -Level WARN
        return @()
    }

    $tailLines = if (@($lines).Count -gt $MaxRecords) {
        $lines[-$MaxRecords..-1]
    } else { $lines }

    foreach ($line in $tailLines) {
        if (-not $line -or $line.Trim() -eq "") { continue }
        try {
            $rec = $line | ConvertFrom-Json -ErrorAction Stop
            [void]$records.Add($rec)
        }
        catch { continue }
    }

    return @($records)
}

# Appends a time telemetry record (generation duration) to the .stat file.
function Add-TimeStatRecord {
    param([Parameter(Mandatory=$true)] $Record)

    # Opt-out for this run (-NoTelemetry, used by SelfTest on the sub-processes):
    # the test generations must NOT end up in the .stat nor in the [TIME] log, otherwise
    # they would pollute the kNN estimate and the -Auto Time medians with artificial times. This
    # centralized check covers ALL the flows that write statistics (cli, batch,
    # benchmark, storyboard, tui), because they all pass through here.
    if ($script:NoTelemetryFlag) { return }

    try {
        $jsonLine = $Record | ConvertTo-Json -Compress -Depth 5
        Add-Content -Path $script:StatsFile -Value $jsonLine -Encoding UTF8 -ErrorAction Stop
    }
    catch {
        Write-Log (T 'stat.update_failed' ($_.Exception.Message)) -Level WARN
    }

    $human = "date=$($Record.date) start=$($Record.start) end=$($Record.end) " +
             "estimated=$($Record.estimated) actual=$($Record.actual) " +
             "model=$($Record.model) deployment=$($Record.deployment) mode=$($Record.mode) " +
             "prompt_len=$($Record.prompt_len) size=$($Record.size) format=$($Record.format) " +
             "quality=$($Record.quality) n_images=$($Record.n_images) " +
             "input_images_count=$($Record.input_images_count) attempts=$($Record.attempts)"
    Write-Log $human -Level TIME
}

# Helper: builds a time telemetry record from the $Result of
# Invoke-ImageGeneration and the request parameters, then writes it to the .stat
# (and logs the [TIME] line, which also feeds -Auto Time). Centralizes the logic
# used by ALL the flows that generate (cli, batch, benchmark, storyboard), so
# every real generation contributes to the kNN estimate and the Auto Time medians.
# Writes ONLY if the generation succeeded and has valid times. NOT to be used
# for the SelfTest (deliberately excluded from the statistics).
function Write-GenerationStat {
    param(
        [Parameter(Mandatory=$true)] $Result,
        [Parameter(Mandatory=$true)][string]$Model,
        [string]$Deployment = "",
        [string]$ModeKey = "generation",
        [int]$PromptLen = 0,
        [string]$Size = "",
        [string]$Format = "",
        [string]$Quality = "",
        [int]$NImages = 1,
        [int]$InputImagesCount = 0,
        [int]$EstimatedTotal = 0
    )
    if (-not $Result -or -not $Result.Success) { return }
    if (-not $Result.StartTime -or -not $Result.ActualDurationSec) { return }
    if ([double]$Result.ActualDurationSec -le 0) { return }

    $endAttempt = $Result.StartTime.AddSeconds($Result.ActualDurationSec)
    $rec = [ordered]@{
        date               = $Result.StartTime.ToString("yyyy-MM-dd", [System.Globalization.CultureInfo]::InvariantCulture)
        start              = $Result.StartTime.ToString("HH:mm:ss")
        end                = $endAttempt.ToString("HH:mm:ss")
        estimated          = [int]$EstimatedTotal
        actual             = [int]$Result.ActualDurationSec
        model              = $Model
        deployment         = $Deployment
        mode               = $ModeKey
        prompt_len         = [int]$PromptLen
        size               = $Size
        format             = $Format
        quality            = $Quality
        n_images           = [int]$NImages
        input_images_count = [int]$InputImagesCount
        attempts           = if ($null -ne $Result.Attempts) { [int]$Result.Attempts } else { 1 }
    }
    Add-TimeStatRecord -Record $rec
}

function Get-MeterPrice {
    <#
    Helper: extracts a price by name from the pricing.meters block (case-insensitive).
    Returns 0.0 if the meter does not exist or is not a valid number.

    The $Pricing.meters schema is a hashtable/PSCustomObject with keys like:
      inputText, cachedInputText, inputImage, cachedInputImage, outputText, outputImage  (AOAI)
      input, output                                                                       (MAI)
    #>
    param($Pricing, [string]$MeterName)

    if (-not $Pricing) { return 0.0 }

    # Schema nuovo: $Pricing.meters
    if ($Pricing.PSObject.Properties.Name -contains 'meters' -and $Pricing.meters) {
        $meters = $Pricing.meters
        foreach ($prop in $meters.PSObject.Properties) {
            if ($prop.Name -ieq $MeterName) {
                try { return [double]$prop.Value } catch { return 0.0 }
            }
        }
    }
    return 0.0
}

function Test-ModelOperationalLimits {
    <#
    Validates the generation parameters against the model's operational constraints
    ('operationalLimits' field in the .conf) BEFORE calling the API. Intercepting
    the errors here avoids calls destined to fail and gives clear and
    immediate messages to the user (e.g. "model X accepts at most 4 images").

    Constraints checked:
      - maxImages / minImages    : number of images per request (NImages)
      - allowedSizes (sizeMode=enum)        : Size must be one of the allowed values
      - sizeMultiple/maxMegapixels/min-maxSide (sizeMode=constraints): for the
        per-megapixel models (FLUX) that accept arbitrary dimensions within rules
      - allowedQualities         : allowed Quality (if the list is non-empty)
      - maxReferenceImages       : number of reference images in edit mode

    Parameters:
      -ModelConfig:   the model object from the .conf (contains operationalLimits)
      -ModelName:     logical name (for the messages)
      -NImages, -Size, -Quality: the requested parameters
      -ReferenceCount: number of reference images passed (edit), default 0
      -QualityExplicit: $true if the user passed -Quality explicitly (to
                        decide whether to validate the quality or let the default run)

    Returns: array of already-translated strings (errors). Empty = no problem.
    #>
    param(
        $ModelConfig,
        [string]$ModelName,
        [int]$NImages,
        [string]$Size,
        [string]$Quality,
        [int]$ReferenceCount = 0,
        [bool]$QualityExplicit = $false
    )

    $errors = @()
    $lim = $ModelConfig.operationalLimits
    if (-not $lim) {
        # No constraint defined: nothing to validate (backward compatibility with
        # any models added by hand without operationalLimits).
        return $errors
    }

    # ---- Number of images ----
    $maxImg = if ($null -ne $lim.maxImages) { [int]$lim.maxImages } else { 0 }
    $minImg = if ($null -ne $lim.minImages) { [int]$lim.minImages } else { 1 }
    if ($maxImg -gt 0 -and $NImages -gt $maxImg) {
        $errors += (T 'limits.too_many_images' $ModelName $NImages $maxImg)
    }
    if ($NImages -lt $minImg) {
        $errors += (T 'limits.too_few_images' $ModelName $NImages $minImg)
    }

    # ---- Dimensioni ----
    $sizeMode = if ($lim.sizeMode) { $lim.sizeMode } else { "enum" }
    if ($sizeMode -eq "enum") {
        $allowed = @($lim.allowedSizes)
        if ($allowed.Count -gt 0 -and ($allowed -notcontains $Size)) {
            $errors += (T 'limits.size_not_allowed' $ModelName $Size ($allowed -join ', '))
        }
    } elseif ($sizeMode -eq "constraints") {
        # Parsing "WxH" and checking the dimensional constraints (FLUX-style).
        if ($Size -match '^(\d+)\s*[xX]\s*(\d+)$') {
            $w = [int]$Matches[1]; $h = [int]$Matches[2]
            $mult = if ($null -ne $lim.sizeMultiple) { [int]$lim.sizeMultiple } else { 0 }
            if ($mult -gt 0 -and (($w % $mult) -ne 0 -or ($h % $mult) -ne 0)) {
                $errors += (T 'limits.size_not_multiple' $ModelName $Size $mult)
            }
            $minSide = if ($null -ne $lim.minSide) { [int]$lim.minSide } else { 0 }
            $maxSide = if ($null -ne $lim.maxSide) { [int]$lim.maxSide } else { 0 }
            if ($minSide -gt 0 -and ($w -lt $minSide -or $h -lt $minSide)) {
                $errors += (T 'limits.side_too_small' $ModelName $Size $minSide)
            }
            if ($maxSide -gt 0 -and ($w -gt $maxSide -or $h -gt $maxSide)) {
                $errors += (T 'limits.side_too_large' $ModelName $Size $maxSide)
            }
            $maxMp = if ($null -ne $lim.maxMegapixels) { [double]$lim.maxMegapixels } else { 0.0 }
            if ($maxMp -gt 0) {
                $mp = ($w * $h) / 1000000.0
                if ($mp -gt $maxMp + 0.0001) {
                    $errors += (T 'limits.megapixels_exceeded' $ModelName ("{0:F2}" -f $mp) ("{0:F1}" -f $maxMp))
                }
            }
        } else {
            $errors += (T 'limits.size_malformed' $ModelName $Size)
        }
    }

    # ---- Quality ----
    # I validate only if the user passed it explicitly AND the model defines
    # a non-empty list of allowed qualities. Models that do not use 'quality'
    # (e.g. FLUX) have an empty allowedQualities and so are not touched.
    if ($QualityExplicit) {
        $allowedQ = @($lim.allowedQualities)
        if ($allowedQ.Count -gt 0 -and ($allowedQ -notcontains $Quality)) {
            $errors += (T 'limits.quality_not_allowed' $ModelName $Quality ($allowedQ -join ', '))
        }
    }

    # ---- Reference images (edit) ----
    $maxRef = if ($null -ne $lim.maxReferenceImages) { [int]$lim.maxReferenceImages } else { 0 }
    if ($ReferenceCount -gt 0 -and $maxRef -ge 0 -and $ReferenceCount -gt $maxRef) {
        if ($maxRef -eq 0) {
            $errors += (T 'limits.no_reference_support' $ModelName $ReferenceCount)
        } else {
            $errors += (T 'limits.too_many_references' $ModelName $ReferenceCount $maxRef)
        }
    }

    return $errors
}

function Get-EstimatedTokens {
    <#
    Estimates the INPUT (prompt) and OUTPUT (image) tokens when the API does NOT return them
    in the response. It is a last-resort FALLBACK: to be used only for the
    token-based models with valid pricing whose API does not expose 'usage' (e.g. MAI). An estimate
    is always better than a zero cost that would distort the analytics; the caller MUST
    warn the user with a WARN that the cost is estimated, not measured.

    Estimation model (agreed):
      INPUT  = ceil(prompt_length / charsPerToken)
               Rule of thumb: ~4 characters per token (typical English text). The empty
               or absent prompt gets a safety minimum.
      OUTPUT = ceil(area_px / pxPerToken) per image, x NImages
               The image is tokenized as a function of the AREA. The pxPerToken factor
               depends on the QUALITY TIER (low/medium/high): higher quality
               corresponds to more tokens for the same area (a "denser" image).
               The defaults are calibrated on the known gpt-image values:
                 ~1024x1024 (1,048,576 px) -> ~1056 tokens at 'low', ~4160 at 'high'.
               From which: pxPerToken ~ 992 (low), ~430 (medium), ~252 (high).

    Parameters:
      -PromptText: text prompt (for the input tokens)
      -Width, -Height: dimensions of the generated image (px)
      -NImages: number of generated images
      -Quality: "low"|"medium"|"high"|"auto"|"" (maps to the output factor; default medium)

    Returns [PSCustomObject] { InputTokens; OutputTokens }.
    #>
    param(
        [string]$PromptText = "",
        [int]$Width = 0,
        [int]$Height = 0,
        [int]$NImages = 1,
        [string]$Quality = ""
    )

    # ---- INPUT: dal prompt ----
    $charsPerToken = 4.0
    $promptLen = if ($PromptText) { $PromptText.Length } else { 0 }
    $inputTokens = [int][math]::Ceiling($promptLen / $charsPerToken)
    if ($inputTokens -lt 1) { $inputTokens = 1 }   # minimo di sicurezza

    # ---- OUTPUT: from the area, with a factor per quality tier ----
    # px per token: lower = more tokens (denser image, higher quality).
    $q = if ($Quality) { $Quality.Trim().ToLower() } else { "" }
    $pxPerToken = switch ($q) {
        "low"    { 992.0 }
        "medium" { 430.0 }
        "high"   { 252.0 }
        "auto"   { 430.0 }   # 'auto' -> trattato come medium
        default  { 430.0 }   # default prudente: medium
    }

    $nImg = [math]::Max(1, $NImages)
    $area = 0
    if ($Width -gt 0 -and $Height -gt 0) { $area = $Width * $Height }
    if ($area -le 0) { $area = 1048576 }   # fallback: assume ~1024x1024 se dimensioni ignote

    $perImageOutput = [int][math]::Ceiling($area / $pxPerToken)
    if ($perImageOutput -lt 1) { $perImageOutput = 1 }
    $outputTokens = $perImageOutput * $nImg

    return [PSCustomObject]@{
        InputTokens  = $inputTokens
        OutputTokens = $outputTokens
    }
}

function Get-CostBreakdown {
    <#
    Calculates costs in USD and EUR from the 'usage' block of the API response.

    New 6-meter pricing schema for labeled models (AOAI):
      - inputText, cachedInputText, inputImage, cachedInputImage, outputText, outputImage
    For columnar models (MAI): 2 meters:
      - input, output

    Maps the Azure usage to the correct meters:
      input_tokens_details.text_tokens         -> inputText (or input for MAI)
      input_tokens_details.image_tokens        -> inputImage (or input for MAI)
      input_tokens_details.cached_tokens.text  -> cachedInputText (if exposed)
      input_tokens_details.cached_tokens.image -> cachedInputImage (if exposed)
      output_tokens_details.text_tokens        -> outputText (if exposed)
      output_tokens_details.image_tokens       -> outputImage (if exposed)

    For GPT-Image models where the response does NOT expose output_tokens_details:
      output_tokens goes entirely to outputImage (they are the generated image's tokens).

    For columnar models (MAI): all input -> input, all output -> output.
    #>
    param(
        $Usage,                       # oggetto dalla response: input_tokens, output_tokens, ...details
        $Pricing,                     # blocco pricing del modello (con .meters)
        [double]$EurRate,
        # --- parametri per pricing per-megapixel (FLUX e simili) ---
        # When the model uses "per-megapixel" pricing instead of per-token, the cost
        # does NOT derive from the usage (tokens) but from the dimensions of the generated image and
        # of any reference images (edit). These parameters are ignored
        # for token-based models (labeled/columnar).
        [int]$GenWidth = 0,           # width of the generated image (px)
        [int]$GenHeight = 0,          # height of the generated image (px)
        [int]$NImages = 1,            # number of generated images (the per-MP cost is per image)
        [int[]]$ReferenceMpList = @(), # list of megapixels (already rounded) for each reference image
        # --- Token estimation fallback (last resort) ---
        # Used ONLY if the pricing is token-based, there is a valid price, but the API did not
        # return any token (e.g. MAI). They serve to estimate the tokens instead of
        # recording a zero cost. See Get-EstimatedTokens.
        [string]$PromptText = "",     # text prompt (to estimate the input tokens)
        [string]$Quality = ""         # requested quality (for the output px/token factor)
    )

    # -------- Extraction of the sub-tokens from the usage --------
    # Helper: reads a value from $Usage trying several alternative field names.
    # The image APIs are not uniform: gpt-image (openai-images) uses
    # input_tokens/output_tokens, but other providers/schemas (e.g. MAI) may use
    # prompt_tokens/completion_tokens (chat/legacy OpenAI style) or input/output.
    # Without this fallback, the tokens turned out 0 for MAI and the cost was zeroed.
    function _usageVal($u, [string[]]$names) {
        if (-not $u) { return $null }
        foreach ($nm in $names) {
            if (($u.PSObject.Properties.Name -contains $nm) -and ($null -ne $u.$nm)) {
                $v = $u.$nm
                # Must be numeric (some fields are details objects: we skip them)
                $parsed = 0
                if ([int]::TryParse([string]$v, [ref]$parsed)) { return $parsed }
            }
        }
        return $null
    }

    $inVal  = _usageVal $Usage @('input_tokens','prompt_tokens','input','promptTokens','inputTokens')
    $outVal = _usageVal $Usage @('output_tokens','completion_tokens','output','completionTokens','outputTokens')
    $totVal = _usageVal $Usage @('total_tokens','totalTokens')

    $inputTokens  = if ($null -ne $inVal)  { [int]$inVal }  else { 0 }
    $outputTokens = if ($null -ne $outVal) { [int]$outVal } else { 0 }

    # If we have the total but one of the two is missing (some APIs give only total +
    # prompt, or only total), we derive the missing one by difference.
    if ($null -ne $totVal) {
        $tot = [int]$totVal
        if ($null -eq $inVal -and $null -ne $outVal) { $inputTokens  = [math]::Max(0, $tot - $outputTokens) }
        if ($null -eq $outVal -and $null -ne $inVal) { $outputTokens = [math]::Max(0, $tot - $inputTokens) }
    }

    # Input details: text/image/cached
    $textTokens         = $inputTokens   # default: tutto testo se manca details
    $imageTokens        = 0
    $cachedTextTokens   = 0
    $cachedImageTokens  = 0
    if ($Usage -and $Usage.input_tokens_details) {
        $det = $Usage.input_tokens_details
        if ($null -ne $det.text_tokens)  { $textTokens  = [int]$det.text_tokens }
        if ($null -ne $det.image_tokens) { $imageTokens = [int]$det.image_tokens }
        # Cached: Azure might expose it as cached_tokens (number) or cached_tokens_details.{text,image}
        if ($null -ne $det.cached_tokens) {
            # Form sometimes used: single number. We treat it as cached text by default.
            $cachedTextTokens = [int]$det.cached_tokens
        }
        if ($det.cached_tokens_details) {
            $cdet = $det.cached_tokens_details
            if ($null -ne $cdet.text_tokens)  { $cachedTextTokens  = [int]$cdet.text_tokens }
            if ($null -ne $cdet.image_tokens) { $cachedImageTokens = [int]$cdet.image_tokens }
        }
    }

    # Output details: text/image
    $outputTextTokens  = 0
    $outputImageTokens = 0
    $hasOutputDetails  = $false
    if ($Usage -and $Usage.output_tokens_details) {
        $hasOutputDetails = $true
        $odet = $Usage.output_tokens_details
        if ($null -ne $odet.text_tokens)  { $outputTextTokens  = [int]$odet.text_tokens }
        if ($null -ne $odet.image_tokens) { $outputImageTokens = [int]$odet.image_tokens }
    }
    # For image models, the output is essentially the generated image. The Azure
    # API however is INCONSISTENT in populating output_tokens_details:
    # - sometimes it does not expose it at all -> all output = image
    # - sometimes it exposes it with image_tokens set -> we use that
    # - sometimes it exposes it "empty"/partial (image_tokens=0 or absent, text=0)
    # despite output_tokens > 0 -> the UNclassified tokens
    # must be treated as IMAGE, not lost (otherwise the output
    # cost turns out 0 even for real images: this was the bug for which
    # many .cost lines had output_usd=0 despite having thousands of
    # output tokens).
    # Unified rule: the output tokens not explained by text+image are attributed
    # to the image. This way we cover all three cases conservatively and correctly.
    if (-not $hasOutputDetails) {
        $outputImageTokens = $outputTokens
    } else {
        $classified = $outputTextTokens + $outputImageTokens
        $unclassified = $outputTokens - $classified
        if ($unclassified -gt 0) {
            $outputImageTokens += $unclassified
        }
    }

    # -------- Retrieving the prices from pricing.meters --------
    # first we check whether the model uses PER-MEGAPIXEL pricing (FLUX).
    # The per-MP meters are: firstMpUsd, additionalMpUsd, referenceMpUsd. If present
    # (at least one > 0), the cost is calculated from the image dimensions, not from the tokens.
    $pFirstMp      = Get-MeterPrice -Pricing $Pricing -MeterName 'firstMpUsd'
    $pAdditionalMp = Get-MeterPrice -Pricing $Pricing -MeterName 'additionalMpUsd'
    $pReferenceMp  = Get-MeterPrice -Pricing $Pricing -MeterName 'referenceMpUsd'
    $hasPerMpSchema = ($pFirstMp -gt 0 -or $pAdditionalMp -gt 0 -or $pReferenceMp -gt 0)

    # Capisce se siamo in schema "labeled" (AOAI: ha inputText) o "columnar" (MAI: ha input)
    $hasLabeledSchema  = (Get-MeterPrice -Pricing $Pricing -MeterName 'inputText')  -gt 0 `
                     -or (Get-MeterPrice -Pricing $Pricing -MeterName 'outputImage') -gt 0 `
                     -or (Get-MeterPrice -Pricing $Pricing -MeterName 'inputImage')  -gt 0
    $hasColumnarSchema = (Get-MeterPrice -Pricing $Pricing -MeterName 'input')      -gt 0 `
                     -or (Get-MeterPrice -Pricing $Pricing -MeterName 'output')     -gt 0

    # tracking of the pricing schema used and the megapixels (for per-MP models
    # like FLUX). They are needed by Write-CostLog to show MP instead of "0 tok".
    $pricingMode      = "tokens"   # "tokens" | "megapixels"
    $genMegapixels    = 0
    $refMegapixelsTot = 0

    if ($hasPerMpSchema) {
        # ---- Schema PER-MEGAPIXEL (FLUX.2) ----
        # Cost of the generated image: first MP at firstMpUsd, subsequent MPs at additionalMpUsd.
        # The resolution is rounded UP to the next megapixel (Azure rule).
        # 1 MP = 1,000,000 px. The cost is PER generated IMAGE (multiplied by NImages).
        # Cost of the reference images (edit): referenceMpUsd for each MP of each reference.
        $genMp = 0
        if ($GenWidth -gt 0 -and $GenHeight -gt 0) {
            $genMp = [math]::Ceiling(($GenWidth * $GenHeight) / 1000000.0)
        }
        if ($genMp -lt 1) { $genMp = 1 }   # minimo 1 MP fatturato per immagine valida

        $perImageGenCost = $pFirstMp + $pAdditionalMp * [math]::Max(0, $genMp - 1)
        $nImg = [math]::Max(1, $NImages)
        # In the per-MP model there is no input/output distinction: all the generation
        # cost we attribute to "output" (the produced image) for consistency with the
        # reports; the references go to "input" (they are material provided as input).
        $outputCostUsd = $perImageGenCost * $nImg

        $refCostUsd = 0.0
        if ($ReferenceMpList -and $ReferenceMpList.Count -gt 0) {
            foreach ($rmp in $ReferenceMpList) {
                $refMpRounded = [math]::Max(1, [int]$rmp)
                $refCostUsd += $pReferenceMp * $refMpRounded
                $refMegapixelsTot += $refMpRounded
            }
        }
        $inputCostUsd = $refCostUsd

        # I save the megapixels for the report. The "gen" is per image x NImages.
        $pricingMode   = "megapixels"
        $genMegapixels = $genMp * $nImg

        $pricingAvailable = ($pFirstMp -gt 0 -or $pAdditionalMp -gt 0)
    }
    elseif ($hasLabeledSchema) {
        # Schema AOAI a 6 meter
        $pInputText        = Get-MeterPrice -Pricing $Pricing -MeterName 'inputText'
        $pCachedInputText  = Get-MeterPrice -Pricing $Pricing -MeterName 'cachedInputText'
        $pInputImage       = Get-MeterPrice -Pricing $Pricing -MeterName 'inputImage'
        $pCachedInputImage = Get-MeterPrice -Pricing $Pricing -MeterName 'cachedInputImage'
        $pOutputText       = Get-MeterPrice -Pricing $Pricing -MeterName 'outputText'
        $pOutputImage      = Get-MeterPrice -Pricing $Pricing -MeterName 'outputImage'

        # The cached are subtracted from the normal text/image (they represent a subcategory
        # already counted in text/image_tokens). Azure example: input_tokens_details.text_tokens=100
        # and cached_tokens=20 means that 80 are billed at $5/1M (inputText) and 20 at $1.25/1M (cached).
        $regularTextTokens  = [math]::Max(0, $textTokens  - $cachedTextTokens)
        $regularImageTokens = [math]::Max(0, $imageTokens - $cachedImageTokens)

        $inputCostUsd = ($regularTextTokens  / 1000000.0) * $pInputText `
                      + ($cachedTextTokens   / 1000000.0) * $pCachedInputText `
                      + ($regularImageTokens / 1000000.0) * $pInputImage `
                      + ($cachedImageTokens  / 1000000.0) * $pCachedInputImage

        $outputCostUsd = ($outputTextTokens  / 1000000.0) * $pOutputText `
                       + ($outputImageTokens / 1000000.0) * $pOutputImage

        $pricingAvailable = ($pInputText -gt 0 -or $pInputImage -gt 0 -or $pOutputImage -gt 0 -or $pOutputText -gt 0)
    }
    elseif ($hasColumnarSchema) {
        # Schema MAI a 2 meter: input/output globali (no distinzione text/image)
        $pInput  = Get-MeterPrice -Pricing $Pricing -MeterName 'input'
        $pOutput = Get-MeterPrice -Pricing $Pricing -MeterName 'output'

        $inputCostUsd  = ($inputTokens  / 1000000.0) * $pInput
        $outputCostUsd = ($outputTokens / 1000000.0) * $pOutput

        $pricingAvailable = ($pInput -gt 0 -or $pOutput -gt 0)
    }
    else {
        # No pricing configured
        $inputCostUsd  = 0.0
        $outputCostUsd = 0.0
        $pricingAvailable = $false
    }

    $totalCostUsd = $inputCostUsd + $outputCostUsd

    # Diagnostics + ESTIMATION FALLBACK: valid token-based pricing but ZERO tokens read
    # from the usage. This would produce a zero cost despite there being a configured price:
    # typically the model's API does not return 'usage' (e.g. MAI). In this case,
    # as a LAST resort, we ESTIMATE the tokens (Get-EstimatedTokens) and recalculate the
    # costs, so the analytics do not record a misleading zero. The
    # tokens_estimated flag tells the caller to warn the user that the cost is ESTIMATED.
    $tokensMissing   = $false
    $tokensEstimated = $false
    if ($pricingAvailable -and -not $hasPerMpSchema -and (($inputTokens + $outputTokens) -le 0)) {
        $tokensMissing = $true
        $est = Get-EstimatedTokens -PromptText $PromptText -Width $GenWidth -Height $GenHeight `
                                   -NImages $NImages -Quality $Quality
        $inputTokens  = $est.InputTokens
        $outputTokens = $est.OutputTokens
        $tokensEstimated = $true

        # I recalculate the costs with the estimated tokens, according to the active schema.
        if ($hasLabeledSchema) {
            # Labeled schema: the estimate does not distinguish text/image. We attribute all
            # the input to inputText and all the output to outputImage (the generated image),
            # which is the dominant and billed component for image models.
            $pInputText   = Get-MeterPrice -Pricing $Pricing -MeterName 'inputText'
            $pOutputImage = Get-MeterPrice -Pricing $Pricing -MeterName 'outputImage'
            $textTokens        = $inputTokens
            $imageTokens       = 0
            $outputImageTokens = $outputTokens
            $outputTextTokens  = 0
            $inputCostUsd  = ($inputTokens  / 1000000.0) * $pInputText
            $outputCostUsd = ($outputTokens / 1000000.0) * $pOutputImage
        }
        elseif ($hasColumnarSchema) {
            $pInput  = Get-MeterPrice -Pricing $Pricing -MeterName 'input'
            $pOutput = Get-MeterPrice -Pricing $Pricing -MeterName 'output'
            $inputCostUsd  = ($inputTokens  / 1000000.0) * $pInput
            $outputCostUsd = ($outputTokens / 1000000.0) * $pOutput
        }
        $totalCostUsd = $inputCostUsd + $outputCostUsd
    }

    # Conversione EUR
    $inputCostEur  = $inputCostUsd  * $EurRate
    $outputCostEur = $outputCostUsd * $EurRate
    $totalCostEur  = $totalCostUsd  * $EurRate

    return [pscustomobject]@{
        input_tokens         = $inputTokens
        text_tokens          = $textTokens
        image_tokens         = $imageTokens
        cached_text_tokens   = $cachedTextTokens
        cached_image_tokens  = $cachedImageTokens
        output_tokens        = $outputTokens
        output_text_tokens   = $outputTextTokens
        output_image_tokens  = $outputImageTokens
        total_tokens         = $inputTokens + $outputTokens
        input_cost_usd       = $inputCostUsd
        output_cost_usd      = $outputCostUsd
        total_cost_usd       = $totalCostUsd
        input_cost_eur       = $inputCostEur
        output_cost_eur      = $outputCostEur
        total_cost_eur       = $totalCostEur
        eur_rate             = $EurRate
        pricing_available    = $pricingAvailable
        pricing_mode         = $pricingMode
        gen_megapixels       = $genMegapixels
        reference_megapixels = $refMegapixelsTot
        tokens_missing       = $tokensMissing
        tokens_estimated     = $tokensEstimated
    }
}

function Write-CostLog {
    <#
    Writes the [COST] line to the log file with ALL the details (input, output, total
    in tokens/USD/EUR + eur_rate). On screen it shows a synthetic version in ONLY the
    local currency (defaultCurrency) to reduce visual noise.

    In the .log and .cost file it keeps saving EVERYTHING, so the analytics and historical
    reports have all the data. A split between "full log" and "clean screen".
    #>
    param($Cost, [string]$Model, $HasPricingSection, [int]$NImages = 1)

    if (-not $Cost.pricing_available) {
        if (-not $HasPricingSection) {
            Write-Log (T 'cost.no_pricing_section' $Model) -Level COST
        } else {
            Write-Log (T 'cost.all_prices_zero' $Model) -Level COST
        }
        return
    }

    # Diagnostics: valid token-based pricing but no token returned by the API.
    # In this case we ESTIMATED the tokens (Get-EstimatedTokens) so as not to record
    # a misleading zero. We warn the user that the cost is an ESTIMATE, not measured.
    if (($Cost.PSObject.Properties.Name -contains 'tokens_estimated') -and $Cost.tokens_estimated) {
        Write-Log (T 'cost.tokens_estimated' $Model $Cost.input_tokens $Cost.output_tokens) -Level WARN
    }
    elseif (($Cost.PSObject.Properties.Name -contains 'tokens_missing') -and $Cost.tokens_missing) {
        # Residual case: tokens missing but estimate not applied (e.g. unhandled schema).
        Write-Log (T 'cost.tokens_missing' $Model) -Level WARN
    }

    # Detailed COST line: ONLY in the log file (not on screen, for cleanliness).
    # It contains all the information for analytics, historical reconstruction, etc.
    # esposto il dettaglio cached e output (text+image) per modelli labeled.
    $timestamp = (Get-Date).ToString("yyyy-MM-dd HH:mm:ss", [System.Globalization.CultureInfo]::InvariantCulture)
    $cachedTxt = if ($null -ne $Cost.cached_text_tokens)  { $Cost.cached_text_tokens }  else { 0 }
    $cachedImg = if ($null -ne $Cost.cached_image_tokens) { $Cost.cached_image_tokens } else { 0 }
    $outTxt    = if ($null -ne $Cost.output_text_tokens)  { $Cost.output_text_tokens }  else { 0 }
    $outImg    = if ($null -ne $Cost.output_image_tokens) { $Cost.output_image_tokens } else { 0 }
    $costMode = if ($Cost.PSObject.Properties.Name -contains 'pricing_mode') { $Cost.pricing_mode } else { 'tokens' }
    $mpDetail = ""
    if ($costMode -eq 'megapixels') {
        $gMp = if ($null -ne $Cost.gen_megapixels) { $Cost.gen_megapixels } else { 0 }
        $rMp = if ($null -ne $Cost.reference_megapixels) { $Cost.reference_megapixels } else { 0 }
        $mpDetail = "gen_megapixels=$gMp reference_megapixels=$rMp "
    }
    $estFlag = if (($Cost.PSObject.Properties.Name -contains 'tokens_estimated') -and $Cost.tokens_estimated) { "true" } else { "false" }
    $detailedLine = "model=$Model pricing_mode=$costMode n_images=$NImages tokens_estimated=$estFlag " +
                    $mpDetail +
                    "input_tokens=$($Cost.input_tokens) (text=$($Cost.text_tokens) image=$($Cost.image_tokens) cached_text=$cachedTxt cached_image=$cachedImg) " +
                    "output_tokens=$($Cost.output_tokens) (text=$outTxt image=$outImg) " +
                    "total_tokens=$($Cost.total_tokens) " +
                    # The costs in the .log ALWAYS use the invariant format (decimal
                    # point), via Format-StorageNumber: the file is machine-readable
                    # and parsed by the analytics regex, which expects the point.
                    ("input_usd={0} input_eur={1} "   -f (Format-StorageNumber $Cost.input_cost_usd),  (Format-StorageNumber $Cost.input_cost_eur)) +
                    ("output_usd={0} output_eur={1} " -f (Format-StorageNumber $Cost.output_cost_usd), (Format-StorageNumber $Cost.output_cost_eur)) +
                    ("total_usd={0} total_eur={1} "   -f (Format-StorageNumber $Cost.total_cost_usd),  (Format-StorageNumber $Cost.total_cost_eur)) +
                    ("eur_rate={0}" -f (Format-StorageNumber $Cost.eur_rate 4))
    $fullLogLine = "[$timestamp] [COST] $detailedLine"

    # I write directly to the file (I do not go through Write-Log to avoid duplication on screen)
    if ($script:LogFile) {
        Add-Content -Path $script:LogFile -Value (Protect-LogFileLine $fullLogLine) -Encoding UTF8 -ErrorAction SilentlyContinue
    }

    # On screen: SYNTHETIC version in the local currency only, if verbosity allows.
    # For token-based models it shows input/output/total in tokens; for
    # per-megapixel models (FLUX) it shows the generated and reference megapixels, because
    # "0 tok" would be misleading (FLUX is not billed by tokens).
    if ($Verbosity -eq "verbose" -or $Verbosity -eq "normal") {
        $localCurrency = if ($DefaultCurrency) { $DefaultCurrency } else { "EUR" }
        $localCost = if ($localCurrency -eq "EUR") {
            (Format-DisplayNumber -Value $Cost.total_cost_eur -Decimals 4) + " EUR"
        } else {
            (Format-DisplayNumber -Value $Cost.total_cost_usd -Decimals 4) + " USD"
        }
        $costMode = if ($Cost.PSObject.Properties.Name -contains 'pricing_mode') { $Cost.pricing_mode } else { 'tokens' }
        if ($costMode -eq 'megapixels') {
            $genMp = if ($null -ne $Cost.gen_megapixels) { $Cost.gen_megapixels } else { 0 }
            $refMp = if ($null -ne $Cost.reference_megapixels) { $Cost.reference_megapixels } else { 0 }
            $detail = T 'cost.synthetic_megapixels' $genMp $refMp
        } else {
            $detail = T 'cost.synthetic_tokens' $Cost.input_tokens $Cost.output_tokens $Cost.total_tokens
        }
        $synLine = "[$timestamp] [COST] $localCost $detail"
        Write-Host $synLine
    }
}

function Add-DailyCostRecord {
    <#
    Aggiorna New-GPTImage.cost con il totale del giorno (cumulativo).
    File format: JSONL, one line per day with the final cumulative total of that day.
    To avoid accumulating duplicate lines, I keep a single record per (date) and
    update it; I keep the history by adding new lines at the start of a new day.
    #>
    param($Cost)

    if (-not $Cost.pricing_available) { return }

    $today = (Get-Date).ToString("yyyy-MM-dd", [System.Globalization.CultureInfo]::InvariantCulture)
    $now   = (Get-Date).ToString("HH:mm:ss")

    # I read the existing history
    $records = [System.Collections.Generic.List[object]]::new()
    if (Test-Path $script:CostFile) {
        try {
            $lines = Get-Content $script:CostFile -Encoding UTF8 -ErrorAction Stop
            foreach ($l in $lines) {
                if (-not $l -or $l.Trim() -eq "") { continue }
                try {
                    $rec = $l | ConvertFrom-Json -ErrorAction Stop
                    [void]$records.Add($rec)
                } catch { continue }
            }
        } catch { $records = @() }
    }
    $records = @($records)

    # I look for today's record (the last for today's date). If it exists, I update; otherwise I add.
    $todayIndex = -1
    for ($i = $records.Count - 1; $i -ge 0; $i--) {
        if ($records[$i].date -eq $today) {
            $todayIndex = $i
            break
        }
    }

    if ($todayIndex -ge 0) {
        # I update today's record: I add to the existing one
        $existing = $records[$todayIndex]
        $records[$todayIndex] = [pscustomobject]@{
            date              = $today
            last_update       = $now
            total_input_tokens   = ([int]$existing.total_input_tokens   + $Cost.input_tokens)
            total_image_tokens   = ([int]$existing.total_image_tokens   + $Cost.image_tokens)
            total_text_tokens    = ([int]$existing.total_text_tokens    + $Cost.text_tokens)
            total_output_tokens  = ([int]$existing.total_output_tokens  + $Cost.output_tokens)
            total_tokens         = ([int]$existing.total_tokens         + $Cost.total_tokens)
            total_input_usd      = ([double]$existing.total_input_usd   + $Cost.input_cost_usd)
            total_input_eur      = ([double]$existing.total_input_eur   + $Cost.input_cost_eur)
            total_output_usd     = ([double]$existing.total_output_usd  + $Cost.output_cost_usd)
            total_output_eur     = ([double]$existing.total_output_eur  + $Cost.output_cost_eur)
            total_usd            = ([double]$existing.total_usd         + $Cost.total_cost_usd)
            total_eur            = ([double]$existing.total_eur         + $Cost.total_cost_eur)
            requests_count       = ([int]$existing.requests_count + 1)
        }
    } else {
        # New record for today
        $records += [pscustomobject]@{
            date              = $today
            last_update       = $now
            total_input_tokens   = $Cost.input_tokens
            total_image_tokens   = $Cost.image_tokens
            total_text_tokens    = $Cost.text_tokens
            total_output_tokens  = $Cost.output_tokens
            total_tokens         = $Cost.total_tokens
            total_input_usd      = $Cost.input_cost_usd
            total_input_eur      = $Cost.input_cost_eur
            total_output_usd     = $Cost.output_cost_usd
            total_output_eur     = $Cost.output_cost_eur
            total_usd            = $Cost.total_cost_usd
            total_eur            = $Cost.total_cost_eur
            requests_count       = 1
        }
    }

    # I rewrite the file (all the records)
    try {
        $allLines = $records | ForEach-Object { $_ | ConvertTo-Json -Compress -Depth 5 }
        $allLines | Set-Content -Path $script:CostFile -Encoding UTF8 -ErrorAction Stop
    }
    catch {
        Write-Log (T 'cost.update_failed' ($_.Exception.Message)) -Level WARN
    }
}

# kNN helper: quality score used to weight the neighbors in the time estimation.
function Get-QualityScore {
    param([string]$Quality)
    switch -Regex ($Quality.ToLower()) {
        '^low$|^standard$' { return 1 }
        '^medium$|^med$'   { return 2 }
        '^high$|^hd$'      { return 3 }
        default            { return 2 }
    }
}

# kNN helper: classifies an image dimension into a bucket for comparing similar requests.
function Get-SizeBucket {
    param([int]$Width, [int]$Height)
    $megapixels = ($Width * $Height) / 1000000.0
    if     ($megapixels -lt 1.2)  { return "small" }
    elseif ($megapixels -lt 2.0)  { return "medium" }
    else                          { return "large"  }
}

# kNN helper: decreasing weight based on the record's age (recent data weigh more).
function Get-RecencyWeight {
    param([string]$DateStr)
    try {
        $recordDate = [DateTime]::ParseExact($DateStr, "yyyy-MM-dd", [System.Globalization.CultureInfo]::InvariantCulture)
        $ageInDays  = ((Get-Date) - $recordDate).TotalDays
        if ($ageInDays -lt 0) { $ageInDays = 0 }
        return [math]::Pow(0.5, $ageInDays / 90.0)
    } catch { return 0.5 }
}

# Helper: maps a "raw" model name (from log/.stat) back to the CANONICAL name defined
# in the .conf. It serves to merge the variants of the same model that in the historical files
# may appear with a different case (e.g. "GPT-Image-2" vs "gpt-image-2") or with suffixes
# (e.g. "gpt-image-2-cto"), avoiding "phantom entries" in -Analytics and -Auto Time.
# Strategy (source of truth = .conf):
#   1. Exact case-insensitive match with the name of a .conf model.
#   2. Otherwise match by LONGEST PREFIX (the raw name starts with the name of a
#      .conf model): so "gpt-image-2-cto" -> "gpt-image-2". The longest
#      prefix is chosen so as not to confuse "gpt-image-2" with "gpt-image-2.5".
#   3. No match: the name stays unchanged (a truly unknown model).
# $CanonMap is an optional cache (hashtable) to avoid recomputing on many records;
# if not provided, the function works anyway (just without the cache).
function Get-CanonicalModelName {
    param(
        [string]$RawName,
        [string[]]$ConfModelNames,
        [hashtable]$CanonMap = $null
    )
    if ([string]::IsNullOrWhiteSpace($RawName)) { return $RawName }
    $r = $RawName.Trim()
    if ($CanonMap -and $CanonMap.ContainsKey($r)) { return $CanonMap[$r] }
    $result = $r
    # 1. Exact case-insensitive match
    $exact = $ConfModelNames | Where-Object { $_ -ieq $r } | Select-Object -First 1
    if ($exact) {
        $result = $exact
    } else {
        # 2. Match by longest prefix (case-insensitive)
        $byLenDesc = @($ConfModelNames | Sort-Object -Property Length -Descending)
        foreach ($cn in $byLenDesc) {
            if ($r.ToLowerInvariant().StartsWith($cn.ToLowerInvariant())) {
                $result = $cn
                break
            }
        }
        # 3. No match: $result stays $r
    }
    if ($CanonMap) { $CanonMap[$r] = $result }
    return $result
}

# Statistical helper: computes the median of a list of numeric values.
function Get-Median {
    param([double[]]$Values)
    if (-not $Values -or $Values.Count -eq 0) { return 0 }
    $sorted = @($Values | Sort-Object)
    $n = $sorted.Count
    if ($n % 2 -eq 1) {
        return [double]$sorted[[math]::Floor($n / 2)]
    } else {
        return ([double]$sorted[$n/2 - 1] + [double]$sorted[$n/2]) / 2.0
    }
}

# Statistical helper: computes the weighted median of values with their weights.
function Get-WeightedMedian {
    param($WeightedValues)
    if (-not $WeightedValues -or @($WeightedValues).Count -eq 0) { return 0 }
    $sorted = @(@($WeightedValues) | Sort-Object { $_.value })
    $totalWeight = ($sorted | Measure-Object -Property weight -Sum).Sum
    if ($totalWeight -eq 0) {
        return Get-Median ($sorted | ForEach-Object { [double]$_.value })
    }
    $cumulative = 0
    foreach ($item in $sorted) {
        $cumulative += $item.weight
        if ($cumulative -ge ($totalWeight / 2.0)) { return [double]$item.value }
    }
    return [double]$sorted[-1].value
}

# kNN helper: distance between two requests (model/size/quality/n) to find the most similar neighbors.
function Get-RequestDistance {
    param($Candidate, $Record)
    $wSize=3.0; $wQuality=3.0; $wNImages=2.0; $wInputImg=1.5; $wPromptLn=1.0; $wHour=0.5

    $recPixels = 0
    if ($Record.size -match '^(\d+)x(\d+)$') {
        $recPixels = ([int]$Matches[1] * [int]$Matches[2]) / 1000000.0
    }
    $candPixels = $Candidate.size_pixels / 1000000.0
    $dSize = [math]::Abs($candPixels - $recPixels)

    $recQuality = Get-QualityScore $Record.quality
    $dQuality   = [math]::Abs($Candidate.quality_score - $recQuality)
    $dNImages = [math]::Abs($Candidate.n_images - [int]$Record.n_images) / 4.0
    $recInputs = if ($Record.input_images_count) { [int]$Record.input_images_count } else { 0 }
    $dInputImg = [math]::Abs($Candidate.input_images_count - $recInputs) / 4.0
    $recPromptLen = if ($Record.prompt_len) { [int]$Record.prompt_len } else { 0 }
    $dPromptLn = [math]::Abs($Candidate.prompt_len - $recPromptLen) / 500.0

    $recHour = 12
    if ($Record.start -match '^(\d{1,2}):') { $recHour = [int]$Matches[1] }
    $hourDiff = [math]::Abs($Candidate.hour_of_day - $recHour)
    if ($hourDiff -gt 12) { $hourDiff = 24 - $hourDiff }
    $dHour = $hourDiff / 12.0

    $sumSq = ($wSize*$dSize)*($wSize*$dSize) + ($wQuality*$dQuality)*($wQuality*$dQuality) +
             ($wNImages*$dNImages)*($wNImages*$dNImages) + ($wInputImg*$dInputImg)*($wInputImg*$dInputImg) +
             ($wPromptLn*$dPromptLn)*($wPromptLn*$dPromptLn) + ($wHour*$dHour)*($wHour*$dHour)
    return [math]::Sqrt($sumSq)
}

# Estimates the generation time via kNN on the historical .stat records; falls back to a default estimate if data is missing.
function Get-TimeEstimate {
    param($Candidate, [string]$ModeKey, [string]$ModelName)

    $all = Import-TimeStats -MaxRecords $MaxStatsRecords
    # I canonicalize the model name of each record before comparing: the historical records
    # in the .stat may have a different case (e.g. "GPT-Image-2") and otherwise would not
    # match $ModelName (canonical from the .conf), losing good data for the estimate.
    $confModelNamesTE = @()
    if ($config -and $config.models) {
        $confModelNamesTE = @($config.models.PSObject.Properties.Name)
    }
    $canonMapTE = @{}
    $filtered = @($all | Where-Object {
        $recModelCanon = Get-CanonicalModelName -RawName ([string]$_.model) -ConfModelNames $confModelNamesTE -CanonMap $canonMapTE
        $_.mode -eq $ModeKey -and $recModelCanon -eq $ModelName -and [double]$_.actual -gt 0
    })
    $totalRecords = $filtered.Count

    if ($totalRecords -eq 0) {
        # No history for this model/mode: conservative estimate per quality
        $coldStartValue = switch ($Candidate.quality_score) {
            1 { 50  }    # low
            2 { 90  }    # medium
            3 { 240 }    # high
            default { 180 }
        }
        # Modalita' edit: piccolo bonus
        if ($ModeKey -eq "edit") { $coldStartValue = [math]::Round($coldStartValue * 1.15) }
        $adjusted = [math]::Round($coldStartValue * $Candidate.n_images)
        if ($adjusted -lt 30) { $adjusted = 30 }
        return [pscustomobject]@{
            estimated_single = $adjusted; tier = "cold_start"; sample_count = 0
            neighbors_used = 0; median = $null; range_min = $null; range_max = $null
            confidence = "very_low"
            explanation = (T 'estimate.cold_start' $ModelName $ModeKey $adjusted)
        }
    }

    if ($totalRecords -ge $KnnMinRecords) {
        $scored = foreach ($rec in $filtered) {
            $d = Get-RequestDistance -Candidate $Candidate -Record $rec
            [pscustomobject]@{
                record = $rec; distance = $d; recency = Get-RecencyWeight $rec.date
            }
        }
        $neighbors = @($scored | Sort-Object distance | Select-Object -First $KnnK)
        $weighted = @($neighbors | ForEach-Object {
            $similarityWeight = 1.0 / (1.0 + $_.distance)
            $combinedWeight   = $similarityWeight * $_.recency
            [pscustomobject]@{ value = [double]$_.record.actual; weight = $combinedWeight }
        })
        $median = Get-WeightedMedian $weighted
        $values = @($neighbors | ForEach-Object { [double]$_.record.actual })
        $rangeMin = ($values | Measure-Object -Minimum).Minimum
        $rangeMax = ($values | Measure-Object -Maximum).Maximum
        $avgDistance = ($neighbors | Measure-Object -Property distance -Average).Average
        $spread = if ($median -gt 0) { ($rangeMax - $rangeMin) / [double]$median } else { 1.0 }
        $confidence = if ($avgDistance -lt 2 -and $spread -lt 0.4) { "high" }
                      elseif ($avgDistance -lt 4 -and $spread -lt 0.7) { "medium" }
                      else { "low" }
        $estimatedSingle = [math]::Round($median * $Candidate.n_images)
        # NO 30s floor here: the kNN is based on real data. For fast models
        # (FLUX ~6-9s) a floor of 30 would distort the estimate by 200-300%. I keep only a
        # safety minimum of 1s to avoid 0/negatives from rounding.
        if ($estimatedSingle -lt 1) { $estimatedSingle = 1 }
        return [pscustomobject]@{
            estimated_single = $estimatedSingle; tier = "knn"; sample_count = $totalRecords
            neighbors_used = $neighbors.Count; median = [math]::Round($median, 1)
            range_min = [int]$rangeMin; range_max = [int]$rangeMax; confidence = $confidence
            explanation = (T 'estimate.knn' $neighbors.Count $ModelName $median $rangeMin $rangeMax)
        }
    }

    if ($totalRecords -ge $SegmentMinRecords) {
        $candBucket = $Candidate.size_bucket
        $candQualityScore = $Candidate.quality_score

        $segment = @($filtered | Where-Object {
            $w = 0; $h = 0
            if ($_.size -match '^(\d+)x(\d+)$') { $w = [int]$Matches[1]; $h = [int]$Matches[2] }
            (Get-SizeBucket -Width $w -Height $h) -eq $candBucket -and
            (Get-QualityScore $_.quality) -eq $candQualityScore
        })

        if ($segment.Count -ge $SegmentMinRecords) {
            $vals = @($segment | ForEach-Object { [double]$_.actual })
            $median = Get-Median $vals
            $rangeMin = ($vals | Measure-Object -Minimum).Minimum
            $rangeMax = ($vals | Measure-Object -Maximum).Maximum
            $estimatedSingle = [math]::Round($median * $Candidate.n_images)
            # No 30s floor: estimate based on the segment's real data (see kNN).
            if ($estimatedSingle -lt 1) { $estimatedSingle = 1 }
            return [pscustomobject]@{
                estimated_single = $estimatedSingle; tier = "segment_match"; sample_count = $totalRecords
                neighbors_used = $segment.Count; median = [math]::Round($median, 1)
                range_min = [int]$rangeMin; range_max = [int]$rangeMax; confidence = "medium"
                explanation = (T 'estimate.segment' $segment.Count $ModelName $candQualityScore $candBucket $median)
            }
        }
    }

    # Tier 3 EMA fallback
    # The historical gpt-image-2 data show that the time depends almost exclusively
    # on the quality (low ~50s, medium ~80s, high ~230s), while size and prompt_len have
    # very little impact. So we NO LONGER apply the artificial multipliers
    # based on sizeFactor or promptComplexity that produced unrealistic estimates.
    # We use the EMA as the base estimate, with a small modulation on quality and mode.
    $values = @($filtered | ForEach-Object { [double]$_.actual })
    $ema = if ($values.Count -gt 0) {
        $alpha = 0.4; $e = $values[0]
        for ($i = 1; $i -lt $values.Count; $i++) { $e = $alpha * $values[$i] + (1 - $alpha) * $e }
        $e
    } else { 120 }

    # Light modulation on quality: if the EMA was computed by averaging records with
    # different qualities, we apply a small correction. But if the kNN or segment tier
    # already filtered by quality, here we generally have homogeneous records.
    $qualityMultiplier = switch ($Candidate.quality_score) {
        1 { 0.25 }   # low: tipicamente ~1/4 di high
        2 { 0.40 }   # medium: tipicamente ~40% di high
        3 { 1.00 }   # high: nessun cambio
        default { 1.00 }
    }

    # If the average of the records already has a quality homogeneous with the candidate, the
    # correction is not needed (it would already be baked-in in the EMA). We apply it
    # only if the majority of the records have a quality different from the candidate.
    $candQ = $Candidate.quality_score
    $recordsSameQuality = @($filtered | Where-Object {
        (Get-QualityScore $_.quality) -eq $candQ
    }).Count
    $applyQualityMult = ($recordsSameQuality -lt ($filtered.Count / 2.0))

    $base = if ($applyQualityMult) { $ema * $qualityMultiplier } else { $ema }

    # Edit mode: historically slightly slower (10-15% more)
    if ($ModeKey -eq "edit") { $base = $base * 1.15 }

    $estimatedSingle = [math]::Round($base * $Candidate.n_images)
    # No 30s floor: estimate based on the EMA of the real data (see kNN).
    if ($estimatedSingle -lt 1) { $estimatedSingle = 1 }
    return [pscustomobject]@{
        estimated_single = $estimatedSingle; tier = "ema_fallback"; sample_count = $totalRecords
        neighbors_used = $values.Count; median = [math]::Round($ema, 1)
        range_min = [int]($values | Measure-Object -Minimum).Minimum
        range_max = [int]($values | Measure-Object -Maximum).Maximum
        confidence = "low"
        explanation = (T 'estimate.ema' $values.Count $ModelName ([math]::Round($ema,1)) $applyQualityMult $ModeKey)
    }
}

# Writes next to the generated image a .json file with the parameters needed to regenerate it (no secrets).
function Write-MetadataFile {
    param(
        [string]$ImagePath,
        [string]$PromptFull,
        [string]$ModelName,
        [string]$Deployment,
        [string]$Size,
        [string]$Quality,
        [string]$Format,
        [int]$NImages,
        [string]$Moderation,
        [string]$Background,
        [string]$InputFidelity,
        [string[]]$InputImagesOriginal,
        [string]$MaskPath,
        [int]$ImageIndex,
        [string]$Mode,
        $CostBreakdown
    )

    $jsonPath = [System.IO.Path]::ChangeExtension($ImagePath, ".json")
    $metadata = [ordered]@{
        generated_at        = (Get-Date).ToString("yyyy-MM-ddTHH:mm:ssK", [System.Globalization.CultureInfo]::InvariantCulture)
        script_version      = $script:ScriptVersion
        model               = $ModelName
        deployment          = $Deployment
        mode                = $Mode
        prompt              = $PromptFull
        prompt_length_chars = $PromptFull.Length
        parameters          = [ordered]@{
            size              = $Size
            quality           = $Quality
            format            = $Format
            n_images          = $NImages
            moderation        = $Moderation
            background        = $Background
            input_fidelity    = $InputFidelity
        }
        input_images        = @(if ($InputImagesOriginal) { $InputImagesOriginal } else { @() })
        mask                = if ($MaskPath) { $MaskPath } else { "" }
        image_index         = $ImageIndex
        cost = if ($CostBreakdown -and $CostBreakdown.pricing_available) {
            [ordered]@{
                input_tokens   = $CostBreakdown.input_tokens
                output_tokens  = $CostBreakdown.output_tokens
                total_tokens   = $CostBreakdown.total_tokens
                total_cost_usd = $CostBreakdown.total_cost_usd
                total_cost_eur = $CostBreakdown.total_cost_eur
            }
        } else { $null }
    }

    try {
        $metadata | ConvertTo-Json -Depth 10 | Set-Content -Path $jsonPath -Encoding UTF8 -ErrorAction Stop
        Write-Log (T 'metadata.saved' $jsonPath)
    }
    catch {
        Write-Log (T 'metadata.save_failed' $jsonPath ($_.Exception.Message)) -Level WARN
    }
}

function Invoke-ImageGeneration {
    <#
    Esegue una singola richiesta di generazione (generation o edit) con tutti i parametri
    gia' risolti dal chiamante. E' il cuore della generazione: costruisce il body adatto
    allo schema API del modello (openai-images / mai-images / bfl-flux), gestisce retry,
    failover sull'endpoint secondario, e due forme di AUTO-RECOVERY che evitano di far
    fallire una richiesta recuperabile:
      - feature non supportate: se l'API rifiuta background/input_fidelity/mask perche' il
        modello non li supporta davvero, il flag viene disattivato e la richiesta ritentata
        senza quel parametro (l'immagine esce comunque, pur senza la feature).
      - size non valida: se l'API rifiuta la dimensione, la size viene ridotta al valore
        valido piu' vicino (Get-DownscaledSize) usando $OperationalParams, e si ritenta.
    I ritentativi di auto-recovery NON consumano il budget di retry (sono correzioni, non
    errori transitori).

    Ritorna un oggetto con: Success, ImagesPaths[], Error, Cost, ActualDurationSec
    (piu' StartTime, Attempts e altri campi accessori). Usata da tutti i flussi che
    generano immagini: singola richiesta, batch, benchmark e adapter TUI.

    Parametri principali: i dati del modello (Deployment, ApiSchema, Endpoint, ApiKey...),
    i parametri di generazione (Prompt, Size, Quality, NImages...), i prezzi per il calcolo
    costi (PriceInputUsd/.../Pricing), e $OperationalParams (il blocco operationalParams del
    modello, usato dall'auto-recovery sulla size per sapere quali dimensioni sono valide).
    #>
    param(
        [string]$Prompt,
        [string]$Size,
        [string]$Quality,
        [string]$Format,
        [int]$NImages,
        [string]$Moderation,
        [string]$Background,
        [string]$InputFidelity,
        [string]$Mask,
        [string[]]$InputImages,
        [string]$OutputFolder,
        [string]$OutputMode,
        [string]$ModelName,
        [string]$Deployment,
        [string]$ApiSchema = "openai-images",
        [string]$AuthMode = "",        # "api-key"|"bearer"|"" (vuoto = default per schema)
        [string]$Endpoint,
        [string]$EditEndpoint,
        [string]$FailoverEndpoint = "",
        [string]$FailoverEditEndpoint = "",
        [string]$ApiKey,
        [int]$MaxRetries,
        [int]$TimeoutMinutes,
        [bool]$ApplyBackground,
        [bool]$ApplyInputFidelity,
        [bool]$ApplyModeration = $true,
        [bool]$UseMetadata,
        [string[]]$InputImagesOriginal,
        [string]$FileTemplate,
        [string]$Hash,
        [int]$Compression,
        [double]$PriceInputUsd,
        [double]$PriceOutputUsd,
        [double]$PriceImageUsd,
        $Pricing,
        [double]$EurRate,
        [int]$EstimatedTotal,
        $OperationalParams = $null,
        [scriptblock]$ProgressCallback = $null
    )

    $isEditMode = ($InputImages -and $InputImages.Count -gt 0)

    # "Recoverable" features: if the API rejects one of these parameters because the
    # model does not support it (user-error with a known "param"), instead of failing
    # we zero the corresponding flag and RETRY the same request without that
    # parameter (the image comes out, just without the feature). I use mutable LOCAL variables
    # initialized from the parameters: the body reads them instead of the original parameters,
    # so I can disable them at runtime between one attempt and the next.
    $bgActive   = [bool]$ApplyBackground
    $ifActive   = [bool]$ApplyInputFidelity
    $maskActive = ($Mask -and (Test-Path $Mask))
    # Size mutabile: se l'API rifiuta la size (troppo grande / non in lista), proviamo
    # to reduce it to the closest valid value (Get-DownscaledSize) and retry, instead
    # of failing. The body reads $sizeActive instead of $Size.
    $sizeActive = $Size
    # Tracks which features we have already auto-disabled, so as not to loop
    # endlessly on the same parameter.
    $featuresAutoDisabled = @{}
    # Anti-loop per il downscaling size: limito i tentativi di riduzione.
    $sizeDownscaleAttempts = 0

    # for the bfl-flux schema the editing happens on the SAME endpoint as the
    # generation (the reference images go in the body as base64), so we do NOT
    # use EditEndpoint. For openai-images the edit uses the dedicated /edits endpoint.
    if ($ApiSchema -eq "bfl-flux") {
        $primaryEndpoint  = $Endpoint
        $failoverEndpoint = $FailoverEndpoint
    } else {
        $primaryEndpoint  = if ($isEditMode) { $EditEndpoint } else { $Endpoint }
        $failoverEndpoint = if ($isEditMode) { $FailoverEditEndpoint } else { $FailoverEndpoint }
    }
    $targetEndpoint = $primaryEndpoint
    # Flag that tracks whether we have already tried the failover (so as not to do it twice)
    $failoverAlreadyTried = $false
    $modeKey = if ($isEditMode) { "edit" } else { "generation" }

    # split di Size "WIDTHxHEIGHT" in width/height per gli schemi che usano
    # campi separati nel body (mai-images, bfl-flux). Lo schema openai-images usa
    # direttamente la stringa Size. NB: derivati da $sizeActive (non $Size) e ricalcolati
    # at each attempt, because the downscaling auto-recovery can modify the size.
    $imgWidth = 0; $imgHeight = 0
    if ($sizeActive -match '^\s*(\d+)\s*[xX]\s*(\d+)\s*$') {
        $imgWidth  = [int]$Matches[1]
        $imgHeight = [int]$Matches[2]
    }

    $response = $null
    $successfulAttemptDuration = $null
    $successfulAttemptStart    = $null
    $attemptsToSuccess         = 0
    $estimatedTotal = $EstimatedTotal
    # Guard: $EstimatedTotal serves ONLY for the progress bar (percentage and current
    # estimated image), not for the real generation. If 0 or an invalid value arrives
    # (e.g. from the benchmark which does not compute an ex-ante estimate, or from a failed estimate), the
    # progress calculations would divide by zero producing NaN, and [math]::Min/Floor
    # would throw an exception that would make the whole generation fail. We use a reasonable
    # fallback so the bar shows a plausible progress and nothing crashes.
    if ($estimatedTotal -le 0) {
        $estimatedTotal = 60 * [math]::Max(1, $NImages)
    }
    $estimatedSingle = [math]::Round($estimatedTotal / [math]::Max(1, $NImages))
    if ($estimatedSingle -lt 1) { $estimatedSingle = 30 }

    # === ADAPTIVE TIMEOUT (robustness against network drops) ===
    # The fixed HTTP timeout (requestTimeoutMinutes, e.g. 10 min) is right as an upper
    # cap, but for a fast model (FLUX ~8s) waiting 10 minutes when the network
    # drops makes the script "hang" for a long time, with the bar projecting forward
    # endlessly. I therefore compute an EFFECTIVE timeout proportional to the estimate:
    #   adaptive = total_estimate * 5, with a minimum of 90s (so as not to penalize
    #   requests that are sometimes slower than usual) and a MAXIMUM equal to the
    #   conf timeout (TimeoutMinutes). This way a block from a lost network is
    #   detected in ~90s on fast models, while remaining generous on slow ones.
    $hardTimeoutSec = [int]$TimeoutMinutes * 60
    $adaptiveTimeoutSec = [math]::Max(90, $estimatedTotal * 5)
    if ($adaptiveTimeoutSec -gt $hardTimeoutSec) { $adaptiveTimeoutSec = $hardTimeoutSec }
    # Lo converto in minuti (frazionari) per il client HTTP del job.
    $effectiveTimeoutMinutes = [double]$adaptiveTimeoutSec / 60.0

    for ($i = 1; $i -le $MaxRetries; $i++) {

        Write-Log (T 'request.attempt' $i $MaxRetries)

        # Ricalcolo width/height dalla size CORRENTE ($sizeActive): l'auto-recovery del
        # downscaling may have reduced it after a failed attempt due to invalid size.
        if ($sizeActive -match '^\s*(\d+)\s*[xX]\s*(\d+)\s*$') {
            $imgWidth  = [int]$Matches[1]
            $imgHeight = [int]$Matches[2]
        }
        if ($isEditMode -and $ApiSchema -eq "mai-images") {
            # ===== EDIT mai-images: multipart/form-data verso endpoint /mai/v1/images/edits =====
            # Conforme alla doc Microsoft per MAI-Image-2.5 / 2.5-Flash: il body multipart
            # contains ONLY 'model', 'prompt' and 'image' with ONE single image, JPEG or PNG;
            # MAI NON accetta size/quality/n/moderation/background nel body di edit.
            # L'auth segue authMode: default mai-images = api-key, ma sovrascrivibile dal conf.
            $request = [ordered]@{
                endpoint       = $targetEndpoint
                authMode       = $AuthMode
                timeoutMinutes = $effectiveTimeoutMinutes
                contentType    = "multipart"
                fields         = @(
                    @{ name = "prompt"; value = $Prompt }
                    @{ name = "model";  value = $Deployment }
                )
                # MAI accepts ONE single image: the first in the list.
                # 'image' SINGULAR field, not 'image[]', as per the MAI doc.
                files          = @(
                    @{ name = "image"; path = $InputImages[0] }
                )
            }
        }
        elseif ($isEditMode -and $ApiSchema -eq "openai-images") {
            # ===== EDIT openai-images: multipart/form-data verso endpoint /edits =====
            # NB: historical behavior, the openai edit ALWAYS uses the api-key header
            # and does not apply the authMode override from the conf, unlike the generation.
            $editFields = [System.Collections.Generic.List[object]]::new()
            $editFields.Add(@{ name = "prompt";  value = $Prompt })
            $editFields.Add(@{ name = "model";   value = $Deployment })
            $editFields.Add(@{ name = "size";    value = $sizeActive })
            $editFields.Add(@{ name = "quality"; value = $Quality })
            $editFields.Add(@{ name = "n";       value = $NImages.ToString() })

            # moderation must be sent in edit too, not only in generation.
            # With moderation=auto, Foundry applies more restrictive safety filters that
            # degrade realistic faces. With moderation=low, the faces are preserved better.
            # It is the main fix for the face-similarity problem.
            if ($Moderation) {
                $editFields.Add(@{ name = "moderation"; value = $Moderation })
            }

            # explicit output_format in edit too for consistency with generation.
            # Foundry always returns PNG by default, but forcing it avoids ambiguity.
            $editFields.Add(@{ name = "output_format"; value = "png" })

            if ($bgActive) {
                $editFields.Add(@{ name = "background"; value = $Background })
            }
            if ($ifActive) {
                $editFields.Add(@{ name = "input_fidelity"; value = $InputFidelity })
            }

            # All the reference images: 'image[]' field repeated, mime from the extension.
            $editFiles = [System.Collections.Generic.List[object]]::new()
            foreach ($imgPath in $InputImages) {
                $editFiles.Add(@{ name = "image[]"; path = $imgPath })
            }

            # Mask: exactly the same format as the image, PNG with alpha channel.
            if ($maskActive) {
                $editFiles.Add(@{ name = "mask"; path = $Mask; mime = "image/png" })
            }

            $request = [ordered]@{
                endpoint       = $targetEndpoint
                authMode       = "api-key"
                timeoutMinutes = $effectiveTimeoutMinutes
                contentType    = "multipart"
                fields         = @($editFields)
                files          = @($editFiles)
            }
        }
        else {
            # ===== GENERATION (all schemas) + EDIT bfl-flux =====
            # body and auth header construction based on the model's API schema.
            # openai-images: 'api-key' header, body with size "WxH", quality, moderation, output_format
            # mai-images: 'api-key' header, body with separate width/height, model, prompt
            # bfl-flux: 'Authorization: Bearer' header, body with width/height, model, prompt, n;
            # in edit the references go as input_image/input_image_2/... (base64)
            #
            # NOTE: we always request output_format=png where supported. The local
            # conversion to jpg/webp happens afterward (compression block). For mai/flux the
            # output_format parameter does not exist: the server returns PNG by default.
            # authMode: authentication header. It has a DEFAULT per schema but is
            # OVERRIDABLE from the .conf (model's "authMode" field: "api-key"|"bearer").
            # This allows adding models of the same family/schema but with
            # a different auth WITHOUT touching the code. E.g.: the more recent MAIs speak the
            # standard openai-images protocol but on Foundry require 'Bearer'.
            $authMode = "api-key"   # generic default
            switch ($ApiSchema) {
                "mai-images" {
                    # MAI: minimal body with separate dimensions. width*height <= 1048576,
                    # each side >= 768 (model constraints, validated upstream).
                    $body = [ordered]@{
                        model  = $Deployment
                        prompt = $Prompt
                        width  = $imgWidth
                        height = $imgHeight
                    }
                    $authMode = "api-key"
                }
                "bfl-flux" {
                    # FLUX: body with separate dimensions + n. Bearer auth.
                    $body = [ordered]@{
                        model  = $Deployment
                        prompt = $Prompt
                        width  = $imgWidth
                        height = $imgHeight
                        n      = $NImages
                    }
                    # FLUX Edit: reference images as base64 in the body.
                    # Fields: input_image (1st), input_image_2, input_image_3, ... (up to 8).
                    if ($isEditMode -and $InputImages -and $InputImages.Count -gt 0) {
                        $refIndex = 0
                        foreach ($imgPath in $InputImages) {
                            $refIndex++
                            if ($refIndex -gt 8) { break }   # FLUX accetta max 8 reference
                            try {
                                $imgBytes = [System.IO.File]::ReadAllBytes($imgPath)
                                $imgB64   = [System.Convert]::ToBase64String($imgBytes)
                            } catch {
                                Write-Log (T 'edit.image_not_found' $imgPath) -Level ERROR
                                return [pscustomobject]@{
                                    Success = $false; ImagesPaths = @(); Error = "Impossibile leggere reference: $imgPath"
                                    Cost = $null; ActualDurationSec = $null; Attempts = 0
                                }
                            }
                            $fieldName = if ($refIndex -eq 1) { "input_image" } else { "input_image_$refIndex" }
                            $body[$fieldName] = $imgB64
                        }
                    }
                    $authMode = "bearer"
                }
                default {
                    # openai-images (gpt-image-*): historical behavior unchanged.
                    $body = [ordered]@{
                        model         = $Deployment
                        prompt        = $Prompt
                        size          = $sizeActive
                        quality       = $Quality
                        n             = $NImages
                        output_format = "png"
                    }
                    if ($ApplyModeration)    { $body.moderation = $Moderation }
                    if ($bgActive)           { $body.background = $Background }
                    if ($ifActive)           { $body.input_fidelity = $InputFidelity }
                    $authMode = "api-key"
                }
            }

            # authMode override from the .conf (if specified for the model). It prevails over the
            # per-schema default: so models of the same schema can use different auth
            # without code changes (e.g. recent MAIs on the openai schema with Bearer).
            if ($AuthMode -and ($AuthMode -eq "api-key" -or $AuthMode -eq "bearer")) {
                $authMode = $AuthMode
            }

            $bodyJson = $body | ConvertTo-Json -Depth 10

            $request = [ordered]@{
                endpoint       = $targetEndpoint
                authMode       = $authMode
                timeoutMinutes = $effectiveTimeoutMinutes
                contentType    = "json"
                bodyJson       = $bodyJson
            }
        }

        # ===== JOB HTTP UNIFICATO =====
        # The three request types (MAI edit, openai edit, JSON generation) share
        # the same HTTP skeleton: auth, timeout, sending, error classification and
        # dispose vivono QUI, in un punto solo. Le differenze (JSON vs multipart,
        # fields and files) are described by the $request built in the branches above, which
        # viaggia come stringa JSON per evitare le stranezze di serializzazione di
        # PowerShell sugli oggetti annidati attraverso il confine del job.
        $requestJson = $request | ConvertTo-Json -Depth 10

        $job = Start-Job -ScriptBlock {
            param($ApiKey, $RequestJson)

            Add-Type -AssemblyName System.Net.Http
            $client = $null; $payload = $null; $streamsToDispose = @()

            try {
                $req = $RequestJson | ConvertFrom-Json -ErrorAction Stop

                $client = [System.Net.Http.HttpClient]::new()
                # Authentication header:
                # api-key -> 'api-key: <key>' header (Azure OpenAI / MAI)
                # bearer  -> 'Authorization: Bearer' header (BFL/FLUX provider)
                if ($req.authMode -eq "bearer") {
                    $client.DefaultRequestHeaders.Authorization =
                        [System.Net.Http.Headers.AuthenticationHeaderValue]::new("Bearer", $ApiKey)
                } else {
                    $client.DefaultRequestHeaders.Add("api-key", $ApiKey)
                }
                $client.Timeout = [System.TimeSpan]::FromMinutes([double]$req.timeoutMinutes)

                if ($req.contentType -eq "multipart") {
                    # Multipart body: string fields + files, described by the request.
                    $payload = [System.Net.Http.MultipartFormDataContent]::new()
                    if ($req.fields) {
                        foreach ($f in @($req.fields)) {
                            $payload.Add([System.Net.Http.StringContent]::new([string]$f.value), [string]$f.name)
                        }
                    }
                    if ($req.files) {
                        foreach ($file in @($req.files)) {
                            $fileBytes  = [System.IO.File]::ReadAllBytes([string]$file.path)
                            $fileStream = [System.IO.MemoryStream]::new($fileBytes)
                            $streamsToDispose += $fileStream
                            $fileName = [System.IO.Path]::GetFileName([string]$file.path)
                            # Mime: explicit in the request if forced, e.g. the mask always
                            # image/png, otherwise inferred from the file extension.
                            $mime = [string]$file.mime
                            if (-not $mime) {
                                $ext  = [System.IO.Path]::GetExtension([string]$file.path).ToLower()
                                $mime = switch ($ext) {
                                    ".png"  { "image/png"  }
                                    ".jpg"  { "image/jpeg" }
                                    ".jpeg" { "image/jpeg" }
                                    default { throw "Estensione non supportata: $ext" }
                                }
                            }
                            $fileContent = [System.Net.Http.StreamContent]::new($fileStream)
                            $fileContent.Headers.ContentType = [System.Net.Http.Headers.MediaTypeHeaderValue]::new($mime)
                            $payload.Add($fileContent, [string]$file.name, $fileName)
                        }
                    }
                }
                else {
                    # JSON body for the generation and the bfl-flux edit.
                    $payload = [System.Net.Http.StringContent]::new([string]$req.bodyJson, [System.Text.Encoding]::UTF8, "application/json")
                }

                # HTTP call. HttpClient can rethrow AggregateException with
                # TaskCanceledException inside in case of timeout, or return $null
                # in alcuni edge case. Gestiamo entrambi.
                $result = $null
                try {
                    $result = $client.PostAsync([string]$req.endpoint, $payload).Result
                }
                catch {
                    $inner = $_.Exception
                    while ($inner.InnerException) { $inner = $inner.InnerException }
                    if ($inner -is [System.Threading.Tasks.TaskCanceledException] -or
                        $inner.Message -match "task was canceled|operation was canceled") {
                        throw "TIMEOUT: the request exceeded the timeout of $($req.timeoutMinutes) minutes without receiving a response from the server."
                    }
                    throw "Connection error: $($inner.Message)"
                }
                if ($null -eq $result) {
                    throw "Null response from server (connection interrupted likely)."
                }
                if ($null -eq $result.Content) {
                    throw "HTTP $([int]$result.StatusCode): response without body."
                }
                $responseBody = $result.Content.ReadAsStringAsync().Result

                if (-not $result.IsSuccessStatusCode) {
                    throw "HTTP $([int]$result.StatusCode) ($($result.StatusCode)) | Dettagli: $responseBody"
                }
                try {
                    $responseBody | ConvertFrom-Json -ErrorAction Stop
                } catch {
                    $preview = if ($responseBody.Length -gt 200) { $responseBody.Substring(0,200) + "..." } else { $responseBody }
                    throw "The server response is not valid JSON (possible proxy/gateway or truncated response). Response start: $preview"
                }
            }
            finally {
                if ($payload) { $payload.Dispose() }
                if ($client)  { $client.Dispose() }
                foreach ($strm in $streamsToDispose) { if ($strm) { $strm.Dispose() } }
            }
        } -ArgumentList $ApiKey, $requestJson

        # Progress bar intelligente
        $startAttempt = Get-Date
        # Variables for the recalibrate "sanity check" every 60 seconds
        $lastSanityCheck = 0
        $minSensibleEstimate = 60   # no gpt-image-2 request has ever been < 20s

        # Failsafe watchdog: the wait loop relies on the internal HTTP timeout of the
        # unified HTTP job (always present). As a safety belt, if the
        # job does not finish within TimeoutMinutes + 2 minutes of margin we stop it ourselves:
        # it avoids an infinite loop in case a future path forgot the timeout.
        $watchdogLimitSec = $adaptiveTimeoutSec + 120
        $watchdogTripped = $false

        while ($job.State -eq "Running") {
            $elapsed = (Get-Date) - $startAttempt
            $elapsedSec = [math]::Round($elapsed.TotalSeconds)

            # Watchdog: beyond the safety limit I stop the job and exit the loop.
            if ($elapsedSec -gt $watchdogLimitSec) {
                $watchdogTripped = $true
                try { Stop-Job $job -ErrorAction SilentlyContinue } catch { }
                break
            }

            # CASE 1: elapsed time has exceeded the estimate -> projection, BUT with a brake.
            # Without a brake, on a lost network the bar "runs away" endlessly (8s -> 536s -> ...).
            # I cap the projection at the EFFECTIVE timeout: the estimate never rises beyond the
            # point at which the timeout would fire anyway. Beyond a certain threshold
            # (80% of the timeout) I set a flag to show a waiting message
            # instead of inflating the number further.
            $waitingBeyondEstimate = $false
            if ($elapsedSec -gt $estimatedTotal) {
                $projected = [math]::Round($elapsedSec / 0.85)
                # Brake: not beyond the effective timeout (the tool that will stop the job).
                if ($projected -gt $adaptiveTimeoutSec) { $projected = $adaptiveTimeoutSec }
                if ($projected -gt $estimatedTotal) {
                    $estimatedTotal = $projected
                    $estimatedSingle = [math]::Round($estimatedTotal / $NImages)
                    if ($estimatedSingle -lt 1) { $estimatedSingle = 1 }
                }
                # If we are already beyond 80% of the timeout with no response, the
                # request is probably stuck (lost network / slow server): I report it.
                if ($elapsedSec -ge ($adaptiveTimeoutSec * 0.8)) {
                    $waitingBeyondEstimate = $true
                }
            }

            # CASE 2: estimate plainly too high (example: 29933s with elapsed 200s).
            # Every 60s we check: if the elapsed time is >= 90s and we are at <5%
            # of the estimate, then the estimate is inconsistent. We resize it to a
            # more reasonable value based on the elapsed time and quality.
            if ($elapsedSec -ge 90 -and ($elapsedSec - $lastSanityCheck) -ge 60) {
                $lastSanityCheck = $elapsedSec
                $percentSoFar = ($elapsedSec / $estimatedTotal) * 100
                if ($percentSoFar -lt 5 -and $estimatedTotal -gt 600) {
                    # Estimate evidently absurd: we recalculate on a reasonable value.
                    # We assume the remaining time is similar to the time already elapsed.
                    $newEstimate = [math]::Round($elapsedSec * 2.0)
                    if ($newEstimate -lt $minSensibleEstimate) { $newEstimate = $minSensibleEstimate }
                    $estimatedTotal = $newEstimate
                    $estimatedSingle = [math]::Round($estimatedTotal / $NImages)
                    if ($estimatedSingle -lt 30) { $estimatedSingle = 30 }
                }
            }

            # Defense in depth: denominators always > 0 (already guaranteed above, but
            # a runtime recalculation could have touched them). Avoids NaN/infinity.
            $denTotal  = if ($estimatedTotal  -gt 0) { $estimatedTotal }  else { 1 }
            $denSingle = if ($estimatedSingle -gt 0) { $estimatedSingle } else { 1 }
            $percent = [math]::Min(95, ($elapsedSec / $denTotal) * 100)
            $currentImage = [math]::Min($NImages, [math]::Floor($elapsedSec / $denSingle) + 1)
            $modeLabel = if ($isEditMode) { T 'progress.mode_editing' } else { T 'progress.mode_generation' }

            if ($ProgressCallback) {
                & $ProgressCallback $percent $currentImage $NImages $elapsedSec $estimatedTotal
            }
            elseif ($Verbosity -ne "ultrasilent") {
                # Normal status, or a waiting message if the request is
                # exceeding the timeout (probable slow/lost network): in that case I do not
                # show ever-larger numbers but a clear notice.
                $statusMsg = if ($waitingBeyondEstimate) {
                    T 'progress.status_waiting' $elapsedSec
                } else {
                    T 'progress.status' $elapsedSec $estimatedTotal
                }
                Write-Progress -Activity (T 'progress.activity' $currentImage $NImages $modeLabel $i) `
                               -Status $statusMsg `
                               -PercentComplete $percent
            }
            Start-Sleep -Milliseconds 500
        }
        if (-not $ProgressCallback -and $Verbosity -ne "ultrasilent") { Write-Progress -Activity (T 'progress.completed') -Completed }

        try {
            if ($watchdogTripped) {
                # I force the standard error path: the TIMEOUT prefix is
                # classified by ConvertFrom-ApiError as a transient error.
                throw "TIMEOUT: the job did not finish within the watchdog limit of $watchdogLimitSec seconds."
            }
            $response = Receive-Job $job -ErrorAction Stop
            Write-Log (T 'request.success')
            Remove-Job $job -Force
            $successfulAttemptDuration = [math]::Round(((Get-Date) - $startAttempt).TotalSeconds)
            $successfulAttemptStart = $startAttempt
            $attemptsToSuccess = $i
            break
        }
        catch {
            $rawMessage = $_.Exception.Message
            $errorBody = if ($_.ErrorDetails -and $_.ErrorDetails.Message) { $_.ErrorDetails.Message } else { $null }
            $fullMessage = if ($errorBody) { "$rawMessage | Dettagli: $errorBody" } else { $rawMessage }
            $translated = ConvertFrom-ApiError $fullMessage
            Write-Log (T 'request.error' $translated) -Level ERROR
            Remove-Job $job -Force

            # ERROR CLASSIFICATION:
            # - 401 Unauthorized: wrong API Key. Special case (see below): I ask
            # the user to re-enter it ONCE, then retry. If it fails again, exit.
            # - Other 4xx user-errors (400 invalid_value, 403, 404, 422):
            # they are "permanent" errors caused by invalid input. No point retrying,
            # the result would be identical. Immediate fail.
            # - 429 rate limit / 5xx server: transient errors, I retry with exponential delay.
            # - Network errors (timeout, ECONNREFUSED, DNS): transient, I retry.
            $is401Unauthorized = ($fullMessage -match 'HTTP 401|Unauthorized')
            $isUserError = (
                $fullMessage -match 'HTTP 400|BadRequest|invalid_value|invalid_request_error' -or
                $is401Unauthorized -or
                $fullMessage -match 'HTTP 403|Forbidden' -or
                $fullMessage -match 'HTTP 404|NotFound' -or
                $fullMessage -match 'HTTP 422|Unprocessable' -or
                $fullMessage -match 'image_generation_user_error'
            )
            $isTransientError = (
                $fullMessage -match 'HTTP 429|rate limit|TooManyRequests' -or  # rate limit
                $fullMessage -match 'HTTP 5\d\d' -or                            # 5xx server
                $fullMessage -match 'timeout|timed out' -or                     # timeout
                $fullMessage -match 'ECONNREFUSED' -or                          # connection refused
                $fullMessage -match 'Name or service not known|getaddrinfo' -or # DNS
                $fullMessage -match 'No such host'                              # DNS Windows
            )

            # 401 HANDLING (invalid or expired API Key):
            # The first time, I ask the user to re-enter it via a hidden prompt,
            # encode it in the .conf, update $ApiKey in memory and retry ONCE WITHOUT
            # consuming a retry. If it fails again, immediate fail.
            if ($is401Unauthorized -and -not $script:ApiKeyReprompted) {
                Write-Log (T 'apikey.http401_reprompt') -Level ERROR
                try {
                    $newPlainKey = Read-ApiKeyFromUser -ModelName $ModelName
                    if ($newPlainKey) {
                        $newEncoded = Protect-ApiKey -PlainText $newPlainKey
                        # I update the .conf
                        $cfgUpdate = (Get-Content $script:ConfigFile -Raw -Encoding UTF8 -ErrorAction Stop) | ConvertFrom-Json -ErrorAction Stop
                        if ($cfgUpdate.models.$ModelName) {
                            $cfgUpdate.models.$ModelName.apiKey = $newEncoded
                            $cfgUpdate | ConvertTo-Json -Depth 10 | Set-Content -Path $script:ConfigFile -Encoding UTF8
                            $method = if ($script:IsWin) { "DPAPI" } else { "Base64" }
                            Write-Log (T 'apikey.http401_reencoded' $method)
                        }
                        # I update the API Key used in the current call (local + script scope)
                        $ApiKey = $newPlainKey
                        $script:ApiKey = $newPlainKey
                        $script:ApiKeyReprompted = $true   # flag globale per non chiedere di nuovo
                        $i--   # Non consumo un retry: e' un caso speciale di recovery
                        continue
                    } else {
                        Write-Log (T 'apikey.http401_no_key_given') -Level ERROR
                        exit 1
                    }
                } catch {
                    Write-Log (T 'apikey.http401_reprompt_error' ($_.Exception.Message)) -Level ERROR
                    exit 1
                }
            } elseif ($is401Unauthorized -and $script:ApiKeyReprompted) {
                Write-Log (T 'apikey.http401_second_fail') -Level ERROR
                exit 1
            }

            # AUTO-DISABLE feature in config if the API reports an unsupported feature.
            # Typical example: -Background transparent on a model with supportsBackground=true
            # in the .conf but the feature is not actually active on the Foundry deployment.
            if ($isUserError) {
                # SIZE AUTO-RECOVERY: if the error concerns the dimension (size not in
                # the list, excessive area/side), I try to reduce the size to the closest valid
                # value for this model and retry, instead of failing. I recognize
                # the size error from the typical API messages (size/dimensions/pixel).
                $isSizeError = ($fullMessage -match '(?i)\b(size|dimension|dimensions|pixel|pixels|resolution|width|height)\b' -and
                                $fullMessage -match '(?i)(invalid|unsupported|not support|exceed|maximum|too large|supported sizes)')
                if ($isSizeError -and $sizeDownscaleAttempts -lt 3) {
                    $newSize = Get-DownscaledSize -OpParams $OperationalParams -Size $sizeActive
                    if ($newSize -and $newSize -ine $sizeActive) {
                        $sizeDownscaleAttempts++
                        Write-Log (T 'request.size_downscale' $ModelName $sizeActive $newSize) -Level WARN
                        $sizeActive = $newSize
                        # I retry without consuming the budget (it is a correction).
                        $i--
                        Start-Sleep -Milliseconds 200
                        continue
                    }
                }

                # I extract the "param" from the API JSON message
                $disabledFeature = $null
                if ($fullMessage -match '"param"\s*:\s*"background"') {
                    $disabledFeature = "supportsBackground"
                } elseif ($fullMessage -match '"param"\s*:\s*"input_fidelity"') {
                    $disabledFeature = "supportsInputFidelity"
                } elseif ($fullMessage -match '"param"\s*:\s*"mask"') {
                    $disabledFeature = "supportsInpainting"
                }

                if ($disabledFeature) {
                    Write-Log (T 'request.feature_unsupported_disable' $ModelName $disabledFeature $disabledFeature) -Level WARN
                    try {
                        $cfgUpdate = (Get-Content $script:ConfigFile -Raw -Encoding UTF8 -ErrorAction Stop) | ConvertFrom-Json -ErrorAction Stop
                        if ($cfgUpdate.models.$ModelName) {
                            if ($cfgUpdate.models.$ModelName.PSObject.Properties.Name -contains $disabledFeature) {
                                $cfgUpdate.models.$ModelName.$disabledFeature = $false
                            } else {
                                $cfgUpdate.models.$ModelName | Add-Member -NotePropertyName $disabledFeature -NotePropertyValue $false -Force
                            }
                            $cfgUpdate | ConvertTo-Json -Depth 10 | Set-Content -Path $script:ConfigFile -Encoding UTF8
                            Write-Log (T 'request.config_updated' $ModelName $disabledFeature)
                        }
                    } catch {
                        Write-Log (T 'request.config_update_failed' ($_.Exception.Message)) -Level WARN
                    }

                    # AUTO-RECOVERY: instead of failing, I disable the problematic feature
                    # and RETRY the same request without that parameter. The image is
                    # generated anyway (just WITHOUT the feature: e.g. no transparent background,
                    # or global edit instead of localized if it was a mask). The WARN warns
                    # clearly that the result will not include the requested feature.
                    # I retry only if: the feature is one of the "recoverable" ones, I have not
                    # already disabled it before (anti-loop), and I still have attempts available.
                    $canRecover = $false
                    if (-not $featuresAutoDisabled.ContainsKey($disabledFeature)) {
                        switch ($disabledFeature) {
                            "supportsBackground"     { $bgActive = $false;   $canRecover = $true }
                            "supportsInputFidelity"  { $ifActive = $false;   $canRecover = $true }
                            "supportsInpainting"     { $maskActive = $false; $canRecover = $true }
                        }
                    }

                    if ($canRecover) {
                        $featuresAutoDisabled[$disabledFeature] = $true
                        Write-Log (T 'request.feature_retry_without' $disabledFeature) -Level WARN
                        # I repeat the attempt WITHOUT consuming it: this is not a transient
                        # error but a correction, so it must not eat into the
                        # retry budget. I decrement $i so the for loop brings it back to the value.
                        $i--
                        Start-Sleep -Milliseconds 200
                        continue
                    }
                }

                # Non-recoverable user error (or feature already disabled without success):
                # NON ritento, fail immediato con messaggio chiaro.
                Write-Log (T 'request.user_error_stop') -Level ERROR
                return [pscustomobject]@{
                    Success = $false
                    ImagesPaths = @()
                    Error = $translated
                    Cost = $null
                    ActualDurationSec = 0
                    Attempts = $i
                }
            }

            # FAILOVER LOGIC: if the primary endpoint fails with transient errors
            # (HTTP 5xx, timeout, ECONNREFUSED, DNS failure), we try the failover ONCE
            # before continuing with the normal retry policy.
            if ($isTransientError -and $failoverEndpoint -and -not $failoverAlreadyTried) {
                Write-Log (T 'request.failover') -Level WARN
                $targetEndpoint = $failoverEndpoint
                $failoverAlreadyTried = $true
                # I retry immediately WITHOUT delay and WITHOUT consuming a retry (decrement $i)
                $i--
                continue
            }

            if ($i -eq $MaxRetries) {
                return [pscustomobject]@{
                    Success = $false
                    ImagesPaths = @()
                    Error = $translated
                    Cost = $null
                    ActualDurationSec = 0
                    Attempts = $i
                }
            }
            $baseDelay = [math]::Min(60, [math]::Pow(2, $i))
            $delay     = $baseDelay + (Get-Random -Minimum 0 -Maximum 6)
            Write-Log (T 'request.wait_retry' $delay)
            Start-Sleep -Seconds $delay
        }
    }

    if (-not $response -or -not $response.data -or @($response.data).Count -eq 0) {
        Write-Log (T 'request.empty_response') -Level ERROR
        return [pscustomobject]@{
            Success = $false; ImagesPaths = @(); Error = "Risposta vuota dall'API"
            Cost = $null; ActualDurationSec = $successfulAttemptDuration; Attempts = $attemptsToSuccess
        }
    }

    # Cost calculation. token-based schema (6/2 meters) via response.usage.
    # for per-megapixel models (FLUX) the cost derives from the DIMENSIONS
    # of the generated image and of the references, not from the tokens. Here we calculate the
    # megapixels of the reference images (rounded up) for the FLUX edit.
    $referenceMpList = @()
    if ($ApiSchema -eq "bfl-flux" -and $isEditMode -and $InputImages -and $InputImages.Count -gt 0) {
        foreach ($refPath in $InputImages) {
            $refMp = 1
            try {
                # I measure the real dimensions of the reference image (post-resize,
                # since ConvertTo-ValidImage has already resized them if necessary).
                Add-Type -AssemblyName System.Drawing -ErrorAction SilentlyContinue
                $img = [System.Drawing.Image]::FromFile($refPath)
                try {
                    $refMp = [int][math]::Ceiling(($img.Width * $img.Height) / 1000000.0)
                    if ($refMp -lt 1) { $refMp = 1 }
                } finally { $img.Dispose() }
            } catch {
                # System.Drawing not available (non-Windows) or unreadable file:
                # I assume 1 MP as a minimum conservative estimate.
                $refMp = 1
            }
            $referenceMpList += $refMp
        }
    }

    $cost = Get-CostBreakdown -Usage $response.usage `
                              -Pricing $Pricing `
                              -EurRate $EurRate `
                              -GenWidth $imgWidth `
                              -GenHeight $imgHeight `
                              -NImages $NImages `
                              -ReferenceMpList $referenceMpList `
                              -PromptText $Prompt `
                              -Quality $Quality

    # Saving the images
    $batchTimestamp = Get-Date -Format yyyyMMdd_HHmmss
    $savedPaths = @()

    for ($idx = 0; $idx -lt $response.data.Count; $idx++) {
        $base64 = $response.data[$idx].b64_json
        if (-not $base64) {
            Write-Log (T 'save.no_b64' $idx) -Level WARN
            continue
        }

        if ($OutputMode -eq "base64") {
            $fileName = Get-OutputFileName -Template $FileTemplate -Timestamp $batchTimestamp -Index $idx -Hash $Hash -Extension "txt"
            $filePath = Join-Path $OutputFolder $fileName
            Set-Content -Path $filePath -Value $base64 -Encoding UTF8
            Write-Log (T 'save.base64_saved' $filePath)
            $savedPaths += $filePath
            continue
        }

        try {
            $bytes = [Convert]::FromBase64String($base64)
        }
        catch {
            Write-Log (T 'save.invalid_base64' $idx ($_.Exception.Message)) -Level WARN
            continue
        }

        if ($Format -eq "jpg" -or $Format -eq "webp") {
            # System.Drawing e' richiesto per la compressione jpg/webp e funziona
            # only on Windows. On other OSes we save as PNG with the correct extension
            # e avvertiamo l'utente.
            if (-not $script:IsWin) {
                Write-Log (T 'save.compression_unsupported_os' $Format) -Level WARN
                $fileName = Get-OutputFileName -Template $FileTemplate -Timestamp $batchTimestamp -Index $idx -Hash $Hash -Extension "png"
                $filePath = Join-Path $OutputFolder $fileName
                [IO.File]::WriteAllBytes($filePath, $bytes)
                Write-Log (T 'save.image_saved' $filePath)
                $savedPaths += $filePath
                if ($UseMetadata) {
                    Write-MetadataFile -ImagePath $filePath -PromptFull $Prompt -ModelName $ModelName `
                                       -Deployment $Deployment -Size $Size -Quality $Quality -Format "png" `
                                       -NImages $NImages -Moderation $Moderation -Background $Background `
                                       -InputFidelity $InputFidelity -InputImagesOriginal $InputImagesOriginal `
                                       -MaskPath $Mask -ImageIndex $idx -Mode $modeKey -CostBreakdown $cost
                }
                continue
            }

            $imageObj = $null; $params = $null; $memStream = $null
            try {
                $memStream = [System.IO.MemoryStream]::new($bytes)
                $imageObj  = [System.Drawing.Image]::FromStream($memStream)
                # Correct MimeType per format: the GDI+ JPEG codec exposes "image/jpeg"
                # (NOT "image/jpg"), so we map jpg->jpeg, otherwise the codec is
                # never found and jpg ends up by mistake in the PNG fallback.
                $targetMime = switch ($Format) {
                    "jpg"   { "image/jpeg" }
                    "jpeg"  { "image/jpeg" }
                    "webp"  { "image/webp" }
                    default { "image/$Format" }
                }
                $codec = [System.Drawing.Imaging.ImageCodecInfo]::GetImageEncoders() |
                         Where-Object { $_.MimeType -eq $targetMime }
                if (-not $codec) { throw "Codec for format '$Format' (MimeType $targetMime) not available on this system." }
                $params = New-Object System.Drawing.Imaging.EncoderParameters(1)
                $qualityEncoder = [System.Drawing.Imaging.Encoder]::Quality
                $params.Param[0] = New-Object System.Drawing.Imaging.EncoderParameter($qualityEncoder, [int]$Compression)

                $fileName = Get-OutputFileName -Template $FileTemplate -Timestamp $batchTimestamp -Index $idx -Hash $Hash -Extension $Format
                $filePath = Join-Path $OutputFolder $fileName
                $imageObj.Save($filePath, $codec, $params)
                Write-Log (T 'save.image_compressed' $Compression $filePath)
                $savedPaths += $filePath

                if ($UseMetadata) {
                    Write-MetadataFile -ImagePath $filePath -PromptFull $Prompt -ModelName $ModelName `
                                       -Deployment $Deployment -Size $Size -Quality $Quality -Format $Format `
                                       -NImages $NImages -Moderation $Moderation -Background $Background `
                                       -InputFidelity $InputFidelity -InputImagesOriginal $InputImagesOriginal `
                                       -MaskPath $Mask -ImageIndex $idx -Mode $modeKey -CostBreakdown $cost
                }
                continue
            }
            catch {
                # Compression failed (typically WEBP on Windows without a GDI+ codec).
                # The raw bytes from the API are PNG (Foundry always returns PNG via b64_json),
                # so we save with a .png extension so as not to mislead the user into thinking they have
                # davvero un file WEBP/JPG compresso.
                $isCodecError = ($_.Exception.Message -match 'Codec for format|encoder' -or
                                 $_.Exception.Message -match 'GenericError' -or
                                 $_.Exception.Message -match 'not supported on this platform|PlatformNotSupported|System.Drawing')
                if ($isCodecError -and $Format -ne "png") {
                    # Intended fallback (zero dependencies): I save as PNG. I show the warning ONCE
                    # per run, and only if there is NO CLI tool
                    # able to convert after saving (see block below).
                    $cliCanConvert = (-not $script:IsWin) -and (
                        ((Get-ImageCliTool).Kind -in @('magick','convert')) -or
                        ((Get-ImageCliTool).Kind -eq 'sips' -and $Format -eq 'jpg'))
                    if (-not $script:WebPFallbackUsed -and -not $cliCanConvert) {
                        Write-Log (T 'save.codec_unavailable' $Format) -Level WARN
                        $script:WebPFallbackUsed = $true
                    }
                } else {
                    Write-Log (T 'save.compression_failed' ($_.Exception.Message)) -Level WARN
                }
            }
            finally {
                if ($imageObj)  { $imageObj.Dispose() }
                if ($params)    { $params.Dispose() }
                if ($memStream) { $memStream.Dispose() }
            }
        }

        # Fallback: I save the raw bytes (they are PNG from Foundry) with a .png extension
        # instead of keeping the requested extension (.webp/.jpg) which would be misleading.
        $actualExtension = if ($Format -eq "jpg" -or $Format -eq "webp") { "png" } else { $Format }
        $fileName = Get-OutputFileName -Template $FileTemplate -Timestamp $batchTimestamp -Index $idx -Hash $Hash -Extension $actualExtension
        $filePath = Join-Path $OutputFolder $fileName
        [IO.File]::WriteAllBytes($filePath, $bytes)

        # Cross-platform conversion of the output format: if the user requested
        # jpg/webp and a CLI tool exists on the system (sips on macOS, ImageMagick
        # on Linux), I convert the just-written PNG to the requested format. webp with
        # sips is not reliable, so with sips I only convert jpg; without tools
        # the PNG remains (with the one-off warning from the block above).
        if (-not $script:IsWin -and ($Format -eq "jpg" -or $Format -eq "webp")) {
            $convTool = Get-ImageCliTool
            $convOk = ($convTool.Kind -in @('magick','convert')) -or ($convTool.Kind -eq 'sips' -and $Format -eq 'jpg')
            if ($convOk) {
                $convName = Get-OutputFileName -Template $FileTemplate -Timestamp $batchTimestamp -Index $idx -Hash $Hash -Extension $Format
                $convPath = Join-Path $OutputFolder $convName
                if ($convTool.Kind -eq 'sips') {
                    & sips -s format jpeg $filePath --out $convPath 2>$null | Out-Null
                } else {
                    & $convTool.Bin $filePath -quality ([int]$Compression) $convPath 2>$null | Out-Null
                }
                if ($LASTEXITCODE -eq 0 -and (Test-Path $convPath)) {
                    Remove-Item $filePath -ErrorAction SilentlyContinue
                    $filePath = $convPath
                    $actualExtension = $Format
                }
            }
        }

        Write-Log (T 'save.image_saved' $filePath)
        $savedPaths += $filePath

        if ($UseMetadata) {
            Write-MetadataFile -ImagePath $filePath -PromptFull $Prompt -ModelName $ModelName `
                               -Deployment $Deployment -Size $Size -Quality $Quality -Format $actualExtension `
                               -NImages $NImages -Moderation $Moderation -Background $Background `
                               -InputFidelity $InputFidelity -InputImagesOriginal $InputImagesOriginal `
                               -MaskPath $Mask -ImageIndex $idx -Mode $modeKey -CostBreakdown $cost
        }
    }

    return [pscustomobject]@{
        Success = $true
        ImagesPaths = $savedPaths
        Error = $null
        Cost = $cost
        ActualDurationSec = $successfulAttemptDuration
        Attempts = $attemptsToSuccess
        StartTime = $successfulAttemptStart
    }
}

# Batch orchestration: reads the request file, runs each element (sequential or parallel) and aggregates the results.
function Invoke-BatchProcessing {
    param(
        [string]$BatchFilePath,
        [int]$Threads
    )

    if (-not (Test-Path $BatchFilePath)) {
        Write-Log (T 'batch.file_not_found' $BatchFilePath) -Level ERROR
        exit 1
    }

    try {
        $batchContent = Get-Content $BatchFilePath -Raw -Encoding UTF8 -ErrorAction Stop
        $batchItems   = $batchContent | ConvertFrom-Json -ErrorAction Stop
    }
    catch {
        Write-Log (T 'batch.parse_error' $BatchFilePath ($_.Exception.Message)) -Level ERROR
        exit 1
    }

    if (-not $batchItems -or @($batchItems).Count -eq 0) {
        Write-Log (T 'batch.empty_or_not_array') -Level ERROR
        exit 1
    }

    # Limite max 99 richieste per batch. La numerazione zero-padded a 2 cifre
    # (01..99) rende l'output del report perfettamente allineato; oltre le 99 richieste
    # one would need to extend to 3 digits with more complex visual and parsing costs.
    # For larger scenarios, split into several separate batch files.
    if (@($batchItems).Count -gt 99) {
        Write-Log (T 'batch.limit_exceeded' (@($batchItems).Count)) -Level ERROR
        exit 1
    }

    # STRUCTURAL validation of each batch entry BEFORE starting to process:
    #  - each entry must have a 'prompt' (text) or a 'promptFile' (path);
    #  - if it has 'promptFile' or 'inputImages', the referenced files must exist.
    # This way a malformed batch fails immediately with a clear message indicating the
    # problematic entry, instead of starting the generations and failing halfway.
    $batchErrors = @()
    $idx0 = 0
    foreach ($bi in @($batchItems)) {
        $idx0++
        $hasPrompt     = ($bi.prompt -and ([string]$bi.prompt).Trim() -ne "")
        $hasPromptFile = ($bi.promptFile -and ([string]$bi.promptFile).Trim() -ne "")
        if (-not $hasPrompt -and -not $hasPromptFile) {
            $batchErrors += (T 'batch.item_no_prompt' $idx0)
        }
        if ($hasPromptFile -and -not (Test-Path -LiteralPath ([string]$bi.promptFile) -PathType Leaf)) {
            $batchErrors += (T 'batch.item_promptfile_missing' $idx0 ([string]$bi.promptFile))
        }
        if ($bi.inputImages) {
            foreach ($bimg in @($bi.inputImages)) {
                if (-not $bimg -or ([string]$bimg).Trim() -eq "") { continue }
                if (-not (Test-Path -LiteralPath ([string]$bimg) -PathType Leaf)) {
                    $batchErrors += (T 'batch.item_image_missing' $idx0 ([string]$bimg))
                }
            }
        }
        if ($bi.n) {
            $niTmp = 0
            if (-not [int]::TryParse([string]$bi.n, [ref]$niTmp) -or $niTmp -lt 1) {
                $batchErrors += (T 'batch.item_bad_n' $idx0 ([string]$bi.n))
            }
        }
    }
    if ($batchErrors.Count -gt 0) {
        foreach ($be in $batchErrors) { Write-Log $be -Level ERROR }
        Write-Log (T 'batch.validation_failed' ($batchErrors.Count)) -Level ERROR
        exit 1
    }

    # Progressive number if not already present. The IDs go from 1 to 99.
    $batchItems = @($batchItems)
    $numberedItems = @()
    for ($i = 0; $i -lt $batchItems.Count; $i++) {
        $item = $batchItems[$i]
        $id = if ($item.id) { [int]$item.id } else { $i + 1 }
        if ($id -lt 1 -or $id -gt 99) {
            Write-Log (T 'batch.id_out_of_range' $id) -Level ERROR
            exit 1
        }
        $numberedItems += [pscustomobject]@{
            id = $id
            item = $item
        }
    }

    Write-Log (T 'batch.processing' ($numberedItems.Count) $Threads)

    # Budget guardrail for the BATCH: if -Budget is specified, it sums
    # the estimates of all the items and blocks if total_max > budget. NB: the batch
    # budget is considered as "maximum cumulative spend", not per single item.
    if ($null -ne $Budget) {
        $batchTotalEur = 0.0
        $batchTotalUsd = 0.0
        foreach ($entry in $numberedItems) {
            $itemPrompt = $entry.item.prompt
            $itemSize    = if ($entry.item.size) { $entry.item.size } else { $Size }
            $itemQuality = if ($entry.item.quality) { $entry.item.quality } else { $Quality }
            $itemN       = if ($entry.item.n) { [int]$entry.item.n } else { $NImages }
            $itemRefs    = if ($entry.item.inputImages) { @($entry.item.inputImages).Count } else { 0 }
            $est = Get-EstimatedCost -Prompt $itemPrompt -NImages $itemN `
                                     -InputImagesCount $itemRefs `
                                     -Quality $itemQuality -Size $itemSize `
                                     -PriceInputUsd $priceInputUsd -PriceOutputUsd $priceOutputUsd `
                                     -PriceImageUsd $priceImageUsd -Pricing $modelPricing `
                                     -EurRate $UsdToEurRate
            $batchTotalUsd += $est.CostUsd
            $batchTotalEur += $est.CostEur
        }
        $estimateBatch = [pscustomobject]@{
            CostUsd = $batchTotalUsd
            CostEur = $batchTotalEur
        }
        $budgetOk = Test-BudgetGuardrail -Budget $Budget -Currency $DefaultCurrency -Estimate $estimateBatch
        if (-not $budgetOk) {
            exit 1
        }
    }

    $batchStart = Get-Date
    $results = @()

    # Parallel execution with ForEach-Object -Parallel (PowerShell 7+)
    # I must pass ALL the context parameters via $using:
    $usingState = @{
        Prompt = $Prompt; Size = $Size; Quality = $Quality; Format = $Format
        NImages = $NImages; Moderation = $Moderation; Background = $Background
        InputFidelity = $InputFidelity; Mask = $Mask; InputImages = $InputImages
        OutputFolder = $OutputFolder; OutputMode = $OutputMode
        ModelLogicalName = $ModelLogicalName; Deployment = $Deployment
        ApiSchema = $apiSchema
        AuthMode = $authMode
        Endpoint = $modelConfig.endpoint; EditEndpoint = $modelConfig.editEndpoint
        FailoverEndpoint = if ($modelConfig.failoverEndpoint) { $modelConfig.failoverEndpoint } else { "" }
        FailoverEditEndpoint = if ($modelConfig.failoverEditEndpoint) { $modelConfig.failoverEditEndpoint } else { "" }
        ApiKey = $ApiKey; MaxRetries = $MaxRetries; RequestTimeoutMinutes = $RequestTimeoutMinutes
        applyBackground = $applyBackground; applyInputFidelity = $applyInputFidelity
        applyModeration = $applyModeration
        useMetadata = $useMetadata; FileTemplate = $FileTemplate
        DefaultOutputCompression = [int]$config.defaultOutputCompression
        PriceInputUsd = $priceInputUsd; PriceOutputUsd = $priceOutputUsd
        PriceImageUsd = $priceImageUsd; Pricing = $modelPricing; EurRate = $UsdToEurRate
        ModelHasPricing = ($null -ne $modelPricing)
        OperationalParams = $modelConfig.operationalParams
        MaxImageDimension = $MaxImageDimension
        MaxImageArea = $MaxImageArea
        ScriptPath = $PSCommandPath
        Config = $config
    }

    # Sequential or parallel iteration based on $Threads
    if ($Threads -le 1) {
        # Sequential (simpler and more predictable for debugging)
        foreach ($entry in $numberedItems) {
            $itemResult = Invoke-BatchItem -Entry $entry -State $usingState
            $results += $itemResult
        }
    } else {
        # Parallel: ForEach-Object -Parallel of PS7
        # NOTE: in parallel, logging happens from different threads and the order
        # of the lines in the .log can be interleaved. It is a known characteristic.
        $results = $numberedItems | ForEach-Object -Parallel {
            $entry = $_
            $state = $using:usingState

            # I must redeclare the functions needed in the thread scope.
            # Alternatively I could call the main script recursively,
            # but it would be more fragile. For simplicity: the thread makes a
            # recursive call to New-GPTImage.ps1 itself, with specific arguments.

            $itemArgs = @(
                "-Prompt", $entry.item.prompt
                "-Verbosity", "silent"  # output minimo per non spammare
            )
            # I apply the item parameters if present, otherwise the state defaults
            if ($entry.item.size)        { $itemArgs += @("-Size", $entry.item.size) }
            elseif ($state.Size)         { $itemArgs += @("-Size", $state.Size) }
            if ($entry.item.quality)     { $itemArgs += @("-Quality", $entry.item.quality) }
            elseif ($state.Quality)      { $itemArgs += @("-Quality", $state.Quality) }
            if ($entry.item.format)      { $itemArgs += @("-Format", $entry.item.format) }
            elseif ($state.Format)       { $itemArgs += @("-Format", $state.Format) }
            if ($entry.item.n)           { $itemArgs += @("-NImages", [string]$entry.item.n) }
            if ($entry.item.inputImages -and $entry.item.inputImages.Count -gt 0) {
                $itemArgs += @("-InputImages") + @($entry.item.inputImages)
            }
            if ($entry.item.mask)        { $itemArgs += @("-Mask", $entry.item.mask) }
            if ($state.useMetadata)      { $itemArgs += @("-Metadata", "true") }
            if ($state.OutputFolder)     { $itemArgs += @("-OutputFolder", $state.OutputFolder) }
            if ($state.ModelLogicalName) { $itemArgs += @("-Model", $state.ModelLogicalName) }

            $itemStart = Get-Date
            try {
                $output = & pwsh -NoProfile -ExecutionPolicy Bypass -File $state.ScriptPath @itemArgs 2>&1
                $exitCode = $LASTEXITCODE
                $itemEnd = Get-Date
                [pscustomobject]@{
                    Id = $entry.id
                    Success = ($exitCode -eq 0)
                    DurationSec = [math]::Round(($itemEnd - $itemStart).TotalSeconds, 1)
                    ExitCode = $exitCode
                    Output = ($output -join "`n")
                    Error = if ($exitCode -ne 0) { "exit code $exitCode" } else { "" }
                }
            }
            catch {
                $itemEnd = Get-Date
                [pscustomobject]@{
                    Id = $entry.id
                    Success = $false
                    DurationSec = [math]::Round(($itemEnd - $itemStart).TotalSeconds, 1)
                    ExitCode = -1
                    Output = ""
                    Error = $_.Exception.Message
                }
            }
        } -ThrottleLimit $Threads
    }

    $batchEnd = Get-Date
    $batchDuration = $batchEnd - $batchStart
    $batchDurStr = if ($batchDuration.TotalMinutes -ge 1) {
        "$([math]::Floor($batchDuration.TotalMinutes))m $([math]::Round($batchDuration.Seconds))s"
    } else {
        "$([math]::Round($batchDuration.TotalSeconds))s"
    }

    $okCount = @($results | Where-Object { $_.Success }).Count
    $koCount = @($results | Where-Object { -not $_.Success }).Count
    $totalImages = if ($Threads -le 1) {
        ($results | ForEach-Object { @($_.ImagesPaths).Count } | Measure-Object -Sum).Sum
    } else { 0 }   # in parallelo non abbiamo il count diretto; segnalato come N/D

    # Calculate the batch's total cost (in both currencies, for the log; on screen local only)
    $totalCostUsd = 0.0
    $totalCostEur = 0.0
    foreach ($r in $results) {
        if ($r.Cost -and $r.Cost.pricing_available) {
            $totalCostUsd += [double]$r.Cost.total_cost_usd
            $totalCostEur += [double]$r.Cost.total_cost_eur
        }
    }

    # Determine the cost in the local currency for the on-screen output
    $localCurrency = if ($DefaultCurrency) { $DefaultCurrency } else { "EUR" }
    $totalCostLocal = if ($localCurrency -eq "EUR") {
        "{0:F4} EUR" -f $totalCostEur
    } else {
        "{0:F4} USD" -f $totalCostUsd
    }

    # ID padding width based on the maximum. By default we will use 2 digits (01..99).
    # If for some reason I had IDs > 99 (should not happen), fallback to 3 digits.
    $maxId = ($numberedItems | ForEach-Object { $_.id } | Measure-Object -Maximum).Maximum
    $idWidth = if ($maxId -ge 100) { 3 } else { 2 }
    $totalCount = $numberedItems.Count
    $totalCountStr = ([string]$totalCount).PadLeft($idWidth, '0')

    # Detailed report in the log: each request on a line with duration and cost
    Write-Log (T 'batch.report_title') -Level INFO
    foreach ($r in $results) {
        $statusStr = if ($r.Success) { "OK" } else { "KO" }
        $idStr = ([string]$r.Id).PadLeft($idWidth, '0')

        # Cost for the request in the local currency
        $itemCostStr = if ($r.Cost -and $r.Cost.pricing_available) {
            if ($localCurrency -eq "EUR") {
                T 'batch.cost_suffix' $r.Cost.total_cost_eur "EUR"
            } else {
                T 'batch.cost_suffix' $r.Cost.total_cost_usd "USD"
            }
        } else {
            ""
        }

        $detailLine = T 'batch.report_item' $idStr $totalCountStr $statusStr ($r.DurationSec) $itemCostStr
        if (-not $r.Success) { $detailLine += T 'batch.report_error_suffix' $r.Error }
        Write-Log $detailLine -Level INFO
    }

    # Final summary: includes the batch's total cost in the local currency
    $imagesInfo = if ($Threads -le 1) { T 'batch.images_count' $totalImages } else { T 'batch.images_see_log' }
    $failedIds = @($results | Where-Object { -not $_.Success } | ForEach-Object { ([string]$_.Id).PadLeft($idWidth, '0') })
    $failedStr = if ($failedIds.Count -gt 0) { " | KO: $($failedIds -join ', ')" } else { "" }

    # Final summary: "Batch completed: 10/10 requests | 11 images | 30m 14s | cost 0.4123 EUR | 0 errors"
    $summary = (T 'batch.summary' $okCount $totalCount $imagesInfo $batchDurStr $totalCostLocal $koCount) + $failedStr
    Write-Log $summary -Level INFO
}

# Runs a single batch request by re-launching the script as a sub-process with the element's parameters.
function Invoke-BatchItem {
    param($Entry, $State)

    $itemStart = Get-Date

    # I resolve the item parameters with priority on the item's over the state's
    $itemPrompt        = $Entry.item.prompt
    $itemSize          = if ($Entry.item.size)    { $Entry.item.size }    else { $State.Size }
    $itemQuality       = if ($Entry.item.quality) { $Entry.item.quality } else { $State.Quality }
    $itemFormat        = if ($Entry.item.format)  { $Entry.item.format }  else { $State.Format }
    $itemNImages       = if ($Entry.item.n)       { [int]$Entry.item.n }  else { $State.NImages }
    $itemInputImages   = if ($Entry.item.inputImages) { @($Entry.item.inputImages) } else { @() }
    $itemMask          = if ($Entry.item.mask)    { $Entry.item.mask }    else { "" }

    # Preemptive downscaling of the item's size (same behavior as the single
    # flow): if too large for the batch model, I reduce it before generating.
    if ($State.OperationalParams) {
        $itemDownscaled = Invoke-PreemptiveSizeDownscale -OpParams $State.OperationalParams -ModelName $State.ModelLogicalName -Size $itemSize
        if ($itemDownscaled -and $itemDownscaled -ine $itemSize) {
            Write-Log (T 'request.size_downscale' $State.ModelLogicalName $itemSize $itemDownscaled) -Level WARN
            $itemSize = $itemDownscaled
        }
    }

    if (-not $itemPrompt -or $itemPrompt.Length -lt 5) {
        return [pscustomobject]@{
            Id = $Entry.id; Success = $false; DurationSec = 0
            Error = "Prompt missing or too short"; ImagesPaths = @(); Cost = $null
        }
    }

    Write-Log (T 'batch.item_processing' ($Entry.id) ($itemPrompt.Substring(0, [math]::Min(50, $itemPrompt.Length))))

    # Validation and conversion of input images if present
    $validatedInputs = @()
    if ($itemInputImages.Count -gt 0) {
        foreach ($img in $itemInputImages) {
            if (-not (Test-Path $img)) {
                return [pscustomobject]@{
                    Id = $Entry.id; Success = $false; DurationSec = 0
                    Error = "InputImage not found: $img"; ImagesPaths = @(); Cost = $null
                }
            }
            $validated = ConvertTo-ValidImage -ImagePath $img -MaxDimension $State.MaxImageDimension -MaxArea $State.MaxImageArea
            $validatedInputs += $validated
        }
    }

    $hashBatch = (Get-FileHash -InputStream ([IO.MemoryStream]::new([Text.Encoding]::UTF8.GetBytes($itemPrompt))) -Algorithm SHA256).Hash.Substring(0,8)

    $result = Invoke-ImageGeneration `
        -Prompt $itemPrompt -Size $itemSize -Quality $itemQuality -Format $itemFormat `
        -NImages $itemNImages -Moderation $State.Moderation -Background $State.Background `
        -InputFidelity $State.InputFidelity -Mask $itemMask -InputImages $validatedInputs `
        -OutputFolder $State.OutputFolder -OutputMode $State.OutputMode `
        -ModelName $State.ModelLogicalName -Deployment $State.Deployment `
        -ApiSchema $State.ApiSchema `
        -AuthMode $State.AuthMode `
        -Endpoint $State.Endpoint -EditEndpoint $State.EditEndpoint `
        -FailoverEndpoint $State.FailoverEndpoint -FailoverEditEndpoint $State.FailoverEditEndpoint `
        -ApiKey $State.ApiKey `
        -MaxRetries $State.MaxRetries -TimeoutMinutes $State.RequestTimeoutMinutes `
        -ApplyBackground $State.applyBackground -ApplyInputFidelity $State.applyInputFidelity `
        -ApplyModeration $State.applyModeration `
        -UseMetadata $State.useMetadata -InputImagesOriginal $itemInputImages `
        -FileTemplate $State.FileTemplate -Hash $hashBatch -Compression $State.DefaultOutputCompression `
        -PriceInputUsd $State.PriceInputUsd -PriceOutputUsd $State.PriceOutputUsd `
        -PriceImageUsd $State.PriceImageUsd -Pricing $State.Pricing `
        -EurRate $State.EurRate -EstimatedTotal 120 `
        -OperationalParams $State.OperationalParams

    if ($result.Success -and $result.Cost) {
        Write-CostLog -Cost $result.Cost -Model $State.ModelLogicalName -HasPricingSection ($null -ne $State.ModelHasPricing -and $State.ModelHasPricing) -NImages $itemNImages
        Add-DailyCostRecord -Cost $result.Cost
    }

    $itemEnd = Get-Date

    # Telemetry (source="batch"): only in the SEQUENTIAL branch of the batch, which runs
    # in-process. The parallel branch (-Threads > 1) instead invokes the script as a
    # sub-process, which already sends its telemetry as a "cli" flow: hooking
    # it here too would cause a double send. $State.Config is the config (passed by the
    # caller) needed by Send-GenerationTelemetry; if absent, I skip.
    if ($result.Success -and $State.Config) {
        Send-GenerationTelemetry -Config $State.Config -Cost $result.Cost `
            -DurationSec ($itemEnd - $itemStart).TotalSeconds -Model $State.ModelLogicalName `
            -Size $itemSize -Quality $itemQuality -NImages $itemNImages -Source "batch"
    }

    # Time telemetry (.stat) for the kNN estimate and -Auto Time. Same logic as the
    # telemetry above: ONLY the in-process sequential branch (the parallel branch runs as a
    # "cli" sub-process that already writes its own record, avoiding duplicates). The
    # batch generations are real generations in every respect: they must contribute.
    if ($result.Success) {
        $batchMode = if ($itemInputImages.Count -gt 0) { "edit" } else { "generation" }
        Write-GenerationStat -Result $result -Model $State.ModelLogicalName `
            -Deployment $State.Deployment -ModeKey $batchMode `
            -PromptLen $itemPrompt.Length -Size $itemSize -Format $itemFormat `
            -Quality $itemQuality -NImages $itemNImages `
            -InputImagesCount $itemInputImages.Count -EstimatedTotal 120
    }
    return [pscustomobject]@{
        Id = $Entry.id
        Success = $result.Success
        DurationSec = [math]::Round(($itemEnd - $itemStart).TotalSeconds, 1)
        Error = $result.Error
        ImagesPaths = $result.ImagesPaths
        Cost = $result.Cost
    }
}

function Resolve-ModelRuntime {
    <#
    Given the logical name of a model and the config object, performs ALL the runtime setup
    needed to be able to use it in a generation: field validation, endpoint URL
    validation, API key decoding, reading of schema/authMode/supportsEdit, feature
    flags and pricing (with back-compat across the various meter schemas).

    Unlike the inline setup of the main flow, it NEVER calls exit: in case of a
    problem it returns an object with .Ok=$false and .Error set. This makes it
    reusable in contexts that must iterate over several models without interrupting
    (e.g. the benchmark): a misconfigured model produces a collectable error, not
    an abrupt exit of the script.

    Ritorna un PSCustomObject con:
      .Ok (bool), .Error (string)
      .Name .Config .ApiKey .Deployment .ApiSchema .AuthMode .SupportsEdit
      .SupportsInpainting .SupportsInputFidelity .SupportsBackground
      .ModelPricing .PriceInputUsd .PriceOutputUsd .PriceImageUsd
    #>
    param(
        [Parameter(Mandatory=$true)][string]$ModelName,
        [Parameter(Mandatory=$true)]$Config
    )

    $rt = [PSCustomObject]@{
        Ok = $false; Error = ""
        Name = $ModelName; Config = $null
        ApiKey = ""; Deployment = ""; ApiSchema = "openai-images"; AuthMode = ""
        SupportsEdit = $true; SupportsInpainting = $false
        SupportsInputFidelity = $false; SupportsBackground = $false
        ModelPricing = $null; PriceInputUsd = 0.0; PriceOutputUsd = 0.0; PriceImageUsd = 0.0
    }

    if (-not $Config.models.$ModelName) {
        $rt.Error = (T 'model.not_defined' $ModelName (@($Config.models.PSObject.Properties.Name) -join ', '))
        return $rt
    }
    # Name normalization: the property lookup is case-insensitive, so
    # 'GPT-Image-2' resolves even if the conf has 'gpt-image-2'; but the CANONICAL name
    # for metadata, log, .stat, .cost and gallery is the one written in the .conf, so the
    # same model never appears with different capitalization in the produced data.
    $canonicalName = @($Config.models.PSObject.Properties.Name) |
                     Where-Object { $_ -ieq $ModelName } | Select-Object -First 1
    if ($canonicalName) { $ModelName = [string]$canonicalName; $rt.Name = $ModelName }

    $mc = $Config.models.$ModelName
    $rt.Config = $mc

    # Mandatory fields
    foreach ($f in @("endpoint","apiKey","deployment")) {
        if ($null -eq $mc.$f) {
            $rt.Error = (T 'model.field_missing' $f $ModelName)
            return $rt
        }
    }
    # Non-empty endpoint + valid URL
    if (-not $mc.endpoint -or $mc.endpoint.Trim() -eq "") {
        $rt.Error = (T 'model.empty_endpoint' $ModelName); return $rt
    }
    $epTrim = $mc.endpoint.Trim()
    $epValid = $false
    try {
        $epUri = [System.Uri]$epTrim
        $epValid = ($epUri.Scheme -eq 'http' -or $epUri.Scheme -eq 'https') -and $epUri.IsAbsoluteUri
    } catch { $epValid = $false }
    if (-not $epValid) {
        $rt.Error = (T 'model.invalid_endpoint_url' $ModelName $epTrim); return $rt
    }
    # API key present and decodable
    if (-not $mc.apiKey -or $mc.apiKey.Trim() -eq "") {
        $rt.Error = (T 'model.no_apikey' $ModelName); return $rt
    }
    $decodedKey = Unprotect-ApiKey -EncodedValue $mc.apiKey
    if (-not $decodedKey) {
        $rt.Error = (T 'apikey.decode_failed_for_model' $ModelName); return $rt
    }
    $rt.ApiKey     = $decodedKey
    $rt.Deployment = $mc.deployment

    # schema / authMode / supportsEdit
    $rt.ApiSchema    = if ($mc.apiSchema -and $mc.apiSchema.Trim() -ne "") { $mc.apiSchema.Trim() } else { "openai-images" }
    $rt.AuthMode     = if ($mc.authMode -and $mc.authMode.Trim() -ne "") { $mc.authMode.Trim().ToLower() } else { "" }
    $rt.SupportsEdit = if ($null -ne $mc.supportsEdit) { [bool]$mc.supportsEdit } else { $true }

    # Feature flags
    $rt.SupportsInpainting    = if ($null -ne $mc.supportsInpainting)    { [bool]$mc.supportsInpainting }    else { $false }
    $rt.SupportsInputFidelity = if ($null -ne $mc.supportsInputFidelity) { [bool]$mc.supportsInputFidelity } else { $false }
    $rt.SupportsBackground    = if ($null -ne $mc.supportsBackground)    { [bool]$mc.supportsBackground }    else { $false }

    # Pricing (same logic as the main flow, with back-compat)
    $modelPricing = $mc.pricing
    $rt.ModelPricing = $modelPricing
    if ($modelPricing -and ($modelPricing.PSObject.Properties.Name -contains 'meters') -and $modelPricing.meters) {
        $m = $modelPricing.meters
        if ($m.PSObject.Properties.Name -contains 'inputText'  -and $null -ne $m.inputText)  { $rt.PriceInputUsd  = [double]$m.inputText }
        if ($m.PSObject.Properties.Name -contains 'outputText' -and $null -ne $m.outputText) { $rt.PriceOutputUsd = [double]$m.outputText }
        if ($m.PSObject.Properties.Name -contains 'outputImage' -and $null -ne $m.outputImage) { $rt.PriceImageUsd  = [double]$m.outputImage }
        if ($m.PSObject.Properties.Name -contains 'input'  -and $null -ne $m.input)  { $rt.PriceInputUsd  = [double]$m.input }
        if ($m.PSObject.Properties.Name -contains 'output' -and $null -ne $m.output) {
            $rt.PriceOutputUsd = [double]$m.output
            if ($rt.PriceImageUsd -eq 0.0) { $rt.PriceImageUsd = [double]$m.output }
        }
    }

    $rt.Ok = $true
    return $rt
}

function Invoke-Benchmark {
    <#
    Benchmark mode: runs the same prompt (or several prompts) on a list of models,
    measuring for each prompt x model combination time, cost and tokens, and saving
    the path of the generated image (for manual quality evaluation).

    - $Prompts: array of objects { Id; Text }. A single element with -Prompt/-PromptFile,
      or N elements with -Batch.
    - $ModelNames: list of the models to run on (already normalized and validated).
    - The generation options (Size, Quality, Format, NImages, ...) come from the
      script's global parameters via $GenOptions.

    A model that fails on a prompt does NOT block the others: the error is recorded
    in the result of that combination and it continues. Returns an array of results
    (one per combination) with the fields needed for on-screen output and CSV export.

    Budget: if $GenOptions.Budget is set, BEFORE generating it estimates the TOTAL cost
    of all the combinations (each prompt on each model, summing per-model because the
    prices differ) and, if the conservative estimate (+20%) exceeds the budget, it exits with
    code 1 without generating anything (consistent with the other flows).

    Size: for each model the requested size goes through the preemptive downscaling
    (Invoke-PreemptiveSizeDownscale), computed on its operationalParams: if excessive
    it is reduced to the closest valid value before the generation. The reduction is
    local to the single model and does not alter the shared $GenOptions.Size.
    #>
    param(
        [Parameter(Mandatory=$true)][array]$Prompts,
        [Parameter(Mandatory=$true)][string[]]$ModelNames,
        [Parameter(Mandatory=$true)]$Config,
        [Parameter(Mandatory=$true)][hashtable]$GenOptions
    )

    $results = New-Object System.Collections.Generic.List[object]

    # I pre-resolve each model's runtime ONCE (validation, key, pricing):
    # if a model is misconfigured I report it for each prompt but I do not redo the setup.
    $runtimes = @{}
    foreach ($mn in $ModelNames) {
        $runtimes[$mn] = Resolve-ModelRuntime -ModelName $mn -Config $Config
    }

    $totalCombos = $Prompts.Count * $ModelNames.Count
    $combo = 0

    # Budget guardrail for the BENCHMARK: if -Budget is specified, I estimate the
    # TOTAL cost of all the combinations (each prompt on each model) BEFORE generating
    # and I block if the conservative estimate (+20%) exceeds the budget. Unlike the
    # other flows (a single model), here I sum the estimated costs model by model,
    # because each model has different prices. NB: the estimate uses the REQUESTED size; if a
    # model does downscaling the real spend will be lower, so the estimate is
    # prudential (it can overestimate, never underestimate for that reason).
    if ($null -ne $GenOptions.Budget) {
        $totEur = 0.0; $totUsd = 0.0
        foreach ($p in $Prompts) {
            foreach ($mn in $ModelNames) {
                $rtmB = $runtimes[$mn]
                if (-not $rtmB.Ok) { continue }   # i modelli non configurati non generano: non contano
                $estB = Get-EstimatedCost -Prompt $p.Text -NImages $GenOptions.NImages `
                            -InputImagesCount (@($GenOptions.InputImages).Count) `
                            -Quality $GenOptions.Quality -Size $GenOptions.Size `
                            -PriceInputUsd $rtmB.PriceInputUsd -PriceOutputUsd $rtmB.PriceOutputUsd `
                            -PriceImageUsd $rtmB.PriceImageUsd -Pricing $rtmB.ModelPricing `
                            -EurRate $GenOptions.EurRate
                $totEur += [double]$estB.CostEur
                $totUsd += [double]$estB.CostUsd
            }
        }
        $estTotal = [pscustomobject]@{ CostEur = $totEur; CostUsd = $totUsd }
        $budgetOk = Test-BudgetGuardrail -Budget $GenOptions.Budget -Currency $GenOptions.DefaultCurrency -Estimate $estTotal
        if (-not $budgetOk) {
            # Benchmark total estimate over budget: I generate nothing and exit with
            # code 1, consistently with the other flows (single/batch). Test-BudgetGuardrail
            # has already logged the detail (estimate, conservative estimate, budget).
            exit 1
        }
    }

    foreach ($p in $Prompts) {
        foreach ($mn in $ModelNames) {
            $combo++
            $rtm = $runtimes[$mn]
            Write-Log (T 'bench.running' $combo $totalCombos $mn ([string]$p.Id)) -Level INFO

            # Misconfigured model: I record the error and continue.
            if (-not $rtm.Ok) {
                $results.Add([PSCustomObject]@{
                    PromptId = $p.Id; PromptText = $p.Text; Model = $mn
                    Success = $false; Error = $rtm.Error
                    DurationSec = $null; CostEur = $null; CostUsd = $null
                    InputTokens = $null; OutputTokens = $null; TotalTokens = $null
                    TokensEstimated = $null; ImagePaths = @()
                })
                Write-Log (T 'bench.model_failed' $mn $rtm.Error) -Level WARN
                continue
            }

            # Edit guard: if the model does not support edit but reference images are
            # required, I skip this combination with a clear message.
            if (-not $rtm.SupportsEdit -and $GenOptions.InputImages -and @($GenOptions.InputImages).Count -gt 0) {
                $results.Add([PSCustomObject]@{
                    PromptId = $p.Id; PromptText = $p.Text; Model = $mn
                    Success = $false; Error = (T 'edit.model_no_edit_support' $mn)
                    DurationSec = $null; CostEur = $null; CostUsd = $null
                    InputTokens = $null; OutputTokens = $null; TotalTokens = $null
                    TokensEstimated = $null; ImagePaths = @()
                })
                Write-Log (T 'bench.model_failed' $mn (T 'edit.model_no_edit_support' $mn)) -Level WARN
                continue
            }

            # Apply-flags consistent with the model (as in the main flow)
            $applyBackground     = $rtm.SupportsBackground    -and $GenOptions.Background     -and $GenOptions.Background.Trim() -ne ""
            $applyInputFidelity  = $rtm.SupportsInputFidelity -and $GenOptions.InputFidelity  -and $GenOptions.InputFidelity.Trim() -ne ""
            $applyModeration     = $true

            # Specific file template for the benchmark: it includes the model name and the
            # prompt-id, so the images of the various models do not overwrite each other and are
            # riconoscibili. Sanitizzazione gestita da Get-OutputFileName.
            $safeModel = ($mn -replace '[^\w\.\-]', '_')
            $benchTemplate = "bench_{timestamp}_p$($p.Id)_${safeModel}_{index}"

            # Preemptive downscaling for THIS model: each benchmark model has its
            # own operationalParams, so the valid size can differ. I use a
            # local variable so as not to alter $GenOptions.Size (shared among the models).
            $benchSize = $GenOptions.Size
            if ($rtm.Config -and $rtm.Config.operationalParams) {
                $benchDownscaled = Invoke-PreemptiveSizeDownscale -OpParams $rtm.Config.operationalParams -ModelName $mn -Size $benchSize
                if ($benchDownscaled -and $benchDownscaled -ine $benchSize) {
                    Write-Log (T 'request.size_downscale' $mn $benchSize $benchDownscaled) -Level WARN
                    $benchSize = $benchDownscaled
                }
            }

            $startedAt = Get-Date
            try {
                $r = Invoke-ImageGeneration `
                    -Prompt $p.Text -Size $benchSize -Quality $GenOptions.Quality `
                    -Format $GenOptions.Format -NImages $GenOptions.NImages `
                    -Moderation $GenOptions.Moderation -Background $GenOptions.Background `
                    -InputFidelity $GenOptions.InputFidelity -Mask $GenOptions.Mask `
                    -InputImages $GenOptions.InputImages -OutputFolder $GenOptions.OutputFolder `
                    -OutputMode $GenOptions.OutputMode `
                    -ModelName $mn -Deployment $rtm.Deployment `
                    -ApiSchema $rtm.ApiSchema -AuthMode $rtm.AuthMode `
                    -Endpoint $rtm.Config.endpoint -EditEndpoint $rtm.Config.editEndpoint `
                    -FailoverEndpoint "" -FailoverEditEndpoint "" `
                    -ApiKey $rtm.ApiKey `
                    -MaxRetries $GenOptions.MaxRetries -TimeoutMinutes $GenOptions.TimeoutMinutes `
                    -ApplyBackground $applyBackground -ApplyInputFidelity $applyInputFidelity `
                    -ApplyModeration $applyModeration `
                    -UseMetadata $GenOptions.UseMetadata -InputImagesOriginal $GenOptions.InputImagesOriginal `
                    -FileTemplate $benchTemplate -Hash $GenOptions.Hash `
                    -Compression $GenOptions.Compression `
                    -PriceInputUsd $rtm.PriceInputUsd -PriceOutputUsd $rtm.PriceOutputUsd `
                    -PriceImageUsd $rtm.PriceImageUsd -Pricing $rtm.ModelPricing `
                    -EurRate $GenOptions.EurRate -EstimatedTotal 0 `
                    -OperationalParams $rtm.Config.operationalParams
            }
            catch {
                $r = [PSCustomObject]@{ Success = $false; Error = $_.Exception.Message; ImagesPaths = @(); Cost = $null; ActualDurationSec = $null; StartTime = $startedAt }
            }

            if ($r.Success) {
                $dur = if ($null -ne $r.ActualDurationSec) { [double]$r.ActualDurationSec } else { ((Get-Date) - $startedAt).TotalSeconds }
                # Time telemetry (.stat): the benchmark generations are real
                # generations and must feed the kNN estimate and -Auto Time, like all the others.
                # (They remain however excluded from the Application Insights telemetry, so as not
                # to mix comparative runs with the production metrics.)
                $benchMode = if ($GenOptions.InputImages -and @($GenOptions.InputImages).Count -gt 0) { "edit" } else { "generation" }
                $benchInputCount = if ($GenOptions.InputImages) { @($GenOptions.InputImages).Count } else { 0 }
                Write-GenerationStat -Result $r -Model $mn -Deployment $rtm.Deployment `
                    -ModeKey $benchMode -PromptLen $p.Text.Length -Size $GenOptions.Size `
                    -Format $GenOptions.Format -Quality $GenOptions.Quality `
                    -NImages $GenOptions.NImages -InputImagesCount $benchInputCount -EstimatedTotal 0
                # [COST] line in the .log (like the other flows): the benchmark is a
                # real generation, so its cost must be logged and appears in -Analytics.
                if ($r.Cost) {
                    Write-CostLog -Cost $r.Cost -Model $mn -HasPricingSection ($null -ne $rtm.ModelPricing) -NImages $GenOptions.NImages
                    Add-DailyCostRecord -Cost $r.Cost
                }
                # Application Insights telemetry: the benchmark is included like the other
                # flows (source="benchmark"), so its real generations appear in the
                # cost/usage Workbooks. Only the SelfTest remains excluded (via -NoTelemetry).
                Send-GenerationTelemetry -Config $Config -Cost $r.Cost `
                    -DurationSec $dur -Model $mn `
                    -Size $GenOptions.Size -Quality $GenOptions.Quality `
                    -NImages $GenOptions.NImages -Source "benchmark"
                $results.Add([PSCustomObject]@{
                    PromptId = $p.Id; PromptText = $p.Text; Model = $mn
                    Success = $true; Error = ""
                    DurationSec = [math]::Round($dur, 1)
                    CostEur = if ($r.Cost) { $r.Cost.total_cost_eur } else { 0.0 }
                    CostUsd = if ($r.Cost) { $r.Cost.total_cost_usd } else { 0.0 }
                    InputTokens  = if ($r.Cost) { $r.Cost.input_tokens } else { 0 }
                    OutputTokens = if ($r.Cost) { $r.Cost.output_tokens } else { 0 }
                    TotalTokens  = if ($r.Cost) { $r.Cost.total_tokens } else { 0 }
                    TokensEstimated = if ($r.Cost) { [bool]$r.Cost.tokens_estimated } else { $false }
                    ImagePaths = @($r.ImagesPaths)
                })
            } else {
                $results.Add([PSCustomObject]@{
                    PromptId = $p.Id; PromptText = $p.Text; Model = $mn
                    Success = $false; Error = [string]$r.Error
                    DurationSec = $null; CostEur = $null; CostUsd = $null
                    InputTokens = $null; OutputTokens = $null; TotalTokens = $null
                    TokensEstimated = $null; ImagePaths = @()
                })
                Write-Log (T 'bench.model_failed' $mn ([string]$r.Error)) -Level WARN
            }
        }
    }

    return $results.ToArray()
}

function Write-BenchmarkReport {
    <#
    Prints to the screen (as [INFO] lines) the benchmark results grouped BY PROMPT,
    so the user compares the models for the same prompt. For each combination it shows
    time, EUR/USD cost, tokens (with a marker if estimated) and the image path.
    #>
    param([Parameter(Mandatory=$true)][array]$Results)

    Write-Log (T 'bench.report_title') -Level INFO

    # I group by PromptId preserving the order of first appearance
    $orderedIds = New-Object System.Collections.Generic.List[object]
    foreach ($r in $Results) { if (-not $orderedIds.Contains($r.PromptId)) { $orderedIds.Add($r.PromptId) } }

    foreach ($promptId in $orderedIds) {
        $group = $Results | Where-Object { $_.PromptId -eq $promptId }
        $promptText = ($group | Select-Object -First 1).PromptText
        $promptPreview = if ($promptText.Length -gt 70) { $promptText.Substring(0,70) + "..." } else { $promptText }
        Write-Log (T 'bench.prompt_header' ([string]$promptId) $promptPreview) -Level INFO

        foreach ($r in $group) {
            if ($r.Success) {
                $estMark = if ($r.TokensEstimated) { " " + (T 'bench.tokens_est_mark') } else { "" }
                $imgInfo = if ($r.ImagePaths -and $r.ImagePaths.Count -gt 0) { ($r.ImagePaths -join "; ") } else { "-" }
                $line = (T 'bench.row_ok' $r.Model `
                            (Format-DisplayNumber -Value $r.DurationSec) `
                            (Format-DisplayNumber -Value $r.CostEur) `
                            (Format-DisplayNumber -Value $r.CostUsd) `
                            ([string]$r.TotalTokens + $estMark) `
                            $imgInfo)
                Write-Log $line -Level INFO
            } else {
                Write-Log (T 'bench.row_fail' $r.Model $r.Error) -Level INFO
            }
        }
    }
}

function Export-BenchmarkCsv {
    <#
    Exports the benchmark results to a CSV file (one row per prompt x model
    combination). Column separator = ListSeparator of the current culture
    (";" in IT, "," in US), UTF-8 encoding with BOM for Excel compatibility. The
    numeric values (time, costs) use the culture's decimal separator via
    Format-DisplayNumber, consistently with Export-AnalyticsCsv: so "0,0479" in IT and
    "0.0479" in US, and Excel interprets them as numbers in the user's language.
    Note: the column separator in IT is ";" so there is no conflict with the decimal
    comma.
    #>
    param(
        [Parameter(Mandatory=$true)][array]$Results,
        [Parameter(Mandatory=$true)][string]$Path
    )
    $sep = if ($script:CsvListSeparator) { $script:CsvListSeparator } else { "," }

    $rows = New-Object System.Collections.Generic.List[string]
    # Intestazione
    $headers = @("prompt_id","model","success","duration_sec","cost_eur","cost_usd",
                 "input_tokens","output_tokens","total_tokens","tokens_estimated",
                 "image_paths","error","prompt")
    $rows.Add(($headers -join $sep))

    foreach ($r in $Results) {
        function _csv($v) {
            $s = if ($null -eq $v) { "" } else { [string]$v }
            # Escape CSV: se contiene separatore, virgolette o newline, racchiudo tra "" e raddoppio le "
            if ($s -match '["\r\n]' -or $s.Contains($sep)) { '"' + $s.Replace('"','""') + '"' } else { $s }
        }
        # Numbers in the system culture's decimal separator (like the analytics).
        $durCell = if ($null -ne $r.DurationSec) { Format-DisplayNumber -Value ([double]$r.DurationSec) -Decimals 1 } else { "" }
        $eurCell = if ($null -ne $r.CostEur)     { Format-DisplayNumber -Value ([double]$r.CostEur)     -Decimals 6 } else { "" }
        $usdCell = if ($null -ne $r.CostUsd)     { Format-DisplayNumber -Value ([double]$r.CostUsd)     -Decimals 6 } else { "" }
        $imgJoined = if ($r.ImagePaths) { ($r.ImagePaths -join " | ") } else { "" }
        $line = @(
            (_csv $r.PromptId), (_csv $r.Model), (_csv $r.Success), (_csv $durCell),
            (_csv $eurCell), (_csv $usdCell), (_csv $r.InputTokens), (_csv $r.OutputTokens),
            (_csv $r.TotalTokens), (_csv $r.TokensEstimated), (_csv $imgJoined),
            (_csv $r.Error), (_csv $r.PromptText)
        ) -join $sep
        $rows.Add($line)
    }

    try {
        $utf8Bom = [System.Text.UTF8Encoding]::new($true)
        [System.IO.File]::WriteAllText($Path, ($rows -join "`r`n"), $utf8Bom)
        Write-Log (T 'bench.export_ok' $Path) -Level INFO
    }
    catch {
        Write-Log (T 'bench.export_failed' $Path ($_.Exception.Message)) -Level ERROR
    }
}

function Get-CostRecordsFromLog {
    <#
    Parses the New-GPTImage.log file extracting all the [COST] lines,
    which contain the entire history of generations and their costs.

    [COST] line format (the fields may evolve; the parsing is per-field via regex,
    therefore tolerant to additional or absent fields):
      [yyyy-MM-dd HH:mm:ss] [COST] model=<nome> pricing_mode=<tokens|megapixels>
        n_images=<n> [gen_megapixels=<n> reference_megapixels=<n>]
        input_tokens=<n> (...) output_tokens=<n> (...) total_tokens=<n>
        input_usd=<f> input_eur=<f> output_usd=<f> output_eur=<f>
        total_usd=<f> total_eur=<f> eur_rate=<f>

    Returns: array of pscustomobject with fields Date, Model, NImages, InputTokens,
    OutputTokens, TotalTokens, InputUsd, OutputUsd, TotalUsd, InputEur, OutputEur,
    TotalEur. NImages is the number of images of the line (batch); the COST lines
    prior to the introduction of the field use default 1 (backward compatibility).
    #>
    param([string]$LogPath)

    $records = [System.Collections.Generic.List[object]]::new()
    if (-not (Test-Path $LogPath)) {
        return @($records)
    }

    try {
        $lines = Get-DecryptedLogLines -Path $LogPath
    } catch {
        return @($records)
    }

    foreach ($line in $lines) {
        # Pattern: [2026-05-20 10:15:33] [COST] model=gpt-image-2 input_tokens=187 ...
        if ($line -match '^\[(\d{4}-\d{2}-\d{2}) (\d{2}:\d{2}:\d{2})\]\s+\[COST\]\s+(.+)$') {
            $dateStr = $Matches[1]
            $payload = $Matches[3]

            # Skip COST lines without data ("Costs not available...")
            if ($payload -notmatch 'model=') { continue }

            try {
                $dateVal = [DateTime]::ParseExact($dateStr, "yyyy-MM-dd", [System.Globalization.CultureInfo]::InvariantCulture)
            } catch { continue }

            # Extraction of the key=value fields
            $modelMatch = if ($payload -match 'model=(\S+)')                 { $Matches[1] } else { "unknown" }
            # n_images: number of images generated by THIS line (batch). The old
            # COST lines do not have the field: default 1 for backward compatibility.
            $nImg       = if ($payload -match 'n_images=(\d+)')              { [int]$Matches[1] } else { 1 }
            if ($nImg -lt 1) { $nImg = 1 }
            # tokens_estimated: flag indicating whether the costs of this line are based
            # on ESTIMATED tokens (the API did not return them). Old lines do not have the
            # field: default false (measured cost).
            $tokEst     = if ($payload -match 'tokens_estimated=(true|false)') { ($Matches[1] -eq 'true') } else { $false }
            $inTok      = if ($payload -match 'input_tokens=(\d+)')          { [int]$Matches[1] } else { 0 }
            $outTok     = if ($payload -match 'output_tokens=(\d+)')         { [int]$Matches[1] } else { 0 }
            $totTok     = if ($payload -match 'total_tokens=(\d+)')          { [int]$Matches[1] } else { 0 }
            # The EUR/USD values can have a comma OR a point as the decimal separator
            # depending on the system culture. I normalize to a point for parsing.
            function _parseFloat([string]$txt) {
                if (-not $txt) { return 0.0 }
                $normalized = $txt.Replace(',', '.')
                $result = 0.0
                if ([double]::TryParse($normalized, [System.Globalization.NumberStyles]::Any,
                                       [System.Globalization.CultureInfo]::InvariantCulture, [ref]$result)) {
                    return $result
                }
                return 0.0
            }
            $inUsd  = if ($payload -match 'input_usd=([\d\.,]+)')   { _parseFloat $Matches[1] } else { 0.0 }
            $outUsd = if ($payload -match 'output_usd=([\d\.,]+)')  { _parseFloat $Matches[1] } else { 0.0 }
            $totUsd = if ($payload -match 'total_usd=([\d\.,]+)')   { _parseFloat $Matches[1] } else { 0.0 }
            $inEur  = if ($payload -match 'input_eur=([\d\.,]+)')   { _parseFloat $Matches[1] } else { 0.0 }
            $outEur = if ($payload -match 'output_eur=([\d\.,]+)')  { _parseFloat $Matches[1] } else { 0.0 }
            $totEur = if ($payload -match 'total_eur=([\d\.,]+)')   { _parseFloat $Matches[1] } else { 0.0 }

            # kind: distinguishes the IMAGE cost lines (absent or "image") from those of the
            # TEXT MODEL ("textmodel"). operation: for the text lines, the
            # function that generated them (optimize/negative/storyboard/describe).
            $kind      = if ($payload -match 'kind=(\S+)')      { $Matches[1] } else { "image" }
            $operation = if ($payload -match 'operation=(\S+)') { $Matches[1] } else { "" }

            [void]$records.Add([pscustomobject]@{
                Date         = $dateVal
                Model        = $modelMatch
                Kind         = $kind
                Operation    = $operation
                NImages      = $nImg
                TokensEstimated = $tokEst
                InputTokens  = $inTok
                OutputTokens = $outTok
                TotalTokens  = $totTok
                InputUsd     = $inUsd
                OutputUsd    = $outUsd
                TotalUsd     = $totUsd
                InputEur     = $inEur
                OutputEur    = $outEur
                TotalEur     = $totEur
            })
        }
    }

    return @($records)
}

function Format-BarChart {
    <#
    Genera un grafico a barre verticali testuale.

    Parametri:
      -Title:        chart title (maximum 50 chars)
      -Labels:       array of labels (X axis)
      -Values:       array of numeric values (Y axis), same order as Labels
      -ValueFormat:  "currency" (e.g. 0.45) | "int" (integer) | "tokens" (k/M suffix)
      -Unit:         e.g. "EUR", "USD", "img", "tok"
      -Height:       height in rows of the chart part (default 8)
      -Width:        total width including the Y axis (default 56)

    Width note: with 2 side-by-side charts (Join-ChartsHorizontal, separator 3)
    the total is about 56+3+56 = 115 characters, suitable for a 120+ console.
    With Width=56 and 4 bars, each bar/label has ~12 characters, enough
    for names like "FLUX.2-pro". Longer names are abbreviated in a readable way
    (see _shortLabel) instead of being brutally truncated.
    #>
    param(
        [string]$Title,
        [string[]]$Labels,
        [double[]]$Values,
        [string]$ValueFormat = "currency",
        [string]$Unit = "",
        [int]$Height = 8,
        [int]$Width = 56
    )

    $output = New-Object System.Collections.Generic.List[string]
    $output.Add($Title)
    $output.Add("")   # #1: riga di spaziatura tra titolo e grafico

    if (-not $Values -or $Values.Count -eq 0) {
        $output.Add("  " + (T 'analytics.no_chart_data'))
        return $output.ToArray()
    }

    # I compute max to scale the bars. If all the values are 0, scale to 1 to avoid /0.
    $maxVal = ($Values | Measure-Object -Maximum).Maximum
    if ($maxVal -le 0) { $maxVal = 1 }

    # Value formatting for the Y axis (I show maxVal and intermediate steps)
    function _fmt($v) {
        switch ($ValueFormat) {
            "currency" { return ("{0,6:F2}" -f $v) }
            "int"      { return ("{0,6:D}" -f [int]$v) }
            "tokens"   {
                if ($v -ge 1000000) { return ("{0,5:F1}M" -f ($v / 1000000.0)) }
                elseif ($v -ge 1000) { return ("{0,5:F1}k" -f ($v / 1000.0)) }
                else { return ("{0,6:D}" -f [int]$v) }
            }
            default    { return ("{0,6:F2}" -f $v) }
        }
    }
    # COMPACT formatting of the value to print above/on the bar (without fixed padding)
    function _fmtBar($v) {
        switch ($ValueFormat) {
            "currency" { return ("{0:F2}" -f $v) }
            "int"      { return ("{0:D}" -f [int]$v) }
            "tokens"   {
                if ($v -ge 1000000) { return ("{0:F1}M" -f ($v / 1000000.0)) }
                elseif ($v -ge 1000) { return ("{0:F1}k" -f ($v / 1000.0)) }
                else { return ("{0:D}" -f [int]$v) }
            }
            default    { return ("{0:F2}" -f $v) }
        }
    }

    # Bar width (characters per bar) based on the number of labels
    $nBars = $Values.Count
    $axisWidth = 8   # spazio per le label dell'asse Y
    $barAreaWidth = $Width - $axisWidth
    if ($barAreaWidth -lt $nBars) { $barAreaWidth = $nBars * 4 }
    $barWidth = [math]::Max(3, [math]::Floor($barAreaWidth / $nBars))
    $padBetween = 1
    $blockChar = [char]0x2588  # █

    # Helper: centers a string in a field of width w (truncates if necessary)
    function _center([string]$s, [int]$w) {
        if ($s.Length -ge $w) { return $s.Substring(0, $w) }
        $totalPad = $w - $s.Length
        $left = [math]::Floor($totalPad / 2.0)
        $right = $totalPad - $left
        return (" " * $left) + $s + (" " * $right)
    }

    # #2: row of the VALUES above the bars. We mark it with a sentinel prefix
    # "__VAL__" that the on-screen output recognizes to color it (yellow). In the file the
    # prefix is removed, leaving the values aligned above each bar.
    $valuesRow = (" " * $axisWidth)
    foreach ($v in $Values) {
        $valStr = _fmtBar $v
        $valuesRow += (_center $valStr $barWidth) + (" " * $padBetween)
    }
    $output.Add("__VAL__" + $valuesRow)

    # I build the grid: $Height rows tall, each with the Y-axis label on the left and bars on the right
    # #4: I show 4 levels on the Y axis (top, two intermediate, bottom) instead of 3.
    $yLevels = @($Height, [int][math]::Round($Height * 2 / 3.0), [int][math]::Round($Height / 3.0), 1)
    for ($row = $Height; $row -ge 1; $row--) {
        $thresholdRatio = $row / [double]$Height
        $thresholdVal = $maxVal * $thresholdRatio

        $axisLabel = ""
        if ($yLevels -contains $row) {
            $axisLabel = (_fmt $thresholdVal)
        }
        $axisLabel = $axisLabel.PadLeft($axisWidth - 2) + " |"

        # I build the bars row
        $barRow = ""
        foreach ($v in $Values) {
            $barFilled = ($v -ge $thresholdVal - 0.0001)
            $cell = if ($barFilled) {
                ([string]$blockChar) * $barWidth
            } else {
                " " * $barWidth
            }
            $barRow += $cell + (" " * $padBetween)
        }
        $output.Add($axisLabel + " " + $barRow)
    }

    # Baseline. The length is the REAL one occupied by the bars: each bar
    # is $barWidth wide and between one bar and the next there is $padBetween of space. The last
    # bar has no padding after, so: nBars*barWidth + (nBars-1)*padBetween. This way
    # the X axis ends exactly where the last bar ends, not beyond.
    $barsRealWidth = ($nBars * $barWidth) + (($nBars - 1) * $padBetween)
    $baseline = (" " * ($axisWidth - 2)) + " +" + ("-" * $barsRealWidth)
    $output.Add($baseline)

    # X-axis labels line
    # Readable abbreviation: if the label exceeds the bar width, instead
    # of brutally truncating it (e.g. "gpt-imag") we keep the start and end with a
    # central ellipsis dot (e.g. "gpt-i...1.5"), which stays recognizable.
    function _shortLabel([string]$lbl, [int]$w) {
        if ($lbl.Length -le $w) { return $lbl }
        if ($w -le 3) { return $lbl.Substring(0, $w) }
        if ($w -le 6) { return $lbl.Substring(0, $w - 1) + "." }
        $keep = $w - 3   # caratteri utili oltre i 3 puntini
        $head = [math]::Ceiling($keep / 2.0)
        $tail = $keep - $head
        return $lbl.Substring(0, $head) + "..." + $lbl.Substring($lbl.Length - $tail, $tail)
    }
    # X-axis labels. If a label contains the '|' separator (e.g. shortName
    # "gpt-image|2"), it is split over TWO rows: row 1 = name, row 2 = version.
    # This way long model names stay readable without overlapping. Labels without
    # '|' stay on a single row (row 2 empty for alignment).
    $hasTwoLines = ($Labels | Where-Object { $_ -like "*|*" } | Measure-Object).Count -gt 0
    $xLabelsRow1 = (" " * $axisWidth)
    $xLabelsRow2 = (" " * $axisWidth)
    foreach ($lbl in $Labels) {
        if ($lbl -like "*|*") {
            $parts = $lbl -split '\|', 2
            $line1 = _shortLabel $parts[0].Trim() $barWidth
            $line2 = _shortLabel $parts[1].Trim() $barWidth
        } else {
            $line1 = _shortLabel $lbl $barWidth
            $line2 = ""
        }
        $xLabelsRow1 += (_center $line1 $barWidth) + (" " * $padBetween)
        $xLabelsRow2 += (_center $line2 $barWidth) + (" " * $padBetween)
    }
    $output.Add($xLabelsRow1)
    if ($hasTwoLines) { $output.Add($xLabelsRow2) }

    return $output.ToArray()
}

function Format-BarChartStacked {
    <#
    Variant of Format-BarChart for stacked input+output charts (Token mode).
    Shows bars where the BOTTOM part is input_tokens and the TOP part output_tokens,
    distinguished by different characters (input=█ output=▓).
    #>
    param(
        [string]$Title,
        [string[]]$Labels,
        [double[]]$InputValues,
        [double[]]$OutputValues,
        [int]$Height = 8,
        [int]$Width = 56
    )

    $output = New-Object System.Collections.Generic.List[string]
    $output.Add($Title)
    $output.Add("")   # #1: riga di spaziatura tra titolo e grafico

    if (-not $InputValues -or $InputValues.Count -eq 0) {
        $output.Add("  " + (T 'analytics.no_chart_data'))
        return $output.ToArray()
    }

    # I compute the total for each bar and the overall max
    $totals = @()
    for ($i = 0; $i -lt $InputValues.Count; $i++) {
        $totals += ($InputValues[$i] + $OutputValues[$i])
    }
    $maxVal = ($totals | Measure-Object -Maximum).Maximum
    if ($maxVal -le 0) { $maxVal = 1 }

    function _fmtTok($v) {
        if ($v -ge 1000000) { return ("{0,5:F1}M" -f ($v / 1000000.0)) }
        elseif ($v -ge 1000) { return ("{0,5:F1}k" -f ($v / 1000.0)) }
        else { return ("{0,6:D}" -f [int]$v) }
    }
    # Compact version (without padding) for the values printed inside the bars
    function _fmtTokBar($v) {
        if ($v -ge 1000000) { return ("{0:F1}M" -f ($v / 1000000.0)) }
        elseif ($v -ge 1000) { return ("{0:F1}k" -f ($v / 1000.0)) }
        else { return ("{0:D}" -f [int]$v) }
    }
    function _centerS([string]$s, [int]$w) {
        if ($s.Length -ge $w) { return $s.Substring(0, $w) }
        $totalPad = $w - $s.Length
        $left = [math]::Floor($totalPad / 2.0)
        return (" " * $left) + $s + (" " * ($totalPad - $left))
    }
    # Like _centerS, but the padding uses a FILL CHARACTER (e.g. the bar
    # block) instead of spaces: this way the value appears "inside" the bar, without
    # color/background interruptions at the sides of the digits. I also add a single
    # space to the left and right of the digits (if there is margin) to detach them from the
    # blocks and make them more readable.
    function _centerOnFill([string]$s, [int]$w, [string]$fill) {
        if ($s.Length -ge $w) { return $s.Substring(0, $w) }
        # I add surrounding spaces to the digits if there is room (>=2 of margin)
        $core = $s
        if (($w - $s.Length) -ge 2) { $core = " " + $s + " " }
        if ($core.Length -ge $w) { return $core.Substring(0, $w) }
        $totalPad = $w - $core.Length
        $left = [math]::Floor($totalPad / 2.0)
        $right = $totalPad - $left
        return ($fill * $left) + $core + ($fill * $right)
    }

    $nBars = $InputValues.Count
    $axisWidth = 8
    $barAreaWidth = $Width - $axisWidth
    if ($barAreaWidth -lt $nBars) { $barAreaWidth = $nBars * 4 }
    $barWidth = [math]::Max(3, [math]::Floor($barAreaWidth / $nBars))
    $padBetween = 1
    # Characters for the bars: chosen to have a sharp contrast between input and output.
    # input: full block (█) - very dense, "heavy"
    # output: light shade (░) - very sparse, "light"
    # The visual separation is marked even on monochrome terminals.
    $blockInput  = [char]0x2588   # █ FULL BLOCK
    $blockOutput = [char]0x2591   # ░ LIGHT SHADE

    # #2/#4 (Token): three levels of information, consistent with the currency charts:
    # - ABOVE the bar: the TOTAL (input+output), like the values row of the
    # non-stacked charts. Row marked "__VAL__" so on screen it is colored (yellow).
    # - INSIDE the bar, at the BOTTOM: the input value (input segment, usually small).
    # - INSIDE the bar, at the TOP: the output value, positioned high (not at the middle
    # of the output segment, which with a tiny input fell too low).
    function _rowForHeight([double]$h) {
        if ($maxVal -le 0) { return 1 }
        $r = [int][math]::Round(($h / $maxVal) * $Height)
        if ($r -lt 1) { $r = 1 }
        if ($r -gt $Height) { $r = $Height }
        return $r
    }
    $inputLabelRow  = @{}   # row -> @{ barIndex = string }
    $outputLabelRow = @{}
    for ($i = 0; $i -lt $InputValues.Count; $i++) {
        $inV = $InputValues[$i]; $outV = $OutputValues[$i]; $totV = $inV + $outV
        if ($totV -le 0) { continue }
        # input: circa a meta' del (piccolo) segmento input, in basso.
        $rowIn = _rowForHeight ($inV / 2.0)
        # output: at the TOP in the output segment. We place it at ~75% of the height
        # of the output segment (measured from the top of the input), so it is in the
        # upper part of the bar instead of the middle. Clamped below the top (Height) to
        # stay inside the bar and not overlap the total printed above.
        $rowOut = _rowForHeight ($inV + ($outV * 0.75))
        if ($rowOut -ge $Height) { $rowOut = $Height - 1 }
        if ($rowOut -lt 1) { $rowOut = 1 }
        # I avoid input/output overlap on the same row
        if ($rowOut -le $rowIn) { $rowOut = [math]::Min($Height - 1, $rowIn + 1) }
        if ($inV -gt 0) {
            if (-not $inputLabelRow.ContainsKey($rowIn)) { $inputLabelRow[$rowIn] = @{} }
            $inputLabelRow[$rowIn][$i] = (_fmtTokBar $inV)
        }
        if ($outV -gt 0) {
            if (-not $outputLabelRow.ContainsKey($rowOut)) { $outputLabelRow[$rowOut] = @{} }
            $outputLabelRow[$rowOut][$i] = (_fmtTokBar $outV)
        }
    }

    # TOTAL row above the bars (as in the currency charts), marked for the color.
    $totalsRow = (" " * $axisWidth)
    foreach ($tot in $totals) {
        $totStr = if ($tot -gt 0) { _fmtTokBar $tot } else { "" }
        $totalsRow += (_centerS $totStr $barWidth) + (" " * $padBetween)
    }
    $output.Add("__VAL__" + $totalsRow)

    # #4: 4 levels on the Y axis
    $yLevels = @($Height, [int][math]::Round($Height * 2 / 3.0), [int][math]::Round($Height / 3.0), 1)

    for ($row = $Height; $row -ge 1; $row--) {
        $thresholdRatio = $row / [double]$Height
        $thresholdVal = $maxVal * $thresholdRatio

        $axisLabel = ""
        if ($yLevels -contains $row) {
            $axisLabel = (_fmtTok $thresholdVal)
        }
        $axisLabel = $axisLabel.PadLeft($axisWidth - 2) + " |"

        $barRow = ""
        for ($i = 0; $i -lt $InputValues.Count; $i++) {
            $inputV  = $InputValues[$i]
            $outputV = $OutputValues[$i]
            $totalV  = $inputV + $outputV

            # Base cell (empty / input / output)
            $cell = if ($thresholdVal -gt $totalV + 0.0001) {
                " " * $barWidth
            } elseif ($thresholdVal -le $inputV + 0.0001) {
                ([string]$blockInput) * $barWidth
            } else {
                ([string]$blockOutput) * $barWidth
            }
            # I overwrite with the value if this is the row designated for input or output.
            # IMPORTANT: so as not to create a black "hole" in the bar, the padding around
            # the digits does NOT use spaces but the BAR CHARACTER (blockInput for the
            # input segment, blockOutput for the output). This way the value appears written
            # "inside" the bar, with the bar pattern at the sides, without interruptions.
            $valHere = $null
            $fillChar = [string]$blockOutput
            if ($inputLabelRow.ContainsKey($row) -and $inputLabelRow[$row].ContainsKey($i))  {
                $valHere = $inputLabelRow[$row][$i]; $fillChar = [string]$blockInput
            }
            if ($outputLabelRow.ContainsKey($row) -and $outputLabelRow[$row].ContainsKey($i)) {
                $valHere = $outputLabelRow[$row][$i]; $fillChar = [string]$blockOutput
            }
            if ($null -ne $valHere) {
                $cell = _centerOnFill $valHere $barWidth $fillChar
            }
            $barRow += $cell + (" " * $padBetween)
        }
        $output.Add($axisLabel + " " + $barRow)
    }

    $barsRealWidth = ($nBars * $barWidth) + (($nBars - 1) * $padBetween)
    $baseline = (" " * ($axisWidth - 2)) + " +" + ("-" * $barsRealWidth)
    $output.Add($baseline)

    # Readable abbreviation of the labels (see note in Format-BarChart).
    function _shortLabelS([string]$lbl, [int]$w) {
        if ($lbl.Length -le $w) { return $lbl }
        if ($w -le 3) { return $lbl.Substring(0, $w) }
        if ($w -le 6) { return $lbl.Substring(0, $w - 1) + "." }
        $keep = $w - 3
        $head = [math]::Ceiling($keep / 2.0)
        $tail = $keep - $head
        return $lbl.Substring(0, $head) + "..." + $lbl.Substring($lbl.Length - $tail, $tail)
    }
    $xLabelsRow1 = (" " * $axisWidth)
    $xLabelsRow2 = (" " * $axisWidth)
    $hasTwoLines = ($Labels | Where-Object { $_ -like "*|*" } | Measure-Object).Count -gt 0
    foreach ($lbl in $Labels) {
        if ($lbl -like "*|*") {
            $parts = $lbl -split '\|', 2
            $line1 = _shortLabelS $parts[0].Trim() $barWidth
            $line2 = _shortLabelS $parts[1].Trim() $barWidth
        } else {
            $line1 = _shortLabelS $lbl $barWidth
            $line2 = ""
        }
        $xLabelsRow1 += (_centerS $line1 $barWidth) + (" " * $padBetween)
        $xLabelsRow2 += (_centerS $line2 $barWidth) + (" " * $padBetween)
    }
    $output.Add($xLabelsRow1)
    if ($hasTwoLines) { $output.Add($xLabelsRow2) }
    $output.Add((" " * ($axisWidth - 2)) + "   (" + [string]$blockInput + "=input  " + [string]$blockOutput + "=output)")

    return $output.ToArray()
}

function Join-ChartsHorizontal {
    <#
    Combines 2 charts (arrays of strings) in a 2-column side-by-side layout.
    The rows are aligned and separated by a central space.

    IMPORTANT: $LeftWidth is used as the FIXED WIDTH of the left column. If
    a Left row is longer than $LeftWidth, it overflows to the right and misaligns
    the right column. For the stacked charts (Token with legend) the legend
    row can be longer than the others, so $LeftWidth must be
    >= max(Left[i].Length).

    Se -LeftWidth e' 0 (default), lo calcoliamo dinamicamente dal max dei Left.
    #>
    param(
        [string[]]$Left,
        [string[]]$Right,
        [int]$LeftWidth = 0,
        [int]$Separator = 3
    )

    # The "__VAL__" marker at the start of a row indicates a "values row" (numbers
    # above the bars) that on screen must be colored. We remove it here for the calculation of
    # the widths and the alignment, and re-mark the resulting COMBINED row with
    # "__VALROW__" at the start, so the on-screen output can color it. The removal
    # happens on Left and Right separately before the join.
    $VAL = "__VAL__"
    function _stripVal([string]$s, [ref]$wasVal) {
        if ($s.StartsWith($VAL)) { $wasVal.Value = $true; return $s.Substring($VAL.Length) }
        return $s
    }

    # Dynamic calculation of the left column width if not specified.
    # NB: I calculate on the version WITHOUT the marker so as not to distort the width.
    if ($LeftWidth -le 0) {
        $maxLen = 0
        foreach ($l in $Left) {
            $clean = if ($l.StartsWith($VAL)) { $l.Substring($VAL.Length) } else { $l }
            if ($clean.Length -gt $maxLen) { $maxLen = $clean.Length }
        }
        $LeftWidth = $maxLen
    }

    $output = @()
    $maxRows = [math]::Max($Left.Count, $Right.Count)
    for ($i = 0; $i -lt $maxRows; $i++) {
        $l = if ($i -lt $Left.Count)  { $Left[$i]  } else { "" }
        $r = if ($i -lt $Right.Count) { $Right[$i] } else { "" }
        $wasVal = $false
        $l = _stripVal $l ([ref]$wasVal)
        $r = _stripVal $r ([ref]$wasVal)
        # Padding a destra del blocco sinistro per allineare
        if ($l.Length -lt $LeftWidth) { $l = $l.PadRight($LeftWidth) }
        $combined = $l + (" " * $Separator) + $r
        if ($wasVal) { $combined = "__VALROW__" + $combined }
        $output += $combined
    }
    return $output
}

# Generates the labels of the last N days for the analytics charts.
function Get-LastNDays {
    param([int]$N)
    $today = (Get-Date).Date
    $days = @()
    for ($i = $N - 1; $i -ge 0; $i--) {
        $days += $today.AddDays(-$i)
    }
    return $days
}

# Generates the labels of the last N months for the analytics charts.
function Get-LastNMonths {
    param([int]$N)
    $now = Get-Date
    $months = @()
    for ($i = $N - 1; $i -ge 0; $i--) {
        $months += (Get-Date -Year $now.Year -Month $now.Month -Day 1).AddMonths(-$i)
    }
    return $months
}

# Generates the labels of the last N years for the analytics charts.
function Get-LastNYears {
    param([int]$N)
    $now = Get-Date
    $years = @()
    for ($i = $N - 1; $i -ge 0; $i--) {
        $years += $now.Year - $i
    }
    return $years
}

function Export-AnalyticsCsv {
    <#
    Exports ALL the cost records (from the first to the last) to a CSV file suitable for
    Business Intelligence / dashboard systems.

    Record layout (one row per logged generation, ordered by date):
      Date              date of the generation (yyyy-MM-dd, ISO, culture-independent)
      Model             logical name of the model
      PricingMode       "tokens" | "megapixels"
      NImages           number of images generated by the line (batch)
      InputTokens       input tokens (0 for per-megapixel models)
      OutputTokens      output tokens (0 for per-megapixel models)
      TotalTokens       total tokens
      GenMegapixels     generated megapixels (0 for token-based models)
      ReferenceMegapixels megapixels of the reference images (per-MP edit)
      InputUSD/OutputUSD/TotalUSD   costs in USD
      InputEUR/OutputEUR/TotalEUR   costs in EUR
      EurRate           USD->EUR rate applied to that line
      CostPerImageUSD   TotalUSD / NImages (handy for dashboards)
      CostPerImageEUR   TotalEUR / NImages

    Numeric format and separator: the CSV is an OUTPUT toward the user, so it follows
    the system's regional settings (like the charts and messages). The decimals
    use the culture's separator (e.g. comma in IT) via Format-DisplayNumber, and
    the column separator is the culture's ListSeparator ($script:CsvListSeparator,
    ";" in IT/DE/FR, "," in US/UK). This way Excel opens the file correctly according to the
    local settings, without the comma decimals colliding with the column
    separator. The numbers do NOT use a thousands separator (it would create ambiguity).
    UTF-8 encoding with BOM (Excel recognizes the encoding and the non-ASCII characters).
    #>
    param(
        [Parameter(Mandatory=$true)][string]$CsvPath,
        [double]$EurRate = 1.0
    )

    # Contextual log (file only): without it, in the .log it would not be clear that a
    # full CSV export was launched. On screen the save message remains.
    if ($script:LogFile) {
        $tsCsv = (Get-Date).ToString("yyyy-MM-dd HH:mm:ss", [System.Globalization.CultureInfo]::InvariantCulture)
        Add-Content -Path $script:LogFile -Value (Protect-LogFileLine ("[$tsCsv] [INFO] " + (T 'analytics.log_csv_command' $CsvPath))) -Encoding UTF8 -ErrorAction SilentlyContinue
    }

    $records = Get-CostRecordsFromLog -LogPath $script:LogFile
    if (@($records).Count -eq 0) {
        Write-Log (T 'analytics.no_data' $script:LogFile) -Level WARN
        return
    }

    $resolved = if ([System.IO.Path]::IsPathRooted($CsvPath)) { $CsvPath } else { Join-Path $PSScriptRoot $CsvPath }

    # If the CSV already exists, warn and overwrite (agreed behavior for
    # the export: unlike -AnalyticsFile, here we always overwrite with a WARN,
    # because an "all data" export is by nature a complete and
    # regenerable snapshot, not an incremental report to preserve).
    if (Test-Path $resolved) {
        Write-Log (T 'analytics.csv_overwrite' $resolved) -Level WARN
    }

    # Column separator from the system culture (";" in IT, "," in US).
    $sep = $script:CsvListSeparator
    # Numbers in local format, WITHOUT a thousands separator (to avoid ambiguity
    # with the column separator). E.g. in IT: "0,047875"; in US: "0.047875".
    function _csvNum($v, [int]$dec = 6) {
        return (Format-DisplayNumber -Value ([double]$v) -Decimals $dec)
    }

    # I sort the records by ascending date (from the first to the last)
    $sorted = $records | Sort-Object Date

    $sb = New-Object System.Text.StringBuilder
    # Header (the column headings stay in English, they are field names).
    $header = @("Date","Model","PricingMode","NImages","InputTokens","OutputTokens",
                "TotalTokens","GenMegapixels","ReferenceMegapixels","InputUSD","OutputUSD",
                "TotalUSD","InputEUR","OutputEUR","TotalEUR","EurRate","CostPerImageUSD",
                "CostPerImageEUR","TokensEstimated") -join $sep
    [void]$sb.AppendLine($header)

    foreach ($r in $sorted) {
        $nImg = if ($r.NImages -and $r.NImages -gt 0) { [int]$r.NImages } else { 1 }
        # PricingMode and the megapixels are not fields of the parsed record by default
        # (Get-CostRecordsFromLog does not expose them): I derive them if present, otherwise
        # I infer "megapixels" when the tokens are 0 but there is a cost.
        $pMode = "tokens"
        if (($r.TotalTokens -eq 0) -and ($r.TotalUsd -gt 0)) { $pMode = "megapixels" }
        $genMp = 0; $refMp = 0   # i MP non sono nel record base; restano 0 nel CSV
                                  # (the total cost stays correct and sufficient for BI)

        $costPerImgUsd = if ($nImg -gt 0) { $r.TotalUsd / $nImg } else { $r.TotalUsd }
        $costPerImgEur = if ($nImg -gt 0) { $r.TotalEur / $nImg } else { $r.TotalEur }

        # I quote the model name for safety (it could in theory contain the separator).
        $modelCell = '"' + ($r.Model -replace '"','""') + '"'
        $dateCell  = $r.Date.ToString("yyyy-MM-dd", [System.Globalization.CultureInfo]::InvariantCulture)
        # Estimated (1) vs measured (0) cost flag: useful in BI to filter/flag.
        $estCell   = if (($r.PSObject.Properties.Name -contains 'TokensEstimated') -and $r.TokensEstimated) { "1" } else { "0" }

        $line = @(
            $dateCell, $modelCell, $pMode, $nImg,
            $r.InputTokens, $r.OutputTokens, $r.TotalTokens,
            $genMp, $refMp,
            (_csvNum $r.InputUsd), (_csvNum $r.OutputUsd), (_csvNum $r.TotalUsd),
            (_csvNum $r.InputEur), (_csvNum $r.OutputEur), (_csvNum $r.TotalEur),
            (_csvNum $EurRate 4),
            (_csvNum $costPerImgUsd), (_csvNum $costPerImgEur), $estCell
        ) -join $sep
        [void]$sb.AppendLine($line)
    }

    try {
        # UTF-8 with BOM: Excel recognizes the encoding and shows the special characters well.
        $utf8Bom = New-Object System.Text.UTF8Encoding($true)
        [System.IO.File]::WriteAllText($resolved, $sb.ToString(), $utf8Bom)
        Write-Log (T 'analytics.csv_exported' $resolved (@($records).Count))
    }
    catch {
        Write-Log (T 'analytics.write_failed' $resolved ($_.Exception.Message)) -Level ERROR
    }
}

function Invoke-Analytics {
    <#
    Generates all 8 analytics charts and returns them as an array of strings.
    If -OutputFile is specified, it writes to a file; otherwise to the screen.

    -Currency parameter: "EUR" | "USD" | "Token"
      - EUR/USD: standard bar charts with costs
      - Token: stacked input+output charts

    The data is read from the New-GPTImage.log file via Get-CostRecordsFromLog.
    #>
    param(
        [Parameter(Mandatory=$true)] [string]$Currency,
        [string]$OutputFile = ""
    )

    # Uniform width of the charts. Used both for -Width of the individual charts and
    # for the fixed LeftWidth of the 2-column layout (see further on). Keeping it in a
    # single variable guarantees that bars, labels and alignment stay consistent.
    $script:AnalyticsChartWidth = 64

    $records = Get-CostRecordsFromLog -LogPath $script:LogFile
    if (@($records).Count -eq 0) {
        $msg = T 'analytics.no_data' $script:LogFile
        if ($OutputFile) {
            Set-Content -Path $OutputFile -Value $msg -Encoding UTF8
        } else {
            Write-Host $msg
        }
        return
    }

    # === MODEL-NAME CANONICALIZATION ===
    # The model names in the log can diverge from the .conf names: historical typos,
    # temporary deployment suffixes (e.g. "gpt-image-2-cto"), upper/lowercase
    # variants or spaces. Without merging, these generate PHANTOM BARS
    # in the per-model charts (4-8), often indistinguishable from the "real" bar because
    # the label truncates to the same visible string. The merged records flow into
    # the parent model: their costs/images add up in the correct bar.
    # The merging logic is centralized in Get-CanonicalModelName (shared
    # with -Auto Time and the kNN estimate), so there is a single point to maintain.
    $canonMap = @{}
    $confModelNames = @()
    if ($config -and $config.models) {
        $confModelNames = @($config.models.PSObject.Properties.Name)
    }
    foreach ($rec in $records) {
        $rec.Model = Get-CanonicalModelName -RawName ([string]$rec.Model) -ConfModelNames $confModelNames -CanonMap $canonMap
    }

    # I separate the TEXT MODEL records (kind=textmodel) from the IMAGE ones: the
    # charts 1-8 concern only the images, the new 9-10 only the text. Without
    # this separation the text costs would pollute the image charts (and the
    # text model would appear as a "phantom bar" among the image models).
    $textRecords = @($records | Where-Object { $_.Kind -eq 'textmodel' })
    $records     = @($records | Where-Object { $_.Kind -ne 'textmodel' })

    # Selettori basati su Currency
    $isToken = ($Currency -eq "Token")

    # Helper function to extract the correct value (field)
    function _valFor($rec, [string]$Which) {
        # $Which: "Total", "Input", "Output"
        if ($isToken) {
            switch ($Which) {
                "Total"  { return [double]$rec.TotalTokens }
                "Input"  { return [double]$rec.InputTokens }
                "Output" { return [double]$rec.OutputTokens }
            }
        } elseif ($Currency -eq "EUR") {
            switch ($Which) {
                "Total"  { return $rec.TotalEur }
                "Input"  { return $rec.InputEur }
                "Output" { return $rec.OutputEur }
            }
        } else {  # USD
            switch ($Which) {
                "Total"  { return $rec.TotalUsd }
                "Input"  { return $rec.InputUsd }
                "Output" { return $rec.OutputUsd }
            }
        }
    }

    # === DATA: aggregated by day, month, year, model ===

    # 1. Cost per day (last 7 days)
    # Compact day/month labels. They respect the system culture's order:
    # in US-style cultures the order is month-day (MM/dd), elsewhere day-month (dd/MM).
    # We keep the compact form (2 components) so as not to break the charts layout.
    $days = Get-LastNDays -N 7
    $script:DayMonthCompact = if ($script:CultureMonthFirst) { "MM/dd" } else { "dd/MM" }
    $dayLabels = $days | ForEach-Object { $_.ToString($script:DayMonthCompact) }
    $dayTotals = @(); $dayInputs = @(); $dayOutputs = @()
    foreach ($d in $days) {
        $filtered = $records | Where-Object { $_.Date.Date -eq $d }
        $dayTotals  += ([double](($filtered | ForEach-Object { _valFor $_ "Total"  } | Measure-Object -Sum).Sum))
        $dayInputs  += ([double](($filtered | ForEach-Object { _valFor $_ "Input"  } | Measure-Object -Sum).Sum))
        $dayOutputs += ([double](($filtered | ForEach-Object { _valFor $_ "Output" } | Measure-Object -Sum).Sum))
    }

    # 2. Cost per month (last 7 months)
    $months = Get-LastNMonths -N 7
    $monthLabels = $months | ForEach-Object { $_.ToString("MM/yy") }
    $monthTotals = @(); $monthInputs = @(); $monthOutputs = @()
    foreach ($m in $months) {
        $filtered = $records | Where-Object {
            $_.Date.Year -eq $m.Year -and $_.Date.Month -eq $m.Month
        }
        $monthTotals  += ([double](($filtered | ForEach-Object { _valFor $_ "Total"  } | Measure-Object -Sum).Sum))
        $monthInputs  += ([double](($filtered | ForEach-Object { _valFor $_ "Input"  } | Measure-Object -Sum).Sum))
        $monthOutputs += ([double](($filtered | ForEach-Object { _valFor $_ "Output" } | Measure-Object -Sum).Sum))
    }

    # 3. Cost per year (last 7 years)
    $years = Get-LastNYears -N 7
    $yearLabels = $years | ForEach-Object { $_.ToString() }
    $yearTotals = @(); $yearInputs = @(); $yearOutputs = @()
    foreach ($y in $years) {
        $filtered = $records | Where-Object { $_.Date.Year -eq $y }
        $yearTotals  += ([double](($filtered | ForEach-Object { _valFor $_ "Total"  } | Measure-Object -Sum).Sum))
        $yearInputs  += ([double](($filtered | ForEach-Object { _valFor $_ "Input"  } | Measure-Object -Sum).Sum))
        $yearOutputs += ([double](($filtered | ForEach-Object { _valFor $_ "Output" } | Measure-Object -Sum).Sum))
    }

    # Distinct models present in the log
    $modelsInLog = @($records | Select-Object -ExpandProperty Model -Unique | Sort-Object)
    # I limit to a max of 7 models for readability (it would be odd to have more)
    if ($modelsInLog.Count -gt 7) {
        $modelsInLog = $modelsInLog | Select-Object -First 7
    }

    # Map model-name -> shortName (from the .conf) for the labels of the per-model
    # charts. The shortName uses '|' to go on two rows (name / version).
    # If a model has no shortName in the conf (or is not in the conf), the full name is used.
    function _modelShortLabel([string]$modelName) {
        if ($config -and $config.models -and ($config.models.PSObject.Properties.Name -contains $modelName)) {
            $sn = $config.models.$modelName.shortName
            if ($sn -and $sn.Trim() -ne "") { return $sn }
        }
        return $modelName
    }
    $modelShortLabels = @($modelsInLog | ForEach-Object { _modelShortLabel $_ })

    # 4. Number of images generated per model (sum of n_images, no time filter).
    # NB: a COST line with n_images=4 represents 4 images generated in a batch;
    # we sum n_images (not the line count) to reflect the real images.
    $imgPerModelLabels = $modelShortLabels
    $imgPerModelValues = @()
    foreach ($mdl in $modelsInLog) {
        $imgPerModelValues += [double]((@($records | Where-Object { $_.Model -eq $mdl }) | ForEach-Object { $_.NImages } | Measure-Object -Sum).Sum)
    }

    # 5-8. Aggregated per model (for each model, sum of costs in the last 7 days/months/years/overall)
    # For charts 5-7 I use a layout: one bar per model with the period's sum.
    # NB: in Token mode, each bar is stacked input/output.
    #
    # IMPORTANT (chart consistency): the 7d/7m/7y windows use the SAME calendar
    # buckets as the temporal charts 1/2/3 (the $days, $months, $years sets already
    # computed above), NOT a "rolling" cutoff (Get-Date).AddDays(-7). A rolling
    # cutoff with -ge would cover 8 days instead of 7 (today + 7 previous), making
    # records that do NOT appear in charts 1/2/3 enter these charts and making
    # the totals inconsistent between charts that should match. By using the same
    # buckets, the per-model-7d sum coincides exactly with the sum of chart 1.
    $daySet   = @{}; foreach ($d in $days)   { $daySet[$d.Date]            = $true }
    $monthSet = @{}; foreach ($m in $months) { $monthSet["$($m.Year)-$($m.Month)"] = $true }
    $yearSet  = @{}; foreach ($y in $years)  { $yearSet[[int]$y]           = $true }

    $modelLabels7d = $modelShortLabels
    $modelTotals7d = @(); $modelInputs7d = @(); $modelOutputs7d = @()
    foreach ($mdl in $modelsInLog) {
        $filtered = $records | Where-Object { $_.Model -eq $mdl -and $daySet.ContainsKey($_.Date.Date) }
        $modelTotals7d  += ([double](($filtered | ForEach-Object { _valFor $_ "Total"  } | Measure-Object -Sum).Sum))
        $modelInputs7d  += ([double](($filtered | ForEach-Object { _valFor $_ "Input"  } | Measure-Object -Sum).Sum))
        $modelOutputs7d += ([double](($filtered | ForEach-Object { _valFor $_ "Output" } | Measure-Object -Sum).Sum))
    }

    $modelLabels7m = $modelShortLabels
    $modelTotals7m = @(); $modelInputs7m = @(); $modelOutputs7m = @()
    foreach ($mdl in $modelsInLog) {
        $filtered = $records | Where-Object { $_.Model -eq $mdl -and $monthSet.ContainsKey("$($_.Date.Year)-$($_.Date.Month)") }
        $modelTotals7m  += ([double](($filtered | ForEach-Object { _valFor $_ "Total"  } | Measure-Object -Sum).Sum))
        $modelInputs7m  += ([double](($filtered | ForEach-Object { _valFor $_ "Input"  } | Measure-Object -Sum).Sum))
        $modelOutputs7m += ([double](($filtered | ForEach-Object { _valFor $_ "Output" } | Measure-Object -Sum).Sum))
    }

    $modelLabels7y = $modelShortLabels
    $modelTotals7y = @(); $modelInputs7y = @(); $modelOutputs7y = @()
    foreach ($mdl in $modelsInLog) {
        $filtered = $records | Where-Object { $_.Model -eq $mdl -and $yearSet.ContainsKey([int]$_.Date.Year) }
        $modelTotals7y  += ([double](($filtered | ForEach-Object { _valFor $_ "Total"  } | Measure-Object -Sum).Sum))
        $modelInputs7y  += ([double](($filtered | ForEach-Object { _valFor $_ "Input"  } | Measure-Object -Sum).Sum))
        $modelOutputs7y += ([double](($filtered | ForEach-Object { _valFor $_ "Output" } | Measure-Object -Sum).Sum))
    }

    # 8. Overall per model (entire history)
    $modelLabelsOverall = $modelShortLabels
    $modelTotalsOverall = @(); $modelInputsOverall = @(); $modelOutputsOverall = @()
    foreach ($mdl in $modelsInLog) {
        $filtered = $records | Where-Object { $_.Model -eq $mdl }
        $modelTotalsOverall  += ([double](($filtered | ForEach-Object { _valFor $_ "Total"  } | Measure-Object -Sum).Sum))
        $modelInputsOverall  += ([double](($filtered | ForEach-Object { _valFor $_ "Input"  } | Measure-Object -Sum).Sum))
        $modelOutputsOverall += ([double](($filtered | ForEach-Object { _valFor $_ "Output" } | Measure-Object -Sum).Sum))
    }

    # === CHART CONSTRUCTION ===

    $fmtVal = if ($isToken) { "tokens" } else { "currency" }

    # #3: helper for the "Total" to append to the title of each chart.
    # For currencies: sums the values, 2-decimal format. For tokens: sums input+output,
    # compact format (k/M). The string is already ready to concatenate to the title.
    function _chartTotalCurrency([double[]]$vals) {
        $sum = ($vals | Measure-Object -Sum).Sum
        if (-not $sum) { $sum = 0 }
        return (T 'analytics.title_total' ("{0:N2}" -f $sum))
    }
    function _chartTotalTokens([double[]]$ins, [double[]]$outs) {
        $si = ($ins  | Measure-Object -Sum).Sum; if (-not $si) { $si = 0 }
        $so = ($outs | Measure-Object -Sum).Sum; if (-not $so) { $so = 0 }
        $sum = $si + $so
        $fmt = if ($sum -ge 1000000) { "{0:N1}M" -f ($sum / 1000000.0) }
               elseif ($sum -ge 1000) { "{0:N1}k" -f ($sum / 1000.0) }
               else { "{0:N0}" -f $sum }
        return (T 'analytics.title_total' $fmt)
    }
    function _chartTotalInt([double[]]$vals) {
        $sum = ($vals | Measure-Object -Sum).Sum; if (-not $sum) { $sum = 0 }
        return (T 'analytics.title_total' ("{0:N0}" -f $sum))
    }

    # === TEXT DATA for charts [9] and [10] (only kind=textmodel records) ===
    # [9] Text cost per month (last 7 months), respects EUR/USD/Token like the others.
    $textMonths = Get-LastNMonths -N 7
    $textMonthLabels = $textMonths | ForEach-Object { $_.ToString("MM/yy") }
    $textMonthTotals = @(); $textMonthInputs = @(); $textMonthOutputs = @()
    foreach ($m in $textMonths) {
        $tf = $textRecords | Where-Object { $_.Date.Year -eq $m.Year -and $_.Date.Month -eq $m.Month }
        $textMonthTotals  += ([double](($tf | ForEach-Object { _valFor $_ "Total"  } | Measure-Object -Sum).Sum))
        $textMonthInputs  += ([double](($tf | ForEach-Object { _valFor $_ "Input"  } | Measure-Object -Sum).Sum))
        $textMonthOutputs += ([double](($tf | ForEach-Object { _valFor $_ "Output" } | Measure-Object -Sum).Sum))
    }
    # [10] Text cost per FUNCTION (operation: optimize/negative/storyboard/describe).
    $opOrder = @("optimize","negative","storyboard","describe")
    $textOpLabels = @(); $textOpTotals = @(); $textOpInputs = @(); $textOpOutputs = @()
    foreach ($op in $opOrder) {
        $of = $textRecords | Where-Object { $_.Operation -eq $op }
        if (@($of).Count -eq 0) { continue }
        $textOpLabels  += (T ('textcost.op_' + $op))
        $textOpTotals  += ([double](($of | ForEach-Object { _valFor $_ "Total"  } | Measure-Object -Sum).Sum))
        $textOpInputs  += ([double](($of | ForEach-Object { _valFor $_ "Input"  } | Measure-Object -Sum).Sum))
        $textOpOutputs += ([double](($of | ForEach-Object { _valFor $_ "Output" } | Measure-Object -Sum).Sum))
    }

    if ($isToken) {
        $g1 = Format-BarChartStacked -Title ((T 'analytics.chart_tokens_per_day')   + (_chartTotalTokens $dayInputs $dayOutputs))     -Labels $dayLabels   -InputValues $dayInputs   -OutputValues $dayOutputs
        $g2 = Format-BarChartStacked -Title ((T 'analytics.chart_tokens_per_month') + (_chartTotalTokens $monthInputs $monthOutputs)) -Labels $monthLabels -InputValues $monthInputs -OutputValues $monthOutputs
        $g3 = Format-BarChartStacked -Title ((T 'analytics.chart_tokens_per_year')  + (_chartTotalTokens $yearInputs $yearOutputs))   -Labels $yearLabels  -InputValues $yearInputs  -OutputValues $yearOutputs
    } else {
        $g1 = Format-BarChart -Title ((T 'analytics.chart_cost_per_day'   $Currency) + (_chartTotalCurrency $dayTotals))   -Labels $dayLabels   -Values $dayTotals   -ValueFormat $fmtVal
        $g2 = Format-BarChart -Title ((T 'analytics.chart_cost_per_month' $Currency) + (_chartTotalCurrency $monthTotals)) -Labels $monthLabels -Values $monthTotals -ValueFormat $fmtVal
        $g3 = Format-BarChart -Title ((T 'analytics.chart_cost_per_year'  $Currency) + (_chartTotalCurrency $yearTotals))  -Labels $yearLabels  -Values $yearTotals  -ValueFormat $fmtVal
    }
    # "(IMG)" to the title of chart 4 for homogeneity with the others (currency in
    # parentheses) and to save the space of the "(unit: img)" below.
    $g4 = Format-BarChart -Title ((T 'analytics.chart_images_per_model') + (_chartTotalInt $imgPerModelValues)) -Labels $imgPerModelLabels -Values $imgPerModelValues -ValueFormat "int"

    if ($isToken) {
        $g5 = Format-BarChartStacked -Title ((T 'analytics.chart_tokens_per_model_7d')    + (_chartTotalTokens $modelInputs7d $modelOutputs7d))           -Labels $modelLabels7d -InputValues $modelInputs7d -OutputValues $modelOutputs7d
        $g6 = Format-BarChartStacked -Title ((T 'analytics.chart_tokens_per_model_7m')    + (_chartTotalTokens $modelInputs7m $modelOutputs7m))           -Labels $modelLabels7m -InputValues $modelInputs7m -OutputValues $modelOutputs7m
        $g7 = Format-BarChartStacked -Title ((T 'analytics.chart_tokens_per_model_7y')    + (_chartTotalTokens $modelInputs7y $modelOutputs7y))           -Labels $modelLabels7y -InputValues $modelInputs7y -OutputValues $modelOutputs7y
        $g8 = Format-BarChartStacked -Title ((T 'analytics.chart_tokens_per_model_total') + (_chartTotalTokens $modelInputsOverall $modelOutputsOverall)) -Labels $modelLabelsOverall -InputValues $modelInputsOverall -OutputValues $modelOutputsOverall
    } else {
        $g5 = Format-BarChart -Title ((T 'analytics.chart_cost_per_model_7d'    $Currency) + (_chartTotalCurrency $modelTotals7d))      -Labels $modelLabels7d -Values $modelTotals7d -ValueFormat $fmtVal
        $g6 = Format-BarChart -Title ((T 'analytics.chart_cost_per_model_7m'    $Currency) + (_chartTotalCurrency $modelTotals7m))      -Labels $modelLabels7m -Values $modelTotals7m -ValueFormat $fmtVal
        $g7 = Format-BarChart -Title ((T 'analytics.chart_cost_per_model_7y'    $Currency) + (_chartTotalCurrency $modelTotals7y))      -Labels $modelLabels7y -Values $modelTotals7y -ValueFormat $fmtVal
        $g8 = Format-BarChart -Title ((T 'analytics.chart_cost_per_model_total' $Currency) + (_chartTotalCurrency $modelTotalsOverall)) -Labels $modelLabelsOverall -Values $modelTotalsOverall -ValueFormat $fmtVal
    }

    # [9] Text model cost in the last 7 months; [10] per function. They respect
    # the currency (EUR/USD: cost bars; Token: stacked input+output bars) like 1-8.
    if ($isToken) {
        $g9  = Format-BarChartStacked -Title ((T 'analytics.chart_textcost_per_month_tok') + (_chartTotalTokens $textMonthInputs $textMonthOutputs)) -Labels $textMonthLabels -InputValues $textMonthInputs -OutputValues $textMonthOutputs
        $g10 = Format-BarChartStacked -Title ((T 'analytics.chart_textcost_per_function_tok') + (_chartTotalTokens $textOpInputs $textOpOutputs))     -Labels $textOpLabels   -InputValues $textOpInputs   -OutputValues $textOpOutputs
    } else {
        $g9  = Format-BarChart -Title ((T 'analytics.chart_textcost_per_month' $Currency) + (_chartTotalCurrency $textMonthTotals)) -Labels $textMonthLabels -Values $textMonthTotals -ValueFormat $fmtVal
        $g10 = Format-BarChart -Title ((T 'analytics.chart_textcost_per_function' $Currency) + (_chartTotalCurrency $textOpTotals)) -Labels $textOpLabels -Values $textOpTotals -ValueFormat $fmtVal
    }

    # === LOG CONTESTUALE (solo file) ===
    # On screen the user sees the charts; but in the log file, without context, it would
    # not be clear what was launched. So I write a series of [INFO] ONLY to the file
    # (not on screen, so as not to duplicate) that summarize: command, currency, export/mode
    # and the 10 chart titles with their overall value. Local helper that bypasses the
    # screen by writing directly to the .log (as Write-CostLog does for the verbose line).
    $logToFileOnly = {
        param([string]$Msg)
        if ($script:LogFile) {
            $ts = (Get-Date).ToString("yyyy-MM-dd HH:mm:ss", [System.Globalization.CultureInfo]::InvariantCulture)
            Add-Content -Path $script:LogFile -Value (Protect-LogFileLine "[$ts] [INFO] $Msg") -Encoding UTF8 -ErrorAction SilentlyContinue
        }
    }
    & $logToFileOnly (T 'analytics.log_command' $Currency)
    if ($OutputFile) {
        $modeLabel = switch ($script:AnalyticsWriteMode) {
            "append"             { T 'analytics.log_mode_append' }
            "overwrite-existing" { T 'analytics.log_mode_overwrite' }
            default              { T 'analytics.log_mode_new' }
        }
        & $logToFileOnly (T 'analytics.log_file' $OutputFile $modeLabel)
    } else {
        & $logToFileOnly (T 'analytics.log_video_only')
    }
    & $logToFileOnly (T 'analytics.log_records' (@($records).Count) (@($textRecords).Count))
    # The 10 titles with the overall total (the same shown in the charts).
    $titlesWithTotals = @(
        if ($isToken) { (T 'analytics.chart_tokens_per_day')   + (_chartTotalTokens $dayInputs $dayOutputs) }   else { (T 'analytics.chart_cost_per_day'   $Currency) + (_chartTotalCurrency $dayTotals) }
        if ($isToken) { (T 'analytics.chart_tokens_per_month') + (_chartTotalTokens $monthInputs $monthOutputs) } else { (T 'analytics.chart_cost_per_month' $Currency) + (_chartTotalCurrency $monthTotals) }
        if ($isToken) { (T 'analytics.chart_tokens_per_year')  + (_chartTotalTokens $yearInputs $yearOutputs) }   else { (T 'analytics.chart_cost_per_year'  $Currency) + (_chartTotalCurrency $yearTotals) }
        (T 'analytics.chart_images_per_model') + (_chartTotalInt $imgPerModelValues)
        if ($isToken) { (T 'analytics.chart_tokens_per_model_7d')    + (_chartTotalTokens $modelInputs7d $modelOutputs7d) }       else { (T 'analytics.chart_cost_per_model_7d'    $Currency) + (_chartTotalCurrency $modelTotals7d) }
        if ($isToken) { (T 'analytics.chart_tokens_per_model_7m')    + (_chartTotalTokens $modelInputs7m $modelOutputs7m) }       else { (T 'analytics.chart_cost_per_model_7m'    $Currency) + (_chartTotalCurrency $modelTotals7m) }
        if ($isToken) { (T 'analytics.chart_tokens_per_model_7y')    + (_chartTotalTokens $modelInputs7y $modelOutputs7y) }       else { (T 'analytics.chart_cost_per_model_7y'    $Currency) + (_chartTotalCurrency $modelTotals7y) }
        if ($isToken) { (T 'analytics.chart_tokens_per_model_total') + (_chartTotalTokens $modelInputsOverall $modelOutputsOverall) } else { (T 'analytics.chart_cost_per_model_total' $Currency) + (_chartTotalCurrency $modelTotalsOverall) }
        if ($isToken) { (T 'analytics.chart_textcost_per_month_tok')    + (_chartTotalTokens $textMonthInputs $textMonthOutputs) } else { (T 'analytics.chart_textcost_per_month'    $Currency) + (_chartTotalCurrency $textMonthTotals) }
        if ($isToken) { (T 'analytics.chart_textcost_per_function_tok') + (_chartTotalTokens $textOpInputs $textOpOutputs) }       else { (T 'analytics.chart_textcost_per_function' $Currency) + (_chartTotalCurrency $textOpTotals) }
    )
    & $logToFileOnly (T 'analytics.log_charts_header')
    foreach ($tt in $titlesWithTotals) { & $logToFileOnly ("  " + $tt) }

    # === LAYOUT: 5 horizontal rows, 2 charts per row (10 charts total) ===
    # I use a FIXED and uniform LeftWidth for ALL the rows, so the right columns
    # (charts [2][4][6][8][10]) all start at the same position. Without this, rows
    # with a different number of bars (7 days vs 4 models) produced different LeftWidths
    # and the right columns turned out misaligned with each other.
    # The max width of a row of the left chart is about:
    # axisWidth(8) + nBars*(barWidth+pad). Con Width=56 il caso peggiore e' ~62.
    $chartLeftWidth = $script:AnalyticsChartWidth + 8
    $finalLines = @()
    $finalLines += "==================================================================="
    $finalLines += (T 'analytics.header_title' $Currency)
    $finalLines += (T 'analytics.header_generated' (Format-DisplayDate))
    $finalLines += (T 'analytics.header_records' (@($records).Count))
    $finalLines += "==================================================================="
    $finalLines += ""
    $finalLines += Join-ChartsHorizontal -Left $g1 -Right $g2 -LeftWidth $chartLeftWidth
    $finalLines += ""
    $finalLines += Join-ChartsHorizontal -Left $g3 -Right $g4 -LeftWidth $chartLeftWidth
    $finalLines += ""
    $finalLines += Join-ChartsHorizontal -Left $g5 -Right $g6 -LeftWidth $chartLeftWidth
    $finalLines += ""
    $finalLines += Join-ChartsHorizontal -Left $g7 -Right $g8 -LeftWidth $chartLeftWidth
    $finalLines += ""
    $finalLines += Join-ChartsHorizontal -Left $g9 -Right $g10 -LeftWidth $chartLeftWidth
    $finalLines += ""
    $finalLines += "==================================================================="

    # I clean the internal "__VALROW__" markers that mark the value rows. In a file
    # they are simply removed (the numbers aligned above the bars remain). On screen
    # they are removed and the row is colored to stand out against the bar blocks.
    $VALROW = "__VALROW__"

    if ($OutputFile) {
        # Path: se relativo, lo risolvo rispetto a PSScriptRoot
        $resolvedPath = if ([System.IO.Path]::IsPathRooted($OutputFile)) {
            $OutputFile
        } else {
            Join-Path $PSScriptRoot $OutputFile
        }
        $cleanLines = $finalLines | ForEach-Object {
            if ($_.StartsWith($VALROW)) { $_.Substring($VALROW.Length) } else { $_ }
        }
        try {
            # #5: gestione sovrascrittura/append (Set/Add-Content) decisa dal chiamante
            # via $script:AnalyticsWriteMode ("overwrite" | "append").
            if ($script:AnalyticsWriteMode -eq "append" -and (Test-Path $resolvedPath)) {
                Add-Content -Path $resolvedPath -Value "" -Encoding UTF8 -ErrorAction Stop
                Add-Content -Path $resolvedPath -Value $cleanLines -Encoding UTF8 -ErrorAction Stop
                Write-Log (T 'analytics.appended_to' $resolvedPath) -Level WARN
            } else {
                $cleanLines | Set-Content -Path $resolvedPath -Encoding UTF8 -ErrorAction Stop
                if ($script:AnalyticsWriteMode -eq "overwrite-existing") {
                    Write-Log (T 'analytics.overwritten' $resolvedPath) -Level WARN
                } else {
                    Write-Log (T 'analytics.saved_to' $resolvedPath)
                }
            }
        }
        catch {
            Write-Log (T 'analytics.write_failed' $resolvedPath ($_.Exception.Message)) -Level ERROR
        }
    } else {
        # On-screen output with colored titles (cyan) and colored value rows (yellow).
        # The title pattern covers the numbers [1]..[10] (the added text charts
        # are [9] and [10]): \[(?:[1-9]|10)\] includes them all.
        $titleRegex = '^\s*\[(?:[1-9]|10)\]\s'
        foreach ($line in $finalLines) {
            if ($line.StartsWith($VALROW)) {
                # Values row above the bars: I remove the marker and color it yellow
                # so the numbers stand out against the bar blocks.
                Write-Host ($line.Substring($VALROW.Length)) -ForegroundColor Yellow
            }
            elseif ($line -match $titleRegex -or $line -match '\s{2,}\[(?:[1-9]|10)\]\s') {
                Write-Host $line -ForegroundColor Cyan
            } else {
                Write-Host $line
            }
        }
    }
}

function Invoke-Gallery {
    <#
    Genera gallery.html nella cartella delle immagini (defaultOutputFolder).
    Strategia "dinamica con fallback":
      - La gallery prova ad usare File System Access API (Chrome/Edge moderni) per
        leggere dinamicamente la cartella, autorizzata dall'utente con un click.
      - Se non disponibile, fallback a gallery-data.js (file esterno generato dallo
        script al momento di -Gallery, contenente la lista immagini + metadata).

    aggiunge info extra estraibili dal file (dim pixel, aspect ratio, DPI,
    trasparenza, data di creazione/modifica), theme switch, sort per data creazione.
    #>
    param([string]$ImagesFolder)

    if (-not (Test-Path $ImagesFolder)) {
        Write-Log (T 'gallery.folder_not_found' $ImagesFolder) -Level ERROR
        exit 1
    }

    # List of images (png, jpg, jpeg, webp)
    $imageFiles = Get-ChildItem -Path $ImagesFolder -File -ErrorAction SilentlyContinue |
                  Where-Object { $_.Extension -match '^\.(png|jpg|jpeg|webp)$' } |
                  Sort-Object CreationTime -Descending

    # To extract dimensions/DPI/bit/transparency I use System.Drawing on Windows.
    # On other OSes these fields remain $null (they will be handled gracefully in the JS).
    $canReadImageInfo = $script:IsWin
    if ($canReadImageInfo) {
        try { Add-Type -AssemblyName System.Drawing -ErrorAction Stop } catch { $canReadImageInfo = $false }
    }

    # I build the data list with any metadata from .json and image info
    $itemsArray = @()
    foreach ($img in $imageFiles) {
        $jsonPath = [System.IO.Path]::ChangeExtension($img.FullName, ".json")
        $hasJson = Test-Path $jsonPath
        $metadata = $null
        if ($hasJson) {
            try {
                $metadata = (Get-Content $jsonPath -Raw -Encoding UTF8 -ErrorAction Stop) | ConvertFrom-Json -ErrorAction Stop
            } catch { $metadata = $null }
        }

        # Reading the image info (Windows only)
        $imgWidth = $null; $imgHeight = $null; $imgAspect = $null
        $imgDpiX = $null; $imgDpiY = $null; $imgBitsPerPixel = $null
        $imgHasAlpha = $null; $imgPixelFormat = $null
        if ($canReadImageInfo) {
            $tmpImg = $null
            try {
                $tmpImg = [System.Drawing.Image]::FromFile($img.FullName)
                $imgWidth = $tmpImg.Width
                $imgHeight = $tmpImg.Height
                $imgAspect = if ($tmpImg.Height -gt 0) {
                    [math]::Round($tmpImg.Width / [double]$tmpImg.Height, 3)
                } else { $null }
                $imgDpiX = [math]::Round($tmpImg.HorizontalResolution)
                $imgDpiY = [math]::Round($tmpImg.VerticalResolution)
                $imgPixelFormat = $tmpImg.PixelFormat.ToString()
                # I compute bits per pixel from the PixelFormat name (e.g. Format24bppRgb -> 24)
                if ($imgPixelFormat -match '(\d+)bpp') {
                    $imgBitsPerPixel = [int]$Matches[1]
                }
                # Transparency: PixelFormat contains "Argb" or "Alpha" -> has alpha channel
                # NOTE: avere canale alpha NON significa avere pixel trasparenti effettivi,
                # ma e' un'approssimazione utile e veloce.
                $imgHasAlpha = ($imgPixelFormat -match 'Argb|Alpha')
            } catch {
                # Image not readable, I leave the fields null
            } finally {
                if ($tmpImg) { try { $tmpImg.Dispose() } catch {} }
            }
        }

        $itemsArray += [pscustomobject]@{
            file          = $img.Name
            size          = $img.Length
            modified      = $img.LastWriteTimeUtc.ToLocalTime().ToString("yyyy-MM-ddTHH:mm:ssK", [System.Globalization.CultureInfo]::InvariantCulture)
            created       = $img.CreationTimeUtc.ToLocalTime().ToString("yyyy-MM-ddTHH:mm:ssK", [System.Globalization.CultureInfo]::InvariantCulture)
            hasJson       = $hasJson
            metadata      = $metadata
            width         = $imgWidth
            height        = $imgHeight
            aspect        = $imgAspect
            dpiX          = $imgDpiX
            dpiY          = $imgDpiY
            bitsPerPixel  = $imgBitsPerPixel
            pixelFormat   = $imgPixelFormat
            hasAlpha      = $imgHasAlpha
        }
    }

    # I generate gallery-data.js (fallback for browsers that do not support the File System Access API)
    $dataJsPath = Join-Path $ImagesFolder "gallery-data.js"
    $dataJson = $itemsArray | ConvertTo-Json -Depth 10 -Compress

    # I build the i18n object with ALL the UI strings translated in the current language,
    # so the gallery JS (static here-string) can apply them to the elements.
    # The gallery_ui.* keys are resolved via T in the language chosen with -Lang.
    $i18nKeys = @(
        'title','loading','theme_dark','theme_light','refresh','authorize_folder',
        'sort_by','sort_created','sort_modified','sort_name','sort_size','order_desc','order_asc',
        'download','copy_path','copy_image','info_title','no_images','images_count',
        'field_filename','field_model','field_prompt','field_size','field_aspect','field_filesize',
        'field_created','field_modified','field_dpi','field_depth','field_transparency',
        'field_quality','field_seed','yes','no','section_metadata','section_fileinfo',
        'toast_folder_ok','toast_folder_err','toast_refreshed','toast_download',
        'toast_path_copied','toast_path_err','toast_img_copied','toast_img_err','close',
        'search_placeholder','aspect_all','aspect_landscape','aspect_portrait','aspect_square',
        'grid_size','chip_all','stat_images','stat_models','stat_cost','stat_tokens',
        'compare_open','compare_clear','compare_title','compare_select','compare_selected',
        'compare_need_two',
        'rotate_image','resize_image','convert_image','pick_file','toast_saved','prompt_resize','prompt_convert',
        'edit_image','save_edit','edit_reset','flip_h','grayscale','sepia','invert','bright_up','bright_down','contrast_up','contrast_down','sat_up','sat_down','edit_unavailable',
        'crop_image','sharpen','show_grid','keep_aspect','apply','edit_geometry','edit_color','bright','contrast','saturation','sharpness','edit_orig','edit_half','edit_custom','crop_hint',
        'edit_pick_needed',
        'exposure','shadows','vibrance','intensity','temperature','edit_temperature','show_ratings',
        'field_model_unknown','sort_rating','edit_presets','edit_effects','fx_sharpen','fx_emboss','fx_edges','fx_blur','fx_posterize','fx_solarize','fx_vignette','fx_pixelate',
        'enable_advanced','advanced_enabled','gen_prompt','gen_prompt_copied','gen_prompt_manual','edit_up2x','edit_up4x',
        'edit_artistic','fx_oilpaint','fx_watercolor','fx_pencil','fx_splittone','fx_duotone2','fx_gradientmap','fx_falsecolor','fx_thermal',
        'toast_ratings_exported','toast_ratings_export_err'
    )
    $i18nObj = [ordered]@{}
    foreach ($k in $i18nKeys) { $i18nObj[$k] = (T "gallery_ui.$k") }
    $i18nJson = $i18nObj | ConvertTo-Json -Depth 3 -Compress

    # Metadati di lingua: codice lingua (per attributo <html lang>) e direzione testo
    # (rtl for Arabic, ltr for the others), consistent with the rest of the script.
    $galleryLang = $script:CurrentLang
    $galleryDir  = if ($script:RtlLanguages -contains $script:CurrentLang) { "rtl" } else { "ltr" }

    $dataFileContent = @"
window.__GALLERY_DATA__ = $dataJson;
window.__GALLERY_I18N__ = $i18nJson;
window.__GALLERY_LANG__ = "$galleryLang";
window.__GALLERY_DIR__ = "$galleryDir";
window.__GALLERY_VERSION__ = "$($script:GalleryVersion)";
window.__GALLERY_CURRENCY__ = "$($config.defaultCurrency)";
window.__GALLERY_DIR_PATH__ = "$($ImagesFolder -replace '\\','/')";
"@
    $dataFileContent | Set-Content -Path $dataJsPath -Encoding UTF8

    # I generate gallery.html
    $galleryHtml = @'
<!DOCTYPE html>
<html lang="it">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>New-GPTImage Gallery</title>
<style>
  *{box-sizing:border-box;margin:0;padding:0}

  /* Dark theme (default) */
  :root, :root[data-theme="dark"]{
    --lightbox-bg: rgba(0,0,0,.95);
    --lb-panel-bg: rgba(15,15,18,.96);
    --lb-text: #ffffff;
    --lb-btn-bg: rgba(255,255,255,.15);
    --lb-btn-bg-hover: rgba(255,255,255,.25);
    --bg:#0e0e10; --bg-card:#1a1a1f; --bg-hover:#22222a;
    --text:#e6e6eb; --text-dim:#9a9aa6;
    --accent:#7c5cff; --accent-hover:#9579ff;
    --border:#2a2a32; --shadow:0 8px 32px rgba(0,0,0,.4);
    --info-bg:rgba(0,0,0,.7);
  }

  /* Light theme */
  :root[data-theme="light"]{
    --lightbox-bg: rgba(245,245,247,.97);
    --lb-panel-bg: rgba(255,255,255,.96);
    --lb-text: #1a1a1f;
    --lb-btn-bg: rgba(0,0,0,.08);
    --lb-btn-bg-hover: rgba(0,0,0,.16);
    --bg:#f7f7f9; --bg-card:#ffffff; --bg-hover:#f0f0f4;
    --text:#1a1a1f; --text-dim:#6a6a76;
    --accent:#5c3cff; --accent-hover:#4527e6;
    --border:#e0e0e6; --shadow:0 4px 20px rgba(0,0,0,.08);
    --info-bg:rgba(255,255,255,.85);
  }

  body{
    font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Helvetica,Arial,sans-serif;
    background:var(--bg); color:var(--text); min-height:100vh; padding:24px;
    transition:background .2s ease, color .2s ease;
  }
  header{
    display:flex; justify-content:space-between; align-items:flex-start;
    margin-bottom:24px; padding-bottom:16px; border-bottom:1px solid var(--border);
    gap:16px; flex-wrap:wrap;
  }
  header h1{ font-size:28px; font-weight:600; letter-spacing:-0.02em; }
  header .stats{ color:var(--text-dim); font-size:14px; margin-top:4px; }
  .controls{ display:flex; gap:8px; flex-wrap:wrap; align-items:center; }
  button, select{
    background:var(--bg-card); color:var(--text); border:1px solid var(--border);
    padding:8px 14px; border-radius:6px; cursor:pointer; font-size:13px;
    transition:all .15s ease; font-family:inherit;
  }
  button:hover, select:hover{ background:var(--bg-hover); border-color:var(--accent); }
  button.primary{ background:var(--accent); border-color:var(--accent); color:#fff; }
  button.primary:hover{ background:var(--accent-hover); }

  /* Theme switch */
  .theme-toggle{
    display:inline-flex; align-items:center; gap:6px;
    padding:6px 10px; border-radius:20px;
    background:var(--bg-card); border:1px solid var(--border);
  }
  .theme-toggle button{
    border:none; background:transparent; padding:4px 8px; border-radius:14px;
    font-size:12px; color:var(--text-dim);
  }
  .theme-toggle button.active{
    background:var(--accent); color:#fff;
  }

  /* Filtri/Sort bar */
  .filter-bar{
    display:flex; gap:12px; align-items:center; flex-wrap:wrap;
    margin-bottom:24px; padding:12px 16px;
    background:var(--bg-card); border:1px solid var(--border); border-radius:8px;
  }
  .filter-bar label{ font-size:13px; color:var(--text-dim); }
  .filter-bar select{ padding:6px 10px; font-size:13px; }

  .grid{
    display:grid;
    grid-template-columns:repeat(auto-fill,minmax(240px,1fr));
    gap:20px;
  }
  .card{
    background:var(--bg-card); border:1px solid var(--border);
    border-radius:10px; overflow:hidden; transition:transform .2s ease, box-shadow .2s ease;
    position:relative; cursor:pointer;
  }
  .card:hover{ transform:translateY(-4px); box-shadow:var(--shadow); }
  .card img{ width:100%; aspect-ratio:1/1; object-fit:cover; display:block; background:#000; }
  .card .meta{ padding:10px 12px; font-size:12px; color:var(--text-dim); display:flex; justify-content:space-between; }
  .card .info-btn{
    position:absolute; top:8px; right:8px;
    width:28px; height:28px; border-radius:50%;
    background:var(--info-bg); color:var(--text);
    border:none; cursor:pointer; font-size:16px; font-weight:700;
    display:flex; align-items:center; justify-content:center;
    opacity:0; transition:opacity .15s ease;
  }
  .card:hover .info-btn{ opacity:1; }
  .card .info-btn:hover{ background:var(--accent); color:#fff; }

  #pickDirBtn.enabled{ background:rgba(80,160,90,.55) !important; }
  /* Star rating */
  .star-rating{ display:inline-flex; gap:1px; }
  .star-rating .star{
    cursor:pointer; font-size:18px; line-height:1; color:rgba(255,255,255,.35);
    position:relative; width:18px; text-align:center; user-select:none;
  }
  .star-rating .star.full{ color:#ffc542; }
  .star-rating .star.half{
    color:rgba(255,255,255,.35);
    background:linear-gradient(90deg,#ffc542 50%, rgba(255,255,255,.35) 50%);
    -webkit-background-clip:text; background-clip:text; -webkit-text-fill-color:transparent;
  }
  .card .card-rating{
    position:absolute; left:8px; bottom:34px; z-index:3;
    background:rgba(0,0,0,.45); border-radius:12px; padding:2px 6px; display:none;
  }
  .card.rating-on .card-rating{ display:block; }
  .lb-rating{
    position:fixed; left:50%; transform:translateX(-50%); bottom:64px; z-index:1003;
    background:rgba(0,0,0,.6); border-radius:16px; padding:6px 14px;
  }
  .lb-rating .star{ font-size:26px; width:26px; }

  /* Lightbox */
  .lightbox{
    position:fixed; inset:0; background:var(--lightbox-bg); z-index:1000;
    display:none; align-items:center; justify-content:center; padding:24px;
  }
  .lightbox.active{ display:flex; }
  .lightbox img{ max-width:88vw; max-height:78vh; object-fit:contain; border-radius:8px; }
  /* In edit mode the image area leaves room for the side panel */
  .lightbox.editing .lb-stage{ margin-right:300px; }
  .lb-stage{ position:relative; display:flex; align-items:center; justify-content:center; max-width:88vw; max-height:78vh; }
  .lb-stage canvas{ max-width:100%; max-height:78vh; object-fit:contain; border-radius:8px; display:block; }
  .lb-stage img, .lb-stage canvas{ transition:transform .08s ease-out; transform-origin:center center; }
  .lb-stage{ overflow:hidden; }
  .lb-zoom-ind{
    position:absolute; right:12px; bottom:12px; z-index:5;
    background:rgba(0,0,0,.6); color:#fff; font-size:12px; font-variant-numeric:tabular-nums;
    padding:3px 9px; border-radius:12px; pointer-events:none;
    opacity:0; transition:opacity .25s ease;
  }
  .lightbox .close{
    position:absolute; top:20px; right:24px; background:rgba(255,255,255,.1);
    width:40px; height:40px; border-radius:50%; color:#fff; font-size:24px;
    border:none; cursor:pointer;
  }
  .lightbox .close:hover{ background:rgba(255,255,255,.2); }
  .lightbox .nav{
    position:absolute; top:50%; transform:translateY(-50%);
    background:rgba(255,255,255,.1); width:48px; height:48px;
    border-radius:50%; color:#fff; font-size:28px;
    border:none; cursor:pointer;
  }
  .lightbox .nav:hover{ background:rgba(255,255,255,.2); }
  .lightbox .nav.prev{ left:24px; }
  .lightbox .nav.next{ right:24px; }
  /* Actions bar: full strip at the bottom, does not overlap the photo */
  .lightbox .actions{
    position:fixed; left:0; right:0; bottom:0; z-index:1002;
    display:flex; gap:12px; justify-content:center; flex-wrap:wrap;
    padding:14px 16px; background:var(--lb-panel-bg);
    border-top:1px solid rgba(127,127,127,.2);
  }
  .lightbox .actions button{
    background:var(--lb-btn-bg); color:var(--lb-text); border:none;
    padding:10px 18px; border-radius:6px; cursor:pointer; font-size:13px;
  }
  .lightbox .actions button:hover{ background:var(--lb-btn-bg-hover); }
  /* Vertical editor panel on the right */
  .lb-editpanel{
    position:fixed; top:64px; right:0; width:300px; height:calc(100vh - 124px);
    overflow-y:auto; z-index:1001; padding:12px 14px 18px;
    background:var(--lb-panel-bg); border-left:1px solid rgba(127,127,127,.2);
    display:none; flex-direction:column; gap:9px; color:var(--lb-text);
  }
  .lightbox.editing .lb-stage{ margin-right:316px; }
  .lightbox.editing .lb-editpanel{ display:flex; }
  .lb-editpanel h4{ margin:0 0 1px; font-size:10px; text-transform:uppercase; letter-spacing:.06em; color:#9aa0a6; }
  .lb-group{ display:flex; flex-direction:column; gap:5px; padding-bottom:7px; border-bottom:1px solid rgba(127,127,127,.18); }
  .lb-editpanel .lb-slider label{ font-size:11px; }
  .lb-editpanel .lb-slider input[type=range]{ height:14px; }
  .lb-editpanel button{ padding:5px 8px; font-size:11px; }
  /* The presets as a compact grid of chips */
  .lb-presets{ display:grid; grid-template-columns:1fr 1fr; gap:4px; }
  .lb-presets button{ flex:none; }
  .lb-presets button.fx-active{ background:rgba(90,150,235,.75) !important; color:#fff; box-shadow:inset 0 0 0 1px rgba(255,255,255,.35); }
  .lb-group .row{ display:flex; flex-wrap:wrap; gap:6px; }
  .lb-editpanel button{
    background:var(--lb-btn-bg); color:var(--lb-text); border:none;
    padding:8px 10px; border-radius:6px; cursor:pointer; font-size:12px; flex:1 1 auto;
  }
  .lb-editpanel button:hover{ background:var(--lb-btn-bg-hover); }
  .lb-editpanel button.primary{ background:rgba(80,160,90,.55); }
  .lb-editpanel button.primary:hover{ background:rgba(80,160,90,.75); }
  .lb-slider{ display:flex; flex-direction:column; gap:3px; }
  .lb-slider label{ display:flex; justify-content:space-between; font-size:12px; color:#cfd3d7; }
  .lb-slider input[type=range]{ width:100%; }
  .lb-resize select, .lb-resize input{ width:100%; padding:6px; border-radius:5px; border:1px solid rgba(255,255,255,.2); background:#23232a; color:#fff; font-size:12px; }
  .lb-resize select option{ background:#23232a; color:#fff; }
  .lb-check{ display:flex; align-items:center; gap:6px; font-size:12px; color:#cfd3d7; }
  /* Grid and crop overlay above the canvas */
  .lb-overlay{ position:absolute; inset:0; pointer-events:none; }
  .lb-cropbox{ position:absolute; border:2px dashed #fff; box-shadow:0 0 0 9999px rgba(0,0,0,.45); cursor:move; }
  .lb-cropbox .handle{ position:absolute; width:14px; height:14px; background:#fff; border-radius:2px; }
  .lb-cropbox .handle.br{ right:-7px; bottom:-7px; cursor:se-resize; pointer-events:auto; }

  /* Info panel */
  .info-panel{
    position:fixed; right:-480px; top:0; height:100vh; width:460px;
    background:var(--bg-card); border-left:1px solid var(--border);
    transition:right .25s ease; padding:24px; z-index:1100; overflow-y:auto;
    box-shadow:var(--shadow);
  }
  .info-panel.active{ right:0; }
  .info-panel h2{ font-size:20px; margin-bottom:16px; }
  .info-panel .field{ margin-bottom:12px; }
  .info-panel .field .label{ color:var(--text-dim); font-size:11px; text-transform:uppercase; letter-spacing:.05em; margin-bottom:4px; }
  .info-panel .field .value{ font-size:14px; word-break:break-word; }
  .info-panel .section-title{
    font-size:13px; font-weight:600; color:var(--accent); margin:16px 0 8px;
    text-transform:uppercase; letter-spacing:.05em;
  }
  .info-panel .prompt-box{
    background:var(--bg); padding:12px; border-radius:6px;
    font-family:'SF Mono',Menlo,Consolas,monospace; font-size:12px;
    white-space:pre-wrap; max-height:280px; overflow-y:auto;
  }
  .info-panel .close{
    position:absolute; top:16px; right:16px; background:transparent;
    color:var(--text); font-size:20px; border:none; cursor:pointer;
    width:32px; height:32px; border-radius:50%;
  }
  .info-panel .close:hover{ background:var(--bg-hover); }

  .badge{
    display:inline-block; padding:2px 8px; border-radius:10px;
    font-size:11px; font-weight:500;
    background:var(--accent); color:#fff;
  }
  .badge.warn{ background:#d97706; }

  .empty{ text-align:center; padding:60px 20px; color:var(--text-dim); }
  .toast{
    position:fixed; bottom:24px; left:50%; transform:translateX(-50%);
    background:var(--accent); color:#fff; padding:10px 20px;
    border-radius:6px; opacity:0; transition:opacity .2s ease;
    pointer-events:none; z-index:2000;
  }
  .toast.show{ opacity:1; }

  /* === Enhancements: search, model chips, statistics, comparison === */

  /* Text search bar */
  .search-box{
    flex:1; min-width:180px; position:relative;
  }
  .search-box input{
    width:100%; background:var(--bg); color:var(--text);
    border:1px solid var(--border); border-radius:6px;
    padding:8px 32px 8px 12px; font-size:13px; font-family:inherit;
  }
  .search-box input:focus{ outline:none; border-color:var(--accent); }
  .search-box .clear-search{
    position:absolute; right:6px; top:50%; transform:translateY(-50%);
    background:transparent; border:none; color:var(--text-dim);
    cursor:pointer; font-size:16px; padding:2px 6px; display:none;
  }
  .search-box.has-text .clear-search{ display:block; }

  /* Filter chip per model */
  .model-chips{ display:flex; gap:8px; flex-wrap:wrap; align-items:center; margin-bottom:16px; }
  .chip{
    background:var(--bg-card); color:var(--text-dim);
    border:1px solid var(--border); border-radius:16px;
    padding:5px 14px; font-size:12px; cursor:pointer; transition:all .15s ease;
    display:inline-flex; align-items:center; gap:6px;
  }
  .chip:hover{ border-color:var(--accent); color:var(--text); }
  .chip.active{ background:var(--accent); border-color:var(--accent); color:#fff; }
  .chip .chip-count{ opacity:.7; font-size:11px; }

  /* Statistics panel at the top */
  .stats-panel{
    display:flex; gap:24px; flex-wrap:wrap;
    margin-bottom:20px; padding:14px 18px;
    background:var(--bg-card); border:1px solid var(--border); border-radius:8px;
  }
  .stats-panel .stat-item{ display:flex; flex-direction:column; gap:2px; }
  .stats-panel .stat-item .stat-value{ font-size:20px; font-weight:600; color:var(--text); }
  .stats-panel .stat-item .stat-label{ font-size:11px; color:var(--text-dim); text-transform:uppercase; letter-spacing:.05em; }

  /* Grid size slider */
  .grid-size{ display:inline-flex; align-items:center; gap:8px; }
  .grid-size input[type=range]{ width:90px; cursor:pointer; }

  /* Selection for comparison */
  .card .compare-check{
    position:absolute; top:8px; left:8px;
    width:24px; height:24px; border-radius:6px;
    background:var(--info-bg); border:2px solid var(--border);
    cursor:pointer; opacity:0; transition:opacity .15s ease;
    display:flex; align-items:center; justify-content:center;
    font-size:14px; color:#fff; font-weight:700;
  }
  .card:hover .compare-check, .card.selected .compare-check{ opacity:1; }
  .card.selected .compare-check{ background:var(--accent); border-color:var(--accent); }
  .card.selected{ outline:2px solid var(--accent); outline-offset:-2px; }

  /* Comparison actions bar (appears when there are selections) */
  .compare-bar{
    position:fixed; bottom:24px; left:50%; transform:translateX(-50%);
    background:var(--bg-card); border:1px solid var(--accent); border-radius:10px;
    padding:12px 20px; display:none; align-items:center; gap:16px;
    box-shadow:var(--shadow); z-index:1500;
  }
  .compare-bar.show{ display:flex; }
  .compare-bar .count{ font-size:14px; color:var(--text); }

  /* Side-by-side comparison view */
  .compare-view{
    position:fixed; inset:0; background:rgba(0,0,0,.97); z-index:1800;
    display:none; flex-direction:column; padding:24px;
  }
  .compare-view.active{ display:flex; }
  .compare-view .compare-header{
    display:flex; justify-content:space-between; align-items:center;
    margin-bottom:16px; color:#fff;
  }
  .compare-view .compare-grid{
    flex:1; display:grid; gap:16px; overflow:auto;
    grid-auto-flow:column; grid-auto-columns:minmax(280px,1fr);
  }
  .compare-view .compare-col{
    display:flex; flex-direction:column; background:var(--bg-card);
    border-radius:10px; overflow:hidden; min-height:0;
  }
  .compare-view .compare-col img{
    width:100%; flex:1; object-fit:contain; background:#000; min-height:200px;
  }
  .compare-view .compare-col .compare-meta{
    padding:12px; font-size:12px; color:var(--text); border-top:1px solid var(--border);
  }
  .compare-view .compare-col .compare-meta .m-model{ font-weight:600; color:var(--accent); margin-bottom:4px; }
  .compare-view .compare-col .compare-meta .m-row{ color:var(--text-dim); margin-bottom:2px; word-break:break-word; }
  .compare-view .close{
    position:absolute; top:20px; right:24px; background:rgba(255,255,255,.1);
    width:40px; height:40px; border-radius:50%; color:#fff; font-size:24px;
    border:none; cursor:pointer;
  }

  /* RTL: flips the positions of info-panel and card buttons */
  :root[dir="rtl"] .info-panel{ right:auto; left:-480px; border-left:none; border-right:1px solid var(--border); }
  :root[dir="rtl"] .info-panel.active{ left:0; right:auto; }
  :root[dir="rtl"] .card .info-btn{ right:auto; left:8px; }
  :root[dir="rtl"] .card .compare-check{ left:auto; right:8px; }
</style>
</head>
<body>

<header>
  <div>
    <h1>New-GPTImage - <span data-i18n="title">Galleria immagini</span></h1>
    <span id="galleryVersion" style="font-size:11px;opacity:.5;letter-spacing:.04em;"></span>
  </div>
  <div class="controls">
    <div class="theme-toggle">
      <button id="themeDark" class="active" data-i18n="theme_dark">Scuro</button>
      <button id="themeLight" data-i18n="theme_light">Chiaro</button>
    </div>
    <button id="refreshBtn" data-i18n="refresh">Aggiorna</button>
    <button class="primary" id="pickDirBtn" style="display:none" data-i18n="enable_advanced">Abilita funzionalit&agrave; avanzate</button>
  </div>
</header>

<div class="stats-panel" id="statsPanel"></div>

<div class="model-chips" id="modelChips"></div>

<div class="filter-bar">
  <div class="search-box" id="searchBox">
    <input type="text" id="searchInput" data-i18n-ph="search_placeholder" placeholder="Cerca nel prompt, modello, nome file...">
    <button class="clear-search" id="clearSearch" title="">&times;</button>
  </div>
  <label for="sortBy" data-i18n="sort_by">Ordina per:</label>
  <select id="sortBy">
    <option value="created" data-i18n="sort_created">Data di creazione</option>
    <option value="modified" data-i18n="sort_modified">Data di modifica</option>
    <option value="file" data-i18n="sort_name">Nome file</option>
    <option value="size" data-i18n="sort_size">Dimensione file</option>
    <option value="rating" data-i18n="sort_rating">Voto</option>
  </select>
  <select id="sortOrder">
    <option value="desc" data-i18n="order_desc">Decrescente</option>
    <option value="asc" data-i18n="order_asc">Crescente</option>
  </select>
  <select id="filterAspect">
    <option value="all" data-i18n="aspect_all">Tutti gli orientamenti</option>
    <option value="landscape" data-i18n="aspect_landscape">Orizzontali</option>
    <option value="portrait" data-i18n="aspect_portrait">Verticali</option>
    <option value="square" data-i18n="aspect_square">Quadrate</option>
  </select>
  <span class="grid-size">
    <label for="gridSize" data-i18n="grid_size">Dimensione:</label>
    <input type="range" id="gridSize" min="160" max="400" step="20" value="240">
  </span>
  <label class="lb-check" style="gap:6px;">
    <input type="checkbox" id="toggleRatings"> <span data-i18n="show_ratings">Mostra voti</span>
  </label>
</div>

<div class="grid" id="grid"></div>

<div class="lightbox" id="lightbox">
  <button class="close" id="lbClose">&times;</button>
  <button class="nav prev" id="lbPrev">&lt;</button>
  <button class="nav next" id="lbNext">&gt;</button>
  <div class="lb-stage" id="lbStage">
    <img id="lbImg" src="" alt="">
    <canvas id="lbCanvas" style="display:none;"></canvas>
    <div class="lb-overlay" id="lbOverlay" style="display:none;"></div>
    <div class="lb-zoom-ind" id="lbZoomInd">100%</div>
  </div>
  <div class="lb-rating" id="lbRating"></div>

  <div class="lb-editpanel" id="lbEditPanel">
    <div class="lb-group">
      <h4 data-i18n="edit_geometry">Geometria</h4>
      <div class="row">
        <button id="lbRotate" data-i18n="rotate_image">Ruota 90&deg;</button>
        <button id="lbFlipH" data-i18n="flip_h">Specchia</button>
      </div>
      <div class="row">
        <button id="lbCrop" data-i18n="crop_image">Ritaglia</button>
      </div>
      <label class="lb-check"><input type="checkbox" id="lbGrid"> <span data-i18n="show_grid">Mostra griglia</span></label>
    </div>

    <div class="lb-group lb-resize">
      <h4 data-i18n="resize_image">Ridimensiona</h4>
      <select id="lbResizePreset"></select>
      <div class="row">
        <input type="number" id="lbResizeW" min="1" placeholder="L">
        <input type="number" id="lbResizeH" min="1" placeholder="A">
      </div>
      <label class="lb-check"><input type="checkbox" id="lbKeepAr" checked> <span data-i18n="keep_aspect">Mantieni proporzioni</span></label>
      <button id="lbResizeApply" data-i18n="apply">Applica</button>
    </div>

    <div class="lb-group">
      <h4 data-i18n="edit_color">Colore</h4>
      <div class="row">
        <button id="lbGray" data-i18n="grayscale">Bianco/nero</button>
        <button id="lbSepia" data-i18n="sepia">Seppia</button>
        <button id="lbInvert" data-i18n="invert">Inverti</button>
      </div>
      <div class="lb-slider"><label><span data-i18n="bright">Luminosit&agrave;</span><span id="lbBrightVal">0</span></label><input type="range" id="lbBright" min="-100" max="100" value="0"></div>
      <div class="lb-slider"><label><span data-i18n="contrast">Contrasto</span><span id="lbContrastVal">0</span></label><input type="range" id="lbContrast" min="-100" max="100" value="0"></div>
      <div class="lb-slider"><label><span data-i18n="saturation">Saturazione</span><span id="lbSatVal">0</span></label><input type="range" id="lbSat" min="-100" max="100" value="0"></div>
      <div class="lb-slider"><label><span data-i18n="exposure">Esposizione</span><span id="lbExpoVal">0</span></label><input type="range" id="lbExpo" min="-100" max="100" value="0"></div>
      <div class="lb-slider"><label><span data-i18n="shadows">Ombre</span><span id="lbShadVal">0</span></label><input type="range" id="lbShad" min="-100" max="100" value="0"></div>
      <div class="lb-slider"><label><span data-i18n="vibrance">Brillantezza</span><span id="lbVibVal">0</span></label><input type="range" id="lbVib" min="-100" max="100" value="0"></div>
      <div class="lb-slider"><label><span data-i18n="intensity">Intensit&agrave;</span><span id="lbIntVal">0</span></label><input type="range" id="lbInt" min="-100" max="100" value="0"></div>
      <div class="lb-slider"><label><span data-i18n="sharpness">Nitidezza</span><span id="lbSharpVal">0</span></label><input type="range" id="lbSharp" min="0" max="100" value="0"></div>
    </div>

    <div class="lb-group">
      <h4 data-i18n="edit_temperature">Temperatura</h4>
      <div class="lb-slider"><label><span data-i18n="temperature">Temperatura</span><span id="lbTempVal">0</span></label><input type="range" id="lbTemp" min="-100" max="100" value="0"></div>
    </div>

    <div class="lb-group">
      <h4 data-i18n="edit_presets">Preset fotografici</h4>
      <div class="lb-presets">
        <button data-preset="fuji">Fuji X100</button>
        <button data-preset="kodak">Kodak Gold</button>
        <button data-preset="cross">Cross Process</button>
        <button data-preset="grain">Film Grain</button>
        <button data-preset="duotone">Duotone</button>
        <button data-preset="cyanotype">Cyanotype</button>
        <button data-preset="holga">Holga</button>
        <button data-preset="infrared">Infrared</button>
      </div>
    </div>

    <div class="lb-group">
      <h4 data-i18n="edit_effects">Effetti</h4>
      <div class="lb-presets">
        <button data-effect="sharpenConv" data-i18n="fx_sharpen">Nitidezza+</button>
        <button data-effect="emboss" data-i18n="fx_emboss">Rilievo</button>
        <button data-effect="edges" data-i18n="fx_edges">Contorni</button>
        <button data-effect="blur" data-i18n="fx_blur">Sfocatura</button>
        <button data-effect="posterize" data-i18n="fx_posterize">Posterizza</button>
        <button data-effect="solarize" data-i18n="fx_solarize">Solarizza</button>
        <button data-effect="vignette" data-i18n="fx_vignette">Vignetta</button>
        <button data-effect="pixelate" data-i18n="fx_pixelate">Pixel</button>
      </div>
    </div>

    <div class="lb-group">
      <h4 data-i18n="edit_artistic">Artistici</h4>
      <div class="lb-presets">
        <button data-effect="oilpaint" data-i18n="fx_oilpaint">Olio</button>
        <button data-effect="watercolor" data-i18n="fx_watercolor">Acquerello</button>
        <button data-effect="pencil" data-i18n="fx_pencil">Matita</button>
        <button data-effect="splittone" data-i18n="fx_splittone">Split tone</button>
        <button data-effect="duotone2" data-i18n="fx_duotone2">Duotone</button>
        <button data-effect="gradientmap" data-i18n="fx_gradientmap">Gradient map</button>
        <button data-effect="falsecolor" data-i18n="fx_falsecolor">Falsi colori</button>
        <button data-effect="thermal" data-i18n="fx_thermal">Termico</button>
      </div>
    </div>

    <div class="lb-group">
      <button id="lbReset" data-i18n="edit_reset">Ripristina</button>
      <button id="lbSaveEdit" class="primary" data-i18n="save_edit">Salva modifiche</button>
    </div>
  </div>

  <div class="actions">
    <button id="lbDownload" data-i18n="download">Scarica</button>
    <button id="lbCopyPath" data-i18n="copy_path">Copia path</button>
    <button id="lbCopyImg" data-i18n="copy_image">Copia immagine</button>
    <button id="lbGenPrompt" data-i18n="gen_prompt">Genera prompt</button>
    <button id="lbEdit" data-i18n="edit_image">Modifica</button>
    <button id="lbConvert" data-i18n="convert_image">Converti</button>
  </div>
</div>

<div class="info-panel" id="infoPanel">
  <button class="close" id="ipClose">&times;</button>
  <h2 data-i18n="info_title">Informazioni</h2>
  <div id="ipContent"></div>
</div>

<div class="compare-bar" id="compareBar">
  <span class="count" id="compareCount"></span>
  <button class="primary" id="compareBtn" data-i18n="compare_open">Confronta</button>
  <button id="compareClear" data-i18n="compare_clear">Annulla selezione</button>
</div>

<div class="compare-view" id="compareView">
  <button class="close" id="cvClose">&times;</button>
  <div class="compare-header">
    <h2 data-i18n="compare_title">Confronto modelli</h2>
  </div>
  <div class="compare-grid" id="compareGrid"></div>
</div>

<div class="toast" id="toast"></div>

<script src="gallery-data.js"></script>
<script>
(function(){
  'use strict';

  // -------- i18n --------
  // UI strings injected by PowerShell in the language chosen with -Lang (window.__GALLERY_I18N__).
  // If absent (e.g. old data file), the Italian texts already present in the HTML are used.
  const I18N = (window.__GALLERY_I18N__) ? window.__GALLERY_I18N__ : {};
  function t(key, fallback) {
    return (I18N && I18N[key] != null) ? I18N[key] : (fallback != null ? fallback : key);
  }
  // I apply the language and text direction to the <html> element
  if (window.__GALLERY_LANG__) { document.documentElement.setAttribute('lang', window.__GALLERY_LANG__); }
  if (window.__GALLERY_DIR__)  { document.documentElement.setAttribute('dir', window.__GALLERY_DIR__); }
  // Applico le traduzioni a tutti gli elementi marcati con data-i18n
  function applyI18n() {
    document.querySelectorAll('[data-i18n]').forEach(function(el){
      const key = el.getAttribute('data-i18n');
      if (I18N && I18N[key] != null) { el.textContent = I18N[key]; }
    });
    // Placeholder of the inputs (data-i18n-ph)
    document.querySelectorAll('[data-i18n-ph]').forEach(function(el){
      const key = el.getAttribute('data-i18n-ph');
      if (I18N && I18N[key] != null) { el.setAttribute('placeholder', I18N[key]); }
    });
  }

  // -------- State --------
  let items = [];                  // dati immagini (sorgente)
  let displayItems = [];           // items dopo filtri + sort (cio' che si vede)
  let currentIndex = -1;
  let dirHandle = null;            // FileSystemDirectoryHandle se autorizzato
  const hasFSA = ('showDirectoryPicker' in window);

  // State of the active filters
  let searchText = '';             // testo di ricerca (prompt/modello/file)
  let activeModel = '__all__';     // modello selezionato via chip ('__all__' = tutti)
  let aspectFilter = 'all';        // all|landscape|portrait|square

  // State of the selection for the comparison (set of indices in items, per file)
  const compareSet = new Set();    // contiene i nomi file selezionati
  // State of the star rating: declared here at the top (before any use) to
  // avoid the temporal dead zone, since the toggle's init runs right below.
  const RATING_KEY = 'gallery_ratings';
  let ratings = {};
  try { ratings = JSON.parse(localStorage.getItem(RATING_KEY) || '{}'); } catch (e) { ratings = {}; }
  let ratingsVisible = (localStorage.getItem('gallery_ratings_visible') === '1');

  // -------- Init --------
  applyI18n();

  // Badge versione galleria.
  (function(){
    const gv = document.getElementById('galleryVersion');
    const ver = (typeof window.__GALLERY_VERSION__ !== 'undefined') ? window.__GALLERY_VERSION__ : '';
    if (gv && ver) { gv.textContent = 'v' + ver; }
  })();

  // "Show votes" toggle: persistent state, acts on the thumbnails.
  (function(){
    const tg = document.getElementById('toggleRatings');
    if (!tg) return;
    tg.checked = ratingsVisible;
    tg.addEventListener('change', function(e){
      ratingsVisible = e.target.checked;
      try { localStorage.setItem('gallery_ratings_visible', ratingsVisible ? '1' : '0'); } catch (err) {}
      applyRatingsVisibility();
    });
  })();
  const galleryCurrency = (typeof window.__GALLERY_CURRENCY__ !== 'undefined' && window.__GALLERY_CURRENCY__) ? window.__GALLERY_CURRENCY__ : 'EUR';
  if (window.__GALLERY_DATA__) {
    items = window.__GALLERY_DATA__;
  }
  if (hasFSA) {
    document.getElementById('pickDirBtn').style.display = 'inline-block';
    updateAdvancedBtn();
  }

  // Loads preferences (theme, sort, grid size) from localStorage
  const savedTheme = localStorage.getItem('gallery_theme') || 'dark';
  const savedSortBy = localStorage.getItem('gallery_sortBy') || 'created';
  const savedSortOrder = localStorage.getItem('gallery_sortOrder') || 'desc';
  const savedGridSize = localStorage.getItem('gallery_gridSize') || '240';
  applyTheme(savedTheme);
  document.getElementById('sortBy').value = savedSortBy;
  document.getElementById('sortOrder').value = savedSortOrder;
  document.getElementById('gridSize').value = savedGridSize;
  applyGridSize(savedGridSize);

  buildModelChips();
  applyFilters();

  // -------- Eventi UI --------
  document.getElementById('refreshBtn').addEventListener('click', refresh);
  document.getElementById('pickDirBtn').addEventListener('click', pickDirectory);
  document.getElementById('themeDark').addEventListener('click', () => applyTheme('dark'));
  document.getElementById('themeLight').addEventListener('click', () => applyTheme('light'));
  document.getElementById('sortBy').addEventListener('change', () => {
    localStorage.setItem('gallery_sortBy', document.getElementById('sortBy').value);
    applyFilters();
  });
  document.getElementById('sortOrder').addEventListener('change', () => {
    localStorage.setItem('gallery_sortOrder', document.getElementById('sortOrder').value);
    applyFilters();
  });
  // Text search (with a small debounce for smoothness)
  let searchTimer = null;
  document.getElementById('searchInput').addEventListener('input', (e) => {
    const box = document.getElementById('searchBox');
    box.classList.toggle('has-text', e.target.value.length > 0);
    clearTimeout(searchTimer);
    searchTimer = setTimeout(() => {
      searchText = e.target.value.trim().toLowerCase();
      applyFilters();
    }, 150);
  });
  document.getElementById('clearSearch').addEventListener('click', () => {
    const input = document.getElementById('searchInput');
    input.value = ''; searchText = '';
    document.getElementById('searchBox').classList.remove('has-text');
    applyFilters();
  });
  document.getElementById('filterAspect').addEventListener('change', (e) => {
    aspectFilter = e.target.value;
    applyFilters();
  });
  document.getElementById('gridSize').addEventListener('input', (e) => {
    applyGridSize(e.target.value);
    localStorage.setItem('gallery_gridSize', e.target.value);
  });
