  document.getElementById('compareClear').addEventListener('click', clearCompare);
  document.getElementById('cvClose').addEventListener('click', closeCompare);
  document.getElementById('lbClose').addEventListener('click', closeLightbox);
  document.getElementById('lbPrev').addEventListener('click', () => navigate(-1));
  document.getElementById('lbNext').addEventListener('click', () => navigate(1));
  document.getElementById('lbDownload').addEventListener('click', downloadCurrent);
  document.getElementById('lbCopyPath').addEventListener('click', copyPath);
  document.getElementById('lbCopyImg').addEventListener('click', copyImageBlob);
  document.getElementById('lbEdit').addEventListener('click', enterEditMode);
  document.getElementById('lbSaveEdit').addEventListener('click', saveEdit);
  document.getElementById('lbConvert').addEventListener('click', convertCurrent);
  document.getElementById('lbGenPrompt').addEventListener('click', genPromptCurrent);
  // Zoom with the mouse wheel in the lightbox (0.25x .. 8x), proportional step.
  document.getElementById('lbStage').addEventListener('wheel', function(e){
    e.preventDefault();
    const factor = (e.deltaY < 0) ? 1.12 : (1 / 1.12);
    lbZoom = Math.min(8, Math.max(0.25, lbZoom * factor));
    if (lbZoom <= 1) { lbPanX = 0; lbPanY = 0; }
    clampPan();
    applyLbZoom();
  }, { passive: false });
  // Pan by dragging with the mouse when zoomed (lbZoom > 1).
  (function(){
    const stage = document.getElementById('lbStage');
    let dragging = false, sx = 0, sy = 0, ox = 0, oy = 0;
    stage.addEventListener('mousedown', function(e){
      if (lbZoom <= 1) return;
      // I do not interfere with the crop handles in editor mode.
      if (e.target.closest && e.target.closest('.lb-cropbox')) return;
      dragging = true; sx = e.clientX; sy = e.clientY; ox = lbPanX; oy = lbPanY;
      stage.style.cursor = 'grabbing';
      e.preventDefault();
    });
    document.addEventListener('mousemove', function(e){
      if (!dragging) return;
      lbPanX = ox + (e.clientX - sx);
      lbPanY = oy + (e.clientY - sy);
      clampPan();
      applyLbZoom();
    });
    document.addEventListener('mouseup', function(){ dragging = false; });
    // Double click: quick reset of zoom and pan.
    stage.addEventListener('dblclick', function(){ resetLbZoom(); });
  })();
  document.getElementById('lbRotate').addEventListener('click', editRotate);
  document.getElementById('lbFlipH').addEventListener('click', editFlipH);
  document.getElementById('lbGray').addEventListener('click', editGray);
  document.getElementById('lbSepia').addEventListener('click', editSepia);
  document.getElementById('lbInvert').addEventListener('click', editInvert);
  document.getElementById('lbReset').addEventListener('click', editReset);
  // I delegate the clicks of the presets/effects (buttons with data-preset / data-effect).
  document.querySelectorAll('.lb-presets button[data-preset]').forEach(function(btn){
    btn.addEventListener('click', function(){ applyPhotoPreset(btn.getAttribute('data-preset')); });
  });
  document.querySelectorAll('.lb-presets button[data-effect]').forEach(function(btn){
