  document.getElementById('lbResizeApply').addEventListener('click', editResizeApply);
  document.getElementById('lbResizePreset').addEventListener('change', onResizePreset);
  document.getElementById('lbResizeW').addEventListener('input', function(){ onResizeDimInput('w'); });
  document.getElementById('lbResizeH').addEventListener('input', function(){ onResizeDimInput('h'); });
  document.getElementById('lbGrid').addEventListener('change', function(e){ if (edit) { edit.grid = e.target.checked; drawOverlay(); } });
  // Parametric sliders: they update the shown value and redraw live.
  function bindAdjSlider(id, key, valId) {
    document.getElementById(id).addEventListener('input', function(e) {
      if (!edit) return;
      const v = parseInt(e.target.value, 10);
      document.getElementById(valId).textContent = v;
      edit.adj[key] = v;
      renderEdit();
    });
  }
  bindAdjSlider('lbBright', 'bright', 'lbBrightVal');
  bindAdjSlider('lbContrast', 'contrast', 'lbContrastVal');
  bindAdjSlider('lbSat', 'sat', 'lbSatVal');
  bindAdjSlider('lbExpo', 'expo', 'lbExpoVal');
  bindAdjSlider('lbShad', 'shad', 'lbShadVal');
  bindAdjSlider('lbVib', 'vib', 'lbVibVal');
  bindAdjSlider('lbInt', 'intens', 'lbIntVal');
  bindAdjSlider('lbTemp', 'temp', 'lbTempVal');
  bindAdjSlider('lbSharp', 'sharp', 'lbSharpVal');
  document.getElementById('ipClose').addEventListener('click', closeInfo);

  document.addEventListener('keydown', (e) => {
    if (e.key === 'Escape') {
      if (document.getElementById('compareView').classList.contains('active')) { closeCompare(); return; }
      if (document.getElementById('infoPanel').classList.contains('active')) { closeInfo(); return; }
    }
    if (!document.getElementById('lightbox').classList.contains('active')) return;
    if (e.key === 'Escape') closeLightbox();
    if (e.key === 'ArrowLeft') navigate(-1);
    if (e.key === 'ArrowRight') navigate(1);
  });

  // -------- Funzioni principali --------

  function applyTheme(theme) {
    document.documentElement.setAttribute('data-theme', theme);
    document.getElementById('themeDark').classList.toggle('active', theme === 'dark');
    document.getElementById('themeLight').classList.toggle('active', theme === 'light');
    localStorage.setItem('gallery_theme', theme);
  }

  // Helper: extracts the model name from an item (from the metadata, if present).
  // The names are CANONICALIZED case-insensitively: if the metadata contain
  // the same model with different capitalization (e.g. gpt-image-2 and GPT-Image-2, perhaps
  // produced by previous versions of the script), all the occurrences converge
  // on the first form encountered, so filters, statistics and model comparison
  // never see two distinct models due only to casing.
  // NB: the cache lives as a property of the function (modelOf._canon), NOT as an
  // external const: the IIFE's init calls buildModelChips()/applyFilters() BEFORE
  // this section of the file is executed, and a const declared here would still be
  // in the temporal dead zone -> ReferenceError that blocks the whole script.
  // Function declarations are hoisted, so this form is always safe.
  function modelOf(item) {
    const raw = (item.metadata && item.metadata.model) ? String(item.metadata.model) : '';
    if (!raw) return '';
    if (!modelOf._canon) { modelOf._canon = {}; }
    const key = raw.toLowerCase();
    if (!modelOf._canon[key]) { modelOf._canon[key] = raw; }
    return modelOf._canon[key];
  }
  // Helper: extracts the prompt from an item.
  function promptOf(item) {
    return (item.metadata && item.metadata.prompt) ? String(item.metadata.prompt) : '';
  }
  // Helper: categoria di orientamento dall'aspect ratio (o dalle dimensioni).
  function aspectCategory(item) {
    let r = item.aspect;
    if (r == null && item.width && item.height && item.height > 0) { r = item.width / item.height; }
    if (r == null) return null;
    if (r > 1.05) return 'landscape';
    if (r < 0.95) return 'portrait';
    return 'square';
  }

  // Sets the minimum width of the grid cards (size slider).
  function applyGridSize(px) {
    document.getElementById('grid').style.gridTemplateColumns =
      'repeat(auto-fill,minmax(' + px + 'px,1fr))';
  }

  // Full chain: FILTERS -> SORTING -> RENDER -> STATISTICS.
  // displayItems contiene solo gli item che passano tutti i filtri attivi.
  function applyFilters() {
    const by = document.getElementById('sortBy').value;
    const order = document.getElementById('sortOrder').value;
    const dir = (order === 'asc') ? 1 : -1;

    let filtered = items.filter(function(item){
      // Model filter (chip)
      if (activeModel !== '__all__' && modelOf(item) !== activeModel) return false;
      // Orientation filter
      if (aspectFilter !== 'all') {
        if (aspectCategory(item) !== aspectFilter) return false;
      }
      // Text search on prompt + model + file name
      if (searchText) {
        const hay = (promptOf(item) + ' ' + modelOf(item) + ' ' + (item.file || '')).toLowerCase();
        if (hay.indexOf(searchText) === -1) return false;
      }
      return true;
    });

    filtered.sort(function(a, b){
      let va, vb;
      if (by === 'rating') { va = getRating(a.file); vb = getRating(b.file); }
      else { va = a[by]; vb = b[by]; }
      if (va == null && vb == null) return 0;
      if (va == null) return 1;
      if (vb == null) return -1;
      if (typeof va === 'string' && typeof vb === 'string') return va.localeCompare(vb) * dir;
      if (va < vb) return -1 * dir;
      if (va > vb) return 1 * dir;
      return 0;
    });

    displayItems = filtered;
    renderGrid();
    renderStats();
  }

  // Builds the chips of the models present in the data (with count).
  function buildModelChips() {
    const container = document.getElementById('modelChips');
    container.innerHTML = '';
    // Count per model
    const counts = {};
    items.forEach(function(it){
      const m = modelOf(it) || t('field_model_unknown', 'Sconosciuto');
      counts[m] = (counts[m] || 0) + 1;
    });
    const models = Object.keys(counts).sort();
    // "All" chip
    container.appendChild(makeChip('__all__', t('chip_all', 'Tutti'), items.length));
    models.forEach(function(m){ container.appendChild(makeChip(m, m, counts[m])); });
    updateChipActive();
  }
  function makeChip(value, label, count) {
    const chip = document.createElement('button');
    chip.className = 'chip';
    chip.setAttribute('data-model', value);
    chip.innerHTML = escapeHtml(label) + ' <span class="chip-count">' + count + '</span>';
    chip.addEventListener('click', function(){
      activeModel = value;
      updateChipActive();
      applyFilters();
    });
    return chip;
  }
  function updateChipActive() {
    document.querySelectorAll('#modelChips .chip').forEach(function(c){
      c.classList.toggle('active', c.getAttribute('data-model') === activeModel);
    });
  }

  // Statistics panel: count of visible images, models, total estimated cost, total tokens.
  function renderStats() {
    const panel = document.getElementById('statsPanel');
    let totEur = 0, totUsd = 0, withCost = 0, totTokens = 0, withTokens = 0;
    const modelsSeen = {};
    displayItems.forEach(function(it){
      const m = modelOf(it); if (m) modelsSeen[m] = true;
      if (it.metadata && it.metadata.cost) {
        if (typeof it.metadata.cost.total_cost_eur === 'number') { totEur += it.metadata.cost.total_cost_eur; withCost++; }
        if (typeof it.metadata.cost.total_cost_usd === 'number') { totUsd += it.metadata.cost.total_cost_usd; }
        if (typeof it.metadata.cost.total_tokens === 'number') { totTokens += it.metadata.cost.total_tokens; withTokens++; }
      }
    });
    const nModels = Object.keys(modelsSeen).length;
    function stat(val, label){
      return '<div class="stat-item"><div class="stat-value">' + val + '</div><div class="stat-label">' + label + '</div></div>';
    }
    // Compact formatting of the tokens (k/M) so as not to take up too much space.
    function fmtTokens(n){
      if (n >= 1000000) return (n/1000000).toFixed(1) + 'M';
      if (n >= 1000) return (n/1000).toFixed(1) + 'k';
      return String(n);
    }
    let html = '';
    html += stat(displayItems.length, t('stat_images', 'Immagini'));
    html += stat(nModels, t('stat_models', 'Modelli'));
    if (withCost > 0) {
      // I show only the currency configured in the script (window.__GALLERY_CURRENCY__).
      if (galleryCurrency === 'USD') {
        html += stat(totUsd.toFixed(2) + ' USD', t('stat_cost', 'Costo totale'));
      } else {
        html += stat(totEur.toFixed(2) + ' EUR', t('stat_cost', 'Costo totale'));
      }
    }
    if (withTokens > 0) {
      html += stat(fmtTokens(totTokens), t('stat_tokens', 'Token totali'));
    }
    panel.innerHTML = html;
  }

  function updateAdvancedBtn() {
    const btn = document.getElementById('pickDirBtn');
    if (!btn) return;
    if (dirHandle) {
      btn.textContent = t('advanced_enabled', 'Funzionalita\' avanzate abilitate');
      btn.classList.add('enabled');
    } else {
      btn.textContent = t('enable_advanced', 'Abilita funzionalita\' avanzate');
      btn.classList.remove('enabled');
    }
  }
  async function pickDirectory() {
    try {
      // I request read+write access IMMEDIATELY: this way the browser collects the
      // write consent at the moment of authorization (where the user expects
      // it) and does NOT re-prompt at each subsequent write (each vote).
      dirHandle = await window.showDirectoryPicker({ mode: 'readwrite' });
      await loadFromDirectory();
      updateAdvancedBtn();
      showToast(t('toast_folder_ok', 'Cartella autorizzata.'));
      // I immediately export the votes aggregate (if there are any) for -Auto Quality.
      await exportRatingsAggregate();
    } catch (e) {
      if (e.name !== 'AbortError') {
        showToast(t('toast_folder_err', 'Impossibile accedere alla cartella: ') + e.message);
      }
    }
  }

  async function loadFromDirectory() {
    if (!dirHandle) return;
    const newItems = [];
    for await (const [name, handle] of dirHandle.entries()) {
      if (handle.kind !== 'file') continue;
      if (!/\.(png|jpg|jpeg|webp)$/i.test(name)) continue;
      const file = await handle.getFile();
      // Cerca eventuale .json adiacente
      const jsonName = name.replace(/\.(png|jpg|jpeg|webp)$/i, '.json');
      let metadata = null;
      let hasJson = false;
      try {
        const jsonHandle = await dirHandle.getFileHandle(jsonName);
        const jsonFile = await jsonHandle.getFile();
        metadata = JSON.parse(await jsonFile.text());
        hasJson = true;
      } catch (e) { /* no json */ }

      // Lettura dimensioni pixel tramite Image object
      const blobUrl = URL.createObjectURL(file);
      let width = null, height = null, aspect = null;
      try {
        const imgEl = await loadImage(blobUrl);
        width = imgEl.naturalWidth;
        height = imgEl.naturalHeight;
        aspect = height > 0 ? Math.round((width / height) * 1000) / 1000 : null;
      } catch (e) { /* skip */ }

      newItems.push({
        file: name,
        size: file.size,
        modified: toLocalIso(file.lastModified),
        // The FSA API does not give access to the files' creationDate: I use modified as a fallback.
        created: toLocalIso(file.lastModified),
        hasJson: hasJson,
        metadata: metadata,
        blobUrl: blobUrl,
        width: width,
        height: height,
        aspect: aspect,
        dpiX: null, dpiY: null, bitsPerPixel: null, hasAlpha: null, pixelFormat: null
      });
    }
    items = newItems;
    buildModelChips();
    applyFilters();
  }

  function loadImage(src) {
    return new Promise((resolve, reject) => {
      const img = new Image();
      img.onload = () => resolve(img);
      img.onerror = reject;
      img.src = src;
    });
  }

  async function refresh() {
    if (dirHandle) {
      await loadFromDirectory();
      showToast(t('toast_refreshed', 'Aggiornato') + ' (' + t('images_count', '{0} immagini').replace('{0}', items.length) + ')');
    } else {
      window.location.reload();
    }
  }


  // ===== Export of the votes aggregate for -Auto Quality =====
  // Computes the average of the votes per model and writes gallery_ratings.json in the folder
  // (next to the images). It requires the authorized dirHandle (File System Access API):
  // it is called right after the user grants the permissions, when writing
  // becomes possible. The script, in -Auto Quality, reads this file to weight the
  // model choice with the user's real votes. Minimum threshold on the script side: 5 votes.
  async function exportRatingsAggregate() {
    if (!dirHandle) return;            // without permission I cannot write
    try {
      // I check/obtain the WRITE permission once. If already granted
      // (because the folder was authorized in readwrite mode), it does not
      // mostrato alcun prompt; in caso contrario il browser lo chiede una volta e poi
      // remembers it for the session, avoiding a request at each vote.
      if (dirHandle.queryPermission && dirHandle.requestPermission) {
        const opts = { mode: 'readwrite' };
        let perm = await dirHandle.queryPermission(opts);
        if (perm !== 'granted') {
          perm = await dirHandle.requestPermission(opts);
        }
        if (perm !== 'granted') { return; }   // permesso negato: non scrivo, non blocco
      }
      // I aggregate: for each image with a vote > 0 and a known model, I accumulate sum and
      // count for that model.
      const agg = {};
      items.forEach(function(it) {
        const r = getRating(it.file);
        if (!r || r <= 0) return;
        const m = modelOf(it);
        if (!m) return;                // without the model metadata, the vote cannot be attributed
        if (!agg[m]) { agg[m] = { sum: 0, count: 0 }; }
        agg[m].sum += r;
        agg[m].count += 1;
      });
      // I build the final object with the rounded average.
      const models = {};
      Object.keys(agg).forEach(function(m) {
        models[m] = {
          votes: agg[m].count,
          average: Math.round((agg[m].sum / agg[m].count) * 1000) / 1000
        };
      });
      const payload = {
        generatedAt: new Date().toISOString(),
        scale: 5,
        source: 'gallery',
        models: models
      };
      // I write the file in the authorized folder (overwrites if already present).
      const fh = await dirHandle.getFileHandle('gallery_ratings.json', { create: true });
      const w = await fh.createWritable();
      await w.write(JSON.stringify(payload, null, 2));
      await w.close();
      const nModels = Object.keys(models).length;
      if (nModels > 0) {
        showToast(t('toast_ratings_exported', 'Voti esportati ({0} modelli) per Auto Quality.').replace('{0}', nModels));
      }
    } catch (e) {
      // Non bloccante: se la scrittura fallisce, la galleria continua a funzionare.
      showToast(t('toast_ratings_export_err', 'Impossibile esportare i voti: ') + e.message);
    }
  }

  // ===== Star rating (0..5, step 0.5), persistent in localStorage =====
  // Per-folder key so as not to mix the votes between different galleries: I use the file
  // name as the id (unique in the folder). The Auto Quality mode on the script side
  // will be able to read these votes from the metadata in the future; here they remain in the browser.
  function getRating(file) { return (typeof ratings[file] === 'number') ? ratings[file] : 0; }
  function setRating(file, val) {
    val = Math.max(0, Math.min(5, val));
    if (val === 0) { delete ratings[file]; } else { ratings[file] = val; }
    try { localStorage.setItem(RATING_KEY, JSON.stringify(ratings)); } catch (e) { }
    // If the folder is authorized, I keep the aggregate up to date on disk at each
    // vote, so -Auto Quality always sees the most recent data without re-authorizing.
    if (dirHandle) { exportRatingsAggregate(); }
  }
  // HTML of 5 stars: each full/half/empty based on the vote.
  function starRatingHtml(value, scope) {
    let h = '<span class="star-rating" data-scope="' + scope + '">';
    for (let i = 1; i <= 5; i++) {
      let cls = 'star';
      if (value >= i) { cls += ' full'; }
      else if (value >= i - 0.5) { cls += ' half'; }
      h += '<span class="' + cls + '" data-star="' + i + '">&#9733;</span>';
    }
    h += '</span>';
    return h;
  }
  // Click on a star: the left half is worth i-0.5, the right i. Re-clicking the
  // same value resets it (toggle), so a vote can be removed.
  function bindStarRating(container, file, onChange) {
    const sr = container.querySelector('.star-rating');
    if (!sr) return;
    sr.querySelectorAll('.star').forEach(function(st) {
      st.addEventListener('click', function(e) {
        e.stopPropagation();
        const idx = parseInt(st.getAttribute('data-star'), 10);
        const rect = st.getBoundingClientRect();
        const half = (e.clientX - rect.left) < rect.width / 2;
        let val = half ? (idx - 0.5) : idx;
        if (getRating(file) === val) { val = 0; }
        setRating(file, val);
        if (onChange) { onChange(val); }
      });
    });
  }

  function renderGrid() {
    const grid = document.getElementById('grid');
    grid.innerHTML = '';
    if (displayItems.length === 0) {
      grid.innerHTML = '<div class="empty">' + t('no_images', 'Nessuna immagine nella cartella.') + '</div>';
      return;
    }
    displayItems.forEach((item, idx) => {
      const card = document.createElement('div');
      card.className = 'card';
      if (compareSet.has(item.file)) card.classList.add('selected');
      const imgSrc = item.blobUrl || item.file;
      const dimStr = (item.width && item.height) ? (item.width + 'x' + item.height) : formatBytes(item.size);
      card.innerHTML =
        '<div class="compare-check" title="' + t('compare_select', 'Seleziona per confronto') + '">' + (compareSet.has(item.file) ? '&#10003;' : '') + '</div>' +
        '<img src="' + escapeHtml(imgSrc) + '" alt="' + escapeHtml(item.file) + '" loading="lazy">' +
        '<div class="card-rating">' + starRatingHtml(getRating(item.file), 'card') + '</div>' +
        '<div class="meta">' +
          '<span>' + escapeHtml(item.file.length > 22 ? item.file.substring(0,20)+'...' : item.file) + '</span>' +
          '<span>' + dimStr + '</span>' +
        '</div>' +
        '<button class="info-btn" title="Info">i</button>';
      card.addEventListener('click', (e) => {
        if (e.target.classList.contains('star')) {
          return; // gestito da bindStarRating
        } else if (e.target.classList.contains('compare-check')) {
          toggleCompare(item.file, card);
        } else if (e.target.classList.contains('info-btn')) {
          openInfo(idx);
        } else {
          openLightbox(idx);
        }
      });
      if (ratingsVisible) { card.classList.add('rating-on'); }
      // I hook the thumbnail's stars: on change I realign all the stars
      // (renderGridRatings re-hooks the listeners) and any open lightbox.
      const cardRating = card.querySelector('.card-rating');
      bindStarRating(cardRating, item.file, function(val) {
        renderGridRatings();
        if (lightboxOpenFor(item.file)) { renderLbRating(item.file); }
      });
      grid.appendChild(card);
    });
  }
  // Toggles the display of the stars on the thumbnails.
  function applyRatingsVisibility() {
    document.querySelectorAll('.card').forEach(function(c) {
      if (ratingsVisible) { c.classList.add('rating-on'); } else { c.classList.remove('rating-on'); }
    });
  }
  function lightboxOpenFor(file) {
    return currentIndex >= 0 && displayItems[currentIndex] && displayItems[currentIndex].file === file
           && document.getElementById('lightbox').classList.contains('active');
  }

  // -------- Model comparison (visual benchmark) --------
  function toggleCompare(file, card) {
    if (compareSet.has(file)) {
      compareSet.delete(file);
      if (card) { card.classList.remove('selected'); const c = card.querySelector('.compare-check'); if (c) c.innerHTML = ''; }
    } else {
      compareSet.add(file);
      if (card) { card.classList.add('selected'); const c = card.querySelector('.compare-check'); if (c) c.innerHTML = '&#10003;'; }
    }
    updateCompareBar();
  }
  function updateCompareBar() {
    const bar = document.getElementById('compareBar');
    const n = compareSet.size;
    bar.classList.toggle('show', n > 0);
    if (n > 0) {
      document.getElementById('compareCount').textContent =
        t('compare_selected', '{0} selezionate').replace('{0}', n);
    }
  }
  function clearCompare() {
    compareSet.clear();
    document.querySelectorAll('#grid .card.selected').forEach(function(card){
      card.classList.remove('selected');
      const c = card.querySelector('.compare-check'); if (c) c.innerHTML = '';
    });
    updateCompareBar();
  }
  function openCompare() {
    if (compareSet.size < 2) {
      showToast(t('compare_need_two', 'Seleziona almeno 2 immagini da confrontare.'));
      return;
    }
    const grid = document.getElementById('compareGrid');
    grid.innerHTML = '';
    // I keep the order in which they appear in displayItems (or items if filtered out)
    const selected = items.filter(function(it){ return compareSet.has(it.file); });
    selected.forEach(function(item){
      const col = document.createElement('div');
      col.className = 'compare-col';
      const m = item.metadata || {};
      const imgSrc = item.blobUrl || item.file;
      let meta = '<div class="m-model">' + escapeHtml(modelOf(item) || t('field_model_unknown','Sconosciuto')) + '</div>';
      if (m.prompt) meta += '<div class="m-row">' + escapeHtml(m.prompt.length > 160 ? m.prompt.substring(0,160)+'...' : m.prompt) + '</div>';
      if (item.width && item.height) meta += '<div class="m-row">' + item.width + ' x ' + item.height + ' px</div>';
      if (m.parameters && m.parameters.quality) meta += '<div class="m-row">' + t('field_quality','Qualita') + ': ' + escapeHtml(m.parameters.quality) + '</div>';
      if (m.cost && typeof m.cost.total_cost_eur === 'number') {
        const cval = (galleryCurrency === 'USD') ? ((m.cost.total_cost_usd||0).toFixed(4) + ' USD') : (m.cost.total_cost_eur.toFixed(4) + ' EUR');
        meta += '<div class="m-row">' + cval + '</div>';
      }
      col.innerHTML = '<img src="' + escapeHtml(imgSrc) + '" alt="' + escapeHtml(item.file) + '">' +
                      '<div class="compare-meta">' + meta + '</div>';
      grid.appendChild(col);
    });
    document.getElementById('compareView').classList.add('active');
  }
  function closeCompare() {
    document.getElementById('compareView').classList.remove('active');
  }

  let lbZoom = 1, lbPanX = 0, lbPanY = 0;
  function applyLbZoom() {
    const img = document.getElementById('lbImg');
    const cv = document.getElementById('lbCanvas');
    // When zoomed, the pan (translate) moves the framing; at zoom 1
    // the offset is zeroed. translate before scale = movement in screen px.
    const tr = 'translate(' + lbPanX + 'px,' + lbPanY + 'px) scale(' + lbZoom + ')';
    if (img) { img.style.transform = tr; img.style.cursor = (lbZoom > 1) ? 'grab' : ''; }
    if (cv) { cv.style.transform = tr; cv.style.cursor = (lbZoom > 1) ? 'grab' : ''; }
    // Indicator: visible only when zoom != 1, fades out by itself.
    const ind = document.getElementById('lbZoomInd');
    if (ind) {
      ind.textContent = Math.round(lbZoom * 100) + '%';
      ind.style.opacity = (Math.abs(lbZoom - 1) > 0.001) ? '1' : '0';
      clearTimeout(ind._hideTimer);
      if (Math.abs(lbZoom - 1) > 0.001) {
        ind._hideTimer = setTimeout(function(){ ind.style.opacity = '0'; }, 1400);
      }
    }
  }
  function resetLbZoom() { lbZoom = 1; lbPanX = 0; lbPanY = 0; applyLbZoom(); }
  // Keeps the offset within reasonable limits based on the zoom factor, so
  // the image cannot be dragged completely out of view.
  function clampPan() {
    const stage = document.getElementById('lbStage');
    if (!stage) return;
    const r = stage.getBoundingClientRect();
    const maxX = (r.width * (lbZoom - 1)) / 2;
    const maxY = (r.height * (lbZoom - 1)) / 2;
    lbPanX = Math.min(maxX, Math.max(-maxX, lbPanX));
    lbPanY = Math.min(maxY, Math.max(-maxY, lbPanY));
  }
  function openLightbox(idx) {
    currentIndex = idx;
    const item = displayItems[idx];
    exitEditMode();
    fillResizePresets();
    resetLbZoom();
    document.getElementById('lbImg').src = item.blobUrl || item.file;
    document.getElementById('lightbox').classList.add('active');
    renderLbRating(item.file);
  }
  // Renders the stars in the lightbox for the given file and makes them clickable.
  function renderLbRating(file) {
    const box = document.getElementById('lbRating');
    if (!box) return;
    box.innerHTML = starRatingHtml(getRating(file), 'lb');
    bindStarRating(box, file, function(val) {
      renderLbRating(file);
      // I also sync the corresponding thumbnail in the grid.
      const cards = document.querySelectorAll('.card .card-rating');
      renderGridRatings();
    });
  }
  // Realigns the stars of all the thumbnails to the current values (after a vote).
  function renderGridRatings() {
    displayItems.forEach(function(it, i) {
      const cards = document.querySelectorAll('.card');
      const card = cards[i];
      if (!card) return;
      const cr = card.querySelector('.card-rating');
      if (!cr) return;
      cr.innerHTML = starRatingHtml(getRating(it.file), 'card');
      bindStarRating(cr, it.file, function(val) {
        renderGridRatings();
        if (lightboxOpenFor(it.file)) { renderLbRating(it.file); }
      });
    });
  }

  function closeLightbox() {
    // La X scarta sempre le eventuali modifiche non salvate (richiesta esplicita).
    exitEditMode();
    document.getElementById('lightbox').classList.remove('active');
  }

  function navigate(delta) {
    if (currentIndex < 0) return;
    exitEditMode();
    currentIndex = (currentIndex + delta + displayItems.length) % displayItems.length;
    const item = displayItems[currentIndex];
    resetLbZoom();
    document.getElementById('lbImg').src = item.blobUrl || item.file;
    renderLbRating(item.file);
  }

