        if (p.quality)      html += '<div class="field"><div class="label">' + t('field_quality', 'Quality') + '</div><div class="value">' + escapeHtml(p.quality) + '</div></div>';
        if (p.format)       html += '<div class="field"><div class="label">Format</div><div class="value">' + escapeHtml(p.format) + '</div></div>';
