        html += '<div class="field"><div class="label">Costo</div><div class="value">' + cv + '</div></div>';
        html += '<div class="field"><div class="label">Token</div><div class="value">' +
                'input: ' + m.cost.input_tokens + ' / output: ' + m.cost.output_tokens + ' / total: ' + m.cost.total_tokens + '</div></div>';
      }
      if (m.prompt) {
