    $cases += @{
        id = "c58"; title = (T 'selftest.case.c58'); cost = $false
        run = {
            # Language pack integrity: every key has all 11 languages non-empty,
            # the {n} placeholders coincide with the Italian version, _total_keys is aligned.
            if (-not $script:LangFile -or -not (Test-Path $script:LangFile)) {
                return @{ Passed = $false; Detail = "file .lang non trovato" }
            }
            $d = Get-Content $script:LangFile -Raw -Encoding UTF8 | ConvertFrom-Json
            $langs = @('it','en','fr','es','pt','de','ru','zh','ja','hi','ar')
            $keys = @($d.translations.PSObject.Properties.Name)
            $missing = 0; $phBad = 0
            foreach ($k in $keys) {
                $e = $d.translations.$k
                $phIt = @([regex]::Matches([string]$e.it, '\{(\d+)\}') | ForEach-Object { $_.Groups[1].Value } | Sort-Object -Unique)
                foreach ($lg in $langs) {
                    if ($null -eq $e.$lg -or [string]$e.$lg -eq '') { $missing++; continue }
                    $ph = @([regex]::Matches([string]$e.$lg, '\{(\d+)\}') | ForEach-Object { $_.Groups[1].Value } | Sort-Object -Unique)
                    if (Compare-Object $phIt $ph) { $phBad++ }
                }
            }
            $totOk = ([int]$d._total_keys -eq $keys.Count)
            return @{ Passed = (($missing -eq 0) -and ($phBad -eq 0) -and $totOk); Detail = "chiavi=$($keys.Count) mancanti=$missing placeholder_ko=$phBad total_keys_ok=$totOk" }
        }
    }
    $cases += @{
