    $cases += @{
        id = "c60"; title = (T 'selftest.case.c60'); cost = $false
        run = {
            $bad = @()
            if ((Get-TuiDisplayWidth -Text "abc") -ne 3) { $bad += "ascii" }
            if ((Get-TuiDisplayWidth -Text "abc def 123!") -ne 12) { $bad += "ascii_misto" }
            if ((Get-TuiDisplayWidth -Text ([string]::Join('', @([char]0x4E2D, [char]0x6587)))) -ne 4) { $bad += "cjk" }
            if ((Get-TuiDisplayWidth -Text ("e" + [string][char]0x0301)) -ne 1) { $bad += "combinante" }
            if ((Get-TuiDisplayWidth -Text ([char]::ConvertFromUtf32(0x1F600))) -ne 2) { $bad += "emoji_surrogate" }
            $cjk3 = [string]::Join('', @([char]0x4E2D, [char]0x6587, [char]0x5B57))
            $cjk2 = [string]::Join('', @([char]0x4E2D, [char]0x6587))
            if ((Get-TuiTruncateToWidth -Text $cjk3 -Width 5) -ne $cjk2) { $bad += "truncate_celle" }
            if ((Get-TuiPadToWidth -Text ([string][char]0x4E2D) -Width 4).Length -ne 3) { $bad += "pad_celle" }
            $detail = if ($bad.Count -gt 0) { "KO: " + ($bad -join ',') } else { "7 asserzioni ok" }
            return @{ Passed = ($bad.Count -eq 0); Detail = $detail }
        }
    }
    $cases += @{
        id = "c61"; title = (T 'selftest.case.c61'); cost = $false
        run = {
            $bad = @()
            # Latin with spaces: no line beyond the requested width (in cells).
            $latin = ("alpha beta " * 15).Trim()
            foreach ($l in @(Split-TuiWrappedText -Text $latin -Width 20)) {
                if ((Get-TuiDisplayWidth -Text $l) -gt 20) { $bad += "latino_width"; break }
            }
            # CJK without spaces: no overflow AND no loss of characters.
            $cjk = [string]::Join('', @(1..40 | ForEach-Object { [char]0x6F22, [char]0x5B57 }))
            $segs = @(Split-TuiWrappedText -Text $cjk -Width 21)
            foreach ($l in $segs) {
                if ((Get-TuiDisplayWidth -Text $l) -gt 21) { $bad += "cjk_width"; break }
            }
            if (($segs -join '') -ne $cjk) { $bad += "cjk_perdita" }
            $detail = if ($bad.Count -gt 0) { "KO: " + ($bad -join ',') } else { "wrap latino+cjk ok, nessuna perdita" }
            return @{ Passed = ($bad.Count -eq 0); Detail = $detail }
        }
    }
