    $cases += @{
        id = "c65"; title = (T 'selftest.case.c65'); cost = $false
        run = {
            # Round-trip ToString/ParseExact with InvariantCulture: it must produce the
            # ISO Gregorian date identical on any locale (including ar-SA / non-Gregorian calendars).
            $inv = [System.Globalization.CultureInfo]::InvariantCulture
            $dt  = [datetime]::new(2026, 6, 12, 0, 0, 0)
            $str = $dt.ToString("yyyy-MM-dd", $inv)
            $back = [datetime]::ParseExact($str, "yyyy-MM-dd", $inv)
            $ok = ($str -eq "2026-06-12") -and ($back -eq $dt)
            return @{ Passed = $ok; Detail = "iso=$str roundtrip_ok=$($back -eq $dt)" }
        }
    }
    $cases += @{
        id = "c66"; title = (T 'selftest.case.c66'); cost = $false
        run = {
            # Round-trip of the request descriptor of the unified HTTP job, including the
            # PowerShell gotcha of ONE-element arrays in ConvertTo-Json (files with 1 entry).
            $reqObj = [ordered]@{
                endpoint       = "https://example.invalid/images"
                authMode       = "api-key"
                timeoutMinutes = 5
                contentType    = "multipart"
                fields         = @(
                    @{ name = "prompt"; value = "p di prova" }
                    @{ name = "model";  value = "m" }
                )
                files          = @(
                    @{ name = "image"; path = "selftest_a.png" }
                )
            }
            $req = ($reqObj | ConvertTo-Json -Depth 10) | ConvertFrom-Json
            $bad = @()
            if (@($req.fields).Count -ne 2) { $bad += "fields_count" }
            if (@($req.files).Count -ne 1)  { $bad += "files_count_singolo" }
            if (@($req.files)[0].name -ne "image") { $bad += "file_name" }
            if (([string]@($req.files)[0].mime) -ne "") { $bad += "mime_assente" }
            if ($req.contentType -ne "multipart") { $bad += "content_type" }
            $detail = if ($bad.Count -gt 0) { "KO: " + ($bad -join ',') } else { "round-trip json ok, incluso array singolo" }
            return @{ Passed = ($bad.Count -eq 0); Detail = $detail }
        }
    }
