    # --- Unit tests for the recently added features (cost=$false) ---
    $cases += @{
        id = "c72"; title = (T 'selftest.case.c72'); cost = $false
        run = {
            # Text cost calculation: Write-TextCostLog must compute the correct USD/EUR
            # from the tokens and the .conf prices, and return the operation.
            $cfg = [pscustomobject]@{
                usdToEurRate = 0.86
                textModel = [pscustomobject]@{
                    model = "selftest-text"; inputUsdPerMillion = 5.0; outputUsdPerMillion = 15.0
                }
            }
            $r = Write-TextCostLog -InputTokens 1000000 -OutputTokens 1000000 -Config $cfg -Operation "optimize" -Verbosity "ultrasilent"
            $bad = @()
            if (-not $r) { $bad += "null" }
            else {
                # 1M input * 5 + 1M output * 15 = 20 USD; * 0.86 = 17.2 EUR
                if ([math]::Abs($r.TotalUsd - 20.0) -gt 0.0001) { $bad += "usd=$($r.TotalUsd)" }
                if ([math]::Abs($r.TotalEur - 17.2) -gt 0.0001) { $bad += "eur=$($r.TotalEur)" }
                if ($r.Operation -ne "optimize") { $bad += "op=$($r.Operation)" }
            }
            # Prices absent -> returns null (no calculation)
            $cfg2 = [pscustomobject]@{ usdToEurRate = 0.86; textModel = [pscustomobject]@{ model = "x"; inputUsdPerMillion = 0; outputUsdPerMillion = 0 } }
            $r2 = Write-TextCostLog -InputTokens 100 -OutputTokens 100 -Config $cfg2 -Operation "negative" -Verbosity "ultrasilent"
            if ($null -ne $r2) { $bad += "no_pricing_non_null" }
            $detail = if ($bad.Count -gt 0) { "KO: " + ($bad -join ',') } else { "costo testuale usd/eur/op ok, no-pricing->null" }
            return @{ Passed = ($bad.Count -eq 0); Detail = $detail }
        }
    }
    $cases += @{
        id = "c73"; title = (T 'selftest.case.c73'); cost = $false
        run = {
            # Base64 obfuscation of the prompts (privacy): the round-trip must return the
            # original text, and the obfuscated one must differ from the original.
            $orig = "Prompt di test con accenti: citta', perche', piu'"
            $bytes = [System.Text.Encoding]::UTF8.GetBytes($orig)
            $enc = [System.Convert]::ToBase64String($bytes)
            $dec = [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String($enc))
            $bad = @()
            if ($enc -eq $orig) { $bad += "non_offuscato" }
            if ($dec -ne $orig) { $bad += "roundtrip_ko" }
            $detail = if ($bad.Count -gt 0) { "KO: " + ($bad -join ',') } else { "base64 round-trip ok" }
            return @{ Passed = ($bad.Count -eq 0); Detail = $detail }
        }
    }
    $cases += @{
        id = "c74"; title = (T 'selftest.case.c74'); cost = $false
        run = {
            # Parsing of the textual [COST] lines: Get-CostRecordsFromLog must extract
            # kind=textmodel and operation, even with the "Optimize:" prefix in front.
            $tmp = Join-Path $script:SelfTestTempDir ("costlog-" + [Guid]::NewGuid().ToString('N') + ".log")
            $lines = @(
                '[2026-06-19 10:00:00] [COST] Optimize: model=gpt-x kind=textmodel operation=optimize input_tokens=100 output_tokens=50 total_tokens=150 input_usd=0.0005 output_usd=0.00075 total_usd=0.00125 total_eur=0.00108 eur_rate=0.86',
                '[2026-06-19 10:01:00] [COST] model=gpt-image-2 n_images=1 input_tokens=200 output_tokens=300 total_tokens=500 input_usd=0.001 output_usd=0.009 total_usd=0.01 total_eur=0.0086 eur_rate=0.86'
            )
            Set-Content -Path $tmp -Value $lines -Encoding UTF8
            $recs = @(Get-CostRecordsFromLog -LogPath $tmp)
            $txt = @($recs | Where-Object { $_.Kind -eq 'textmodel' })
            $img = @($recs | Where-Object { $_.Kind -ne 'textmodel' })
            $bad = @()
            if ($recs.Count -ne 2) { $bad += "count=$($recs.Count)" }
            if ($txt.Count -ne 1) { $bad += "txt=$($txt.Count)" }
            if ($img.Count -ne 1) { $bad += "img=$($img.Count)" }
            if ($txt.Count -eq 1 -and $txt[0].Operation -ne "optimize") { $bad += "op=$($txt[0].Operation)" }
            Remove-Item $tmp -ErrorAction SilentlyContinue
            $detail = if ($bad.Count -gt 0) { "KO: " + ($bad -join ',') } else { "parsing textmodel/image + operation ok" }
            return @{ Passed = ($bad.Count -eq 0); Detail = $detail }
        }
    }
    $cases += @{
