            $r2 = Test-TextModelAvailable -Config ([pscustomobject]@{ textModel = [pscustomobject]@{ endpoint = ""; model = "" } }) -TimeoutSec 1
            if ($r2.Available) { $bad += "vuoto_disponibile" }
