    $cases += @{
        id = "c76"; title = (T 'selftest.case.c76'); cost = $false
        run = {
            # Prompt token estimate (~4 char/token heuristic) used in Write-PromptLog:
            # it must be consistent (ceil(len/4)) and never negative.
            $bad = @()
            foreach ($pair in @(@{t="";e=0}, @{t="abcd";e=1}, @{t="abcde";e=2}, @{t=("x"*400);e=100})) {
                $len = $pair.t.Length
                $est = [int][math]::Ceiling($len / 4.0)
                if ($len -eq 0) { $est = 0 }
                if ($est -ne $pair.e) { $bad += "len$len->$est!=$($pair.e)" }
            }
            $detail = if ($bad.Count -gt 0) { "KO: " + ($bad -join ',') } else { "stima token coerente (ceil len/4)" }
            return @{ Passed = ($bad.Count -eq 0); Detail = $detail }
        }
    }
    $cases += @{
        id = "c77"; title = (T 'selftest.case.c77'); cost = $false
        run = {
            # Get-DownscaledSize: downscaling size per le due famiglie di vincoli.
            $bad = @()
            # Family A (fixed list): 2048x2048 -> 1024x1024 (the largest square).
            $opA = [pscustomobject]@{ allowedSizes = @("1024x1024","1024x1536","1536x1024","auto"); allowedSizesEnforce = $true }
            $rA = Get-DownscaledSize -OpParams $opA -Size "2048x2048"
            if ($rA -ne "1024x1024") { $bad += "A:2048->$rA" }
            # Family A: size already valid -> null (no downscaling).
            $rA2 = Get-DownscaledSize -OpParams $opA -Size "1024x1024"
            if ($null -ne $rA2) { $bad += "A:valida->$rA2" }
            # Famiglia B (maxArea+minSide): 2048x2048 -> rientra in 1048576, lati >=768.
            $opB = [pscustomobject]@{ allowedSizes = @(); maxArea = 1048576; minSide = 768; maxSide = 0; sizeDivisibleBy = 0 }
            $rB = Get-DownscaledSize -OpParams $opB -Size "2048x2048"
            if ($rB) {
                $p = $rB -split 'x'; $bw = [int]$p[0]; $bh = [int]$p[1]
                if (($bw * $bh) -gt 1048576) { $bad += "B:area=$($bw*$bh)" }
                if ($bw -lt 768 -or $bh -lt 768) { $bad += "B:minside=$rB" }
            } else { $bad += "B:null" }
            # Famiglia B, AR estremo non realizzabile (2:1 con minSide 768) -> null.
            $rB2 = Get-DownscaledSize -OpParams $opB -Size "4096x2048"
            if ($null -ne $rB2) {
                $p = $rB2 -split 'x'; $bw = [int]$p[0]; $bh = [int]$p[1]
                if ($bw -lt 768 -or $bh -lt 768) { $bad += "B:extreme_minside=$rB2" }
            }
            # "auto" -> null (nothing to reduce).
            $rAuto = Get-DownscaledSize -OpParams $opB -Size "auto"
            if ($null -ne $rAuto) { $bad += "auto->$rAuto" }
            $detail = if ($bad.Count -gt 0) { "KO: " + ($bad -join ',') } else { "downscaling famiglie A/B + edge case ok" }
            return @{ Passed = ($bad.Count -eq 0); Detail = $detail }
        }
    }
    $cases += @{
        id = "c78"; title = (T 'selftest.case.c78'); cost = $false
        run = {
            # Budget parsing: reproduces PowerShell's real binding, which splits "1,0"
            # into @("1","0"). The function recomposes with a comma, normalizes to a point and
            # converts in a culture-invariant way. Comma and point must give the same
            # value; non-numeric values must fail.
            $bad = @()
            function _parseBudgetArr([string[]]$raw) {
                if (-not $raw -or @($raw).Count -eq 0) { return $null }
                $joined = (@($raw) -join ',').Trim()
                if ([string]::IsNullOrWhiteSpace($joined)) { return $null }
                $p = 0.0
                $norm = $joined.Replace(',', '.')
                if ([double]::TryParse($norm, [System.Globalization.NumberStyles]::Float, [System.Globalization.CultureInfo]::InvariantCulture, [ref]$p)) { return $p }
                return "ERR"
            }
            # "1,0" arriva come @("1","0") -> 1.0; "1.0" arriva come @("1.0") -> 1.0.
            if (([double](_parseBudgetArr @("1","0"))) -ne 1.0) { $bad += "virgola1,0" }
            if (([double](_parseBudgetArr @("1.0"))) -ne 1.0) { $bad += "punto1.0" }
            # "0,05" -> @("0","05") -> 0.05 ; "1,50" -> @("1","50") -> 1.5
            if (([double](_parseBudgetArr @("0","05"))) -ne 0.05) { $bad += "0,05" }
            if (([double](_parseBudgetArr @("1","50"))) -ne 1.5) { $bad += "1,50" }
            # Integer without separator: @("2") -> 2.0
            if (([double](_parseBudgetArr @("2"))) -ne 2.0) { $bad += "intero2" }
            # Empty -> null (no budget).
            if ($null -ne (_parseBudgetArr @())) { $bad += "vuoto_non_null" }
            # Non-numeric -> error.
            if ((_parseBudgetArr @("abc")) -ne "ERR") { $bad += "abc_non_err" }
            # Double comma (typo) -> @("1","5","0") -> "1.5.0" -> error.
            if ((_parseBudgetArr @("1","5","0")) -ne "ERR") { $bad += "doppia_virgola_non_err" }
            $detail = if ($bad.Count -gt 0) { "KO: " + ($bad -join ',') } else { "budget array+virgola/punto invariante ok" }
            return @{ Passed = ($bad.Count -eq 0); Detail = $detail }
        }
    }
    $cases += @{
        id = "c79"; title = (T 'selftest.case.c79'); cost = $false
        run = {
            # Preemptive downscaling: a size that is too large must be reduced to a
            # valid one (do not block); a size already valid must not be touched.
            $bad = @()
            # MAI-like: maxArea 1048576, minSide 768.
            $opMai = [pscustomobject]@{ allowedSizes = @(); allowedSizesEnforce = $false; maxArea = 1048576; minSide = 768; maxSide = 0; sizeRulesEnforce = $true; sizeDivisibleBy = 0 }
            # 2048x2048 too large -> it must reduce to a valid size (<=area, sides>=768).
            $r1 = Invoke-PreemptiveSizeDownscale -OpParams $opMai -ModelName "TestMai" -Size "2048x2048"
            if (-not $r1) { $bad += "mai_2048_no_downscale" }
            else {
                $p = $r1 -split 'x'; $w = [int]$p[0]; $h = [int]$p[1]
                if (($w * $h) -gt 1048576) { $bad += "mai_area=$($w*$h)" }
                if ($w -lt 768 -or $h -lt 768) { $bad += "mai_minside=$r1" }
            }
            # 1024x1024 already valid -> no downscaling ($null).
            $r2 = Invoke-PreemptiveSizeDownscale -OpParams $opMai -ModelName "TestMai" -Size "1024x1024"
            if ($null -ne $r2) { $bad += "mai_valida_toccata=$r2" }
            # Closed list (openai-1.5-like): 2048x2048 -> it must reduce to a value in the list.
            $opList = [pscustomobject]@{ allowedSizes = @("1024x1024","1024x1536","1536x1024","auto"); allowedSizesEnforce = $true }
            $r3 = Invoke-PreemptiveSizeDownscale -OpParams $opList -ModelName "TestList" -Size "2048x2048"
            if ($r3 -ne "1024x1024") { $bad += "lista_2048->$r3" }
            # Size already in the list -> no downscaling.
            $r4 = Invoke-PreemptiveSizeDownscale -OpParams $opList -ModelName "TestList" -Size "1024x1024"
            if ($null -ne $r4) { $bad += "lista_valida_toccata=$r4" }
            $detail = if ($bad.Count -gt 0) { "KO: " + ($bad -join ',') } else { "downscaling preventivo ok (riduce invalide, preserva valide)" }
            return @{ Passed = ($bad.Count -eq 0); Detail = $detail }
        }
    }

    # =============================================================
    # In-depth verification of the outputs (cost=$true): cross-checks on the data
    # =============================================================

    $cases += @{
        id = "c69"; title = (T 'selftest.case.c69'); cost = $true
        run = {
            # Generation with -Metadata True: the produced .json must report the CANONICAL
            # name of the default model and the exact prompt of the generation.
            $mdBefore = @()
            if (Test-Path $script:SelfTestOutputDir) {
                $mdBefore = @(Get-ChildItem $script:SelfTestOutputDir -Filter "*.json" -File -ErrorAction SilentlyContinue | Select-Object -ExpandProperty FullName)
            }
            $w = Invoke-SelfTestGenAndValidate -Arguments @("-Prompt", $script:SelfTestGenPrompt, "-Quality", "low", "-Metadata", "True", "-OutputFolder", $script:SelfTestOutputDir, "-Verbosity", "ultrasilent")
            $newMd = @()
            if (Test-Path $script:SelfTestOutputDir) {
                $newMd = @(Get-ChildItem $script:SelfTestOutputDir -Filter "*.json" -File -ErrorAction SilentlyContinue | Where-Object { $mdBefore -notcontains $_.FullName })
            }
            $detail = "exit=$($w.ExitCode) md_nuovi=$($newMd.Count)"
            $passed = $false
            if (($w.ExitCode -eq 0) -and $w.ImagesValid -and ($newMd.Count -ge 1)) {
                try {
                    $m = Get-Content $newMd[0].FullName -Raw -Encoding UTF8 | ConvertFrom-Json
                    $modelOk = (([string]$m.model).Trim() -ieq ([string]$script:SelfTestConfig.defaultModel).Trim())
                    # The prompt in the metadata can be LONGER than the one sent:
                    # if the standard file (New-GPTImage.md) exists, its content is
                    # appended to the user prompt with a double newline (see single flow).
                    # I therefore verify that the recorded prompt STARTS with the one sent,
                    # not strict equality.
                    $promptOk = $true
                    if ($null -ne $m.prompt) { $promptOk = ([string]$m.prompt).StartsWith($script:SelfTestGenPrompt) }
                    $passed = $modelOk -and $promptOk
                    $detail += " model_ok=$modelOk prompt_ok=$promptOk"
                } catch { $detail += " parse_ko=$($_.Exception.Message)" }
            }
            return @{ Passed = $passed; Detail = $detail }
        }
    }
    $cases += @{
        id = "c70"; title = (T 'selftest.case.c70'); cost = $true
        run = {
            # Generation telemetry cross-check via the per-image metadata JSON (isolated
            # artifact in the test output folder), NOT via the global .stat file.
            # Rationale: the SelfTest sub-process always runs with -NoTelemetry, which by
            # design suppresses the .stat write (Add-TimeStatRecord) so the test images do
            # not pollute the real kNN/-Auto Time history. Asserting a new .stat record
            # would therefore be self-contradictory and can never pass. The .json metadata
            # is written regardless of -NoTelemetry and carries the same authoritative
            # fields (canonical model, mode=generation). If the .stat happens to grow
            # (telemetry not suppressed), I still validate the new record opportunistically.
            $mdBefore = @()
            if (Test-Path $script:SelfTestOutputDir) {
                $mdBefore = @(Get-ChildItem $script:SelfTestOutputDir -Filter "*.json" -File -ErrorAction SilentlyContinue | Select-Object -ExpandProperty FullName)
            }
            $statBefore = 0
            if ($script:StatsFile -and (Test-Path $script:StatsFile)) { $statBefore = @(Get-Content $script:StatsFile -ErrorAction SilentlyContinue).Count }
            $w = Invoke-SelfTestGenAndValidate -Arguments @("-Prompt", $script:SelfTestGenPrompt, "-Quality", "low", "-Metadata", "True", "-OutputFolder", $script:SelfTestOutputDir, "-Verbosity", "ultrasilent")
            $detail = "exit=$($w.ExitCode)"
            $passed = $false
            $newMd = @()
            if (Test-Path $script:SelfTestOutputDir) {
                $newMd = @(Get-ChildItem $script:SelfTestOutputDir -Filter "*.json" -File -ErrorAction SilentlyContinue | Where-Object { $mdBefore -notcontains $_.FullName })
            }
            if (($w.ExitCode -eq 0) -and $w.ImagesValid -and ($newMd.Count -ge 1)) {
                try {
                    $m = Get-Content $newMd[0].FullName -Raw -Encoding UTF8 | ConvertFrom-Json -ErrorAction Stop
                    $modelOk = (([string]$m.model).Trim() -ieq ([string]$script:SelfTestConfig.defaultModel).Trim())
                    $modeOk  = (([string]$m.mode) -eq "generation")
                    $passed  = $modelOk -and $modeOk
                    $detail += " md_nuovi=$($newMd.Count) model_ok=$modelOk mode_ok=$modeOk"
                } catch { $detail += " parse_ko=$($_.Exception.Message)" }
            } else {
                $detail += " md_nuovi=$($newMd.Count)"
            }
            # Opportunistic .stat check: only if a new record was actually written
            # (i.e. telemetry was NOT suppressed). Never required for the test to pass.
            if ($passed -and $script:StatsFile -and (Test-Path $script:StatsFile)) {
                $statLines = @(Get-Content $script:StatsFile -ErrorAction SilentlyContinue)
                if ($statLines.Count -ge ($statBefore + 1)) {
                    try {
                        $rec = $statLines[-1] | ConvertFrom-Json -ErrorAction Stop
                        $statModelOk = (([string]$rec.model) -ieq ([string]$script:SelfTestConfig.defaultModel))
                        $statDurOk   = ([double]$rec.actual -gt 0)
                        $statModeOk  = (([string]$rec.mode) -eq "generation")
                        $detail += " stat_check=$($statModelOk -and $statDurOk -and $statModeOk)"
                        if (-not ($statModelOk -and $statDurOk -and $statModeOk)) { $passed = $false }
                    } catch { $detail += " stat_parse_ko" }
                } else {
                    $detail += " stat_suppressed=NoTelemetry"
                }
            }
            return @{ Passed = $passed; Detail = $detail }
        }
    }
    $cases += @{
        id = "c71"; title = (T 'selftest.case.c71'); cost = $true
        run = {
            # Analytics cross-check, DIFFERENTIAL: the two cost pipelines are independent
            # (the [COST] lines in the .log, read by -Analytics -ExportAll, vs the cumulative
            # daily total in the .cost). Comparing their ABSOLUTE today-totals is unreliable
            # inside a SelfTest: the .cost and .log are the REAL files (not isolated), so they
            # already carry today's prior generations (other test cases + any real usage), and
            # the two aggregations need not match in absolute terms. Instead I measure the
            # DELTA produced by ONE generation: the increment of the .cost daily total must
            # equal the increment of the CSV today-sum (same event, two independent sources).
            # This is robust to pre-existing pollution and is the actual invariant we care about.
            $inv = [System.Globalization.CultureInfo]::InvariantCulture
            $today = (Get-Date).ToString("yyyy-MM-dd", $inv)

            # Local helper: today's cumulative total from the .cost file (0 if absent).
            $readCostToday = {
                $v = 0.0
                if ($script:CostFile -and (Test-Path $script:CostFile)) {
                    foreach ($l in @(Get-Content $script:CostFile -Encoding UTF8 -ErrorAction SilentlyContinue)) {
                        try { $rec = $l | ConvertFrom-Json -ErrorAction Stop } catch { continue }
                        if (([string]$rec.date) -eq $today -and $null -ne $rec.total_usd) { $v = [double]$rec.total_usd }
                    }
                }
                return $v
            }
            # Local helper: today's TotalUSD sum from a fresh -ExportAll CSV (0 if none).
            $readCsvToday = {
                $csv = Join-Path $script:SelfTestTempDir ("analytics_" + [Guid]::NewGuid().ToString('N') + ".csv")
                $r = Invoke-SelfTestTarget -Arguments @("-Analytics", "-ExportAll", $csv, "-Verbosity", "ultrasilent") -TimeoutSeconds 120
                if (($r.ExitCode -ne 0) -or (-not (Test-Path $csv))) { return @{ Ok = $false; Sum = 0.0; ModelSeen = $false } }
                $rows = @(Get-Content $csv -Encoding UTF8)
                if ($rows.Count -lt 2) { return @{ Ok = $true; Sum = 0.0; ModelSeen = $false } }
                $sep = $script:CsvListSeparator
                $hh = $rows[0].Split($sep)
                $iD = [array]::IndexOf($hh, "Date"); $iM = [array]::IndexOf($hh, "Model"); $iT = [array]::IndexOf($hh, "TotalUSD")
                if ($iD -lt 0 -or $iM -lt 0 -or $iT -lt 0) { return @{ Ok = $false; Sum = 0.0; ModelSeen = $false } }
                $s = 0.0; $seen = $false
                foreach ($row in @($rows | Select-Object -Skip 1)) {
                    $cells = $row.Split($sep)
                    if ($cells.Count -le $iT) { continue }
                    if ($cells[$iD] -ne $today) { continue }
                    try { $s += [double]::Parse($cells[$iT], [System.Globalization.CultureInfo]::CurrentCulture) } catch { }
                    if ($cells[$iM].Trim('"') -ieq ([string]$script:SelfTestConfig.defaultModel)) { $seen = $true }
                }
                return @{ Ok = $true; Sum = $s; ModelSeen = $seen }
            }

            # Snapshot BEFORE the generation.
            $costBefore = & $readCostToday
            $csvBefore  = & $readCsvToday
            if (-not $csvBefore.Ok) { return @{ Passed = $false; Detail = "export ko (before)" } }

            # ONE generation.
            $w = Invoke-SelfTestGenAndValidate -Arguments @("-Prompt", $script:SelfTestGenPrompt, "-Quality", "low", "-OutputFolder", $script:SelfTestOutputDir, "-Verbosity", "ultrasilent")
            if (($w.ExitCode -ne 0) -or (-not $w.ImagesValid)) {
                return @{ Passed = $false; Detail = "generazione ko: exit=$($w.ExitCode)" }
            }

            # Snapshot AFTER the generation.
            $costAfter = & $readCostToday
            $csvAfter  = & $readCsvToday
            if (-not $csvAfter.Ok) { return @{ Passed = $false; Detail = "export ko (after)" } }

            $dCost = $costAfter - $costBefore
            $dCsv  = $csvAfter.Sum - $csvBefore.Sum
            $diff  = [math]::Abs($dCsv - $dCost)
            # The single generation must have produced a positive cost in BOTH sources, the two
            # deltas must agree within tolerance, and the default model must appear in the CSV.
            $bothPositive = ($dCost -gt 0) -and ($dCsv -gt 0)
            $passed = $bothPositive -and ($diff -le 0.02) -and $csvAfter.ModelSeen
            return @{ Passed = $passed; Detail = ("d_csv={0} d_cost={1} diff={2} default_presente={3}" -f [math]::Round($dCsv,6), [math]::Round($dCost,6), [math]::Round($diff,6), $csvAfter.ModelSeen) }
        }
    }

    # =============================================================
    # PARAMETRIC per-model tests (cost=$true, config-aware)
    # =============================================================
    # One GENERATION case for each active model different from the default (the default
    # is already covered extensively by the previous cases) and one EDIT case for each
    # active model that declares supportsEdit. No size/quality override: the
    # model's defaults are used, so the cases stay valid for any schema.
    # The model name lives in the case's 'model' field and is read at runtime from
    # $script:SelfTestCurrentCase (set by the runner before invoking 'run'),
    # avoiding the loop-variable capture problems in scriptblocks.
    $defModelForDyn = [string]$Config.defaultModel
    $dynIdx = 0
    foreach ($mn in @($script:SelfTestActiveModels | Where-Object { $_ -ine $defModelForDyn })) {
        $dynIdx++
        $cases += @{
            id = ("g{0:D2}" -f $dynIdx); title = (T 'selftest.case.model_gen' $mn); cost = $true
            model = $mn
            run = {
                $dynModel = [string]$script:SelfTestCurrentCase.model
                $w = Invoke-SelfTestGenAndValidate -Arguments @("-Prompt", $script:SelfTestGenPrompt, "-Model", $dynModel, "-OutputFolder", $script:SelfTestOutputDir, "-Verbosity", "ultrasilent")
                return @{ Passed = (($w.ExitCode -eq 0) -and $w.ImagesValid); Detail = "model=$dynModel exit=$($w.ExitCode) img_valida=$($w.ImagesValid)" }
            }
        }
    }
    $dynIdx = 0
    foreach ($mn in @($script:SelfTestActiveModels | Where-Object { $_ -ine $defModelForDyn })) {
        $mm = $Config.models.$mn
        if (-not [bool]$mm.supportsEdit) { continue }
        $dynIdx++
        $cases += @{
            id = ("e{0:D2}" -f $dynIdx); title = (T 'selftest.case.model_edit' $mn); cost = $true; needsImage = $true
            model = $mn
            run = {
                $dynModel = [string]$script:SelfTestCurrentCase.model
                $img = New-SelfTestImage -Width 512 -Height 512 -Extension "png"
                $w = Invoke-SelfTestGenAndValidate -Arguments @("-Prompt", "Add a thin yellow border to the image", "-Model", $dynModel, "-InputImages", $img, "-OutputFolder", $script:SelfTestOutputDir, "-Verbosity", "ultrasilent")
                return @{ Passed = (($w.ExitCode -eq 0) -and $w.ImagesValid); Detail = "model=$dynModel exit=$($w.ExitCode) img_valida=$($w.ImagesValid)" }
            }
        }
    }

    return $cases
}

function Get-SelfTestTotalCost {
    <#
    Somma il costo cumulativo di TUTTI i record del file costi ($script:CostFile, JSONL
    con 1 record per giorno). Serve a calcolare il costo del self-test come delta
    prima/dopo la suite, senza dipendere dai metadata delle singole immagini.
    Sommiamo TUTTI i giorni (non solo "oggi") cosi' il delta resta corretto anche se il
    run attraversa la mezzanotte: in quel caso il record del giorno cambia, ma il totale
    complessivo cresce comunque del costo effettivo del run.
    Ritorna un oggetto con TotalUsd, TotalEur, Requests.
    #>
    $res = [pscustomobject]@{ TotalUsd = 0.0; TotalEur = 0.0; Requests = 0 }
    if (-not $script:CostFile -or -not (Test-Path $script:CostFile)) { return $res }
    try {
        $lines = Get-Content $script:CostFile -Encoding UTF8 -ErrorAction Stop
        foreach ($l in $lines) {
            if (-not $l -or $l.Trim() -eq "") { continue }
            try { $rec = $l | ConvertFrom-Json -ErrorAction Stop } catch { continue }
            if ($null -ne $rec.total_usd)      { $res.TotalUsd += [double]$rec.total_usd }
            if ($null -ne $rec.total_eur)      { $res.TotalEur += [double]$rec.total_eur }
            if ($null -ne $rec.requests_count) { $res.Requests += [int]$rec.requests_count }
        }
    } catch { }
    return $res
}

function Invoke-SelfTestSuite {
    <#
    Esegue la suite di test nella modalita' indicata e ritorna l'exit code
    (0 = nessun KO, 1 = almeno un KO). Filtra i casi per costo in base alla
    modalita', li numera in sequenza, ne logga l'esito con Write-Log e pulisce
    SEMPRE la temp dir (anche su eccezione/Ctrl+C) tramite try/finally.
    #>
    param(
        [ValidateSet("simulate", "real", "all")]
        [string]$Mode,
        [pscustomobject]$Config
    )

    $script:SelfTestRunStart = Get-Date

    # Working folders: output (real images produced by the tests) and temp (synthetic
    # input files). Both in the system TEMP (see $script:SelfTestParentDir)
    # and REMOVED at the end of the run (finally), so the file system stays clean.
    $script:SelfTestOutputDir = Join-Path $script:SelfTestParentDir "New-GPTImage-selftest-output"
    $script:SelfTestTempDir   = Join-Path $script:SelfTestParentDir ($script:SelfTestTempMarker + "$PID-" + [int][double]::Parse((Get-Date -UFormat %s)))

    # Housekeeping: I remove any residues of previous interrupted runs (orphaned
    # "New-GPTImage-selftest-*" folders), BEFORE creating the new ones.
    $staleDirs = @(Get-ChildItem -LiteralPath $script:SelfTestParentDir -Directory -ErrorAction SilentlyContinue |
                   Where-Object { $_.Name.StartsWith($script:SelfTestDirPrefix) })
    foreach ($sd in $staleDirs) { Clear-SelfTestWorkDir -Path $sd.FullName }
    if ($staleDirs.Count -gt 0) { Write-Log (T 'selftest.cleanup_stale' $staleDirs.Count) }

    foreach ($d in @($script:SelfTestOutputDir, $script:SelfTestTempDir)) {
        if (-not (Test-Path $d)) {
            New-Item -ItemType Directory -Path $d -Force | Out-Null
        }
    }

    $onWindows = $script:IsWin
    # Capability to create local synthetic images: Windows (System.Drawing)
    # or any system with ImageMagick. On macOS without ImageMagick the
    # needsImage cases are skipped (sips transforms images but does not create them).
    $canMakeTestImage = $onWindows -or ((Get-ImageCliTool).Kind -in @('magick','convert'))
    $exitCode = 0

    # Snapshot of today's cumulative cost BEFORE the suite: the delta at the end of the run
    # (only in real/all mode) is the effective cost of the self-test.
    $costBefore = Get-SelfTestTotalCost

    try {
        $allCases = Get-SelfTestCases -Config $Config

        # Filter by mode: simulate=only cost=$false, real=only cost=$true.
        # outer @(...): guarantees that $selected is ALWAYS an array even with 0/1 elements.
        $selected = @(switch ($Mode) {
            "simulate" { @($allCases | Where-Object { -not $_.cost }) }
            "real"     { @($allCases | Where-Object { $_.cost }) }
            "all"      { @($allCases) }
        })

        $total = $selected.Count
        $modeLabel = switch ($Mode) {
            "simulate" { T 'selftest.mode_simulate' }
            "real"     { T 'selftest.mode_real' }
            "all"      { T 'selftest.mode_all' }
        }

        Write-Log (T 'selftest.start' $modeLabel $total)

        if ($total -eq 0) {
            Write-Log (T 'selftest.no_tests') -Level WARN
            return 0
        }

        # Connectivity probe only once, if there are real tests in scope.
        $needConnectivity = @($selected | Where-Object { $_.cost }).Count -gt 0
        $apiReachable = $true
        if ($needConnectivity) {
            $apiReachable = Test-SelfTestConnectivity -Config $Config
        }

        $okCount = 0
        $koCount = 0
        $skipCount = 0
        $index = 0

        foreach ($case in $selected) {
            $index++
            $numStr = "{0:D2}/{1:D2}" -f $index, $total
            $tStart = Get-Date

            # SKIP determination for the cases in scope but not executable here.
            $skipReason = $null
            if ($case.cost -and -not $apiReachable) {
                $skipReason = T 'selftest.skip_no_connectivity'
            }
            elseif ($case.needsImage -and -not $canMakeTestImage) {
                $skipReason = T 'selftest.skip_no_image_tool'
            }

            if ($skipReason) {
                Write-Log (T 'selftest.test_skip' $numStr $total $case.title $skipReason) -Level WARN
                $skipCount++
                continue
            }

            # Test execution.
            $passed = $false
            $detail = ""
            try {
                # Current case available to the scriptblock: the per-model parametric tests
                # read their own 'model' field from here, avoiding the
                # loop-variable capture problems in scriptblocks.
                $script:SelfTestCurrentCase = $case
                $res = & $case.run
                $passed = [bool]$res.Passed
                $detail = if ($res.Detail) { [string]$res.Detail } else { "" }
            }
            catch {
                $passed = $false
                $detail = "Eccezione runtime: $($_.Exception.Message)"
            }

            $durSec = [math]::Round(((Get-Date) - $tStart).TotalSeconds, 1)

            if ($passed) {
                Write-Log (T 'selftest.test_ok' $numStr $total $case.title $durSec)
                $okCount++
            } else {
                # On KOs the diagnostic detail also goes to the screen: the Level TIME
                # below writes only to the file, and without the detail understanding the cause of a
                # KO requires going to look for it in the log.
                Write-Log ((T 'selftest.test_ko' $numStr $total $case.title) + " | " + $detail) -Level ERROR
                $koCount++
            }
            # Diagnostic detail: file only (Level TIME never goes to the screen).
            Write-Log "  Self-test [$numStr] dettaglio: $detail (durata ${durSec}s)" -Level TIME
        }

        # Final summary.
        $runDur = (Get-Date) - $script:SelfTestRunStart
        $durStr = if ($runDur.TotalMinutes -ge 1) {
            "{0}m {1}s" -f [math]::Floor($runDur.TotalMinutes), [math]::Round($runDur.Seconds)
        } else {
            "{0}s" -f [math]::Round($runDur.TotalSeconds)
        }
        $summaryMsg = (T 'selftest.summary' $okCount $koCount $skipCount $total $durStr)

        # In real/all mode I add the overall cost of the run (delta on the cumulative
        # cost file). In simulate there is no cost, so no suffix. I show
        # the configured currency (defaultCurrency), like the rest of the script.
        if ($Mode -ne "simulate") {
            $costAfter = Get-SelfTestTotalCost
            $deltaUsd  = [math]::Max(0.0, $costAfter.TotalUsd - $costBefore.TotalUsd)
            $deltaEur  = [math]::Max(0.0, $costAfter.TotalEur - $costBefore.TotalEur)
            $localCur  = if ($Config.defaultCurrency) { [string]$Config.defaultCurrency } else { "EUR" }
            $costStr   = if ($localCur -eq "USD") {
                (Format-DisplayNumber -Value $deltaUsd -Decimals 4) + " USD"
            } else {
                (Format-DisplayNumber -Value $deltaEur -Decimals 4) + " EUR"
            }
            $summaryMsg += " " + (T 'selftest.summary_cost' $costStr)
        }
        Write-Log $summaryMsg

        $exitCode = if ($koCount -gt 0) { 1 } else { 0 }
    }
    finally {
        # I remove both working folders (temp and output): no residue left behind.
        Clear-SelfTestWorkDir -Path $script:SelfTestTempDir
        Clear-SelfTestWorkDir -Path $script:SelfTestOutputDir
        # Outcome check: if a folder still exists, I warn on screen (not just to the file).
        foreach ($wd in @($script:SelfTestTempDir, $script:SelfTestOutputDir)) {
            if ($wd -and (Test-Path -LiteralPath $wd)) {
                Write-Log (T 'selftest.cleanup_failed' $wd) -Level WARN
            }
        }
    }

    return $exitCode
}

# ============================================================================
# TUI - FULL-SCREEN INTERACTIVE INTERFACE (switch -TUI)
# ----------------------------------------------------------------------------
# Full-screen interface based on [Console]: header with a clock, scrollable
# message area, two status bars, command line with history and
# path autocompletion, full-screen prompt editor and color themes.
# All the functions are prefixed "Tui" to avoid collisions with the rest
# of the script. The configuration ("tui" section of the main .conf file)
# is normalized in memory by Set-TuiConfigDefaults: the TUI neither reads nor
# writes configuration files on its own.
# NOTE (alpha): the generation is still a MOCK (Invoke-TuiGenerateAdapter);
# the connection to the real pipeline will arrive in a subsequent increment.
# ============================================================================

# Global state of the TUI (initialized here, populated at runtime in Enter-TuiMode)
$script:TuiConfig             = $null
$script:TuiState              = $null
$script:TuiUi                 = $null
$script:TuiPalette            = $null
$script:TuiOriginalWindowTitle = $null


function Set-TuiConfigDefaults {
    # Normalizes in memory the "tui" section of the config object already loaded by the
    # main flow. If the section is missing (e.g. .conf not yet updated) it
    # creates it with the default values (theme "midnight"); if individual scalars are missing it
    # adds them. It neither reads nor writes any file: it works only on the in-memory object.
    param([Parameter(Mandatory)]$Config)

    if ($null -eq $Config.tui) {
        # I use the single source shared with the -Setup template: this way the auto-init too
        # gets ALL the themes (not just midnight) and there is no divergence between the two points.
        # I convert the [ordered] to pscustomobject via a JSON round-trip for consistency with the
        # $null -eq $Config.tui.<field> comparisons used further below.
        $tuiDefault = (Get-DefaultTuiConfig | ConvertTo-Json -Depth 12) | ConvertFrom-Json
        $Config | Add-Member -NotePropertyName tui -NotePropertyValue $tuiDefault -Force
    }

    if ($null -eq $Config.tui.scrollbackLines) {
        $Config.tui | Add-Member -NotePropertyName scrollbackLines -NotePropertyValue 5000 -Force
    }
    if ($null -eq $Config.tui.commandHistorySize) {
        $Config.tui | Add-Member -NotePropertyName commandHistorySize -NotePropertyValue 100 -Force
    }
    if ($null -eq $Config.tui.showHints) {
        $Config.tui | Add-Member -NotePropertyName showHints -NotePropertyValue $true -Force
    }
    if (-not $Config.tui.clockFormat) {
        $Config.tui | Add-Member -NotePropertyName clockFormat -NotePropertyValue 'ddd dd MMM yyyy HH:mm:ss' -Force
    }
    if (-not $Config.tui.editorConfirmKey) {
        $Config.tui | Add-Member -NotePropertyName editorConfirmKey -NotePropertyValue 'F2' -Force
    }
    if (-not $Config.tui.progressBarWidth) {
        $Config.tui | Add-Member -NotePropertyName progressBarWidth -NotePropertyValue 34 -Force
    }
    if (-not $Config.tui.theme) {
        $Config.tui | Add-Member -NotePropertyName theme -NotePropertyValue 'midnight' -Force
    }

    # Path of the main config: used only to show it in the startup banner.
    $Config | Add-Member -NotePropertyName _resolvedConfigPath -NotePropertyValue $script:ConfigFile -Force
}

# Prepares the console for the TUI: window title, UTF-8 encoding, hidden cursor, clean screen.
function Initialize-TuiConsole {
    try {
        $script:TuiOriginalWindowTitle = [Console]::Title
        [Console]::Title = "New-GPTImage TUI v$script:TuiVersion"
    } catch {}
    try { [Console]::OutputEncoding = [System.Text.UTF8Encoding]::new($false) } catch {}
    try { [Console]::CursorVisible = $false } catch {}
    try { Clear-Host } catch {}
}

# Restores the console state on exiting the TUI (visible cursor, original title).
function Restore-TuiConsole {
    try { [Console]::CursorVisible = $true } catch {}
    try {
        if ($script:TuiOriginalWindowTitle) {
            [Console]::Title = $script:TuiOriginalWindowTitle
        }
    } catch {}
}

function Open-TuiFrame {
    # Start of a "synchronized" frame: from here the terminal accumulates all the
    # writes without redrawing, until the corresponding Close-TuiFrame.
    try { [Console]::Out.Write($script:TuiSyncBegin) } catch {}
}

function Close-TuiFrame {
    # End of the frame: the terminal presents all the changes at once,
    # eliminating the flicker of row-by-row rendering.
    try { [Console]::Out.Write($script:TuiSyncEnd) } catch {}
}

# Converts the color name of a TUI theme into the corresponding [ConsoleColor], with a fallback if the name is not valid.
function Convert-TuiToConsoleColor {
    param(
        [string]$Name,
        [ConsoleColor]$Fallback = [ConsoleColor]::Gray
    )

    if ([string]::IsNullOrWhiteSpace($Name)) { return $Fallback }
    try {
        return [ConsoleColor]::Parse([ConsoleColor], $Name, $true)
    }
    catch {
        return $Fallback
    }
}

# Extracts the requested TUI theme from the config object (with a fallback to the 'midnight' theme or an error if absent).
function Get-TuiThemeObject {
    param($Config, [string]$ThemeName)

    if ($null -eq $Config.tui -or $null -eq $Config.tui.themes) {
        throw (T 'tui.error.themes_missing')
    }

    $themeProperty = $Config.tui.themes.PSObject.Properties |
        Where-Object { $_.Name -ieq $ThemeName } |
        Select-Object -First 1

    if ($null -eq $themeProperty) {
        $themeProperty = $Config.tui.themes.PSObject.Properties |
            Where-Object { $_.Name -ieq 'midnight' } |
            Select-Object -First 1
    }

    if ($null -eq $themeProperty) {
        throw (T 'tui.error.no_valid_theme')
    }

    return $themeProperty.Value
}

# Populates the TUI's color palette ($script:TuiPalette) from the selected theme.
function Set-TuiColors {
    param($State, $Config)

    $themeName = if ($State.Theme) { [string]$State.Theme } else { 'midnight' }
    $theme = Get-TuiThemeObject -Config $Config -ThemeName $themeName

    $headerLinesLabel = if ($theme.header.PSObject.Properties.Name -contains 'linesLabel') { $theme.header.linesLabel } else { 'DarkCyan' }
    $headerLinesValue = if ($theme.header.PSObject.Properties.Name -contains 'linesValue') { $theme.header.linesValue } else { 'White' }

    $script:TuiPalette = [ordered]@{
        ThemeName = $themeName

        HeaderBackground    = Convert-TuiToConsoleColor $theme.header.background ([ConsoleColor]::Black)
        HeaderClockLabel    = Convert-TuiToConsoleColor $theme.header.clockLabel ([ConsoleColor]::Cyan)
        HeaderClockValue    = Convert-TuiToConsoleColor $theme.header.clockValue ([ConsoleColor]::White)
        HeaderSessionLabel  = Convert-TuiToConsoleColor $theme.header.sessionLabel ([ConsoleColor]::DarkCyan)
        HeaderSessionValue  = Convert-TuiToConsoleColor $theme.header.sessionValue ([ConsoleColor]::White)
        HeaderLinesLabel    = Convert-TuiToConsoleColor $headerLinesLabel ([ConsoleColor]::DarkCyan)
        HeaderLinesValue    = Convert-TuiToConsoleColor $headerLinesValue ([ConsoleColor]::White)

        BodyBackground      = Convert-TuiToConsoleColor $theme.body.background ([ConsoleColor]::Black)
        BodyText            = Convert-TuiToConsoleColor $theme.body.text ([ConsoleColor]::Gray)
        BodyInfo            = Convert-TuiToConsoleColor $theme.body.info ([ConsoleColor]::Cyan)
        BodySuccess         = Convert-TuiToConsoleColor $theme.body.success ([ConsoleColor]::Green)
        BodyWarning         = Convert-TuiToConsoleColor $theme.body.warning ([ConsoleColor]::Yellow)
        BodyError           = Convert-TuiToConsoleColor $theme.body.error ([ConsoleColor]::Red)
        BodyCommandEcho     = Convert-TuiToConsoleColor $theme.body.commandEcho ([ConsoleColor]::Magenta)

        SeparatorForeground = Convert-TuiToConsoleColor $theme.separator.foreground ([ConsoleColor]::DarkGray)
        SeparatorBackground = Convert-TuiToConsoleColor $theme.separator.background ([ConsoleColor]::Black)

        Status1Background   = Convert-TuiToConsoleColor $theme.statusBar1.background ([ConsoleColor]::DarkCyan)
        Status1Label        = Convert-TuiToConsoleColor $theme.statusBar1.label ([ConsoleColor]::Black)
        Status1Value        = Convert-TuiToConsoleColor $theme.statusBar1.value ([ConsoleColor]::White)

        Status2Background   = Convert-TuiToConsoleColor $theme.statusBar2.background ([ConsoleColor]::DarkBlue)
        Status2Label        = Convert-TuiToConsoleColor $theme.statusBar2.label ([ConsoleColor]::Gray)
        Status2Value        = Convert-TuiToConsoleColor $theme.statusBar2.value ([ConsoleColor]::White)

        CommandBackground   = Convert-TuiToConsoleColor $theme.commandLine.background ([ConsoleColor]::DarkGray)
        CommandPrompt       = Convert-TuiToConsoleColor $theme.commandLine.prompt ([ConsoleColor]::White)
        CommandInput        = Convert-TuiToConsoleColor $theme.commandLine.input ([ConsoleColor]::White)
        CommandHint         = Convert-TuiToConsoleColor $theme.commandLine.hint ([ConsoleColor]::Gray)

        EditorTitleBg       = Convert-TuiToConsoleColor $theme.editor.titleBackground ([ConsoleColor]::DarkBlue)
        EditorTitleFg       = Convert-TuiToConsoleColor $theme.editor.titleForeground ([ConsoleColor]::White)
        EditorLineNumber    = Convert-TuiToConsoleColor $theme.editor.lineNumber ([ConsoleColor]::DarkGray)
        EditorText          = Convert-TuiToConsoleColor $theme.editor.text ([ConsoleColor]::Gray)
        EditorBackground    = Convert-TuiToConsoleColor $theme.editor.background ([ConsoleColor]::Black)

        ProgressBackground  = Convert-TuiToConsoleColor $theme.progress.background ([ConsoleColor]::DarkCyan)
        ProgressLabel       = Convert-TuiToConsoleColor $theme.progress.label ([ConsoleColor]::Black)
        ProgressValue       = Convert-TuiToConsoleColor $theme.progress.value ([ConsoleColor]::White)
        ProgressBar         = Convert-TuiToConsoleColor $theme.progress.bar ([ConsoleColor]::White)
    }
}

# Recomputes the dimensions and the key rows of the TUI layout based on the window's current dimensions.
function Sync-TuiDimensions {
    $width  = [Math]::Max(76, [Console]::WindowWidth)
    $height = [Math]::Max(24, [Console]::WindowHeight)

    $script:TuiUi = [ordered]@{
        Width        = $width
        Height       = $height
        HeaderRow    = 0
        HeaderSepRow = 1
        BodyTop      = 2
        FooterSepRow = $height - 4
        StatusRow1   = $height - 3
        StatusRow2   = $height - 2
        CommandRow   = $height - 1
        BodyHeight   = [Math]::Max(1, $height - 6)
        BodyWidth    = $width
    }
}

# Creates and initializes the TUI state object (current parameters, messages, history, flags).
function New-TuiState {
    param([Parameter(Mandatory)]$Config)

    $scrollback = if ($Config.tui.scrollbackLines) { [Math]::Max(100, [int]$Config.tui.scrollbackLines) } else { 5000 }
    $showHints  = if ($null -ne $Config.tui.showHints) { [bool]$Config.tui.showHints } else { $true }
    $theme      = if ($Config.tui.theme) { [string]$Config.tui.theme } else { 'midnight' }

    return [pscustomobject][ordered]@{
        Running              = $true
        PromptText           = ''
        PromptSource         = 'manual'
        PromptFilePath       = $null

        Model                = [string]$Config.defaultModel
        Auto                 = $null
        NImages              = 1
        Size                 = [string]$Config.defaultSize
        Quality              = [string]$Config.defaultQuality
        Format               = [string]$Config.defaultFormat
        Moderation           = [string]$Config.defaultModeration
        InputFidelity        = $null
        Metadata             = [bool]$Config.metadata
        Background           = [string]$Config.defaultBackground
        MaskPath             = $null
        OptimizePrompt       = $false
        NegativePrompt       = $false
        Storyboard           = $false
        SequenceImages       = 5
        InputImages          = [System.Collections.Generic.List[string]]::new()
        OutputFolder         = [string]$Config.defaultOutputFolder
        OutputMode           = 'file'
        Budget               = $null

        SessionCostUsd       = 0.0
        SessionCostLocal     = 0.0
        Currency             = [string]$Config.defaultCurrency
        Language             = [string]$Config.language

        LastGeneratedFiles   = [System.Collections.Generic.List[string]]::new()
        LastError            = $null

        BodyBuffer           = [System.Collections.Generic.List[object]]::new()
        BufferVersion        = 0
        WrapCache            = $null
        WrapCacheVersion     = -1
        WrapCacheWidth       = -1
        ScrollOffset         = 0
        ScrollbackLimit      = $scrollback

        CommandLine          = ''
        CommandCursor        = 0
        CommandHistory       = [System.Collections.Generic.List[string]]::new()
        CommandHistoryIndex  = -1
        MaxCommandHistory    = if ($Config.tui.commandHistorySize) { [int]$Config.tui.commandHistorySize } else { 100 }

        EditorActive         = $false
        EditorTitle          = ''
        EditorLines          = [System.Collections.Generic.List[string]]::new()
        EditorCursorX        = 0
        EditorCursorY        = 0
        EditorSourceMode     = 'manual'
        EditorSourcePath     = $null
        EditorViewportTop    = 0
        EditorPreferredVisualColumn = 0

        ProgressActive       = $false
        ProgressPercent      = 0
        ProgressLabel        = ''

        Theme                = $theme
        ShowHints            = $showHints
    }
}

# Ensures that the TUI state collections (messages, history) are initialized before use.
function Initialize-TuiListState {
    param([Parameter(Mandatory)]$State)

    if ($null -eq $State.BodyBuffer -or -not ($State.BodyBuffer -is [System.Collections.Generic.List[object]])) {
        $newBuffer = [System.Collections.Generic.List[object]]::new()
        foreach ($item in @($State.BodyBuffer)) { [void]$newBuffer.Add($item) }
        $State.BodyBuffer = $newBuffer
    }

    if ($null -eq $State.CommandHistory -or -not ($State.CommandHistory -is [System.Collections.Generic.List[string]])) {
        $newHistory = [System.Collections.Generic.List[string]]::new()
        foreach ($item in @($State.CommandHistory)) { [void]$newHistory.Add([string]$item) }
        $State.CommandHistory = $newHistory
    }

    if ($null -eq $State.InputImages -or -not ($State.InputImages -is [System.Collections.Generic.List[string]])) {
        $newImages = [System.Collections.Generic.List[string]]::new()
        foreach ($item in @($State.InputImages)) { [void]$newImages.Add([string]$item) }
        $State.InputImages = $newImages
    }

    if ($null -eq $State.LastGeneratedFiles -or -not ($State.LastGeneratedFiles -is [System.Collections.Generic.List[string]])) {
        $newFiles = [System.Collections.Generic.List[string]]::new()
        foreach ($item in @($State.LastGeneratedFiles)) { [void]$newFiles.Add([string]$item) }
        $State.LastGeneratedFiles = $newFiles
    }

    if ($null -eq $State.EditorLines -or -not ($State.EditorLines -is [System.Collections.Generic.List[string]])) {
        $newEditorLines = [System.Collections.Generic.List[string]]::new()
        foreach ($item in @($State.EditorLines)) { [void]$newEditorLines.Add([string]$item) }
        if ($newEditorLines.Count -eq 0) { [void]$newEditorLines.Add('') }
        $State.EditorLines = $newEditorLines
    }
}

# Returns the number of visible rows available in the body of the TUI.
function Get-TuiBodyBufferCount {
    param([Parameter(Mandatory)]$State)
    Initialize-TuiListState -State $State
    return [int]$State.BodyBuffer.Count
}

# =================================================================
# TUI: DISPLAY WIDTH (East Asian Width) - CJK / combining support
# =================================================================
# CJK characters (Chinese, Japanese, Hangul) and many emoji are "fullwidth":
# they occupy 2 cells in the terminal but String.Length counts 1. Combining marks
# (e.g. Devanagari, diacritics) occupy 0 cells. To align correctly
# the TUI's padding, truncation and wrapping we reason in CELLS and not in characters,
# iterating by code point (Rune) so as not to break the surrogate pairs.

# Width in cells of a single code point: 0 (combining/format), 2 (wide), 1 (rest).
function Get-TuiRuneWidth {
    param([int]$CodePoint)

    if ($CodePoint -le 0) { return 0 }

    # Combining, enclosing and format characters: width 0.
    $cat = [System.Globalization.CharUnicodeInfo]::GetUnicodeCategory($CodePoint)
    if ($cat -eq [System.Globalization.UnicodeCategory]::NonSpacingMark -or
        $cat -eq [System.Globalization.UnicodeCategory]::EnclosingMark -or
        $cat -eq [System.Globalization.UnicodeCategory]::Format) {
        return 0
    }

    # C0/C1 controls: width 0 (they should not appear in the rendered text).
    if ($CodePoint -lt 32 -or ($CodePoint -ge 127 -and $CodePoint -lt 160)) { return 0 }

    # East Asian Wide / Fullwidth ranges: 2 cells.
    if (
        ($CodePoint -ge 0x1100  -and $CodePoint -le 0x115F)  -or
        ($CodePoint -ge 0x2E80  -and $CodePoint -le 0x303E)  -or
        ($CodePoint -ge 0x3041  -and $CodePoint -le 0x33FF)  -or
        ($CodePoint -ge 0x3400  -and $CodePoint -le 0x4DBF)  -or
        ($CodePoint -ge 0x4E00  -and $CodePoint -le 0x9FFF)  -or
        ($CodePoint -ge 0xA000  -and $CodePoint -le 0xA4CF)  -or
        ($CodePoint -ge 0xAC00  -and $CodePoint -le 0xD7A3)  -or
        ($CodePoint -ge 0xF900  -and $CodePoint -le 0xFAFF)  -or
        ($CodePoint -ge 0xFE10  -and $CodePoint -le 0xFE19)  -or
        ($CodePoint -ge 0xFE30  -and $CodePoint -le 0xFE6F)  -or
        ($CodePoint -ge 0xFF00  -and $CodePoint -le 0xFF60)  -or
        ($CodePoint -ge 0xFFE0  -and $CodePoint -le 0xFFE6)  -or
        ($CodePoint -ge 0x1F300 -and $CodePoint -le 0x1FAFF) -or
        ($CodePoint -ge 0x20000 -and $CodePoint -le 0x3FFFD)
    ) {
        return 2
    }

    return 1
}

# Width in cells of a string, summing the code points (surrogate-safe).
function Get-TuiDisplayWidth {
    param([string]$Text)
    if ([string]::IsNullOrEmpty($Text)) { return 0 }
    # Fast-path: if there are no characters >= U+0300 (no combining, wide or
    # surrogate) the width coincides with the number of characters. It avoids the
    # per-rune cost in the most frequent case (Latin text) in the rendering hot-path.
    if ($Text -notmatch '[\u0300-\uffff]') { return $Text.Length }
    $w = 0
    foreach ($rune in $Text.EnumerateRunes()) {
        $w += (Get-TuiRuneWidth -CodePoint $rune.Value)
    }
    return $w
}

# Truncates a string to a maximum width in CELLS (without breaking a code point).
function Get-TuiTruncateToWidth {
    param([string]$Text, [int]$Width)
    if ([string]::IsNullOrEmpty($Text) -or $Width -le 0) { return '' }
    # Fast-path: text without combining/wide/surrogate -> 1 character = 1 cell.
    if ($Text -notmatch '[\u0300-\uffff]') {
        if ($Text.Length -le $Width) { return $Text }
        return $Text.Substring(0, $Width)
    }
    if ((Get-TuiDisplayWidth -Text $Text) -le $Width) { return $Text }
    $acc = 0
    $sb = [System.Text.StringBuilder]::new()
    foreach ($rune in $Text.EnumerateRunes()) {
        $cw = Get-TuiRuneWidth -CodePoint $rune.Value
        if (($acc + $cw) -gt $Width) { break }
        [void]$sb.Append($rune.ToString())
        $acc += $cw
    }
    return $sb.ToString()
}

# Pads on the right with spaces up to a width in CELLS.
function Get-TuiPadToWidth {
    param([string]$Text, [int]$Width)
    $dw = Get-TuiDisplayWidth -Text $Text
    if ($dw -ge $Width) { return $Text }
    return $Text + (' ' * ($Width - $dw))
}

# Truncates and then pads to a fixed width in CELLS (for full-width rows).
function Get-TuiFitToWidth {
    param([string]$Text, [int]$Width)
    if ($Width -le 0) { return '' }
    return Get-TuiPadToWidth -Text (Get-TuiTruncateToWidth -Text $Text -Width $Width) -Width $Width
}

# Rendering primitive: writes a TUI row at a given position, with colors and full-width padding.
function Write-TuiLine {
    param(
        [int]$Row,
        [string]$Text = '',
        [ConsoleColor]$Foreground = [ConsoleColor]::Gray,
        [ConsoleColor]$Background = [ConsoleColor]::Black
    )

    if (-not $script:TuiUi) { return }
    $width = $script:TuiUi.Width
    if ($width -lt 1) { return }

    $padded = Get-TuiFitToWidth -Text $Text -Width $width

    $oldFg = [Console]::ForegroundColor
    $oldBg = [Console]::BackgroundColor
    try {
        [Console]::ForegroundColor = $Foreground
        [Console]::BackgroundColor = $Background
        [Console]::SetCursorPosition(0, $Row)
        [Console]::Write($padded)
    }
    finally {
        [Console]::ForegroundColor = $oldFg
        [Console]::BackgroundColor = $oldBg
    }
}

# Rendering primitive: writes several side-by-side colored segments on a row (label/value).
function Write-TuiSegments {
    param(
        [int]$Row,
        [ConsoleColor]$Background,
        [array]$Segments
    )

    $oldFg = [Console]::ForegroundColor
    $oldBg = [Console]::BackgroundColor

    try {
        [Console]::BackgroundColor = $Background
        [Console]::SetCursorPosition(0, $Row)
        [Console]::Write((' ' * $script:TuiUi.Width))

        $col = 0
        foreach ($seg in @($Segments)) {
            $text = [string]$seg.Text
            if ([string]::IsNullOrEmpty($text)) { continue }
            if ($col -ge $script:TuiUi.Width) { break }

            $maxLen = $script:TuiUi.Width - $col
            $text = Get-TuiTruncateToWidth -Text $text -Width $maxLen
            if ([string]::IsNullOrEmpty($text)) { continue }

            [Console]::SetCursorPosition($col, $Row)
            [Console]::ForegroundColor = $seg.Foreground
            [Console]::BackgroundColor = $Background
            [Console]::Write($text)
            $col += Get-TuiDisplayWidth -Text $text
        }
    }
    finally {
        [Console]::ForegroundColor = $oldFg
        [Console]::BackgroundColor = $oldBg
    }
}

# Draws a horizontal separator row (e.g. between header, body and status bar).
function Show-TuiSeparator {
    param([int]$Row, [string]$Char = '─', [string]$Title = '')
    $sepW = $script:TuiUi.Width
    if ($Title -and $Title.Trim() -ne '') {
        # Separatore con titolo incassato:  --| Titolo |---------
        $label  = '┤ ' + $Title + ' ├'
        $labelW = Get-TuiDisplayWidth -Text $label
        $fill   = [Math]::Max(0, $sepW - 2 - $labelW)
        $sepText = ([string]$Char * 2) + $label + ([string]$Char * $fill)
        $sepText = Get-TuiTruncateToWidth -Text $sepText -Width $sepW
    } else {
        $sepText = [string]$Char * $sepW
    }
    Write-TuiLine -Row $Row -Text $sepText -Foreground $script:TuiPalette.SeparatorForeground -Background $script:TuiPalette.SeparatorBackground
}

# Breaks a text into several rows respecting the available width (word wrap).
function Split-TuiWrappedText {
    param([string]$Text, [int]$Width)

    $out = [System.Collections.Generic.List[string]]::new()
    if ($Width -lt 1) { [void]$out.Add(''); return $out }
    if ([string]::IsNullOrEmpty($Text)) { [void]$out.Add(''); return $out }

    $remaining = $Text -replace "`r", ''
    foreach ($logical in ($remaining -split "`n")) {
        if ((Get-TuiDisplayWidth -Text $logical) -le $Width) {
            [void]$out.Add($logical)
            continue
        }

        $rest = $logical
        # Width computed ONCE and updated incrementally by subtracting
        # the width of the consumed part (which is limited to ~$Width cells):
        # avoids recomputing the width of the entire remainder at each iteration (O(n^2)).
        $restWidth = Get-TuiDisplayWidth -Text $rest
        while ($restWidth -gt $Width) {
            $slice = Get-TuiTruncateToWidth -Text $rest -Width $Width
            if ($slice.Length -eq 0) {
                # Safeguard: usable width too small for the first character.
                [void]$out.Add($rest)
                $rest = ''
                break
            }
            $breakIndex = $slice.LastIndexOf(' ')
            if ($breakIndex -ge 10) {
                [void]$out.Add($slice.Substring(0, $breakIndex))
                $consumed = $rest.Substring(0, $breakIndex + 1)
                $rest = $rest.Substring($breakIndex + 1)
            }
            else {
                [void]$out.Add($slice)
                $consumed = $slice
                $rest = $rest.Substring($slice.Length)
            }
            $restWidth -= (Get-TuiDisplayWidth -Text $consumed)
        }
        if ($rest.Length -gt 0) { [void]$out.Add($rest) }
    }

    return $out
}

# Creates a TUI body element (message) with text and type (Info/Warning/Error/Success).
function New-TuiBodyItem {
    param(
        [Parameter(Mandatory)][string]$Text,
        [string]$Kind = 'Normal'
    )

    return [pscustomobject]@{
        Text = $Text
        Kind = $Kind
    }
}

# Adds a message to the TUI body, classified by type and with a timestamp.
function Add-TuiMessage {
    param(
        [Parameter(Mandatory)]$State,
        [Parameter(Mandatory)][string]$Text,
        [string]$Kind = 'Normal'
    )

    Initialize-TuiListState -State $State

    $stamp = (Get-Date).ToString('HH:mm:ss')
    $line = "[$stamp] $Text"
    [void]$State.BodyBuffer.Add((New-TuiBodyItem -Text $line -Kind $Kind))

    while ($State.BodyBuffer.Count -gt $State.ScrollbackLimit) {
        $State.BodyBuffer.RemoveAt(0)
    }

    # The buffer has changed: I invalidate the wrapping cache by incrementing the version.
    $State.BufferVersion = $State.BufferVersion + 1
    $State.ScrollOffset = 0
}

# Expands the body messages into wrapped rows ready for rendering, applying the scroll.
# Returns the icon (1 cell, a glyph safe on all terminals) for the body
# message type. Used by the rendering's colored gutter.
function Get-TuiKindIcon {
    param([string]$Kind)
    switch ($Kind) {
        'Success'     { return [string][char]0x2713 }
        'Error'       { return [string][char]0x2717 }
        'Warning'     { return '!' }
        'Info'        { return [string][char]0x00B7 }
        'CommandEcho' { return [string][char]0x203A }
        default       { return ' ' }
    }
}

function Get-TuiWrappedBodyLines {
    param($State)

    Initialize-TuiListState -State $State

    # -5: two cells for the gutter (vertical bar + space), one for the icon,
    # one of space and one of right margin as in the original.
    $width = [Math]::Max(10, $script:TuiUi.BodyWidth - 5)

    # Wrapping the entire buffer is costly when the buffer is large, and
    # it was redone at every frame (even during the scroll), causing a slight
    # slowdown. I cache it and recompute it only when the buffer's content
    # changes (BufferVersion) or the usable width changes: this way scroll and
    # redraw do not re-wrap uselessly.
    if ($null -ne $State.WrapCache -and
        $State.WrapCacheVersion -eq $State.BufferVersion -and
        $State.WrapCacheWidth -eq $width) {
        return $State.WrapCache
    }

    $result = [System.Collections.Generic.List[object]]::new()

    foreach ($item in @($State.BodyBuffer)) {
        $kind = if ($null -ne $item.Kind) { [string]$item.Kind } else { 'Normal' }
        $text = if ($null -ne $item.Text) { [string]$item.Text } else { [string]$item }
        $chunks = Split-TuiWrappedText -Text $text -Width $width
        # First row: gutter + type icon; continuation rows: gutter and
        # aligned indent, so the multi-row messages stay visually joined.
        $gutter = [string][char]0x258C
        $first = $true
        foreach ($c in @($chunks)) {
            $lineText = if ($first) { $gutter + ' ' + (Get-TuiKindIcon -Kind $kind) + ' ' + $c }
                        else        { $gutter + '   ' + $c }
            [void]$result.Add([pscustomobject]@{ Text = $lineText; Kind = $kind })
            $first = $false
        }
    }

    $State.WrapCache = $result
    $State.WrapCacheVersion = $State.BufferVersion
    $State.WrapCacheWidth = $width
    return $result
}

# Determines the colors (foreground/background) of a body row based on the message type.
function Get-TuiLineColors {
    param([string]$Kind)

    switch ($Kind) {
        'Success' { return @($script:TuiPalette.BodySuccess, $script:TuiPalette.BodyBackground) }
        'Warning' { return @($script:TuiPalette.BodyWarning, $script:TuiPalette.BodyBackground) }
        'Error'   { return @($script:TuiPalette.BodyError, $script:TuiPalette.BodyBackground) }
        'Command' { return @($script:TuiPalette.BodyCommandEcho, $script:TuiPalette.BodyBackground) }
        'Info'    { return @($script:TuiPalette.BodyInfo, $script:TuiPalette.BodyBackground) }
        default   { return @($script:TuiPalette.BodyText, $script:TuiPalette.BodyBackground) }
    }
}

# Derives from the config the capabilities of the selected model (edit, background, fidelity, inpainting) for the TUI header.
function Get-TuiModelCapabilities {
    param($Config, [string]$ModelName)

    $mc = $Config.models.$ModelName
    return [ordered]@{
        SupportsInpainting    = if ($null -ne $mc.supportsInpainting) { [bool]$mc.supportsInpainting } else { $false }
        SupportsInputFidelity = if ($null -ne $mc.supportsInputFidelity) { [bool]$mc.supportsInputFidelity } else { $false }
        SupportsBackground    = if ($null -ne $mc.supportsBackground) { [bool]$mc.supportsBackground } else { $false }
    }
}

# Returns the format of the clock shown in the TUI header.
function Get-TuiClockFormat {
    param($Config)
    if ($Config.tui -and $Config.tui.clockFormat) { return [string]$Config.tui.clockFormat }
    return 'ddd dd MMM yyyy HH:mm:ss'
}

# Builds the progress bar string (fill + percentage) for the TUI.
function Get-TuiProgressBarText {
    param($State, $Config)

    $barWidth = 34
    if ($Config.tui -and $Config.tui.progressBarWidth) {
        $barWidth = [Math]::Max(10, [int]$Config.tui.progressBarWidth)
    }

    $filled = [Math]::Floor(($State.ProgressPercent / 100.0) * $barWidth)
    $empty = [Math]::Max(0, $barWidth - $filled)
    # Gradient progress border: full blocks, one medium transition block,
    # then light blocks. Same total width, zero additional cost per frame.
    $bar = if ($empty -gt 0) { ('█' * $filled) + '▓' + ('░' * [Math]::Max(0, $empty - 1)) }
           else              { ('█' * $filled) }
    return "$bar {0,3}%" -f [int]$State.ProgressPercent
}

# Formats an integer for display in the TUI (separators/width).
function Format-TuiInt {
    param([int]$Value)
    return ('{0:N0}' -f $Value)
}

# Draws the TUI header: title, model and current parameters, clock.
function Show-TuiHeader {
    param($State, $Config)

    $fmt = Get-TuiClockFormat -Config $Config
    $clockValue = (Get-Date).ToString($fmt)
    $sessionValue = ('{0:N4} {1}' -f $State.SessionCostLocal, $State.Currency)

    $usedLines = Get-TuiBodyBufferCount -State $State
    $maxLines = [int]$State.ScrollbackLimit
    $linesValue = ('{0}/{1}' -f (Format-TuiInt $usedLines), (Format-TuiInt $maxLines))

    $leftLabel = (T 'tui.header.datetime')
    $centerLabel = (T 'tui.header.lines')
    $rightLabel = (T 'tui.header.cost')

    $leftText = $leftLabel + $clockValue
    $centerText = $centerLabel + $linesValue
    $rightText = $rightLabel + $sessionValue

    $leftLen = Get-TuiDisplayWidth -Text $leftText
    $centerLen = Get-TuiDisplayWidth -Text $centerText
    $rightLen = Get-TuiDisplayWidth -Text $rightText
    $width = $script:TuiUi.Width

    if (($leftLen + $centerLen + $rightLen + 4) -le $width) {
        $centerStart = [Math]::Max($leftLen + 2, [Math]::Floor(($width - $centerLen) / 2))
        $rightStart = [Math]::Max($centerStart + $centerLen + 2, $width - $rightLen)

        $oldFg = [Console]::ForegroundColor
        $oldBg = [Console]::BackgroundColor
        try {
            # Progressive writing from left to right WITHOUT clearing the row first
            # (no "Write(spaces) then rewrite"): each cell is written only
            # once, so the row never appears empty -> no flicker.
            [Console]::BackgroundColor = $script:TuiPalette.HeaderBackground
            [Console]::SetCursorPosition(0, $script:TuiUi.HeaderRow)

            # Left block: date and time
            [Console]::ForegroundColor = $script:TuiPalette.HeaderClockLabel
            [Console]::Write($leftLabel)
            [Console]::ForegroundColor = $script:TuiPalette.HeaderClockValue
            [Console]::Write($clockValue)
            $cursor = $leftLen

            # Riempimento fino al blocco centrale
            if ($centerStart -gt $cursor) {
                [Console]::Write(' ' * ($centerStart - $cursor))
                $cursor = $centerStart
            }

            # Center block: rows used
            [Console]::ForegroundColor = $script:TuiPalette.HeaderLinesLabel
            [Console]::Write($centerLabel)
            [Console]::ForegroundColor = $script:TuiPalette.HeaderLinesValue
            [Console]::Write($linesValue)
            $cursor += $centerLen

            # Riempimento fino al blocco destro
            if ($rightStart -gt $cursor) {
                [Console]::Write(' ' * ($rightStart - $cursor))
                $cursor = $rightStart
            }

            # Right block: session cost
            [Console]::ForegroundColor = $script:TuiPalette.HeaderSessionLabel
            [Console]::Write($rightLabel)
            [Console]::ForegroundColor = $script:TuiPalette.HeaderSessionValue
            [Console]::Write($sessionValue)
            $cursor += $rightLen

            # Final padding: clears any residue on the right
            if ($cursor -lt $width) {
                [Console]::Write(' ' * ($width - $cursor))
            }
        }
        finally {
            [Console]::ForegroundColor = $oldFg
            [Console]::BackgroundColor = $oldBg
        }
    }
    else {
        $fallback = "$leftLabel$clockValue |$centerLabel$linesValue |$rightLabel$sessionValue"
        Write-TuiLine -Row $script:TuiUi.HeaderRow -Text $fallback -Foreground $script:TuiPalette.HeaderClockValue -Background $script:TuiPalette.HeaderBackground
    }
}

# Draws the standard body of the TUI (wrapped and scrolled message list).
function Show-TuiBodyStandard {
    param($State)

    $wrapped = Get-TuiWrappedBodyLines -State $State
    $total   = @($wrapped).Count
    $height  = $script:TuiUi.BodyHeight

    $start = [Math]::Max(0, $total - $height - $State.ScrollOffset)
    $end   = [Math]::Min($total - 1, $start + $height - 1)

    for ($i = 0; $i -lt $height; $i++) {
        $row = $script:TuiUi.BodyTop + $i
        $index = $start + $i
        if ($index -le $end -and $index -ge 0) {
            $entry = $wrapped[$index]
            $colors = Get-TuiLineColors -Kind $entry.Kind
            Write-TuiLine -Row $row -Text $entry.Text -Foreground $colors[0] -Background $colors[1]
        }
        else {
            Write-TuiLine -Row $row -Text '' -Foreground $script:TuiPalette.BodyText -Background $script:TuiPalette.BodyBackground
        }
    }
}

# Returns the usable width for the text in the full-screen prompt editor.
function Get-TuiEditorTextWidth {
    $lineNumberWidth = 5
    return [Math]::Max(1, $script:TuiUi.Width - $lineNumberWidth)
}

# Computes the wrapped segments of a logical row of the prompt editor.
function Get-TuiWrappedSegmentsForLine {
    param(
        [string]$Text,
        [int]$Width
    )

    $segments = [System.Collections.Generic.List[object]]::new()
    if ($Width -lt 1) { $Width = 1 }

    if ($null -eq $Text) { $Text = '' }
    if ($Text.Length -eq 0) {
        [void]$segments.Add([pscustomobject]@{ Start = 0; Length = 0; Text = '' })
        return $segments
    }

    $offset = 0
    $n = $Text.Length
    while ($offset -lt $n) {
        # I accumulate code points until the width in cells exceeds $Width.
        # $take stays in CHARACTERS (UTF-16) for consistency with the cursor indices.
        $take = 0
        $cells = 0
        while (($offset + $take) -lt $n) {
            $ch = $Text[$offset + $take]
            $cpLen = 1
            $cp = [int]$ch
            if ([char]::IsHighSurrogate($ch) -and (($offset + $take + 1) -lt $n) -and [char]::IsLowSurrogate($Text[$offset + $take + 1])) {
                $cp = [char]::ConvertToUtf32($ch, $Text[$offset + $take + 1])
                $cpLen = 2
            }
            $cw = Get-TuiRuneWidth -CodePoint $cp
            if ((($cells + $cw) -gt $Width) -and ($take -gt 0)) { break }
            $cells += $cw
            $take += $cpLen
        }
        if ($take -eq 0) { $take = 1 }
        $part = $Text.Substring($offset, $take)
        [void]$segments.Add([pscustomobject]@{ Start = $offset; Length = $take; Text = $part })
        $offset += $take
    }

    return $segments
}

# Converts the editor text into visual rows (after the word wrap) for rendering.
function Get-TuiEditorVisualLines {
    param($State)

    Initialize-TuiListState -State $State
    $width = Get-TuiEditorTextWidth
    $visual = [System.Collections.Generic.List[object]]::new()

    for ($logicalIndex = 0; $logicalIndex -lt $State.EditorLines.Count; $logicalIndex++) {
        $line = [string]$State.EditorLines[$logicalIndex]
        $segments = Get-TuiWrappedSegmentsForLine -Text $line -Width $width
        for ($segmentIndex = 0; $segmentIndex -lt $segments.Count; $segmentIndex++) {
            $segment = $segments[$segmentIndex]
            [void]$visual.Add([pscustomobject]@{
                LogicalIndex = $logicalIndex
                SegmentIndex = $segmentIndex
                Start        = [int]$segment.Start
                Length       = [int]$segment.Length
                Text         = [string]$segment.Text
            })
        }
    }

    if ($visual.Count -eq 0) {
        [void]$visual.Add([pscustomobject]@{
            LogicalIndex = 0
            SegmentIndex = 0
            Start        = 0
            Length       = 0
            Text         = ''
        })
    }

    return $visual
}

# Computes the visual position (row/column) of the cursor in the prompt editor.
function Get-TuiEditorCursorVisualPosition {
    param($State)

    $width = Get-TuiEditorTextWidth
    $logicalIndex = [Math]::Max(0, [int]$State.EditorCursorY)
    $logicalLine = [string]$State.EditorLines[$logicalIndex]

    $cursorX = [Math]::Max(0, [Math]::Min([int]$State.EditorCursorX, $logicalLine.Length))
    $visualRow = 0

    # Previous logical rows: I count the real visual segments (wrap by cells).
    for ($i = 0; $i -lt $logicalIndex; $i++) {
        $prevSegs = Get-TuiWrappedSegmentsForLine -Text ([string]$State.EditorLines[$i]) -Width $width
        $visualRow += $prevSegs.Count
    }

    # Current row: I find the segment that contains the cursor and the column in CELLS.
    $segs = Get-TuiWrappedSegmentsForLine -Text $logicalLine -Width $width
    $segmentIndex = 0
    $segmentCol = 0
    for ($k = 0; $k -lt $segs.Count; $k++) {
        $s = $segs[$k]
        $segStart = [int]$s.Start
        $segLen = [int]$s.Length
        $isLast = ($k -eq ($segs.Count - 1))
        if (($cursorX -lt ($segStart + $segLen)) -or $isLast) {
            $segmentIndex = $k
            if ($cursorX -gt $segStart) {
                $within = $logicalLine.Substring($segStart, [Math]::Min($cursorX - $segStart, $segLen))
                $segmentCol = Get-TuiDisplayWidth -Text $within
            }
            break
        }
    }

    $visualRow += $segmentIndex

    return [pscustomobject]@{
        VisualRow = [int]$visualRow
        VisualCol = [int]$segmentCol
    }
}

# Stores the preferred visual column of the cursor for the vertical movements in the editor.
function Set-TuiEditorPreferredVisualColumn {
    param($State)
    $pos = Get-TuiEditorCursorVisualPosition -State $State
    $State.EditorPreferredVisualColumn = [int]$pos.VisualCol
}

# Moves the editor cursor up/down by one visual row keeping the preferred column.
function Move-TuiEditorVertical {
    param(
        $State,
        [int]$Delta
    )

    $current = Get-TuiEditorCursorVisualPosition -State $State
    $targetVisualRow = [Math]::Max(0, $current.VisualRow + $Delta)
    $preferredCol = [int]$State.EditorPreferredVisualColumn

    $visual = Get-TuiEditorVisualLines -State $State
    if ($visual.Count -eq 0) { return }

    if ($targetVisualRow -ge $visual.Count) {
        $targetVisualRow = $visual.Count - 1
    }

    $target = $visual[$targetVisualRow]
    $line = [string]$State.EditorLines[$target.LogicalIndex]
    $segmentStart = [int]$target.Start
    $segmentMax = [int]$target.Length

    # $preferredCol is a column in CELLS: I convert it to the corresponding character
    # offset inside the target segment, stopping at the desired column.
    $segText = $line.Substring($segmentStart, [Math]::Min($segmentMax, [Math]::Max(0, $line.Length - $segmentStart)))
    $accCells = 0
    $accChars = 0
    foreach ($rune in $segText.EnumerateRunes()) {
        $cw = Get-TuiRuneWidth -CodePoint $rune.Value
        if (($accCells + $cw) -gt $preferredCol) { break }
        $accCells += $cw
        $accChars += $rune.Utf16SequenceLength
    }

    $newX = $segmentStart + $accChars
    $newX = [Math]::Min($newX, $line.Length)

    $State.EditorCursorY = [int]$target.LogicalIndex
    $State.EditorCursorX = [int]$newX
}

# Draws the full-screen prompt editor (wrapped text, cursor, instructions).
function Show-TuiEditorFullScreen {
    param($State, $Config)

    $bodyTop = $script:TuiUi.BodyTop
    $bodyHeight = $script:TuiUi.BodyHeight
    $bodyWidth = $script:TuiUi.BodyWidth
    $lineNumberWidth = 5
    $textWidth = Get-TuiEditorTextWidth

    $title = (T 'tui.editor.titlebar' $State.EditorTitle)
    Write-TuiLine -Row $bodyTop -Text $title -Foreground $script:TuiPalette.EditorTitleFg -Background $script:TuiPalette.EditorTitleBg

    $availableRows = [Math]::Max(1, $bodyHeight - 1)
    $visualLines = Get-TuiEditorVisualLines -State $State
    $cursorPos = Get-TuiEditorCursorVisualPosition -State $State

    if ($cursorPos.VisualRow -lt $State.EditorViewportTop) {
        $State.EditorViewportTop = $cursorPos.VisualRow
    }
    elseif ($cursorPos.VisualRow -ge ($State.EditorViewportTop + $availableRows)) {
        $State.EditorViewportTop = $cursorPos.VisualRow - $availableRows + 1
    }

    for ($i = 0; $i -lt $availableRows; $i++) {
        $row = $bodyTop + 1 + $i
        $visualIndex = $State.EditorViewportTop + $i

        if ($visualIndex -lt $visualLines.Count) {
            $entry = $visualLines[$visualIndex]
            $isFirstVisualOfLogical = ([int]$entry.Start -eq 0)
            $lineNumber = if ($isFirstVisualOfLogical) { ('{0,4} ' -f ($entry.LogicalIndex + 1)) } else { '     ' }

            $oldFg = [Console]::ForegroundColor
            $oldBg = [Console]::BackgroundColor
            try {
                [Console]::SetCursorPosition(0, $row)
                [Console]::ForegroundColor = $script:TuiPalette.EditorLineNumber
                [Console]::BackgroundColor = $script:TuiPalette.EditorBackground
                [Console]::Write($lineNumber)

                $lineBody = Get-TuiTruncateToWidth -Text ([string]$entry.Text) -Width $textWidth

                [Console]::ForegroundColor = $script:TuiPalette.EditorText
                [Console]::BackgroundColor = $script:TuiPalette.EditorBackground
                [Console]::Write((Get-TuiPadToWidth -Text $lineBody -Width $textWidth))
            }
            finally {
                [Console]::ForegroundColor = $oldFg
                [Console]::BackgroundColor = $oldBg
            }
        }
        else {
            Write-TuiLine -Row $row -Text '' -Foreground $script:TuiPalette.EditorText -Background $script:TuiPalette.EditorBackground
        }
    }

    [Console]::CursorVisible = $true
    $cursorRow = $bodyTop + 1 + ($cursorPos.VisualRow - $State.EditorViewportTop)
    $cursorCol = [Math]::Min($bodyWidth - 1, $lineNumberWidth + $cursorPos.VisualCol)
    if ($cursorRow -ge ($bodyTop + 1) -and $cursorRow -lt ($bodyTop + 1 + $availableRows)) {
        [Console]::SetCursorPosition($cursorCol, $cursorRow)
    }
}

# Draws the TUI body choosing between the standard view and the prompt editor depending on the state.
function Show-TuiBody {
    param($State, $Config)

    if ($State.EditorActive) {
        Show-TuiEditorFullScreen -State $State -Config $Config
        return
    }

    Show-TuiBodyStandard -State $State
}

# Builds a list of colored label/value segments for the status bars.
function New-TuiLabelValueSegments {
    param(
        [array]$Pairs,
        [ConsoleColor]$LabelColor,
        [ConsoleColor]$ValueColor
    )

    $segments = @()
    for ($i = 0; $i -lt @($Pairs).Count; $i++) {
        $pair = $Pairs[$i]
        $segments += [pscustomobject]@{ Text = $pair.Label; Foreground = $LabelColor }
        $segments += [pscustomobject]@{ Text = $pair.Value; Foreground = $ValueColor }
        if ($i -lt (@($Pairs).Count - 1)) {
            $segments += [pscustomobject]@{ Text = ' ' + [char]0x2590 + ' '; Foreground = $LabelColor }
        }
    }
    return $segments
}

# Returns the label/value pairs of the first status bar (current generation parameters).
function Get-TuiStatusPairs1 {
    param($State)

    $autoVal = if ($State.Auto) { $State.Auto } else { (T 'tui.status.na') }

    return @(
        [pscustomobject]@{ Label = (T 'tui.status.model');   Value = [string]$State.Model }
        [pscustomobject]@{ Label = (T 'tui.status.auto');       Value = [string]$autoVal }
        [pscustomobject]@{ Label = (T 'tui.status.images');   Value = [string]$State.NImages }
        [pscustomobject]@{ Label = (T 'tui.status.size'); Value = [string]$State.Size }
        [pscustomobject]@{ Label = (T 'tui.status.quality');    Value = [string]$State.Quality }
        [pscustomobject]@{ Label = (T 'tui.status.format');    Value = [string]$State.Format }
    )
}

# Returns the label/value pairs of the second status bar (output, session costs, budget).
function Get-TuiStatusPairs2 {
    param($State, $Config)

    $modelCaps = Get-TuiModelCapabilities -Config $Config -ModelName $State.Model
    $fidelityVal = if ($modelCaps.SupportsInputFidelity) {
        if ($State.InputFidelity) { $State.InputFidelity } else { (T 'tui.status.na') }
    } else {
        (T 'tui.status.na')
    }

    $budgetVal = if ($null -ne $State.Budget) { '{0:N2} {1}' -f $State.Budget, $State.Currency } else { 'off' }

    return @(
        [pscustomobject]@{ Label = (T 'tui.status.moderation'); Value = [string]$State.Moderation }
        [pscustomobject]@{ Label = (T 'tui.status.fidelity');      Value = [string]$fidelityVal }
        [pscustomobject]@{ Label = (T 'tui.status.metadata');     Value = [string]$State.Metadata }
        [pscustomobject]@{ Label = (T 'tui.status.attached'); Value = [string]$State.InputImages.Count }
        [pscustomobject]@{ Label = (T 'tui.status.background');       Value = [string]$State.Background }
        [pscustomobject]@{ Label = (T 'tui.status.output');       Value = [string]$State.OutputMode }
        [pscustomobject]@{ Label = (T 'tui.status.budget');       Value = [string]$budgetVal }
        [pscustomobject]@{ Label = (T 'tui.status.features');     Value = (Get-TuiFeaturesSummary -State $State) }
    )
}

# Compact summary of the active generation functions (optimization, negative,
# storyboard) for the status bar. It shows only the active ones, or "-" if none.
function Get-TuiFeaturesSummary {
    param($State)
    $f = @()
    if ($State.OptimizePrompt) { $f += 'opt' }
    if ($State.NegativePrompt) { $f += 'neg' }
    if ($State.Storyboard)     { $f += ('sb:' + [string]$State.SequenceImages) }
    if ($f.Count -eq 0) { return '-' }
    return ($f -join ',')
}

# Draws the two status bars at the bottom of the TUI; the first becomes a progress bar during the generation.
function Show-TuiStatusBars {
    param($State, $Config)

    if ($State.ProgressActive) {
        $progressText = if ($State.ProgressLabel) {
            " $($State.ProgressLabel)  $(Get-TuiProgressBarText -State $State -Config $Config)"
        } else {
            ' ' + (Get-TuiProgressBarText -State $State -Config $Config)
        }

        Write-TuiLine -Row $script:TuiUi.StatusRow1 -Text $progressText -Foreground $script:TuiPalette.ProgressValue -Background $script:TuiPalette.ProgressBackground
    }
    else {
        $segments1 = New-TuiLabelValueSegments -Pairs (Get-TuiStatusPairs1 -State $State) -LabelColor $script:TuiPalette.Status1Label -ValueColor $script:TuiPalette.Status1Value
        Write-TuiSegments -Row $script:TuiUi.StatusRow1 -Background $script:TuiPalette.Status1Background -Segments $segments1
    }

    $segments2 = New-TuiLabelValueSegments -Pairs (Get-TuiStatusPairs2 -State $State -Config $Config) -LabelColor $script:TuiPalette.Status2Label -ValueColor $script:TuiPalette.Status2Value
    Write-TuiSegments -Row $script:TuiUi.StatusRow2 -Background $script:TuiPalette.Status2Background -Segments $segments2
}

# Draws the TUI command line (prompt, typed text, cursor position).
function Show-TuiCommandLine {
    param($State)

    if ($State.EditorActive) {
        Write-TuiLine -Row $script:TuiUi.CommandRow -Text (T 'tui.cmdline.editor_active') -Foreground $script:TuiPalette.CommandInput -Background $script:TuiPalette.CommandBackground
        return
    }

    $prefix = ' ' + [char]0x276F + ' '
    $hint = ''
    if ($State.ShowHints) {
        $hint = (T 'tui.cmdline.hint')
    }

    $oldFg = [Console]::ForegroundColor
    $oldBg = [Console]::BackgroundColor
    try {
        # Progressive writing without clearing the row first (anti-flicker):
        # prompt + typed text + hint, then spaces to the end of the row to clear
        # any residue (e.g. after deleting characters with Backspace).
        [Console]::SetCursorPosition(0, $script:TuiUi.CommandRow)
        [Console]::ForegroundColor = $script:TuiPalette.CommandPrompt
        [Console]::BackgroundColor = $script:TuiPalette.CommandBackground
        [Console]::Write($prefix)

        [Console]::ForegroundColor = $script:TuiPalette.CommandInput
        [Console]::Write($State.CommandLine)
        $cursor = $prefix.Length + (Get-TuiDisplayWidth -Text $State.CommandLine)

        if ($hint) {
            [Console]::ForegroundColor = $script:TuiPalette.CommandHint
            $remaining = [Math]::Max(0, $script:TuiUi.Width - $cursor)
            $hintText = Get-TuiTruncateToWidth -Text $hint -Width $remaining
            [Console]::Write($hintText)
            $cursor += Get-TuiDisplayWidth -Text $hintText
        }

        if ($cursor -lt $script:TuiUi.Width) {
            [Console]::ForegroundColor = $script:TuiPalette.CommandInput
            [Console]::Write(' ' * ($script:TuiUi.Width - $cursor))
        }
    }
    finally {
        [Console]::ForegroundColor = $oldFg
        [Console]::BackgroundColor = $oldBg
    }

    [Console]::CursorVisible = $true
    $cursorChars = [Math]::Max(0, [Math]::Min([int]$State.CommandCursor, $State.CommandLine.Length))
    $cursorCells = $prefix.Length + (Get-TuiDisplayWidth -Text $State.CommandLine.Substring(0, $cursorChars))
    [Console]::SetCursorPosition(
        [Math]::Min($script:TuiUi.Width - 1, $cursorCells),
        $script:TuiUi.CommandRow
    )
}

# Draws the entire TUI (header, body, status bar, command line) inside a synchronized frame, for flicker-free rendering.
function Show-Tui {
    param($State, $Config)

    Initialize-TuiListState -State $State
    Sync-TuiDimensions
    Open-TuiFrame
    try {
        Show-TuiHeader -State $State -Config $Config
        Show-TuiSeparator -Row $script:TuiUi.HeaderSepRow -Char '═'
        Show-TuiBody -State $State -Config $Config
        Show-TuiSeparator -Row $script:TuiUi.FooterSepRow -Char '═'
        Show-TuiStatusBars -State $State -Config $Config
        Show-TuiCommandLine -State $State
    }
    finally {
        Close-TuiFrame
    }
}

function Update-TuiProgressBars {
    # Light refresh used during the generation: redraws ONLY the two status
    # rows (where the progress bar lives) inside a synchronized frame, without
    # the full redraw of Show-Tui. During the generation header/body/command-line do not
    # change (the logs go to the file, no message is added), so it is
    # correct and much faster: a few cells updated instead of the whole screen.
    param($State, $Config)
    if (-not $script:TuiUi) { return }
    # Protezione resize: se la finestra si restringe durante la generazione una
    # SetCursorPosition can go out of bounds; in that case I skip the frame: the
    # next callback, about 2 per second, will redraw the bar.
    try {
        Open-TuiFrame
        try {
            Show-TuiStatusBars -State $State -Config $Config
        }
        finally {
            Close-TuiFrame
        }
    }
    catch { }
}

# Performs a TUI render protecting it from the exceptions due to window resize
# (e.g. SetCursorPosition out of range if the console shrinks mid-frame): in that
# case it resynchronizes the dimensions, clears the screen and retries ONCE with a
# full render; if the retry also fails, the frame is skipped and the next
# input event will redraw everything.
function Invoke-TuiSafeRender {
    param(
        $State,
        $Config,
        [ValidateSet('Full','Editor','CommandLine')]
        [string]$Mode = 'Full'
    )
    try {
        switch ($Mode) {
            'Full'        { Show-Tui -State $State -Config $Config }
            'Editor'      { Show-TuiEditorFullScreen -State $State -Config $Config }
            'CommandLine' { Show-TuiCommandLine -State $State }
        }
    }
    catch {
        try {
            Sync-TuiDimensions
            [Console]::Clear()
            Show-Tui -State $State -Config $Config
        }
        catch { }
    }
}

# Navigates backward in the TUI command history.
function Get-TuiHistoryPrev {
    param($State)
    Initialize-TuiListState -State $State
    if ($State.CommandHistory.Count -eq 0) { return }
    if ($State.CommandHistoryIndex -lt 0) { $State.CommandHistoryIndex = $State.CommandHistory.Count }
    $State.CommandHistoryIndex = [Math]::Max(0, $State.CommandHistoryIndex - 1)
    $State.CommandLine = $State.CommandHistory[$State.CommandHistoryIndex]
    $State.CommandCursor = $State.CommandLine.Length
}

# Navigates forward in the TUI command history.
function Get-TuiHistoryNext {
    param($State)
    Initialize-TuiListState -State $State
    if ($State.CommandHistory.Count -eq 0) { return }
    if ($State.CommandHistoryIndex -lt 0) { return }

    $State.CommandHistoryIndex = [Math]::Min($State.CommandHistory.Count, $State.CommandHistoryIndex + 1)
    if ($State.CommandHistoryIndex -ge $State.CommandHistory.Count) {
        $State.CommandLine = ''
        $State.CommandCursor = 0
        return
    }

    $State.CommandLine = $State.CommandHistory[$State.CommandHistoryIndex]
    $State.CommandCursor = $State.CommandLine.Length
}

# Inserts a character into the TUI command line at the cursor position.
function Add-TuiCommandChar {
    param($State, [char]$Char)
    $left  = $State.CommandLine.Substring(0, $State.CommandCursor)
    $right = $State.CommandLine.Substring($State.CommandCursor)
    $State.CommandLine = $left + $Char + $right
    $State.CommandCursor++
}

# Deletes the character to the left of the cursor in the command line (Backspace).
function Remove-TuiCommandCharLeft {
    param($State)
    if ($State.CommandCursor -le 0) { return }
    $left  = $State.CommandLine.Substring(0, $State.CommandCursor - 1)
    $right = $State.CommandLine.Substring($State.CommandCursor)
    $State.CommandLine = $left + $right
    $State.CommandCursor--
}

# Deletes the character to the right of the cursor in the command line (Delete).
function Remove-TuiCommandCharRight {
    param($State)
    if ($State.CommandCursor -ge $State.CommandLine.Length) { return }
    $left = $State.CommandLine.Substring(0, $State.CommandCursor)
    $right = ''
    if ($State.CommandCursor + 1 -lt $State.CommandLine.Length) {
        $right = $State.CommandLine.Substring($State.CommandCursor + 1)
    }
    $State.CommandLine = $left + $right
}

# Returns the TUI commands that accept a path as an argument (for autocompletion).
function Get-TuiPathCommandNames {
    return @('/promptfile','/mask','/inputimages','/outputfolder')
}

# Parses the TUI command line separating command and argument.
function Get-TuiCommandAndArgState {
    param([string]$CommandLine)

    $line = if ($null -ne $CommandLine) { [string]$CommandLine } else { '' }
    $trimStart = $line.TrimStart()

    if (-not $trimStart.StartsWith('/')) {
        return [pscustomobject]@{
            Command = ''
            ArgText = ''
            HasArg  = $false
        }
    }

    $parts = $trimStart.Split(' ', 2, [System.StringSplitOptions]::None)
    $cmd = $parts[0]
    $arg = if ($parts.Count -gt 1) { $parts[1] } else { '' }
    $hasArg = ($parts.Count -gt 1)

    return [pscustomobject]@{
        Command = $cmd
        ArgText = $arg
        HasArg  = $hasArg
    }
}

# Rimuove le virgolette eventualmente presenti attorno a un path inserito dall'utente.
function Remove-TuiPathQuotes {
    param([string]$Text)

    if ([string]::IsNullOrEmpty($Text)) { return '' }
    $t = $Text.Trim()
    if ($t.Length -ge 2) {
        if (($t.StartsWith('"') -and $t.EndsWith('"')) -or ($t.StartsWith("'") -and $t.EndsWith("'"))) {
            return $t.Substring(1, $t.Length - 2)
        }
    }
    if ($t.StartsWith('"') -or $t.StartsWith("'")) {
        return $t.Substring(1)
    }
    return $t
}

# Adds quotes around a path if it contains spaces or commas.
function Add-TuiPathQuoteIfNeeded {
    param([string]$Path)

    if ($null -eq $Path) { return '' }
    if ($Path -match '\s|,') {
        return '"' + $Path + '"'
    }
    return $Path
}

# Resolves a path to its absolute form if it exists, otherwise returns $null.
function Resolve-TuiExistingPath {
    param([string]$Path)

    if ([string]::IsNullOrWhiteSpace($Path)) { return $null }
    try {
        return (Resolve-Path -LiteralPath $Path -ErrorAction Stop).Path
    }
    catch {
        return $null
    }
}

# Determines the context for path autocompletion (prefix and current fragment).
function Get-TuiPathAutocompleteContext {
    param(
        [string]$Command,
        [string]$ArgText
    )

    $arg = if ($null -ne $ArgText) { [string]$ArgText } else { '' }

    if ($Command -ieq '/inputimages') {
        $lastComma = $arg.LastIndexOf(',')
        if ($lastComma -ge 0) {
            $prefix = $arg.Substring(0, $lastComma + 1)
            $current = $arg.Substring($lastComma + 1).TrimStart()
            return [pscustomobject]@{
                Prefix  = $prefix + ($(if ($arg.Substring($lastComma + 1) -match '^\s+') { ' ' } else { '' }))
                Current = $current
            }
        }
    }

    return [pscustomobject]@{
        Prefix  = ''
        Current = $arg.TrimStart()
    }
}

# Searches the files/folders that match the typed path fragment (for autocompletion).
function Get-TuiPathMatches {
    param([string]$CurrentText)

    $rawInput = if ($null -ne $CurrentText) { [string]$CurrentText } else { '' }
    $typed = Remove-TuiPathQuotes -Text $rawInput

    if ([string]::IsNullOrWhiteSpace($typed)) {
        $typed = '.'
    }

    $searchBase = $typed
    $leafPrefix = ''
    $endsWithSlash = ($typed -match '[\\/]\s*$')

    if ($endsWithSlash) {
        $searchBase = $typed.TrimEnd('\','/')
        if ([string]::IsNullOrWhiteSpace($searchBase)) { $searchBase = $typed }
        $leafPrefix = ''
    }
    else {
        $parent = Split-Path -Path $typed -Parent -ErrorAction SilentlyContinue
        $leaf = Split-Path -Path $typed -Leaf -ErrorAction SilentlyContinue

        if ([string]::IsNullOrWhiteSpace($parent)) {
            if ($typed -match '^[A-Za-z]:$') {
                $searchBase = $typed + '\'
                $leafPrefix = ''
            }
            elseif ($typed -match '^[A-Za-z]:\\') {
                $searchBase = $typed
                $leafPrefix = ''
            }
            else {
                $searchBase = '.'
                $leafPrefix = $typed
            }
        }
        else {
            $searchBase = $parent
            $leafPrefix = $leaf
        }
    }

    $resolvedBase = $null
    try {
        if ($searchBase -match '^[A-Za-z]:\\?$' -and -not (Test-Path -LiteralPath $searchBase -ErrorAction SilentlyContinue)) {
            $resolvedBase = $searchBase
        }
        else {
            $resolvedBase = (Resolve-Path -LiteralPath $searchBase -ErrorAction Stop).Path
        }
    }
    catch {
        return @()
    }

    $items = @()
    try {
        $items = @(Get-ChildItem -LiteralPath $resolvedBase -Force -ErrorAction Stop)
    }
    catch {
        return @()
    }

    $tuiMatches = @($items | Where-Object { $_.Name -like "$leafPrefix*" } | Sort-Object @{ Expression = { -not $_.PSIsContainer } }, Name)

    $result = @()
    foreach ($m in $tuiMatches) {
        $full = $m.FullName
        if ($m.PSIsContainer) {
            $full = $full.TrimEnd('\') + '\'
        }
        $result += [pscustomobject]@{
            FullPath = $full
            Name     = $m.Name
            IsDir    = [bool]$m.PSIsContainer
        }
    }

    return $result
}

# Applies the chosen path completion to the command line.
function Set-TuiPathCompletion {
    param(
        $State,
        [string]$Command,
        [string]$ArgText
    )

    $ctx = Get-TuiPathAutocompleteContext -Command $Command -ArgText $ArgText
    $tuiMatches = @(Get-TuiPathMatches -CurrentText $ctx.Current)

    if ($tuiMatches.Count -eq 0) {
        Add-TuiMessage -State $State -Text (T 'tui.msg.path_none') -Kind 'Warning'
        return
    }

    if ($tuiMatches.Count -eq 1) {
        $completed = Add-TuiPathQuoteIfNeeded -Path $tuiMatches[0].FullPath
        $newArg = ($ctx.Prefix + $completed).TrimStart()
        $State.CommandLine = "$Command $newArg"
        $State.CommandCursor = $State.CommandLine.Length
        return
    }

    $common = $tuiMatches[0].FullPath
    foreach ($m in $tuiMatches[1..($tuiMatches.Count - 1)]) {
        $limit = [Math]::Min($common.Length, $m.FullPath.Length)
        $i = 0
        while ($i -lt $limit -and [char]::ToLowerInvariant($common[$i]) -eq [char]::ToLowerInvariant($m.FullPath[$i])) {
            $i++
        }
        $common = $common.Substring(0, $i)
        if ([string]::IsNullOrEmpty($common)) { break }
    }

    if (-not [string]::IsNullOrWhiteSpace($common)) {
        $completed = Add-TuiPathQuoteIfNeeded -Path $common
        $newArg = ($ctx.Prefix + $completed).TrimStart()
        $State.CommandLine = "$Command $newArg"
        $State.CommandCursor = $State.CommandLine.Length
    }

    $preview = @($tuiMatches | Select-Object -First 10 | ForEach-Object { $_.FullPath })
    Add-TuiMessage -State $State -Text (T 'tui.preview.path' ($preview -join ' | ')) -Kind 'Info'
}

# Handles Tab in the TUI: completes commands or paths based on the context.
function Invoke-TuiAutocomplete {
    param($State, $Config)

    $current = [string]$State.CommandLine
    $cmdState = Get-TuiCommandAndArgState -CommandLine $current
    $pathCommands = Get-TuiPathCommandNames

    if ($pathCommands -contains $cmdState.Command -and ($cmdState.HasArg -or $current.EndsWith(' '))) {
        Set-TuiPathCompletion -State $State -Command $cmdState.Command -ArgText $cmdState.ArgText
        return
    }

    $commands = @(
        '/prompt','/promptfile','/model','/auto','/nimages','/size','/quality',
        '/format','/moderation','/inputfidelity','/metadata','/background',
        '/mask','/inputimages','/outputfolder','/theme','/generate','/clear','/reset',
        '/reload','/optimize','/negative','/storyboard','/sequenceimages',
        '/help','/exit'
    )

    if ([string]::IsNullOrWhiteSpace($current)) {
        Add-TuiMessage -State $State -Text (T 'tui.preview.commands' ($commands -join ', ')) -Kind 'Info'
        return
    }

    $tuiMatches = @($commands | Where-Object { $_ -like "$current*" })
    $matchCount = @($tuiMatches).Count

    if ($matchCount -eq 1) {
        $State.CommandLine = ([string]$tuiMatches[0]) + ' '
        $State.CommandCursor = $State.CommandLine.Length
    }
    elseif ($matchCount -gt 1) {
        Add-TuiMessage -State $State -Text (T 'tui.preview.commands' ($tuiMatches -join ', ')) -Kind 'Info'
    }
}

# Opens the full-screen prompt editor starting from the current prompt.
function Open-TuiPromptEditor {
    param($State)

    Initialize-TuiListState -State $State

    $State.EditorActive = $true
    $State.EditorTitle = (T 'tui.editor.title_prompt')
    $State.EditorSourceMode = 'manual'
    $State.EditorSourcePath = $null
    $State.EditorLines.Clear()

    if ([string]::IsNullOrWhiteSpace($State.PromptText)) {
        [void]$State.EditorLines.Add('')
    }
    else {
        foreach ($line in ($State.PromptText -split "`r?`n")) {
            [void]$State.EditorLines.Add([string]$line)
        }
    }

    $State.EditorCursorY = [Math]::Max(0, $State.EditorLines.Count - 1)
    $State.EditorCursorX = $State.EditorLines[$State.EditorCursorY].Length
    $State.EditorViewportTop = 0
    Set-TuiEditorPreferredVisualColumn -State $State

    Add-TuiMessage -State $State -Text (T 'tui.msg.editor_prompt_on') -Kind 'Info'
}

# Opens the prompt editor preloading it with a given text.
function Open-TuiEditorWithText {
    param($State, [string]$Title, [string]$Text, [string]$Mode, [string]$Path)

    Initialize-TuiListState -State $State

    $State.EditorActive = $true
    $State.EditorTitle = $Title
    $State.EditorSourceMode = $Mode
    $State.EditorSourcePath = $Path
    $State.EditorLines.Clear()

    if ([string]::IsNullOrEmpty($Text)) {
        [void]$State.EditorLines.Add('')
    }
    else {
        foreach ($line in ($Text -split "`r?`n")) {
            [void]$State.EditorLines.Add([string]$line)
        }
    }

    $State.EditorCursorY = 0
    $State.EditorCursorX = 0
    $State.EditorViewportTop = 0
    Set-TuiEditorPreferredVisualColumn -State $State
    Add-TuiMessage -State $State -Text (T 'tui.msg.editor_promptfile_on') -Kind 'Info'
}

# Confirms the editor text as the current prompt and closes the editor.
function Save-TuiEditor {
    param($State)

    $text = ($State.EditorLines -join "`n")
    $State.PromptText = $text
    $State.PromptSource = $State.EditorSourceMode
    $State.PromptFilePath = $State.EditorSourcePath
    $State.EditorActive = $false

    if ($State.EditorSourceMode -eq 'file' -and $State.EditorSourcePath) {
        Add-TuiMessage -State $State -Text (T 'tui.msg.prompt_loaded_file' $State.EditorSourcePath) -Kind 'Success'
    }
    else {
        Add-TuiMessage -State $State -Text (T 'tui.msg.prompt_updated') -Kind 'Success'
    }

    $preview = $text.Trim()
    if ($preview.Length -gt 180) { $preview = $preview.Substring(0, 180) + '…' }
    if (-not [string]::IsNullOrWhiteSpace($preview)) {
        Add-TuiMessage -State $State -Text (T 'tui.preview.prompt_ready' $preview) -Kind 'Normal'
    }
    Add-TuiMessage -State $State -Text (T 'tui.msg.prompt_ready') -Kind 'Info'
}

# Closes the prompt editor discarding the changes.
function Exit-TuiEditor {
    param($State)
    $State.EditorActive = $false
    Add-TuiMessage -State $State -Text (T 'tui.msg.editor_cancelled') -Kind 'Warning'
}

# Loads the content of a text file into the prompt (/promptfile command).
function Set-TuiPromptFile {
    param($State, [string]$Path)

    if ([string]::IsNullOrWhiteSpace($Path)) {
        Add-TuiMessage -State $State -Text (T 'tui.msg.promptfile_specify') -Kind 'Warning'
        return
    }

    try {
        $cleanPath = Remove-TuiPathQuotes -Text $Path
        if (-not (Test-Path -LiteralPath $cleanPath -PathType Leaf -ErrorAction SilentlyContinue)) {
            Add-TuiMessage -State $State -Text (T 'tui.msg.promptfile_notfound') -Kind 'Error'
            return
        }

        $resolved = (Resolve-Path -LiteralPath $cleanPath -ErrorAction Stop).Path
        $content = Get-Content -Path $resolved -Raw -Encoding UTF8 -ErrorAction Stop
        Add-TuiMessage -State $State -Text (T 'tui.msg.promptfile_loading' $resolved) -Kind 'Info'
        Open-TuiEditorWithText -State $State -Title (T 'tui.editor.title_promptfile') -Text $content -Mode 'file' -Path $resolved
    }
    catch {
        Add-TuiMessage -State $State -Text (T 'tui.error.promptfile_load' $_.Exception.Message) -Kind 'Error'
    }
}

# Initializes the row/cursor state of the prompt editor.
function Initialize-TuiEditorLine {
    param($State)
    Initialize-TuiListState -State $State
    if ($State.EditorLines.Count -eq 0) { [void]$State.EditorLines.Add('') }
}

# Handles a key pressed while the prompt editor is active (insertion, movement, confirmation).
function Invoke-TuiEditorKey {
    param($Key, $State, $Config)

    Initialize-TuiEditorLine -State $State
    $ctrl = (($Key.Modifiers -band [ConsoleModifiers]::Control) -ne 0)

    # Ctrl+C: copies all the editor text to the clipboard (TUI request #2). It does not
    # exit the editor; it just copies. Set-Clipboard is available on Windows; in
    # case of error (non-interactive/non-Windows sessions) I warn without blocking.
    if ($ctrl -and $Key.Key -eq 'C') {
        $allText = ($State.EditorLines -join "`n")
        try {
            Set-Clipboard -Value $allText -ErrorAction Stop
            Add-TuiMessage -State $State -Text (T 'tui.msg.editor_copied') -Kind 'Success'
        } catch {
            Add-TuiMessage -State $State -Text (T 'tui.msg.editor_copy_failed') -Kind 'Warning'
        }
        return
    }

    switch ($Key.Key) {
        'Escape' { Exit-TuiEditor -State $State; return }
        'F2'     { Save-TuiEditor -State $State; return }
        'LeftArrow' {
            if ($State.EditorCursorX -gt 0) {
                $State.EditorCursorX--
            }
            elseif ($State.EditorCursorY -gt 0) {
                $State.EditorCursorY--
                $State.EditorCursorX = $State.EditorLines[$State.EditorCursorY].Length
            }
            Set-TuiEditorPreferredVisualColumn -State $State
            return
        }
        'RightArrow' {
            $line = $State.EditorLines[$State.EditorCursorY]
            if ($State.EditorCursorX -lt $line.Length) {
                $State.EditorCursorX++
            }
            elseif ($State.EditorCursorY -lt $State.EditorLines.Count - 1) {
                $State.EditorCursorY++
                $State.EditorCursorX = 0
            }
            Set-TuiEditorPreferredVisualColumn -State $State
            return
        }
        'UpArrow' {
            Move-TuiEditorVertical -State $State -Delta -1
            return
        }
        'DownArrow' {
            Move-TuiEditorVertical -State $State -Delta 1
            return
        }
        'Home' {
            $line = [string]$State.EditorLines[$State.EditorCursorY]
            $width = Get-TuiEditorTextWidth
            $segmentStart = [Math]::Floor($State.EditorCursorX / [double]$width) * $width
            if ($State.EditorCursorX -eq $segmentStart) {
                $State.EditorCursorX = 0
            }
            else {
                $State.EditorCursorX = [int]$segmentStart
            }
            $State.EditorCursorX = [Math]::Min($State.EditorCursorX, $line.Length)
            Set-TuiEditorPreferredVisualColumn -State $State
            return
        }
        'End' {
            $line = [string]$State.EditorLines[$State.EditorCursorY]
            $width = Get-TuiEditorTextWidth
            $segmentStart = [Math]::Floor($State.EditorCursorX / [double]$width) * $width
            $segmentEnd = [Math]::Min($line.Length, $segmentStart + $width)
            if ($State.EditorCursorX -eq $segmentEnd) {
                $State.EditorCursorX = $line.Length
            }
            else {
                $State.EditorCursorX = [int]$segmentEnd
            }
            Set-TuiEditorPreferredVisualColumn -State $State
            return
        }
        'Backspace' {
            $line = [string]$State.EditorLines[$State.EditorCursorY]
            if ($State.EditorCursorX -gt 0) {
                $newLine = $line.Substring(0, $State.EditorCursorX - 1) + $line.Substring($State.EditorCursorX)
                $State.EditorLines[$State.EditorCursorY] = $newLine
                $State.EditorCursorX--
            }
            elseif ($State.EditorCursorY -gt 0) {
                $prev = [string]$State.EditorLines[$State.EditorCursorY - 1]
                $curr = [string]$State.EditorLines[$State.EditorCursorY]
                $newX = $prev.Length
                $State.EditorLines[$State.EditorCursorY - 1] = $prev + $curr
                $State.EditorLines.RemoveAt($State.EditorCursorY)
                $State.EditorCursorY--
                $State.EditorCursorX = $newX
            }
            Set-TuiEditorPreferredVisualColumn -State $State
            return
        }
        'Delete' {
            $line = [string]$State.EditorLines[$State.EditorCursorY]
            if ($State.EditorCursorX -lt $line.Length) {
                $newLine = $line.Substring(0, $State.EditorCursorX) + $line.Substring($State.EditorCursorX + 1)
                $State.EditorLines[$State.EditorCursorY] = $newLine
            }
            elseif ($State.EditorCursorY -lt $State.EditorLines.Count - 1) {
                $next = [string]$State.EditorLines[$State.EditorCursorY + 1]
                $State.EditorLines[$State.EditorCursorY] = $line + $next
                $State.EditorLines.RemoveAt($State.EditorCursorY + 1)
            }
            Set-TuiEditorPreferredVisualColumn -State $State
            return
        }
        'Enter' {
            $line = [string]$State.EditorLines[$State.EditorCursorY]
            $left = $line.Substring(0, $State.EditorCursorX)
            $right = $line.Substring($State.EditorCursorX)
            $State.EditorLines[$State.EditorCursorY] = $left
            $State.EditorLines.Insert($State.EditorCursorY + 1, $right)
            $State.EditorCursorY++
            $State.EditorCursorX = 0
            Set-TuiEditorPreferredVisualColumn -State $State
            return
        }
    }

    if ($ctrl -and $Key.Key -eq 'V') {
        try {
            Add-Type -AssemblyName PresentationCore,PresentationFramework -ErrorAction SilentlyContinue | Out-Null
            $clip = [Windows.Clipboard]::GetText()
            if (-not [string]::IsNullOrEmpty($clip)) {
                foreach ($ch in $clip.ToCharArray()) {
                    if ($ch -eq "`r") { continue }
                    if ($ch -eq "`n") {
                        $line = [string]$State.EditorLines[$State.EditorCursorY]
                        $left = $line.Substring(0, $State.EditorCursorX)
                        $right = $line.Substring($State.EditorCursorX)
                        $State.EditorLines[$State.EditorCursorY] = $left
                        $State.EditorLines.Insert($State.EditorCursorY + 1, $right)
                        $State.EditorCursorY++
                        $State.EditorCursorX = 0
                    }
                    else {
                        $line = [string]$State.EditorLines[$State.EditorCursorY]
                        $State.EditorLines[$State.EditorCursorY] = $line.Substring(0, $State.EditorCursorX) + $ch + $line.Substring($State.EditorCursorX)
                        $State.EditorCursorX++
                    }
                }
                Set-TuiEditorPreferredVisualColumn -State $State
            }
        }
        catch {}
        return
    }

    if (-not [char]::IsControl($Key.KeyChar)) {
        $line = [string]$State.EditorLines[$State.EditorCursorY]
        $State.EditorLines[$State.EditorCursorY] = $line.Substring(0, $State.EditorCursorX) + $Key.KeyChar + $line.Substring($State.EditorCursorX)
        $State.EditorCursorX++
        Set-TuiEditorPreferredVisualColumn -State $State
    }
}

# TUI command: sets the current model, validating it against the config.
function Set-TuiModel {
    param($State, $Config, [string]$Value)

    if ([string]::IsNullOrWhiteSpace($Value)) {
        Add-TuiMessage -State $State -Text (T 'tui.msg.model_specify') -Kind 'Warning'
        return
    }

    $available = @($Config.models.PSObject.Properties.Name)
    # Case-insensitive match, but in the state I save the CANONICAL .conf name
    # (coerente con la normalizzazione di Resolve-ModelRuntime e del flusso CLI).
    $canonical = @($available | Where-Object { $_ -ieq $Value } | Select-Object -First 1)
    if (-not $canonical) {
        Add-TuiMessage -State $State -Text (T 'tui.preview.models_available' ($available -join ', ')) -Kind 'Error'
        return
    }

    $State.Model = [string]$canonical[0]
    $State.Auto = $null
    Add-TuiMessage -State $State -Text (T 'tui.msg.model_set' $State.Model) -Kind 'Success'
}

# TUI command: activates/sets the automatic model selection (Cost/Quality/Time).
function Set-TuiAuto {
    param($State, [string]$Value)
    $valid = @('Cost','Quality','Time')
    if ($valid -notcontains $Value) {
        Add-TuiMessage -State $State -Text (T 'tui.msg.auto_invalid') -Kind 'Error'
        return
    }
    $State.Auto = $Value
    Add-TuiMessage -State $State -Text (T 'tui.msg.auto_set' $Value) -Kind 'Success'
}

# TUI command: sets the number of images to generate.
function Set-TuiNImages {
    param($State, [string]$Value)
    $n = 0
    if (-not [int]::TryParse($Value, [ref]$n) -or $n -lt 1 -or $n -gt 10) {
        Add-TuiMessage -State $State -Text (T 'tui.msg.nimages_invalid') -Kind 'Error'
        return
    }
    $State.NImages = $n
    Add-TuiMessage -State $State -Text (T 'tui.msg.nimages_set' $n) -Kind 'Success'
}

# TUI command: sets the image dimension.
function Set-TuiSize {
    param($State, [string]$Value)
    if ($Value -notmatch '^\d+x\d+$') {
        Add-TuiMessage -State $State -Text (T 'tui.msg.size_invalid') -Kind 'Error'
        return
    }
    $State.Size = $Value
    Add-TuiMessage -State $State -Text (T 'tui.msg.size_set' $Value) -Kind 'Success'
}

# TUI command: sets the generation quality.
function Set-TuiQuality {
    param($State, [string]$Value)
    $valid = @('low','medium','high')
    if ($valid -notcontains $Value) {
        Add-TuiMessage -State $State -Text (T 'tui.msg.quality_invalid') -Kind 'Error'
        return
    }
    $State.Quality = $Value
    Add-TuiMessage -State $State -Text (T 'tui.msg.quality_set' $Value) -Kind 'Success'
}

# TUI command: sets the output file format.
function Set-TuiFormat {
    param($State, [string]$Value)
    $valid = @('png','jpg','webp')
    if ($valid -notcontains $Value) {
        Add-TuiMessage -State $State -Text (T 'tui.msg.format_invalid') -Kind 'Error'
        return
    }
    $State.Format = $Value
    Add-TuiMessage -State $State -Text (T 'tui.msg.format_set' $Value) -Kind 'Success'
}

# TUI command: sets the content moderation policy.
function Set-TuiModeration {
    param($State, [string]$Value)
    $valid = @('low','auto')
    if ($valid -notcontains $Value) {
        Add-TuiMessage -State $State -Text (T 'tui.msg.moderation_invalid') -Kind 'Error'
        return
    }
    $State.Moderation = $Value
    Add-TuiMessage -State $State -Text (T 'tui.msg.moderation_set' $Value) -Kind 'Success'
}

# TUI command: sets the input fidelity (warns if the model does not support it).
function Set-TuiInputFidelity {
    param($State, $Config, [string]$Value)
    $caps = Get-TuiModelCapabilities -Config $Config -ModelName $State.Model
    if (-not $caps.SupportsInputFidelity) {
        Add-TuiMessage -State $State -Text (T 'tui.msg.fidelity_unsupported') -Kind 'Warning'
        return
    }

    $valid = @('low','high')
    if ($valid -notcontains $Value) {
        Add-TuiMessage -State $State -Text (T 'tui.msg.fidelity_invalid') -Kind 'Error'
        return
    }

    $State.InputFidelity = $Value
    Add-TuiMessage -State $State -Text (T 'tui.msg.fidelity_set' $Value) -Kind 'Success'
}

# TUI command: enables/disables the writing of the metadata file.
function Set-TuiMetadata {
    param($State, [string]$Value)

    switch ($Value.ToLowerInvariant()) {
        'true'  { $State.Metadata = $true;  Add-TuiMessage -State $State -Text (T 'tui.msg.metadata_on') -Kind 'Success'; return }
        'false' { $State.Metadata = $false; Add-TuiMessage -State $State -Text (T 'tui.msg.metadata_off') -Kind 'Success'; return }
        default { Add-TuiMessage -State $State -Text (T 'tui.msg.metadata_invalid') -Kind 'Error'; return }
    }
}


# TUI command: enables/disables the prompt optimization (-OptimizePrompt). Without an
# argument it acts as a toggle; it also accepts explicit true/false. It requires a
# text model configured: I verify it and warn if it is missing.
function Set-TuiOptimize {
    param($State, [string]$Value)
    $new = Get-TuiToggleValue -Current $State.OptimizePrompt -Value $Value
    if ($null -eq $new) { Add-TuiMessage -State $State -Text (T 'tui.msg.toggle_invalid') -Kind 'Error'; return }
    if ($new -and -not (Test-TuiTextModelReady)) {
        Add-TuiMessage -State $State -Text (T 'tui.msg.textmodel_missing') -Kind 'Warning'
    }
    $State.OptimizePrompt = $new
    $msg = if ($new) { T 'tui.msg.optimize_on' } else { T 'tui.msg.optimize_off' }
    Add-TuiMessage -State $State -Text $msg -Kind 'Success'
}

# TUI command: enables/disables the generation of the negative prompt (-NegativePrompt).
function Set-TuiNegative {
    param($State, [string]$Value)
    $new = Get-TuiToggleValue -Current $State.NegativePrompt -Value $Value
    if ($null -eq $new) { Add-TuiMessage -State $State -Text (T 'tui.msg.toggle_invalid') -Kind 'Error'; return }
    if ($new -and -not (Test-TuiTextModelReady)) {
        Add-TuiMessage -State $State -Text (T 'tui.msg.textmodel_missing') -Kind 'Warning'
    }
    $State.NegativePrompt = $new
    $msg = if ($new) { T 'tui.msg.negative_on' } else { T 'tui.msg.negative_off' }
    Add-TuiMessage -State $State -Text $msg -Kind 'Success'
}

# TUI command: enables/disables the storyboard mode (-Storyboard). A narrative
# sequence of coherent images. It too requires the text model.
function Set-TuiStoryboard {
    param($State, [string]$Value)
    $new = Get-TuiToggleValue -Current $State.Storyboard -Value $Value
    if ($null -eq $new) { Add-TuiMessage -State $State -Text (T 'tui.msg.toggle_invalid') -Kind 'Error'; return }
    if ($new -and -not (Test-TuiTextModelReady)) {
        Add-TuiMessage -State $State -Text (T 'tui.msg.textmodel_missing') -Kind 'Warning'
    }
    $State.Storyboard = $new
    $msg = if ($new) { T 'tui.msg.storyboard_on' ([string]$State.SequenceImages) } else { T 'tui.msg.storyboard_off' }
    Add-TuiMessage -State $State -Text $msg -Kind 'Success'
}

# TUI command: number of images in the storyboard sequence (2-20).
function Set-TuiSequenceImages {
    param($State, [string]$Value)
    $n = 0
    if (-not [int]::TryParse($Value, [ref]$n) -or $n -lt 2 -or $n -gt 20) {
        Add-TuiMessage -State $State -Text (T 'tui.msg.sequenceimages_invalid') -Kind 'Error'
        return
    }
    $State.SequenceImages = $n
    Add-TuiMessage -State $State -Text (T 'tui.msg.sequenceimages_set' ([string]$n)) -Kind 'Success'
}

# TUI helper: interprets a toggle value. Without an argument it inverts the current
# state; with 'true'/'on'/'1' or 'false'/'off'/'0' it sets explicitly. It returns
# $null if the value is not recognized.
function Get-TuiToggleValue {
    param([bool]$Current, [string]$Value)
    if ([string]::IsNullOrWhiteSpace($Value)) { return (-not $Current) }
    switch ($Value.ToLowerInvariant()) {
        'true'  { return $true }
        'on'    { return $true }
        '1'     { return $true }
        'false' { return $false }
        'off'   { return $false }
        '0'     { return $false }
        default { return $null }
    }
}

# TUI helper: verifies that the text model is configured (needed by optimize,
# negative, storyboard). Returns $true if there is a text model set.
function Test-TuiTextModelReady {
    return ($null -ne $config.textModel -and -not [string]::IsNullOrWhiteSpace([string]$config.textModel.model))
}

# TUI command: sets the background type (warns if the model does not support it).
function Set-TuiBackground {
    param($State, $Config, [string]$Value)

    $caps = Get-TuiModelCapabilities -Config $Config -ModelName $State.Model
    if (-not $caps.SupportsBackground) {
        Add-TuiMessage -State $State -Text (T 'tui.msg.background_unsupported') -Kind 'Warning'
        return
    }

    $valid = @('auto','opaque','transparent')
    if ($valid -notcontains $Value) {
        Add-TuiMessage -State $State -Text (T 'tui.msg.background_invalid') -Kind 'Error'
        return
    }

    $State.Background = $Value
    Add-TuiMessage -State $State -Text (T 'tui.msg.background_set' $Value) -Kind 'Success'
}

# TUI command: sets the mask path for inpainting.
function Set-TuiMask {
    param($State, [string]$Value)

    if ([string]::IsNullOrWhiteSpace($Value)) {
        Add-TuiMessage -State $State -Text (T 'tui.msg.mask_specify') -Kind 'Warning'
        return
    }

    try {
        $cleanPath = Remove-TuiPathQuotes -Text $Value
        if (-not (Test-Path -LiteralPath $cleanPath -PathType Leaf -ErrorAction SilentlyContinue)) {
            Add-TuiMessage -State $State -Text (T 'tui.msg.mask_notfound') -Kind 'Error'
            return
        }

        $resolved = (Resolve-Path -LiteralPath $cleanPath -ErrorAction Stop).Path
        $State.MaskPath = $resolved
        Add-TuiMessage -State $State -Text (T 'tui.msg.mask_loaded' $resolved) -Kind 'Info'
    }
    catch {
        Add-TuiMessage -State $State -Text (T 'tui.error.mask_load' $_.Exception.Message) -Kind 'Error'
    }
}

# TUI command: sets the reference images for edit mode.
function Set-TuiInputImages {
    param($State, [string]$Value)

    if ([string]::IsNullOrWhiteSpace($Value)) {
        Add-TuiMessage -State $State -Text (T 'tui.msg.inputimages_specify') -Kind 'Warning'
        return
    }

    Initialize-TuiListState -State $State
    $State.InputImages.Clear()

    $items = @($Value.Split(',', [System.StringSplitOptions]::RemoveEmptyEntries) | ForEach-Object { (Remove-TuiPathQuotes -Text $_.Trim()) } | Where-Object { $_ })

    foreach ($item in $items) {
        if (-not (Test-Path -LiteralPath $item -PathType Leaf -ErrorAction SilentlyContinue)) {
            Add-TuiMessage -State $State -Text ("Input image file not found: $item") -Kind 'Error'
            $State.InputImages.Clear()
            return
        }

        $resolved = (Resolve-Path -LiteralPath $item -ErrorAction Stop).Path
        [void]$State.InputImages.Add($resolved)
    }

    Add-TuiMessage -State $State -Text ("Aggiunte {0} immagini di input." -f $State.InputImages.Count) -Kind 'Success'
    foreach ($img in @($State.InputImages)) {
        Add-TuiMessage -State $State -Text $img -Kind 'Info'
    }
}

# TUI command: sets the output folder.
function Set-TuiOutputFolder {
    param($State, [string]$Value)

    if ([string]::IsNullOrWhiteSpace($Value)) {
        Add-TuiMessage -State $State -Text (T 'tui.msg.outputfolder_specify') -Kind 'Warning'
        return
    }

    try {
        $cleanPath = Remove-TuiPathQuotes -Text $Value
        if (-not (Test-Path -LiteralPath $cleanPath)) {
            New-Item -ItemType Directory -Path $cleanPath -Force | Out-Null
        }
        $resolved = (Resolve-Path -LiteralPath $cleanPath).Path
        $State.OutputFolder = $resolved
        Add-TuiMessage -State $State -Text (T 'tui.msg.outputfolder_set' $resolved) -Kind 'Success'
    }
    catch {
        Add-TuiMessage -State $State -Text (T 'tui.error.outputfolder' $_.Exception.Message) -Kind 'Error'
    }
}

# TUI command: sets the output mode (file or base64).
function Set-TuiOutputMode {
    param($State, [string]$Value)

    $valid = @('file', 'base64')
    $v = $Value.ToLowerInvariant()
    if ($valid -notcontains $v) {
        Add-TuiMessage -State $State -Text (T 'tui.msg.outputmode_invalid') -Kind 'Error'
        return
    }
    $State.OutputMode = $v
    Add-TuiMessage -State $State -Text (T 'tui.msg.outputmode_set' $v) -Kind 'Success'
}

function Set-TuiBudget {
    param($State, [string]$Value)

    # Without a value or "off"/"none"/"0" it removes the cost limit.
    if ([string]::IsNullOrWhiteSpace($Value) -or @('off', 'none', '0') -contains $Value.ToLowerInvariant()) {
        $State.Budget = $null
        Add-TuiMessage -State $State -Text (T 'tui.msg.budget_cleared') -Kind 'Success'
        return
    }

    # It accepts both comma and point as the decimal separator.
    $parsed = 0.0
    $normalized = $Value.Replace(',', '.')
    $ok = [double]::TryParse($normalized, [System.Globalization.NumberStyles]::Float, [System.Globalization.CultureInfo]::InvariantCulture, [ref]$parsed)
    if (-not $ok -or $parsed -le 0) {
        Add-TuiMessage -State $State -Text (T 'tui.msg.budget_invalid') -Kind 'Error'
        return
    }
    $State.Budget = $parsed
    Add-TuiMessage -State $State -Text (T 'tui.msg.budget_set' ("{0:N4} {1}" -f $parsed, $State.Currency)) -Kind 'Success'
}

# TUI command: changes the color theme at runtime and reapplies the palette.
function Set-TuiTheme {
    param($State, $Config, [string]$Value)

    if ([string]::IsNullOrWhiteSpace($Value)) {
        $available = @($Config.tui.themes.PSObject.Properties.Name)
        Add-TuiMessage -State $State -Text (T 'tui.preview.themes_available' ($available -join ', ')) -Kind 'Info'
        return
    }

    $match = @($Config.tui.themes.PSObject.Properties | Where-Object { $_.Name -ieq $Value }) | Select-Object -First 1
    if ($null -eq $match) {
        $available = @($Config.tui.themes.PSObject.Properties.Name)
        Add-TuiMessage -State $State -Text (T 'tui.preview.theme_invalid' ($available -join ', ')) -Kind 'Error'
        return
    }

    $State.Theme = $match.Name
    Set-TuiColors -State $State -Config $Config
    Add-TuiMessage -State $State -Text (T 'tui.msg.theme_set' $match.Name) -Kind 'Success'
}

