# Resets the TUI parameters to the config's default values.
# TUI command /reload: re-reads the .conf file from disk and updates the session
# configuration WITHOUT closing the TUI. Useful after manually editing the .conf
# (e.g. timeoutSec or maxCompletionTokens of the textModel) while the TUI is open.
# Delicate point: $Config is passed by reference, so I UPDATE its properties
# in-place instead of reassigning the variable (the reassignment would stay local and
# would not propagate to the other functions that already hold the reference). If the
# file is absent or the JSON is malformed, I warn and leave the current config intact.
function Set-TuiReloadConfig {
    param($State, $Config)

    if (-not (Test-Path $script:ConfigFile)) {
        Add-TuiMessage -State $State -Text (T 'tui.msg.reload_notfound' $script:ConfigFile) -Kind 'Error'
        return
    }
    try {
        $fresh = (Get-Content $script:ConfigFile -Raw -Encoding UTF8 -ErrorAction Stop) | ConvertFrom-Json -ErrorAction Stop
    } catch {
        Add-TuiMessage -State $State -Text (T 'tui.msg.reload_badjson' $_.Exception.Message) -Kind 'Error'
        return
    }

    # I update in-place: I overwrite/add every property of the re-read file onto the
    # existing $Config, so the shared reference sees the new values.
    foreach ($prop in $fresh.PSObject.Properties) {
        if ($prop.Name -eq '_resolvedConfigPath') { continue }
        $Config | Add-Member -NotePropertyName $prop.Name -NotePropertyValue $prop.Value -Force
    }

    Add-TuiMessage -State $State -Text (T 'tui.msg.reload_done') -Kind 'Success'
    # Summary of the two most relevant parameters for whoever reloads (usually they touch them).
    if ($Config.textModel) {
        $tmo = if ($Config.textModel.timeoutSec) { [string]$Config.textModel.timeoutSec } else { '600' }
        $tok = if ($Config.textModel.maxCompletionTokens) { [string]$Config.textModel.maxCompletionTokens } else { '4096' }
        Add-TuiMessage -State $State -Text (T 'tui.msg.reload_textmodel' $tmo $tok) -Kind 'Info'
    }
}

function Reset-TuiState {
    param($State, $Config)

    $oldCurrency = $State.Currency
    $oldTheme = $State.Theme
    $fresh = New-TuiState -Config $Config

    foreach ($prop in $fresh.PSObject.Properties) {
        $State | Add-Member -NotePropertyName $prop.Name -NotePropertyValue $prop.Value -Force
    }

    if ($oldCurrency) { $State.Currency = $oldCurrency }
    if ($oldTheme) { $State.Theme = $oldTheme }

    Initialize-TuiListState -State $State
    Set-TuiColors -State $State -Config $Config
    Add-TuiMessage -State $State -Text (T 'tui.msg.reset') -Kind 'Success'
}

# Converts a USD cost to the local currency (EUR) using the current exchange rate.
function Get-TuiLocalCost {
    param([double]$UsdCost, $Config, $State)
    $currency = [string]$State.Currency
    if ($currency -eq 'EUR') {
        $rate = if ($Config.usdToEurRate) { [double]$Config.usdToEurRate } else { 0.92 }
        return [Math]::Round($UsdCost * $rate, 4)
    }
    return [Math]::Round($UsdCost, 4)
}

function Resolve-TuiGenerationContext {
    <#
    Risolve tutti i parametri "tecnici" richiesti da Invoke-ImageGeneration a
    partire dallo stato TUI e dal config, per il modello CORRENTE ($State.Model).
    Replica la risoluzione del flusso CLI (modelConfig, apikey, schema, pricing,
    flag apply*) SENZA toccarlo, cosi' il percorso a riga di comando resta intatto.
    Ritorna un PSCustomObject con Ok (bool), Error (string) e i parametri risolti.
    #>
    param($State, $Config)

    $ctx = [ordered]@{ Ok = $false; Error = $null }

    $modelName = [string]$State.Model
    if ([string]::IsNullOrWhiteSpace($modelName)) {
        $ctx.Error = (T 'tui.msg.model_specify'); return [pscustomobject]$ctx
    }
    $mc = $Config.models.$modelName
    if ($null -eq $mc -or
        (-not $mc.endpoint -or $mc.endpoint.Trim() -eq "") -or
        (-not $mc.apiKey   -or $mc.apiKey.Trim()   -eq "")) {
        $ctx.Error = (T 'tui.error.resolve' $modelName); return [pscustomobject]$ctx
    }
    $apiKey = Unprotect-ApiKey -EncodedValue $mc.apiKey
    if (-not $apiKey) {
        $ctx.Error = (T 'tui.error.resolve' $modelName); return [pscustomobject]$ctx
    }

    # supports* from the model (conservative defaults if absent)
    $supportsInputFidelity = if ($null -ne $mc.supportsInputFidelity) { [bool]$mc.supportsInputFidelity } else { $false }
    $supportsBackground    = if ($null -ne $mc.supportsBackground)    { [bool]$mc.supportsBackground }    else { $false }

    $apiSchema = if ($mc.apiSchema -and $mc.apiSchema.Trim() -ne "") { $mc.apiSchema.Trim() } else { "openai-images" }
    $authMode  = if ($mc.authMode  -and $mc.authMode.Trim()  -ne "") { $mc.authMode.Trim().ToLower() } else { "" }

    # Pricing: same logic as the CLI flow (AOAI labeled / MAI columnar meters +
    # safety net for the old flat fields pre-migration).
    $modelPricing   = $mc.pricing
    $priceInputUsd  = 0.0
    $priceOutputUsd = 0.0
    $priceImageUsd  = 0.0
    if ($modelPricing -and ($modelPricing.PSObject.Properties.Name -contains 'meters') -and $modelPricing.meters) {
        $m = $modelPricing.meters
        if ($m.PSObject.Properties.Name -contains 'inputText'   -and $null -ne $m.inputText)   { $priceInputUsd  = [double]$m.inputText }
        if ($m.PSObject.Properties.Name -contains 'outputText'  -and $null -ne $m.outputText)  { $priceOutputUsd = [double]$m.outputText }
        if ($m.PSObject.Properties.Name -contains 'outputImage' -and $null -ne $m.outputImage) { $priceImageUsd  = [double]$m.outputImage }
        if ($m.PSObject.Properties.Name -contains 'input'  -and $null -ne $m.input)  { $priceInputUsd  = [double]$m.input }
        if ($m.PSObject.Properties.Name -contains 'output' -and $null -ne $m.output) {
            $priceOutputUsd = [double]$m.output
            if ($priceImageUsd -eq 0.0) { $priceImageUsd = [double]$m.output }
        }
    }
    if ($priceInputUsd -eq 0.0 -and $priceOutputUsd -eq 0.0 -and $priceImageUsd -eq 0.0 -and $modelPricing) {
        if ($modelPricing.PSObject.Properties.Name -contains 'inputTokensPerMillionUsd'  -and $null -ne $modelPricing.inputTokensPerMillionUsd)  { $priceInputUsd  = [double]$modelPricing.inputTokensPerMillionUsd }
        if ($modelPricing.PSObject.Properties.Name -contains 'outputTokensPerMillionUsd' -and $null -ne $modelPricing.outputTokensPerMillionUsd) { $priceOutputUsd = [double]$modelPricing.outputTokensPerMillionUsd }
        if ($modelPricing.PSObject.Properties.Name -contains 'imageTokensPerMillionUsd'  -and $null -ne $modelPricing.imageTokensPerMillionUsd)  { $priceImageUsd  = [double]$modelPricing.imageTokensPerMillionUsd }
    }

    # apply* flags (like the CLI flow): moderation only for openai-images; background
    # only if different from auto and supported; input fidelity only if set and supported.
    $supportsModeration = ($apiSchema -eq "openai-images")
    $applyModeration    = $supportsModeration
    $applyBackground    = ($supportsBackground -and $State.Background -and $State.Background -ne "auto")
    $applyInputFidelity = ($supportsInputFidelity -and $State.InputFidelity -and ([string]$State.InputFidelity).Trim() -ne "")

    # Config-level values (independent of the model). No network refresh: I use the
    # values already present in the config (loaded at startup).
    $maxRetries   = if ($Config.maxRetries) { [int]$Config.maxRetries } else { 3 }
    $timeoutMin   = if ($Config.requestTimeoutMinutes -and [int]$Config.requestTimeoutMinutes -gt 0) { [int]$Config.requestTimeoutMinutes } else { 10 }
    $compression  = if ($null -ne $Config.defaultOutputCompression) { [int]$Config.defaultOutputCompression } else { 100 }
    $eurRate      = if ($null -ne $Config.usdToEurRate -and [double]$Config.usdToEurRate -gt 0) { [double]$Config.usdToEurRate } else { 0.92 }
    $currency     = if ([string]::IsNullOrWhiteSpace([string]$State.Currency)) { "USD" } else { [string]$State.Currency }

    $inputImages = @($State.InputImages)
    $isEditMode  = ($inputImages -and $inputImages.Count -gt 0)
    $foEndpoint     = if ($mc.failoverEndpoint)     { $mc.failoverEndpoint }     else { "" }
    $foEditEndpoint = if ($mc.failoverEditEndpoint) { $mc.failoverEditEndpoint } else { "" }

    $ctx.Ok                  = $true
    $ctx.ModelLogicalName    = $modelName
    $ctx.Deployment          = $mc.deployment
    $ctx.Endpoint            = $mc.endpoint
    $ctx.EditEndpoint        = $mc.editEndpoint
    $ctx.FailoverEndpoint    = $foEndpoint
    $ctx.FailoverEditEndpoint= $foEditEndpoint
    $ctx.ApiKey              = $apiKey
    $ctx.ApiSchema           = $apiSchema
    $ctx.AuthMode            = $authMode
    $ctx.ApplyBackground     = [bool]$applyBackground
    $ctx.ApplyInputFidelity  = [bool]$applyInputFidelity
    $ctx.ApplyModeration     = [bool]$applyModeration
    $ctx.PriceInputUsd       = $priceInputUsd
    $ctx.PriceOutputUsd      = $priceOutputUsd
    $ctx.PriceImageUsd       = $priceImageUsd
    $ctx.ModelPricing        = $modelPricing
    $ctx.OperationalParams   = $mc.operationalParams
    $ctx.MaxRetries          = $maxRetries
    $ctx.TimeoutMinutes      = $timeoutMin
    $ctx.FileTemplate        = $Config.fileNameTemplate
    $ctx.Compression         = $compression
    $ctx.EurRate             = $eurRate
    $ctx.Currency            = $currency
    $ctx.IsEditMode          = $isEditMode
    $ctx.ModeKey             = if ($isEditMode) { "edit" } else { "generation" }
    return [pscustomobject]$ctx
}

function Invoke-TuiGenerateAdapter {
    <#
    Generazione REALE per la TUI. Risolve i parametri tecnici per il modello
    corrente, applica il budget guardrail, invoca il motore Invoke-ImageGeneration
    con un callback che aggiorna la barra di avanzamento (la stessa logica "a tempo"
    della CLI), registra le statistiche [TIME]/[COST] e mappa il risultato sul
    contratto atteso da Start-TuiGenerate (Success/Message/Files/CostUsd/CostLocal).
    #>
    param($Request, $Config, $State)

    # (1) Resolution of the technical parameters for the current model
    $ctx = Resolve-TuiGenerationContext -State $State -Config $Config
    if (-not $ctx.Ok) {
        return [pscustomobject]@{ Success = $false; Message = $ctx.Error; Files = @(); CostUsd = 0; CostLocal = 0 }
    }

    # (1b) Preemptive downscaling of the size: if too large for the current model,
    # I reduce it before estimating cost/time and generating. I update $Request.Size
    # only once so all subsequent uses (estimate, generation, telemetry) are
    # consistent. In TUI it does not exit: it reduces and proceeds, signaling with a message.
    if ($ctx.OperationalParams) {
        $tuiDownscaled = Invoke-PreemptiveSizeDownscale -OpParams $ctx.OperationalParams -ModelName $ctx.ModelLogicalName -Size ([string]$Request.Size)
        if ($tuiDownscaled -and $tuiDownscaled -ine [string]$Request.Size) {
            Add-TuiMessage -State $State -Text (T 'request.size_downscale' $ctx.ModelLogicalName ([string]$Request.Size) $tuiDownscaled) -Kind 'Warning'
            if ($Request.PSObject.Properties.Name -contains 'Size') { $Request.Size = $tuiDownscaled }
        }
    }

    # (2) Time estimate (feeds the bar) and size parse
    $parts = ([string]$Request.Size) -split 'x'
    $reqWidth  = if ($parts.Count -ge 2) { [int]$parts[0] } else { 1024 }
    $reqHeight = if ($parts.Count -ge 2) { [int]$parts[1] } else { 1024 }
    $inputImagesCount = @($Request.InputImages).Count
    $promptLen = ([string]$Request.Prompt).Length
    $candidate = @{
        size_pixels        = $reqWidth * $reqHeight
        size_bucket        = (Get-SizeBucket -Width $reqWidth -Height $reqHeight)
        quality_score      = (Get-QualityScore $Request.Quality)
        n_images           = [int]$Request.NImages
        input_images_count = $inputImagesCount
        prompt_len         = $promptLen
        hour_of_day        = (Get-Date).Hour
    }
    $estimate = Get-TimeEstimate -Candidate $candidate -ModeKey $ctx.ModeKey -ModelName $ctx.ModelLogicalName
    $estimatedTotal = [int]$estimate.estimated_single

    # (3) Budget guardrail: in TUI it does not exit, it cancels with a message
    if ($null -ne $Request.Budget) {
        $costEstimate = Get-EstimatedCost -Prompt $Request.Prompt -NImages ([int]$Request.NImages) `
                                          -InputImagesCount $inputImagesCount `
                                          -Quality $Request.Quality -Size $Request.Size `
                                          -PriceInputUsd $ctx.PriceInputUsd -PriceOutputUsd $ctx.PriceOutputUsd `
                                          -PriceImageUsd $ctx.PriceImageUsd -Pricing $ctx.ModelPricing `
                                          -EurRate $ctx.EurRate
        $budgetOk = Test-BudgetGuardrail -Budget $Request.Budget -Currency $ctx.Currency -Estimate $costEstimate
        if (-not $budgetOk) {
            return [pscustomobject]@{ Success = $false; Message = (T 'tui.msg.budget_exceeded'); Files = @(); CostUsd = 0; CostLocal = 0 }
        }
    }

    # (4) Guaranteed output folder
    if (-not [string]::IsNullOrWhiteSpace([string]$Request.OutputFolder) -and -not (Test-Path -LiteralPath $Request.OutputFolder)) {
        New-Item -ItemType Directory -Path $Request.OutputFolder -Force | Out-Null
    }

    # (5) Progress callback: reuses the CLI's "timed" bar by redrawing the TUI.
    #    NB: the scriptblock does NOT use GetNewClosure: that would isolate the scope making
    #    the script's functions (T, Show-Tui) invisible. State and Config are
    #    passed via script-scoped variables, read inside the callback; this way the
    #    functions stay accessible and the State object is updated by reference.
    $script:TuiProgressState  = $State
    $script:TuiProgressConfig = $Config
    $progressCb = {
        param($pct, $img, $n, $elapsedSec, $estTotal)
        $script:TuiProgressState.ProgressPercent = [int]$pct
        $script:TuiProgressState.ProgressLabel   = (T 'tui.progress.detail' $img $n $elapsedSec $estTotal)
        Update-TuiProgressBars -State $script:TuiProgressState -Config $script:TuiProgressConfig
    }

    # (5b) Prompt functions (optimize/negative) if active in the TUI state. They use the
    # same functions as the CLI flow; a failure does not block the generation.
    if ($State.OptimizePrompt -or $State.NegativePrompt) {
        if (-not (Test-TuiTextModelReady)) {
            Add-TuiMessage -State $State -Text (T 'tui.msg.textmodel_missing') -Kind 'Warning'
        } else {
            if ($State.OptimizePrompt) {
                Add-TuiMessage -State $State -Text (T 'tui.msg.optimizing') -Kind 'Info'
                Show-Tui -State $State -Config $Config
                $opt = Invoke-TextModelPromptRewrite -Prompt $Request.Prompt -Config $Config
                if ($opt -and $opt.Text) {
                    $Request.Prompt = $opt.Text
                    # Text cost of the operation (like the CLI flow): [COST] line
                    # operation=optimize + telemetry. Normal verbosity to show it in TUI.
                    if (([int]$opt.InputTokens + [int]$opt.OutputTokens) -gt 0) {
                        $tc = Write-TextCostLog -InputTokens ([int]$opt.InputTokens) -OutputTokens ([int]$opt.OutputTokens) `
                                -Config $Config -Operation "optimize" -Verbosity "ultrasilent" -DefaultCurrency ([string]$Config.defaultCurrency)
                        if ($tc) { Send-TextCostTelemetry -Config $Config -TextCost $tc -TextModel ([string]$Config.textModel.model) }
                    }
                }
            }
            if ($State.NegativePrompt) {
                Add-TuiMessage -State $State -Text (T 'tui.msg.negating') -Kind 'Info'
                Show-Tui -State $State -Config $Config
                $neg = Invoke-TextModelNegative -Prompt $Request.Prompt -Config $Config
                if ($neg -and $neg.Text) {
                    $Request.Prompt = $Request.Prompt + "`n`nAvoid: " + $neg.Text
                    if (([int]$neg.InputTokens + [int]$neg.OutputTokens) -gt 0) {
                        $tc = Write-TextCostLog -InputTokens ([int]$neg.InputTokens) -OutputTokens ([int]$neg.OutputTokens) `
                                -Config $Config -Operation "negative" -Verbosity "ultrasilent" -DefaultCurrency ([string]$Config.defaultCurrency)
                        if ($tc) { Send-TextCostTelemetry -Config $Config -TextCost $tc -TextModel ([string]$Config.textModel.model) }
                    }
                }
            }
        }
    }

    # (6) Generazione vera (in-process). Sopprimo eventuali Write-Progress residui.
    $promptHash = (Get-FileHash -InputStream ([IO.MemoryStream]::new([Text.Encoding]::UTF8.GetBytes([string]$Request.Prompt))) -Algorithm SHA256).Hash.Substring(0, 8)
    $inputImagesArr = @($Request.InputImages)
    $prevProgress = $ProgressPreference
    $ProgressPreference = 'SilentlyContinue'
    try {
        $result = Invoke-ImageGeneration `
            -Prompt $Request.Prompt -Size $Request.Size -Quality $Request.Quality -Format $Request.Format -NImages ([int]$Request.NImages) `
            -Moderation $Request.Moderation -Background $Request.Background -InputFidelity $Request.InputFidelity -Mask $Request.Mask `
            -InputImages $inputImagesArr -OutputFolder $Request.OutputFolder -OutputMode $Request.OutputMode `
            -ModelName $ctx.ModelLogicalName -Deployment $ctx.Deployment `
            -ApiSchema $ctx.ApiSchema -AuthMode $ctx.AuthMode `
            -Endpoint $ctx.Endpoint -EditEndpoint $ctx.EditEndpoint `
            -FailoverEndpoint $ctx.FailoverEndpoint -FailoverEditEndpoint $ctx.FailoverEditEndpoint `
            -ApiKey $ctx.ApiKey `
            -MaxRetries $ctx.MaxRetries -TimeoutMinutes $ctx.TimeoutMinutes `
            -ApplyBackground $ctx.ApplyBackground -ApplyInputFidelity $ctx.ApplyInputFidelity `
            -ApplyModeration $ctx.ApplyModeration `
            -UseMetadata ([bool]$Request.Metadata) -InputImagesOriginal $inputImagesArr `
            -FileTemplate $ctx.FileTemplate -Hash $promptHash -Compression $ctx.Compression `
            -PriceInputUsd $ctx.PriceInputUsd -PriceOutputUsd $ctx.PriceOutputUsd `
            -PriceImageUsd $ctx.PriceImageUsd -Pricing $ctx.ModelPricing `
            -EurRate $ctx.EurRate `
            -EstimatedTotal $estimatedTotal `
            -OperationalParams $ctx.OperationalParams `
            -ProgressCallback $progressCb
    }
    finally {
        $ProgressPreference = $prevProgress
        $script:TuiProgressState  = $null
        $script:TuiProgressConfig = $null
    }

    if (-not $result.Success) {
        return [pscustomobject]@{ Success = $false; Message = $result.Error; Files = @(); CostUsd = 0; CostLocal = 0 }
    }

    # (7) Costs + statistics [COST]/[TIME], like the CLI flow
    $costUsd = 0.0
    $costLocal = 0.0
    if ($result.Cost) {
        $costUsd = [double]$result.Cost.total_cost_usd
        $costLocal = if ($ctx.Currency -eq 'EUR') { [double]$result.Cost.total_cost_eur } else { $costUsd }
        Write-CostLog -Cost $result.Cost -Model $ctx.ModelLogicalName -HasPricingSection ($null -ne $ctx.ModelPricing) -NImages ([int]$Request.NImages)
        Add-DailyCostRecord -Cost $result.Cost
    }
    if ($result.StartTime -and $result.ActualDurationSec) {
        $endAttempt = $result.StartTime.AddSeconds($result.ActualDurationSec)
        $timeRecord = [ordered]@{
            date               = $result.StartTime.ToString("yyyy-MM-dd", [System.Globalization.CultureInfo]::InvariantCulture)
            start              = $result.StartTime.ToString("HH:mm:ss")
            end                = $endAttempt.ToString("HH:mm:ss")
            estimated          = [int]$estimatedTotal
            actual             = [int]$result.ActualDurationSec
            model              = $ctx.ModelLogicalName
            deployment         = $ctx.Deployment
            mode               = $ctx.ModeKey
            prompt_len         = [int]$promptLen
            size               = $Request.Size
            format             = $Request.Format
            quality            = $Request.Quality
            n_images           = [int]$Request.NImages
            input_images_count = [int]$inputImagesCount
            attempts           = [int]$result.Attempts
        }
        Add-TimeStatRecord -Record $timeRecord
    }

    # Telemetry (source="tui"): the TUI generates in-process, so I send the metrics here
    # with the shared function. Duration = real duration of the generation from the engine.
    $tuiDuration = if ($result.ActualDurationSec) { [double]$result.ActualDurationSec } else { 0 }
    Send-GenerationTelemetry -Config $Config -Cost $result.Cost `
        -DurationSec $tuiDuration -Model $ctx.ModelLogicalName `
        -Size $Request.Size -Quality $Request.Quality -NImages ([int]$Request.NImages) -Source "tui"

    return [pscustomobject]@{
        Success   = $true
        Message   = 'OK'
        Files     = @($result.ImagesPaths)
        CostUsd   = $costUsd
        CostLocal = $costLocal
    }
}


# Runs the storyboard from the TUI delegating to the main script as a sub-process
# (same pattern as the parallel batch): the storyboard has a dedicated multi-image
# logic that makes no sense to duplicate here. It shows the outcome in the TUI messages.
function Invoke-TuiStoryboard {
    param($State, $Config)

    Add-TuiMessage -State $State -Text (T 'tui.msg.storyboard_running' ([string]$State.SequenceImages)) -Kind 'Info'
    Show-Tui -State $State -Config $Config

    $sbArgs = @(
        '-Prompt', $State.PromptText
        '-Storyboard'
        '-SequenceImages', [string]$State.SequenceImages
        '-Verbosity', 'silent'
    )
    if ($State.Model)        { $sbArgs += @('-Model', $State.Model) }
    if ($State.Size)         { $sbArgs += @('-Size', $State.Size) }
    if ($State.Quality)      { $sbArgs += @('-Quality', $State.Quality) }
    if ($State.Format)       { $sbArgs += @('-Format', $State.Format) }
    if ($State.OutputFolder) { $sbArgs += @('-OutputFolder', $State.OutputFolder) }
    if ($State.Optimize -or $State.OptimizePrompt) { $sbArgs += '-OptimizePrompt' }
    if ($State.NegativePrompt) { $sbArgs += '-NegativePrompt' }

    try {
        & pwsh -NoProfile -ExecutionPolicy Bypass -File $PSCommandPath @sbArgs | Out-Null
        if ($LASTEXITCODE -eq 0) {
            Add-TuiMessage -State $State -Text (T 'tui.msg.storyboard_done') -Kind 'Success'
        } else {
            Add-TuiMessage -State $State -Text (T 'tui.msg.storyboard_error' ([string]$LASTEXITCODE)) -Kind 'Error'
        }
    } catch {
        Add-TuiMessage -State $State -Text (T 'tui.error.generation' $_.Exception.Message) -Kind 'Error'
    }
}

# Logs (file-only) the summary of a generation started from the TUI: command, model,
# generation parameters and active options (optimize/negative/storyboard). The prompt is
# logged separately with Write-PromptLog, which applies the privacy. This way in the .log the
# interactive session is reconstructable like a normal CLI invocation.
function Write-TuiGenerateLog {
    param($State, $Config)
    if (-not $script:LogFile) { return }
    # Parameter summary (in clear: they are not sensitive data). The boolean options
    # are included only if active, to keep the line compact.
    $opts = @()
    if ($State.OptimizePrompt) { $opts += "Optimize" }
    if ($State.NegativePrompt) { $opts += "Negative" }
    if ($State.Storyboard)     { $opts += ("Storyboard(" + [int]$State.SequenceImages + ")") }
    $optsStr = if ($opts.Count -gt 0) { $opts -join "+" } else { (T 'tui.log_gen_noopts') }
    $summary = T 'tui.log_generate' ([string]$State.Model) ([string]$State.Size) ([string]$State.Quality) ([int]$State.NImages) ([string]$State.Format) $optsStr
    $ts = (Get-Date).ToString("yyyy-MM-dd HH:mm:ss", [System.Globalization.CultureInfo]::InvariantCulture)
    Add-Content -Path $script:LogFile -Value (Protect-LogFileLine "[$ts] [INFO] $summary") -Encoding UTF8 -ErrorAction SilentlyContinue
    # The typed prompt: respects privacy.imagePrompts (obfuscated if active). It uses
    # the standard helper so it is consistent with the rest of the log ([PROMPT] level).
    Write-PromptLog -LabelKey 'prompt.label_original' -PromptText ([string]$State.PromptText) -Kind "image" -Config $Config
}

# Starts the generation from the TUI: prepares the state, shows the progress and records outcome/costs/times.
function Start-TuiGenerate {
    param($State, $Config)

    if ([string]::IsNullOrWhiteSpace($State.PromptText)) {
        Add-TuiMessage -State $State -Text (T 'tui.msg.prompt_none') -Kind 'Warning'
        return
    }

    # TUI generation log: summary of the active parameters (file-only), so in the
    # .log one sees exactly what was generated and with which settings. The
    # prompt is logged separately via Write-PromptLog (respects privacy.imagePrompts).
    Write-TuiGenerateLog -State $State -Config $Config

    # Storyboard: it is a multi-image mode with dedicated logic (narrative
    # decomposition + N generations). I delegate it to the script as a sub-process, which
    # handles it end-to-end, instead of duplicating its logic in the TUI adapter.
    if ($State.Storyboard) {
        Invoke-TuiStoryboard -State $State -Config $Config
        return
    }

    $request = [ordered]@{
        Prompt         = $State.PromptText
        PromptSource   = $State.PromptSource
        PromptFilePath = $State.PromptFilePath
        Model          = $State.Model
        Auto           = $State.Auto
        NImages        = $State.NImages
        Size           = $State.Size
        Quality        = $State.Quality
        Format         = $State.Format
        Moderation     = $State.Moderation
        InputFidelity  = $State.InputFidelity
        Metadata       = $State.Metadata
        Background     = $State.Background
        Mask           = $State.MaskPath
        InputImages    = @($State.InputImages)
        OutputFolder   = $State.OutputFolder
        OutputMode     = $State.OutputMode
        Budget         = $State.Budget
    }

    Add-TuiMessage -State $State -Text (T 'tui.msg.generate_started') -Kind 'Info'
    $State.ProgressActive = $true
    $State.ProgressPercent = 0
    $State.ProgressLabel = (T 'tui.progress.generating')
    Show-Tui -State $State -Config $Config

    try {
        $result = Invoke-TuiGenerateAdapter -Request $request -Config $Config -State $State
        $State.ProgressPercent = 100
        $State.ProgressActive = $false
        $State.ProgressLabel = ''

        if ($result.Success) {
            $State.LastGeneratedFiles.Clear()
            foreach ($f in @($result.Files)) { [void]$State.LastGeneratedFiles.Add($f) }
            $State.SessionCostUsd += [double]$result.CostUsd
            $State.SessionCostLocal += [double]$result.CostLocal
            Add-TuiMessage -State $State -Text (T 'tui.msg.image_ok') -Kind 'Success'
            foreach ($file in @($result.Files)) {
                Add-TuiMessage -State $State -Text $file -Kind 'Info'
            }
        }
        else {
            Add-TuiMessage -State $State -Text $result.Message -Kind 'Error'
        }
    }
    catch {
        $State.ProgressActive = $false
        $State.ProgressLabel = ''
        Add-TuiMessage -State $State -Text (T 'tui.error.generation' $_.Exception.Message) -Kind 'Error'
    }
}

# Logs to the file (.log) a command typed in the TUI, file-only and never on screen, so
# the interactive session stays reconstructable by reading the log. Normal paths and arguments
# are in clear; the commands that do NOT carry prompt content are logged as
# they are. The /prompt command opens the editor (the text does not pass here): I log only
# the opening. The /generate has its own dedicated summary apart (Write-TuiGenerateLog),
# so here I omit it so as not to duplicate.
function Write-TuiCommandLog {
    param([string]$Command, [string]$Argument = "", $Config = $null)
    if (-not $script:LogFile) { return }
    if ($Command -eq '/generate') { return }   # riepilogo dedicato altrove
    $line = if ($Command -eq '/prompt') {
        T 'tui.log_prompt_editor'
    } elseif ($Argument -ne '') {
        (T 'tui.log_command' $Command $Argument)
    } else {
        (T 'tui.log_command_noarg' $Command)
    }
    $ts = (Get-Date).ToString("yyyy-MM-dd HH:mm:ss", [System.Globalization.CultureInfo]::InvariantCulture)
    Add-Content -Path $script:LogFile -Value (Protect-LogFileLine "[$ts] [INFO] $line") -Encoding UTF8 -ErrorAction SilentlyContinue
}

# TUI command dispatcher: interprets the typed line and routes to the corresponding setter/action.
function Invoke-TuiCommand {
    param(
        [string]$CommandLine,
        $State,
        $Config
    )

    if ([string]::IsNullOrWhiteSpace($CommandLine)) {
        return
    }

    if ($CommandLine[0] -ne '/') {
        Add-TuiMessage -State $State -Text (T 'tui.msg.command_invalid') -Kind 'Error'
        return
    }

    $parts = $CommandLine.Split(' ', 2, [System.StringSplitOptions]::RemoveEmptyEntries)
    $cmd = $parts[0].ToLowerInvariant()
    $arg = if ($parts.Count -gt 1) { $parts[1].Trim() } else { '' }

    # TUI command log to the file (.log), file-only and never on screen, so the
    # interactive session is reconstructable afterwards. Normal paths and arguments are
    # logged in clear; the PROMPTs are handled separately (with possible privacy
    # obfuscation) at the moment they are set/used, not here. The /prompt command
    # opens the editor and the text does not transit through this point, so here I log only that
    # the editor was opened.
    Write-TuiCommandLog -Command $cmd -Argument $arg -Config $Config

    switch ($cmd) {
        '/prompt'         { Open-TuiPromptEditor -State $State; return }
        '/promptfile'     { Set-TuiPromptFile -State $State -Path $arg; return }
        '/model'          { Set-TuiModel -State $State -Config $Config -Value $arg; return }
        '/auto'           { Set-TuiAuto -State $State -Value $arg; return }
        '/nimages'        { Set-TuiNImages -State $State -Value $arg; return }
        '/size'           { Set-TuiSize -State $State -Value $arg; return }
        '/quality'        { Set-TuiQuality -State $State -Value $arg; return }
        '/format'         { Set-TuiFormat -State $State -Value $arg; return }
        '/moderation'     { Set-TuiModeration -State $State -Value $arg; return }
        '/inputfidelity'  { Set-TuiInputFidelity -State $State -Config $Config -Value $arg; return }
        '/metadata'       { Set-TuiMetadata -State $State -Value $arg; return }
        '/background'     { Set-TuiBackground -State $State -Config $Config -Value $arg; return }
        '/mask'           { Set-TuiMask -State $State -Value $arg; return }
        '/inputimages'    { Set-TuiInputImages -State $State -Value $arg; return }
        '/outputfolder'   { Set-TuiOutputFolder -State $State -Value $arg; return }
        '/outputmode'     { Set-TuiOutputMode -State $State -Value $arg; return }
        '/budget'         { Set-TuiBudget -State $State -Value $arg; return }
        '/optimize'       { Set-TuiOptimize -State $State -Value $arg; return }
        '/negative'       { Set-TuiNegative -State $State -Value $arg; return }
        '/storyboard'     { Set-TuiStoryboard -State $State -Value $arg; return }
        '/sequenceimages' { Set-TuiSequenceImages -State $State -Value $arg; return }
        '/theme'          { Set-TuiTheme -State $State -Config $Config -Value $arg; return }
        '/generate'       { Start-TuiGenerate -State $State -Config $Config; return }
        '/clear'          {
            Initialize-TuiListState -State $State
            $State.BodyBuffer.Clear()
            $State.BufferVersion = $State.BufferVersion + 1
            $State.ScrollOffset = 0
            Add-TuiMessage -State $State -Text (T 'tui.msg.cleared') -Kind 'Info'
            return
        }
        '/reset'          { Reset-TuiState -State $State -Config $Config; return }
        '/reload'         { Set-TuiReloadConfig -State $State -Config $Config; return }
        '/help'           { Show-TuiHelp -State $State -Config $Config; return }
        '/exit'           { $State.Running = $false; return }
        default           { Add-TuiMessage -State $State -Text (T 'tui.msg.command_unknown' $cmd) -Kind 'Error'; return }
    }
}

# TUI entry point: initializes console and state, runs the input/render loop, restores on exit.
function Enter-TuiMode {
    param([Parameter(Mandatory)]$Config)

    $state = New-TuiState -Config $Config
    Initialize-TuiListState -State $state
    Set-TuiColors -State $state -Config $Config
    Initialize-TuiConsole
    $script:TuiActive = $true   # da qui Write-Log scrive solo su file (non a video)

    Add-TuiMessage -State $state -Text (T 'tui.startup.started' $script:TuiVersion) -Kind 'Success'
    Add-TuiMessage -State $state -Text (T 'tui.startup.config_loaded' $Config._resolvedConfigPath) -Kind 'Info'
    Add-TuiMessage -State $state -Text (T 'tui.startup.help_hint') -Kind 'Info'

    try {
        Invoke-TuiSafeRender -State $state -Config $Config
        $lastClock = ''

        while ($state.Running) {
            # Non-blocking input: if there are no keys I update only the clock
            # (first row) and wait a moment. This way the time advances by itself, without
            # flicker and without keeping the CPU busy.
            if (-not [Console]::KeyAvailable) {
                $fmt = Get-TuiClockFormat -Config $Config
                $nowClock = (Get-Date).ToString($fmt)
                if ($nowClock -ne $lastClock) {
                    # I save the cursor's position and visibility, hide it during the
                    # drawing of the header and then put it back where it was: this way it does not "jump".
                    # Protected block: a resize mid-frame can send the SetCursorPosition out of
                    # range; in that case I recover with a full render.
                    try {
                        $cx = [Console]::CursorLeft
                        $cy = [Console]::CursorTop
                        $cv = [Console]::CursorVisible
                        [Console]::CursorVisible = $false
                        Show-TuiHeader -State $state -Config $Config
                        [Console]::SetCursorPosition($cx, $cy)
                        [Console]::CursorVisible = $cv
                    }
                    catch {
                        Invoke-TuiSafeRender -State $state -Config $Config
                    }
                    $lastClock = $nowClock
                }
                Start-Sleep -Milliseconds 50
                continue
            }

            $key = [Console]::ReadKey($true)

            if ($state.EditorActive) {
                Invoke-TuiEditorKey -Key $key -State $state -Config $Config
                # While writing the prompt I redraw only the editor (header still ->
                # no flicker); if the editor has closed I go back to the full render.
                if ($state.EditorActive) {
                    Invoke-TuiSafeRender -State $state -Config $Config -Mode 'Editor'
                } else {
                    Invoke-TuiSafeRender -State $state -Config $Config
                }
                $lastClock = ''
                continue
            }

            $fullRender = $false
            $ctrlDown = (($key.Modifiers -band [ConsoleModifiers]::Control) -ne 0)
            switch ($key.Key) {
                'LeftArrow'  { if ($state.CommandCursor -gt 0) { $state.CommandCursor-- } }
                'RightArrow' { if ($state.CommandCursor -lt $state.CommandLine.Length) { $state.CommandCursor++ } }
                'Home'       {
                    if ($ctrlDown) { $state.ScrollOffset = [Math]::Max(0, (Get-TuiBodyBufferCount -State $state)); $fullRender = $true }
                    else { $state.CommandCursor = 0 }
                }
                'End'        {
                    if ($ctrlDown) { $state.ScrollOffset = 0; $fullRender = $true }
                    else { $state.CommandCursor = $state.CommandLine.Length }
                }
                'Backspace'  { Remove-TuiCommandCharLeft -State $state }
                'Delete'     { Remove-TuiCommandCharRight -State $state }
                'UpArrow'    { Get-TuiHistoryPrev -State $state }
                'DownArrow'  { Get-TuiHistoryNext -State $state }
                'Tab'        { Invoke-TuiAutocomplete -State $state -Config $Config; $fullRender = $true }
                'PageUp'     {
                    $bufferCount = Get-TuiBodyBufferCount -State $state
                    $state.ScrollOffset = [Math]::Min($state.ScrollOffset + 5, [Math]::Max(0, $bufferCount))
                    $fullRender = $true
                }
                'PageDown'   { $state.ScrollOffset = [Math]::Max(0, $state.ScrollOffset - 5); $fullRender = $true }
                'Enter' {
                    $cmd = $state.CommandLine.Trim()
                    if (-not [string]::IsNullOrWhiteSpace($cmd)) {
                        [void]$state.CommandHistory.Add($cmd)
                        while ($state.CommandHistory.Count -gt $state.MaxCommandHistory) {
                            $state.CommandHistory.RemoveAt(0)
                        }
                        $state.CommandHistoryIndex = -1
                        Add-TuiMessage -State $state -Text $cmd -Kind 'Command'
                        Invoke-TuiCommand -CommandLine $cmd -State $state -Config $Config
                    }
                    $state.CommandLine = ''
                    $state.CommandCursor = 0
                    $fullRender = $true
                }
                default {
                    if (-not [char]::IsControl($key.KeyChar)) {
                        Add-TuiCommandChar -State $state -Char $key.KeyChar
                    }
                }
            }

            # Targeted re-render: the actions that touch body/header/colors (Enter, Tab,
            # scroll, entering the editor) do a full refresh; simple typing
            # or moving the cursor update only the command line, leaving
            # the header still -> no flicker during writing.
            if ($fullRender -or $state.EditorActive) {
                Invoke-TuiSafeRender -State $state -Config $Config
            } else {
                Invoke-TuiSafeRender -State $state -Config $Config -Mode 'CommandLine'
            }
            $lastClock = ''
        }
    }
    finally {
        $script:TuiActive = $false
        Restore-TuiConsole
        Clear-Host
    }
}


# ============================================================
# MAIN FLOW
# ============================================================

# =================================================================
# FORMATTAZIONE DATE PER L'UTENTE 
# =================================================================



# List separator (CSV column) of the system culture: "," for US/UK, ";"
# for IT/DE/FR etc. Excel uses this separator when it opens/imports a CSV according to
# the regional settings. We determine it once at startup.
$script:CsvListSeparator = ","
try {
    $sep = [System.Globalization.CultureInfo]::CurrentCulture.TextInfo.ListSeparator
    if ($sep -and $sep.Trim() -ne "") { $script:CsvListSeparator = $sep }
} catch {
    $script:CsvListSeparator = ","
}

# =================================================================
# DEFINIZIONI LINGUE / SCRIPT UNICODE 
# =================================================================
# Map language -> type of "script" (writing system). It is needed by the
# renderability check in Test-Prerequisites: non-Latin languages require a
# UTF-8 console; the RTL ones (Arabic) also require bidi support that the Windows
# console does not have (the data stays correct in the files, but the screen is degraded).
$script:LanguageScripts = @{
    "it" = "latin";  "en" = "latin";  "fr" = "latin"
    "es" = "latin";  "pt" = "latin";  "de" = "latin"
    "ru" = "cyrillic"
    "zh" = "cjk";    "ja" = "cjk"
    "hi" = "devanagari"
    "ar" = "arabic"
}
# Right-to-left languages. The Windows console does not render them correctly
# (they appear LTR and without contextual shaping). Prepared for future bidi GUI/TUI.
$script:RtlLanguages = @("ar")

# Determines whether the system culture uses the month-first order (US-style: MM/dd/yyyy)
# or day-first (EU-style: dd/MM/yyyy). Used for the compact labels of the temporal
# charts, which must stay at 2 components but respect the expected order.
$script:CultureMonthFirst = $false
try {
    $shortPattern = [System.Globalization.CultureInfo]::CurrentCulture.DateTimeFormat.ShortDatePattern
    # If in the pattern 'M' (month) appears before 'd' (day) -> month-first
    $idxM = $shortPattern.IndexOf('M')
    $idxD = $shortPattern.IndexOf('d')
    if ($idxM -ge 0 -and $idxD -ge 0 -and $idxM -lt $idxD) {
        $script:CultureMonthFirst = $true
    }
} catch {
    $script:CultureMonthFirst = $false   # fallback: giorno-prima (EU/IT)
}

# =================================================================
# CHECK PREREQUISITI 
# =================================================================

# Logs the messages accumulated by Test-Prerequisites translating them with T.
# Each message is an object { Key; Args; Level }. It must be called AFTER the
# loading of the language pack. It also tolerates simple strings (fallback).

# =================================================================
# SECURITY UTILITY
# =================================================================

# =================================================================
# API KEY ENCODING (cross-platform)
# =================================================================
# To avoid saving the API keys in clear in the .conf, the script stores them
# encoded with a prefix that identifies the method:
# - "enc:" + payload -> Windows DPAPI (secure, tied to the current Windows user)
# - "b64:" + payload -> Base64 (obfuscation, not secure - only Unix as a fallback)
# A key WITHOUT a prefix (e.g. "4s4BYoVVj...") is considered IN CLEAR and is
# auto-encoded at the first launch.
#
# IMPORTANT - SECURITY LIMITATIONS:
# DPAPI (Windows): the encryption is tied to the Windows user that started the
# script. If you copy the .conf to another PC or open it with another user, the
# keys are NOT decodable. This is a feature, not a bug: it is what
# makes DPAPI secure.
# Base64 (Unix): it is NOT encryption, it is only obfuscation. Anyone who accesses the
# .conf can decode it trivially. It is used as "not in clear" to
# avoid accidental display, but it does not protect against an attacker.






# =================================================================
# MULTILINGUA (i18n) - Infrastruttura
# =================================================================
# /C/G: i18n infrastructure with 11 supported languages.
# Latine: it/en/fr/es/pt/de | Cirillico: ru | CJK: zh/ja |
# Devanagari: hi | Arabo RTL: ar
# The user-facing strings are identified with keys (e.g. "msg.internet_present")
# and translated via the New-GPTImage.lang file (UTF-8 without BOM). The file contains over
# a thousand keys, each with the translation in all 11 languages; the exact count is
# in the "_total_keys" field of the .lang itself (kept aligned to the number of translations).
# Logic of the T function:
# 1. Loads the translations from the .lang file if it exists, otherwise uses only the fallbacks
# 2. Looks up the key in the current language
# 3. If not found, fallback to the "en" language
# 4. If not found in "en" either, fallback to the hardcoded Italian text as the "default"
# 5. If the key does not exist in any language, returns the key itself as a string

$script:LangPack = $null     # Cache delle traduzioni caricate
$script:CurrentLang = "it"   # Lingua effettiva da usare (settata dopo Import-LanguagePack)



# =================================================================
# CARICAMENTO LANGUAGE PACK (EARLY LOADING)
# =================================================================
# The language pack must be loaded BEFORE the various utility switches (-Version,
# -Help, -Setup, -ModelList, -CheckModels) to allow those flows to use
# the T function correctly. So here we do an "early" load with
# only the language passed via -Lang. If -Lang was not passed, we will use "it"
# as the default for now; then (after loading the config) we will do a possible
# "refresh" if config.language is different.
#
# NB: $script:LangFile has already been computed at the top of the script (it is a path
# constant based on $PSScriptRoot), so it is available right away.
$earlyLang = if ($Lang -and $Lang.Trim() -ne "") { $Lang } else { "it" }

# =================================================================
# PREREQUISITES CHECK — performed BEFORE the language pack
# =================================================================
# Sets the UTF-8 console encoding, normalizes any BOM in the text files,
# and validates the renderability of the requested language (English fallback if the
# console is not UTF-8). The result determines the effective language to load.
$script:PrereqResult = Test-Prerequisites -RequestedLang $earlyLang `
                                          -ConfigPath $script:ConfigFile `
                                          -LangPath $script:LangFile
if (-not $script:PrereqResult.Ok) {
    # Check critico fallito (es. PS < 7 in un contesto che ha aggirato #requires).
    # This happens BEFORE the langpack: I use the direct bilingual fatal message.
    if ($script:PrereqResult.FatalMessage) {
        [Console]::Error.WriteLine($script:PrereqResult.FatalMessage)
    }
    exit 1
}
# If the check has imposed a language fallback (e.g. non-UTF-8 console), I apply it.
if ($script:PrereqResult.EffectiveLang -and $script:PrereqResult.EffectiveLang -ne $earlyLang) {
    $earlyLang = $script:PrereqResult.EffectiveLang
}

Import-LanguagePack -LangFilePath $script:LangFile -RequestedLang $earlyLang

# Logs the non-critical messages of the prerequisites check (encoding/language/BOM warnings),
# now that the language pack is loaded: each message is { Key; Args; Level } and
# is translated with T at the moment of the log (deferred translation).
Write-PrereqMessages -Messages $script:PrereqResult.Messages

# =================================================================
# LOCAL CURRENCY DETECTION (based on the system region)
# =================================================================
# Returns the default currency for the user based on the system country:
# - EU/EEA countries -> EUR
# - All others -> USD
# Saved in the .conf (defaultCurrency and defaultCurrencyLastCheck fields) so as not to
# recompute it at each run. The check is redone once a day, similar
# to the exchange rate.


