# =================================================================
# CROSS-PLATFORM DETECTION
# =================================================================
# Global OS-detection variables, used in various points of the script
# to enable/disable platform-specific code.
$script:IsWin = ($PSVersionTable.Platform -eq 'Win32NT') -or (-not $PSVersionTable.Platform)
$script:IsMac = ($PSVersionTable.Platform -eq 'Unix') -and ($PSVersionTable.OS -match 'Darwin')
$script:IsLin = ($PSVersionTable.Platform -eq 'Unix') -and ($PSVersionTable.OS -notmatch 'Darwin')

# (the version is defined once at the start of the script: see $script:ScriptVersion)

# =================================================================
# SYSTEM INFO (cross-platform)
# =================================================================


# =================================================================
# DEFAULT CONFIG (for -Setup / auto-generation)
# =================================================================

# =================================================================
# SELF-TEST PARAMETER COMBINATION VALIDATION
# =================================================================
# The -Simulate / -Real / -AllTest parameters make sense ONLY with -SelfTest, and with
# -SelfTest exactly ONE of them must be chosen. We validate here, early (right
# after the early-loading of the language pack, so T is available), so that an
# incorrect use fails immediately with a clear message instead of proceeding.
$selfTestModeCount = 0
if ($Simulate) { $selfTestModeCount++ }
if ($Real)     { $selfTestModeCount++ }
if ($AllTest)  { $selfTestModeCount++ }
if (($selfTestModeCount -gt 0) -and -not $SelfTest) {
    Write-Log (T 'selftest.misuse_needs_selftest') -Level ERROR
    exit 1
}
if ($SelfTest -and $selfTestModeCount -eq 0) {
    Write-Log (T 'selftest.misuse_mode_required') -Level ERROR
    exit 1
}
if ($SelfTest -and $selfTestModeCount -gt 1) {
    Write-Log (T 'selftest.misuse_mode_exclusive') -Level ERROR
    exit 1
}

# =================================================================
# -HELP PARAMETER HANDLING
# =================================================================
# Prints to screen the full help with all the parameters, valid values and descriptions.
# It exits right after, without doing any other operation (no internet check, no
# config loading, etc.).
# The -Help parameter accepts an optional value:
# -Help prints the base help
# -Help Example prints the base help + 3 usage examples for each parameter
#
# The coloring (Cyan for titles/sections, Yellow for parameters, Green for examples)
# makes the text readable without overdoing the colors.
if ($Help) {
    # KNOWN PowerShell PROBLEM: when the user writes "-Help Example", PowerShell
    # treats "Example" as the POSITIONAL value of the first declared non-switch parameter,
    # which in this script is [string]$Prompt. So "Example" ends up in $Prompt
    # instead of $RemainingArgs.
    # Solution: we look for "Example" in:
    # 1. $RemainingArgs[0] (ideal case, when PositionalBinding allows it)
    # 2. $Prompt (real case: "Example" absorbed by the first positional)
    # 3. $Model, $PromptFile (for safety, if the user puts -Help after other params)
    $helpModifier = ""
    if ($RemainingArgs -and $RemainingArgs.Count -gt 0)              { $helpModifier = $RemainingArgs[0] }
    elseif ($Prompt -and $Prompt.Trim() -ne "")                       { $helpModifier = $Prompt.Trim() }
    elseif ($PromptFile -and $PromptFile.Trim() -ne "")               { $helpModifier = $PromptFile.Trim() }
    elseif ($Model -and $Model.Trim() -ne "")                         { $helpModifier = $Model.Trim() }
    $showExamples = ($helpModifier -eq "Example")

    # "Structured" definition of the parameters to generate the help consistently.
    # Each element has: name, valid values/range, short description, 3 examples.
    $helpSections = @(
        @{
            Title = "INPUT TESTUALE"
            Items = @(
                @{ Name = "-Prompt <stringa>"; DescKey = "help.desc_prompt"
                   Examples = @(
                       '-Prompt "Un gatto astronauta sulla luna, stile fotografico"',
                       '-Prompt "Logo minimalista per startup tech, sfondo bianco"',
                       '-Prompt "Ritratto cinematografico, luce calda, 50mm bokeh"'
                   ) }
                @{ Name = "-PromptFile <path>"; DescKey = "help.desc_promptfile"
                   Examples = @(
                       '-PromptFile "C:\prompts\donna01.txt"',
                       '-PromptFile ".\prompts\paesaggio.md"',
                       '-PromptFile "/Users/me/prompts/logo.txt"'
                   ) }
            )
        }
        @{
            Title = "MODELLO"
            Items = @(
                @{ Name = "-Model <nome>"; DescKey = "help.desc_model"
                   Examples = @(
                       '-Model gpt-image-2',
                       '-Model MAI-Image-2.5',
                       '-Model gpt-image-1.5'
                   ) }
                @{ Name = "-Auto <strategia>"; DescKey = "help.desc_auto"
                   Examples = @(
                       '-Auto Cost      # sceglie il modello piu'' economico',
                       '-Auto Quality   # miglior qualita'' (qualityRating Arena + voti gallery pesati)',
                       '-Auto Time      # sceglie il modello con miglior speedRating'
                   ) }
                @{ Name = "-Force"; DescKey = "help.desc_force"
                   Examples = @(
                       '-Auto Quality -Force   # ricalcola la leaderboard qualita''',
                       '-Auto Time -Force      # ricalcola le mediane dei tempi',
                       '-Auto Cost -Force      # riaggiorna i prezzi prima di scegliere'
                   ) }
            )
        }
        @{
            Title = "PARAMETRI DI GENERAZIONE"
            Items = @(
                @{ Name = "-Storyboard [-SequenceImages <2-20>]"; DescKey = "help.desc_storyboard"
                   Examples = @(
                       '-Storyboard -Prompt "Una fiaba in tre atti..."',
                       '-Storyboard -SequenceImages 8 -PromptFile racconto.txt',
                       '-Storyboard -SequenceImages 4 -Model gpt-image-2 -Quality high'
                   ) }
                @{ Name = "-OptimizePrompt"; DescKey = "help.desc_optimizeprompt"
                   Examples = @(
                       '-Prompt "un gatto" -OptimizePrompt',
                       '-PromptFile idea.txt -OptimizePrompt -Quality high'
                   ) }
                @{ Name = "-NegativePrompt"; DescKey = "help.desc_negativeprompt"
                   Examples = @(
                       '-Prompt "ritratto fotorealistico" -NegativePrompt',
                       '-Prompt "paesaggio" -OptimizePrompt -NegativePrompt'
                   ) }
                @{ Name = "-DescribeImage <path>"; DescKey = "help.desc_describeimage"
                   Examples = @(
                       '-DescribeImage "C:\img\foto.jpg"',
                       '(richiede un modello textModel MULTIMODALE in grado di analizzare immagini)'
                   ) }
                @{ Name = "-NImages <int>"; DescKey = "help.desc_nimages"
                   Examples = @('-NImages 1', '-NImages 3', '-NImages 5') }
                @{ Name = "-Size <WxH>"; DescKey = "help.desc_size"
                   Examples = @('-Size 1024x1024', '-Size 1024x1536', '-Size 1536x1024') }
                @{ Name = "-Quality <livello>"; DescKey = "help.desc_quality"
