                       '-Bench gpt-image-2,FLUX.2-pro -BenchExport ".\bench.csv" -Overwrite'
                   ) }
                @{ Name = "-Threads <int>"; DescKey = "help.desc_threads"
                   Examples = @('-Threads 1', '-Threads 3', '-Threads 5') }
            )
        }
        @{
            Title = "METADATA E ANALYTICS"
            Items = @(
                @{ Name = "-Metadata <True|False>"; DescKey = "help.desc_metadata"
                   Examples = @('-Metadata True', '-Metadata False', '(default: da config, False)') }
                @{ Name = "-Analytics [valore]"; DescKey = "help.desc_analytics"
                   Examples = @('-Analytics', '-Analytics USD', '-Analytics Token -AnalyticsFile "rep.txt"') }
                @{ Name = "-AnalyticsFile <path>"; DescKey = "help.desc_analytics_file"
                   Examples = @(
                       '-Analytics EUR -AnalyticsFile "report.txt"',
                       '-Analytics Token -AnalyticsFile "C:\reports\token-usage.txt"',
                       '-Analytics -AnalyticsFile ".\analytics.txt"'
                   ) }
                @{ Name = "-Overwrite"; DescKey = "help.desc_overwrite"
                   Examples = @(
