        }
        @{
            Title = "UTILITY"
            Items = @(
                @{ Name = "-DryRun"; DescKey = "help.desc_dryrun"
                   Examples = @(
                       '-Prompt "test" -DryRun',
                       '-PromptFile "p.txt" -DryRun',
                       '-Prompt "test" -InputImages "img.jpg" -DryRun'
                   ) }
                @{ Name = "-Setup"; DescKey = "help.desc_setup"
                   Examples = @('-Setup', '(esegui questo come primo step)', '(poi compila apiKey e endpoint nel .conf)') }
                @{ Name = "-Gallery"; DescKey = "help.desc_gallery"
                   Examples = @(
                       '-Gallery',
                       '-Gallery -OutputFolder "C:\foto\AI"',
                       '(apri gallery.html nel browser dopo la generazione)'
                   ) }
                @{ Name = "-IaC [-IaCMode <generate|dry-run|execute>]"; DescKey = "help.desc_iac"
                   Examples = @(
                       '-IaC',
                       '-IaC -IaCMode execute -IaCResourceGroup "rg-mia" -IaCRegion "swedencentral" -IaCFoundryName "mio-foundry"',
                       '-IaC -IaCMode execute -IaCDeployModel -IaCModelName "gpt-image-1" -IaCModelFormat OpenAI',
                       '-IaC -IaCWizard  (raccolta interattiva guidata dei parametri)',
                       '-IaC -IaCTeardown -IaCResourceGroup "rg-mia"  (smantella le risorse)',
                       '(richiede Azure CLI; -IaCDeployModel crea anche il deployment del modello)'
                   ) }
                @{ Name = "-ModelList"; DescKey = "help.desc_modellist"
                   Examples = @('-ModelList', '(modelli attivi evidenziati in verde)', '(verifica conf prima di lavorare)') }
                @{ Name = "-CheckModels"; DescKey = "help.desc_checkmodels"
                   Examples = @('-CheckModels', '(stampa tabella stato modelli)', '(utile per debug connettivita)') }
                @{ Name = "-CheckEndpoint"; DescKey = "help.desc_checkendpoint"
                   Examples = @('-CheckEndpoint', '(testa endpoint dei modelli attivi)', '(dice se disponibili e in quale region)') }
                @{ Name = "-DumpPricingPages"; DescKey = "help.desc_dumppricingpages"
                   Examples = @('-DumpPricingPages', '(scarica le pagine pricing dei modelli)', '(in _pricing_pages_dump accanto al .conf)') }
                @{ Name = "-AddModel"; DescKey = "help.desc_addmodel"
                   Examples = @('-AddModel', '(wizard guidato per aggiungere un modello)', '(cifra la key, niente .conf a mano)') }
                @{ Name = "-RemoveModel"; DescKey = "help.desc_removemodel"
                   Examples = @('-RemoveModel', '(rimuove un modello con conferma)') }
                @{ Name = "-EditModel"; DescKey = "help.desc_editmodel"
                   Examples = @('-EditModel', '(modifica i campi di un modello esistente)') }
                @{ Name = "-ModelPrice <valore>"; DescKey = "help.desc_modelprice"
                   Examples = @('-ModelPrice Force', '(bypass del check giornaliero)', '(utile dopo cambio listino Azure)') }
                @{ Name = "-PricingDiscovery <keyword>"; DescKey = "help.desc_pricing_discovery"
                   Examples = @('-PricingDiscovery "GPT-Image"', '-PricingDiscovery "MAI-Image-2"', '(esplora il catalogo Retail API)') }
                @{ Name = "-Help [Example]"; DescKey = "help.desc_help"
                   Examples = @('-Help', '-Help Example', '(usa Example per imparare)') }
                @{ Name = "-Version"; DescKey = "help.desc_version"
                   Examples = @('-Version', ('(versione attuale: ' + $script:ScriptVersion + ')'), '(utile per script automatici)') }
                @{ Name = "-Budget <numero>"; DescKey = "help.desc_budget"
                   Examples = @(
                       '-Budget 0,10           # virgola o punto: max 0,10 valuta locale',
                       '-Budget 0.05 -Batch "demo.batch"',
                       '-Budget 1,50 -NImages 5'
                   ) }
                @{ Name = "-Lang <codice>"; DescKey = "help.desc_lang"
                   Examples = @(
                       '-Lang en',
                       '-Lang fr',
                       '(traduzione completa disponibile)'
                   ) }
                @{ Name = "-TUI"; DescKey = "help.desc_tui"
                   Examples = @(
                       '-TUI',
                       '-TUI -Lang en',
                       '-TUI -Version          # versione della TUI'
                   ) }
                @{ Name = "-SelfTest <modalita>"; DescKey = "help.desc_selftest"
                   Examples = @(
                       '-SelfTest -Simulate    # test senza costi (no token)',
                       '-SelfTest -Real        # test che generano immagini reali',
                       '-SelfTest -AllTest     # esegue tutti i test'
                   ) }
                @{ Name = "-DecryptLog"; DescKey = "help.desc_decryptlog"
                   Examples = @(
                       '-DecryptLog',
                       '-DecryptLog | Select-String "ERROR"',
                       '-DecryptLog > log_chiaro.txt'
                   ) }
            )
        }
        @{
            Title = "VERBOSITA'"
            Items = @(
                @{ Name = "-Verbosity <livello>"; DescKey = "help.desc_verbosity"
                   Examples = @(
                       '-Verbosity verbose    # default, mostra tutto',
                       '-Verbosity normal     # nasconde TIME e COST',
                       '-Verbosity silent     # solo ERROR'
                   ) }
            )
        }
    )

    # --- Print header ---
    Write-Host ""
    Write-Host "===============================================================================" -ForegroundColor Cyan
    Write-Host (T 'help.title') -ForegroundColor Cyan
    Write-Host (T 'help.version_line' $script:ScriptVersion) -ForegroundColor Cyan
    Write-Host "===============================================================================" -ForegroundColor Cyan
    Write-Host ""
    Write-Host (T 'help.description_label') -ForegroundColor Yellow
    Write-Host (T 'help.description_1')
    Write-Host (T 'help.description_2')
    Write-Host (T 'help.description_3')
    Write-Host (T 'help.description_4')
    Write-Host ""
    Write-Host (T 'help.basic_usage') -ForegroundColor Yellow
    Write-Host '  .\New-GPTImage.ps1 -Prompt "Un gatto astronauta"' -ForegroundColor Green
    Write-Host '  .\New-GPTImage.ps1 -Prompt "..." -InputImages "ref.png"' -ForegroundColor Green
    Write-Host '  .\New-GPTImage.ps1 -Batch ".\demo.batch" -Threads 3' -ForegroundColor Green
    Write-Host '  .\New-GPTImage.ps1 -Analytics EUR' -ForegroundColor Green
    Write-Host '  .\New-GPTImage.ps1 -Gallery' -ForegroundColor Green
    Write-Host '  .\New-GPTImage.ps1 -Prompt "..." -OptimizePrompt -NegativePrompt' -ForegroundColor Green
    Write-Host '  .\New-GPTImage.ps1 -Storyboard -SequenceImages 6 -Prompt "..."' -ForegroundColor Green
    Write-Host '  .\New-GPTImage.ps1 -IaC -IaCWizard' -ForegroundColor Green
    Write-Host '  .\New-GPTImage.ps1 -TUI' -ForegroundColor Green
    Write-Host ""

    # --- Print parameter sections ---
    Write-Host (T 'help.parameters_label') -ForegroundColor Yellow
    foreach ($section in $helpSections) {
        Write-Host ""
        # The section titles (Title) are stored in the helpSections dictionaries as Italian
        # strings. For multilingual support, each Title has a corresponding T key
        # in the 'help.section_*' namespace. Mapping done inline here to avoid duplicating
        # the Titles already present as a field of the hash.
        $sectionTitleKey = switch ($section.Title) {
            "INPUT TESTUALE"           { 'help.section_input' }
            "MODELLO"                  { 'help.section_model' }
            "PARAMETRI DI GENERAZIONE" { 'help.section_generation' }
            "INPUT / OUTPUT"           { 'help.section_io' }
            "BATCH PROCESSING"         { 'help.section_batch' }
            "METADATA E ANALYTICS"     { 'help.section_metadata' }
            "UTILITY"                  { 'help.section_utility' }
            "VERBOSITA'"               { 'help.section_verbosity' }
            default                    { $null }
        }
        $sectionTitle = if ($sectionTitleKey) { T $sectionTitleKey } else { $section.Title }
        Write-Host ("  -- " + $sectionTitle + " --") -ForegroundColor Cyan
        foreach ($item in $section.Items) {
            Write-Host ""
            Write-Host ("    " + $item.Name) -ForegroundColor Yellow
            Write-Host ("      " + (T $item.DescKey))
            if ($showExamples) {
                Write-Host (T 'help.examples_label') -ForegroundColor DarkGray
                foreach ($ex in $item.Examples) {
                    Write-Host ("        " + $ex) -ForegroundColor Green
                }
            }
        }
    }

    Write-Host ""
    Write-Host (T 'help.notes_label') -ForegroundColor Yellow
    Write-Host (T 'help.note_1')
    Write-Host (T 'help.note_2')
    Write-Host (T 'help.note_3')
    Write-Host (T 'help.note_4')
    Write-Host ""
    Write-Host (T 'help.textmodel_title') -ForegroundColor Yellow
    Write-Host (T 'help.textmodel_1')
    Write-Host (T 'help.textmodel_2')
    Write-Host (T 'help.textmodel_3')
    Write-Host (T 'help.textmodel_4')
    Write-Host ""
    Write-Host (T 'help.telemetry_title') -ForegroundColor Yellow
    Write-Host (T 'help.telemetry_1')
    Write-Host (T 'help.telemetry_2')
    Write-Host (T 'help.telemetry_3')
    Write-Host ""
    Write-Host (T 'help.gallery_title') -ForegroundColor Yellow
    Write-Host (T 'help.gallery_1')
    Write-Host (T 'help.gallery_2')
    Write-Host (T 'help.gallery_3')
    Write-Host (T 'help.gallery_4')
    Write-Host (T 'help.gallery_5')
    Write-Host (T 'help.gallery_6')
    Write-Host (T 'help.gallery_7')
    Write-Host ""

    if (-not $showExamples) {
        Write-Host (T 'help.suggestion') -ForegroundColor DarkGray
        Write-Host ""
    }

    Write-Host "===============================================================================" -ForegroundColor Cyan
    Write-Host ""
    exit 0
}

# =================================================================
# -SETUP PARAMETER HANDLING
# =================================================================
if ($Setup) {
    if (Test-Path $script:ConfigFile) {
        Write-Host (T 'setup.conf_exists' $script:ConfigFile)
        Write-Host (T 'setup.regenerate_hint')
        exit 0
    }

    try {
        Get-DefaultConfigJson | Set-Content -Path $script:ConfigFile -Encoding UTF8 -ErrorAction Stop
        Write-Host (T 'setup.conf_created' $script:ConfigFile)
        Write-Host (T 'setup.compile_hint')
        exit 0
    }
    catch {
        [Console]::Error.WriteLine("ERROR: Unable to create $script:ConfigFile : $($_.Exception.Message)")
        exit 1
    }
}

# =================================================================
# -CHECKMODELS PARAMETER HANDLING
# =================================================================
# Verifies which configured models are reachable (TCP probe on the endpoint)
# and which have endpoint+apiKey filled in. Prints a summary table.
# NOTE: this does NOT really validate the API key (it makes no calls), it only verifies
# network reachability. For a complete check a real DryRun call is needed
# (which however costs time and potentially tokens).
if ($CheckModels) {
    # Carico subito il config (non possiamo aspettare il flusso normale)
    if (-not (Test-Path $script:ConfigFile)) {
        [Console]::Error.WriteLine((T 'setup.conf_not_found' $script:ConfigFile))
        exit 1
    }
    try {
        $cfgCheck = (Get-Content $script:ConfigFile -Raw -Encoding UTF8 -ErrorAction Stop) | ConvertFrom-Json -ErrorAction Stop
    }
    catch {
        [Console]::Error.WriteLine("ERROR: $script:ConfigFile is not valid JSON.")
        exit 1
    }

    Write-Host ""
    Write-Host (T 'modellist.verify_title') -ForegroundColor Cyan
    Write-Host ""

    # I build ALL the rows FIRST (titles + data) in a structure, so I can
    # compute the real width of each column (max between title and data) and then:
    #  - size the yellow underline bar exactly as wide as the column,
    #  - color OK/FAIL in the Reachability column without breaking the alignment.
    # The "Reachable" column has an extra field ($reachState: ok|fail|na) used only to
    # decide the color; the shown text stays in $reach.
    $headers = @(
        (T 'modellist.col_model'),
        (T 'modellist.col_active'),
        "Endpoint",
        (T 'modellist.col_apikey'),
        (T 'modellist.col_reachable')
    )

    $modelNamesCheck = @($cfgCheck.models | Get-Member -MemberType NoteProperty | Select-Object -ExpandProperty Name)
    $rows = @()
    # Flag: true if at least one model has the 'active' field absent (shown with "*").
    # The explanatory note at the bottom is printed ONLY if this flag is true, so
    # it does not appear when all the models have an explicit 'active' (the common case).
    $hasActiveStar = $false
    foreach ($modelName in $modelNamesCheck) {
        $mc = $cfgCheck.models.$modelName
        # Etichetta active: si/no tradotte. "*" come marker per "active assente nel conf"
        # (back-compatibility: treated as active).
        $activeStr = if ($null -ne $mc.active) {
            if ([bool]$mc.active) { T 'modellist.val_yes' } else { T 'modellist.val_no' }
        } else {
            $hasActiveStar = $true
            (T 'modellist.val_yes') + "*"
        }
        $endpointStr = if ($mc.endpoint -and $mc.endpoint.Trim() -ne "") { T 'modellist.val_configured' } else { "EMPTY" }
        $apiKeyStr = if ($mc.apiKey -and $mc.apiKey.Trim() -ne "") { T 'modellist.val_configured' } else { "EMPTY" }

        $reachStr = "n/a"
        $reachState = "na"
        if ($mc.endpoint -and $mc.endpoint.Trim() -ne "") {
            $hostCheck = Get-HostFromUrl $mc.endpoint
            if ($hostCheck) {
                $reachable = Test-InternetConnectivity -TargetHost $hostCheck -TargetPort 443 -TimeoutSec 3
                if ($reachable) { $reachStr = "OK ($hostCheck)";   $reachState = "ok" }
                else            { $reachStr = "FAIL ($hostCheck)"; $reachState = "fail" }
            } else {
                $reachStr = T 'modellist.val_invalid_url'
                $reachState = "fail"
            }
        }

        $rows += [pscustomobject]@{
            Model      = $modelName
            Active     = $activeStr
            Endpoint   = $endpointStr
            ApiKey     = $apiKeyStr
            Reach      = $reachStr
            ReachState = $reachState
        }
    }

    # Width of each column = max between the title and all the values of the column.
    $colVals = @(
        @(@($headers[0]) + @($rows | ForEach-Object { $_.Model })),
        @(@($headers[1]) + @($rows | ForEach-Object { $_.Active })),
        @(@($headers[2]) + @($rows | ForEach-Object { $_.Endpoint })),
        @(@($headers[3]) + @($rows | ForEach-Object { $_.ApiKey })),
        @(@($headers[4]) + @($rows | ForEach-Object { $_.Reach }))
    )
    $colW = @(0,0,0,0,0)
    for ($c = 0; $c -lt 5; $c++) {
        $maxLen = 0
        foreach ($v in $colVals[$c]) {
            $len = ([string]$v).Length
            if ($len -gt $maxLen) { $maxLen = $len }
        }
        $colW[$c] = $maxLen
    }
    $gap = 2   # spazi tra una colonna e l'altra

    # Helper: adds padding on the right up to the column width.
    function _pad([string]$txt, [int]$width) {
        if ($null -eq $txt) { $txt = "" }
        return $txt.PadRight($width)
    }

    # Titles row (yellow). The last column is not padded (end of row).
    $sep = " " * $gap
    $headerLine = (_pad $headers[0] $colW[0]) + $sep + (_pad $headers[1] $colW[1]) + $sep +
                  (_pad $headers[2] $colW[2]) + $sep + (_pad $headers[3] $colW[3]) + $sep + $headers[4]
    Write-Host $headerLine -ForegroundColor Yellow

    # Yellow bar: a sequence of '-' EXACTLY as long as the column, aligned
    # under each title. Same width and same gaps as the titles row.
    $underLine = ("-" * $colW[0]) + $sep + ("-" * $colW[1]) + $sep +
                 ("-" * $colW[2]) + $sep + ("-" * $colW[3]) + $sep + ("-" * $colW[4])
    Write-Host $underLine -ForegroundColor Yellow

    # Data rows. The first 4 columns printed normally; in the 5th (Reachability)
    # I color ONLY the status prefix (OK in green / FAIL in red), leaving the host
    # "(...)" in the default color. I use multiple -NoNewline to split the segments:
    #   [columns prefix]  [colored OK|FAIL]  [rest of the host in default]
    # For "ok"/"fail" the Reach string has the form "<STATUS> (host)": I separate the first word
    # (the status) from the rest. For the other states (invalid URL = fail without host, n/a)
    # I print the whole string with the appropriate color.
    foreach ($row in $rows) {
        $prefix = (_pad $row.Model $colW[0]) + $sep + (_pad $row.Active $colW[1]) + $sep +
                  (_pad $row.Endpoint $colW[2]) + $sep + (_pad $row.ApiKey $colW[3]) + $sep
        Write-Host $prefix -NoNewline

        $reach = [string]$row.Reach
        $spaceIdx = $reach.IndexOf(' ')
        # I separate "status" and "host" ONLY if the string really has the form of a status followed
        # by a host in round parentheses: a space present AND the character after the space is
        # an open round parenthesis (char 40). This way multi-word error messages
        # without a host (e.g. "INVALID URL") stay whole and colored.
        $openParenChar = [char]40
        $hasHostSuffix = ($spaceIdx -gt 0 -and $reach.Length -gt ($spaceIdx + 1) -and $reach[$spaceIdx + 1] -eq $openParenChar)
        if (($row.ReachState -eq "ok" -or $row.ReachState -eq "fail") -and $hasHostSuffix) {
            # "<STATUS> (host)": I color only the status, host in default.
            $statePart = $reach.Substring(0, $spaceIdx)            # es. "OK" / "FAIL"
            $restPart  = $reach.Substring($spaceIdx)               # es. " (host...)"
            $stateColor = if ($row.ReachState -eq "ok") { "Green" } else { "Red" }
            Write-Host $statePart -ForegroundColor $stateColor -NoNewline
            Write-Host $restPart
        } else {
            # No host to separate (invalid URL, n/a): whole string with the color.
            switch ($row.ReachState) {
                "ok"   { Write-Host $reach -ForegroundColor Green }
                "fail" { Write-Host $reach -ForegroundColor Red }
                default { Write-Host $reach }
            }
        }
    }

    Write-Host ""
    # Note about the asterisk: I show it ONLY if at least one model actually uses it ('active'
    # field absent). If all the models have an explicit 'active', the note is not needed.
    if ($hasActiveStar) {
        Write-Host (T 'modellist.active_note')
        Write-Host ""
    }
    exit 0
}

# =================================================================
# -CHECKENDPOINT PARAMETER HANDLING
# =================================================================
# Tests the AVAILABILITY of the endpoints of all the ACTIVE models. For each one
# it says whether it is available (and in which region) or not contactable, so
# the user can diagnose problems on a specific region/Foundry. It exits after.
if ($CheckEndpoint) {
    if (-not (Test-Path $script:ConfigFile)) {
        [Console]::Error.WriteLine((T 'setup.conf_not_found' $script:ConfigFile))
        exit 1
    }
    try {
        $cfgCe = (Get-Content $script:ConfigFile -Raw -Encoding UTF8) | ConvertFrom-Json -ErrorAction Stop
    }
    catch {
        Write-Log (T 'config.parse_error' $script:ConfigFile ($_.Exception.Message)) -Level ERROR
        exit 1
    }

    Write-Log (T 'checkendpoint.intro')

    $modelNamesCe = @($cfgCe.models | Get-Member -MemberType NoteProperty | Select-Object -ExpandProperty Name)
    $testedCount = 0
    foreach ($modelName in $modelNamesCe) {
        $mc = $cfgCe.models.$modelName
        # Only ACTIVE models (active absent = treated as active, back-compat).
        $isActive = if ($null -ne $mc.active) { [bool]$mc.active } else { $true }
        if (-not $isActive) { continue }
        $testedCount++

        # Region dal pricingMapping (se assente, "n/d").
        $region = "n/d"
        if ($mc.pricingMapping -and $mc.pricingMapping.armRegionName -and $mc.pricingMapping.armRegionName.Trim() -ne "") {
            $region = $mc.pricingMapping.armRegionName.Trim()
        }

        # Missing endpoint: we flag it and move on.
        if (-not $mc.endpoint -or $mc.endpoint.Trim() -eq "") {
            Write-Log (T 'checkendpoint.no_endpoint' $modelName) -Level WARN
            continue
        }

        # I decode the apiKey (it can be enc:/b64:). If it is missing, I still test the
        # network reachability but the auth will fail (we flag it).
        $plainKey = ""
        if ($mc.apiKey -and $mc.apiKey.Trim() -ne "") {
            $plainKey = Unprotect-ApiKey -EncodedValue $mc.apiKey
        }
        $schema = if ($mc.apiSchema -and $mc.apiSchema.Trim() -ne "") { $mc.apiSchema.Trim() } else { "openai-images" }
        $deploy = if ($mc.deployment) { $mc.deployment } else { $modelName }
        $authM  = if ($mc.authMode -and $mc.authMode.Trim() -ne "") { $mc.authMode.Trim().ToLower() } else { "" }

        $check = Test-ModelEndpoint -Endpoint $mc.endpoint -ApiKey $plainKey -Deployment $deploy -ApiSchema $schema -AuthMode $authM

        # Message based on the outcome. I always show model + region.
        switch ($check.Reason) {
            'checkendpoint.available'    { Write-Log (T 'checkendpoint.available'    $modelName $region) }
            'checkendpoint.auth_failed'  { Write-Log (T 'checkendpoint.auth_failed'  $modelName $region) -Level WARN }
            'checkendpoint.not_found'    { Write-Log (T 'checkendpoint.not_found'    $modelName $region) -Level WARN }
            'checkendpoint.unreachable'  { Write-Log (T 'checkendpoint.unreachable'  $modelName $region $check.HostName) -Level WARN }
            'checkendpoint.invalid_url'  { Write-Log (T 'checkendpoint.invalid_url'  $modelName) -Level WARN }
            'checkendpoint.http_timeout' { Write-Log (T 'checkendpoint.http_timeout' $modelName $region) -Level WARN }
            'checkendpoint.http_error'   { Write-Log (T 'checkendpoint.http_error'   $modelName $region $check.HttpStatus) -Level WARN }
            default                      { Write-Log (T 'checkendpoint.http_error'   $modelName $region $check.HttpStatus) -Level WARN }
        }
    }

    if ($testedCount -eq 0) {
        Write-Log (T 'checkendpoint.no_active_models') -Level WARN
    }
    exit 0
}

# =================================================================
# MODEL MANAGEMENT: -ADDMODEL / -REMOVEMODEL / -EDITMODEL
# =================================================================
# Interactive wizards to manage the .conf models without editing it by hand. Each one
# loads the config, runs the wizard and exits. They exit BEFORE the model
# selection/validation (they are non-model commands, like -CheckEndpoint).
if ($AddModel -or $RemoveModel -or $EditModel) {
    if (-not (Test-Path $script:ConfigFile)) {
        [Console]::Error.WriteLine((T 'setup.conf_not_found' $script:ConfigFile))
        exit 1
    }
    try {
        $cfgMgmt = (Get-Content $script:ConfigFile -Raw -Encoding UTF8) | ConvertFrom-Json -ErrorAction Stop
    }
    catch {
        Write-Log (T 'config.parse_error' $script:ConfigFile ($_.Exception.Message)) -Level ERROR
        exit 1
    }
    # Assicuro la presenza del contenitore models.
    if (-not ($cfgMgmt.PSObject.Properties.Name -contains 'models') -or $null -eq $cfgMgmt.models) {
        $cfgMgmt | Add-Member -MemberType NoteProperty -Name models -Value ([PSCustomObject]@{}) -Force
    }

    if ($AddModel)    { Invoke-AddModelWizard    -Config $cfgMgmt -ConfigPath $script:ConfigFile }
    elseif ($RemoveModel) { Invoke-RemoveModelWizard -Config $cfgMgmt -ConfigPath $script:ConfigFile }
    elseif ($EditModel)   { Invoke-EditModelWizard   -Config $cfgMgmt -ConfigPath $script:ConfigFile }
    exit 0
}

# =================================================================
# -DUMPPRICINGPAGES PARAMETER HANDLING
# =================================================================
# Downloads locally the official pricing pages of ALL the configured models,
# reading pricingMapping.pricingPageUrl from the .conf. It deduplicates the URLs (several models
# can share the same page) and saves the HTML in a subfolder next to
# the .conf, with readable names derived from the URL. It uses the same HTTP headers as the
# internal scraper, so the HTML is identical to the one analyzed by the pricing pipeline.
# It exits after. It does not generate images.
if ($DumpPricingPages) {
    if (-not (Test-Path $script:ConfigFile)) {
        [Console]::Error.WriteLine((T 'setup.conf_not_found' $script:ConfigFile))
        exit 1
    }
    try {
        $cfgDump = (Get-Content $script:ConfigFile -Raw -Encoding UTF8) | ConvertFrom-Json -ErrorAction Stop
    }
    catch {
        Write-Log (T 'config.parse_error' $script:ConfigFile ($_.Exception.Message)) -Level ERROR
        exit 1
    }

    # Output folder next to the .conf
    $confDir = Split-Path -Parent $script:ConfigFile
    $dumpFolder = Join-Path $confDir "_pricing_pages_dump"
    if (-not (Test-Path $dumpFolder)) {
        New-Item -ItemType Directory -Path $dumpFolder -Force | Out-Null
    }

    # I collect the unique pages: URL -> list of "model [region]"
    $dumpPages = @{}
    if ($cfgDump.models) {
        foreach ($mProp in @($cfgDump.models.PSObject.Properties)) {
            $pm = $mProp.Value.pricingMapping
            if (-not $pm -or -not $pm.pricingPageUrl) { continue }
            $u = [string]$pm.pricingPageUrl
            $reg = if ($pm.armRegionName) { [string]$pm.armRegionName } else { "?" }
            if (-not $dumpPages.ContainsKey($u)) {
                $dumpPages[$u] = [System.Collections.Generic.List[string]]::new()
            }
            [void]$dumpPages[$u].Add("$($mProp.Name) [$reg]")
        }
    }

    if ($dumpPages.Count -eq 0) {
        Write-Log (T 'dump.no_pages') -Level WARN
        exit 0
    }

    # Helper: readable file name from the URL (last 1-2 meaningful segments).
    function Get-DumpFileName([string]$url) {
        $clean = $url.TrimEnd('/')
        $parts = $clean -split '/'
        $last = $parts[-1]
        $prev = if ($parts.Count -ge 2) { $parts[-2] } else { "" }
        $base = if ($prev -eq 'ai-foundry-models') { "$prev`__$last" } else { $last }
        # sanitizzo: solo lettere, cifre, trattino, underscore
        $base = ($base -replace '[^\w\-]', '_')
        if ([string]::IsNullOrWhiteSpace($base)) { $base = "pricing_page" }
        return "$base.html"
    }

    # Same headers as the internal scraper (Get-PricesFromPricingPage)
    $dumpHeaders = @{
        'Accept'          = 'text/html,application/xhtml+xml'
        'Accept-Language' = 'en-US,en;q=0.9'
        'User-Agent'      = 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 PowerShell New-GPTImage.ps1'
    }

    Write-Log (T 'dump.header' $dumpPages.Count $dumpFolder) -Level INFO
    $okCount = 0
    foreach ($u in $dumpPages.Keys) {
        $fileName = Get-DumpFileName $u
        $outPath = Join-Path $dumpFolder $fileName
        $modelsStr = ($dumpPages[$u] -join ', ')
        Write-Log (T 'dump.downloading' $u $modelsStr) -Level INFO
        try {
            $respDump = Invoke-WebRequest -Uri $u -Headers $dumpHeaders -TimeoutSec 60 -UseBasicParsing -ErrorAction Stop
            Set-Content -Path $outPath -Value $respDump.Content -Encoding UTF8
            $sizeKb = [math]::Round((Get-Item $outPath).Length / 1KB, 1)
            Write-Log (T 'dump.saved' $fileName $sizeKb) -Level INFO
            $okCount++
        }
        catch {
            Write-Log (T 'dump.fail' $u ($_.Exception.Message)) -Level WARN
        }
    }
    Write-Log (T 'dump.done' $okCount $dumpPages.Count $dumpFolder) -Level INFO
    exit 0
}

# =================================================================
# -MODELLIST PARAMETER HANDLING
# =================================================================
# Prints the list of configured models with a clear visual status:
# - Green + "active" for models with active=true and endpoint+apiKey set
# - Gray + "inactive" for models with active=false or not configured
# Unlike -CheckModels, it does NOT do a network probe (faster).
if ($ModelList) {
    if (-not (Test-Path $script:ConfigFile)) {
        [Console]::Error.WriteLine((T 'setup.conf_not_found' $script:ConfigFile))
        exit 1
    }
    try {
        $cfgList = (Get-Content $script:ConfigFile -Raw -Encoding UTF8 -ErrorAction Stop) | ConvertFrom-Json -ErrorAction Stop
    }
    catch {
        [Console]::Error.WriteLine("ERROR: $script:ConfigFile is not valid JSON.")
        exit 1
    }

    Write-Host ""
    Write-Host (T 'modellist.list_title' $script:ConfigFile) -ForegroundColor Cyan
    Write-Host ""

    # Table layout:
    # Model Status Pricing (USD/1M) Feature
    # gpt-image-2 ACTIVE in:5 img:10 inpaint, bg
    # MAI-Image-2e disattivo - -
    $fmtML = "{0,-22} {1,-12} {2,-28} {3}"
    Write-Host ($fmtML -f (T 'modellist.col_model'), (T 'modellist.col_status'), (T 'modellist.col_pricing'), (T 'modellist.col_feature')) -ForegroundColor Yellow
    Write-Host ($fmtML -f ('-' * 22), ('-' * 12), ('-' * 28), ('-' * 38)) -ForegroundColor Yellow

    $modelNamesML = @($cfgList.models | Get-Member -MemberType NoteProperty | Select-Object -ExpandProperty Name)
    foreach ($modelName in $modelNamesML) {
        $mc = $cfgList.models.$modelName

        # I determine the effective status: ACTIVE only if active=true AND endpoint AND apiKey
        $activeFlag = if ($null -ne $mc.active) { [bool]$mc.active } else { $true }
        $hasEndpoint = $mc.endpoint -and $mc.endpoint.Trim() -ne ""
        $hasApiKey = $mc.apiKey -and $mc.apiKey.Trim() -ne ""
        $isFullyActive = $activeFlag -and $hasEndpoint -and $hasApiKey

        $statoStr = if ($isFullyActive) { T 'modellist.val_active' } else { T 'modellist.val_inactive' }
        $statoColor = if ($isFullyActive) { "Green" } else { "DarkGray" }

        # Pricing: reads from the new meters schema, fallback to the old fields.
        $pricingStr = "-"
        if ($mc.pricing) {
            $hasMeters = ($mc.pricing.PSObject.Properties.Name -contains 'meters') -and ($null -ne $mc.pricing.meters)
            if ($hasMeters) {
                $mm = $mc.pricing.meters
                # AOAI labeled
                $vIn  = if ($mm.PSObject.Properties.Name -contains 'inputText'   -and $null -ne $mm.inputText)   { [double]$mm.inputText }   else { 0.0 }
                $vImg = if ($mm.PSObject.Properties.Name -contains 'outputImage' -and $null -ne $mm.outputImage) { [double]$mm.outputImage } else { 0.0 }
                # MAI columnar
                $vInG = if ($mm.PSObject.Properties.Name -contains 'input'  -and $null -ne $mm.input)  { [double]$mm.input }  else { 0.0 }
                $vOutG= if ($mm.PSObject.Properties.Name -contains 'output' -and $null -ne $mm.output) { [double]$mm.output } else { 0.0 }
                # FLUX per-megapixel 
                $vMp1 = if ($mm.PSObject.Properties.Name -contains 'firstMpUsd'      -and $null -ne $mm.firstMpUsd)      { [double]$mm.firstMpUsd }      else { 0.0 }
                $vMp2 = if ($mm.PSObject.Properties.Name -contains 'additionalMpUsd' -and $null -ne $mm.additionalMpUsd) { [double]$mm.additionalMpUsd } else { 0.0 }
                if ($vMp1 -gt 0 -or $vMp2 -gt 0) {
                    $pricingStr = "mp1:$vMp1 mpN:$vMp2 (USD/MP)"
                } elseif ($vInG -gt 0 -or $vOutG -gt 0) {
                    $pricingStr = "in:$vInG out:$vOutG"
                } elseif ($vIn -gt 0 -or $vImg -gt 0) {
                    $pricingStr = "inT:$vIn outI:$vImg"
                }
            } elseif ($mc.pricing.PSObject.Properties.Name -contains 'inputTokensPerMillionUsd' -and
                      [double]$mc.pricing.inputTokensPerMillionUsd -gt 0) {
                # Schema vecchio (pre-migrazione)
                $pricingStr = "in:$($mc.pricing.inputTokensPerMillionUsd) img:$($mc.pricing.imageTokensPerMillionUsd)"
            }
        }

        # Feature. txt2img is the base capability common to ALL the models
        # (text-to-image generation); edit is an additional capability (reference
        # images or editing endpoint). The others depend on the switches.
        $feats = @("txt2img")
        $mcEdit = if ($null -ne $mc.supportsEdit) { [bool]$mc.supportsEdit } else { $true }
        if ($mcEdit)                   { $feats += "edit" }
        if ($mc.supportsInpainting)    { $feats += "inpaint" }
        if ($mc.supportsInputFidelity) { $feats += "fidelity" }
        if ($mc.supportsBackground)    { $feats += "bg" }
        $featStr = $feats -join ", "

        # Print with color only on the "status" field
        $linePrefix = "{0,-22} " -f $modelName
        $lineSuffix = "{0,-12} {1,-28} {2}" -f $statoStr, $pricingStr, $featStr

        Write-Host $linePrefix -NoNewline
        Write-Host $lineSuffix -ForegroundColor $statoColor
    }

    Write-Host ""
    Write-Host (T 'modellist.active_legend') -ForegroundColor DarkGray
    Write-Host (T 'modellist.inactive_legend') -ForegroundColor DarkGray
    Write-Host ""
    exit 0
}

# =================================================================
# SWITCH -PricingDiscovery (, esteso )
# =================================================================
# Interactive command to explore the Azure Retail Prices API catalog and discover
# the real serviceName, productName and meterName for your models. Useful when
# Phases 1-2 of the pricing pipeline fail because we do not know how
# Microsoft has cataloged the model internally.
#
# Usage:
# .\New-GPTImage.ps1 -PricingDiscovery "GPT-Image"
# .\New-GPTImage.ps1 -PricingDiscovery "MAI-Image-2"
# .\New-GPTImage.ps1 -PricingDiscovery "Image" # ROUND E: finds image models too
#
# the query uses contains(...) on productName OR skuName OR meterName,
# because Microsoft sometimes puts the model name only in skuName or meterName
# (e.g. productName="Azure OpenAI" generic, skuName="GPT-Image-2 Outpt Img").
# So "Image" previously returned 0 results; now it returns all the meters that have
# "Image" in any one of the three fields. Results deduplicated by meterId.
# ----- DECRYPTLOG: prints the decrypted log to stdout (greppable) and exits -----
if ($DecryptLog) {
    if (-not (Test-Path $script:LogFile)) {
        Write-Log (T 'logenc.no_log' $script:LogFile) -Level ERROR
        exit 1
    }
    foreach ($dl in (Get-DecryptedLogLines -Path $script:LogFile)) { Write-Output $dl }
    exit 0
}

if ($PricingDiscovery -ne "__NOTSET__") {
    # The parameter was passed (with or without a value). If empty/whitespace,
    # I show a clear usage instead of running a useless query.
    if (-not $PricingDiscovery -or $PricingDiscovery.Trim() -eq "") {
        Write-Log (T 'pricing.discovery_cli_usage') -Level WARN
        exit 0
    }
    Write-Log (T 'pricing.discovery_cli_intro' $PricingDiscovery)
    $keyword = $PricingDiscovery.Trim()
    $keywordEsc = $keyword.Replace("'", "''")
    # OR on 3 fields of the Retail catalog, CASE-INSENSITIVE via tolower.
    # L'API Retail OData e' case-sensitive su contains: cercare "FLUX" non
    # matcherebbe "Flux 2 Pro Initial MP". Normalizziamo entrambi i lati a minuscolo.
    $keywordLower = $keywordEsc.ToLower()
    $filter = "contains(tolower(productName), '$keywordLower') or contains(tolower(skuName), '$keywordLower') or contains(tolower(meterName), '$keywordLower')"

    try {
        $items = Invoke-PricingApiQuery -Filter $filter -TimeoutSec 30 -CurrencyCode "USD"
    } catch {
        Write-Log "Discovery: API error - $($_.Exception.Message)" -Level ERROR
        exit 1
    }

    if (-not $items -or $items.Count -eq 0) {
        Write-Log (T 'pricing.discovery_cli_no_results') -Level WARN
        exit 0
    }

    # Deduplication by meterId (the OR on 3 fields can return the same record several times)
    $uniqueItems = $items | Sort-Object meterId -Unique

    Write-Log (T 'pricing.discovery_cli_results' $uniqueItems.Count $keyword)
    Write-Host ""

    # On-screen table: serviceName | productName | skuName | meterName | unitPrice | unitOfMeasure | armRegion
    # Mostra anche skuName per aiutare l'utente a costruire i productHints/meterRoles giusti.
    $tableData = $uniqueItems | Select-Object `
        @{N='serviceName';   E={$_.serviceName}}, `
        @{N='productName';   E={$_.productName}}, `
        @{N='skuName';       E={$_.skuName}}, `
        @{N='meterName';     E={$_.meterName}}, `
        @{N='unitPrice';     E={$_.unitPrice}}, `
        @{N='unitOfMeasure'; E={$_.unitOfMeasure}}, `
        @{N='armRegion';     E={$_.armRegionName}} | `
        Sort-Object serviceName, productName, skuName, meterName, armRegion

    # Formats as a compact table (wide to accommodate skuName)
    $tableData | Format-Table -AutoSize | Out-String -Width 260 | Write-Host

    # Saves the complete JSON
    $discoveryFile = Join-Path $PSScriptRoot "New-GPTImage.pricing-discovery-cli.json"
    try {
        $discoveryObj = [PSCustomObject]@{
            generated_at = (Get-Date).ToString("yyyy-MM-dd HH:mm:ss", [System.Globalization.CultureInfo]::InvariantCulture)
            keyword      = $keyword
            filter       = $filter
            results_count = $uniqueItems.Count
            results      = $uniqueItems
        }
        $discoveryObj | ConvertTo-Json -Depth 10 | Set-Content -Path $discoveryFile -Encoding UTF8
        Write-Log (T 'pricing.discovery_cli_saved' $discoveryFile)
    } catch {
        Write-Log "Discovery: save error - $($_.Exception.Message)" -Level WARN
    }

    Write-Log (T 'pricing.discovery_cli_completed')
    exit 0
}

# =================================================================
# PULIZIA LOG
# =================================================================

# =================================================================
# CONFIGURATION LOADING
# =================================================================
if (-not (Test-Path $script:ConfigFile)) {
    Write-Log (T 'setup.conf_not_found' $script:ConfigFile) -Level ERROR
    Write-Log (T 'setup.run_setup_hint') -Level ERROR
    exit 1
}

try {
    $configRaw = Get-Content $script:ConfigFile -Raw -Encoding UTF8
    $config    = $configRaw | ConvertFrom-Json -ErrorAction Stop

    # Automatic migration on non-Windows systems: the historical confs have "b64:"
    # keys (obfuscated, not encrypted). I re-protect them as "aes:" (AES-256-GCM with
    # a per-user master key) and save the conf, logging the outcome.
    if (-not $script:IsWin) {
        $aesMigrated = 0
        foreach ($mProp in @($config.models.PSObject.Properties)) {
            $mv = $mProp.Value
            if ($mv.apiKey -and ([string]$mv.apiKey).StartsWith("b64:")) {
                $plainK = Unprotect-ApiKey ([string]$mv.apiKey)
                if ($plainK) {
                    $newK = Protect-ApiKey -PlainText $plainK
                    if ($newK -and $newK.StartsWith("aes:")) { $mv.apiKey = $newK; $aesMigrated++ }
                }
            }
        }
        if ($aesMigrated -gt 0) {
            try {
                $config | ConvertTo-Json -Depth 10 | Set-Content -Path $script:ConfigFile -Encoding UTF8
                Write-Log (T 'apikey.aes_migrated' $aesMigrated)
            } catch {
                Write-Log (T 'apikey.aes_migrate_save_failed' ($_.Exception.Message)) -Level WARN
            }
        }
    }

    # Log file encryption (logEncryption conf option, disabled by default):
    # if active, it converts any clear-text log and from here on every line
    # written to the file is encrypted (the console stays in clear).
    if ($config.logEncryption -eq $true) {
        Enable-LogEncryption
    }

    # Auto-protection of the text model's API key: the user can paste it
    # in clear in the .conf and at the first launch it is encrypted (DPAPI on Windows, AES
    # elsewhere) and re-saved, as happens for the image models' keys.
    if ($config.textModel -and $config.textModel.apiKey -and
        -not (Test-ApiKeyEncoded ([string]$config.textModel.apiKey))) {
        $tmProtected = Protect-ApiKey -PlainText ([string]$config.textModel.apiKey)
        if ($tmProtected) {
            $config.textModel.apiKey = $tmProtected
            try {
                $config | ConvertTo-Json -Depth 10 | Set-Content -Path $script:ConfigFile -Encoding UTF8
                Write-Log (T 'textmodel.key_protected')
            } catch {
                Write-Log (T 'apikey.aes_migrate_save_failed' ($_.Exception.Message)) -Level WARN
            }
        }
    }

    # ----- DESCRIBEIMAGE: image-to-prompt with the multimodal model -----
    # It must be executed HERE, after the config loading (it needs $config.textModel
    # set): if placed before the load, textModel would be empty.
    if ($DescribeImage -ne "") {
        # Essential informative banner (like the other flows): without it, the command
        # would seem mute until the model's response. The FIRST line is the version
        # (header.banner), for consistency with the main flow and the other commands.
        Write-Log (T 'header.banner' $script:ScriptVersion)
        $sysInfoD = Get-SystemInfo
        Write-Log (T 'header.system_info' $sysInfoD.OS $sysInfoD.Version $sysInfoD.CPU $sysInfoD.RAM_GB $sysInfoD.Disk_GB)
        Write-Log (T 'header.path_script' $PSScriptRoot)
        Write-Log (T 'header.file_config' $script:ConfigFile)
        Write-Log (T 'header.lang_file' $script:LangFile)
        # In the message I include the name of the chosen text/multimodal model, so
        # the user knows with which model the analysis was done.
        Write-Log (T 'describe.analyzing' ([string]$config.textModel.model) $DescribeImage)
        # Describe DEPENDS on the text (multimodal) model: if it is not available,
        # a blocking ERROR (like storyboard, unlike optimize/negative).
        $tmCheck = Test-TextModelAvailable -Config $config
        if (-not $tmCheck.Available) {
            Write-Log (T 'textmodel.unavailable_stop' (T $tmCheck.Reason)) -Level ERROR
            exit 1
        }
        # The output language follows that of the script (-Lang or the conf default).
        $describeResult = Invoke-TextModelDescribe -ImagePath $DescribeImage -Config $config -Language $script:CurrentLang
        if ($describeResult -and $describeResult.Text) {
            # The description also in the log as [INFO] (besides on stdout), so it stays
            # tracked. The generated prompt is subject to privacy like the other prompts.
            Write-PromptLog -LabelKey 'describe.result_label' -PromptText $describeResult.Text -Kind "support" -Config $config
            Write-Log (T 'describe.done')
            # Text cost of the describe operation ([COST] Describe) + telemetry.
            if (([int]$describeResult.InputTokens + [int]$describeResult.OutputTokens) -gt 0) {
                $tc = Write-TextCostLog -InputTokens ([int]$describeResult.InputTokens) -OutputTokens ([int]$describeResult.OutputTokens) `
                        -Config $config -Operation "describe" -Verbosity $Verbosity -DefaultCurrency ([string]$config.defaultCurrency)
                if ($tc) { Send-TextCostTelemetry -Config $config -TextCost $tc -TextModel ([string]$config.textModel.model) }
            }
            # stdout: only the description (for programmatic use / pipe).
            Write-Output $describeResult.Text
            exit 0
        }
        exit 1
    }
}
catch {
    Write-Log (T 'config.parse_error' $script:ConfigFile ($_.Exception.Message)) -Level ERROR
    exit 1
}

# =================================================================
# MANDATORY KEYS VALIDATION
# =================================================================
$requiredKeys = @(
    "defaultModel","models",
    "defaultSize","defaultQuality","defaultOutputFolder",
    "defaultOutputCompression","defaultModeration","defaultFormat",
    "fileNameTemplate","maxRetries"
)

$missingKeys = @()
foreach ($key in $requiredKeys) {
    if ($null -eq $config.$key) { $missingKeys += $key }
}

if ($missingKeys.Count -gt 0) {
    Write-Log (T 'config.missing_keys' ($missingKeys -join ', ')) -Level ERROR
    exit 1
}

# =================================================================
# shortName VALIDATION (-Analytics charts consistency)
# =================================================================
# The per-model charts of -Analytics use the shortName as a label. If two
# models share the SAME shortName, their bars turn out indistinguishable
# (a problem mirroring the "phantom bars" already handled via canonicalization of the
# model name in Invoke-Analytics). Here I warn at startup if the config has
# duplicate or empty shortNames. It is a non-fatal WARN: it does not block the execution (the
# script stays usable even with imperfect shortNames), but it signals the problem
# once and clearly, with the name of the models involved.
if ($config.models) {
    $shortNameMap = @{}   # shortName (lower, trim) -> lista nomi modello che lo usano
    foreach ($mProp in @($config.models.PSObject.Properties)) {
        $mName = $mProp.Name
        $sn = $null
        if ($mProp.Value -and ($mProp.Value.PSObject.Properties.Name -contains 'shortName')) {
            $sn = [string]$mProp.Value.shortName
        }
        if ([string]::IsNullOrWhiteSpace($sn)) {
            # shortName absent or empty: not fatal, but I flag it (the analytics
            # will fall back to the full model name as a label).
            Write-Log (T 'config.shortname_empty' $mName) -Level WARN
            continue
        }
        $key = $sn.Trim().ToLowerInvariant()
        if (-not $shortNameMap.ContainsKey($key)) {
            $shortNameMap[$key] = [System.Collections.Generic.List[string]]::new()
        }
        [void]$shortNameMap[$key].Add($mName)
    }
    foreach ($kv in $shortNameMap.GetEnumerator()) {
        if ($kv.Value.Count -gt 1) {
            # Same shortName on several models: I warn with a list of the models involved.
            Write-Log (T 'config.shortname_duplicate' $kv.Key ($kv.Value -join ', ')) -Level WARN
        }
    }
}

# =================================================================
# PULIZIA LOG
# =================================================================
$MaxLogSizeMB    = if ($config.maxLogFileSizeMB -and [int]$config.maxLogFileSizeMB -gt 0) {
                       [int]$config.maxLogFileSizeMB
                   } else { 5 }
$LogRetentionDays = if ($config.logRetentionDays -and [int]$config.logRetentionDays -gt 0) {
                       [int]$config.logRetentionDays
                   } else { 365 }

Invoke-LogCleanup -MaxSizeMB $MaxLogSizeMB -RetentionDays $LogRetentionDays

if ($script:PendingLogCleanupMessage) {
    Write-Log $script:PendingLogCleanupMessage
}

# =================================================================
# REFRESH LANGUAGE PACK (se config.language differisce dall'early loading)
# =================================================================
# At this point we have read the config. If the user did NOT pass an explicit -Lang
# but set language in the .conf, and that language differs from the language used
# at the early loading, we reload. Skipping if -Lang was explicit (already used).
if ((-not $Lang -or $Lang.Trim() -eq "") -and $config.language -and $config.language -ne $earlyLang) {
    # I validate the renderability of the language from config (console already configured
    # at the early loading, so -SkipConsoleSetup). If the console is not UTF-8
    # capable, EffectiveLang falls back to "en"; any WARN (RTL/CJK) is logged.
    $cfgLangCheck = Test-Prerequisites -RequestedLang $config.language -SkipConsoleSetup
    $effectiveCfgLang = if ($cfgLangCheck.EffectiveLang) { $cfgLangCheck.EffectiveLang } else { $config.language }
    Import-LanguagePack -LangFilePath $script:LangFile -RequestedLang $effectiveCfgLang
    Write-PrereqMessages -Messages $cfgLangCheck.Messages
}

# =================================================================
# INIZIALIZZAZIONE API KEYS (encoding)
# =================================================================
# =================================================================
# PRICING STRUCTURE MIGRATION 
# =================================================================
# Automatically migrates the .conf structure from the old form (flat pricing,
# without pricingMapping) to the new structure with pricingMapping and pricingUpdate.
# Idempotent: if the conf is already migrated it does nothing. The migration is silent except for errors.
$migrated = Convert-ConfigToNewPricingStructure -Config $config -ConfigPath $script:ConfigFile
if ($migrated) {
    # We log only as INFO without details: the user sees the changes anyway
    # nel .conf se le va a controllare. Non fa rumore inutile.
    Write-Log "Config migrato: aggiunta struttura pricingMapping/pricingUpdate"
}

# === ENUMERATED PARAMETERS NORMALIZATION (case-insensitive) ===
# The models' APIs (e.g. gpt-image) accept the enumerated values ONLY in lowercase
# ('high' yes, 'High' no -> HTTP 400). The user, however, can write them in any
# case (-Quality High). I normalize here, ONCE and BEFORE any use (the
# -Auto block, validations, API payload), so the whole downstream flow works on
# canonical values. It concerns the parameters with a fixed value set:
#   - Quality: low|medium|high|auto
#   - Moderation: low|auto
#   - Background: auto|opaque|transparent
#   - Format: png|jpg|jpeg|webp
#   - Size: the lowercase serves to normalize the 'x' (1024X1024 -> 1024x1024)
# I do NOT touch Prompt, paths, or other free values: only the enumerated ones.
if ($Quality    -and $Quality.Trim()    -ne "") { $Quality    = $Quality.Trim().ToLower() }
if ($Moderation -and $Moderation.Trim() -ne "") { $Moderation = $Moderation.Trim().ToLower() }
if ($Background -and $Background.Trim() -ne "") { $Background = $Background.Trim().ToLower() }
if ($Format     -and $Format.Trim()     -ne "") { $Format     = $Format.Trim().ToLower() }
if ($Size       -and $Size.Trim()       -ne "") { $Size       = $Size.Trim().ToLower() }

# I verify that all the apiKeys of the active models are encoded. If I find a
# key in clear, I ask the user to re-enter it via a hidden prompt, then
# encoded with DPAPI (Windows) or Base64 (Unix) and saved in the .conf.
# Skip in obvious non-interactive modes (Setup, Help, Version have already exited
# before here, so we are always in an interactive context here).
Initialize-ApiKeys -Config $config -ConfigPath $script:ConfigFile

# =================================================================
# MODEL RESOLUTION
# =================================================================
# Model selection priority:
# 1. -Auto switch: automatic selection based on the requested parameters + cost
# 2. -Model <name>: the user specifies the model explicitly
# 3. defaultModel: fallback to the default model in config







# This section (-Auto selection, model resolution, validation of
# endpoint/apiKey/deployment, key decoding) is needed ONLY by the commands that
# actually use a model: image generation and -CheckEndpoint.
# The "task-oriented" commands that do NOT contact a specific model (-Analytics and
# -Gallery process local data) skip it: for them choosing and validating a
# model would be useless and, worse, could block them if the default model
# avesse apiKey/endpoint non configurati ma l'utente volesse solo le analytics.
$isNonModelCommand = $Analytics -or $Gallery -or $IaC

if (-not $isNonModelCommand) {

if ($Auto -and $Auto.Trim() -ne "") {
    $needsInp = ($Mask -and $Mask.Trim() -ne "")
    $needsIF  = ($InputFidelity -and $InputFidelity.Trim() -ne "")
    $needsBg  = ($Background -and $Background.Trim() -ne "" -and $Background -ne "auto")

    # refresh dati di supporto per -Auto Quality/Time/Cost.
    # The defaults here are taken from the .conf because the standard resolution
    # (line 4157 further below) is after this block.
    $effectiveQuality = if ($Quality -and $Quality.Trim() -ne "") { $Quality } else { [string]$config.defaultQuality }
    $effectiveSize    = if ($Size -and $Size.Trim() -ne "")       { $Size }    else { [string]$config.defaultSize }

    switch ($Auto) {
        "Quality" {
            # Refresh leaderboard arena.ai (cache 7gg, bypassata da -Force)
            Update-QualityRatingsFromArena -Config $config -ConfigPath $script:ConfigFile -Force:$Force.IsPresent | Out-Null
        }
        "Time" {
            # Refresh mediane tempi dal log (cache 7gg, bypassata da -Force).
            # The quality/size parameters filter the records for a fair comparison.
            Update-SpeedRatingsFromLog -Config $config -ConfigPath $script:ConfigFile `
                                       -Quality $effectiveQuality -Size $effectiveSize `
                                       -LogFilePath $script:LogFile -Force:$Force.IsPresent | Out-Null
        }
        "Cost" {
            # -Auto Cost: the prices are already updated by -ModelPrice (own cache).
            # Se l'utente ha passato -Force, eseguiamo internamente l'aggiornamento prezzi
            # come scorciatoia (vs farlo separatamente con -ModelPrice Force).
            if ($Force.IsPresent) {
                Write-Log (T 'auto.cost_force_triggers_modelprice')
                Update-ModelPricing -Config $config -ConfigPath $script:ConfigFile -Force
            }
        }
    }

    # The gallery votes folder is the images folder. At this point of the flow
    # $OutputFolder might not be resolved yet (the resolution to the default
    # happens further on, after this block): if empty, I fall back to the conf's defaultOutputFolder,
    # which is the same folder where the gallery writes gallery_ratings.json.
    # Without this early resolution, -RatingsFolder would arrive empty and the votes
    # would NEVER be read when the user does not pass an explicit -OutputFolder.
    $ratingsFolderResolved = if ($OutputFolder -and $OutputFolder.Trim() -ne "") {
        $OutputFolder
    } else {
        [string]$config.defaultOutputFolder
    }

    # USD/EUR rate from the conf (the full resolution with refresh happens further on):
    # for the costScore I compare the costs in USD, so the rate is not critical here;
    # lo passo solo per completezza del breakdown.
    $autoEurRate = if ($null -ne $config.usdToEurRate -and [double]$config.usdToEurRate -gt 0) {
        [double]$config.usdToEurRate
    } else { 1.0 }

    $autoChoice = Select-AutoModel -Config $config `
                                   -Strategy $Auto `
                                   -NeedsInpainting $needsInp `
                                   -NeedsInputFidelity $needsIF `
                                   -NeedsBackground $needsBg `
                                   -RatingsFolder $ratingsFolderResolved `
                                   -EffectiveQuality $effectiveQuality `
                                   -EffectiveSize $effectiveSize `
                                   -PromptText $Prompt `
                                   -EurRate $autoEurRate
    if (-not $autoChoice) {
        exit 1
    }
    $selectedModelName = $autoChoice
} else {
    $selectedModelName = if ($Model -and $Model.Trim() -ne "") {
        $Model
    } else {
        $config.defaultModel
    }
}

if (-not $config.models.$selectedModelName) {
    $available = @($config.models | Get-Member -MemberType NoteProperty | Select-Object -ExpandProperty Name)
    Write-Log (T 'model.not_defined' $selectedModelName ($available -join ', ')) -Level ERROR
    exit 1
}

# Case-insensitive normalization of the model name: the user can type
# any upper/lowercase, but from here on (metadata, log, .stat, .cost,
# gallery) ONLY the canonical name as written in the .conf is used.
$mCanonical = @($config.models.PSObject.Properties.Name) |
              Where-Object { $_ -ieq $selectedModelName } | Select-Object -First 1
if ($mCanonical) { $selectedModelName = [string]$mCanonical }

$modelConfig = $config.models.$selectedModelName

# editEndpoint is NO LONGER a mandatory field. It is relevant only for the
# openai-images schema when edit is used; mai-images does not use it (no edit) and bfl-flux
# uses the same endpoint as generation. We require only the always-necessary fields.
$modelRequired = @("endpoint","apiKey","deployment")
foreach ($f in $modelRequired) {
    if ($null -eq $modelConfig.$f) {
        Write-Log (T 'model.field_missing' $f $selectedModelName) -Level ERROR
        exit 1
    }
}

if (-not $modelConfig.endpoint -or $modelConfig.endpoint.Trim() -eq "") {
    Write-Log (T 'model.empty_endpoint' $selectedModelName) -Level ERROR
    exit 1
}
# Validation of the endpoint FORMAT: it must be a well-formed http(s) URL.
# It intercepts typos in the .conf (e.g. missing "https://", or spaces) before
# attempting the connection, which would fail with an unclear network error.
$epTrim = $modelConfig.endpoint.Trim()
$epValid = $false
try {
    $epUri = [System.Uri]$epTrim
    $epValid = ($epUri.Scheme -eq 'http' -or $epUri.Scheme -eq 'https') -and $epUri.IsAbsoluteUri
} catch { $epValid = $false }
if (-not $epValid) {
    Write-Log (T 'model.invalid_endpoint_url' $selectedModelName $epTrim) -Level ERROR
    exit 1
}
if (-not $modelConfig.apiKey -or $modelConfig.apiKey.Trim() -eq "") {
    Write-Log (T 'model.no_apikey' $selectedModelName) -Level ERROR
    exit 1
}

$Endpoint         = $modelConfig.endpoint       # URL completo dell'endpoint /images/generations
# The apiKey in the .conf can be in clear or encoded (enc:/b64:). I decode it
# to get the clear value to use in the API call.
$rawApiKey        = $modelConfig.apiKey
$ApiKey           = Unprotect-ApiKey -EncodedValue $rawApiKey
if (-not $ApiKey) {
    Write-Log (T 'apikey.decode_failed_for_model' $selectedModelName) -Level ERROR
    exit 1
}
$Deployment       = $modelConfig.deployment     # Name of the Azure deployment (can differ from the logical name)
$ModelLogicalName = $selectedModelName          # Nome "amichevole" del modello (usato per logging e .stat)

# --- Per-model feature flags ---
# Each model declares in config which optional features it supports. The script consults
# these flags before sending the corresponding parameter. Models that do not declare
# the flag are assumed as "not supported" (safe default = $false).
#
# - supportsInpainting: the model accepts the 'mask' parameter for localized editing
# - supportsInputFidelity:the model accepts the 'input_fidelity' parameter (low|high)
# - supportsBackground: the model accepts the 'background' parameter (auto|opaque|transparent)
$supportsInpainting    = if ($null -ne $modelConfig.supportsInpainting)    { [bool]$modelConfig.supportsInpainting }    else { $false }
$supportsInputFidelity = if ($null -ne $modelConfig.supportsInputFidelity) { [bool]$modelConfig.supportsInputFidelity } else { $false }
$supportsBackground    = if ($null -ne $modelConfig.supportsBackground)    { [bool]$modelConfig.supportsBackground }    else { $false }

# --- schema API e supporto edit ---
# apiSchema: identifies the model's API "dialect". It determines the auth header,
# the body structure and the dimension handling. Values:
# "openai-images" (default): Azure OpenAI gpt-image-* and recent MAI (size "WxH",
# quality/moderation/output_format, edit via /edits multipart)
# "mai-images": Microsoft MAI "classic" (api-key header, separate
# width/height, minimal body, ONLY generation)
# "bfl-flux": Black Forest Labs FLUX (Authorization: Bearer header,
# separate width/height, edit on the SAME endpoint with
# base64 reference input_image/input_image_2/...)
# authMode (optional): "api-key" | "bearer". Overrides the schema's default auth
# header. It is needed for models of the same family/schema but with a different auth
# (e.g. recent MAI use the openai-images schema but require 'Bearer' on Foundry).
# If absent, the schema's default is used (openai/mai = api-key, flux = bearer).
# supportsEdit: if $false, the model rejects -InputImages and -Mask (text-to-image-only
# model, e.g. MAI). It generalizes: a model without an edit endpoint must not
# accept reference images. When a model adds edit, it will be enough to
# set supportsEdit=true (and for openai-images configure editEndpoint).
$apiSchema    = if ($modelConfig.apiSchema -and $modelConfig.apiSchema.Trim() -ne "") { $modelConfig.apiSchema.Trim() } else { "openai-images" }
# authMode: the model's auth header. Read from the .conf if present ("api-key"|"bearer"),
# otherwise "" = uses the per-schema default decided inside Invoke-ImageGeneration.
$authMode     = if ($modelConfig.authMode -and $modelConfig.authMode.Trim() -ne "") { $modelConfig.authMode.Trim().ToLower() } else { "" }
$supportsEdit = if ($null -ne $modelConfig.supportsEdit) { [bool]$modelConfig.supportsEdit } else { $true }

# Guard: if the model does not support edit but the user passed reference
# images or a mask, we block immediately with a clear message.
if (-not $supportsEdit) {
    if ($InputImages -and $InputImages.Count -gt 0) {
        Write-Log (T 'edit.model_no_edit_support' $selectedModelName) -Level ERROR
        exit 1
    }
    if ($Mask -and $Mask.Trim() -ne "") {
        Write-Log (T 'edit.model_no_edit_support' $selectedModelName) -Level ERROR
        exit 1
    }
}

}   # fine blocco "if (-not $isNonModelCommand)" — selezione/validazione modello

# --- Per-model pricing ---
# new pricing.meters schema with 6/2 keys. The scalar variables
# $priceInputUsd / $priceOutputUsd / $priceImageUsd are kept for backward-compat
# with the ex-ante estimate and the -Auto sortBy=Cost, deriving them from the relevant meters.
# The real cost calculation uses $modelPricing directly via Get-CostBreakdown.
#
# Back-compat mapping:
# priceInputUsd = inputText (or input for MAI) -- "main" input price
# priceOutputUsd = outputText (or output for MAI) -- text/columnar output price
# priceImageUsd = outputImage (or input for MAI) -- "main" output image price,
# used by the ex-ante estimate and the cost sort
$modelPricing = $null
$priceInputUsd  = 0.0
$priceOutputUsd = 0.0
$priceImageUsd  = 0.0
if (-not $isNonModelCommand) {
$modelPricing = $modelConfig.pricing
if ($modelPricing -and ($modelPricing.PSObject.Properties.Name -contains 'meters') -and $modelPricing.meters) {
    $m = $modelPricing.meters
    # AOAI labeled
    if ($m.PSObject.Properties.Name -contains 'inputText'  -and $null -ne $m.inputText)  { $priceInputUsd  = [double]$m.inputText }
    if ($m.PSObject.Properties.Name -contains 'outputText' -and $null -ne $m.outputText) { $priceOutputUsd = [double]$m.outputText }
    if ($m.PSObject.Properties.Name -contains 'outputImage' -and $null -ne $m.outputImage) { $priceImageUsd  = [double]$m.outputImage }
    # MAI columnar (overrides with global values)
    if ($m.PSObject.Properties.Name -contains 'input'  -and $null -ne $m.input)  { $priceInputUsd  = [double]$m.input }
    if ($m.PSObject.Properties.Name -contains 'output' -and $null -ne $m.output) {
        $priceOutputUsd = [double]$m.output
        # For MAI the "image price" coincides with output (single meter)
        if ($priceImageUsd -eq 0.0) { $priceImageUsd = [double]$m.output }
    }
}
# Back-compat: if the .conf still uses the old 3 flat fields (pre-migration),
# I read them as a fallback. Convert-ConfigToNewPricingStructure should have already
# converted them, but we keep this safety net for manually-edited .conf
# editati.
if ($priceInputUsd -eq 0.0 -and $priceOutputUsd -eq 0.0 -and $priceImageUsd -eq 0.0 -and $modelPricing) {
    if ($modelPricing.PSObject.Properties.Name -contains 'inputTokensPerMillionUsd'  -and $null -ne $modelPricing.inputTokensPerMillionUsd)  { $priceInputUsd  = [double]$modelPricing.inputTokensPerMillionUsd }
    if ($modelPricing.PSObject.Properties.Name -contains 'outputTokensPerMillionUsd' -and $null -ne $modelPricing.outputTokensPerMillionUsd) { $priceOutputUsd = [double]$modelPricing.outputTokensPerMillionUsd }
    if ($modelPricing.PSObject.Properties.Name -contains 'imageTokensPerMillionUsd'  -and $null -ne $modelPricing.imageTokensPerMillionUsd)  { $priceImageUsd  = [double]$modelPricing.imageTokensPerMillionUsd }
}

}   # fine blocco pricing per-modello (solo comandi che usano il modello)

# --- USD -> EUR exchange rate ---
# Manually updatable in config ("usdToEurRate" key). If absent or invalid,
# fallback to 0.92 (conservative value, May 2026). We do not download the live rate
# because it fluctuates little daily and introduces a useless external dependency.
$UsdToEurRate = if ($null -ne $config.usdToEurRate -and [double]$config.usdToEurRate -gt 0) {
    [double]$config.usdToEurRate
} else { 0.92 }

# =================================================================
# CONFIG VALUES VALIDATION
# =================================================================
if ($config.defaultOutputCompression -isnot [int] -and $config.defaultOutputCompression -isnot [long] -and $config.defaultOutputCompression -isnot [double]) {
    Write-Log (T 'validation.compression_not_numeric') -Level ERROR
    exit 1
}
if ([int]$config.defaultOutputCompression -lt 0 -or [int]$config.defaultOutputCompression -gt 100) {
    Write-Log (T 'validation.compression_range') -Level ERROR
    exit 1
}

# =================================================================
# DEFAULT PARAMETERS RESOLUTION (parameters > config > fallback)
# =================================================================
# UNIFORM priority logic for the whole script: the value passed on the command
# line always takes precedence. If not specified, we look at the config. If the config too
# does not define it (or is null), a safe hard-coded fallback is used.
# This allows temporarily overriding any default without modifying the config.
if (-not $Size -or $Size.Trim() -eq "")               { $Size = $config.defaultSize }                                                          # es. "1024x1024"
if (-not $Quality -or $Quality.Trim() -eq "")         { $Quality = $config.defaultQuality }                                                    # "low" | "medium" | "high"
if (-not $OutputFolder -or $OutputFolder.Trim() -eq ""){ $OutputFolder = $config.defaultOutputFolder }                                         # cartella di destinazione delle immagini
if (-not $Format -or $Format.Trim() -eq "")           { $Format = $config.defaultFormat }                                                      # "png" | "jpg" | "webp"

# For WEBP: we do NOT do an upfront check via GetImageEncoders, because on Windows
# the codecs installed via the Microsoft Store (e.g. "WebP Image Extensions") are
# exposed via WIC but NOT via GDI+ ImageCodecInfo. The pessimistic check would do a
# useless fallback to PNG even when WEBP would work. We let the
# save be attempted: if Image.Save fails, we will fall back to PNG inside the
# save routine with a precise WARN.
if (-not $Moderation -or $Moderation.Trim() -eq "")   { $Moderation = $config.defaultModeration }                                              # "auto" | "low"
if (-not $Background -or $Background.Trim() -eq "")   {
    $Background = if ($config.defaultBackground) { $config.defaultBackground } else { "auto" }                                                 # "auto" | "opaque" | "transparent"
}

# I re-normalize to lowercase AFTER the resolution from the .conf defaults: if the user
# wrote a default with non-standard case in the .conf (e.g. defaultQuality "High"),
# here I make it canonical anyway, so the API does not reject the value (HTTP 400).
if ($Quality)    { $Quality    = $Quality.ToString().ToLower() }
if ($Moderation) { $Moderation = $Moderation.ToString().ToLower() }
if ($Background) { $Background = $Background.ToString().ToLower() }
if ($Format)     { $Format     = $Format.ToString().ToLower() }
if ($Size)       { $Size       = $Size.ToString().ToLower() }

# Metadata: the CLI parameter is a "True"/"False" string (handier than $true/$false).
# Empty string = "not passed": in that case we read the value from the config. Otherwise
# we convert the string to bool (tolerant of variants: True/1/yes/on = true).
if ($Metadata -eq "") {
    $useMetadata = if ($null -ne $config.metadata) { [bool]$config.metadata } else { $false }
} else {
    $useMetadata = ($Metadata -match '^(?i:true|1|yes|on)$')
}

# Threads: range 1-5 for the parallel batch. Max limit=5 so as not to saturate the Foundry rate limit.
# $Threads = 0 means "not specified on CLI", so we read from the config.
if ($Threads -le 0) {
    $effectiveThreads = if ($config.batchThreads -and [int]$config.batchThreads -gt 0) {
        [int]$config.batchThreads
    } else { 1 }
} else {
    $effectiveThreads = $Threads
}
if ($effectiveThreads -lt 1) { $effectiveThreads = 1 }
if ($effectiveThreads -gt 5) { $effectiveThreads = 5 }

# Format "base64" e' una compatibilita' legacy con vecchi script: oggi e' deprecato
# in favore di -OutputMode base64 (che funziona con qualsiasi Format).
if ($Format -eq "base64") {
    Write-Log (T 'validation.format_base64_deprecated') -Level WARN
    $OutputMode = "base64"
    $Format = "png"
}

$MaxRetries   = [int]$config.maxRetries          # Numero massimo di tentativi in caso di errori HTTP transitori (429, 500, 503)
$FileTemplate = $config.fileNameTemplate          # Pattern del nome file output, con placeholder {timestamp}, {index}, {promptHash}

# Maximum size of the long side for the input images. Larger images
# are resized keeping the aspect ratio. Default 4096px (Foundry limit).
$MaxImageDimension = if ($config.defaultMaxImageDimension -and [int]$config.defaultMaxImageDimension -gt 0) {
    [int]$config.defaultMaxImageDimension
} else { 4096 }

# AREA constraint on the reference images per model. Some models (e.g. MAI)
# accept as input only images within a certain total area (maxArea in
# operationalParams). Without this limit, a large reference image (e.g.
# 4000x3000 = 12 MP) is sent intact and the server rejects it or goes into TIMEOUT
# (408) trying to process it. If the model declares maxArea > 0, we use it to
# ridimensionare le reference entro quell'area (mantenendo l'aspect ratio).
$MaxImageArea = 0
if ($modelConfig.operationalParams -and $modelConfig.operationalParams.maxArea) {
    $MaxImageArea = [int]$modelConfig.operationalParams.maxArea
}

# HTTP timeout for the API requests. Foundry can take 5+ minutes for
# complex generations (gpt-image-2 quality=high), so 10 minutes is a good default.
$RequestTimeoutMinutes = if ($config.requestTimeoutMinutes -and [int]$config.requestTimeoutMinutes -gt 0) {
    [int]$config.requestTimeoutMinutes
} else { 10 }

# Parameters of the time estimation engine (kNN on .stat):
# - $MaxStatsRecords: how many .stat rows to read at startup (the most recent)
# - $KnnK: number of neighbors to consider in the kNN regression
# - $KnnMinRecords: minimum threshold to activate kNN (below, we go to segment or EMA fallback)
# - $SegmentMinRecords: minimum threshold for the "homogeneous segment" fallback (size+quality match)
$MaxStatsRecords   = if ($config.maxStatsRecordsToRead -and [int]$config.maxStatsRecordsToRead -gt 0) { [int]$config.maxStatsRecordsToRead } else { 1000 }
$KnnK              = if ($config.knnK -and [int]$config.knnK -gt 0) { [int]$config.knnK } else { 5 }
$KnnMinRecords     = if ($config.knnMinRecords -and [int]$config.knnMinRecords -gt 0) { [int]$config.knnMinRecords } else { 20 }
$SegmentMinRecords = if ($config.segmentMinRecords -and [int]$config.segmentMinRecords -gt 0) { [int]$config.segmentMinRecords } else { 5 }

# =================================================================
# PARAMETERS VALIDATION
# =================================================================
# This whole section validates the GENERATION parameters (size, format, moderation,
# background, input_fidelity, mask) against the chosen model's capabilities. It is needed
# only by the commands that generate images: -Analytics and -Gallery have no active
# model and do not pass through here.
if (-not $isNonModelCommand) {

# EXISTENCE validation of the files passed as input by the user. It must be done BEFORE
# any operation: if a file does not exist, failing immediately with a clear message
# is much better than running into a cryptic Get-Content/ReadAllBytes error further
# along the flow. We use -PathType Leaf to make sure it is a file, not a
# folder. Each missing file produces an [ERROR] and a controlled exit (exit 1).
$missingInputs = @()
if ($PromptFile -and $PromptFile.Trim() -ne "") {
    if (-not (Test-Path -LiteralPath $PromptFile -PathType Leaf)) {
        $missingInputs += @{ Kind = 'prompt'; Path = $PromptFile }
    }
}
if ($Batch -and $Batch.Trim() -ne "") {
    if (-not (Test-Path -LiteralPath $Batch -PathType Leaf)) {
        $missingInputs += @{ Kind = 'batch'; Path = $Batch }
    }
}
if ($Mask -and $Mask.Trim() -ne "") {
    if (-not (Test-Path -LiteralPath $Mask -PathType Leaf)) {
        $missingInputs += @{ Kind = 'mask'; Path = $Mask }
    }
}
if ($InputImages) {
    foreach ($imgPath in @($InputImages)) {
        if (-not $imgPath -or $imgPath.Trim() -eq "") { continue }
        if (-not (Test-Path -LiteralPath $imgPath -PathType Leaf)) {
            $missingInputs += @{ Kind = 'input_image'; Path = $imgPath }
        }
    }
}
if ($missingInputs.Count -gt 0) {
    foreach ($mi in $missingInputs) {
        Write-Log (T 'validation.input_file_not_found' $mi.Kind $mi.Path) -Level ERROR
    }
    exit 1
}

# CONTENT validation of the input images via magic-bytes: a file with a
# .jpg/.png extension but non-image content (e.g. renamed text, corrupted file)
# would be rejected by the API with an unclear error. We intercept it here.
# The mask too, if present, must be a real image.
$badImages = @()
$imagesToCheck = @()
if ($InputImages) { $imagesToCheck += @($InputImages) }
if ($Mask -and $Mask.Trim() -ne "") { $imagesToCheck += $Mask }
foreach ($imgPath in $imagesToCheck) {
    if (-not $imgPath -or $imgPath.Trim() -eq "") { continue }
    $sig = Test-ImageFileSignature -Path $imgPath
    if (-not $sig.IsValid) {
        $badImages += $imgPath
    }
}
if ($badImages.Count -gt 0) {
    foreach ($bi in $badImages) {
        Write-Log (T 'validation.not_a_valid_image' $bi) -Level ERROR
    }
    exit 1
}

# Check of the benchmark export file AS EARLY AS POSSIBLE: the results of a
# benchmark are precious (they represent time and money spent on real generations),
# so we do NOT silently overwrite an existing file. If -BenchExport points to
# an already-present file and -Overwrite was not passed, we exit immediately, before
# generare alcunche', per non sprecare chiamate API. Con -Overwrite procediamo (con WARN).
$benchActiveEarly = (@($Bench) | Where-Object { $_ -and $_.Trim() -ne "" }).Count -gt 0
if ($benchActiveEarly -and $BenchExport -and $BenchExport.Trim() -ne "") {
    if (Test-Path -LiteralPath $BenchExport -PathType Leaf) {
        if (-not $Overwrite) {
            Write-Log (T 'bench.export_exists' $BenchExport) -Level ERROR
            exit 1
        } else {
            Write-Log (T 'bench.export_overwrite' $BenchExport) -Level WARN
        }
    }
    # I also verify that the destination folder exists (if a path
    # with a folder was indicated), to fail immediately instead of at the end of the benchmark during writing.
    $exportDir = [System.IO.Path]::GetDirectoryName([System.IO.Path]::GetFullPath($BenchExport))
    if ($exportDir -and -not (Test-Path -LiteralPath $exportDir -PathType Container)) {
        Write-Log (T 'bench.export_dir_missing' $exportDir) -Level ERROR
        exit 1
    }
}

if ($Size -notmatch '^\d+x\d+$') {
    Write-Log (T 'validation.size_invalid' $Size) -Level ERROR
    exit 1
}

# I retrieve the model's operationalParams block (the "matrix" of the limits declared
# in the .conf: number of images, allowed dimensions, geometric rules, etc.). It can
# be missing for models with a minimal .conf: in that case the validation imposes nothing
# and only the hardcoded historical constraints further below remain active.
$opParams = $null
if ($modelConfig -and ($modelConfig.PSObject.Properties.Name -contains 'operationalParams')) {
    $opParams = $modelConfig.operationalParams
}

# PREEMPTIVE DOWNSCALING (runs BEFORE the validation): if the requested size is too
# large for the model, I reduce it to the closest valid value. This is the
# PRIMARY agreed behavior: an excessive size does not make the script fail, it is
# reduced and we proceed (with a WARN). If reducing is not possible (e.g. aspect ratio not
# achievable within the model's constraints), $Size stays unchanged and it will be the validation
# below that blocks with a clear message. Same logic as the post-API auto-recovery
# in Invoke-ImageGeneration, but applied earlier to avoid a call destined to fail.
$downscaled = Invoke-PreemptiveSizeDownscale -OpParams $opParams -ModelName $ModelLogicalName -Size $Size
if ($downscaled -and $downscaled -ine $Size) {
    Write-Log (T 'request.size_downscale' $ModelLogicalName $Size $downscaled) -Level WARN
    $Size = $downscaled
}

# DECLARATIVE validation of the operational parameters against the model's matrix.
# It intercepts limits on number of images, allowed dimensions, dimensional rules, reference
# images, quality and format BEFORE the API call. At this point the size has
# already passed through the preemptive downscaling, so a size error here means it was NOT
# reducible. "Certain" limits (*Enforce=true field) -> blocking ERROR; "uncertain"
# limits (*Enforce=false) -> WARN (see Test-ModelOperationalParams). It complements the
# hardcoded historical constraints further below.
$refCount = if ($InputImages) { @($InputImages).Count } else { 0 }
$opCheck = Test-ModelOperationalParams -OpParams $opParams -ModelName $ModelLogicalName `
                                       -NImages $NImages -Size $Size -Quality $Quality `
                                       -Format $Format -ReferenceCount $refCount
foreach ($m in $opCheck.Messages) {
    Write-Log (T $m.Key @($m.Args)) -Level $m.Level
}
if ($opCheck.HasError) {
    # Almeno un limite certo violato: usciamo, l'utente ha gia' i dettagli nei messaggi.
    exit 1
}

# Dimensional constraints specific to the mai-images schema, as a RESIDUAL SAFETY
# NET. The MAI models require each side >= 768px and area (width*height) <=
# 1,048,576 (equivalent to 1024x1024). Note: at this point $Size has already passed through the
# preemptive downscaling (Invoke-PreemptiveSizeDownscale, above), which in almost
# all cases has already reduced it to a valid value. This block therefore intervenes
# only in the residual case in which the downscaling could NOT produce a valid
# size (e.g. aspect ratio not achievable within maxArea+minSide for this model):
# in that case we block with a clear message BEFORE calling the API, which
# would otherwise return a cryptic error. The values are redundant with those of the
# .conf operationalParams block, but we keep them hardcoded as a last defense even
# for MAI models lacking (for some reason) operationalParams.
if ($apiSchema -eq "mai-images") {
    $sizeParts = $Size -split 'x'
    $mw = [int]$sizeParts[0]
    $mh = [int]$sizeParts[1]
    $maiMinSide = 768
    $maiMaxArea = 1048576
    if ($mw -lt $maiMinSide -or $mh -lt $maiMinSide) {
        Write-Log (T 'validation.mai_size_min_side' $Size $maiMinSide) -Level ERROR
        exit 1
    }
    if (($mw * $mh) -gt $maiMaxArea) {
        Write-Log (T 'validation.mai_size_max_area' $Size ($mw * $mh) $maiMaxArea) -Level ERROR
        exit 1
    }
}

$validFormats = @("png","jpg","webp")
if ($validFormats -notcontains $Format) {
    Write-Log (T 'validation.format_invalid' $Format) -Level ERROR
    exit 1
}

$validModeration = @("auto","low")
if ($validModeration -notcontains $Moderation) {
    Write-Log (T 'validation.moderation_invalid' $Moderation) -Level ERROR
    exit 1
}

# the 'moderation' parameter is supported only by the openai-images schema
# (gpt-image-*). Gli schemi mai-images e bfl-flux non lo accettano nel body: la loro
# content safety e' gestita server-side da Azure e NON e' regolabile via API.
# If the user passed -Moderation explicitly on a model that ignores it,
# we emit a WARN so they do not expect an effect that is not there.
$supportsModeration = ($apiSchema -eq "openai-images")
$applyModeration = $supportsModeration
if (-not $supportsModeration) {
    # Warn only if the user passed -Moderation on the command line (explicit
    # override), not when it comes silently from the .conf's defaultModeration.
    if ($PSBoundParameters.ContainsKey('Moderation')) {
        Write-Log (T 'validation.moderation_unsupported' $ModelLogicalName) -Level WARN
    }
}

$validBackground = @("auto","opaque","transparent")
if ($validBackground -notcontains $Background) {
    Write-Log (T 'validation.background_invalid' $Background) -Level ERROR
    exit 1
}

# Validated background: if the model does not support custom background, we ignore it
$applyBackground = $false
if ($Background -ne "auto") {
    if ($supportsBackground) {
        $applyBackground = $true
    } else {
        Write-Log (T 'validation.background_unsupported' $ModelLogicalName) -Level WARN
    }
}

# InputFidelity: parameter applied only if the model supports it
$applyInputFidelity = $false
if ($InputFidelity -and $InputFidelity.Trim() -ne "") {
    $validFidelity = @("low","high")
    if ($validFidelity -notcontains $InputFidelity) {
        Write-Log (T 'validation.input_fidelity_invalid' $InputFidelity) -Level ERROR
        exit 1
    }
    if ($supportsInputFidelity) {
        $applyInputFidelity = $true
    } else {
        Write-Log (T 'validation.input_fidelity_unsupported' $ModelLogicalName) -Level WARN
    }
}

# Mask: only if the model supports inpainting
if ($Mask -and $Mask.Trim() -ne "") {
    if (-not $supportsInpainting) {
        Write-Log (T 'validation.inpainting_unsupported' $ModelLogicalName) -Level ERROR
        exit 1
    }
    if (-not (Test-Path $Mask)) {
        Write-Log (T 'validation.mask_not_found' $Mask) -Level ERROR
        exit 1
    }
    $maskExt = [System.IO.Path]::GetExtension($Mask).ToLower()
    if ($maskExt -ne ".png") {
        Write-Log (T 'validation.mask_not_png' $maskExt) -Level ERROR
        exit 1
    }
    if (-not $InputImages -or $InputImages.Count -eq 0) {
        Write-Log (T 'validation.mask_requires_input') -Level ERROR
        exit 1
    }
}

}   # fine blocco "VALIDAZIONE PARAMETRI" (solo comandi che generano immagini)

# =================================================================
# OUTPUT FOLDER VALIDATION
# =================================================================
try {
    $invalidChars = [System.IO.Path]::GetInvalidPathChars()
    foreach ($c in $invalidChars) {
        if ($OutputFolder.Contains($c)) {
            Write-Log (T 'validation.outputfolder_invalid_chars') -Level ERROR
            exit 1
        }
    }
    $OutputFolder = [System.IO.Path]::GetFullPath($OutputFolder)
}
catch {
    Write-Log (T 'validation.outputfolder_invalid' ($_.Exception.Message)) -Level ERROR
    exit 1
}

if (-not (Test-Path $OutputFolder)) {
    try {
        New-Item -ItemType Directory -Path $OutputFolder -Force | Out-Null
    }
    catch {
        Write-Log (T 'validation.outputfolder_create_failed' $OutputFolder ($_.Exception.Message)) -Level ERROR
        exit 1
    }
}

# Check of the free space on the output folder's volume. AI images
# can weigh several MB each (more in batch). If the space is very low,
# we warn with a WARN (we do not block: the space can change and the user might
# comunque voler procedere). Best-effort: se non riusciamo a leggerlo, ignoriamo.
try {
    $outFull = [System.IO.Path]::GetFullPath($OutputFolder)
    $driveRoot = [System.IO.Path]::GetPathRoot($outFull)
    if ($driveRoot) {
        $di = New-Object System.IO.DriveInfo($driveRoot)
        if ($di.IsReady) {
            $freeMb = [math]::Round($di.AvailableFreeSpace / 1MB)
            $minFreeMb = 100   # soglia prudenziale
            if ($freeMb -lt $minFreeMb) {
                Write-Log (T 'validation.low_disk_space' $freeMb $driveRoot) -Level WARN
            }
        }
    }
} catch {
    # Best-effort: no block if the space check fails.
}

# REAL check of the write permissions on the output folder. Test-Path confirms
# that the folder exists, but NOT that one can write to it (e.g. system folder,
# denied permissions, read-only volume). The only reliable way is to try to create
# a temporary file and then remove it. If it fails, we block immediately with a clear
# message instead of discovering it after spending an API call.
try {
    $writeProbe = Join-Path $OutputFolder (".write_probe_" + [System.Guid]::NewGuid().ToString("N") + ".tmp")
    [System.IO.File]::WriteAllText($writeProbe, "probe")
    Remove-Item -LiteralPath $writeProbe -Force -ErrorAction SilentlyContinue
}
catch {
    Write-Log (T 'validation.outputfolder_not_writable' $OutputFolder ($_.Exception.Message)) -Level ERROR
    exit 1
}

# =================================================================
# UTILITY: OUTPUT FILE NAME
# =================================================================

# =================================================================
# ERROR TRANSLATOR
# =================================================================

# =================================================================
# INPUT IMAGE VALIDATION, CONVERSION AND RESIZING
# =================================================================
$script:TempFilesToCleanup = @()

# Global flag to avoid infinite loops in the API Key re-prompt in case of HTTP 401.
# Set to $true after the first request to the user; at the second 401 the script terminates.
$script:ApiKeyReprompted = $false



# =================================================================
# TELEMETRY — READING / WRITING New-GPTImage.stat
# =================================================================


# =================================================================
# COST MANAGEMENT # =================================================================






# =================================================================
# kNN ESTIMATION ENGINE
# =================================================================







# =================================================================
# METADATA: writing the .json file next to the image
# =================================================================

# =================================================================
# MAIN FUNCTION: generation of a single request
# =================================================================

# =================================================================
# BATCH FLOW
# =================================================================

# Sequential helper for the batch (direct in-process call, no sub-process)

# =================================================================
# ANALYTICS — Log parsing and generation of textual charts
# =================================================================










# =================================================================
# GALLERY HTML (static + optional dynamic via FileSystem API)
# =================================================================


# =================================================================
# COST ESTIMATE AND BUDGET CHECK
# =================================================================
# the -Budget parameter allows blocking the requests that are estimated
# to cost more than a threshold (expressed in local currency).
#
# IMPORTANT - ESTIMATE LIMITATIONS:
# The ex-ante estimate is NOT accurate because:
# - text_tokens depend on the prompt length (estimable)
# - INPUT image_tokens depend on the references (approximately estimable)
# - the OUTPUT tokens (which are often the most expensive for image models) depend
# entirely on the model's response and are NOT predictable
# For this we apply a conservative +20% margin above the estimate.
# It is a safety, not a guarantee. Real costs can be higher if the
# generation is particularly complex.



# =================================================================
# MAIN — Decides between normal flow, batch
# =================================================================

# --- Log header: execution context + active configuration ---
# The first lines are meant to give a quick glance at:
# 1. System (OS, CPU, RAM, system disk) — useful for remote support
# 2. Path from which the script is executed
# 3. Configuration file used (full path)
# 4. Standard file used (full path), if present
# 5-9. Model, API Key (masked), moderation, background, input_fidelity

# 0. Name + version banner (the very first message). For the TUI the line also indicates
# the startup of the interface and uses the TUI version; for all the other
# commands it shows the script's name and version.
if ($TUI) {
    Write-Log (T 'header.banner_tui' $script:ScriptVersion $script:TuiVersion)
} else {
    Write-Log (T 'header.banner' $script:ScriptVersion)
}

# 1. System info (cross-platform Windows/macOS/Linux)
$sysInfo = Get-SystemInfo
Write-Log (T 'header.system_info' $sysInfo.OS $sysInfo.Version $sysInfo.CPU $sysInfo.RAM_GB $sysInfo.Disk_GB)

# 1b. Runtime prerequisites: SYSTEM checks (RAM/disk) and SCRIPT checks (writable
# directory, appendable .log). They run here because they require the language pack
# (already loaded) and the platform variables ($script:IsWin/...). A CRITICAL
# failure (e.g. directory not writable) interrupts the script; the WARN ones proceed.
$runtimePrereq = Test-RuntimePrerequisites -ScriptDir $PSScriptRoot -LogPath $script:LogFile
Write-PrereqMessages -Messages $runtimePrereq.Messages
if (-not $runtimePrereq.Ok) {
    Write-Log (T 'prereq.runtime_failed') -Level ERROR
    exit 1
}

# 2. Path from which the script starts (useful to understand where it is working, also for whoever
# receives only the log and has no context on the user's machine).
Write-Log (T 'header.path_script' $PSScriptRoot)

# 3. Configuration file actually loaded (absolute path)
Write-Log (T 'header.file_config' $script:ConfigFile)

# 3b. Language file (i18n) - optional. It contains the translations. For now,
# if the file exists we log it as information. If it does not exist, we write "(not present)".
if (Test-Path $script:LangFile) {
    Write-Log (T 'header.lang_file' $script:LangFile)
} else {
    Write-Log (T 'header.lang_file_missing' $script:LangFile) -Level WARN
}

# 4. Standard file: same format (full path). Resolved cross-platform via
# IsPathRooted and normalized separators. Logged only if configured and present.
if ($config.standardFile -and $config.standardFile.Trim() -ne "") {
    $stdRawHeader = $config.standardFile.Trim()
    $stdNormHeader = $stdRawHeader.Replace('\', [System.IO.Path]::DirectorySeparatorChar).
                                   Replace('/',  [System.IO.Path]::DirectorySeparatorChar)
    $stdPathHeader = if ([System.IO.Path]::IsPathRooted($stdNormHeader)) {
        $stdNormHeader
    } else {
        Join-Path $PSScriptRoot $stdNormHeader
    }
    if (Test-Path $stdPathHeader) {
        Write-Log (T 'header.standard_file' $stdPathHeader)
    } else {
        # We log the searched path anyway so the user sees it immediately
        Write-Log (T 'header.standard_file_missing' $stdPathHeader) -Level WARN
    }
}

# 5. Internet connectivity check
# Skip if the user requested operations that do NOT require internet:
# -DryRun: validates parameters and shows the prompt, no API calls
# -Setup: handled much earlier, it does not reach here
# -Help: handled much earlier, it does not reach here
# -Gallery: generates local HTML, no API calls
# -CheckModels: uses internet (typical) BUT the connectivity check is part of the workflow
# -Analytics: local log parsing, no API calls
$skipInternetCheck = $DryRun -or $Gallery -or $Analytics -or $IaC
if (-not $skipInternetCheck) {
    $foundryHost = Get-HostFromUrl $Endpoint
    if (-not $foundryHost) {
        Write-Log (T 'internet.hostname_extract_failed' $Endpoint) -Level ERROR
        exit 1
    }
    $internetOk = Test-InternetConnectivity -TargetHost $foundryHost -TargetPort 443 -TimeoutSec 5 -Retries 2
    if ($internetOk) {
        Write-Log (T 'internet.connection_ok')

        # Daily update of the USD/EUR rate (a single call per day).
        # If the API fails, we continue with the existing rate in config.
        $UsdToEurRate = Update-UsdToEurRate -Config $config -ConfigPath $script:ConfigFile

        # Daily update of the model prices via the Azure Retail API.
        # If the user passes -ModelPrice Force, it bypasses the daily check and
        # EXITS after the update (the switch is "task-oriented" like Setup/Gallery/Analytics).
        $forcePricing = ($ModelPrice -eq "Force")
        Update-ModelPricing -Config $config -ConfigPath $script:ConfigFile -Force:$forcePricing
        if ($forcePricing) {
            Write-Log (T 'modelprice.completed')
            exit 0
        }
    } else {
        Write-Log (T 'internet.connection_failed' $foundryHost) -Level ERROR
        exit 1
    }
}

# Local currency detection (Europe=EUR, rest=USD). Once a day.
# This must be done ALWAYS (even without internet), based on the system's RegionInfo.
$DefaultCurrency = Update-DefaultCurrency -Config $config -ConfigPath $script:ConfigFile

# =================================================================
# AUTOMATIC SELF-TEST (dispatch)
# =================================================================
# Executed AFTER the standard startup (system info, internet, USD/EUR rate, currency)
# and BEFORE the model header and the generation: this way on screen the
# usual [INFO] USD/EUR rate ... appears first, then the test startup banner, finally one line
# per test. The switch combination (-Simulate/-Real/-AllTest) has already
# been validated much earlier. We exit with the suite's exit code.
if ($SelfTest) {
    $selfTestMode = if ($AllTest) { "all" } elseif ($Real) { "real" } else { "simulate" }
    $selfTestExit = Invoke-SelfTestSuite -Mode $selfTestMode -Config $config
    exit $selfTestExit
}

# Startup of the TUI (full-screen interactive interface, -TUI switch). It comes after
# the loading of language/config and the validation, but before the generation
# flow: the TUI manages the screen on its own. It normalizes in memory the
# "tui" section of the config (creating it with the defaults if absent), then enters the
# interactive loop. In case of error it always restores the console state.
if ($TUI) {
    Set-TuiConfigDefaults -Config $config
    try {
        Enter-TuiMode -Config $config
    }
    catch {
        Restore-TuiConsole
        Write-Host ''
        Write-Host (T 'tui.error.tui_crash' $_.Exception.Message) -ForegroundColor Red
        Write-Host ''
        exit 1
    }
    exit 0
}

# 6. Header of the model in use. It must be shown ONLY for the commands that actually
# use a specific model (image generation, -CheckEndpoint prints its own).
# Commands like -Analytics and -Gallery do NOT use the active model: for them these
# two lines ("Model in use", "API Key") would be misleading noise, so we
# skip them. The generation parameters (NImages/Size/Quality/...) are logged
# even further on, only if generation actually happens.
# In benchmark mode the model changes at each iteration, so a single
# "Model in use"/"API Key" would be misleading: we skip them and let the
# benchmark declare the models ("Benchmark started. Models: ...").
$benchActive = (@($Bench) | Where-Object { $_ -and $_.Trim() -ne "" }).Count -gt 0
$skipModelHeader = $Analytics -or $Gallery -or $benchActive -or $IaC
if (-not $skipModelHeader) {
    Write-Log (T 'header.model_in_use' $ModelLogicalName $Deployment)
    Write-Log (T 'header.api_key' (Format-MaskedKey $ApiKey))
    # Telemetry status: I report whether it is active (azureMonitor=true in the .conf) or not, so
    # the user knows from the start whether their generations will be tracked on Azure.
    $telemActive = ($null -ne $config.telemetry -and $config.telemetry.azureMonitor -eq $true -and -not $script:NoTelemetryFlag)
    if ($telemActive) {
        Write-Log (T 'header.telemetry_on')
    } else {
        Write-Log (T 'header.telemetry_off')
    }
}

# Outcome flag of the generation flow. It starts at $false; it is set to $true only
# if the try reaches the bottom without errors. The finally reads it to decide whether to print
# "Operation complete" (avoids the misleading message after an error).
$script:GenerationSucceeded = $false

try {

    # ----- ANALYTICS MODE -----
    # If -Analytics is requested, only do the log parsing and show/save the charts.
    # The active model is NOT needed, it does not call the API. It exits after.
    if ($Analytics) {
        # KNOWN PROBLEM: when the user writes "-Analytics USD" or "-Analytics Token",
        # PowerShell treats the value as a positional argument of the first declared
        # non-switch parameter, which is [string]$Prompt. So "USD" ends up in $Prompt.
        # Solution: we look for the modifier in several places:
        # 1. $RemainingArgs[0] (ideal case)
        # 2. $Prompt (real case, value absorbed by positional)
        $analyticsModifier = ""
        if ($RemainingArgs -and $RemainingArgs.Count -gt 0)            { $analyticsModifier = $RemainingArgs[0] }
        elseif ($Prompt -and $Prompt.Trim() -ne "")                     { $analyticsModifier = $Prompt.Trim() }

        $effectiveCurrency = if ([string]::IsNullOrWhiteSpace($analyticsModifier)) {
            if ($DefaultCurrency) { $DefaultCurrency } else { "EUR" }
        } else {
            $analyticsModifier
        }

        # Value validation
        $validCurrencies = @("EUR", "USD", "Token")
        if ($validCurrencies -notcontains $effectiveCurrency) {
            Write-Log (T 'analytics.invalid_currency' $effectiveCurrency) -Level ERROR
            exit 1
        }

        # ----- EXPORT CSV (-ExportAll) -----
        # If requested, exports all the records to CSV and terminates (no charts).
        if ($ExportAll -and $ExportAll.Trim() -ne "") {
            Export-AnalyticsCsv -CsvPath $ExportAll -EurRate $UsdToEurRate
            exit 0
        }

        # -Overwrite and -Append are mutually exclusive
        if ($Overwrite -and $Append) {
            Write-Log (T 'analytics.overwrite_append_conflict') -Level ERROR
            exit 1
        }

        # Output file: existence handling according to the policy (#5).
        # - file does not exist -> create (clean "overwrite" mode)
        # - exists, no flag -> TERMINATES with WARN, does not touch the file
        # - exists, -Overwrite -> overwrites (WARN)
        # - exists, -Append -> appends at the end (WARN)
        $analyticsOutFile = if ($AnalyticsFile -and $AnalyticsFile.Trim() -ne "") { $AnalyticsFile } else { "" }
        $script:AnalyticsWriteMode = "overwrite"   # default per file nuovo
        if ($analyticsOutFile) {
            $resolvedOut = if ([System.IO.Path]::IsPathRooted($analyticsOutFile)) {
                $analyticsOutFile
            } else {
                Join-Path $PSScriptRoot $analyticsOutFile
            }
            if (Test-Path $resolvedOut) {
                if ($Append) {
                    $script:AnalyticsWriteMode = "append"
                } elseif ($Overwrite) {
                    $script:AnalyticsWriteMode = "overwrite-existing"
                } else {
                    # No flag: I do not overwrite, I terminate with a WARN and exit.
                    Write-Log (T 'analytics.file_exists_no_flag' $resolvedOut) -Level WARN
                    exit 0
                }
            }
        }

        Invoke-Analytics -Currency $effectiveCurrency -OutputFile $analyticsOutFile
        exit 0
    }

    # ----- GALLERY MODE -----
    # Generates gallery.html in the images folder (defaultOutputFolder).
    # No API calls, no model.
    if ($Gallery) {
        Invoke-Gallery -ImagesFolder $OutputFolder
        exit 0
    }

    # ----- IaC (Infrastructure as Code) -----
    if ($IaC) {
        if ($IaCTeardown) {
            # Teardown mode: dismantles the resources (RF-7). Destructive, with confirmation.
            $tearOk = Invoke-IaCTeardown -ResourceGroup $IaCResourceGroup
            if ($tearOk) { exit 0 } else { exit 1 }
        }
        if ($IaCWizard) {
            # Interactive wizard (RF-3): collects the parameters and proceeds to execute.
            $wizOk = Invoke-IaCWizard -OutputFolder $OutputFolder
            if ($wizOk) { exit 0 } else { exit 1 }
        }
        $iacOk = Invoke-IaC -Mode $IaCMode -ResourceGroup $IaCResourceGroup `
            -Region $IaCRegion -FoundryName $IaCFoundryName -ProjectName $IaCProjectName `
            -OutputFolder $OutputFolder `
            -DeployModel ([bool]$IaCDeployModel) -ModelName $IaCModelName -ModelVersion $IaCModelVersion `
            -ModelFormat $IaCModelFormat -ModelSku $IaCModelSku -ModelCapacity $IaCModelCapacity `
            -PurgeSoftDeleted ([bool]$IaCPurgeSoftDeleted)
        if ($iacOk) { exit 0 } else { exit 1 }
    }

    # ----- MODEL OPERATIONAL LIMITS VALIDATION -----
    # Before generating, we verify that NImages/Size/Quality/reference fall within
    # the selected model's constraints (operationalLimits in the .conf). Intercepting
    # here avoids API calls destined to fail and gives clear messages. For the batch,
    # this validates the global parameters; any per-item overrides with out-of-limit
    # values are re-checked anyway at the moment they are applied.
    $refCountForLimits = if ($InputImages) { @($InputImages).Count } else { 0 }
    $limitErrors = Test-ModelOperationalLimits -ModelConfig $modelConfig -ModelName $ModelLogicalName `
                       -NImages $NImages -Size $Size -Quality $Quality `
                       -ReferenceCount $refCountForLimits `
                       -QualityExplicit ($PSBoundParameters.ContainsKey('Quality'))
    if ($limitErrors.Count -gt 0) {
        foreach ($e in $limitErrors) { Write-Log $e -Level ERROR }
        Write-Log (T 'limits.aborted' $ModelLogicalName) -Level ERROR
        exit 1
    }

    # ----- GENERATION PARAMETERS HEADER -----
    # From here on generation actually happens (batch or single mode), so we log the
    # active parameters that determine the output, on 2 compact lines.
    # Line 1: the generation parameters (always present)
    # Line 2: the moderation/background parameters (Background appears only if applicable)
    # In benchmark mode these lines are redundant (the focus is the comparison between
    # models, not the single set of parameters), so we skip them.
    if (-not $benchActive) {
        Write-Log (T 'header.params_line1' $NImages $Size $Quality $Format)
        $line2 = "Moderation: $Moderation"
        if ($applyBackground)    { $line2 += " | Background: $Background" }
        if ($applyInputFidelity) { $line2 += " | InputFidelity: $InputFidelity" }
        Write-Log $line2
    }

    # ----- BENCHMARK MODE -----
    # If -Bench contains models, we run the same prompt (or the same prompts of
    # -Batch) on each indicated model, collecting time/cost/token/image path.
    # It intercepts BEFORE the normal batch/single dispatch: the benchmark handles
    # both prompt sources itself.
    $benchModels = @()
    foreach ($b in @($Bench)) {
        if ($null -eq $b) { continue }
        # I accept both "m1,m2" and already-separated elements: I split each element on the comma.
        foreach ($piece in ($b -split ',')) {
            $t = $piece.Trim()
            if ($t -ne "") { $benchModels += $t }
        }
    }
    $benchModels = @($benchModels | Select-Object -Unique)

    if ($benchModels.Count -gt 0) {
        # Canonicalizzo i nomi indicati alla grafia ESATTA del .conf, in modo
        # case-insensitive (es. "GPT-Image-2" -> "gpt-image-2"), coerentemente con
        # options and values. Get-CanonicalModelName resolves upper/lowercase and
        # prefixes; if it finds no match it leaves the name unchanged, so the real
        # typos (e.g. "GTP-Image-1.5") stay unrecognized and are flagged.
        $confModelNamesB = @($config.models.PSObject.Properties.Name)
        $canonMapB = @{}
        $benchModels = @($benchModels | ForEach-Object {
            Get-CanonicalModelName -RawName $_ -ConfModelNames $confModelNamesB -CanonMap $canonMapB
        })
        # Case-insensitive validation: a model is valid if it exists (regardless
        # of case) among the .conf keys.
        $confLowerB = @{}
        foreach ($cn in $confModelNamesB) { $confLowerB[$cn.ToLowerInvariant()] = $true }
        $unknownModels = @($benchModels | Where-Object { -not $confLowerB[$_.ToLowerInvariant()] })
        if ($unknownModels.Count -gt 0) {
            $available = (@($config.models.PSObject.Properties.Name) -join ', ')
            Write-Log (T 'bench.unknown_models' ($unknownModels -join ', ') $available) -Level ERROR
            exit 1
        }

        # I build the list of prompts to use. Three possible sources:
        #  - -Batch: one prompt for each entry of the batch file (with the entry's id)
        #  - -PromptFile: the file content, single prompt (id = 1)
        #  - -Prompt: the inline prompt, single (id = 1)
        $benchPrompts = New-Object System.Collections.Generic.List[object]

        if ($Batch -and $Batch.Trim() -ne "") {
            try {
                $benchBatchItems = (Get-Content $Batch -Raw -Encoding UTF8 -ErrorAction Stop) | ConvertFrom-Json -ErrorAction Stop
            }
            catch {
                Write-Log (T 'batch.parse_error' $Batch ($_.Exception.Message)) -Level ERROR
                exit 1
            }
            $bidx = 0
            foreach ($bi in @($benchBatchItems)) {
                $bidx++
                $itemId = if ($null -ne $bi.id -and ([string]$bi.id).Trim() -ne "") { [string]$bi.id } else { [string]$bidx }
                # prompt or promptFile
                $itemPrompt = $null
                if ($bi.prompt -and ([string]$bi.prompt).Trim() -ne "") {
                    $itemPrompt = [string]$bi.prompt
                } elseif ($bi.promptFile -and ([string]$bi.promptFile).Trim() -ne "") {
                    $itemPrompt = Read-PromptFile -Path ([string]$bi.promptFile)
                    if ($null -eq $itemPrompt) {
                        Write-Log (T 'batch.item_promptfile_missing' $itemId ([string]$bi.promptFile)) -Level ERROR
                        exit 1
                    }
                }
                if (-not $itemPrompt -or $itemPrompt.Length -lt 5) {
                    Write-Log (T 'batch.item_no_prompt' $itemId) -Level ERROR
                    exit 1
                }
                $benchPrompts.Add([PSCustomObject]@{ Id = $itemId; Text = $itemPrompt })
            }
        }
        else {
            # Single prompt (from -PromptFile or -Prompt). The file has already been validated
            # upstream for existence; here I read it.
            $singlePrompt = $Prompt
            if ($PromptFile) {
                $singlePrompt = Read-PromptFile -Path $PromptFile
                if ($null -eq $singlePrompt) { exit 1 }
            }
            if (-not $singlePrompt -or $singlePrompt.Length -lt 5) {
                Write-Log (T 'prompt.missing_or_short') -Level ERROR
                exit 1
            }
            $benchPrompts.Add([PSCustomObject]@{ Id = "1"; Text = $singlePrompt })
        }

        # Generation options common to all the combinations.
        $benchHash = (Get-FileHash -InputStream ([IO.MemoryStream]::new([Text.Encoding]::UTF8.GetBytes(($benchPrompts[0].Text)))) -Algorithm SHA256).Hash.Substring(0,8)
        $genOptions = @{
            Size = $Size; Quality = $Quality; Format = $Format; NImages = $NImages
            Moderation = $Moderation; Background = $Background; InputFidelity = $InputFidelity
            Mask = $Mask; InputImages = $InputImages; OutputFolder = $OutputFolder
            OutputMode = $OutputMode; MaxRetries = $MaxRetries; TimeoutMinutes = $RequestTimeoutMinutes
            UseMetadata = $useMetadata; InputImagesOriginal = @($InputImages)
            Hash = $benchHash; Compression = [int]$config.defaultOutputCompression
            EurRate = $UsdToEurRate
            Budget = $Budget; DefaultCurrency = $DefaultCurrency
        }

        Write-Log (T 'bench.start' ($benchModels -join ', ') ($benchPrompts.Count)) -Level INFO

        $benchResults = Invoke-Benchmark -Prompts $benchPrompts.ToArray() -ModelNames $benchModels -Config $config -GenOptions $genOptions

        # On-screen report (grouped by prompt)
        Write-BenchmarkReport -Results $benchResults

        # Optional CSV export
        if ($BenchExport -and $BenchExport.Trim() -ne "") {
            Export-BenchmarkCsv -Results $benchResults -Path $BenchExport
        }

        $script:GenerationSucceeded = $true
        exit 0
    }

    # ----- BATCH MODE -----
    if ($Batch -and $Batch.Trim() -ne "") {
        Invoke-BatchProcessing -BatchFilePath $Batch -Threads $effectiveThreads
        exit 0
    }

    # ----- SINGLE FLOW -----
    # Stopwatch for the telemetry: measures the total duration of the generation.
    $genStopwatch = [System.Diagnostics.Stopwatch]::StartNew()
    # Prompt reading
    if ($PromptFile) {
        try {
            $Prompt = Read-PromptFile -Path $PromptFile
            if ($null -eq $Prompt) { exit 1 }
        }
        catch {
            Write-Log (T 'prompt.file_read_failed' $PromptFile ($_.Exception.Message)) -Level ERROR
            exit 1
        }
    }

    if (-not $Prompt -or $Prompt.Length -lt 5) {
        Write-Log (T 'prompt.missing_or_short') -Level ERROR
        exit 1
    }

    # Upper limit of the prompt length. The Microsoft doc indicates 32,000 context
    # tokens for the MAI; estimating ~4 characters per token, a prompt over ~120,000
    # characters surely exceeds the limit. We use a prudent character threshold to
    # block upstream with a clear message instead of a cryptic API error.
    $maxPromptChars = 120000
    if ($Prompt.Length -gt $maxPromptChars) {
        Write-Log (T 'prompt.too_long' $Prompt.Length $maxPromptChars) -Level ERROR
        exit 1
    }

    # ----- ANTI-BINARY-CONTENT GUARD -----
    # If the prompt starts with a binary file signature (PK = ZIP/OOXML like docx/odt
    # read raw, or the OLE signature of the old .doc) or contains an anomalous
    # percentage of control characters, it is almost certain that a non-text file was
    # read as text. Better to fail with a clear message than to send
    # garbage to the model (which "rationalizes" it into off-topic images).
    $looksBinary = $false
    if ($Prompt.Length -ge 2) {
        $p0 = [int][char]$Prompt[0]; $p1 = [int][char]$Prompt[1]
        # "PK" (ZIP/OOXML) = 0x50 0x4B ; OLE docProps spesso iniziano con 0xD0 0xCF
        if (($p0 -eq 0x50 -and $p1 -eq 0x4B) -or ($p0 -eq 0xD0 -and $p1 -eq 0xCF)) { $looksBinary = $true }
    }
    if (-not $looksBinary -and $Prompt.Length -gt 0) {
        $ctrl = 0
        $sample = if ($Prompt.Length -gt 4000) { $Prompt.Substring(0, 4000) } else { $Prompt }
        foreach ($ch in $sample.ToCharArray()) {
            $code = [int][char]$ch
            # Count the non-printable control characters (I exclude tab/CR/LF).
            if ($code -lt 32 -and $code -ne 9 -and $code -ne 10 -and $code -ne 13) { $ctrl++ }
        }
        if ($sample.Length -gt 0 -and ($ctrl / $sample.Length) -gt 0.02) { $looksBinary = $true }
    }
    if ($looksBinary) {
        Write-Log (T 'prompt.binary_detected' $PromptFile) -Level ERROR
        exit 1
    }

    $promptLenForStats = $Prompt.Length

    # Standard file (supporta path assoluti e relativi, cross-platform)

    # ----- STORYBOARD (-Storyboard): narrative sequence of coherent images -----
    # Decomposes the narrative prompt into a style bible + N scenes via the conf's
    # text model, then generates the scenes in sequential sub-processes in a
    # dedicated subfolder, and saves a storyboard.json manifest. It exits at the end.
    if ($Storyboard) {
        Write-Log (T 'story.start' $SequenceImages)
        # The storyboard DEPENDS on the text model for the decomposition: without it, it
        # cannot proceed. If it is not available, a blocking ERROR (unlike
        # optimize/negative which are only enhancements).
        $tmCheck = Test-TextModelAvailable -Config $config
        if (-not $tmCheck.Available) {
            Write-Log (T 'textmodel.unavailable_stop' (T $tmCheck.Reason)) -Level ERROR
            exit 1
        }
        $sbPlan = Invoke-StoryboardDecompose -Narrative $Prompt -Count $SequenceImages -Config $config
        if (-not $sbPlan) { exit 1 }
        # Text cost of the storyboard decomposition (operation=storyboard). The
        # single scenes run as CLI sub-processes without optimize/negative, so
        # they add no text cost: the storyboard cost is that of the decomposition.
        if (([int]$sbPlan.InputTokens + [int]$sbPlan.OutputTokens) -gt 0) {
            $tc = Write-TextCostLog -InputTokens ([int]$sbPlan.InputTokens) -OutputTokens ([int]$sbPlan.OutputTokens) `
                    -Config $config -Operation "storyboard" -Verbosity $Verbosity -DefaultCurrency ([string]$config.defaultCurrency)
            if ($tc) { Send-TextCostTelemetry -Config $config -TextCost $tc -TextModel ([string]$config.textModel.model) }
        }
        $sbStamp = (Get-Date).ToString("yyyyMMdd_HHmmss", [System.Globalization.CultureInfo]::InvariantCulture)
        $sbDir = Join-Path $OutputFolder ("storyboard_" + $sbStamp)
        New-Item -ItemType Directory -Path $sbDir -Force | Out-Null
        $sbOk = 0
        for ($sceneIdx = 1; $sceneIdx -le $SequenceImages; $sceneIdx++) {
            $scene = $sbPlan.Scenes[$sceneIdx - 1]
            $scenePrompt = $sbPlan.StyleBible + "`n`nScene $sceneIdx of $($SequenceImages): " + $scene
            Write-Log (T 'story.scene_progress' $sceneIdx $SequenceImages)
            $sceneArgs = @("-Prompt", $scenePrompt, "-NImages", "1", "-OutputFolder", $sbDir, "-Verbosity", "ultrasilent")
            if ($PSBoundParameters.ContainsKey('Model'))   { $sceneArgs += @("-Model",   $Model) }
            if ($PSBoundParameters.ContainsKey('Size'))    { $sceneArgs += @("-Size",    $Size) }
            if ($PSBoundParameters.ContainsKey('Quality')) { $sceneArgs += @("-Quality", $Quality) }
            if ($PSBoundParameters.ContainsKey('Format'))  { $sceneArgs += @("-Format",  $Format) }
            & pwsh -NoProfile -ExecutionPolicy Bypass -File $PSCommandPath @sceneArgs | Out-Null
            if ($LASTEXITCODE -eq 0) { $sbOk++ }
            else { Write-Log (T 'story.scene_failed' $sceneIdx) -Level WARN }
        }
        # Sequence manifest: narrative, style bible, scenes and produced files.
        try {
            $sbFiles = @(Get-ChildItem $sbDir -File | Where-Object { $_.Extension -in @('.png', '.jpg', '.webp') } | Sort-Object Name | Select-Object -ExpandProperty Name)
            $manifest = [ordered]@{
                narrative   = $Prompt
                style_bible = $sbPlan.StyleBible
                sequence    = $SequenceImages
                generated   = $sbOk
                scenes      = $sbPlan.Scenes
                files       = $sbFiles
                created_at  = (Get-Date).ToString("yyyy-MM-ddTHH:mm:ss", [System.Globalization.CultureInfo]::InvariantCulture)
            }
            $manifest | ConvertTo-Json -Depth 10 | Set-Content -Path (Join-Path $sbDir "storyboard.json") -Encoding UTF8
        } catch {
            Write-Log (T 'story.manifest_failed' ($_.Exception.Message)) -Level WARN
        }
        Write-Log (T 'story.done' $sbOk $SequenceImages $sbDir)
        if ($sbOk -eq $SequenceImages) { exit 0 } else { exit 1 }
    }

    # Check the text model availability if it is needed by optimize/negative. These
    # are ENHANCEMENTS: if the model is not available, I warn (WARN) and proceed with the
    # generation WITHOUT optimization/negative (I disable the two flags). Non-blocking.
    if ($OptimizePrompt -or $NegativePrompt) {
        $tmCheck = Test-TextModelAvailable -Config $config
        if (-not $tmCheck.Available) {
            Write-Log (T 'textmodel.unavailable_skip' (T $tmCheck.Reason)) -Level WARN
            $OptimizePrompt = $false
            $NegativePrompt = $false
        }
    }

    # ----- PROMPT OPTIMIZATION (-OptimizePrompt) via text model -----
    if ($OptimizePrompt) {
        # On screen a waiting message (the call to the model can take a long time);
        # the complete prompts end up only in the log file (TIME level) so as not to
        # clog the console.
        Write-Log (T 'optimize.calling' ([string]$config.textModel.model))
        Write-PromptLog -LabelKey 'prompt.label_original' -PromptText $Prompt -Kind "support" -Config $config
        $optimized = Invoke-TextModelPromptRewrite -Prompt $Prompt -Config $config
        if ($optimized -and $optimized.Text) {
            Write-PromptLog -LabelKey 'prompt.label_optimized' -PromptText $optimized.Text -Kind "support" -Config $config
            Write-Log (T 'optimize.done')
            $Prompt = $optimized.Text
            # Text cost of THIS operation (immediately, with operation=optimize).
            if (([int]$optimized.InputTokens + [int]$optimized.OutputTokens) -gt 0) {
                $tc = Write-TextCostLog -InputTokens ([int]$optimized.InputTokens) -OutputTokens ([int]$optimized.OutputTokens) `
                        -Config $config -Operation "optimize" -Verbosity $Verbosity -DefaultCurrency ([string]$config.defaultCurrency)
                if ($tc) { Send-TextCostTelemetry -Config $config -TextCost $tc -TextModel ([string]$config.textModel.model) }
            }
        } else {
            Write-Log (T 'optimize.failed') -Level WARN
        }
    }

    # ----- NEGATIVE PROMPT (-NegativePrompt): injected into the positive prompt -----
    # The "Avoid: ..." injection makes the feature compatible with all the
    # models, even those without a native negative_prompt field.
    if ($NegativePrompt) {
        Write-Log (T 'negative.calling' ([string]$config.textModel.model))
        $negList = Invoke-TextModelNegative -Prompt $Prompt -Config $config
        if ($negList -and $negList.Text) {
            Write-PromptLog -LabelKey 'prompt.label_negative' -PromptText $negList.Text -Kind "support" -Config $config
            Write-Log (T 'negative.done')
            $Prompt = $Prompt + "`n`nAvoid: " + $negList.Text
            # Text cost of THIS operation (immediately, with operation=negative).
            if (([int]$negList.InputTokens + [int]$negList.OutputTokens) -gt 0) {
                $tc = Write-TextCostLog -InputTokens ([int]$negList.InputTokens) -OutputTokens ([int]$negList.OutputTokens) `
                        -Config $config -Operation "negative" -Verbosity $Verbosity -DefaultCurrency ([string]$config.defaultCurrency)
                if ($tc) { Send-TextCostTelemetry -Config $config -TextCost $tc -TextModel ([string]$config.textModel.model) }
            }
        } else {
            Write-Log (T 'negative.failed') -Level WARN
        }
    }

    if ($config.standardFile -and $config.standardFile.Trim() -ne "") {
        $stdRaw = $config.standardFile.Trim()
        # I normalize the path separators to the current system's native character:
        # this way a conf with "prompts/donna.md" or "prompts\donna.md" works everywhere.
        $stdNormalized = $stdRaw.Replace('\', [System.IO.Path]::DirectorySeparatorChar).
                                 Replace('/',  [System.IO.Path]::DirectorySeparatorChar)

        # If it is an absolute path, I use it directly. Otherwise I combine it with
        # the script's directory. [Path]::IsPathRooted handles correctly
        # 'C:\...' su Windows e '/...' su Unix.
        $standardPath = if ([System.IO.Path]::IsPathRooted($stdNormalized)) {
            $stdNormalized
        } else {
            Join-Path $PSScriptRoot $stdNormalized
        }

        if (Test-Path $standardPath) {
            try {
                $standardContent = Get-Content $standardPath -Raw -Encoding UTF8
                # The content of the standard file is appended to the user prompt.
                # NB: no more "[STANDARD]:" tag that confused the output, I leave
                # only a double newline as a separator. The fact that the content
                # comes from the standard file is already logged at the top.
                $Prompt = "$Prompt`n`n$standardContent"
            }
            catch {
                Write-Log (T 'prompt.standard_file_unreadable' ($_.Exception.Message)) -Level WARN
            }
        }
        # The "not found" case has already been flagged at the top with a WARN.
    }

    if ($DryRun) {
        # In DryRun: on screen we print ONLY a short informative line.
        # The complete final prompt we save ONLY in the log file, NOT on screen
        # (it could be very long and is not useful on the screen).
        Write-Log (T 'dryrun.active')

        # I write the final prompt directly into the log file (not Write-Log which
        # would reduce the message to a single line and show it on screen).
        if ($script:LogFile) {
            $ts = (Get-Date).ToString("yyyy-MM-dd HH:mm:ss", [System.Globalization.CultureInfo]::InvariantCulture)
            $header = "[$ts] [INFO] " + (T 'dryrun.prompt_log' $Prompt.Length)
            Add-Content -Path $script:LogFile -Value (Protect-LogFileLine $header) -Encoding UTF8 -ErrorAction SilentlyContinue
            # The real prompt, indented by 2 spaces to make it recognizable as a block
            $indented = ($Prompt -split "`n" | ForEach-Object { "  $_" }) -join "`n"
            Add-Content -Path $script:LogFile -Value $indented -Encoding UTF8 -ErrorAction SilentlyContinue
        }
        exit 0
    }

    # Prompt hash
    $hash = (Get-FileHash -InputStream ([IO.MemoryStream]::new([Text.Encoding]::UTF8.GetBytes($Prompt))) -Algorithm SHA256).Hash.Substring(0,8)

    # Log of the final image prompt (the one actually sent to the generation,
    # after any -OptimizePrompt / -NegativePrompt). Dedicated "final" label
    # to distinguish it from the user's original. It respects privacy.imagePrompts: if true
    # it is obfuscated in Base64 in the .log. It adds length and estimated tokens.
    Write-PromptLog -LabelKey 'prompt.label_final' -PromptText $Prompt -Kind "image" -Config $config

    # Modalita' edit / generation
    $isEditMode = ($InputImages -and $InputImages.Count -gt 0)
    $InputImagesOriginalCount = if ($isEditMode) { $InputImages.Count } else { 0 }
    $InputImagesOriginalPaths = if ($isEditMode) { @($InputImages) } else { @() }

    if ($isEditMode) {
        # il requisito dell'editEndpoint dipende dallo schema API.
        # bfl-flux: the edit happens on the SAME endpoint as the generation
        # (the references go in the body as base64), so only
        # 'endpoint' is needed, not 'editEndpoint'.
        # openai-images: the dedicated editEndpoint is needed (/edits multipart).
        # mai-images: non arriva qui (supportsEdit=false blocca a monte).
        if ($apiSchema -eq "bfl-flux") {
            if (-not $modelConfig.endpoint -or $modelConfig.endpoint.Trim() -eq "") {
                Write-Log (T 'edit.no_endpoint' $ModelLogicalName) -Level ERROR
                exit 1
            }
        } else {
            if (-not $modelConfig.editEndpoint -or $modelConfig.editEndpoint.Trim() -eq "") {
                Write-Log (T 'edit.no_endpoint' $ModelLogicalName) -Level ERROR
                exit 1
            }
        }

        foreach ($img in $InputImages) {
            if (-not (Test-Path $img)) {
                Write-Log (T 'edit.image_not_found' $img) -Level ERROR
                exit 1
            }
            $ext = [System.IO.Path]::GetExtension($img).ToLower()
            if ($ext -notin @(".png", ".jpg", ".jpeg")) {
                Write-Log (T 'edit.unsupported_format' $img) -Level ERROR
                exit 1
            }
        }

        Write-Log (T 'edit.validation_start' $MaxImageDimension)
        $ValidatedImages = @()
        for ($idx = 0; $idx -lt $InputImages.Count; $idx++) {
            Write-Log (T 'edit.analyzing' ($idx + 1) ($InputImages.Count) ($InputImages[$idx]))
            $validatedPath = ConvertTo-ValidImage -ImagePath $InputImages[$idx] -MaxDimension $MaxImageDimension -MaxArea $MaxImageArea
            $ValidatedImages += $validatedPath
        }
        $InputImages = $ValidatedImages
        Write-Log (T 'edit.mode_active' ($InputImages.Count))

        # Check aspect ratio coherence: se l'output ha aspect molto diverso dalle reference,
        # the model might deform the faces. I warn the user.
        # Skip on non-Windows (requires System.Drawing which is not available there).
        if ($script:IsWin) {
            $sizeParts = $Size.Split("x")
            $reqW = [int]$sizeParts[0]; $reqH = [int]$sizeParts[1]
            $outAspect = if ($reqH -gt 0) { $reqW / [double]$reqH } else { 1.0 }

            $refAspects = @()
            foreach ($validPath in $InputImages) {
                $tmpImg = $null
                try {
                    $tmpImg = [System.Drawing.Image]::FromFile($validPath)
                    $refAsp = if ($tmpImg.Height -gt 0) { $tmpImg.Width / [double]$tmpImg.Height } else { 1.0 }
                    $refAspects += $refAsp
                }
                catch { }
                finally {
                    if ($tmpImg) { $tmpImg.Dispose() }
                }
            }
            if ($refAspects.Count -gt 0) {
                $avgRefAspect = ($refAspects | Measure-Object -Average).Average
                $aspectDiff = [math]::Abs($outAspect - $avgRefAspect) / [math]::Max($outAspect, $avgRefAspect)
                if ($aspectDiff -gt 0.15) {
                    Write-Log (T 'edit.aspect_warning_1' ([math]::Round($outAspect,3)) ([math]::Round($avgRefAspect,3))) -Level WARN
                    Write-Log (T 'edit.aspect_warning_2' ([math]::Round($aspectDiff * 100, 1))) -Level WARN
                }
            }
        }
    }
    else {
        Write-Log (T 'edit.generation_mode')
    }

    # Time estimate
    $parts = $Size.Split("x")
    $reqWidth  = [int]$parts[0]
    $reqHeight = [int]$parts[1]
    $modeKey = if ($isEditMode) { "edit" } else { "generation" }

    $candidate = @{
        size_pixels        = $reqWidth * $reqHeight
        size_bucket        = (Get-SizeBucket -Width $reqWidth -Height $reqHeight)
        quality_score      = (Get-QualityScore $Quality)
        n_images           = $NImages
        input_images_count = $InputImagesOriginalCount
        prompt_len         = $promptLenForStats
        hour_of_day        = (Get-Date).Hour
    }
    $estimate = Get-TimeEstimate -Candidate $candidate -ModeKey $modeKey -ModelName $ModelLogicalName
    $estimatedTotal = $estimate.estimated_single

    $startTime = Get-Date
    Write-Log (T 'generation.start' (Format-DisplayDate -Date $startTime))
    Write-Log (T 'generation.estimate_total' $estimatedTotal ($estimate.tier) ($estimate.confidence))
    Write-Log (T 'generation.estimate_detail' ($estimate.explanation))

    # Budget guardrail : cost estimate + budget check before calling the API
    if ($null -ne $Budget) {
        $costEstimate = Get-EstimatedCost -Prompt $Prompt -NImages $NImages `
                                          -InputImagesCount @($InputImages).Count `
                                          -Quality $Quality -Size $Size `
                                          -PriceInputUsd $priceInputUsd -PriceOutputUsd $priceOutputUsd `
                                          -PriceImageUsd $priceImageUsd -Pricing $modelPricing `
                                          -EurRate $UsdToEurRate
        $budgetOk = Test-BudgetGuardrail -Budget $Budget -Currency $DefaultCurrency -Estimate $costEstimate
        if (-not $budgetOk) {
            exit 1
        }
    }

    # Single execution
    $foEndpoint     = if ($modelConfig.failoverEndpoint)     { $modelConfig.failoverEndpoint }     else { "" }
    $foEditEndpoint = if ($modelConfig.failoverEditEndpoint) { $modelConfig.failoverEditEndpoint } else { "" }
    $result = Invoke-ImageGeneration `
        -Prompt $Prompt -Size $Size -Quality $Quality -Format $Format -NImages $NImages `
        -Moderation $Moderation -Background $Background -InputFidelity $InputFidelity -Mask $Mask `
        -InputImages $InputImages -OutputFolder $OutputFolder -OutputMode $OutputMode `
        -ModelName $ModelLogicalName -Deployment $Deployment `
        -ApiSchema $apiSchema `
        -AuthMode $authMode `
        -Endpoint $modelConfig.endpoint -EditEndpoint $modelConfig.editEndpoint `
        -FailoverEndpoint $foEndpoint -FailoverEditEndpoint $foEditEndpoint `
        -ApiKey $ApiKey `
        -MaxRetries $MaxRetries -TimeoutMinutes $RequestTimeoutMinutes `
        -ApplyBackground $applyBackground -ApplyInputFidelity $applyInputFidelity `
        -ApplyModeration $applyModeration `
        -UseMetadata $useMetadata -InputImagesOriginal $InputImagesOriginalPaths `
        -FileTemplate $FileTemplate -Hash $hash -Compression ([int]$config.defaultOutputCompression) `
        -PriceInputUsd $priceInputUsd -PriceOutputUsd $priceOutputUsd `
        -PriceImageUsd $priceImageUsd -Pricing $modelPricing `
        -EurRate $UsdToEurRate `
        -EstimatedTotal $estimatedTotal `
        -OperationalParams $modelConfig.operationalParams

    if (-not $result.Success) {
        Write-Log (T 'generation.failed' ($result.Error)) -Level ERROR
        exit 1
    }

    # Registrazione [TIME]
    if ($result.StartTime -and $result.ActualDurationSec) {
        $endAttempt = $result.StartTime.AddSeconds($result.ActualDurationSec)
        $timeRecord = [ordered]@{
            date               = $result.StartTime.ToString("yyyy-MM-dd", [System.Globalization.CultureInfo]::InvariantCulture)
            start              = $result.StartTime.ToString("HH:mm:ss")
            end                = $endAttempt.ToString("HH:mm:ss")
            estimated          = [int]$estimatedTotal
            actual             = [int]$result.ActualDurationSec
            model              = $ModelLogicalName
            deployment         = $Deployment
            mode               = $modeKey
            prompt_len         = [int]$promptLenForStats
            size               = $Size
            format             = $Format
            quality            = $Quality
            n_images           = [int]$NImages
            input_images_count = [int]$InputImagesOriginalCount
            attempts           = [int]$result.Attempts
        }
        Add-TimeStatRecord -Record $timeRecord

        $errorPct = if ($estimatedTotal -gt 0) {
            [math]::Round((([double]$result.ActualDurationSec - $estimatedTotal) / $estimatedTotal) * 100, 1)
        } else { 0 }
        $errorSign = if ($errorPct -ge 0) { "+" } else { "" }
        Write-Log (T 'generation.estimate_accuracy' $estimatedTotal ($result.ActualDurationSec) $errorSign $errorPct)
    }

    # Cost logging
    if ($result.Cost) {
        Write-CostLog -Cost $result.Cost -Model $ModelLogicalName -HasPricingSection ($null -ne $modelPricing) -NImages $NImages
        Add-DailyCostRecord -Cost $result.Cost
        # NOTE: the "Session cost" summary has been unified inside Write-CostLog
        # . There is no need to duplicate it here anymore.
    }

    # Telemetry (RF-5): non-blocking send of the generation metrics to
    # Application Insights, if enabled in the conf (telemetry.azureMonitor=true).
    # "cli" source: this is the command-line flow. The construction of the
    # metrics is centralized in Send-GenerationTelemetry (shared with batch/TUI).
    if ($genStopwatch) { $genStopwatch.Stop() }
    Send-GenerationTelemetry -Config $config -Cost $result.Cost `
        -DurationSec $genStopwatch.Elapsed.TotalSeconds -Model $ModelLogicalName `
        -Size $Size -Quality $Quality -NImages $NImages -Source "cli"

    # Having arrived here without early exits or exceptions: the flow went well.
    # The flag distinguishes the real success from the error exits, so the
    # finally block does NOT print "Operation complete" when there actually was an
    # error (the finally always runs, even after exit/throw).
    $script:GenerationSucceeded = $true
}
finally {
    Invoke-TempCleanup

    if ($startTime) {
        $endTime = Get-Date
        $elapsed = $endTime - $startTime
        Write-Log (T 'generation.end' (Format-DisplayDate -Date $endTime))
        Write-Log (T 'generation.total_time' ($elapsed.ToString()))
    }
    # "Operation complete" only if the flow really reached the bottom successfully.
    if ($script:GenerationSucceeded) {
        Write-Log (T 'generation.complete')
    }
}